# ──────────────────────────────────────────────────────────────────────
# Windows subprocess no-console helper
# ──────────────────────────────────────────────────────────────────────
def no_window() -> Dict[str, Any]:
    """Hide child console windows on Windows when launching ffmpeg/ffprobe/helpers."""
    if os.name == "nt":
        return {"creationflags": subprocess.CREATE_NO_WINDOW}
    return {}

