# ──────────────────────────────────────────────────────────────────────
# Helpers
# ──────────────────────────────────────────────────────────────────────
def now_str() -> str:
    return datetime.now().strftime("%Y%m%d_%H%M%S")


def log_ts() -> str:
    return datetime.now().strftime("%H:%M:%S")


def norm(s: Any) -> str:
    return re.sub(r"\s+", " ", str(s or "")).strip()


def safe_name(s: Any, max_len: int = 80) -> str:
    s = norm(s)
    s = "".join(ch if ch.isalnum() or ch in "-_" else "_" for ch in s)
    s = re.sub(r"_+", "_", s).strip("_")
    return (s[:max_len] or "unnamed")


def parse_resolution(text: str) -> Tuple[int, int]:
    m = re.search(r"(\d+)\D+(\d+)", str(text or ""))
    if not m:
        return 1080, 1920
    return int(m.group(1)), int(m.group(2))


def sha1_text(s: str) -> str:
    return hashlib.sha1(s.encode("utf-8", errors="ignore")).hexdigest()[:16]


def is_video_url(url: str) -> bool:
    if not url or not isinstance(url, str) or not url.startswith("http"):
        return False
    low = url.lower()
    if "playphrase.me/#" in low or "playphrase.me/search" in low:
        return False
    if re.search(r"\.(mp4|webm|m4v|mov|ts|m3u8)(\?|#|$)", low):
        return True
    return any(k in low for k in ("/video/", "/media/", "/storage/", "/stream/", "/content/", "/asset/"))


def weighted_match(text: str, query: str) -> int:
    t = norm(text).lower()
    q = norm(query).lower()
    if not q:
        return 0
    score = 0
    if t == q:
        score += 120
    if q in t:
        score += 70
    if t.startswith(q):
        score += 20
    words = [w for w in re.split(r"\W+", q) if w]
    for w in words:
        if re.search(r"\b" + re.escape(w) + r"\b", t):
            score += 10
    return score


def extract_year(obj: Any) -> str:
    years: List[str] = []
    def walk(x: Any, depth: int = 0):
        if depth > 6:
            return
        if isinstance(x, dict):
            for k, v in x.items():
                kl = str(k).lower()
                if "year" in kl or "date" in kl or "release" in kl:
                    m = re.search(r"\b(19|20)\d{2}\b", str(v))
                    if m:
                        years.append(m.group(0))
                if isinstance(v, (dict, list)):
                    walk(v, depth + 1)
        elif isinstance(x, list):
            for v in x[:10]:
                walk(v, depth + 1)
    walk(obj)
    return years[0] if years else ""


def deep_find_first(obj: Any, keys: Iterable[str]) -> str:
    keyset = {k.lower() for k in keys}
    found = ""
    def walk(x: Any, depth: int = 0):
        nonlocal found
        if found or depth > 7:
            return
        if isinstance(x, dict):
            for k, v in x.items():
                if str(k).lower() in keyset and not isinstance(v, (dict, list, bool)):
                    val = norm(v)
                    if val and val.lower() not in {"none", "null", "undefined", "false", "true"}:
                        found = val
                        return
                if isinstance(v, (dict, list)):
                    walk(v, depth + 1)
        elif isinstance(x, list):
            for v in x:
                walk(v, depth + 1)
                if found:
                    return
    walk(obj)
    return found


def deep_video_urls(obj: Any) -> List[Tuple[str, str]]:
    out: List[Tuple[str, str]] = []
    def walk(x: Any, prefix: str = "", depth: int = 0):
        if depth > 8:
            return
        if isinstance(x, dict):
            for k, v in x.items():
                path = f"{prefix}.{k}" if prefix else str(k)
                if isinstance(v, str) and is_video_url(v):
                    out.append((path, v.strip()))
                elif isinstance(v, (dict, list)):
                    walk(v, path, depth + 1)
        elif isinstance(x, list):
            for i, v in enumerate(x[:30]):
                walk(v, f"{prefix}[{i}]", depth + 1)
    walk(obj)
    def score(item: Tuple[str, str]) -> int:
        path, url = item
        low = (path + " " + url).lower()
        s = 0
        if "video-url" in low or "videourl" in low:
            s += 100
        if ".mp4" in low:
            s += 80
        if ".m3u8" in low:
            s += 60
        if "thumbnail" in low or "poster" in low:
            s -= 50
        return -s
    out.sort(key=score)
    return out


def ass_escape(s: str) -> str:
    s = str(s or "")
    return s.replace("\\", r"\\").replace("{", r"\{").replace("}", r"\}").replace("\n", r"\N")


def ass_time(sec: float) -> str:
    sec = max(float(sec), 0.0)
    h = int(sec // 3600)
    m = int((sec % 3600) // 60)
    s = int(sec % 60)
    cs = int(round((sec - int(sec)) * 100))
    if cs >= 100:
        cs = 0
        s += 1
    return f"{h}:{m:02d}:{s:02d}.{cs:02d}"


# ──────────────────────────────────────────────────────────────────────
# Data models
# ──────────────────────────────────────────────────────────────────────
@dataclass
class Clip:
    keyword: str
    text: str
    video_url: str
    title: str = ""
    year: str = ""
    start: str = ""
    end: str = ""
    clip_id: str = ""
    match: int = 0
    zh: str = ""
    local_path: str = ""
    preview_path: str = ""
    checked: bool = False

    def stable_id(self) -> str:
        return self.clip_id or sha1_text(self.video_url + self.text)


# ──────────────────────────────────────────────────────────────────────
# Config / FFmpeg
# ──────────────────────────────────────────────────────────────────────
class ConfigManager:
    def __init__(self, path: Path = CONFIG_FILE):
        self.path = path
        self.data: Dict[str, Any] = {}
        self.load()

    def load(self) -> Dict[str, Any]:
        if self.path.exists():
            try:
                self.data = json.loads(self.path.read_text("utf-8"))
            except Exception:
                self.data = {}
        return self.data

    def save(self) -> None:
        self.path.write_text(json.dumps(self.data, ensure_ascii=False, indent=2), "utf-8")

    def get(self, key: str, default: Any = "") -> Any:
        return self.data.get(key, default)

    def set(self, key: str, value: Any) -> None:
        self.data[key] = value
        self.save()


class FFmpegTools:
    def __init__(self, cfg: ConfigManager, log: Callable[[str, str], None]):
        self.cfg = cfg
        self.log = log
        self._ffmpeg: Optional[str] = None
        self._ffprobe: Optional[str] = None

    def _valid_exe(self, path: str, arg: str = "-version") -> bool:
        if not path:
            return False
        p = Path(path)
        if os.name == "nt" and p.suffix.lower() != ".exe":
            return False
        if not p.exists() or not p.is_file():
            return False
        try:
            r = subprocess.run([str(p), arg], capture_output=True, text=True, timeout=6, **no_window())
            return r.returncode == 0
        except Exception:
            return False

    def _candidates(self, name: str) -> List[str]:
        out: List[str] = []
        cfg_key = "ffmpeg_path" if name == "ffmpeg" else "ffprobe_path"
        cfg_val = norm(self.cfg.get(cfg_key, ""))
        if cfg_val:
            out.append(cfg_val)
        which = shutil.which(name)
        if which:
            out.append(which)
        if os.name == "nt":
            # common locations, including user's known pattern
            roots = [Path("C:/ffmpeg"), Path("D:/ffmpeg"), Path("E:/ffmpeg"), Path("F:/ffmpeg")]
            for root in roots:
                if root.exists():
                    try:
                        out.extend(str(p) for p in root.rglob(f"{name}.exe"))
                    except Exception:
                        pass
        else:
            out.extend([f"/usr/bin/{name}", f"/usr/local/bin/{name}"])
        # unique preserve order
        seen = set(); uniq = []
        for x in out:
            xx = str(x).strip().strip('"')
            if xx and xx not in seen:
                seen.add(xx); uniq.append(xx)
        return uniq

    def resolve(self, name: str) -> Optional[str]:
        cache_attr = "_ffmpeg" if name == "ffmpeg" else "_ffprobe"
        cached = getattr(self, cache_attr)
        if cached:
            return cached
        for cand in self._candidates(name):
            if self._valid_exe(cand):
                setattr(self, cache_attr, str(Path(cand).resolve()))
                return getattr(self, cache_attr)
        return None

    @property
    def ffmpeg(self) -> Optional[str]:
        return self.resolve("ffmpeg")

    @property
    def ffprobe(self) -> Optional[str]:
        return self.resolve("ffprobe")

    def ensure(self) -> bool:
        ff = self.ffmpeg
        fp = self.ffprobe
        if ff and fp:
            self.log(f"FFmpeg OK: {ff}", "ok")
            self.log(f"FFprobe OK: {fp}", "ok")
            return True
        self.log("未找到有效 ffmpeg.exe / ffprobe.exe。请配置 pp_studio_config.json 或加入 PATH。", "err")
        return False

    def run(self, cmd: List[str], label: str, timeout: int = 600) -> subprocess.CompletedProcess:
        try:
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout, **no_window())
            if r.returncode != 0:
                self.log(f"[{label}] FFmpeg失败 returncode={r.returncode}", "err")
                for line in (r.stderr or "").splitlines()[-10:]:
                    self.log("  " + line, "err")
            return r
        except OSError as e:
            self.log(f"[{label}] 执行失败: {type(e).__name__}: {e}", "err")
            self.log("实际命令: " + " ".join(cmd[:3]), "dim")
            raise

    def duration(self, path: Path) -> float:
        fp = self.ffprobe
        if not fp:
            return 3.0
        try:
            r = subprocess.run([fp, "-v", "quiet", "-print_format", "json", "-show_format", str(path)], capture_output=True, text=True, timeout=20, **no_window())
            return float(json.loads(r.stdout or "{}").get("format", {}).get("duration", 3.0))
        except Exception:
            return 3.0

    def has_stream(self, path: Path, kind: str) -> bool:
        fp = self.ffprobe
        if not fp:
            return kind == "video"
        try:
            r = subprocess.run([fp, "-v", "quiet", "-print_format", "json", "-show_streams", str(path)], capture_output=True, text=True, timeout=20, **no_window())
            streams = json.loads(r.stdout or "{}").get("streams", [])
            return any(s.get("codec_type") == kind for s in streams)
        except Exception:
            return False


# ──────────────────────────────────────────────────────────────────────
# Search / Download / Preview
# ──────────────────────────────────────────────────────────────────────
class SearchService:
    def __init__(self, token: str, cookie: str, csrf: str):
        self.session = requests.Session()
        self.session.headers.update(self._headers(token, cookie, csrf))
        if cookie:
            for part in cookie.split(";"):
                if "=" in part:
                    k, v = part.strip().split("=", 1)
                    if k:
                        for dom in (".playphrase.me", "www.playphrase.me", "playphrase.me"):
                            try:
                                self.session.cookies.set(k.strip(), v.strip(), domain=dom)
                            except Exception:
                                pass
        adapter = HTTPAdapter(pool_connections=20, pool_maxsize=20, max_retries=1)
        self.session.mount("https://", adapter)
        self.session.mount("http://", adapter)

    @staticmethod
    def _headers(token: str, cookie: str, csrf: str) -> Dict[str, str]:
        token = norm(token)
        h = {
            "accept": "application/json, text/plain, */*",
            "accept-language": "en-US,en;q=0.9",
            "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/124 Safari/537.36",
            "referer": "https://www.playphrase.me/",
            "origin": "https://www.playphrase.me",
            "cookie": cookie or "",
        }
        if token:
            if token.lower().startswith("token ") or token.lower().startswith("bearer "):
                h["authorization"] = token
            else:
                h["authorization"] = f"Token {token}"
        if csrf:
            h["x-csrf-token"] = csrf
        return h

    def close(self):
        try:
            self.session.close()
        except Exception:
            pass

    def fetch(self, query: str, skip: int, limit: int) -> List[Dict[str, Any]]:
        url = "https://www.playphrase.me/api/v1/phrases/search"
        params = {
            "q": query,
            "limit": limit,
            "skip": skip,
            "language": "en",
            "platform": "desktop safari",
            "hideHardOffensiveIn17Plus": "false",
            "hideExplicitNudityIn17Plus": "false",
        }
        r = self.session.get(url, params=params, timeout=API_TIMEOUT)
        r.raise_for_status()
        data = r.json()
        if isinstance(data, list):
            return data
        if isinstance(data, dict):
            for key in ("results", "phrases", "items", "data", "clips"):
                v = data.get(key)
                if isinstance(v, list):
                    return v
            for v in data.values():
                if isinstance(v, list):
                    return v
        return []

    def parse_item(self, item: Dict[str, Any], query: str) -> Optional[Clip]:
        text = deep_find_first(item, ("text", "phrase", "subtitle", "caption", "line", "body", "words"))
        title = deep_find_first(item, ("title", "movie", "movieTitle", "showTitle", "sourceTitle", "name"))
        # PlayPhrase often uses movie nested object; do not stringify dict as title.
        if title.startswith("{") or title.startswith("["):
            title = ""
        year = extract_year(item)
        start = deep_find_first(item, ("start", "startTime", "clipStart", "time"))
        end = deep_find_first(item, ("end", "endTime", "clipEnd", "next-phrase-start"))
        clip_id = deep_find_first(item, ("id", "clipId", "videoId", "uuid"))
        urls = deep_video_urls(item)
        if not urls:
            return None
        video_url = urls[0][1]
        if not text:
            text = norm(item.get("text", "")) or safe_name(video_url, 50)
        return Clip(keyword=query, text=text, title=title, year=year, start=start, end=end, clip_id=clip_id,
                    video_url=video_url, match=weighted_match(text, query))

    def search_clips(self, query: str, skip: int, limit: int, sensitive_mode: str = "off") -> List[Clip]:
        raw = self.fetch(query, skip, limit)
        clips: List[Clip] = []
        seen = set()
        for item in raw:
            if not isinstance(item, dict):
                continue
            clip = self.parse_item(item, query)
            if not clip or not clip.video_url or clip.video_url in seen:
                continue
            if is_sensitive(clip.text, sensitive_mode):
                continue
            seen.add(clip.video_url)
            clips.append(clip)
        return clips


def is_sensitive(text: str, mode: str) -> bool:
    if mode == "off":
        return False
    words = SENSITIVE_WORDS_STRICT if mode == "strict" else SENSITIVE_WORDS_LIGHT
    low = text.lower()
    return any(re.search(r"\b" + re.escape(w) + r"\b", low) for w in words)


class ClipCache:
    def __init__(self, cache_root: Path, log: Callable[[str, str], None]):
        self.root = cache_root
        self.log = log
        self.root.mkdir(parents=True, exist_ok=True)

    def _headers(self, session: requests.Session, url: str) -> Dict[str, str]:
        return {
            "User-Agent": session.headers.get("user-agent", "Mozilla/5.0"),
            "Accept": "*/*",
            "Accept-Language": "en-US,en;q=0.9",
            "Referer": "https://www.playphrase.me/",
            "Origin": "https://www.playphrase.me",
            "Range": "bytes=0-",
            "Connection": "keep-alive",
            "Cookie": session.headers.get("cookie", ""),
        }

    def path_for(self, clip: Clip) -> Path:
        ext = Path(urlparse(clip.video_url).path).suffix.lower()
        if not ext or len(ext) > 6 or ext == ".m3u8":
            ext = ".mp4"
        return self.root / "clips" / f"{safe_name(clip.keyword, 30)}_{clip.stable_id()}{ext}"

    def ensure_cached(self, clip: Clip, session: requests.Session, ffmpeg: Optional[FFmpegTools] = None) -> Optional[Path]:
        dest = self.path_for(clip)
        if dest.exists() and dest.stat().st_size > 8192:
            clip.local_path = str(dest)
            return dest
        dest.parent.mkdir(parents=True, exist_ok=True)
        url = clip.video_url
        if ".m3u8" in url.lower():
            if not ffmpeg or not ffmpeg.ffmpeg:
                self.log("HLS/m3u8 需要 FFmpeg，但未找到。", "err")
                return None
            header_text = "".join(f"{k}: {v}\r\n" for k, v in self._headers(session, url).items() if v)
            tmp = dest.with_suffix(".tmp.mp4")
            cmd = [ffmpeg.ffmpeg, "-y", "-headers", header_text, "-i", url, "-c", "copy", "-bsf:a", "aac_adtstoasc", str(tmp)]
            r = ffmpeg.run(cmd, f"下载HLS {clip.text[:20]}", 300)
            if r.returncode == 0 and tmp.exists() and tmp.stat().st_size > 8192:
                tmp.replace(dest)
                clip.local_path = str(dest)
                return dest
            return None
        # normal download
        tmp = dest.with_suffix(".tmp")
        try:
            for attempt in range(1, RETRY + 1):
                try:
                    with session.get(url, headers=self._headers(session, url), stream=True, timeout=VIDEO_TIMEOUT, allow_redirects=True) as r:
                        ct = (r.headers.get("content-type") or "").lower()
                        if r.status_code not in (200, 206):
                            self.log(f"下载失败 HTTP {r.status_code}: {url[:100]}", "err")
                            return None
                        if "text/html" in ct or "application/json" in ct:
                            self.log(f"返回不是视频 content-type={ct}", "err")
                            return None
                        with open(tmp, "wb") as f:
                            for chunk in r.iter_content(VIDEO_CHUNK):
                                if chunk:
                                    f.write(chunk)
                        if tmp.exists() and tmp.stat().st_size > 8192:
                            tmp.replace(dest)
                            clip.local_path = str(dest)
                            return dest
                except Exception as e:
                    if attempt == RETRY:
                        self.log(f"缓存失败: {type(e).__name__}: {e}", "err")
                    else:
                        time.sleep(1.2 * attempt)
        finally:
            try:
                tmp.unlink(missing_ok=True)
            except Exception:
                pass
        return None


class PreviewService:
    def __init__(self, ffmpeg: FFmpegTools, cache_root: Path, log: Callable[[str, str], None]):
        self.ffmpeg = ffmpeg
        self.root = cache_root / "previews"
        self.root.mkdir(parents=True, exist_ok=True)
        self.log = log

    def preview_path(self, clip: Clip) -> Path:
        return self.root / f"{clip.stable_id()}.png"

    def ensure_preview(self, clip: Clip) -> Optional[Path]:
        out = self.preview_path(clip)
        if out.exists() and out.stat().st_size > 1024:
            clip.preview_path = str(out)
            return out
        if not clip.local_path:
            return None
        ff = self.ffmpeg.ffmpeg
        if not ff:
            self.log("无法生成预览：未找到 FFmpeg。", "err")
            return None
        src = Path(clip.local_path)
        if not src.exists():
            return None
        dur = max(self.ffmpeg.duration(src), 0.5)
        times = [0.05, 0.25, min(0.75, dur * 0.3), min(dur * 0.5, max(dur - 0.2, 0.05))]
        for t in times:
            cmd = [ff, "-y", "-ss", f"{t:.3f}", "-i", str(src), "-frames:v", "1", "-vf", "scale=620:-2", str(out)]
            r = self.ffmpeg.run(cmd, f"预览帧 {src.name}", 60)
            if r.returncode == 0 and out.exists() and out.stat().st_size > 1024:
                clip.preview_path = str(out)
                return out
        self.log(f"预览帧生成失败：{src.name}", "warn")
        return None


# ──────────────────────────────────────────────────────────────────────
# Player Service: persistent independent Qt player subprocess
# ──────────────────────────────────────────────────────────────────────
QT_PLAYER_HELPER = r'''
import sys, socket, threading, json, os
from pathlib import Path
try:
    from PySide6.QtCore import QObject, Signal, QUrl, Qt
    from PySide6.QtWidgets import QApplication, QMainWindow, QWidget, QVBoxLayout, QLabel
    from PySide6.QtMultimedia import QMediaPlayer, QAudioOutput
    from PySide6.QtMultimediaWidgets import QVideoWidget
except Exception as e:
    print("PY_SIDE6_IMPORT_FAILED", repr(e), flush=True)
    sys.exit(3)

class Bridge(QObject):
    play_signal = Signal(str)
    stop_signal = Signal()

class Win(QMainWindow):
    def __init__(self):
        super().__init__()
        self.setWindowTitle('PlayPhrase Studio Player · 左键重播 / 右键关闭 / Esc关闭')
        self.resize(920, 520)
        self.current_path = '' 
        central = QWidget(); self.setCentralWidget(central)
        layout = QVBoxLayout(central)
        self.video = QVideoWidget(); layout.addWidget(self.video, 1)
        self.label = QLabel('等待播放片段...'); layout.addWidget(self.label)
        self.player = QMediaPlayer(self)
        self.audio = QAudioOutput(self)
        self.audio.setVolume(0.85)
        self.player.setAudioOutput(self.audio)
        self.player.setVideoOutput(self.video)
    def play_path(self, p):
        p = str(Path(p).resolve())
        self.current_path = p
        self.label.setText(p + '    | 左键重播，右键/Esc 关闭')
        self.player.stop()
        self.player.setSource(QUrl.fromLocalFile(p))
        self.player.play()
        self.show(); self.raise_(); self.activateWindow()
    def mousePressEvent(self, event):
        if event.button() == Qt.RightButton:
            self.hide()
        elif event.button() == Qt.LeftButton and self.current_path:
            self.play_path(self.current_path)
    def keyPressEvent(self, event):
        if event.key() == Qt.Key_Escape:
            self.hide()
    def stop(self):
        self.player.stop()


def server_loop(port, bridge):
    srv = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    srv.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    srv.bind(('127.0.0.1', port)); srv.listen(5)
    print('PLAYER_READY', port, flush=True)
    while True:
        conn, _ = srv.accept()
        with conn:
            data = conn.recv(65536).decode('utf-8', errors='ignore')
            if not data: continue
            try:
                msg = json.loads(data)
            except Exception:
                continue
            cmd = msg.get('cmd')
            if cmd == 'play':
                bridge.play_signal.emit(msg.get('path',''))
            elif cmd == 'stop':
                bridge.stop_signal.emit()
            elif cmd == 'quit':
                bridge.stop_signal.emit()
                os._exit(0)


def main():
    if len(sys.argv) < 2:
        print("qt_player_helper must be started by PlayPhrase Studio with a port argument.", flush=True)
        return
    try:
        port = int(sys.argv[1])
    except Exception:
        print("INVALID_PORT", sys.argv[1:] if len(sys.argv) > 1 else [], flush=True)
        return
    app = QApplication(sys.argv)
    win = Win()
    bridge = Bridge()
    bridge.play_signal.connect(win.play_path)
    bridge.stop_signal.connect(win.stop)
    threading.Thread(target=server_loop, args=(port, bridge), daemon=True).start()
    sys.exit(app.exec())

if __name__ == '__main__':
    main()
'''


class PlayerService:
    def __init__(self, log: Callable[[str, str], None]):
        self.log = log
        self.port: Optional[int] = None
        self.proc: Optional[subprocess.Popen] = None
        self.helper_path = Path(tempfile.gettempdir()) / "pp_studio_qt_player.py"

    def _free_port(self) -> int:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.bind(("127.0.0.1", 0))
        port = s.getsockname()[1]
        s.close()
        return port

    def _bundled_helper_exe(self) -> Optional[Path]:
        """Return qt_player_helper.exe when running from a packaged release.

        After PyInstaller packaging, sys.executable points to the main app exe,
        so the app cannot launch qt_player_helper.py through sys.executable.
        The Qt helper must be a separate qt_player_helper.exe placed next to
        the main exe or inside the PyInstaller _internal folder.
        """
        candidates: List[Path] = []
        try:
            if getattr(sys, "frozen", False):
                base = Path(sys.executable).resolve().parent
            else:
                base = Path(__file__).resolve().parent
            candidates.extend([
                base / "qt_player_helper.exe",
                base / "_internal" / "qt_player_helper.exe",
                Path.cwd() / "qt_player_helper.exe",
            ])
        except Exception:
            pass
        for c in candidates:
            try:
                if c.exists() and c.is_file():
                    return c
            except Exception:
                pass
        return None

    def _helper_command(self) -> List[str]:
        helper_exe = self._bundled_helper_exe()
        if helper_exe is not None:
            return [str(helper_exe), str(self.port)]
        self.helper_path.write_text(QT_PLAYER_HELPER, "utf-8")
        return [sys.executable, str(self.helper_path), str(self.port)]

    def _ensure_server(self) -> bool:
        if self.proc and self.proc.poll() is None and self.port:
            return True
        self.port = self._free_port()
        try:
            cmd = self._helper_command()
            # Do NOT use no_window() here. The black flicker is caused by
            # FFmpeg/ffprobe subprocesses, not by the Qt helper. Hiding this
            # process can make IPC startup unstable in some PyInstaller builds.
            self.proc = subprocess.Popen(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                text=True,
            )
            deadline = time.time() + 8.0
            last_err = ""
            while time.time() < deadline:
                if self.proc.poll() is not None:
                    out = ""
                    try:
                        out = self.proc.stdout.read() if self.proc.stdout else ""
                    except Exception:
                        pass
                    self.log("Qt 播放窗口启动失败，降级系统播放器。" + (" " + out[:500] if out else ""), "warn")
                    return False
                try:
                    with socket.create_connection(("127.0.0.1", self.port), timeout=0.5):
                        self.log("Qt 播放窗口已启动；后续会复用同一窗口切换片段。", "ok")
                        return True
                except Exception as e:
                    last_err = str(e)
                    time.sleep(0.15)
            self.log(f"Qt 播放窗口启动超时，降级系统播放器。last={last_err}", "warn")
            return False
        except Exception as e:
            self.log(f"Qt 播放窗口不可用：{type(e).__name__}: {e}", "warn")
            return False

    def _send(self, msg: Dict[str, Any]) -> bool:
        if not self.port:
            return False
        deadline = time.time() + 5.0
        last_err: Optional[Exception] = None
        while time.time() < deadline:
            try:
                if self.proc and self.proc.poll() is not None:
                    out = ""
                    try:
                        out = self.proc.stdout.read() if self.proc.stdout else ""
                    except Exception:
                        pass
                    self.log("播放窗口已退出，降级系统播放器。" + (" " + out[:300] if out else ""), "warn")
                    return False
                with socket.create_connection(("127.0.0.1", self.port), timeout=1.0) as sock:
                    sock.settimeout(2.0)
                    sock.sendall(json.dumps(msg).encode("utf-8"))
                return True
            except Exception as e:
                last_err = e
                time.sleep(0.15)
        self.log(f"播放窗口通信失败：{last_err}", "warn")
        return False

    def play(self, path: Path) -> None:
        if not path or not path.exists():
            self.log("播放失败：本地缓存文件不存在。", "err")
            return
        if self._ensure_server():
            if self._send({"cmd": "play", "path": str(path)}):
                return
        # fallback
        self.log("降级：用系统播放器打开。", "warn")
        try:
            if os.name == "nt":
                os.startfile(str(path))  # type: ignore[attr-defined]
            elif sys.platform == "darwin":
                subprocess.Popen(["open", str(path)])
            else:
                subprocess.Popen(["xdg-open", str(path)])
        except Exception as e:
            self.log(f"系统播放器打开失败：{e}", "err")

    def close(self):
        try:
            if self.proc and self.proc.poll() is None and self.port:
                self._send({"cmd": "quit"})
        except Exception:
            pass


