# Translation / Subtitle / Render
# ──────────────────────────────────────────────────────────────────────
class TranslateService:
    def __init__(self, log: Callable[[str, str], None]):
        self.log = log
        self.argos_engine = None
        self.config = self._load_config()

    def _load_config(self) -> Dict[str, Any]:
        data: Dict[str, Any] = {}
        if TRANSLATION_CONFIG_FILE.exists():
            try:
                data = json.loads(TRANSLATION_CONFIG_FILE.read_text("utf-8"))
            except Exception:
                data = {}
        # Environment override names only, not hardcoding user's secrets.
        data.setdefault("tencent_id", os.getenv("TENCENT_ID", ""))
        data.setdefault("tencent_key", os.getenv("TENCENT_KEY", ""))
        data.setdefault("baidu_id", os.getenv("BAIDU_ID", ""))
        data.setdefault("baidu_key", os.getenv("BAIDU_KEY", ""))
        return data

    def _argos(self, text: str) -> str:
        if not ARGOS_OK:
            return ""
        try:
            if not self.argos_engine:
                langs = _argos.get_installed_languages()
                en = next((l for l in langs if getattr(l, "code", "") == "en"), None)
                zh = next((l for l in langs if getattr(l, "code", "") == "zh"), None)
                if not en or not zh:
                    return ""
                self.argos_engine = en.get_translation(zh)
            return self.argos_engine.translate(text)
        except Exception:
            return ""

    def translate_one(self, text: str, engine: str) -> str:
        text = norm(text)
        if not text or engine == "none":
            return ""
        # Small correction table for common subtitle idioms; user can extend via translation_overrides.csv.
        corr = {
            "there's nothing to be done.": "没什么可做的了。",
            "i'm only trying to help you.": "我只是想帮你。",
            "cat got your tongue?": "怎么不说话了？",
        }
        if text.lower() in corr:
            return corr[text.lower()]
        if engine in ("argos", "auto"):
            z = self._argos(text)
            if z:
                return z
        # API engines intentionally omitted from source to avoid secret handling and unstable signatures.
        # Fallback: empty, allowing manual editing/export.
        return ""

    def batch_translate(self, clips: List[Clip], engine: str) -> None:
        # manual = use the zh field already imported/edited in SelectionPool.
        # Never overwrite manual Chinese translations during render.
        if engine in ("none", "manual"):
            return
        for c in clips:
            if not c.zh:
                c.zh = self.translate_one(c.text, engine)


class SubtitleService:
    def __init__(self):
        pass

    def _karaoke_text(self, text: str, duration_sec: float) -> str:
        # \\kf: fill from left to right. ASS uses SecondaryColour as base and PrimaryColour as filled colour.
        tokens = [t for t in re.split(r"(\s+)", text.strip()) if t != ""]
        if not tokens:
            return ass_escape(text)
        word_count = max(len([t for t in tokens if not t.isspace()]), 1)
        total_cs = max(int(round(duration_sec * 100)), word_count)
        each = max(1, total_cs // word_count)
        out = []
        for t in tokens:
            if t.isspace():
                out.append(t)
            else:
                out.append("{\\kf%d}%s" % (each, ass_escape(t)))
        return "".join(out)

    def _keyword_highlight(self, text: str, keyword: str, color: str = "red") -> str:
        body = ass_escape(text)
        kw = norm(keyword)
        if not kw:
            return body
        col = ASS_COLOR.get(color, ASS_COLOR["red"])
        white = ASS_COLOR["white"]
        pattern = re.compile(re.escape(kw), re.I)
        return pattern.sub(lambda m: "{\\c%s\\b1}%s{\\c%s\\b0}" % (col, ass_escape(m.group(0)), white), body)

    def make_ass(self, clips: List[Clip], out_path: Path, resolution: str,
                 subtitle_mode: str, style: str, font_size: int,
                 en_base: str, en_cover: str, zh_base: str, zh_cover: str,
                 keyword_color: str = "red") -> Path:
        w, h = parse_resolution(resolution)
        # Positions: English above Chinese, no overlap.
        en_margin = 180 if h >= w else 85
        zh_margin = 105 if h >= w else 38
        outline = 2
        en_primary = ASS_COLOR.get(en_cover if en_cover != "white" else en_base, ASS_COLOR["white"])
        en_secondary = ASS_COLOR.get(en_base, ASS_COLOR["white"])
        zh_primary = ASS_COLOR.get(zh_cover if zh_cover != "white" else zh_base, ASS_COLOR["white"])
        zh_secondary = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
        static_en = ASS_COLOR.get(en_base, ASS_COLOR["white"])
        static_zh = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
        fs_zh = max(22, int(font_size * 0.78))
        header = f"""[Script Info]\nScriptType: v4.00+\nPlayResX: {w}\nPlayResY: {h}\nScaledBorderAndShadow: yes\nWrapStyle: 2\n\n[V4+ Styles]\nFormat: Name,Fontname,Fontsize,PrimaryColour,SecondaryColour,OutlineColour,BackColour,Bold,Italic,Underline,StrikeOut,ScaleX,ScaleY,Spacing,Angle,BorderStyle,Outline,Shadow,Alignment,MarginL,MarginR,MarginV,Encoding\nStyle: EnStatic,Microsoft YaHei,{font_size},{static_en},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,60,60,{en_margin},1\nStyle: ZhStatic,Microsoft YaHei,{fs_zh},{static_zh},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,60,60,{zh_margin},1\nStyle: EnKaraoke,Microsoft YaHei,{font_size},{en_primary},{en_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,60,60,{en_margin},1\nStyle: ZhKaraoke,Microsoft YaHei,{fs_zh},{zh_primary},{zh_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,60,60,{zh_margin},1\n\n[Events]\nFormat: Layer,Start,End,Style,Name,MarginL,MarginR,MarginV,Effect,Text\n"""
        lines = [header]
        cur = 0.0
        for c in clips:
            dur = 2.0
            try:
                # duration may be stored in render prefill via local path later; fallback 2 sec.
                pass
            except Exception:
                pass
            if c.local_path and Path(c.local_path).exists():
                # RenderService will set actual durations before calling when possible; keep fallback here.
                pass
            start = cur
            end = cur + max(getattr(c, "_render_duration", 2.0), 0.6)
            cur = end
            en = c.text
            zh = c.zh
            if subtitle_mode == "none":
                continue
            if style == "keyword_highlight":
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{self._keyword_highlight(en, c.keyword, keyword_color)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{ass_escape(zh)}\n")
            elif style in ("en_karaoke_yellow", "en_karaoke_orange"):
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{self._karaoke_text(en, end-start)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{ass_escape(zh)}\n")
            elif style == "bilingual_karaoke":
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{self._karaoke_text(en, end-start)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{self._karaoke_text(zh, end-start)}\n")
            else:
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{ass_escape(en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{ass_escape(zh)}\n")
        out_path.write_text("".join(lines), "utf-8-sig")
        return out_path


class RenderService:
    def __init__(self, ffmpeg: FFmpegTools, subtitle: SubtitleService, log: Callable[[str, str], None]):
        self.ffmpeg = ffmpeg
        self.subtitle = subtitle
        self.log = log

    def _concat_line(self, p: Path) -> str:
        s = str(p.resolve()).replace("\\", "/").replace("'", "'\\''")
        return f"file '{s}'"

    def _std_clip(self, src: Path, dst: Path, resolution: str) -> bool:
        ff = self.ffmpeg.ffmpeg
        if not ff:
            self.log("合成失败：未找到 FFmpeg。", "err")
            return False
        w, h = parse_resolution(resolution)
        dur = max(self.ffmpeg.duration(src), 0.5)
        has_audio = self.ffmpeg.has_stream(src, "audio")
        vchain = f"setpts=PTS-STARTPTS,fps=30,scale={w}:{h}:force_original_aspect_ratio=decrease,pad={w}:{h}:(ow-iw)/2:(oh-ih)/2,setsar=1,format=yuv420p"
        if has_audio:
            fc = f"[0:v:0]{vchain}[v];[0:a:0]asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,aformat=sample_fmts=fltp:sample_rates=44100:channel_layouts=stereo,apad=whole_dur={dur:.3f}[a]"
            cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts", "-i", str(src), "-filter_complex", fc, "-map", "[v]", "-map", "[a]", "-t", f"{dur:.3f}", "-c:v", "libx264", "-crf", "23", "-preset", "veryfast", "-c:a", "aac", "-b:a", "128k", "-ar", "44100", "-ac", "2", "-movflags", "+faststart", str(dst)]
        else:
            fc = f"[0:v:0]{vchain}[v];[1:a:0]asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,aformat=sample_fmts=fltp:sample_rates=44100:channel_layouts=stereo[a]"
            cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts", "-i", str(src), "-f", "lavfi", "-t", f"{dur:.3f}", "-i", "anullsrc=channel_layout=stereo:sample_rate=44100", "-filter_complex", fc, "-map", "[v]", "-map", "[a]", "-t", f"{dur:.3f}", "-c:v", "libx264", "-crf", "23", "-preset", "veryfast", "-c:a", "aac", "-b:a", "128k", "-ar", "44100", "-ac", "2", "-movflags", "+faststart", str(dst)]
        r = self.ffmpeg.run(cmd, f"标准化 {src.name}", 240)
        return r.returncode == 0 and dst.exists() and dst.stat().st_size > 8192

    def render(self, clips: List[Clip], out_dir: Path, name: str, options: Dict[str, Any]) -> Optional[Path]:
        if not clips:
            self.log("精选池为空，无法渲染。", "warn")
            return None
        if not self.ffmpeg.ensure():
            return None
        out_dir.mkdir(parents=True, exist_ok=True)
        work = out_dir / f"_work_{safe_name(name)}_{now_str()}"
        work.mkdir(parents=True, exist_ok=True)
        resolution = options.get("resolution", "1080x1920")
        std_files: List[Path] = []
        for i, c in enumerate(clips, 1):
            if not c.local_path or not Path(c.local_path).exists():
                self.log(f"跳过未缓存片段：{c.text[:40]}", "warn")
                continue
            src = Path(c.local_path)
            c._render_duration = self.ffmpeg.duration(src)  # dynamic attribute used by SubtitleService
            dst = work / f"std_{i:04d}.mp4"
            if self._std_clip(src, dst, resolution):
                std_files.append(dst)
                self.log(f"标准化 {i}/{len(clips)} OK: {src.name}", "dim")
            else:
                self.log(f"标准化失败：{src}", "err")
        if not std_files:
            return None
        concat = work / "concat.txt"
        concat.write_text("\n".join(self._concat_line(p) for p in std_files), "utf-8")
        merged = work / "merged_no_sub.mp4"
        ff = self.ffmpeg.ffmpeg
        cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts", "-f", "concat", "-safe", "0", "-i", str(concat), "-map", "0:v:0", "-map", "0:a:0?", "-vf", "setpts=PTS-STARTPTS,fps=30,format=yuv420p", "-af", "asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-c:a", "aac", "-b:a", "128k", "-movflags", "+faststart", str(merged)]
        r = self.ffmpeg.run(cmd, "concat合并", 900)
        if r.returncode != 0 or not merged.exists():
            return None
        out_path = out_dir / f"{safe_name(name)}_merged.mp4"
        subtitle_mode = options.get("subtitle_mode", "bilingual")
        if subtitle_mode == "none":
            shutil.move(str(merged), str(out_path))
        else:
            ass = out_dir / f"{safe_name(name)}.ass"
            self.subtitle.make_ass(clips, ass, resolution, subtitle_mode,
                                   options.get("subtitle_style", "static"),
                                   int(options.get("font_size", 42)),
                                   options.get("en_base", "white"), options.get("en_cover", "white"),
                                   options.get("zh_base", "white"), options.get("zh_cover", "yellow"),
                                   options.get("keyword_color", "red"))
            ass_path = str(ass.resolve()).replace("\\", "/")
            ass_path = re.sub(r"([A-Za-z]):/", r"\1\\:/", ass_path)
            cmd2 = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(merged), "-vf", f"ass='{ass_path}'", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-c:a", "copy", str(out_path)]
            r2 = self.ffmpeg.run(cmd2, "字幕烧录", 900)
            if r2.returncode != 0 or not out_path.exists():
                self.log("字幕烧录失败，降级输出无字幕版。", "warn")
                shutil.move(str(merged), str(out_path))
        if not options.get("keep_clips", False):
            # only clean work dir, keep cache by default for preview reuse.
            shutil.rmtree(work, ignore_errors=True)
        self.log(f"渲染完成：{out_path}", "ok")
        return out_path


class TextExportService:
    def export(self, clips: List[Clip], path: Path, fmt: str) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        if fmt == "txt":
            lines = []
            for c in clips:
                lines.append(c.text)
                if c.zh:
                    lines.append(c.zh)
                lines.append("")
            path.write_text("\n".join(lines), "utf-8")
        elif fmt == "csv":
            with open(path, "w", encoding="utf-8-sig", newline="") as f:
                w = csv.writer(f)
                w.writerow(["keyword", "text", "zh", "title", "year", "match", "video_url"])
                for c in clips:
                    w.writerow([c.keyword, c.text, c.zh, c.title, c.year, c.match, c.video_url])
        else:
            rows = []
            for c in clips:
                rows.append(f"<tr><td>{html.escape(c.keyword)}</td><td>{html.escape(c.text)}</td><td>{html.escape(c.zh)}</td><td>{html.escape(c.title)}</td><td>{html.escape(c.year)}</td><td>{c.match}</td></tr>")
            body = "<html><meta charset='utf-8'><body><table border='1' cellspacing='0' cellpadding='6'><tr><th>keyword</th><th>text</th><th>zh</th><th>title</th><th>year</th><th>match</th></tr>" + "\n".join(rows) + "</table></body></html>"
            path.write_text(body, "utf-8")


# ──────────────────────────────────────────────────────────────────────
# UI Application
# ──────────────────────────────────────────────────────────────────────
class MainApp(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title(APP_TITLE)
        self.stop_event = threading.Event()
        self.batch_stop_event = threading.Event()
        self.text_results: List[Clip] = []
        self.text_state: Dict[str, int] = {"pages": 0, "total": 0, "skip": 0, "last": 0, "limit": 20}
        self.geometry("1520x920")
        self.minsize(1240, 780)
        self.cfg = ConfigManager()
        self.current_theme_name = self.cfg.get("ui_theme", "01 鎏金深夜")
        self._apply_theme_globals(self.current_theme_name, save=False)
        self.configure(bg=C_BG)
        self.log_q: "queue.Queue[Tuple[str,str]]" = queue.Queue()
        self.ui_q: "queue.Queue[Tuple[str,Any]]" = queue.Queue()
        self.ffmpeg = FFmpegTools(self.cfg, self.log)
        self.cache = ClipCache(CACHE_ROOT, self.log)
        self.preview = PreviewService(self.ffmpeg, CACHE_ROOT, self.log)
        self.player = PlayerService(self.log)
        self.translator = TranslateService(self.log)
        self.subtitle = SubtitleService()
        self.renderer = RenderService(self.ffmpeg, self.subtitle, self.log)
        self.exporter = TextExportService()
        self.results: List[Clip] = []
        self.pool: List[Clip] = []
        self.keyword_state: Dict[str, Dict[str, int]] = {}
        self.current_keyword: str = ""
        self.photo_ref: Optional[tk.PhotoImage] = None
        self._build_style()
        self._build_ui()
        self._load_config_to_ui()
        self.after(100, self._poll)
        self.protocol("WM_DELETE_WINDOW", self._on_close)

    # ── style/UI basics ───────────────────────────────────────────────
    def _apply_theme_globals(self, theme_name: str, save: bool = True):
        """Apply selected theme to global palette used by this single-file app."""
        global C_BG, C_PANEL, C_CARD, C_CARD2, C_BORDER, C_FG, C_DIM, C_AMBER
        global C_BLUE, C_GREEN, C_RED, C_CYAN, C_PURPLE
        if theme_name not in THEME_PRESETS:
            theme_name = "01 鎏金深夜"
        p = THEME_PRESETS[theme_name]
        C_BG = p["bg"]
        C_PANEL = p["panel"]
        C_CARD = p["card"]
        C_CARD2 = p["card2"]
        C_BORDER = p["border"]
        C_FG = p["fg"]
        C_DIM = p["dim"]
        C_AMBER = p["accent"]
        C_BLUE = p["blue"]
        C_GREEN = p["green"]
        C_RED = p["red"]
        C_CYAN = p["cyan"]
        C_PURPLE = p["purple"]
        self.current_theme_name = theme_name
        if save:
            try:
                self.cfg.set("ui_theme", theme_name)
            except Exception:
                pass

    def _build_style(self):
        p = THEME_PRESETS.get(getattr(self, "current_theme_name", "01 鎏金深夜"), THEME_PRESETS["01 鎏金深夜"])
        s = ttk.Style(self)
