    def _repaint_widget_tree(self, w=None):
        """Best-effort repaint for existing tk widgets after theme switch."""
        if w is None:
            w = self
        try:
            cls = w.winfo_class()
        except Exception:
            cls = ""
        try:
            if isinstance(w, tk.Tk):
                w.configure(bg=C_BG)
            elif isinstance(w, tk.Frame):
                # Topbar and major panels keep panel/card hints when possible.
                bg = C_CARD if str(w).lower().endswith("card") else C_BG
                w.configure(bg=bg)
            elif isinstance(w, tk.PanedWindow):
                w.configure(bg=C_BG, sashrelief="flat")
            elif isinstance(w, tk.Label):
                txt = str(w.cget("text"))
                fg = C_AMBER if any(k in txt for k in ["▶", "关键词", "精选", "渲染", "设置", "日志", "导出", "大预览"]) else C_FG
                w.configure(bg=C_BG, fg=fg)
            elif isinstance(w, tk.Text):
                w.configure(bg=C_CARD, fg=C_FG, insertbackground=C_FG, selectbackground=THEME_PRESETS[self.current_theme_name].get("select_bg", C_BORDER))
            elif isinstance(w, tk.Listbox):
                w.configure(bg=C_CARD, fg=C_FG, selectbackground=THEME_PRESETS[self.current_theme_name].get("select_bg", C_BORDER), selectforeground="#ffffff")
            elif isinstance(w, tk.Canvas):
                w.configure(bg=C_CARD, highlightbackground=C_BORDER)
        except Exception:
            pass
        for child in getattr(w, "winfo_children", lambda: [])():
            self._repaint_widget_tree(child)

    def _on_theme_change(self, event=None):
        name = self.theme_var.get() if hasattr(self, "theme_var") else self.current_theme_name
        self._apply_theme_globals(name, save=True)
        self._build_style()
        self._repaint_widget_tree()
        try:
            self.theme_badge.configure(bg=C_CARD2, fg=C_AMBER, text=f"主题：{name}")
        except Exception:
            pass
        self.log(f"主题已切换：{name}", "ok")

