        self.sensitive_cb.pack(anchor="w", pady=5)
        self.limit_var = tk.IntVar(value=20)
        ttk.Label(left, text="每页数量", style="Dim.TLabel").pack(anchor="w")
        ttk.Spinbox(left, from_=5, to=50, textvariable=self.limit_var, width=8).pack(anchor="w")

        # Middle result panel
        top_mid = tk.Frame(mid, bg=C_BG); top_mid.pack(fill="x")
