        ttk.Button(top_mid, text="加载更多", command=self._search_current_more).pack(side="left", padx=3)
        ttk.Button(top_mid, text="加载全部当前", command=self._search_current_all).pack(side="left", padx=3)
        ttk.Button(top_mid, text="批量搜索全部关键词", command=self._search_all_keywords).pack(side="left", padx=3)
        ttk.Button(top_mid, text="终止", command=self._stop_current_tasks).pack(side="left", padx=3)
        ttk.Button(top_mid, text="清空搜索结果", command=self._clear_search_results).pack(side="left", padx=3)
        self.auto_play_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(top_mid, text="选中后自动播放", variable=self.auto_play_var).pack(side="left", padx=10)
        self.status_var = tk.StringVar(value="未搜索")
        ttk.Label(mid, textvariable=self.status_var, style="Dim.TLabel").pack(fill="x", pady=(6, 4))
