def _refresh_text_results_v8(self):
    self.text_tree.delete(*self.text_tree.get_children())
    for i, c in enumerate(self.text_results):
        # v8: pure text table intentionally hides video-url.
        self.text_tree.insert("", "end", iid=str(i), values=(c.keyword, c.match, c.year, c.text, c.title))
    self._text_update_status()


def _on_text_result_select_v8(self, event=None):
    if not hasattr(self, 'text_detail'):
        return
    sel = self.text_tree.selection()
    if not sel:
        return
    try:
        c = self.text_results[int(sel[0])]
    except Exception:
        return
    self.text_detail.delete("1.0", "end")
    self.text_detail.insert("end", c.text)
    if hasattr(self, 'text_translation_box'):
        self.text_translation_box.delete("1.0", "end")
        if c.zh:
            self.text_translation_box.insert("end", c.zh)


def _text_selected_clip_v8(self) -> Optional[Clip]:
    try:
        sel = self.text_tree.selection()
        if sel:
            return self.text_results[int(sel[0])]
    except Exception:
        return None
    return None


def _text_detail_selection_v8(self) -> str:
    if hasattr(self, 'text_detail'):
        try:
            s = self.text_detail.get("sel.first", "sel.last")
            if norm(s):
                return norm(s)
        except Exception:
            pass
        s = self.text_detail.get("1.0", "end")
        if norm(s):
            return norm(s)
    c = self._text_selected_clip()
    return c.text if c else ""


def _copy_text_detail_selection_v8(self):
    s = self._text_detail_selection()
    self._copy_to_clipboard(s, "选中词/短语/句子")


def _translate_text_selection_v8(self):
    s = self._text_detail_selection()
    if not s:
        messagebox.showwarning("提示", "请先选择台词，或在台词详情中框选单词/短语/句子。")
        return
    z = self.translator.translate_one(s, "auto")
    if not z:
        z = "（本地翻译未返回结果。可配置 Argos/在线翻译。）"
    if hasattr(self, 'text_translation_box'):
        self.text_translation_box.delete("1.0", "end")
        self.text_translation_box.insert("end", z)
    c = self._text_selected_clip()
    if c and s == c.text:
        c.zh = z
    self.log(f"[纯文本翻译] {s} -> {z}", "ok")


def _send_text_selection_to_ai_v8(self):
    s = self._text_detail_selection()
    if not s:
        messagebox.showwarning("提示", "请先选择台词，或在台词详情中框选单词/短语/句子。")
        return
    if not hasattr(self, 'ai_input'):
        messagebox.showwarning("提示", "AI互动学习页尚未初始化。")
        return
    self.ai_input.delete("1.0", "end")
    self.ai_input.insert("end", s)
    try:
        self.nb.select(self.tab_ai)
    except Exception:
        pass
    self.ai_status_var.set("已接收纯文本模式发送的内容，可选择模板后打开 AI 平台。")


def _show_text_copy_menu_v8(self, event):
    row = self.text_tree.identify_row(event.y)
    if row:
        self.text_tree.selection_set(row)
        self._on_text_result_select()
    menu = tk.Menu(self, tearoff=0)
    menu.add_command(label="复制选中台词", command=self._copy_selected_text_lines)
    menu.add_command(label="复制台词详情中框选内容", command=self._copy_text_detail_selection)
    menu.add_command(label="翻译选中/当前台词", command=self._translate_text_selection)
    menu.tk_popup(event.x_root, event.y_root)


def _ai_current_prompt_v8(self) -> str:
    raw = norm(self.ai_input.get("1.0", "end")) if hasattr(self, 'ai_input') else ""
    label = self.ai_template_var.get() if hasattr(self, 'ai_template_var') else AI_PROMPT_TEMPLATES_V8[0][0]
    tpl = next((t for k, t in AI_PROMPT_TEMPLATES_V8 if k == label), "{text}")
    return tpl.replace("{text}", raw)


def _copy_ai_prompt_v8(self):
    prompt = self._ai_current_prompt()
    self._copy_to_clipboard(prompt, "AI提示词")
    if hasattr(self, 'ai_status_var'):
        self.ai_status_var.set("已复制 AI 提示词到剪贴板。")


def _open_ai_provider_v8(self, name: str, url: str):
    prompt = self._ai_current_prompt()
    if not norm(prompt):
        messagebox.showwarning("提示", "请先输入或导入要查询的内容。")
        return
    self._copy_to_clipboard(prompt, f"{name} AI提示词")
    try:
        _webbrowser_v8.open(url)
        if hasattr(self, 'ai_status_var'):
            self.ai_status_var.set(f"已复制提示词并打开 {name}。进入网页后直接粘贴即可；登录状态由浏览器保存。")
        self.log(f"[AI互动] 已打开 {name}：{url}", "ok")
    except Exception as e:
        messagebox.showerror("打开失败", str(e))


def _ai_paste_clipboard_v8(self):
    try:
        s = self.clipboard_get()
    except Exception:
        s = ""
    if s:
        self.ai_input.insert("end", s)


def _ai_import_docs_v8(self):
    files = filedialog.askopenfilenames(title="导入文档/文本", filetypes=[("Text/Markdown/CSV", "*.txt *.md *.csv *.srt"), ("All", "*.*")])
    if not files:
        return
    parts = []
    for f in files:
        try:
            p = Path(f)
            parts.append(f"\n\n===== {p.name} =====\n")
            parts.append(p.read_text("utf-8-sig", errors="ignore"))
        except Exception as e:
            parts.append(f"\n[读取失败 {f}: {e}]\n")
    self.ai_input.insert("end", "".join(parts))
    self.ai_status_var.set(f"已导入 {len(files)} 个文件。")


# bind v8 clean overrides before MainApp starts
MainApp._build_ui = _build_ui_v8
MainApp._build_export = _build_export_v8
MainApp._build_ai = _build_ai_v8
MainApp._refresh_text_results = _refresh_text_results_v8
MainApp._on_text_result_select = _on_text_result_select_v8
MainApp._text_selected_clip = _text_selected_clip_v8
MainApp._text_detail_selection = _text_detail_selection_v8
MainApp._copy_text_detail_selection = _copy_text_detail_selection_v8
MainApp._translate_text_selection = _translate_text_selection_v8
MainApp._send_text_selection_to_ai = _send_text_selection_to_ai_v8
MainApp._show_text_copy_menu = _show_text_copy_menu_v8
MainApp._ai_current_prompt = _ai_current_prompt_v8
MainApp._copy_ai_prompt = _copy_ai_prompt_v8
MainApp._open_ai_provider = _open_ai_provider_v8
MainApp._ai_paste_clipboard = _ai_paste_clipboard_v8
MainApp._ai_import_docs = _ai_import_docs_v8



