APP_TITLE = "PlayPhrase Studio Clean v10 · AI内嵌 / 同步增强 / 手动渲染增强"

# Extend subtitle style labels if missing.
def _ensure_option(options, label, value):
    if not any(v == value or k == label for k, v in options):
        options.append((label, value))

_ensure_option(SUBTITLE_STYLE_OPTIONS, "关键词高亮 + 双滚动字幕", "keyword_dual_roll")

class RenderServiceV10(RenderServiceV9):
    """More deterministic renderer for selected/manual/batch render.

    Main changes:
    - use video-stream duration when available;
    - after standardization, assign exact cumulative subtitle start/end for each clip;
    - trim final subtitle end to merged video duration;
    - use final A/V re-encode for subtitle burn, no audio copy.
    """
    def _video_duration(self, path: Path) -> float:
        fp = self.ffmpeg.ffprobe
        if not fp:
            return self.ffmpeg.duration(path)
        try:
            cmd = [fp, "-v", "error", "-select_streams", "v:0", "-show_entries", "stream=duration", "-of", "default=noprint_wrappers=1:nokey=1", str(path)]
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=20, **no_window())
            s = (r.stdout or "").strip().splitlines()
            if s and s[0] and s[0].lower() != "n/a":
                return float(s[0])
        except Exception:
            pass
        return self.ffmpeg.duration(path)

    def _std_clip(self, src: Path, dst: Path, resolution: str) -> bool:
        ff = self.ffmpeg.ffmpeg
        if not ff:
            self.log("合成失败：未找到 FFmpeg。", "err")
            return False
        w, h = parse_resolution(resolution)
        dur = max(self._video_duration(src), 0.5)
        if dur > 1200:
            dur = min(max(self.ffmpeg.duration(src), 0.5), 1200)
        has_audio = self.ffmpeg.has_stream(src, "audio")
        vchain = (
            "setpts=PTS-STARTPTS,"
            "fps=30,"
            f"scale={w}:{h}:force_original_aspect_ratio=decrease,"
            f"pad={w}:{h}:(ow-iw)/2:(oh-ih)/2,"
            "setsar=1,format=yuv420p"
        )
        common = ["-fps_mode", "cfr", "-r", "30", "-c:v", "libx264", "-crf", "23", "-preset", "veryfast",
                  "-pix_fmt", "yuv420p", "-g", "60", "-keyint_min", "60", "-sc_threshold", "0",
                  "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
                  "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero",
                  "-muxdelay", "0", "-muxpreload", "0", "-movflags", "+faststart"]
        if has_audio:
            fc = (
                f"[0:v:0]{vchain}[v];"
                f"[0:a:0]asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,"
                f"aformat=sample_fmts=fltp:sample_rates=48000:channel_layouts=stereo,"
                f"apad=whole_dur={dur:.3f}[a]"
            )
            cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts",
                   "-i", str(src), "-filter_complex", fc, "-map", "[v]", "-map", "[a]", "-t", f"{dur:.3f}"] + common + [str(dst)]
        else:
            fc = (
                f"[0:v:0]{vchain}[v];"
                f"[1:a:0]asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,"
                f"aformat=sample_fmts=fltp:sample_rates=48000:channel_layouts=stereo[a]"
            )
            cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts",
                   "-i", str(src), "-f", "lavfi", "-t", f"{dur:.3f}", "-i", "anullsrc=channel_layout=stereo:sample_rate=48000",
                   "-filter_complex", fc, "-map", "[v]", "-map", "[a]", "-t", f"{dur:.3f}"] + common + [str(dst)]
        r = self.ffmpeg.run(cmd, f"标准化同步V10 {src.name}", 360)
        return r.returncode == 0 and dst.exists() and dst.stat().st_size > 8192

    def render(self, clips: List[Clip], out_dir: Path, name: str, options: Dict[str, Any]) -> Optional[Path]:
        if not clips:
            self.log("没有片段，无法渲染。", "warn")
            return None
        if not self.ffmpeg.ensure():
            return None
        out_dir.mkdir(parents=True, exist_ok=True)
        work = out_dir / f"_sync_v10_{safe_name(name)}_{now_str()}"
        work.mkdir(parents=True, exist_ok=True)
        resolution = options.get("resolution", "1080x1920")
        prepared: List[Clip] = []
        std_files: List[Path] = []
        cursor = 0.0
        for i, c in enumerate(clips, 1):
            if not c.local_path or not Path(c.local_path).exists():
                self.log(f"跳过未缓存片段：{c.text[:50]}", "warn")
                continue
            src = Path(c.local_path)
            dst = work / f"std_{i:04d}.mp4"
            if not self._std_clip(src, dst, resolution):
                self.log(f"标准化失败：{src}", "err")
                continue
            std_dur = max(self._video_duration(dst), 0.5)
            c._render_start = cursor
            c._render_duration = std_dur
            c._render_end = cursor + std_dur
            cursor += std_dur
            prepared.append(c)
            std_files.append(dst)
            self.log(f"标准化 {i}/{len(clips)} OK: {src.name} | {std_dur:.2f}s", "dim")
        if not std_files:
            self.log("没有可合成的标准化片段。", "err")
            return None
        concat = work / "concat.txt"
        concat.write_text("\n".join(self._concat_line(p) for p in std_files), "utf-8")
        merged = work / "merged_no_sub.mp4"
        ff = self.ffmpeg.ffmpeg
        cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts",
               "-f", "concat", "-safe", "0", "-i", str(concat),
               "-map", "0:v:0", "-map", "0:a:0?",
               "-vf", "setpts=PTS-STARTPTS,fps=30,format=yuv420p",
               "-af", "asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0",
               "-fps_mode", "cfr", "-r", "30",
               "-c:v", "libx264", "-crf", "22", "-preset", "veryfast",
               "-pix_fmt", "yuv420p", "-g", "60", "-keyint_min", "60", "-sc_threshold", "0",
               "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
               "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero",
               "-muxdelay", "0", "-muxpreload", "0", "-movflags", "+faststart", str(merged)]
        r = self.ffmpeg.run(cmd, "同步 concat 合并 V10", 1200)
        if r.returncode != 0 or not merged.exists() or merged.stat().st_size < 8192:
            self.log("concat 合并失败。", "err")
            return None
        final_dur = max(self._video_duration(merged), cursor)
        # Trim subtitle timings to final video duration.
        for c in prepared:
            if hasattr(c, "_render_end") and c._render_end > final_dur:
                c._render_end = max(0.1, final_dur - 0.05)
                c._render_duration = max(0.1, c._render_end - getattr(c, "_render_start", 0.0))
        out_path = out_dir / f"{safe_name(name)}_merged.mp4"
        subtitle_mode = options.get("subtitle_mode", "bilingual")
        if subtitle_mode == "none":
            shutil.move(str(merged), str(out_path))
        else:
            ass = out_dir / f"{safe_name(name)}.ass"
            self.subtitle.make_ass(prepared, ass, resolution, subtitle_mode,
                                   options.get("subtitle_style", "static"),
                                   int(options.get("font_size", 42)),
                                   options.get("en_base", "white"), options.get("en_cover", "white"),
                                   options.get("zh_base", "white"), options.get("zh_cover", "yellow"),
                                   options.get("keyword_color", "red"))
            ass_path = str(ass.resolve()).replace("\\", "/")
            ass_path = re.sub(r"([A-Za-z]):/", r"\1\\:/", ass_path)
            cmd2 = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(merged),
                    "-vf", f"ass='{ass_path}',fps=30,format=yuv420p",
                    "-af", "asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0",
                    "-fps_mode", "cfr", "-r", "30",
                    "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p",
                    "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
                    "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero",
                    "-muxdelay", "0", "-muxpreload", "0", "-movflags", "+faststart", str(out_path)]
            r2 = self.ffmpeg.run(cmd2, "同步字幕烧录 V10", 1200)
            if r2.returncode != 0 or not out_path.exists():
                self.log("字幕烧录失败，降级输出无字幕版。", "warn")
                shutil.move(str(merged), str(out_path))
        if not options.get("keep_clips", False):
            shutil.rmtree(work, ignore_errors=True)
        self.log(f"渲染完成：{out_path}", "ok")
        return out_path

# Make subtitle service honor exact starts/ends computed by RenderServiceV10.
_old_make_ass_v10 = SubtitleService.make_ass
def _make_ass_v10(self, clips: List[Clip], out_path: Path, resolution: str,
                  subtitle_mode: str, style: str, font_size: int,
                  en_base: str, en_cover: str, zh_base: str, zh_cover: str,
                  keyword_color: str = "red"):
    # If render timings exist, temporarily convert durations into exact rows by wrapping original logic.
    # This replacement is intentionally conservative: it uses original implementation but first ensures
    # every clip has an exact _render_duration, so no subtitle can exceed the standardized clip.
    for c in clips:
        if hasattr(c, "_render_start") and hasattr(c, "_render_end"):
            c._render_duration = max(0.1, float(c._render_end) - float(c._render_start))
    return _old_make_ass_v10(self, clips, out_path, resolution, subtitle_mode, style, font_size, en_base, en_cover, zh_base, zh_cover, keyword_color)
SubtitleService.make_ass = _make_ass_v10

