def _ai_receive_text_v10(self, text: str, source: str = "手动"):
    if not hasattr(self, "ai_input"):
        try:
            self.nb.select(self.tab_ai)
        except Exception:
            pass
        messagebox.showwarning("AI页未初始化", "请先打开 AI互动学习 标签页。")
        return
    text = str(text or "").strip()
    if not text:
        return
    self.ai_input.insert("end", f"\n\n===== {source} {now_str()} =====\n{text}\n")
    try:
        self.nb.select(self.tab_ai)
    except Exception:
        pass
    if hasattr(self, "ai_status_var"):
        self.ai_status_var.set(f"已接收来自 {source} 的内容。")


def _send_text_selection_to_ai_v10(self):
    text = self._text_detail_selection() if hasattr(self, "_text_detail_selection") else ""
    if not norm(text):
        c = self._text_selected_clip() if hasattr(self, "_text_selected_clip") else None
        text = c.text if c else ""
    self._ai_receive_text(text, "纯文本模式")


def _ai_to_google_box_v10(self):
    if not hasattr(self, "google_input"):
        return
    try:
        text = self.ai_input.get("sel.first", "sel.last")
    except Exception:
        text = self.ai_input.get("1.0", "end") if hasattr(self, "ai_input") else ""
    self.google_input.delete("1.0", "end")
    self.google_input.insert("end", text)


def _provider_url_v10(self, label: str) -> str:
    base = next((u for n, u in AI_PROVIDERS_V10 if n == label), AI_PROVIDERS_V10[0][1])
    if "{text}" in base:
        txt = ""
        if hasattr(self, "google_input"):
            txt = norm(self.google_input.get("1.0", "end"))
        if not txt and hasattr(self, "ai_input"):
            txt = norm(self.ai_input.get("1.0", "end"))
        return base.replace("{text}", quote(txt))
    return base


def _open_ai_selected_inside_v10(self):
    self._open_ai_url_inside(self.ai_provider_var.get())


def _open_google_translate_inside_v10(self):
    self._open_ai_url_inside("Google翻译")


def _open_ai_url_inside_v10(self, label: str):
    url = self._provider_url(label)
    prompt = self._ai_current_prompt()
    if prompt and label != "Google翻译":
        self._copy_to_clipboard(prompt, f"{label} 提示词")
    # Try true embedded tkinterweb first.
    for w in getattr(self, "ai_web_holder", tk.Frame()).winfo_children():
        try: w.destroy()
        except Exception: pass
    try:
        from tkinterweb import HtmlFrame  # type: ignore
        frame = HtmlFrame(self.ai_web_holder, messages_enabled=False)
        frame.pack(fill="both", expand=True)
        frame.load_website(url)
        self.ai_status_var.set(f"已尝试在内嵌区打开：{label}")
        return
    except Exception as e:
        self.log(f"内嵌网页区不可用，改用 pywebview：{type(e).__name__}: {e}", "warn")
    try:
        import webview  # type: ignore
    except Exception:
        messagebox.showwarning("缺少内置网页组件", "请安装：pip install tkinterweb pywebview\n当前已复制提示词，但不能内嵌打开网页。")
        return
    def run():
        try:
            webview.create_window(f"AI互动学习 - {label}", url, width=1280, height=860)
            webview.start()
        except Exception as e:
            self.log(f"AI内置窗口打开失败：{type(e).__name__}: {e}", "err")
    threading.Thread(target=run, daemon=True).start()
    self.ai_status_var.set(f"已用 pywebview 内置窗口打开 {label}。")

