def _manual_options_v10(self):
    def opt(key, opts):
        label = self.manual_render_vars[key].get()
        return next((v for k, v in opts if k == label), opts[0][1])
    return {
        "resolution": opt("resolution", RESOLUTION_OPTIONS),
        "subtitle_mode": opt("subtitle_mode", SUBTITLE_MODE_OPTIONS),
        "subtitle_style": opt("subtitle_style", SUBTITLE_STYLE_OPTIONS),
        "en_base": opt("en_base", COLOR_OPTIONS),
        "en_cover": opt("en_cover", COLOR_OPTIONS),
        "zh_base": opt("zh_base", COLOR_OPTIONS),
        "zh_cover": opt("zh_cover", COLOR_OPTIONS),
        "translate_engine": opt("translate_engine", TRANSLATE_ENGINE_OPTIONS),
        "font_size": self.manual_font_size_var.get(),
        "keep_clips": self.manual_keep_var.get(),
        "keyword_color": "red",
        "keyword": norm(self.manual_keyword_var.get()) if hasattr(self, "manual_keyword_var") else "",
    }


def _manual_render_start_v10(self):
    files = list(self.manual_list.get(0, "end"))
    if not files:
        messagebox.showwarning("提示", "请先添加本地视频。")
        return
    opts = self._manual_options()
    rows = self._manual_subtitle_rows()
    keyword = opts.get("keyword") or "manual"
    clips: List[Clip] = []
    for i, f in enumerate(files):
        p = Path(f)
        en = rows[i][0] if i < len(rows) and rows[i][0] else p.stem
        zh = rows[i][1] if i < len(rows) else ""
        c = Clip(keyword=keyword, text=en, video_url="", title=p.stem, year="")
        c.zh = zh
        c.local_path = str(p)
        clips.append(c)
    engine = opts.get("translate_engine", "manual")
    if engine and engine not in ("none", "manual"):
        self.translator.batch_translate(clips, engine)
    out = self.outdir() / f"manual_render_{now_str()}"
    self.manual_status_var.set(f"正在手动渲染 {len(clips)} 个视频… 引擎={engine} 关键词={keyword}")
    threading.Thread(target=lambda: self._manual_render_worker(clips, out, opts), daemon=True).start()

