# ──────────────────────────────────────────────────────────────────────
# Clean v11: true A/V master-clock render + embedded AI workbench
# ──────────────────────────────────────────────────────────────────────
APP_TITLE = "PlayPhrase Studio Clean v11 · 同步主轴渲染 / AI内嵌重构"

class RenderServiceV11(RenderServiceV10):
    """Strict renderer: video stream is the only master clock.

    Fixes cases where audio continues after the picture disappears and subtitle timing drifts.
    Rules:
    1. each source is normalized to a CFR video with an audio stream trimmed/padded to video duration;
    2. concat output is explicitly limited to the sum of normalized video durations;
    3. subtitles are generated only from normalized durations;
    4. subtitle burn is also limited by the final video duration and uses -shortest.
    """

    def _stream_duration(self, path: Path, stream_kind: str = "v") -> float:
        fp = self.ffmpeg.ffprobe
        if not fp:
            return self.ffmpeg.duration(path)
        try:
            cmd = [
                fp, "-v", "error", "-select_streams", f"{stream_kind}:0",
                "-show_entries", "stream=duration", "-of", "default=noprint_wrappers=1:nokey=1", str(path)
            ]
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=20, **no_window())
            val = (r.stdout or "").strip().splitlines()
            if val and val[0] and val[0].lower() != "n/a":
                return float(val[0])
        except Exception:
            pass
        return self.ffmpeg.duration(path)

    def _video_duration(self, path: Path) -> float:
        return self._stream_duration(path, "v")

    def _std_clip(self, src: Path, dst: Path, resolution: str) -> bool:
        ff = self.ffmpeg.ffmpeg
        if not ff:
            self.log("合成失败：未找到 FFmpeg。", "err")
            return False
        w, h = parse_resolution(resolution)
        dur = max(min(self._video_duration(src), 1200.0), 0.5)
        has_audio = self.ffmpeg.has_stream(src, "audio")
        vchain = (
            f"[0:v:0]trim=0:{dur:.3f},setpts=PTS-STARTPTS,"
            f"fps=30,scale={w}:{h}:force_original_aspect_ratio=decrease,"
            f"pad={w}:{h}:(ow-iw)/2:(oh-ih)/2,setsar=1,format=yuv420p[v]"
        )
        if has_audio:
            achain = (
                f"[0:a:0]atrim=0:{dur:.3f},asetpts=PTS-STARTPTS,"
                f"aresample=async=1:first_pts=0,"
                f"aformat=sample_fmts=fltp:sample_rates=48000:channel_layouts=stereo,"
                f"apad=whole_dur={dur:.3f},atrim=0:{dur:.3f}[a]"
            )
            inputs = ["-i", str(src)]
            fc = vchain + ";" + achain
            maps = ["-map", "[v]", "-map", "[a]"]
        else:
            achain = (
                f"[1:a:0]atrim=0:{dur:.3f},asetpts=PTS-STARTPTS,"
                f"aresample=async=1:first_pts=0,"
                f"aformat=sample_fmts=fltp:sample_rates=48000:channel_layouts=stereo[a]"
            )
            inputs = ["-i", str(src), "-f", "lavfi", "-t", f"{dur:.3f}", "-i", "anullsrc=channel_layout=stereo:sample_rate=48000"]
            fc = vchain + ";" + achain
            maps = ["-map", "[v]", "-map", "[a]"]

        cmd = [
            ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts",
            *inputs,
            "-filter_complex", fc,
            *maps,
            "-t", f"{dur:.3f}", "-shortest",
            "-fps_mode", "cfr", "-r", "30",
            "-c:v", "libx264", "-crf", "23", "-preset", "veryfast", "-pix_fmt", "yuv420p",
            "-g", "60", "-keyint_min", "60", "-sc_threshold", "0",
            "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
            "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero",
            "-muxdelay", "0", "-muxpreload", "0", "-movflags", "+faststart",
            str(dst)
        ]
        r = self.ffmpeg.run(cmd, f"V11标准化 {src.name}", 420)
        if r.returncode != 0 or not dst.exists() or dst.stat().st_size <= 8192:
            return False
        vd = self._video_duration(dst)
        ad = self._stream_duration(dst, "a") if self.ffmpeg.has_stream(dst, "audio") else 0.0
        if abs(vd - ad) > 0.35:
            self.log(f"[同步警告] 标准化后音画时长仍有偏差：video={vd:.3f}s audio={ad:.3f}s file={dst.name}", "warn")
        return True

    def _make_ass_with_precise_timing(self, clips: List[Clip], ass: Path, resolution: str, options: Dict[str, Any]) -> None:
        # Use original subtitle generator but make sure durations are exact and clipped.
        for c in clips:
            if hasattr(c, "_render_start") and hasattr(c, "_render_end"):
                c._render_duration = max(0.10, float(c._render_end) - float(c._render_start))
        self.subtitle.make_ass(
            clips, ass, resolution,
            options.get("subtitle_mode", "bilingual"),
            options.get("subtitle_style", "static"),
            int(options.get("font_size", 42)),
            options.get("en_base", "white"), options.get("en_cover", "white"),
            options.get("zh_base", "white"), options.get("zh_cover", "yellow"),
            options.get("keyword_color", "red")
        )

    def render(self, clips: List[Clip], out_dir: Path, name: str, options: Dict[str, Any]) -> Optional[Path]:
        if not clips:
            self.log("没有片段，无法渲染。", "warn")
            return None
        if not self.ffmpeg.ensure():
            return None
        out_dir.mkdir(parents=True, exist_ok=True)
        work = out_dir / f"_sync_v11_{safe_name(name)}_{now_str()}"
        work.mkdir(parents=True, exist_ok=True)
        resolution = options.get("resolution", "1080x1920")
        prepared: List[Clip] = []
        std_files: List[Path] = []
        cursor = 0.0
        for i, c in enumerate(clips, 1):
            if not c.local_path or not Path(c.local_path).exists():
                self.log(f"跳过未缓存片段：{c.text[:50]}", "warn")
                continue
            src = Path(c.local_path)
            dst = work / f"std_{i:04d}.mp4"
            if not self._std_clip(src, dst, resolution):
                self.log(f"标准化失败：{src}", "err")
                continue
            vd = max(self._video_duration(dst), 0.5)
            c._render_start = cursor
            c._render_duration = vd
            c._render_end = cursor + vd
            cursor += vd
            prepared.append(c)
            std_files.append(dst)
            self.log(f"V11标准化 {i}/{len(clips)} OK: {src.name} | video={vd:.3f}s", "dim")
        if not std_files:
            self.log("没有可合成的标准化片段。", "err")
            return None

        concat = work / "concat.txt"
        concat.write_text("\n".join(self._concat_line(p) for p in std_files), "utf-8")
        merged = work / "merged_no_sub.mp4"
        ff = self.ffmpeg.ffmpeg
        total_v = max(cursor, 0.5)
        cmd = [
            ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts",
            "-f", "concat", "-safe", "0", "-i", str(concat),
            "-map", "0:v:0", "-map", "0:a:0?",
            "-vf", "setpts=PTS-STARTPTS,fps=30,format=yuv420p",
            "-af", "asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,apad,atrim=0:%0.3f" % total_v,
            "-t", f"{total_v:.3f}", "-shortest",
            "-fps_mode", "cfr", "-r", "30",
            "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p",
            "-g", "60", "-keyint_min", "60", "-sc_threshold", "0",
            "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
            "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero",
            "-muxdelay", "0", "-muxpreload", "0", "-movflags", "+faststart", str(merged)
        ]
        r = self.ffmpeg.run(cmd, "V11主时钟concat", 1500)
        if r.returncode != 0 or not merged.exists() or merged.stat().st_size < 8192:
            self.log("V11 concat 合并失败。", "err")
            return None
        final_v = max(min(self._video_duration(merged), total_v), 0.5)
        # hard clamp last subtitle to final video duration
        for c in prepared:
            if getattr(c, "_render_end", 0.0) > final_v:
                c._render_end = max(getattr(c, "_render_start", 0.0) + 0.10, final_v - 0.05)
                c._render_duration = max(0.10, c._render_end - getattr(c, "_render_start", 0.0))
        self.log(f"V11最终主视频时长：{final_v:.3f}s；字幕总时长限制：≤ {final_v:.3f}s", "info")

        out_path = out_dir / f"{safe_name(name)}_merged.mp4"
        subtitle_mode = options.get("subtitle_mode", "bilingual")
        if subtitle_mode == "none":
            shutil.move(str(merged), str(out_path))
        else:
            ass = out_dir / f"{safe_name(name)}.ass"
            self._make_ass_with_precise_timing(prepared, ass, resolution, options)
            ass_path = str(ass.resolve()).replace("\\", "/")
            ass_path = re.sub(r"([A-Za-z]):/", r"\1\\:/", ass_path)
            cmd2 = [
                ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(merged),
                "-vf", f"ass='{ass_path}',fps=30,format=yuv420p",
                "-af", "asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,apad,atrim=0:%0.3f" % final_v,
                "-t", f"{final_v:.3f}", "-shortest",
                "-fps_mode", "cfr", "-r", "30",
                "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p",
                "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
                "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero",
                "-muxdelay", "0", "-muxpreload", "0", "-movflags", "+faststart", str(out_path)
            ]
            r2 = self.ffmpeg.run(cmd2, "V11主时钟字幕烧录", 1500)
            if r2.returncode != 0 or not out_path.exists() or out_path.stat().st_size < 8192:
                self.log("字幕烧录失败，降级输出无字幕版。", "warn")
                shutil.move(str(merged), str(out_path))
        if not options.get("keep_clips", False):
            shutil.rmtree(work, ignore_errors=True)
        vd_out = self._video_duration(out_path) if out_path.exists() else 0.0
        ad_out = self._stream_duration(out_path, "a") if out_path.exists() and self.ffmpeg.has_stream(out_path, "audio") else 0.0
        self.log(f"渲染完成：{out_path} | video={vd_out:.3f}s audio={ad_out:.3f}s", "ok")
        if vd_out and ad_out and abs(vd_out - ad_out) > 0.35:
            self.log("输出文件音画时长仍有明显偏差。建议把该批片段原始文件发我做 ffprobe 诊断。", "warn")
        return out_path


