def _open_ai_selected_inside_v11(self):
    self._open_ai_url_inside(self.ai_provider_var.get(), prefer_tab=True)


def _open_ai_selected_webview_v11(self):
    self._open_ai_url_inside(self.ai_provider_var.get(), prefer_tab=False)


def _open_google_translate_inside_v11(self):
    self._open_ai_url_inside("Google翻译", prefer_tab=True)


def _provider_url_v11(self, label: str) -> str:
    base = next((u for n, u in AI_PROVIDERS_V11 if n == label), AI_PROVIDERS_V11[0][1])
    if "{text}" in base:
        txt = ""
        if hasattr(self, "google_input"):
            txt = norm(self.google_input.get("1.0", "end"))
        if not txt and hasattr(self, "ai_input"):
            txt = norm(self.ai_input.get("1.0", "end"))
        return base.replace("{text}", quote(txt))
    return base


def _open_ai_url_inside_v11(self, label: str, prefer_tab: bool = True):
    url = self._provider_url(label)
    prompt = self._ai_current_prompt() if hasattr(self, "_ai_current_prompt") else ""
    if prompt and label != "Google翻译":
        self._copy_to_clipboard(prompt, f"{label} 提示词")
    if prefer_tab:
        try:
            for w in getattr(self, "ai_web_holder", tk.Frame()).winfo_children():
                try: w.destroy()
                except Exception: pass
            from tkinterweb import HtmlFrame  # type: ignore
            frame = HtmlFrame(self.ai_web_holder, messages_enabled=False)
            frame.pack(fill="both", expand=True)
            frame.load_website(url)
            self.ai_status_var.set(f"已尝试嵌入当前页：{label}。如页面空白，说明该平台阻止轻量内嵌，请点“内置浏览窗口”。")
            return
        except Exception as e:
            self.log(f"当前页内嵌失败：{type(e).__name__}: {e}", "warn")
            self.ai_status_var.set("当前页内嵌失败。请安装 tkinterweb，或使用右侧“内置浏览窗口”。")
            return
    try:
        import webview  # type: ignore
    except Exception:
        messagebox.showwarning("缺少 pywebview", "请安装：pip install pywebview\n本版不会跳外部浏览器。")
        return
    def run():
        try:
            webview.create_window(f"AI互动学习 - {label}", url, width=1320, height=900)
            webview.start()
        except Exception as e:
            self.log(f"内置浏览窗口失败：{type(e).__name__}: {e}", "err")
    threading.Thread(target=run, daemon=True).start()
    self.ai_status_var.set(f"已打开内置浏览窗口：{label}。提示词已复制，可粘贴到输入框。")

# Bind v11 before app start.
MainApp._build_ai = _build_ai_v11
MainApp._provider_url = _provider_url_v11
MainApp._open_ai_selected_inside = _open_ai_selected_inside_v11
MainApp._open_ai_selected_webview = _open_ai_selected_webview_v11
MainApp._open_google_translate_inside = _open_google_translate_inside_v11
MainApp._open_ai_url_inside = _open_ai_url_inside_v11

_old_main_init_v11 = MainApp.__init__
def _main_init_v11(self):
    _old_main_init_v11(self)
    self.renderer = RenderServiceV11(self.ffmpeg, self.subtitle, self.log)
MainApp.__init__ = _main_init_v11

# ──────────────────────────────────────────────────────────────────────
# Clean v13: AI embedded workspace rebuild
# - Open every AI/Google site in a dedicated internal WebView subprocess
# - Avoid pywebview main-thread conflicts by running pywebview in child process
# ──────────────────────────────────────────────────────────────────────
APP_TITLE = "PlayPhrase Studio Clean v13 · AI内置页重构版"

AI_PROVIDERS_V13 = [
    ("豆包", "https://www.doubao.com/"),
    ("千问", "https://www.qianwen.com/"),
    ("元宝", "https://yuanbao.tencent.com/"),
    ("文心一言", "https://yiyan.baidu.com/"),
    ("ChatGPT", "https://chatgpt.com/"),
    ("Gemini", "https://gemini.google.com/"),
    ("Grok", "https://grok.com/"),
]

AI_PROMPT_TEMPLATES_V13 = [
    ("英语分级深度解析", "请按 A1-C2 分级，深度解析下面的英语内容：\n\n{text}\n\n要求：音标、核心含义、搭配、语境、近义词区分、例句、中英对照、考试/美剧常见用法、最后给出总结。"),
    ("短语/词块解析", "请深度解析这个英语短语/词块：\n\n{text}\n\n要求：语义、语法结构、常见搭配、可替换表达、口语强度、影视剧例句。"),
    ("句子语法拆解", "请逐层拆解这个英语句子：\n\n{text}\n\n要求：句子结构、语法点、重点词、自然翻译、地道改写、相似句型。"),
    ("翻译润色", "请把下面英文翻译成自然中文，并说明直译与意译差别：\n\n{text}"),
    ("自定义", "{text}"),
]


def _ai_get_received_text_v13(self) -> str:
    if hasattr(self, "ai_input"):
        return norm(self.ai_input.get("1.0", "end"))
    return ""


def _ai_current_prompt_v13(self) -> str:
    text = _ai_get_received_text_v13(self)
    if not text and hasattr(self, "google_input"):
        text = norm(self.google_input.get("1.0", "end"))
    name = self.ai_template_var.get() if hasattr(self, "ai_template_var") else "英语分级深度解析"
    tmpl = next((t for n, t in AI_PROMPT_TEMPLATES_V13 if n == name), AI_PROMPT_TEMPLATES_V13[0][1])
    return tmpl.replace("{text}", text)


def _copy_ai_prompt_v13(self):
    prompt = _ai_current_prompt_v13(self)
    if not prompt.strip():
        messagebox.showwarning("提示", "AI接收区为空，无法生成提示词。")
        return
    self._copy_to_clipboard(prompt, "AI提示词")
    if hasattr(self, "ai_status_var"):
        self.ai_status_var.set(f"已复制 AI 提示词：{len(prompt)} 字符")


def _ai_receive_text_v13(self, text: str, source: str = "发送"):
    text = str(text or "").strip()
    if not text:
        return
    try:
        self.nb.select(self.tab_ai)
    except Exception:
        pass
    if not hasattr(self, "ai_input"):
        return
    old = norm(self.ai_input.get("1.0", "end"))
    if old:
        self.ai_input.insert("end", f"\n\n===== {source} {now_str()} =====\n{text}\n")
    else:
        self.ai_input.insert("end", text)
    if hasattr(self, "google_input"):
        self.google_input.delete("1.0", "end")
        self.google_input.insert("end", text)
    if hasattr(self, "ai_status_var"):
        self.ai_status_var.set(f"已接收来自 {source} 的文本：{len(text)} 字符")


def _ai_paste_clipboard_v13(self):
    try:
        txt = self.clipboard_get()
    except Exception:
        txt = ""
    if txt:
        _ai_receive_text_v13(self, txt, "剪贴板")


def _ai_clear_v13(self):
    for attr in ("ai_input", "google_input"):
        if hasattr(self, attr):
            getattr(self, attr).delete("1.0", "end")
    if hasattr(self, "ai_status_var"):
        self.ai_status_var.set("已清空 AI 接收区和 Google 翻译输入区。")


def _ai_import_docs_v13(self):
    files = filedialog.askopenfilenames(
        title="导入文本/字幕/CSV 文档",
        filetypes=[("文本/字幕/CSV", "*.txt *.md *.csv *.srt"), ("所有文件", "*.*")]
    )
    if not files:
        return
    chunks = []
    for f in files:
        p = Path(f)
        try:
            raw = p.read_text("utf-8-sig", errors="ignore")
        except Exception:
            try:
                raw = p.read_text("gbk", errors="ignore")
            except Exception as e:
                self.log(f"AI文档导入失败：{p.name} | {e}", "err")
                continue
        chunks.append(f"===== {p.name} =====\n{raw.strip()}")
    if chunks:
        _ai_receive_text_v13(self, "\n\n".join(chunks), "文档导入")


def _ai_to_google_box_v13(self):
    txt = _ai_get_received_text_v13(self)
    if not txt:
        messagebox.showwarning("提示", "AI接收区为空。")
        return
    self.google_input.delete("1.0", "end")
    self.google_input.insert("end", txt)
    self.ai_status_var.set("已把 AI 接收区内容复制到 Google 翻译输入框。")


def _google_translate_url_v13(self) -> str:
    txt = ""
    if hasattr(self, "google_input"):
        txt = norm(self.google_input.get("1.0", "end"))
    if not txt:
        txt = _ai_get_received_text_v13(self)
    return "https://translate.google.com/?sl=en&tl=zh-CN&text=" + quote(txt) + "&op=translate"


def _provider_url_v13(self, label: str) -> str:
    if label == "Google翻译":
        return _google_translate_url_v13(self)
    return next((u for n, u in AI_PROVIDERS_V13 if n == label), AI_PROVIDERS_V13[0][1])


def _launch_internal_webview_process_v13(self, title: str, url: str):
    child_code = (
        "import sys, pathlib, traceback\n"
        "try:\n"
        "    import webview\n"
        "except Exception as e:\n"
        "    print('PYWEBVIEW_IMPORT_ERROR', repr(e))\n"
        "    sys.exit(2)\n"
        "title=sys.argv[1]\n"
        "url=sys.argv[2]\n"
        "profile=pathlib.Path(sys.argv[3]); profile.mkdir(parents=True, exist_ok=True)\n"
        "try:\n"
        "    webview.create_window(title, url, width=1360, height=900, resizable=True)\n"
        "    try:\n"
        "        webview.start(storage_path=str(profile))\n"
        "    except TypeError:\n"
        "        webview.start()\n"
        "except Exception:\n"
        "    traceback.print_exc(); sys.exit(3)\n"
    )
    try:
        profile = CACHE_ROOT / "ai_webview_profiles" / safe_name(title, 60)
        profile.mkdir(parents=True, exist_ok=True)
        proc = subprocess.Popen(
            [sys.executable, "-c", child_code, title, url, str(profile)],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            creationflags=((subprocess.CREATE_NEW_PROCESS_GROUP | subprocess.CREATE_NO_WINDOW) if os.name == "nt" else 0)
        )
        if not hasattr(self, "_ai_webview_processes"):
            self._ai_webview_processes = []
        self._ai_webview_processes.append(proc)
        self.ai_status_var.set(f"已打开内置 WebView：{title}。提示词/翻译文本已复制，可在页面内粘贴。")
        self.log(f"AI内置 WebView 已启动：{title}", "ok")
        return True
    except Exception as e:
        self.log(f"AI内置 WebView 启动失败：{type(e).__name__}: {e}", "err")
        messagebox.showerror("内置 WebView 启动失败", f"{type(e).__name__}: {e}\n\n请先安装：pip install pywebview")
        return False


def _open_ai_provider_v13(self, name: str):
    prompt = _ai_current_prompt_v13(self)
    if prompt.strip():
        self._copy_to_clipboard(prompt, f"{name} 提示词")
    url = _provider_url_v13(self, name)
    _launch_internal_webview_process_v13(self, f"AI互动学习 - {name}", url)


def _open_google_translate_v13(self):
    txt = norm(self.google_input.get("1.0", "end")) if hasattr(self, "google_input") else ""
    if txt:
        self._copy_to_clipboard(txt, "Google翻译文本")
    _launch_internal_webview_process_v13(self, "Google 翻译", _google_translate_url_v13(self))


def _open_custom_ai_url_v13(self):
    url = norm(self.ai_url_var.get() if hasattr(self, "ai_url_var") else "")
    if not url:
        messagebox.showwarning("提示", "请输入 URL。")
        return
    if not re.match(r"^https?://", url, re.I):
        url = "https://" + url
    _launch_internal_webview_process_v13(self, "AI自定义页面", url)


