# ──────────────────────────────────────────────────────────────────────
# Clean v16: strict concat validation + filter_complex fallback + subtitle layout recovery
# ──────────────────────────────────────────────────────────────────────

def _ass_wrap_text_v16(text: str, max_chars: int) -> str:
    """Wrap readable ASS text with ASS line breaks. Keeps words when possible."""
    raw = str(text or "").strip()
    if not raw:
        return ""
    if re.search(r"[\u4e00-\u9fff]", raw):
        # Chinese: fixed-width-ish character wrapping.
        chunks = []
        s = re.sub(r"\s+", " ", raw)
        while len(s) > max_chars:
            cut = max_chars
            chunks.append(s[:cut].strip())
            s = s[cut:].strip()
        if s:
            chunks.append(s)
        return r"\N".join(ass_escape(x) for x in chunks if x)
    words = raw.split()
    lines, cur = [], ""
    for w in words:
        nxt = w if not cur else cur + " " + w
        if len(nxt) <= max_chars or not cur:
            cur = nxt
        else:
            lines.append(cur)
            cur = w
    if cur:
        lines.append(cur)
    return r"\N".join(ass_escape(x) for x in lines if x)


def _karaoke_wrapped_v16(text: str, duration_sec: float, max_chars: int) -> str:
    wrapped = _ass_wrap_text_v16(text, max_chars).replace(r"\N", " \\N ")
    tokens = [t for t in re.split(r"(\\N|\s+)", wrapped) if t != ""]
    words = [t for t in tokens if (not t.isspace() and t != r"\N")]
    if not words:
        return ass_escape(text)
    total_cs = max(int(round(max(duration_sec, 0.1) * 100)), len(words))
    each = max(1, total_cs // max(len(words), 1))
    out = []
    for t in tokens:
        if t == r"\N":
            out.append(r"\N")
        elif t.isspace():
            out.append(t)
        else:
            # t is already escaped by _ass_wrap_text_v16; do not double escape backslashes.
            out.append("{\\kf%d}%s" % (each, t))
    return "".join(out)


def _keyword_highlight_wrapped_v16(text: str, keyword: str, color: str, max_chars: int) -> str:
    wrapped_plain = _ass_wrap_text_v16(text, max_chars)
    kw = norm(keyword)
    if not kw:
        return wrapped_plain
    col = ASS_COLOR.get(color, ASS_COLOR.get("red"))
    white = ASS_COLOR.get("white")
    try:
        # Search after escaping; keyword normally contains no ASS escape chars. Good enough for phrase highlighting.
        pattern = re.compile(re.escape(ass_escape(kw)), re.I)
        return pattern.sub(lambda m: "{\\c%s\\b1}%s{\\c%s\\b0}" % (col, m.group(0), white), wrapped_plain)
    except Exception:
        return wrapped_plain


class RenderServiceV16(RenderServiceV15):
    """No silent truncation renderer.

    Main rule: if concat output is shorter than the sum of normalized clips,
    the concat result is invalid. Do NOT continue with the shorter file.
    Fallback to filter_complex concat; if still short, abort instead of destroying
    the last clip and subtitle timeline.
    """
    VERSION_TAG = "V16"

    def _concat_filter_v16(self, entries: List[Tuple[Clip, Path, float]], out_path: Path) -> bool:
        ff = self.ffmpeg.ffmpeg
        if not ff:
            return False
        cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts"]
        for _, p, _ in entries:
            cmd += ["-i", str(p)]
        parts = []
        chain = []
        for i in range(len(entries)):
            parts.append(f"[{i}:v:0]setpts=PTS-STARTPTS,fps=30,format=yuv420p[v{i}]")
            parts.append(f"[{i}:a:0]asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0,aformat=sample_fmts=fltp:sample_rates=48000:channel_layouts=stereo[a{i}]")
            chain.append(f"[v{i}][a{i}]")
        parts.append("".join(chain) + f"concat=n={len(entries)}:v=1:a=1[v][a]")
        fc = ";".join(parts)
        cmd += [
            "-filter_complex", fc,
            "-map", "[v]", "-map", "[a]",
            "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p",
            "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
            "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero", "-movflags", "+faststart",
            str(out_path)
        ]
        r = self.ffmpeg.run(cmd, f"V16 filter_complex concat 兜底（强制包含 {len(entries)} 段）", 1800)
        return r.returncode == 0 and out_path.exists() and out_path.stat().st_size > 2048

    def _make_ass_timeline_v16(self, entries: List[Tuple[Clip, float]], out_path: Path, options: Dict[str, Any], final_dur: float) -> Path:
        shift = _clamp_float(options.get("subtitle_shift_ms", 0), -10000, 10000, 0.0) / 1000.0
        w, h = parse_resolution(options.get("resolution", "1080x1920"))
        subtitle_mode = options.get("subtitle_mode", "bilingual")
        style = options.get("subtitle_style", "static")
        font_size = int(options.get("font_size", 42))
        en_base = options.get("en_base", "white")
        en_cover = options.get("en_cover", "white")
        zh_base = options.get("zh_base", "white")
        zh_cover = options.get("zh_cover", "yellow")
        keyword_color = options.get("keyword_color", "red")
        # Larger, safe margins. English above Chinese; both away from bottom crop.
        en_margin = 210 if h >= w else 96
        zh_margin = 118 if h >= w else 42
        fs_zh = max(22, int(font_size * 0.78))
        max_en = 30 if h >= w else 54
        max_zh = 18 if h >= w else 32
        outline = 2
        en_primary = ASS_COLOR.get(en_cover if en_cover != "white" else en_base, ASS_COLOR["white"])
        en_secondary = ASS_COLOR.get(en_base, ASS_COLOR["white"])
        zh_primary = ASS_COLOR.get(zh_cover if zh_cover != "white" else zh_base, ASS_COLOR["white"])
        zh_secondary = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
        static_en = ASS_COLOR.get(en_base, ASS_COLOR["white"])
        static_zh = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
        header = f"""[Script Info]\nScriptType: v4.00+\nPlayResX: {w}\nPlayResY: {h}\nScaledBorderAndShadow: yes\nWrapStyle: 0\n\n[V4+ Styles]\nFormat: Name,Fontname,Fontsize,PrimaryColour,SecondaryColour,OutlineColour,BackColour,Bold,Italic,Underline,StrikeOut,ScaleX,ScaleY,Spacing,Angle,BorderStyle,Outline,Shadow,Alignment,MarginL,MarginR,MarginV,Encoding\nStyle: EnStatic,Microsoft YaHei,{font_size},{static_en},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{en_margin},1\nStyle: ZhStatic,Microsoft YaHei,{fs_zh},{static_zh},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{zh_margin},1\nStyle: EnKaraoke,Microsoft YaHei,{font_size},{en_primary},{en_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{en_margin},1\nStyle: ZhKaraoke,Microsoft YaHei,{fs_zh},{zh_primary},{zh_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{zh_margin},1\n\n[Events]\nFormat: Layer,Start,End,Style,Name,MarginL,MarginR,MarginV,Effect,Text\n"""
        lines = [header]
        cur = 0.0
        for c, dur in entries:
            if not c.text:
                cur += dur
                continue
            start = max(0.0, cur + shift)
            end = min(final_dur, max(start + 0.05, cur + dur + shift))
            if end <= 0 or start >= final_dur:
                cur += dur
                continue
            en = c.text or ""
            zh = c.zh or ""
            span = max(end - start, 0.1)
            if subtitle_mode == "none":
                cur += dur
                continue
            if style == "keyword_highlight":
                en_body = _keyword_highlight_wrapped_v16(en, c.keyword, keyword_color, max_en)
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_body}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v16(zh, max_zh)}\n")
            elif style in ("en_karaoke_yellow", "en_karaoke_orange"):
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v16(en, span, max_en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v16(zh, max_zh)}\n")
            elif style == "bilingual_karaoke":
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v16(en, span, max_en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v16(zh, span, max_zh)}\n")
            elif style == "keyword_bilingual_karaoke":
                # Keyword stays red/static in the English line. Non-keyword text still receives karaoke fill.
                # Practical ASS limitation: mixed static red + karaoke in one line is fragile, so we keep keyword highlight wrapper.
                en_body = _keyword_highlight_wrapped_v16(en, c.keyword, keyword_color, max_en)
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_body}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v16(zh, span, max_zh)}\n")
            else:
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{_ass_wrap_text_v16(en, max_en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v16(zh, max_zh)}\n")
            cur += dur
        out_path.write_text("".join(lines), "utf-8-sig")
        return out_path

    def render(self, clips: List[Clip], out_dir: Path, name: str, options: Dict[str, Any]) -> Optional[Path]:
        if not clips:
            self.log("V16渲染取消：片段为空。", "warn")
            return None
        if not self.ffmpeg.ensure():
            return None
        out_dir.mkdir(parents=True, exist_ok=True)
        work = out_dir / f"_work_v16_{safe_name(name)}_{now_str()}"
        work.mkdir(parents=True, exist_ok=True)
        resolution = options.get("resolution", "1080x1920")
        audio_shift_ms = _clamp_float(options.get("audio_shift_ms", 0), -10000, 10000, 0.0)
        clip_gap_ms = _clamp_float(options.get("clip_gap_ms", 0), 0, 5000, 0.0)
        self.log(f"V16强制时间线校验启用 | audio_shift={audio_shift_ms:.0f}ms | clip_gap={clip_gap_ms:.0f}ms", "info")
        entries: List[Tuple[Clip, Path, float]] = []
        source_count = len(clips)
        for idx, c in enumerate(clips, 1):
            if not c.local_path or not Path(c.local_path).exists():
                self.log(f"V16跳过未缓存片段：{c.text[:60]}", "warn")
                continue
            src = Path(c.local_path)
            dst = work / f"std_{len(entries)+1:04d}.mp4"
            dur = self._std_clip_v15(src, dst, resolution)
            if dur is None:
                self.log(f"V16标准化失败：{src}", "err")
                continue
            # Re-probe after standardization; trust the standardized file, not source metadata.
            dur = max(self._v_dur(dst) or dur, 0.05)
            entries.append((c, dst, dur))
            self.log(f"V16标准化 {len(entries)}/{source_count} OK: {dst.name} | video={dur:.3f}s", "ok")
            if clip_gap_ms > 0 and idx < source_count:
                gap_dur = clip_gap_ms / 1000.0
                gap = work / f"gap_{len(entries)+1:04d}.mp4"
                if self._make_gap_clip(gap, resolution, gap_dur):
                    dummy = Clip(keyword=c.keyword, text="", video_url="", title="gap", year="")
                    dummy.zh = ""
                    entries.append((dummy, gap, max(self._v_dur(gap), gap_dur)))
        if not entries:
            self.log("V16渲染失败：没有可用的标准化片段。", "err")
            return None
        std_total = sum(d for _, _, d in entries)
        self.log(f"V16标准化总时长：{std_total:.3f}s；进入 concat 文件数：{len(entries)}", "info")
        ff = self.ffmpeg.ffmpeg
        concat_txt = work / "concat.txt"
        # Important: final newline. Some environments have mishandled the last concat line without it.
        concat_txt.write_text("\n".join(self._concat_line(p) for _, p, _ in entries) + "\n", "utf-8")
        raw_merged = work / "merged_raw.mp4"
        cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-fflags", "+genpts", "-f", "concat", "-safe", "0", "-i", str(concat_txt), "-map", "0:v:0", "-map", "0:a:0?", "-vf", "setpts=PTS-STARTPTS,fps=30,format=yuv420p", "-af", "asetpts=PTS-STARTPTS,aresample=async=1:first_pts=0", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2", "-video_track_timescale", "30000", "-avoid_negative_ts", "make_zero", "-movflags", "+faststart", str(raw_merged)]
        r = self.ffmpeg.run(cmd, "V16 concat demuxer 完整合并", 1200)
        if r.returncode != 0 or not raw_merged.exists() or raw_merged.stat().st_size < 2048:
            self.log("V16 concat demuxer 失败，改用 filter_complex concat。", "warn")
            raw_merged = work / "merged_filter.mp4"
            if not self._concat_filter_v16(entries, raw_merged):
                self.log("V16 filter_complex concat 也失败，停止渲染。", "err")
                return None
        concat_dur = self._v_dur(raw_merged) or self.ffmpeg.duration(raw_merged) or 0.0
        # Critical: if concat is shorter than expected, the result is broken. Do not keep rendering it.
        if concat_dur < std_total - 0.35:
            self.log(f"V16检测到 concat 丢段：concat={concat_dur:.3f}s < 标准化累加={std_total:.3f}s；改用 filter_complex concat。", "err")
            raw_merged2 = work / "merged_filter.mp4"
            if not self._concat_filter_v16(entries, raw_merged2):
                self.log("V16 filter_complex concat 失败，停止渲染，避免继续输出丢段视频。", "err")
                return None
            raw_merged = raw_merged2
            concat_dur = self._v_dur(raw_merged) or self.ffmpeg.duration(raw_merged) or 0.0
            if concat_dur < std_total - 0.35:
                self.log(f"V16严重错误：filter concat 仍然短于标准化总时长 concat={concat_dur:.3f}s std_total={std_total:.3f}s；停止输出。", "err")
                return None
        elif concat_dur > std_total + 0.5:
            self.log(f"V16提示：concat={concat_dur:.3f}s 大于标准化累加={std_total:.3f}s，将后续同步限制到标准化累加时长。", "warn")
            concat_dur = std_total
        else:
            self.log(f"V16 concat真实时长：{concat_dur:.3f}s", "ok")
        synced = work / "merged_sync.mp4"
        if not self._sync_merge_av(raw_merged, synced, concat_dur, audio_shift_ms):
            self.log("V16音画同步校准失败，停止渲染，避免输出不同步视频。", "err")
            return None
        vd, ad = self._v_dur(synced), self._a_dur(synced)
        self.log(f"V16音画同步后：video={vd:.3f}s audio={ad:.3f}s diff={abs(vd-ad):.3f}s", "ok" if abs(vd-ad) <= 0.12 else "warn")
        final_dur = vd or concat_dur
        out_path = out_dir / f"{safe_name(name)}_merged.mp4"
        if options.get("subtitle_mode", "bilingual") == "none":
            shutil.copy2(synced, out_path)
        else:
            ass = work / f"{safe_name(name)}_v16.ass"
            subtitle_entries = [(c, d) for c, _, d in entries if c.text]
            self._make_ass_timeline_v16(subtitle_entries, ass, options, final_dur)
            ass_path = str(ass.resolve()).replace("\\", "/")
            ass_path = re.sub(r"^([A-Za-z]):/", r"\1\\:/", ass_path)
            cmd2 = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(synced), "-vf", f"ass='{ass_path}'", "-t", f"{final_dur:.6f}", "-shortest", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2", "-movflags", "+faststart", str(out_path)]
            r2 = self.ffmpeg.run(cmd2, "V16字幕烧录与对齐", 1200)
            if r2.returncode != 0 or not out_path.exists() or out_path.stat().st_size < 2048:
                self.log("V16字幕烧录失败，降级输出无字幕同步版。", "warn")
                shutil.copy2(synced, out_path)
        vd2, ad2 = self._v_dur(out_path), self._a_dur(out_path)
        self.log(f"V16渲染完成：{out_path} | video={vd2:.3f}s audio={ad2:.3f}s diff={abs(vd2-ad2):.3f}s", "ok" if abs(vd2-ad2) <= 0.15 else "warn")
        if not options.get("keep_clips", False):
            try:
                shutil.rmtree(work, ignore_errors=True)
            except Exception:
                pass
        return out_path


_old_main_init_v16_base = MainApp.__init__

def _main_init_v16(self):
    _old_main_init_v16_base(self)
    self.renderer = RenderServiceV16(self.ffmpeg, self.subtitle, self.log)
    self.log("PlayPhrase Studio Clean v16 启动：RenderServiceV16 已启用；concat 丢段会自动兜底/失败，不再输出截断视频。", "ok")

MainApp.__init__ = _main_init_v16




# ──────────────────────────────────────────────────────────────────────
# Clean v17: filter_complex primary concat + real keyword double-karaoke
# ──────────────────────────────────────────────────────────────────────
def _wrap_plain_lines_v17(text: str, max_chars: int) -> List[str]:
    raw = str(text or "").strip()
    if not raw:
        return []
    if re.search(r"[\u4e00-\u9fff]", raw):
        s = re.sub(r"\s+", " ", raw)
        out = []
        while len(s) > max_chars:
            out.append(s[:max_chars].strip())
            s = s[max_chars:].strip()
        if s:
            out.append(s)
        return out
    words = raw.split()
    lines, cur = [], ""
    for w in words:
        nxt = w if not cur else cur + " " + w
        if len(nxt) <= max_chars or not cur:
            cur = nxt
        else:
            lines.append(cur)
            cur = w
    if cur:
        lines.append(cur)
    return lines


def _norm_loose_v17(s: str) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(s or "").lower()).strip()


def _karaoke_plain_piece_v17(text: str, each_cs: int) -> str:
    toks = [t for t in re.split(r"(\s+)", str(text or "")) if t != ""]
    out = []
    for t in toks:
        if t.isspace():
            out.append(t)
        else:
            out.append("{\\kf%d}%s" % (max(each_cs, 1), ass_escape(t)))
    return "".join(out)


def _keyword_static_red_wrapped_v17(text: str, max_chars: int, color: str = "red") -> str:
    col = ASS_COLOR.get(color, ASS_COLOR["red"])
    lines = _wrap_plain_lines_v17(text, max_chars)
    return r"\N".join("{\\c%s\\b1}%s{\\b0}" % (col, ass_escape(line)) for line in lines)


def _keyword_karaoke_wrapped_v17(text: str, keyword: str, duration_sec: float, max_chars: int, keyword_color: str = "red") -> str:
    r"""English line for 'keyword highlight + double karaoke'.

    Keyword spans are fixed red. Non-keyword text uses \kf fill, so it rolls
    from base colour to cover colour. This avoids the v16 regression where the
    whole upper English line became static and stopped rolling.
    """
    raw = str(text or "").strip()
    kw = str(keyword or "").strip()
    if not raw:
        return ""
    if not kw:
        return _karaoke_wrapped_v16(raw, duration_sec, max_chars)
    # If the whole utterance is the keyword (punctuation ignored), show fixed red only.
    if _norm_loose_v17(raw) == _norm_loose_v17(kw):
        return _keyword_static_red_wrapped_v17(raw, max_chars, keyword_color)

    # Wrap first, then process each line independently.
    lines = _wrap_plain_lines_v17(raw, max_chars)
    pattern = re.compile(re.escape(kw), re.I)
    # Count non-keyword words to distribute karaoke time across rolling pieces.
    non_kw_word_count = 0
    for line in lines:
        pos = 0
        for m in pattern.finditer(line):
            non_kw_word_count += len([x for x in re.split(r"\s+", line[pos:m.start()].strip()) if x])
            pos = m.end()
        non_kw_word_count += len([x for x in re.split(r"\s+", line[pos:].strip()) if x])
    total_cs = max(int(round(max(duration_sec, 0.1) * 100)), max(non_kw_word_count, 1))
    each_cs = max(1, total_cs // max(non_kw_word_count, 1))
    red = ASS_COLOR.get(keyword_color, ASS_COLOR["red"])

    rendered_lines = []
    for line in lines:
        parts = []
        pos = 0
        for m in pattern.finditer(line):
            before = line[pos:m.start()]
            if before:
                parts.append(_karaoke_plain_piece_v17(before, each_cs))
            # \kf0 prevents keyword from consuming karaoke timing; \rEnKaraoke resets to rolling style after red span.
            parts.append("{\\kf0\\c%s\\b1}%s{\\rEnKaraoke}" % (red, ass_escape(m.group(0))))
            pos = m.end()
        tail = line[pos:]
        if tail:
            parts.append(_karaoke_plain_piece_v17(tail, each_cs))
        rendered_lines.append("".join(parts))
    return r"\N".join(rendered_lines)


class RenderServiceV17(RenderServiceV16):
    """Primary filter-complex concat renderer.

    v16 still tried concat demuxer first, then detected the last clip being
    dropped and fell back. v17 skips concat demuxer entirely. The first and only
    normal path is filter_complex concat, which is the safer choice for short
    PlayPhrase mp4 clips with inconsistent container metadata.
    """
    VERSION_TAG = "V17"

    def _make_ass_timeline_v17(self, entries: List[Tuple[Clip, float]], out_path: Path, options: Dict[str, Any], final_dur: float) -> Path:
        shift = _clamp_float(options.get("subtitle_shift_ms", 0), -10000, 10000, 0.0) / 1000.0
        w, h = parse_resolution(options.get("resolution", "1080x1920"))
        subtitle_mode = options.get("subtitle_mode", "bilingual")
        style = options.get("subtitle_style", "static")
        font_size = int(options.get("font_size", 42))
        en_base = options.get("en_base", "white")
        en_cover = options.get("en_cover", "white")
        zh_base = options.get("zh_base", "white")
        zh_cover = options.get("zh_cover", "yellow")
        keyword_color = options.get("keyword_color", "red")
        en_margin = 210 if h >= w else 96
        zh_margin = 118 if h >= w else 42
        fs_zh = max(22, int(font_size * 0.78))
        max_en = 30 if h >= w else 54
        max_zh = 18 if h >= w else 32
        outline = 2
        en_primary = ASS_COLOR.get(en_cover if en_cover != "white" else en_base, ASS_COLOR["white"])
        en_secondary = ASS_COLOR.get(en_base, ASS_COLOR["white"])
        zh_primary = ASS_COLOR.get(zh_cover if zh_cover != "white" else zh_base, ASS_COLOR["white"])
        zh_secondary = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
        static_en = ASS_COLOR.get(en_base, ASS_COLOR["white"])
        static_zh = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
        header = f"""[Script Info]\nScriptType: v4.00+\nPlayResX: {w}\nPlayResY: {h}\nScaledBorderAndShadow: yes\nWrapStyle: 0\n\n[V4+ Styles]\nFormat: Name,Fontname,Fontsize,PrimaryColour,SecondaryColour,OutlineColour,BackColour,Bold,Italic,Underline,StrikeOut,ScaleX,ScaleY,Spacing,Angle,BorderStyle,Outline,Shadow,Alignment,MarginL,MarginR,MarginV,Encoding\nStyle: EnStatic,Microsoft YaHei,{font_size},{static_en},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{en_margin},1\nStyle: ZhStatic,Microsoft YaHei,{fs_zh},{static_zh},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{zh_margin},1\nStyle: EnKaraoke,Microsoft YaHei,{font_size},{en_primary},{en_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{en_margin},1\nStyle: ZhKaraoke,Microsoft YaHei,{fs_zh},{zh_primary},{zh_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},0,2,70,70,{zh_margin},1\n\n[Events]\nFormat: Layer,Start,End,Style,Name,MarginL,MarginR,MarginV,Effect,Text\n"""
        lines = [header]
        cur = 0.0
        for c, dur in entries:
            if not c.text:
                cur += dur
                continue
            start = max(0.0, cur + shift)
            end = min(final_dur, max(start + 0.05, cur + dur + shift))
            if end <= 0 or start >= final_dur:
                cur += dur
                continue
            en = c.text or ""
            zh = c.zh or ""
            span = max(end - start, 0.1)
            if subtitle_mode == "none":
                cur += dur
                continue
            if style == "keyword_highlight":
                en_body = _keyword_highlight_wrapped_v16(en, c.keyword, keyword_color, max_en)
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_body}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v16(zh, max_zh)}\n")
            elif style in ("en_karaoke_yellow", "en_karaoke_orange"):
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v16(en, span, max_en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v16(zh, max_zh)}\n")
            elif style == "bilingual_karaoke":
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v16(en, span, max_en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v16(zh, span, max_zh)}\n")
            elif style == "keyword_bilingual_karaoke":
                en_body = _keyword_karaoke_wrapped_v17(en, c.keyword, span, max_en, keyword_color)
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{en_body}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v16(zh, span, max_zh)}\n")
            else:
                lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{_ass_wrap_text_v16(en, max_en)}\n")
                if subtitle_mode == "bilingual" and zh:
                    lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v16(zh, max_zh)}\n")
            cur += dur
        out_path.write_text("".join(lines), "utf-8-sig")
        return out_path

    def render(self, clips: List[Clip], out_dir: Path, name: str, options: Dict[str, Any]) -> Optional[Path]:
        if not clips:
            self.log("V17渲染取消：片段为空。", "warn")
            return None
        if not self.ffmpeg.ensure():
            return None
        out_dir.mkdir(parents=True, exist_ok=True)
        work = out_dir / f"_work_v17_{safe_name(name)}_{now_str()}"
        work.mkdir(parents=True, exist_ok=True)
        resolution = options.get("resolution", "1080x1920")
        audio_shift_ms = _clamp_float(options.get("audio_shift_ms", 0), -10000, 10000, 0.0)
        clip_gap_ms = _clamp_float(options.get("clip_gap_ms", 0), 0, 5000, 0.0)
        self.log(f"V17强制使用 filter_complex concat 主链；跳过 concat demuxer，避免最后一段被 demuxer 丢弃。audio_shift={audio_shift_ms:.0f}ms | clip_gap={clip_gap_ms:.0f}ms", "info")
        entries: List[Tuple[Clip, Path, float]] = []
        source_count = len(clips)
        for idx, c in enumerate(clips, 1):
            if not c.local_path or not Path(c.local_path).exists():
                self.log(f"V17跳过未缓存片段：{c.text[:60]}", "warn")
                continue
            src = Path(c.local_path)
            dst = work / f"std_{len(entries)+1:04d}.mp4"
            dur = self._std_clip_v15(src, dst, resolution)
            if dur is None:
                self.log(f"V17标准化失败：{src}", "err")
                continue
            dur = max(self._v_dur(dst) or dur, 0.05)
            entries.append((c, dst, dur))
            self.log(f"V17标准化 {len(entries)}/{source_count} OK: {dst.name} | video={dur:.3f}s", "ok")
            if clip_gap_ms > 0 and idx < source_count:
                gap_dur = clip_gap_ms / 1000.0
                gap = work / f"gap_{len(entries)+1:04d}.mp4"
                if self._make_gap_clip(gap, resolution, gap_dur):
                    dummy = Clip(keyword=c.keyword, text="", video_url="", title="gap", year="")
                    dummy.zh = ""
                    entries.append((dummy, gap, max(self._v_dur(gap), gap_dur)))
        if not entries:
            self.log("V17渲染失败：没有可用的标准化片段。", "err")
            return None
        std_total = sum(d for _, _, d in entries)
        self.log(f"V17标准化总时长：{std_total:.3f}s；进入 filter concat 文件数：{len(entries)}", "info")
        raw_merged = work / "merged_filter_primary.mp4"
        if not self._concat_filter_v16(entries, raw_merged):
            self.log("V17 filter_complex concat 失败，停止渲染。", "err")
            return None
        concat_dur = self._v_dur(raw_merged) or self.ffmpeg.duration(raw_merged) or 0.0
        if concat_dur < std_total - 0.35:
            self.log(f"V17严重错误：filter concat 仍短于标准化总时长 concat={concat_dur:.3f}s std_total={std_total:.3f}s；停止输出。", "err")
            return None
        if concat_dur > std_total + 0.75:
            self.log(f"V17提示：filter concat={concat_dur:.3f}s 大于标准化累加={std_total:.3f}s；后续字幕仍按各片段累加，最终上限按真实视频时长。", "warn")
        else:
            self.log(f"V17 filter concat真实时长：{concat_dur:.3f}s", "ok")
        synced = work / "merged_sync.mp4"
        if not self._sync_merge_av(raw_merged, synced, concat_dur, audio_shift_ms):
            self.log("V17音画同步校准失败，停止渲染。", "err")
            return None
        vd, ad = self._v_dur(synced), self._a_dur(synced)
        self.log(f"V17音画同步后：video={vd:.3f}s audio={ad:.3f}s diff={abs(vd-ad):.3f}s", "ok" if abs(vd-ad) <= 0.12 else "warn")
        final_dur = vd or concat_dur
        out_path = out_dir / f"{safe_name(name)}_merged.mp4"
        if options.get("subtitle_mode", "bilingual") == "none":
            shutil.copy2(synced, out_path)
        else:
            ass = work / f"{safe_name(name)}_v17.ass"
            subtitle_entries = [(c, d) for c, _, d in entries if c.text]
            self._make_ass_timeline_v17(subtitle_entries, ass, options, final_dur)
            ass_path = str(ass.resolve()).replace("\\", "/")
            ass_path = re.sub(r"^([A-Za-z]):/", r"\1\\:/", ass_path)
            cmd2 = [self.ffmpeg.ffmpeg, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(synced), "-vf", f"ass='{ass_path}'", "-t", f"{final_dur:.6f}", "-shortest", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2", "-movflags", "+faststart", str(out_path)]
            r2 = self.ffmpeg.run(cmd2, "V17字幕烧录与对齐", 1200)
            if r2.returncode != 0 or not out_path.exists() or out_path.stat().st_size < 2048:
                self.log("V17字幕烧录失败，降级输出无字幕同步版。", "warn")
                shutil.copy2(synced, out_path)
        vd2, ad2 = self._v_dur(out_path), self._a_dur(out_path)
        self.log(f"V17渲染完成：{out_path} | video={vd2:.3f}s audio={ad2:.3f}s diff={abs(vd2-ad2):.3f}s", "ok" if abs(vd2-ad2) <= 0.15 else "warn")
        if not options.get("keep_clips", False):
            try:
                shutil.rmtree(work, ignore_errors=True)
            except Exception:
                pass
        return out_path


_old_main_init_v17_base = MainApp.__init__

def _main_init_v17(self):
    _old_main_init_v17_base(self)
    self.renderer = RenderServiceV17(self.ffmpeg, self.subtitle, self.log)
    self.log("PlayPhrase Studio Clean v17 启动：RenderServiceV17 已启用；filter_complex concat 为主链；关键词+双滚动英文上层恢复滚动。", "ok")

MainApp.__init__ = _main_init_v17


