# ──────────────────────────────────────────────────────────────────────
# Clean v18: subtitle anti-overlap + online/API translation + packaged Argos recovery
# ──────────────────────────────────────────────────────────────────────

def _config_search_paths_v18(filename: str) -> List[Path]:
    """Search config next to exe, current working dir, and source dir.

    This fixes packaged EXE runs where translation_config.json is not found
    because cwd differs from the executable directory.
    """
    out: List[Path] = []
    try:
        if getattr(sys, "frozen", False):
            base = Path(sys.executable).resolve().parent
            out.extend([base / filename, base.parent / filename, base / "_internal" / filename])
    except Exception:
        pass
    try:
        out.append(Path.cwd() / filename)
    except Exception:
        pass
    try:
        out.append(Path(__file__).resolve().parent / filename)
    except Exception:
        pass
    seen = set(); uniq: List[Path] = []
    for p in out:
        sp = str(p)
        if sp not in seen:
            seen.add(sp); uniq.append(p)
    return uniq


def _load_translation_config_v18(self) -> Dict[str, Any]:
    data: Dict[str, Any] = {}
    used = ""
    for p in _config_search_paths_v18("translation_config.json"):
        try:
            if p.exists():
                data = json.loads(p.read_text("utf-8"))
                used = str(p)
                break
        except Exception as e:
            try:
                self.log(f"翻译配置读取失败：{p} | {e}", "warn")
            except Exception:
                pass
    # Keep old names, but also accept clearer aliases.
    data.setdefault("tencent_id", os.getenv("TENCENT_ID", os.getenv("TENCENT_SECRET_ID", "")))
    data.setdefault("tencent_key", os.getenv("TENCENT_KEY", os.getenv("TENCENT_SECRET_KEY", "")))
    data.setdefault("tencent_region", os.getenv("TENCENT_REGION", "ap-guangzhou"))
    data.setdefault("tencent_endpoint", os.getenv("TENCENT_ENDPOINT", "tmt.tencentcloudapi.com"))
    data.setdefault("baidu_id", os.getenv("BAIDU_ID", os.getenv("BAIDU_APPID", "")))
    data.setdefault("baidu_key", os.getenv("BAIDU_KEY", os.getenv("BAIDU_SECRET", "")))
    data.setdefault("argos_package_dir", os.getenv("ARGOS_PACKAGE_DIR", ""))
    data["_config_path"] = used
    return data


def _cfg_v18(self, *names: str, default: str = "") -> str:
    for n in names:
        v = self.config.get(n)
        if v is not None and str(v).strip():
            return str(v).strip()
    return default


def _argos_v18(self, text: str) -> str:
    """Argos local translation with better diagnostics and packaged EXE recovery."""
    text = norm(text)
    if not text:
        return ""
    try:
        # Lazy import helps both source mode and PyInstaller hidden-import mode.
        from argostranslate import translate as argos_translate  # type: ignore
        try:
            pkg_dir = _cfg_v18(self, "argos_package_dir", default="")
            if pkg_dir:
                pkg_path = Path(pkg_dir)
                if not pkg_path.is_absolute():
                    for base in [Path.cwd(), Path(sys.executable).resolve().parent if getattr(sys, "frozen", False) else Path(__file__).resolve().parent]:
                        cand = base / pkg_path
                        if cand.exists():
                            pkg_path = cand
                            break
                # Some Argos versions read this env var; if unsupported it is harmless.
                os.environ.setdefault("ARGOS_PACKAGE_DIR", str(pkg_path))
        except Exception:
            pass
        if not getattr(self, "argos_engine", None):
            langs = argos_translate.get_installed_languages()
            en = next((l for l in langs if getattr(l, "code", "") == "en"), None)
            zh = next((l for l in langs if getattr(l, "code", "") in {"zh", "zh_cn", "zh-CN"}), None)
            if not en or not zh:
                self.log("Argos 本地翻译不可用：未检测到 en→zh 语言包。请在打包环境安装 argostranslate，并安装 en_zh 模型。", "warn")
                return ""
            self.argos_engine = en.get_translation(zh)
        return norm(self.argos_engine.translate(text))
    except Exception as e:
        self.log(f"Argos 本地翻译失败：{type(e).__name__}: {e}", "warn")
        return ""


def _baidu_translate_v18(self, text: str) -> str:
    """Baidu General Translate API: q + appid + salt + sign(md5)."""
    text = norm(text)
    appid = _cfg_v18(self, "baidu_id", "baidu_appid", default="")
    secret = _cfg_v18(self, "baidu_key", "baidu_secret", default="")
    if not text or not appid or not secret:
        self.log("百度翻译未配置：请在 translation_config.json 填 baidu_id / baidu_key。", "warn")
        return ""
    try:
        salt = str(int(time.time() * 1000))
        sign_src = appid + text + salt + secret
        sign = hashlib.md5(sign_src.encode("utf-8")).hexdigest()
        params = {
            "q": text,
            "from": self.config.get("baidu_from", "en"),
            "to": self.config.get("baidu_to", "zh"),
            "appid": appid,
            "salt": salt,
            "sign": sign,
        }
        r = requests.get("https://fanyi-api.baidu.com/api/trans/vip/translate", params=params, timeout=12)
        r.raise_for_status()
        data = r.json()
        if "error_code" in data:
            self.log(f"百度翻译失败：{data.get('error_code')} {data.get('error_msg', '')}", "warn")
            return ""
        items = data.get("trans_result") or []
        return norm("\n".join(x.get("dst", "") for x in items if isinstance(x, dict)))
    except Exception as e:
        self.log(f"百度翻译异常：{type(e).__name__}: {e}", "warn")
        return ""


def _tencent_translate_v18(self, text: str) -> str:
    """Tencent Cloud TMT TextTranslate with TC3-HMAC-SHA256 signature."""
    text = norm(text)
    secret_id = _cfg_v18(self, "tencent_id", "tencent_secret_id", default="")
    secret_key = _cfg_v18(self, "tencent_key", "tencent_secret_key", default="")
    if not text or not secret_id or not secret_key:
        self.log("腾讯翻译未配置：请在 translation_config.json 填 tencent_id / tencent_key。", "warn")
        return ""
    try:
        import hmac
        endpoint = _cfg_v18(self, "tencent_endpoint", default="tmt.tencentcloudapi.com")
        host = endpoint
        service = "tmt"
        region = _cfg_v18(self, "tencent_region", default="ap-guangzhou")
        version = "2018-03-21"
        action = "TextTranslate"
        payload_dict = {
            "SourceText": text,
            "Source": self.config.get("tencent_source", "en"),
            "Target": self.config.get("tencent_target", "zh"),
            "ProjectId": int(self.config.get("tencent_project_id", 0) or 0),
        }
        payload = json.dumps(payload_dict, ensure_ascii=False, separators=(",", ":"))
        timestamp = int(time.time())
        date = datetime.utcfromtimestamp(timestamp).strftime("%Y-%m-%d")
        http_request_method = "POST"
        canonical_uri = "/"
        canonical_querystring = ""
        canonical_headers = f"content-type:application/json; charset=utf-8\nhost:{host}\nx-tc-action:{action.lower()}\n"
        signed_headers = "content-type;host;x-tc-action"
        hashed_request_payload = hashlib.sha256(payload.encode("utf-8")).hexdigest()
        canonical_request = "\n".join([http_request_method, canonical_uri, canonical_querystring, canonical_headers, signed_headers, hashed_request_payload])
        algorithm = "TC3-HMAC-SHA256"
        credential_scope = f"{date}/{service}/tc3_request"
        hashed_canonical_request = hashlib.sha256(canonical_request.encode("utf-8")).hexdigest()
        string_to_sign = "\n".join([algorithm, str(timestamp), credential_scope, hashed_canonical_request])

        def sign(key: bytes, msg: str) -> bytes:
            return hmac.new(key, msg.encode("utf-8"), hashlib.sha256).digest()

        secret_date = sign(("TC3" + secret_key).encode("utf-8"), date)
        secret_service = sign(secret_date, service)
        secret_signing = sign(secret_service, "tc3_request")
        signature = hmac.new(secret_signing, string_to_sign.encode("utf-8"), hashlib.sha256).hexdigest()
        authorization = f"{algorithm} Credential={secret_id}/{credential_scope}, SignedHeaders={signed_headers}, Signature={signature}"
        headers = {
            "Authorization": authorization,
            "Content-Type": "application/json; charset=utf-8",
            "Host": host,
            "X-TC-Action": action,
            "X-TC-Timestamp": str(timestamp),
            "X-TC-Version": version,
            "X-TC-Region": region,
        }
        r = requests.post("https://" + endpoint, data=payload.encode("utf-8"), headers=headers, timeout=12)
        r.raise_for_status()
        data = r.json()
        resp = data.get("Response", {}) if isinstance(data, dict) else {}
        if "Error" in resp:
            err = resp.get("Error", {})
            self.log(f"腾讯翻译失败：{err.get('Code', '')} {err.get('Message', '')}", "warn")
            return ""
        return norm(resp.get("TargetText", ""))
    except Exception as e:
        self.log(f"腾讯翻译异常：{type(e).__name__}: {e}", "warn")
        return ""


def _translate_one_v18(self, text: str, engine: str) -> str:
    text = norm(text)
    engine = str(engine or "none").lower()
    if not text or engine == "none":
        return ""
    corr = {
        "there's nothing to be done.": "没什么可做的了。",
        "i'm only trying to help you.": "我只是想帮你。",
        "cat got your tongue?": "怎么不说话了？",
    }
    if text.lower() in corr:
        return corr[text.lower()]
    if engine == "manual":
        return ""
    if engine == "argos":
        return _argos_v18(self, text)
    if engine == "baidu":
        return _baidu_translate_v18(self, text)
    if engine == "tencent":
        return _tencent_translate_v18(self, text)
    if engine == "auto":
        # Fast local first, then configured cloud fallback.
        z = _argos_v18(self, text)
        if z:
            return z
        if _cfg_v18(self, "tencent_id", "tencent_secret_id", default="") and _cfg_v18(self, "tencent_key", "tencent_secret_key", default=""):
            z = _tencent_translate_v18(self, text)
            if z:
                return z
        if _cfg_v18(self, "baidu_id", "baidu_appid", default="") and _cfg_v18(self, "baidu_key", "baidu_secret", default=""):
            z = _baidu_translate_v18(self, text)
            if z:
                return z
    return ""


def _batch_translate_v18(self, clips: List[Clip], engine: str) -> None:
    if engine in ("none", "manual"):
        return
    total = len(clips)
    for i, c in enumerate(clips, 1):
        if not c.zh:
            z = self.translate_one(c.text, engine)
            if z:
                c.zh = z
                self.log(f"翻译 {i}/{total} OK: {c.text[:36]} -> {z[:36]}", "dim")
            else:
                self.log(f"翻译 {i}/{total} 未得到结果：{c.text[:50]}", "warn")

TranslateService._load_config = _load_translation_config_v18
TranslateService.translate_one = _translate_one_v18
TranslateService.batch_translate = _batch_translate_v18


def _plain_lines_limited_v18(text: str, max_chars: int, max_lines: int = 3, prefer_words: bool = True) -> List[str]:
    raw = norm(text)
    if not raw:
        return []
    max_chars = max(8, int(max_chars))
    max_lines = max(1, int(max_lines))
    if re.search(r"[\u4e00-\u9fff]", raw):
        s = re.sub(r"\s+", " ", raw)
        lines = [s[i:i + max_chars].strip() for i in range(0, len(s), max_chars)]
    elif prefer_words:
        words = raw.split()
        lines, cur = [], ""
        for w in words:
            nxt = w if not cur else cur + " " + w
            if len(nxt) <= max_chars or not cur:
                cur = nxt
            else:
                lines.append(cur)
                cur = w
        if cur:
            lines.append(cur)
    else:
        lines = [raw[i:i + max_chars].strip() for i in range(0, len(raw), max_chars)]
    # Do not create unlimited vertical blocks; merge tail into last visible line.
    if len(lines) > max_lines:
        lines = lines[:max_lines - 1] + [" ".join(lines[max_lines - 1:])]
    return [x for x in lines if x]


def _ass_wrap_text_v18(text: str, max_chars: int, max_lines: int = 3, prefer_words: bool = True) -> str:
    return r"\N".join(ass_escape(x) for x in _plain_lines_limited_v18(text, max_chars, max_lines, prefer_words))


def _karaoke_wrapped_v18(text: str, duration_sec: float, max_chars: int, max_lines: int = 3) -> str:
    wrapped = _ass_wrap_text_v18(text, max_chars, max_lines, True).replace(r"\N", " \\N ")
    tokens = [t for t in re.split(r"(\\N|\s+)", wrapped) if t != ""]
    words = [t for t in tokens if (not t.isspace() and t != r"\N")]
    if not words:
        return ass_escape(text)
    total_cs = max(int(round(max(duration_sec, 0.1) * 100)), len(words))
    each = max(1, total_cs // max(len(words), 1))
    out = []
    for t in tokens:
        if t == r"\N":
            out.append(r"\N")
        elif t.isspace():
            out.append(t)
        else:
            out.append("{\\kf%d}%s" % (each, t))
    return "".join(out)


def _keyword_highlight_wrapped_v18(text: str, keyword: str, color: str, max_chars: int, max_lines: int = 3) -> str:
    wrapped_plain = _ass_wrap_text_v18(text, max_chars, max_lines, True)
    kw = norm(keyword)
    if not kw:
        return wrapped_plain
    col = ASS_COLOR.get(color, ASS_COLOR.get("red"))
    white = ASS_COLOR.get("white")
    try:
        pattern = re.compile(re.escape(ass_escape(kw)), re.I)
        return pattern.sub(lambda m: "{\\c%s\\b1}%s{\\c%s\\b0}" % (col, m.group(0), white), wrapped_plain)
    except Exception:
        return wrapped_plain


def _keyword_karaoke_wrapped_v18(text: str, keyword: str, duration_sec: float, max_chars: int, keyword_color: str = "red", max_lines: int = 3) -> str:
    raw = norm(text)
    kw = norm(keyword)
    if not raw:
        return ""
    if not kw:
        return _karaoke_wrapped_v18(raw, duration_sec, max_chars, max_lines)
    lines = _plain_lines_limited_v18(raw, max_chars, max_lines, True)
    pattern = re.compile(re.escape(kw), re.I)
    non_kw_count = 0
    for line in lines:
        pos = 0
        for m in pattern.finditer(line):
            non_kw_count += len([x for x in re.split(r"\s+", line[pos:m.start()].strip()) if x])
            pos = m.end()
        non_kw_count += len([x for x in re.split(r"\s+", line[pos:].strip()) if x])
    total_cs = max(int(round(max(duration_sec, 0.1) * 100)), max(non_kw_count, 1))
    each = max(1, total_cs // max(non_kw_count, 1))
    red = ASS_COLOR.get(keyword_color, ASS_COLOR["red"])
    rendered = []
    for line in lines:
        parts, pos = [], 0
        for m in pattern.finditer(line):
            before = line[pos:m.start()]
            if before:
                parts.append(_karaoke_plain_piece_v17(before, each))
            parts.append("{\\kf0\\c%s\\b1}%s{\\rEnKaraoke}" % (red, ass_escape(m.group(0))))
            pos = m.end()
        tail = line[pos:]
        if tail:
            parts.append(_karaoke_plain_piece_v17(tail, each))
        rendered.append("".join(parts))
    return r"\N".join(rendered)


def _make_ass_timeline_v18(self, entries: List[Tuple[Clip, float]], out_path: Path, options: Dict[str, Any], final_dur: float) -> Path:
    shift = _clamp_float(options.get("subtitle_shift_ms", 0), -10000, 10000, 0.0) / 1000.0
    w, h = parse_resolution(options.get("resolution", "1080x1920"))
    subtitle_mode = options.get("subtitle_mode", "bilingual")
    style = options.get("subtitle_style", "static")
    font_size = int(options.get("font_size", 42))
    en_base = options.get("en_base", "white")
    en_cover = options.get("en_cover", "white")
    zh_base = options.get("zh_base", "white")
    zh_cover = options.get("zh_cover", "yellow")
    keyword_color = options.get("keyword_color", "red")
    vertical = h >= w
    # Anti-overlap layout: Chinese stays low; English is lifted enough for 2–3 Chinese lines.
    zh_margin = 120 if vertical else 42
    en_margin = 315 if vertical else 190
    fs_zh = max(22, int(font_size * 0.76))
    max_en = 30 if vertical else 42
    max_zh = 18 if vertical else 24
    en_lines = 3
    zh_lines = 3
    outline = 2
    shadow = 0
    en_primary = ASS_COLOR.get(en_cover if en_cover != "white" else en_base, ASS_COLOR["white"])
    en_secondary = ASS_COLOR.get(en_base, ASS_COLOR["white"])
    zh_primary = ASS_COLOR.get(zh_cover if zh_cover != "white" else zh_base, ASS_COLOR["white"])
    zh_secondary = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
    static_en = ASS_COLOR.get(en_base, ASS_COLOR["white"])
    static_zh = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
    header = f"""[Script Info]\nScriptType: v4.00+\nPlayResX: {w}\nPlayResY: {h}\nScaledBorderAndShadow: yes\nWrapStyle: 0\n\n[V4+ Styles]\nFormat: Name,Fontname,Fontsize,PrimaryColour,SecondaryColour,OutlineColour,BackColour,Bold,Italic,Underline,StrikeOut,ScaleX,ScaleY,Spacing,Angle,BorderStyle,Outline,Shadow,Alignment,MarginL,MarginR,MarginV,Encoding\nStyle: EnStatic,Microsoft YaHei,{font_size},{static_en},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},2,80,80,{en_margin},1\nStyle: ZhStatic,Microsoft YaHei,{fs_zh},{static_zh},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},2,80,80,{zh_margin},1\nStyle: EnKaraoke,Microsoft YaHei,{font_size},{en_primary},{en_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},2,80,80,{en_margin},1\nStyle: ZhKaraoke,Microsoft YaHei,{fs_zh},{zh_primary},{zh_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},2,80,80,{zh_margin},1\n\n[Events]\nFormat: Layer,Start,End,Style,Name,MarginL,MarginR,MarginV,Effect,Text\n"""
    lines = [header]
    cur = 0.0
    for c, dur in entries:
        if not c.text:
            cur += dur
            continue
        start = max(0.0, cur + shift)
        end = min(final_dur, max(start + 0.05, cur + dur + shift))
        if end <= 0 or start >= final_dur:
            cur += dur
            continue
        en = c.text or ""
        zh = c.zh or ""
        span = max(end - start, 0.1)
        if subtitle_mode == "none":
            cur += dur
            continue
        if style == "keyword_highlight":
            en_body = _keyword_highlight_wrapped_v18(en, c.keyword, keyword_color, max_en, en_lines)
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_body}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")
        elif style in ("en_karaoke_yellow", "en_karaoke_orange"):
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v18(en, span, max_en, en_lines)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")
        elif style == "bilingual_karaoke":
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v18(en, span, max_en, en_lines)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v18(zh, span, max_zh, zh_lines)}\n")
        elif style == "keyword_bilingual_karaoke":
            en_body = _keyword_karaoke_wrapped_v18(en, c.keyword, span, max_en, keyword_color, en_lines)
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{en_body}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v18(zh, span, max_zh, zh_lines)}\n")
        else:
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{_ass_wrap_text_v18(en, max_en, en_lines, True)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")
        cur += dur
    out_path.write_text("".join(lines), "utf-8-sig")
    return out_path

# Override final renderer timeline method only; keep V17 concat/sync engine.
try:
    RenderServiceV17._make_ass_timeline_v17 = _make_ass_timeline_v18
except Exception:
    pass

