# NOTE: MainApp startup moved to the end of file.
# The V19 translation monkey patches below must be applied BEFORE Tk mainloop starts;
# otherwise only the old Argos/auto translator will run.

# ──────────────────────────────────────────────────────────────────────
# V19 translation stack: OPUS-MT primary, Argos fallback, online enhancement
# 普通句子：OPUS-MT en↔zh 主力；Argos 兜底
# 小说 / 古英语 / 医学 / 诗歌 / 术语：腾讯 / 百度 / DeepL / Google 在线增强
# ──────────────────────────────────────────────────────────────────────
def _bool_cfg_v19(self, name: str, default: bool = False) -> bool:
    v = str(self.config.get(name, default)).strip().lower()
    return v in {"1", "true", "yes", "y", "on", "是", "开启"}


def _detect_lang_v19(text: str) -> str:
    t = str(text or "")
    # Chinese characters dominate -> zh, otherwise English by default for subtitles.
    zh_count = len(re.findall(r"[\u4e00-\u9fff]", t))
    ascii_letters = len(re.findall(r"[A-Za-z]", t))
    return "zh" if zh_count > max(2, ascii_letters * 0.3) else "en"


def _target_lang_v19(self, source_lang: str) -> str:
    # For current subtitle workflow, English -> Chinese is default; Chinese -> English is supported for lookup/testing.
    if source_lang.startswith("zh"):
        return str(self.config.get("translate_target_for_zh", "en")).strip() or "en"
    return str(self.config.get("translate_target_for_en", "zh")).strip() or "zh"


def _opus_model_ref_v19(self, source_lang: str, target_lang: str) -> tuple[str, bool]:
    pair = "zh_en" if source_lang.startswith("zh") else "en_zh"
    dir_key = f"opus_{pair}_model_dir"
    id_key = f"opus_{pair}_model_id"
    default_id = "Helsinki-NLP/opus-mt-zh-en" if pair == "zh_en" else "Helsinki-NLP/opus-mt-en-zh"
    model_dir = str(self.config.get(dir_key, "")).strip()
    if not model_dir:
        model_dir = str(Path("models") / ("opus-mt-zh-en" if pair == "zh_en" else "opus-mt-en-zh"))
    p = Path(model_dir)
    if not p.is_absolute():
        bases = []
        try:
            bases.append(Path(sys.executable).resolve().parent if getattr(sys, "frozen", False) else Path(__file__).resolve().parent)
        except Exception:
            pass
        try:
            bases.append(Path.cwd())
        except Exception:
            pass
        for base in bases:
            cand = base / p
            if cand.exists():
                return str(cand), True
    elif p.exists():
        return str(p), True
    allow_download = _bool_cfg_v19(self, "opus_allow_download", False)
    return str(self.config.get(id_key, default_id)).strip() or default_id, not allow_download


def _opus_translate_v19(self, text: str, source_lang: str = "", target_lang: str = "") -> str:
    text = norm(text)
    if not text:
        return ""
    source_lang = source_lang or _detect_lang_v19(text)
    target_lang = target_lang or _target_lang_v19(self, source_lang)
    if source_lang == target_lang:
        return text
    try:
        # Direct generate is more stable than transformers.pipeline("translation") in newer transformers builds.
        from transformers import AutoTokenizer, AutoModelForSeq2SeqLM  # type: ignore
        if not hasattr(self, "_opus_models"):
            self._opus_models = {}
        pair_key = f"{source_lang}->{target_lang}"
        if pair_key not in self._opus_models:
            model_ref, local_only = _opus_model_ref_v19(self, source_lang, target_lang)
            tokenizer = AutoTokenizer.from_pretrained(model_ref, local_files_only=local_only)
            model = AutoModelForSeq2SeqLM.from_pretrained(model_ref, local_files_only=local_only)
            model.eval()
            self._opus_models[pair_key] = {"tokenizer": tokenizer, "model": model, "model_ref": model_ref}
            self.log(f"OPUS-MT 加载成功：{pair_key} | {model_ref} | direct_generate", "ok")
        pack = self._opus_models[pair_key]
        tokenizer = pack["tokenizer"]
        model = pack["model"]
        max_len = int(self.config.get("opus_max_length", 512) or 512)
        inputs = tokenizer(text, return_tensors="pt", truncation=True, max_length=max_len)
        outputs = model.generate(**inputs, max_length=max_len, num_beams=4, early_stopping=True)
        translated = tokenizer.decode(outputs[0], skip_special_tokens=True)
        return norm(translated)
    except Exception as e:
        self.log(f"OPUS-MT 本地翻译失败：{type(e).__name__}: {e}", "warn")
        return ""

def _deepl_translate_v19(self, text: str, source_lang: str = "", target_lang: str = "") -> str:
    text = norm(text)
    key = _cfg_v18(self, "deepl_auth_key", "deepl_key", default="")
    if not text or not key:
        self.log("DeepL 未配置：请在 translation_config.json 填 deepl_auth_key。", "warn")
        return ""
    try:
        endpoint = str(self.config.get("deepl_endpoint", "")).strip()
        if not endpoint:
            endpoint = "https://api-free.deepl.com/v2/translate" if key.endswith(":fx") else "https://api.deepl.com/v2/translate"
        source_lang = (source_lang or _detect_lang_v19(text)).upper().replace("ZH", "ZH")
        target_lang = (target_lang or _target_lang_v19(self, source_lang.lower())).upper()
        # DeepL uses ZH and EN. Omit source when auto detection is preferred.
        payload = {
            "auth_key": key,
            "text": text,
            "target_lang": "ZH" if target_lang.startswith("ZH") else target_lang,
        }
        if source_lang in {"EN", "ZH"}:
            payload["source_lang"] = source_lang
        r = requests.post(endpoint, data=payload, timeout=18)
        r.raise_for_status()
        data = r.json()
        items = data.get("translations") or []
        if items:
            return norm(items[0].get("text", ""))
        return ""
    except Exception as e:
        self.log(f"DeepL 翻译异常：{type(e).__name__}: {e}", "warn")
        return ""


def _google_translate_v19(self, text: str, source_lang: str = "", target_lang: str = "") -> str:
    """Google web translate fallback. No official key; may be rate-limited by Google."""
    text = norm(text)
    if not text:
        return ""
    try:
        sl = "auto" if not source_lang else ("zh-CN" if source_lang.startswith("zh") else "en")
        tgt = target_lang or _target_lang_v19(self, _detect_lang_v19(text))
        tl = "zh-CN" if tgt.startswith("zh") else "en"
        params = {"client": "gtx", "sl": sl, "tl": tl, "dt": "t", "q": text}
        r = requests.get("https://translate.googleapis.com/translate_a/single", params=params, timeout=15)
        r.raise_for_status()
        data = r.json()
        if isinstance(data, list) and data and isinstance(data[0], list):
            return norm("".join(seg[0] for seg in data[0] if isinstance(seg, list) and seg))
        return ""
    except Exception as e:
        self.log(f"Google 在线翻译异常：{type(e).__name__}: {e}", "warn")
        return ""


def _is_special_domain_v19(self, text: str) -> bool:
    t = norm(text)
    low = t.lower()
    # User-configurable forcing regex. Example: "medical|thou|diagnosis".
    custom = str(self.config.get("online_enhance_regex", "")).strip()
    if custom:
        try:
            if re.search(custom, t, re.I):
                return True
        except Exception:
            pass
    old_english = r"\b(thou|thee|thy|thine|ye|hath|doth|art thou|shalt|wherefore|hither|hence)\b"
    medical = r"\b(diagnosis|diagnostic|symptom|syndrome|therapy|clinical|surgery|tumou?r|infection|pathology|cardiac|renal|hepatic|neurological|dosage|contraindication)\b"
    terminology = r"\b[A-Z]{2,}\b|\b[A-Za-z]+(?:-[A-Za-z]+){2,}\b"
    poetry = r"\b(verse|stanza|rhyme|sonnet|metaphor|ode)\b"
    if re.search(old_english, low) or re.search(medical, low) or re.search(poetry, low) or re.search(terminology, t):
        return True
    if len(t) > int(self.config.get("online_enhance_long_text_threshold", 180) or 180):
        return True
    return False


def _online_enhanced_v19(self, text: str, source_lang: str = "", target_lang: str = "") -> str:
    order_raw = str(self.config.get("online_provider_order", "tencent,baidu,deepl,google"))
    providers = [x.strip().lower() for x in re.split(r"[,;|/\\\s]+", order_raw) if x.strip()]
    for p in providers:
        if p == "tencent":
            z = _tencent_translate_v18(self, text)
        elif p == "baidu":
            z = _baidu_translate_v18(self, text)
        elif p == "deepl":
            z = _deepl_translate_v19(self, text, source_lang, target_lang)
        elif p == "google":
            z = _google_translate_v19(self, text, source_lang, target_lang)
        else:
            continue
        if z:
            self.log(f"在线增强翻译采用：{p}", "dim")
            return z
    return ""


def _translate_one_v19(self, text: str, engine: str) -> str:
    text = norm(text)
    engine = str(engine or "none").lower()
    if not text or engine == "none":
        return ""
    corr = {
        "there's nothing to be done.": "没什么可做的了。",
        "i'm only trying to help you.": "我只是想帮你。",
        "cat got your tongue?": "怎么不说话了？",
    }
    if text.lower() in corr:
        return corr[text.lower()]
    if engine == "manual":
        return ""
    src = _detect_lang_v19(text)
    tgt = _target_lang_v19(self, src)

    if engine == "opus":
        return _opus_translate_v19(self, text, src, tgt)
    if engine == "argos":
        return _argos_v18(self, text)
    if engine == "deepl":
        return _deepl_translate_v19(self, text, src, tgt)
    if engine == "google":
        return _google_translate_v19(self, text, src, tgt)
    if engine == "baidu":
        return _baidu_translate_v18(self, text)
    if engine == "tencent":
        return _tencent_translate_v18(self, text)
    if engine == "online_enhanced":
        return _online_enhanced_v19(self, text, src, tgt)
    if engine == "smart":
        # Specialized material goes online first; ordinary subtitle/sentence stays local first.
        if _is_special_domain_v19(self, text):
            z = _online_enhanced_v19(self, text, src, tgt)
            if z:
                return z
        z = _opus_translate_v19(self, text, src, tgt)
        if z:
            return z
        z = _argos_v18(self, text)
        if z:
            return z
        if _bool_cfg_v19(self, "smart_online_fallback", True):
            return _online_enhanced_v19(self, text, src, tgt)
        return ""
    if engine == "auto":
        # Backward-compatible: local first, then cloud.
        z = _opus_translate_v19(self, text, src, tgt)
        if z:
            return z
        z = _argos_v18(self, text)
        if z:
            return z
        return _online_enhanced_v19(self, text, src, tgt)
    return ""


def _batch_translate_v19(self, clips: List[Clip], engine: str) -> None:
    if str(engine or "").lower() in ("none", "manual"):
        return
    total = len(clips)
    for i, c in enumerate(clips, 1):
        if not c.zh:
            z = self.translate_one(c.text, engine)
            if z:
                c.zh = z
                self.log(f"翻译 {i}/{total} OK [{engine}]: {c.text[:36]} -> {z[:36]}", "dim")
            else:
                self.log(f"翻译 {i}/{total} 未得到结果 [{engine}]：{c.text[:50]}", "warn")


# Override V18 patch with V19 translation policy.
TranslateService.translate_one = _translate_one_v19
TranslateService.batch_translate = _batch_translate_v19



