def _combo_to_value_v21(label: str, options):
    return next((v for k, v in options if k == label), options[0][1])


def _value_to_label_v21(value: str, options):
    return next((k for k, v in options if v == value), options[0][0])


def _ffmpeg_escape_path_v21(p: Path) -> str:
    s = str(Path(p).resolve()).replace("\\", "/")
    s = re.sub(r"^([A-Za-z]):/", r"\1\\:/", s)
    s = s.replace("'", r"\'")
    return s


def _mousewheel_bind_v21(canvas, widget):
    def _on_enter(_e=None):
        canvas.bind_all("<MouseWheel>", _on_mousewheel)
    def _on_leave(_e=None):
        canvas.unbind_all("<MouseWheel>")
    def _on_mousewheel(e):
        delta = -1 * int((e.delta or 0) / 120)
        canvas.yview_scroll(delta, "units")
    widget.bind("<Enter>", _on_enter)
    widget.bind("<Leave>", _on_leave)


def _build_render_options_v21(self, parent):
    ttk.Label(parent, text="渲染选项", style="H.TLabel").pack(anchor="w")
    wrap = ttk.Frame(parent)
    wrap.pack(fill="both", expand=True, pady=(2, 0))
    canvas = tk.Canvas(wrap, bg=C_BG, highlightthickness=0, height=430)
    sb = ttk.Scrollbar(wrap, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=sb.set)
    canvas.pack(side="left", fill="both", expand=True)
    sb.pack(side="right", fill="y")
    inner = ttk.Frame(canvas)
    window = canvas.create_window((0, 0), window=inner, anchor="nw")
    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfigure(window, width=e.width))
    _mousewheel_bind_v21(canvas, inner)

    self.render_vars = {}

    def group(title: str):
        g = ttk.LabelFrame(inner, text=title, padding=(8, 6))
        g.pack(fill="x", pady=6)
        return g

    def combo(container, label, key, options, default_idx=0, width=26):
        f = ttk.Frame(container)
        f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        var = tk.StringVar(value=options[default_idx][0])
        cb = ttk.Combobox(f, state="readonly", textvariable=var, values=[x[0] for x in options], width=width)
        cb.pack(side="left", fill="x", expand=True)
        self.render_vars[key] = var
        return var

    def spin(container, label, var, frm, to, width=8):
        f = ttk.Frame(container)
        f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        ttk.Spinbox(f, from_=frm, to=to, textvariable=var, width=width).pack(side="left")
        return var

    g1 = group("基础渲染")
    combo(g1, "分辨率", "resolution", RESOLUTION_OPTIONS, 0)
    combo(g1, "渲染方式", "fit_mode", RENDER_FIT_MODE_OPTIONS_V22, 0)
    combo(g1, "字幕类型", "subtitle_mode", SUBTITLE_MODE_OPTIONS, 2)
    combo(g1, "字幕样式", "subtitle_style", SUBTITLE_STYLE_OPTIONS, 0)
    combo(g1, "字幕排列", "subtitle_arrangement", SUBTITLE_ARRANGEMENT_OPTIONS_V21, 0)
    combo(g1, "字幕位置", "subtitle_position", SUBTITLE_POSITION_OPTIONS_V21, 0)
    combo(g1, "英文底色", "en_base", COLOR_OPTIONS, 0)
    combo(g1, "英文覆盖", "en_cover", COLOR_OPTIONS, 0)
    combo(g1, "中文底色", "zh_base", COLOR_OPTIONS, 0)
    combo(g1, "中文覆盖", "zh_cover", COLOR_OPTIONS, 2)
    combo(g1, "翻译引擎", "translate_engine", TRANSLATE_ENGINE_OPTIONS, 0)
    self.font_size_var = tk.IntVar(value=42)
    spin(g1, "字体大小", self.font_size_var, 24, 90)
    self.keep_clips_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(g1, text="保留工作 clips/std 文件", variable=self.keep_clips_var).pack(anchor="w", pady=2)

    g2 = group("美化视频")
    combo(g2, "黑边美化", "beauty_mode", BEAUTY_MODE_OPTIONS_V21, 0)
    self.title_enable_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(g2, text="启用顶部标题栏", variable=self.title_enable_var).pack(anchor="w", pady=(2, 0))
    combo(g2, "标题预设", "title_preset", TITLE_PRESET_OPTIONS_V21, 0)
    f = ttk.Frame(g2); f.pack(fill="x", pady=2)
    ttk.Label(f, text="自定义标题", width=12).pack(side="left")
    self.title_text_var = tk.StringVar(value="")
    ttk.Entry(f, textvariable=self.title_text_var).pack(side="left", fill="x", expand=True)
    self.title_font_size_var = tk.IntVar(value=28)
    spin(g2, "标题字号", self.title_font_size_var, 18, 72)
    combo(g2, "标题颜色", "title_color", TEXT_STYLE_COLOR_OPTIONS_V21, 0)

    self.watermark_enable_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(g2, text="启用文字水印", variable=self.watermark_enable_var).pack(anchor="w", pady=(4, 0))
    f = ttk.Frame(g2); f.pack(fill="x", pady=2)
    ttk.Label(f, text="水印文字", width=12).pack(side="left")
    self.watermark_text_var = tk.StringVar(value="")
    ttk.Entry(f, textvariable=self.watermark_text_var).pack(side="left", fill="x", expand=True)
    self.watermark_font_size_var = tk.IntVar(value=24)
    spin(g2, "水印字号", self.watermark_font_size_var, 14, 60)
    combo(g2, "水印颜色", "watermark_color", TEXT_STYLE_COLOR_OPTIONS_V21, 0)

    g3 = group("添加图片 / 遮罩")
    f = ttk.Frame(g3); f.pack(fill="x", pady=2)
    ttk.Label(f, text="本地图片", width=12).pack(side="left")
    self.overlay_image_var = tk.StringVar(value="")
