def _build_render_options_v23(self, parent):
    """V23：用分页替代超长纵向表单，避免右侧渲染选项被遮挡。"""
    ttk.Label(parent, text="渲染选项", style="H.TLabel").pack(anchor="w")
    self.render_vars = {}

    nb = ttk.Notebook(parent)
    nb.pack(fill="both", expand=True, pady=(4, 0))

    tab_basic = ttk.Frame(nb, padding=8)
    tab_beauty = ttk.Frame(nb, padding=8)
    tab_overlay = ttk.Frame(nb, padding=8)

    nb.add(tab_basic, text="基础渲染")
    nb.add(tab_beauty, text="美化视频")
    nb.add(tab_overlay, text="图片/水印")

    def combo(container, label, key, options, default_idx=0, width=26):
        f = ttk.Frame(container)
        f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        var = tk.StringVar(value=options[default_idx][0])
        cb = ttk.Combobox(
            f, state="readonly", textvariable=var,
            values=[x[0] for x in options], width=width
        )
        cb.pack(side="left", fill="x", expand=True)
        self.render_vars[key] = var
        return var

    def spin(container, label, var, frm, to, width=8):
        f = ttk.Frame(container)
        f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        ttk.Spinbox(f, from_=frm, to=to, textvariable=var, width=width).pack(side="left")
        return var

    # 基础渲染
    combo(tab_basic, "分辨率", "resolution", RESOLUTION_OPTIONS, 0)
    combo(tab_basic, "渲染方式", "fit_mode", RENDER_FIT_MODE_OPTIONS_V22, 0)
    combo(tab_basic, "字幕类型", "subtitle_mode", SUBTITLE_MODE_OPTIONS, 2)
    combo(tab_basic, "字幕样式", "subtitle_style", SUBTITLE_STYLE_OPTIONS, 0)
    combo(tab_basic, "字幕排列", "subtitle_arrangement", SUBTITLE_ARRANGEMENT_OPTIONS_V21, 0)
    combo(tab_basic, "字幕位置", "subtitle_position", SUBTITLE_POSITION_OPTIONS_V21, 0)
    combo(tab_basic, "英文底色", "en_base", COLOR_OPTIONS, 0)
    combo(tab_basic, "英文覆盖", "en_cover", COLOR_OPTIONS, 3)
    combo(tab_basic, "中文底色", "zh_base", COLOR_OPTIONS, 0)
    combo(tab_basic, "中文覆盖", "zh_cover", COLOR_OPTIONS, 12)
    combo(tab_basic, "翻译引擎", "translate_engine", TRANSLATE_ENGINE_OPTIONS, 0)

    self.en_font_size_var = tk.IntVar(value=55)
    self.zh_font_size_var = tk.IntVar(value=40)
    # 保留旧变量，兼容旧代码读取 font_size。
    self.font_size_var = tk.IntVar(value=55)

    spin(tab_basic, "英文字号", self.en_font_size_var, 24, 96)
    spin(tab_basic, "中文字幕号", self.zh_font_size_var, 18, 80)

    self.keep_clips_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(tab_basic, text="保留工作 clips/std 文件", variable=self.keep_clips_var).pack(anchor="w", pady=4)

    ttk.Label(
        tab_basic,
        text="字幕位置说明：合并上方=英文+中文都靠近顶部；合并下方=英文+中文都靠近底部；分开布局=一个顶部一个底部。",
        style="Dim.TLabel",
        wraplength=360
    ).pack(fill="x", pady=(6, 0))

    # 美化视频
    combo(tab_beauty, "黑边美化", "beauty_mode", BEAUTY_MODE_OPTIONS_V21, 0)
    self.title_enable_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(tab_beauty, text="启用顶部标题栏", variable=self.title_enable_var).pack(anchor="w", pady=(2, 0))
    combo(tab_beauty, "标题预设", "title_preset", TITLE_PRESET_OPTIONS_V21, 0)

    f = ttk.Frame(tab_beauty); f.pack(fill="x", pady=2)
    ttk.Label(f, text="自定义标题", width=12).pack(side="left")
    self.title_text_var = tk.StringVar(value="")
    ttk.Entry(f, textvariable=self.title_text_var).pack(side="left", fill="x", expand=True)

    self.title_font_size_var = tk.IntVar(value=28)
    spin(tab_beauty, "标题字号", self.title_font_size_var, 18, 72)
    combo(tab_beauty, "标题颜色", "title_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)

    # 图片/水印
    self.watermark_enable_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(tab_overlay, text="启用文字水印", variable=self.watermark_enable_var).pack(anchor="w", pady=(2, 0))

    f = ttk.Frame(tab_overlay); f.pack(fill="x", pady=2)
    ttk.Label(f, text="水印文字", width=12).pack(side="left")
    self.watermark_text_var = tk.StringVar(value="")
    ttk.Entry(f, textvariable=self.watermark_text_var).pack(side="left", fill="x", expand=True)

    self.watermark_font_size_var = tk.IntVar(value=24)
    spin(tab_overlay, "水印字号", self.watermark_font_size_var, 14, 60)
    combo(tab_overlay, "水印颜色", "watermark_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)

    ttk.Separator(tab_overlay).pack(fill="x", pady=8)

    f = ttk.Frame(tab_overlay); f.pack(fill="x", pady=2)
    ttk.Label(f, text="本地图片", width=12).pack(side="left")
    self.overlay_image_var = tk.StringVar(value="")
    ttk.Entry(f, textvariable=self.overlay_image_var).pack(side="left", fill="x", expand=True)
    ttk.Button(f, text="浏览", width=8, command=self._browse_overlay_image_v21).pack(side="left", padx=(6, 0))

    combo(tab_overlay, "图片位置", "overlay_position", OVERLAY_POSITION_OPTIONS_V21, 0)
    self.overlay_scale_var = tk.IntVar(value=28)
    spin(tab_overlay, "缩放比例%", self.overlay_scale_var, 5, 100)


