def _style_defs_v23(w: int, h: int, font_size: int, zh_font_size: int,
                    en_base: str, en_cover: str, zh_base: str, zh_cover: str,
                    subtitle_position: str, arrangement: str, keyword_color: str) -> str:
    """Create ASS style definitions with independent alignments for EN/ZH."""
    vertical = h >= w
    outline = 3 if font_size >= 52 else 2
    shadow = 1

    # Reserve enough vertical space for multiline subtitles to avoid overlap.
    en_line_h = max(30, int(font_size * 1.22))
    zh_line_h = max(26, int(zh_font_size * 1.24))
    en_lines_reserved = 2
    zh_lines_reserved = 2
    gap = 18 if vertical else 12

    top_margin = 70 if vertical else 44
    bottom_margin = 96 if vertical else 50

    if subtitle_position == "merged_top":
        first_align, second_align = 8, 8
        first_margin = top_margin
        # If the first block is English, reserve English height; if Chinese, reserve Chinese height.
        first_h = (en_line_h * en_lines_reserved) if arrangement == "en_top_zh_bottom" else (zh_line_h * zh_lines_reserved)
        second_margin = first_margin + first_h + gap
        if arrangement == "en_top_zh_bottom":
            en_align, zh_align = first_align, second_align
            en_margin, zh_margin = first_margin, second_margin
        else:
            zh_align, en_align = first_align, second_align
            zh_margin, en_margin = first_margin, second_margin

    elif subtitle_position == "merged_bottom":
        first_align, second_align = 2, 2
        second_margin = bottom_margin
        # second block is lower; first block sits above it.
        second_h = (zh_line_h * zh_lines_reserved) if arrangement == "en_top_zh_bottom" else (en_line_h * en_lines_reserved)
        first_margin = second_margin + second_h + gap
        if arrangement == "en_top_zh_bottom":
            en_align, zh_align = first_align, second_align
            en_margin, zh_margin = first_margin, second_margin
        else:
            zh_align, en_align = first_align, second_align
            zh_margin, en_margin = first_margin, second_margin

    else:
        # 分开布局：一个字幕顶部，一个字幕底部。
        if arrangement == "en_top_zh_bottom":
            en_align, en_margin = 8, top_margin
            zh_align, zh_margin = 2, bottom_margin
        else:
            zh_align, zh_margin = 8, top_margin
            en_align, en_margin = 2, bottom_margin

    en_primary = ASS_COLOR.get(en_cover if en_cover != "white" else en_base, ASS_COLOR["white"])
    en_secondary = ASS_COLOR.get(en_base, ASS_COLOR["white"])
    zh_primary = ASS_COLOR.get(zh_cover if zh_cover != "white" else zh_base, ASS_COLOR["white"])
    zh_secondary = ASS_COLOR.get(zh_base, ASS_COLOR["white"])
    static_en = ASS_COLOR.get(en_base, ASS_COLOR["white"])
    static_zh = ASS_COLOR.get(zh_base, ASS_COLOR["white"])

    return (
        "[V4+ Styles]\n"
        "Format: Name,Fontname,Fontsize,PrimaryColour,SecondaryColour,OutlineColour,BackColour,"
        "Bold,Italic,Underline,StrikeOut,ScaleX,ScaleY,Spacing,Angle,BorderStyle,Outline,Shadow,"
        "Alignment,MarginL,MarginR,MarginV,Encoding\n"
        f"Style: EnStatic,Microsoft YaHei,{font_size},{static_en},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},{en_align},70,70,{en_margin},1\n"
        f"Style: ZhStatic,Microsoft YaHei,{zh_font_size},{static_zh},{ASS_COLOR['white']},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},{zh_align},70,70,{zh_margin},1\n"
        f"Style: EnKaraoke,Microsoft YaHei,{font_size},{en_primary},{en_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},{en_align},70,70,{en_margin},1\n"
        f"Style: ZhKaraoke,Microsoft YaHei,{zh_font_size},{zh_primary},{zh_secondary},&H00000000,&H80000000,0,0,0,0,100,100,0,0,1,{outline},{shadow},{zh_align},70,70,{zh_margin},1\n"
    )


def _make_ass_timeline_v23(self, entries: List[Tuple[Clip, float]], out_path: Path,
                           options: Dict[str, Any], final_dur: float) -> Path:
    shift = _clamp_float(options.get("subtitle_shift_ms", 0), -10000, 10000, 0.0) / 1000.0
    w, h = parse_resolution(options.get("resolution", "1080x1920"))
    subtitle_mode = options.get("subtitle_mode", "bilingual")
    style = options.get("subtitle_style", "static")

    en_font_size = int(options.get("en_font_size", options.get("font_size", 55)) or 55)
    zh_font_size = int(options.get("zh_font_size", max(22, int(en_font_size * 0.72))) or 40)

    en_base = options.get("en_base", "white")
    en_cover = options.get("en_cover", "white")
    zh_base = options.get("zh_base", "white")
    zh_cover = options.get("zh_cover", "yellow")
    keyword_color = options.get("keyword_color", "red")

    subtitle_position = options.get("subtitle_position", "separate")
    arrangement = options.get("subtitle_arrangement", "en_top_zh_bottom")

    vertical = h >= w
    max_en = 28 if vertical else 44
    max_zh = 16 if vertical else 26
    en_lines = 2
    zh_lines = 2

    header = (
        "[Script Info]\n"
        "ScriptType: v4.00+\n"
        f"PlayResX: {w}\n"
        f"PlayResY: {h}\n"
        "ScaledBorderAndShadow: yes\n"
        "WrapStyle: 0\n\n"
        + _style_defs_v23(
            w, h, en_font_size, zh_font_size,
            en_base, en_cover, zh_base, zh_cover,
            subtitle_position, arrangement, keyword_color
        )
        + "\n[Events]\n"
        "Format: Layer,Start,End,Style,Name,MarginL,MarginR,MarginV,Effect,Text\n"
    )

    lines = [header]
    cur = 0.0

    for c, dur in entries:
        if not c.text:
            cur += dur
            continue

        start = max(0.0, cur + shift)
        end = min(final_dur, max(start + 0.05, cur + dur + shift))
        if end <= 0 or start >= final_dur:
            cur += dur
            continue

        en = c.text or ""
        zh = c.zh or ""
        span = max(end - start, 0.1)

        if subtitle_mode == "none":
            cur += dur
            continue

        if style == "keyword_highlight":
            en_body = _keyword_highlight_wrapped_v18(en, c.keyword, keyword_color, max_en, en_lines)
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_body}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")

        elif style in ("en_karaoke_yellow", "en_karaoke_orange"):
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v18(en, span, max_en, en_lines)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")

        elif style == "bilingual_karaoke":
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{_karaoke_wrapped_v18(en, span, max_en, en_lines)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v18(zh, span, max_zh, zh_lines)}\n")

        elif style == "keyword_bilingual_karaoke":
            en_body = _keyword_karaoke_wrapped_v18(en, c.keyword, span, max_en, keyword_color, en_lines)
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{en_body}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{_karaoke_wrapped_v18(zh, span, max_zh, zh_lines)}\n")

        else:
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{_ass_wrap_text_v18(en, max_en, en_lines, True)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")

        cur += dur

    out_path.write_text("".join(lines), "utf-8-sig")
    return out_path


