# ──────────────────────────────────────────────────────────────────────
# V24 visual beauty workbench + collapsible preview + draggable subtitle/watermark/image
# ──────────────────────────────────────────────────────────────────────

def _ensure_visual_vars_v24(self):
    """Initialize hidden render variables used by the beauty workbench."""
    if getattr(self, "_visual_vars_ready_v24", False):
        return
    self._visual_vars_ready_v24 = True
    self.title_enable_var = tk.BooleanVar(value=False)
    self.title_text_var = tk.StringVar(value="")
    self.title_font_size_var = tk.IntVar(value=28)
    self.watermark_enable_var = tk.BooleanVar(value=False)
    self.watermark_text_var = tk.StringVar(value="")
    self.watermark_font_size_var = tk.IntVar(value=24)
    self.overlay_image_var = tk.StringVar(value="")
    self.overlay_scale_var = tk.IntVar(value=28)
    # Visual drag positions are percentages of final video canvas.
    self.v24_use_visual_positions = tk.BooleanVar(value=True)
    self.v24_en_x_pct = tk.DoubleVar(value=50.0)
    self.v24_en_y_pct = tk.DoubleVar(value=11.0)
    self.v24_zh_x_pct = tk.DoubleVar(value=50.0)
    self.v24_zh_y_pct = tk.DoubleVar(value=17.0)
    self.v24_title_x_pct = tk.DoubleVar(value=50.0)
    self.v24_title_y_pct = tk.DoubleVar(value=4.0)
    self.v24_wm_x_pct = tk.DoubleVar(value=82.0)
    self.v24_wm_y_pct = tk.DoubleVar(value=93.0)
    self.v24_img_x_pct = tk.DoubleVar(value=82.0)
    self.v24_img_y_pct = tk.DoubleVar(value=82.0)


def _build_render_options_v24(self, parent):
    """V24：右侧渲染区只保留基础设置 + 操作台按钮；复杂美化进入独立窗口。"""
    ttk.Label(parent, text="渲染选项", style="H.TLabel").pack(anchor="w")
    self.render_vars = {}
    _ensure_visual_vars_v24(self)

    topbar = ttk.Frame(parent)
    topbar.pack(fill="x", pady=(4, 4))
    ttk.Button(topbar, text="折叠/展开上方预览", command=self._toggle_preview_area_v24).pack(side="left", padx=(0, 4))
    ttk.Button(topbar, text="美化视频操作台", style="Accent.TButton", command=self._open_beauty_workbench_v24).pack(side="left", padx=4)

    wrap = ttk.LabelFrame(parent, text="基础渲染", padding=(6, 6))
    wrap.pack(fill="both", expand=True, pady=(2, 0))
    canvas = tk.Canvas(wrap, bg=C_BG, highlightthickness=0, height=360)
    sb = ttk.Scrollbar(wrap, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=sb.set)
    canvas.pack(side="left", fill="both", expand=True)
    sb.pack(side="right", fill="y")
    inner = ttk.Frame(canvas)
    win = canvas.create_window((0,0), window=inner, anchor="nw")
    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfigure(win, width=e.width))
    try:
        _mousewheel_bind_v21(canvas, inner)
    except Exception:
        pass

    def combo(container, label, key, options, default_idx=0, width=26):
        f = ttk.Frame(container); f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        var = tk.StringVar(value=options[default_idx][0])
        cb = ttk.Combobox(f, state="readonly", textvariable=var, values=[x[0] for x in options], width=width)
        cb.pack(side="left", fill="x", expand=True)
        self.render_vars[key] = var
        return var

    def spin(container, label, var, frm, to, width=8):
        f = ttk.Frame(container); f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        ttk.Spinbox(f, from_=frm, to=to, textvariable=var, width=width).pack(side="left")
        return var

    combo(inner, "分辨率", "resolution", RESOLUTION_OPTIONS, 0)
    combo(inner, "渲染方式", "fit_mode", RENDER_FIT_MODE_OPTIONS_V22, 0)
    combo(inner, "字幕类型", "subtitle_mode", SUBTITLE_MODE_OPTIONS, 2)
    combo(inner, "字幕样式", "subtitle_style", SUBTITLE_STYLE_OPTIONS, 0)
    combo(inner, "字幕排列", "subtitle_arrangement", SUBTITLE_ARRANGEMENT_OPTIONS_V21, 0)
    combo(inner, "字幕位置", "subtitle_position", SUBTITLE_POSITION_OPTIONS_V21, 0)
    combo(inner, "英文底色", "en_base", COLOR_OPTIONS, 0)
    combo(inner, "英文覆盖", "en_cover", COLOR_OPTIONS, 3)
    combo(inner, "中文底色", "zh_base", COLOR_OPTIONS, 0)
    combo(inner, "中文覆盖", "zh_cover", COLOR_OPTIONS, 12)
    combo(inner, "翻译引擎", "translate_engine", TRANSLATE_ENGINE_OPTIONS, 0)

    self.en_font_size_var = tk.IntVar(value=55)
    self.zh_font_size_var = tk.IntVar(value=40)
    self.font_size_var = tk.IntVar(value=55)  # backward compatibility
    spin(inner, "英文字号", self.en_font_size_var, 24, 96)
    spin(inner, "中文字幕号", self.zh_font_size_var, 18, 80)
    self.keep_clips_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(inner, text="保留工作 clips/std 文件", variable=self.keep_clips_var).pack(anchor="w", pady=4)
    ttk.Label(inner, text="提示：美化视频、水印、图片遮罩、拖拽字幕位置，请进入【美化视频操作台】。", style="Dim.TLabel", wraplength=360).pack(fill="x", pady=(6, 4))


def _toggle_preview_area_v24(self):
    """Hide/show the large preview image to release vertical space for render options."""
    if not hasattr(self, "preview_box"):
        return
    hidden = bool(getattr(self, "_preview_hidden_v24", False))
    if not hidden:
        try:
            self._preview_pack_v24 = self.preview_box.pack_info()
            self.preview_box.pack_forget()
            self._preview_hidden_v24 = True
            self.log("已折叠上方大预览帧区域。", "info")
        except Exception:
            pass
    else:
        try:
            info = getattr(self, "_preview_pack_v24", {}) or {"fill":"x", "pady":6}
            self.preview_box.pack(**info)
            self._preview_hidden_v24 = False
            self.log("已展开上方大预览帧区域。", "info")
        except Exception:
            pass


def _browse_overlay_image_v24(self):
    f = filedialog.askopenfilename(title="选择本地图片", filetypes=[("Image", "*.png *.jpg *.jpeg *.webp *.bmp"), ("All", "*.*")])
    if f:
        self.overlay_image_var.set(f)
        try:
            self._beauty_preview_draw_v24()
        except Exception:
            pass


def _get_preview_text_v24(self):
    en = "English subtitle preview"
    zh = "中文字幕预览"
    try:
        if self.pool_tree.selection():
            idx = int(self.pool_tree.selection()[0]); c = self.pool[idx]
            en = c.text or en; zh = c.zh or zh
        elif self.result_tree.selection():
            idx = int(self.result_tree.selection()[0]); c = self.results[idx]
            en = c.text or en; zh = c.zh or zh
    except Exception:
        pass
    return en, zh


def _open_beauty_workbench_v24(self):
    _ensure_visual_vars_v24(self)
    if getattr(self, "_beauty_win_v24", None) and self._beauty_win_v24.winfo_exists():
        self._beauty_win_v24.lift(); return
    win = tk.Toplevel(self)
    win.title("美化视频操作台 · 实时预览 / 拖拽定位")
    win.geometry("1180x780")
    win.configure(bg=C_BG)
    self._beauty_win_v24 = win

    root = ttk.Frame(win, padding=10)
    root.pack(fill="both", expand=True)
    left = ttk.Frame(root, width=330)
    left.pack(side="left", fill="y", padx=(0, 10))
    right = ttk.Frame(root)
    right.pack(side="left", fill="both", expand=True)

    ttk.Label(left, text="当前基础渲染效果", style="H.TLabel").pack(anchor="w", pady=(0, 6))
    self._beauty_summary_v24 = tk.StringVar(value="")
    ttk.Label(left, textvariable=self._beauty_summary_v24, style="Dim.TLabel", wraplength=310).pack(fill="x", pady=(0, 8))

    def combo(container, label, key, options, default_idx=0):
        f = ttk.Frame(container); f.pack(fill="x", pady=3)
        ttk.Label(f, text=label, width=10).pack(side="left")
        var = self.render_vars.get(key)
        if var is None:
            var = tk.StringVar(value=options[default_idx][0]); self.render_vars[key] = var
        cb = ttk.Combobox(f, state="readonly", textvariable=var, values=[x[0] for x in options], width=22)
        cb.pack(side="left", fill="x", expand=True)
        cb.bind("<<ComboboxSelected>>", lambda e: self._beauty_preview_draw_v24())

    g1 = ttk.LabelFrame(left, text="画面美化", padding=8); g1.pack(fill="x", pady=6)
    combo(g1, "黑边美化", "beauty_mode", BEAUTY_MODE_OPTIONS_V21, 0)
    ttk.Checkbutton(g1, text="启用视觉拖拽位置", variable=self.v24_use_visual_positions, command=self._beauty_preview_draw_v24).pack(anchor="w", pady=3)

    g2 = ttk.LabelFrame(left, text="顶部标题栏", padding=8); g2.pack(fill="x", pady=6)
    ttk.Checkbutton(g2, text="启用顶部标题栏", variable=self.title_enable_var, command=self._beauty_preview_draw_v24).pack(anchor="w")
    combo(g2, "标题预设", "title_preset", TITLE_PRESET_OPTIONS_V21, 0)
    f = ttk.Frame(g2); f.pack(fill="x", pady=3)
    ttk.Label(f, text="标题", width=10).pack(side="left")
    ttk.Entry(f, textvariable=self.title_text_var).pack(side="left", fill="x", expand=True)
    ttk.Spinbox(g2, from_=18, to=72, textvariable=self.title_font_size_var, width=8, command=self._beauty_preview_draw_v24).pack(anchor="w", pady=3)
    combo(g2, "标题颜色", "title_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)

    g3 = ttk.LabelFrame(left, text="水印 / 图片遮罩", padding=8); g3.pack(fill="x", pady=6)
    ttk.Checkbutton(g3, text="启用文字水印", variable=self.watermark_enable_var, command=self._beauty_preview_draw_v24).pack(anchor="w")
    f = ttk.Frame(g3); f.pack(fill="x", pady=3)
    ttk.Label(f, text="水印", width=10).pack(side="left")
    ttk.Entry(f, textvariable=self.watermark_text_var).pack(side="left", fill="x", expand=True)
    ttk.Spinbox(g3, from_=14, to=60, textvariable=self.watermark_font_size_var, width=8, command=self._beauty_preview_draw_v24).pack(anchor="w", pady=3)
    combo(g3, "水印颜色", "watermark_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)
    ttk.Separator(g3).pack(fill="x", pady=6)
    f = ttk.Frame(g3); f.pack(fill="x", pady=3)
    ttk.Label(f, text="图片", width=10).pack(side="left")
    ttk.Entry(f, textvariable=self.overlay_image_var).pack(side="left", fill="x", expand=True)
    ttk.Button(f, text="浏览", width=7, command=self._browse_overlay_image_v24).pack(side="left", padx=(5,0))
    combo(g3, "图片位置", "overlay_position", OVERLAY_POSITION_OPTIONS_V21, 0)
    ttk.Label(g3, text="图片缩放%", style="Dim.TLabel").pack(anchor="w")
    ttk.Spinbox(g3, from_=5, to=100, textvariable=self.overlay_scale_var, width=8, command=self._beauty_preview_draw_v24).pack(anchor="w", pady=3)

    ttk.Button(left, text="应用并关闭", style="Accent.TButton", command=win.destroy).pack(fill="x", pady=(10, 4))
    ttk.Label(left, text="拖拽说明：在右侧预览画布上拖动 EN / CN / TITLE / WM / IMG，即可改变实际渲染位置。", style="Dim.TLabel", wraplength=310).pack(fill="x")

    self._beauty_canvas_v24 = tk.Canvas(right, width=405, height=720, bg="#111111", highlightthickness=1, highlightbackground=C_BORDER)
    self._beauty_canvas_v24.pack(anchor="center", expand=True)
    self._beauty_drag_item_v24 = None
    self._beauty_canvas_v24.bind("<ButtonPress-1>", self._beauty_canvas_press_v24)
    self._beauty_canvas_v24.bind("<B1-Motion>", self._beauty_canvas_drag_v24)
    self._beauty_canvas_v24.bind("<ButtonRelease-1>", lambda e: setattr(self, "_beauty_drag_item_v24", None))
    self._beauty_preview_draw_v24()


def _v24_hex(self, color_name: str) -> str:
    raw = str(color_name or "white")
    # Accept both internal values (yellow) and UI labels (黄色).
    for opts in (COLOR_OPTIONS, TEXT_STYLE_COLOR_OPTIONS_V23):
        for label, val in opts:
            if raw == label:
                raw = val
                break
    return FF_COLOR_HEX_V21.get(raw, "#FFFFFF")


def _beauty_preview_draw_v24(self):
    if not getattr(self, "_beauty_canvas_v24", None):
        return
    cvs = self._beauty_canvas_v24
    cvs.delete("all")
    cw, ch = 405, 720
    cvs.create_rectangle(0,0,cw,ch, fill="#111111", outline="")
    mode = _combo_to_value_v21(self.render_vars.get("beauty_mode", tk.StringVar(value=BEAUTY_MODE_OPTIONS_V21[0][0])).get(), BEAUTY_MODE_OPTIONS_V21) if self.render_vars.get("beauty_mode") else "none"
    if mode == "blur_bg":
        cvs.create_rectangle(0,0,cw,ch, fill="#2a2a2a", outline="")
        cvs.create_text(cw//2, ch//2, text="模糊背景填充预览", fill="#777777", font=("Microsoft YaHei UI", 18, "bold"))
    elif mode == "gradient_bg":
        for y in range(0, ch, 8):
            shade = int(18 + 50*y/ch)
            cvs.create_rectangle(0,y,cw,y+8, fill=f"#{shade:02x}{max(8,shade//2):02x}{min(90,shade+30):02x}", outline="")
    else:
        cvs.create_rectangle(28, 70, cw-28, ch-70, fill="#222222", outline="#444444")
    # Simulated video crop region.
    cvs.create_rectangle(38, 84, cw-38, ch-84, outline="#5c5c5c")
    en, zh = _get_preview_text_v24(self)
    en = en[:48] + ("..." if len(en) > 48 else "")
    zh = zh[:24] + ("..." if len(zh) > 24 else "")
    try:
        self._beauty_summary_v24.set(
            f"分辨率：{self.render_vars['resolution'].get()}\n"
            f"渲染方式：{self.render_vars['fit_mode'].get()}\n"
            f"字幕：{self.render_vars['subtitle_position'].get()} / {self.render_vars['subtitle_arrangement'].get()}\n"
            f"英字号：{self.en_font_size_var.get()}  中字号：{self.zh_font_size_var.get()}"
        )
    except Exception:
        pass
    items = []
    if self.title_enable_var.get():
        title = (self.title_text_var.get() or _combo_to_value_v21(self.render_vars.get("title_preset", tk.StringVar(value="")).get(), TITLE_PRESET_OPTIONS_V21) or "TITLE")
        x, y = cw*self.v24_title_x_pct.get()/100, ch*self.v24_title_y_pct.get()/100
        cvs.create_rectangle(0, max(0,y-26), cw, min(ch,y+30), fill="#000000", stipple="gray50", outline="")
        items.append(("title", cvs.create_text(x, y, text=title, fill=self._v24_hex(self.render_vars.get("title_color", tk.StringVar(value="白色")).get()), font=("Microsoft YaHei UI", 16, "bold"))))
    x, y = cw*self.v24_en_x_pct.get()/100, ch*self.v24_en_y_pct.get()/100
    items.append(("en", cvs.create_text(x, y, text="EN  " + en, fill=self._v24_hex(_combo_to_value_v21(self.render_vars.get("en_cover", tk.StringVar(value="黄色")).get(), COLOR_OPTIONS)), font=("Microsoft YaHei UI", 17, "bold"))))
    x, y = cw*self.v24_zh_x_pct.get()/100, ch*self.v24_zh_y_pct.get()/100
    items.append(("zh", cvs.create_text(x, y, text="CN  " + zh, fill=self._v24_hex(_combo_to_value_v21(self.render_vars.get("zh_cover", tk.StringVar(value="绿色")).get(), COLOR_OPTIONS)), font=("Microsoft YaHei UI", 14, "bold"))))
    if self.watermark_enable_var.get():
        wm = self.watermark_text_var.get() or "WM"
        x, y = cw*self.v24_wm_x_pct.get()/100, ch*self.v24_wm_y_pct.get()/100
        items.append(("wm", cvs.create_text(x, y, text="WM  " + wm, fill=self._v24_hex(self.render_vars.get("watermark_color", tk.StringVar(value="白色")).get()), font=("Microsoft YaHei UI", 12, "bold"))))
    if self.overlay_image_var.get():
        x, y = cw*self.v24_img_x_pct.get()/100, ch*self.v24_img_y_pct.get()/100
        rect = cvs.create_rectangle(x-45, y-28, x+45, y+28, fill="#2f4f4f", outline="#9ee7ff", width=2)
        txt = cvs.create_text(x, y, text="IMG", fill="#ffffff", font=("Microsoft YaHei UI", 14, "bold"))
        items.append(("img", rect)); items.append(("img", txt))
    self._beauty_items_v24 = {iid: name for name, iid in items}
    for name, iid in items:
        cvs.addtag_withtag("drag", iid)


def _beauty_canvas_press_v24(self, event):
    cvs = self._beauty_canvas_v24
    hit = cvs.find_closest(event.x, event.y)
    self._beauty_drag_item_v24 = hit[0] if hit else None


def _beauty_canvas_drag_v24(self, event):
    iid = getattr(self, "_beauty_drag_item_v24", None)
    if not iid:
        return
    name = getattr(self, "_beauty_items_v24", {}).get(iid)
    if not name:
        return
    cw, ch = 405, 720
    x_pct = max(0.0, min(100.0, event.x * 100.0 / cw))
    y_pct = max(0.0, min(100.0, event.y * 100.0 / ch))
    if name == "en":
        self.v24_en_x_pct.set(x_pct); self.v24_en_y_pct.set(y_pct)
    elif name == "zh":
        self.v24_zh_x_pct.set(x_pct); self.v24_zh_y_pct.set(y_pct)
    elif name == "title":
        self.v24_title_x_pct.set(x_pct); self.v24_title_y_pct.set(y_pct)
    elif name == "wm":
        self.v24_wm_x_pct.set(x_pct); self.v24_wm_y_pct.set(y_pct)
    elif name == "img":
        self.v24_img_x_pct.set(x_pct); self.v24_img_y_pct.set(y_pct)
    self._beauty_preview_draw_v24()


def _render_options_v24(self) -> Dict[str, Any]:
    def opt(key, opts):
        label = self.render_vars[key].get()
        return _combo_to_value_v21(label, opts)
    _ensure_visual_vars_v24(self)
    preset_text = opt("title_preset", TITLE_PRESET_OPTIONS_V21) if "title_preset" in self.render_vars else ""
    custom_title = (self.title_text_var.get() or "").strip()
    en_fs = int(self.en_font_size_var.get())
    zh_fs = int(self.zh_font_size_var.get())
    return {
        "resolution": opt("resolution", RESOLUTION_OPTIONS),
        "fit_mode": opt("fit_mode", RENDER_FIT_MODE_OPTIONS_V22),
        "subtitle_mode": opt("subtitle_mode", SUBTITLE_MODE_OPTIONS),
        "subtitle_style": opt("subtitle_style", SUBTITLE_STYLE_OPTIONS),
        "subtitle_arrangement": opt("subtitle_arrangement", SUBTITLE_ARRANGEMENT_OPTIONS_V21),
        "subtitle_position": opt("subtitle_position", SUBTITLE_POSITION_OPTIONS_V21),
        "en_base": opt("en_base", COLOR_OPTIONS),
        "en_cover": opt("en_cover", COLOR_OPTIONS),
        "zh_base": opt("zh_base", COLOR_OPTIONS),
        "zh_cover": opt("zh_cover", COLOR_OPTIONS),
        "translate_engine": opt("translate_engine", TRANSLATE_ENGINE_OPTIONS),
        "font_size": en_fs,
        "en_font_size": en_fs,
        "zh_font_size": zh_fs,
        "keep_clips": bool(self.keep_clips_var.get()),
        "keyword_color": "red",
        "beauty_mode": opt("beauty_mode", BEAUTY_MODE_OPTIONS_V21) if "beauty_mode" in self.render_vars else "none",
        "title_enabled": bool(self.title_enable_var.get()),
        "title_text": custom_title or preset_text,
        "title_font_size": int(self.title_font_size_var.get()),
        "title_color": opt("title_color", TEXT_STYLE_COLOR_OPTIONS_V23) if "title_color" in self.render_vars else "white",
        "watermark_enabled": bool(self.watermark_enable_var.get()),
        "watermark_text": (self.watermark_text_var.get() or "").strip(),
        "watermark_font_size": int(self.watermark_font_size_var.get()),
        "watermark_color": opt("watermark_color", TEXT_STYLE_COLOR_OPTIONS_V23) if "watermark_color" in self.render_vars else "white",
        "overlay_image_path": (self.overlay_image_var.get() or "").strip(),
        "overlay_position": opt("overlay_position", OVERLAY_POSITION_OPTIONS_V21) if "overlay_position" in self.render_vars else "bottom_right",
        "overlay_scale_percent": int(self.overlay_scale_var.get()),
        "use_visual_positions": bool(self.v24_use_visual_positions.get()),
        "subtitle_en_x_pct": float(self.v24_en_x_pct.get()),
        "subtitle_en_y_pct": float(self.v24_en_y_pct.get()),
        "subtitle_zh_x_pct": float(self.v24_zh_x_pct.get()),
        "subtitle_zh_y_pct": float(self.v24_zh_y_pct.get()),
        "title_x_pct": float(self.v24_title_x_pct.get()),
        "title_y_pct": float(self.v24_title_y_pct.get()),
        "watermark_x_pct": float(self.v24_wm_x_pct.get()),
        "watermark_y_pct": float(self.v24_wm_y_pct.get()),
        "overlay_x_pct": float(self.v24_img_x_pct.get()),
        "overlay_y_pct": float(self.v24_img_y_pct.get()),
    }


def _ass_pos_tag_v24(options: Dict[str, Any], which: str, w: int, h: int) -> str:
    if not options.get("use_visual_positions", False):
        return ""
    if which == "en":
        x = w * float(options.get("subtitle_en_x_pct", 50.0)) / 100.0
        y = h * float(options.get("subtitle_en_y_pct", 11.0)) / 100.0
    else:
        x = w * float(options.get("subtitle_zh_x_pct", 50.0)) / 100.0
        y = h * float(options.get("subtitle_zh_y_pct", 17.0)) / 100.0
    return "{\\an5\\pos(%d,%d)}" % (int(x), int(y))


def _make_ass_timeline_v24(self, entries: List[Tuple[Clip, float]], out_path: Path,
                           options: Dict[str, Any], final_dur: float) -> Path:
    # Build on V23, but when visual positions are enabled, inject ASS \pos override tags.
    shift = _clamp_float(options.get("subtitle_shift_ms", 0), -10000, 10000, 0.0) / 1000.0
    w, h = parse_resolution(options.get("resolution", "1080x1920"))
    subtitle_mode = options.get("subtitle_mode", "bilingual")
    style = options.get("subtitle_style", "static")
    en_font_size = int(options.get("en_font_size", options.get("font_size", 55)) or 55)
    zh_font_size = int(options.get("zh_font_size", max(22, int(en_font_size * 0.72))) or 40)
    en_base, en_cover = options.get("en_base", "white"), options.get("en_cover", "white")
    zh_base, zh_cover = options.get("zh_base", "white"), options.get("zh_cover", "yellow")
    keyword_color = options.get("keyword_color", "red")
    subtitle_position = options.get("subtitle_position", "separate")
    arrangement = options.get("subtitle_arrangement", "en_top_zh_bottom")
    vertical = h >= w
    max_en = 28 if vertical else 44
    max_zh = 16 if vertical else 26
    en_lines = 2
    zh_lines = 2
    header = (
        "[Script Info]\nScriptType: v4.00+\n" + f"PlayResX: {w}\nPlayResY: {h}\n" +
        "ScaledBorderAndShadow: yes\nWrapStyle: 0\n\n" +
        _style_defs_v23(w, h, en_font_size, zh_font_size, en_base, en_cover, zh_base, zh_cover, subtitle_position, arrangement, keyword_color) +
        "\n[Events]\nFormat: Layer,Start,End,Style,Name,MarginL,MarginR,MarginV,Effect,Text\n"
    )
    lines = [header]
    cur = 0.0
    en_pos = _ass_pos_tag_v24(options, "en", w, h)
    zh_pos = _ass_pos_tag_v24(options, "zh", w, h)
    for c, dur in entries:
        if not c.text:
            cur += dur; continue
        start = max(0.0, cur + shift)
        end = min(final_dur, max(start + 0.05, cur + dur + shift))
        if end <= 0 or start >= final_dur:
            cur += dur; continue
        en, zh = c.text or "", c.zh or ""
        span = max(end - start, 0.1)
        if subtitle_mode == "none":
            cur += dur; continue
        if style == "keyword_highlight":
            en_body = en_pos + _keyword_highlight_wrapped_v18(en, c.keyword, keyword_color, max_en, en_lines)
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_body}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{zh_pos}{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")
        elif style in ("en_karaoke_yellow", "en_karaoke_orange"):
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{en_pos}{_karaoke_wrapped_v18(en, span, max_en, en_lines)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{zh_pos}{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")
        elif style == "bilingual_karaoke":
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{en_pos}{_karaoke_wrapped_v18(en, span, max_en, en_lines)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{zh_pos}{_karaoke_wrapped_v18(zh, span, max_zh, zh_lines)}\n")
        elif style == "keyword_bilingual_karaoke":
            en_body = en_pos + _keyword_karaoke_wrapped_v18(en, c.keyword, span, max_en, keyword_color, en_lines)
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnKaraoke,,0,0,0,,{en_body}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhKaraoke,,0,0,0,,{zh_pos}{_karaoke_wrapped_v18(zh, span, max_zh, zh_lines)}\n")
        else:
            lines.append(f"Dialogue: 0,{ass_time(start)},{ass_time(end)},EnStatic,,0,0,0,,{en_pos}{_ass_wrap_text_v18(en, max_en, en_lines, True)}\n")
            if subtitle_mode == "bilingual" and zh:
                lines.append(f"Dialogue: 1,{ass_time(start)},{ass_time(end)},ZhStatic,,0,0,0,,{zh_pos}{_ass_wrap_text_v18(zh, max_zh, zh_lines, False)}\n")
        cur += dur
    out_path.write_text("".join(lines), "utf-8-sig")
    return out_path


def _postprocess_video_v24(self, src: Path, dst: Path, options: Dict[str, Any], resolution: str, work: Path) -> Path:
    title_enabled = bool(options.get("title_enabled", False))
    title_text = str(options.get("title_text", "") or "").strip()
    watermark_enabled = bool(options.get("watermark_enabled", False))
    watermark_text = str(options.get("watermark_text", "") or "").strip()
    overlay_path = Path(options.get("overlay_image_path", "") or "") if str(options.get("overlay_image_path", "") or "").strip() else None
    if (not title_enabled or not title_text) and (not watermark_enabled or not watermark_text) and not (overlay_path and overlay_path.exists()):
        shutil.copy2(src, dst); return dst
    ff = self.ffmpeg.ffmpeg
    w, h = parse_resolution(resolution)
    cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(src)]
    filters = []
    cur = "[0:v]"
    vid_idx = 0
    def next_label():
        nonlocal vid_idx
        vid_idx += 1
        return f"[v{vid_idx}]"
    def color_hex(name):
        return FF_COLOR_HEX_V21.get(str(name or "white"), "#FFFFFF")
    if title_enabled and title_text:
        title_file = work / "_title_text_v24.txt"; title_file.write_text(title_text, "utf-8")
        title_path = _ffmpeg_escape_path_v21(title_file)
        fs = int(options.get("title_font_size", 28))
        x = max(0, min(w-10, int(w * float(options.get("title_x_pct", 50.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("title_y_pct", 4.0)) / 100.0)))
        bar_h = max(56, int(fs * 2.2))
        out = next_label()
        filters.append(
            f"{cur}drawbox=x=0:y=0:w=iw:h={bar_h}:color=black@0.40:t=fill,"
            f"drawtext=textfile='{title_path}':reload=1:fontcolor={color_hex(options.get('title_color','white'))}:fontsize={fs}:x={x}-text_w/2:y={y}:shadowcolor=black@0.45:shadowx=1:shadowy=1{out}"
        )
        cur = out
    if watermark_enabled and watermark_text:
        wm_file = work / "_wm_text_v24.txt"; wm_file.write_text(watermark_text, "utf-8")
        wm_path = _ffmpeg_escape_path_v21(wm_file)
        fs = int(options.get("watermark_font_size", 24))
        x = max(0, min(w-10, int(w * float(options.get("watermark_x_pct", 82.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("watermark_y_pct", 93.0)) / 100.0)))
        out = next_label()
        filters.append(
            f"{cur}drawtext=textfile='{wm_path}':reload=1:fontcolor={color_hex(options.get('watermark_color','white'))}@0.65:fontsize={fs}:x={x}-text_w/2:y={y}-text_h/2:shadowcolor=black@0.45:shadowx=1:shadowy=1{out}"
        )
        cur = out
    if overlay_path and overlay_path.exists():
        cmd += ["-i", str(overlay_path)]
        scale_percent = max(5, min(100, int(options.get("overlay_scale_percent", 28) or 28)))
        target_w = max(48, int(w * scale_percent / 100.0))
        filters.append(f"[1:v]scale={target_w}:-1[ovr1]")
        x = max(0, min(w-10, int(w * float(options.get("overlay_x_pct", 82.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("overlay_y_pct", 82.0)) / 100.0)))
        out = next_label()
        filters.append(f"{cur}[ovr1]overlay={x}-w/2:{y}-h/2:format=auto{out}")
        cur = out
    if not filters:
        shutil.copy2(src, dst); return dst
    cmd += ["-filter_complex", ";".join(filters), "-map", cur, "-map", "0:a?", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p", "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2", "-movflags", "+faststart", str(dst)]
    r = self.ffmpeg.run(cmd, "V24视频美化/水印/图片拖拽定位", 1200)
    if r.returncode != 0 or not dst.exists() or dst.stat().st_size < 2048:
        self.log("V24视频美化处理失败，降级使用未美化版本。", "warn")
        shutil.copy2(src, dst)
    return dst


