def _v25_drawtext_fontfile() -> str:
    """Return FFmpeg drawtext fontfile option. Avoid Windows Fontconfig crash."""
    candidates = []
    if os.name == "nt":
        candidates = [
            r"C:\Windows\Fonts\msyh.ttc",
            r"C:\Windows\Fonts\simhei.ttf",
            r"C:\Windows\Fonts\arial.ttf",
        ]
    for c in candidates:
        p = Path(c)
        if p.exists():
            s = str(p.resolve()).replace("\\", "/")
            s = re.sub(r"^([A-Za-z]):/", r"\1\\:/", s)
            return f"fontfile='{s}':"
    return ""


def _ensure_visual_vars_v25(self):
    # Keep existing values if already created; only fix dangerous default.
    if not getattr(self, "_visual_vars_ready_v24", False):
        _ensure_visual_vars_v24(self)
        try:
            # Default must be False; otherwise "分开布局" is overridden by top drag coordinates.
            self.v24_use_visual_positions.set(False)
        except Exception:
            pass
    else:
        if not hasattr(self, "v24_use_visual_positions"):
            self.v24_use_visual_positions = tk.BooleanVar(value=False)


def _build_render_options_v25(self, parent):
    """V25: render options become two buttons + hideable/resizable basic panel."""
    ttk.Label(parent, text="渲染选项", style="H.TLabel").pack(anchor="w")
    self.render_vars = {}
    _ensure_visual_vars_v25(self)

    topbar = ttk.Frame(parent)
    topbar.pack(fill="x", pady=(4, 4))
    self._basic_render_visible_v25 = tk.BooleanVar(value=True)
    ttk.Button(topbar, text="显示/隐藏基础设置", command=self._toggle_basic_render_v25).pack(side="left", padx=(0, 4))
    ttk.Button(topbar, text="美化视频操作台", style="Accent.TButton", command=self._open_beauty_workbench_v25).pack(side="left", padx=4)
    ttk.Button(topbar, text="折叠/展开预览", command=self._toggle_preview_area_v24).pack(side="left", padx=4)

    # A vertical paned window gives a real draggable area for the basic render panel.
    self._render_paned_v25 = tk.PanedWindow(parent, orient="vertical", bg=C_BG, sashwidth=7, sashrelief="raised", bd=0)
    self._render_paned_v25.pack(fill="both", expand=True, pady=(2, 0))
    self._basic_render_wrap_v25 = ttk.LabelFrame(self._render_paned_v25, text="基础渲染（可拖动下方分割条调整高度）", padding=(6, 6))
    self._render_paned_v25.add(self._basic_render_wrap_v25, minsize=260, stretch="always")

    canvas = tk.Canvas(self._basic_render_wrap_v25, bg=C_BG, highlightthickness=0, height=520)
    sb = ttk.Scrollbar(self._basic_render_wrap_v25, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=sb.set)
    canvas.pack(side="left", fill="both", expand=True)
    sb.pack(side="right", fill="y")
    inner = ttk.Frame(canvas)
    win = canvas.create_window((0, 0), window=inner, anchor="nw")
    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfigure(win, width=e.width))
    try:
        _mousewheel_bind_v21(canvas, inner)
    except Exception:
        pass
    self._basic_render_canvas_v25 = canvas

    def combo(container, label, key, options, default_idx=0, width=26):
        f = ttk.Frame(container); f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        var = tk.StringVar(value=options[default_idx][0])
        cb = ttk.Combobox(f, state="readonly", textvariable=var, values=[x[0] for x in options], width=width)
        cb.pack(side="left", fill="x", expand=True)
        self.render_vars[key] = var
        return var

    def spin(container, label, var, frm, to, width=8):
        f = ttk.Frame(container); f.pack(fill="x", pady=2)
        ttk.Label(f, text=label, width=12).pack(side="left")
        ttk.Spinbox(f, from_=frm, to=to, textvariable=var, width=width).pack(side="left")
        return var

    combo(inner, "分辨率", "resolution", RESOLUTION_OPTIONS, 0)
    combo(inner, "渲染方式", "fit_mode", RENDER_FIT_MODE_OPTIONS_V22, 0)
    combo(inner, "字幕类型", "subtitle_mode", SUBTITLE_MODE_OPTIONS, 2)
    combo(inner, "字幕样式", "subtitle_style", SUBTITLE_STYLE_OPTIONS, 0)
    combo(inner, "字幕排列", "subtitle_arrangement", SUBTITLE_ARRANGEMENT_OPTIONS_V21, 0)
    combo(inner, "字幕位置", "subtitle_position", SUBTITLE_POSITION_OPTIONS_V21, 0)
    combo(inner, "英文底色", "en_base", COLOR_OPTIONS, 0)
    combo(inner, "英文覆盖", "en_cover", COLOR_OPTIONS, 3)
    combo(inner, "中文底色", "zh_base", COLOR_OPTIONS, 0)
    combo(inner, "中文覆盖", "zh_cover", COLOR_OPTIONS, 12 if len(COLOR_OPTIONS) > 12 else 2)
    combo(inner, "翻译引擎", "translate_engine", TRANSLATE_ENGINE_OPTIONS, 0)
    self.en_font_size_var = tk.IntVar(value=55)
    self.zh_font_size_var = tk.IntVar(value=40)
    self.font_size_var = tk.IntVar(value=55)
    spin(inner, "英文字号", self.en_font_size_var, 24, 96)
    spin(inner, "中文字幕号", self.zh_font_size_var, 18, 80)
    self.keep_clips_var = tk.BooleanVar(value=False)
    ttk.Checkbutton(inner, text="保留工作 clips/std 文件", variable=self.keep_clips_var).pack(anchor="w", pady=4)
    ttk.Label(inner, text="提示：默认按‘字幕位置/字幕排列’渲染；只有在美化视频操作台勾选‘渲染输出使用拖拽位置’时，才会用拖拽坐标覆盖字幕布局。", style="Dim.TLabel", wraplength=360).pack(fill="x", pady=(6, 4))


def _toggle_basic_render_v25(self):
    pane = getattr(self, "_render_paned_v25", None)
    wrap = getattr(self, "_basic_render_wrap_v25", None)
    if not pane or not wrap:
        return
    visible = bool(getattr(self, "_basic_render_visible_state_v25", True))
    try:
        if visible:
            self._basic_render_pane_saved_v25 = True
            pane.forget(wrap)
            self._basic_render_visible_state_v25 = False
            self.log("已隐藏基础渲染设置。", "info")
        else:
            pane.add(wrap, minsize=260, stretch="always")
            self._basic_render_visible_state_v25 = True
            self.log("已显示基础渲染设置。", "info")
    except Exception as e:
        self.log(f"切换基础设置显示失败：{e}", "warn")


def _get_current_preview_path_v25(self) -> Optional[Path]:
    try:
        if self.pool_tree.selection():
            idx = int(self.pool_tree.selection()[0])
            p = getattr(self.pool[idx], "preview_path", "")
            if p and Path(p).exists():
                return Path(p)
        if self.result_tree.selection():
            idx = int(self.result_tree.selection()[0])
            p = getattr(self.results[idx], "preview_path", "")
            if p and Path(p).exists():
                return Path(p)
    except Exception:
        pass
    return None


def _layout_preview_positions_v25(self, cw: int, ch: int) -> Dict[str, Tuple[float, float]]:
    pos_label = self.render_vars.get("subtitle_position").get() if self.render_vars.get("subtitle_position") else "分开布局"
    arr_label = self.render_vars.get("subtitle_arrangement").get() if self.render_vars.get("subtitle_arrangement") else "上英下中"
    subtitle_position = _combo_to_value_v21(pos_label, SUBTITLE_POSITION_OPTIONS_V21)
    arrangement = _combo_to_value_v21(arr_label, SUBTITLE_ARRANGEMENT_OPTIONS_V21)
    if subtitle_position == "merged_top":
        en_y, zh_y = 72, 122
    elif subtitle_position == "merged_bottom":
        en_y, zh_y = ch - 130, ch - 78
    else:
        en_y, zh_y = 80, ch - 82
    if arrangement != "en_top_zh_bottom":
        en_y, zh_y = zh_y, en_y
    return {"en": (cw * 0.5, en_y), "zh": (cw * 0.5, zh_y)}


def _draw_cross_handle_v25(cvs, x, y, label, color="#00E5FF"):
    r = 10
    ids = []
    ids.append(cvs.create_line(x-r, y, x+r, y, fill=color, width=2))
    ids.append(cvs.create_line(x, y-r, x, y+r, fill=color, width=2))
    ids.append(cvs.create_oval(x-r, y-r, x+r, y+r, outline=color, width=2))
    ids.append(cvs.create_text(x, y-18, text=label, fill=color, font=("Microsoft YaHei UI", 9, "bold")))
    return ids


def _beauty_preview_draw_v25(self):
    if not getattr(self, "_beauty_canvas_v24", None):
        return
    cvs = self._beauty_canvas_v24
    cvs.delete("all")
    cw, ch = 405, 720
    cvs.create_rectangle(0, 0, cw, ch, fill="#111111", outline="")
    mode = _combo_to_value_v21(self.render_vars.get("beauty_mode", tk.StringVar(value=BEAUTY_MODE_OPTIONS_V21[0][0])).get(), BEAUTY_MODE_OPTIONS_V21) if self.render_vars.get("beauty_mode") else "none"

    # Real preview image if possible; otherwise a simple canvas simulation.
    preview_path = _get_current_preview_path_v25(self)
    drawn_img = False
    if preview_path:
        try:
            from PIL import Image, ImageTk  # type: ignore
            im = Image.open(preview_path).convert("RGB")
            if mode in ("blur_bg", "gradient_bg", "ai_expand"):
                bg = im.copy()
                bg.thumbnail((cw, ch), Image.LANCZOS)
            im.thumbnail((cw-44, ch-110), Image.LANCZOS)
            self._beauty_photo_v25 = ImageTk.PhotoImage(im)
            cvs.create_image(cw/2, ch/2, image=self._beauty_photo_v25, anchor="center")
            drawn_img = True
        except Exception:
            drawn_img = False
    if not drawn_img:
        if mode == "blur_bg":
            cvs.create_rectangle(0, 0, cw, ch, fill="#2a2a2a", outline="")
            cvs.create_text(cw//2, ch//2, text="模糊背景填充预览", fill="#777777", font=("Microsoft YaHei UI", 18, "bold"))
        elif mode == "gradient_bg":
            for y in range(0, ch, 12):
                shade = int(18 + 50*y/ch)
                cvs.create_rectangle(0, y, cw, y+12, fill=f"#{shade:02x}{max(8,shade//2):02x}{min(90,shade+30):02x}", outline="")
        else:
            cvs.create_rectangle(28, 70, cw-28, ch-70, fill="#222222", outline="#444444")
    cvs.create_rectangle(12, 12, cw-12, ch-12, outline="#444444")
    en, zh = _get_preview_text_v24(self)
    en = en[:56] + ("..." if len(en) > 56 else "")
    zh = zh[:28] + ("..." if len(zh) > 28 else "")
    try:
        self._beauty_summary_v24.set(
            f"分辨率：{self.render_vars['resolution'].get()}\n"
            f"渲染方式：{self.render_vars['fit_mode'].get()}\n"
            f"字幕：{self.render_vars['subtitle_position'].get()} / {self.render_vars['subtitle_arrangement'].get()}\n"
            f"英字号：{self.en_font_size_var.get()}  中字号：{self.zh_font_size_var.get()}\n"
            f"输出拖拽位置：{'启用' if self.v24_use_visual_positions.get() else '关闭'}"
        )
    except Exception:
        pass
    items = []
    layout_pos = _layout_preview_positions_v25(self, cw, ch)
    if self.v24_use_visual_positions.get():
        en_x, en_y = cw*self.v24_en_x_pct.get()/100, ch*self.v24_en_y_pct.get()/100
        zh_x, zh_y = cw*self.v24_zh_x_pct.get()/100, ch*self.v24_zh_y_pct.get()/100
    else:
        en_x, en_y = layout_pos["en"]
        zh_x, zh_y = layout_pos["zh"]

    if self.title_enable_var.get():
        title = (self.title_text_var.get() or _combo_to_value_v21(self.render_vars.get("title_preset", tk.StringVar(value="")).get(), TITLE_PRESET_OPTIONS_V21) or "TITLE")
        x, y = cw*self.v24_title_x_pct.get()/100, ch*self.v24_title_y_pct.get()/100
        cvs.create_rectangle(0, max(0, y-26), cw, min(ch, y+30), fill="#000000", stipple="gray50", outline="")
        iid = cvs.create_text(x, y, text=title, fill=self._v24_hex(self.render_vars.get("title_color", tk.StringVar(value="白色")).get()), font=("Microsoft YaHei UI", 16, "bold"))
        items.append(("title", iid));
        for hid in _draw_cross_handle_v25(cvs, x, y, "TITLE", "#FFD54F"):
            items.append(("title", hid))
    iid = cvs.create_text(en_x, en_y, text="EN  " + en, fill=self._v24_hex(_combo_to_value_v21(self.render_vars.get("en_cover", tk.StringVar(value="黄色")).get(), COLOR_OPTIONS)), font=("Microsoft YaHei UI", 17, "bold"), justify="center")
    items.append(("en", iid))
    for hid in _draw_cross_handle_v25(cvs, en_x, en_y, "EN", "#00E5FF"):
        items.append(("en", hid))
    iid = cvs.create_text(zh_x, zh_y, text="CN  " + zh, fill=self._v24_hex(_combo_to_value_v21(self.render_vars.get("zh_cover", tk.StringVar(value="绿色")).get(), COLOR_OPTIONS)), font=("Microsoft YaHei UI", 14, "bold"), justify="center")
    items.append(("zh", iid))
    for hid in _draw_cross_handle_v25(cvs, zh_x, zh_y, "CN", "#22C55E"):
        items.append(("zh", hid))
    if self.watermark_enable_var.get():
        wm = self.watermark_text_var.get() or "WM"
        x, y = cw*self.v24_wm_x_pct.get()/100, ch*self.v24_wm_y_pct.get()/100
        iid = cvs.create_text(x, y, text="WM  " + wm, fill=self._v24_hex(self.render_vars.get("watermark_color", tk.StringVar(value="白色")).get()), font=("Microsoft YaHei UI", 12, "bold"))
        items.append(("wm", iid))
        for hid in _draw_cross_handle_v25(cvs, x, y, "WM", "#F472B6"):
            items.append(("wm", hid))
    if self.overlay_image_var.get():
        x, y = cw*self.v24_img_x_pct.get()/100, ch*self.v24_img_y_pct.get()/100
        drew_overlay = False
        try:
            from PIL import Image, ImageTk  # type: ignore
            p = Path(self.overlay_image_var.get())
            if p.exists():
                oi = Image.open(p).convert("RGBA")
                target_w = max(36, int(cw * max(5, min(100, self.overlay_scale_var.get())) / 100))
                oi.thumbnail((target_w, target_w), Image.LANCZOS)
                self._beauty_overlay_photo_v25 = ImageTk.PhotoImage(oi)
                iid = cvs.create_image(x, y, image=self._beauty_overlay_photo_v25, anchor="center")
                items.append(("img", iid))
                drew_overlay = True
        except Exception:
            drew_overlay = False
        if not drew_overlay:
            rect = cvs.create_rectangle(x-45, y-28, x+45, y+28, fill="#2f4f4f", outline="#9ee7ff", width=2)
            txt = cvs.create_text(x, y, text="IMG", fill="#ffffff", font=("Microsoft YaHei UI", 14, "bold"))
            items.append(("img", rect)); items.append(("img", txt))
        for hid in _draw_cross_handle_v25(cvs, x, y, "IMG", "#A78BFA"):
            items.append(("img", hid))
    self._beauty_items_v24 = {iid: name for name, iid in items}
    for name, iid in items:
        cvs.addtag_withtag("drag", iid)
    try:
        cvs.configure(cursor="crosshair")
    except Exception:
        pass


def _beauty_canvas_press_v25(self, event):
    cvs = self._beauty_canvas_v24
    hits = cvs.find_overlapping(event.x-12, event.y-12, event.x+12, event.y+12)
    chosen = None
    for iid in reversed(hits):
        if getattr(self, "_beauty_items_v24", {}).get(iid):
            chosen = iid
            break
    if chosen is None:
        hit = cvs.find_closest(event.x, event.y)
        chosen = hit[0] if hit else None
    self._beauty_drag_item_v24 = chosen
    if chosen and getattr(self, "_beauty_items_v24", {}).get(chosen) in ("en", "zh"):
        # Explicit user drag should enable visual subtitle output.
        try:
            self.v24_use_visual_positions.set(True)
        except Exception:
            pass


def _beauty_canvas_drag_v25(self, event):
    iid = getattr(self, "_beauty_drag_item_v24", None)
    if not iid:
        return
    name = getattr(self, "_beauty_items_v24", {}).get(iid)
    if not name:
        return
    cw, ch = 405, 720
    x_pct = max(0.0, min(100.0, event.x * 100.0 / cw))
    y_pct = max(0.0, min(100.0, event.y * 100.0 / ch))
    if name == "en":
        self.v24_en_x_pct.set(x_pct); self.v24_en_y_pct.set(y_pct); self.v24_use_visual_positions.set(True)
    elif name == "zh":
        self.v24_zh_x_pct.set(x_pct); self.v24_zh_y_pct.set(y_pct); self.v24_use_visual_positions.set(True)
    elif name == "title":
        self.v24_title_x_pct.set(x_pct); self.v24_title_y_pct.set(y_pct)
    elif name == "wm":
        self.v24_wm_x_pct.set(x_pct); self.v24_wm_y_pct.set(y_pct)
    elif name == "img":
        self.v24_img_x_pct.set(x_pct); self.v24_img_y_pct.set(y_pct)
    # Full redraw is acceptable, but do idle update to reduce motion lag.
    try:
        self.after_idle(self._beauty_preview_draw_v25)
    except Exception:
        self._beauty_preview_draw_v25()


def _open_beauty_workbench_v25(self):
    _ensure_visual_vars_v25(self)
    if getattr(self, "_beauty_win_v24", None) and self._beauty_win_v24.winfo_exists():
        self._beauty_win_v24.lift(); return
    win = tk.Toplevel(self)
    win.title("美化视频操作台 · 实时预览 / 拖拽定位")
    win.geometry("1220x820")
    win.configure(bg=C_BG)
    self._beauty_win_v24 = win
    root = ttk.Frame(win, padding=10)
    root.pack(fill="both", expand=True)
    left = ttk.Frame(root, width=350)
    left.pack(side="left", fill="y", padx=(0, 10))
    right = ttk.Frame(root)
    right.pack(side="left", fill="both", expand=True)
    ttk.Label(left, text="当前基础渲染效果", style="H.TLabel").pack(anchor="w", pady=(0, 6))
    self._beauty_summary_v24 = tk.StringVar(value="")
    ttk.Label(left, textvariable=self._beauty_summary_v24, style="Dim.TLabel", wraplength=330).pack(fill="x", pady=(0, 8))

    def combo(container, label, key, options, default_idx=0):
        f = ttk.Frame(container); f.pack(fill="x", pady=3)
        ttk.Label(f, text=label, width=11).pack(side="left")
        var = self.render_vars.get(key)
        if var is None:
            var = tk.StringVar(value=options[default_idx][0]); self.render_vars[key] = var
        cb = ttk.Combobox(f, state="readonly", textvariable=var, values=[x[0] for x in options], width=24)
        cb.pack(side="left", fill="x", expand=True)
        cb.bind("<<ComboboxSelected>>", lambda e: self._beauty_preview_draw_v25())
        return cb

    g0 = ttk.LabelFrame(left, text="拖拽定位", padding=8); g0.pack(fill="x", pady=6)
    ttk.Checkbutton(g0, text="渲染输出使用拖拽字幕位置（默认关闭）", variable=self.v24_use_visual_positions, command=self._beauty_preview_draw_v25).pack(anchor="w", pady=3)
    ttk.Label(g0, text="关闭时：视频严格按‘分开/合并上方/合并下方’输出；拖拽 EN/CN 会自动开启。", style="Dim.TLabel", wraplength=320).pack(fill="x")

    g1 = ttk.LabelFrame(left, text="画面美化", padding=8); g1.pack(fill="x", pady=6)
    combo(g1, "黑边美化", "beauty_mode", BEAUTY_MODE_OPTIONS_V21, 0)

    g2 = ttk.LabelFrame(left, text="顶部标题栏", padding=8); g2.pack(fill="x", pady=6)
    ttk.Checkbutton(g2, text="启用顶部标题栏", variable=self.title_enable_var, command=self._beauty_preview_draw_v25).pack(anchor="w")
    combo(g2, "标题预设", "title_preset", TITLE_PRESET_OPTIONS_V21, 0)
    f = ttk.Frame(g2); f.pack(fill="x", pady=3)
    ttk.Label(f, text="标题", width=11).pack(side="left")
    ent = ttk.Entry(f, textvariable=self.title_text_var); ent.pack(side="left", fill="x", expand=True)
    ent.bind("<KeyRelease>", lambda e: self._beauty_preview_draw_v25())
    ttk.Label(g2, text="标题字号", style="Dim.TLabel").pack(anchor="w")
    ttk.Spinbox(g2, from_=18, to=72, textvariable=self.title_font_size_var, width=8, command=self._beauty_preview_draw_v25).pack(anchor="w", pady=3)
    combo(g2, "标题颜色", "title_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)

    g3 = ttk.LabelFrame(left, text="水印 / 图片遮罩", padding=8); g3.pack(fill="x", pady=6)
    ttk.Checkbutton(g3, text="启用文字水印", variable=self.watermark_enable_var, command=self._beauty_preview_draw_v25).pack(anchor="w")
    f = ttk.Frame(g3); f.pack(fill="x", pady=3)
    ttk.Label(f, text="水印", width=11).pack(side="left")
    ent2 = ttk.Entry(f, textvariable=self.watermark_text_var); ent2.pack(side="left", fill="x", expand=True)
    ent2.bind("<KeyRelease>", lambda e: self._beauty_preview_draw_v25())
    ttk.Label(g3, text="水印字号", style="Dim.TLabel").pack(anchor="w")
    ttk.Spinbox(g3, from_=14, to=60, textvariable=self.watermark_font_size_var, width=8, command=self._beauty_preview_draw_v25).pack(anchor="w", pady=3)
    combo(g3, "水印颜色", "watermark_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)
    ttk.Separator(g3).pack(fill="x", pady=6)
    f = ttk.Frame(g3); f.pack(fill="x", pady=3)
    ttk.Label(f, text="图片", width=11).pack(side="left")
    ttk.Entry(f, textvariable=self.overlay_image_var).pack(side="left", fill="x", expand=True)
    ttk.Button(f, text="浏览", width=7, command=self._browse_overlay_image_v24).pack(side="left", padx=(5, 0))
    combo(g3, "图片位置", "overlay_position", OVERLAY_POSITION_OPTIONS_V21, 0)
    ttk.Label(g3, text="图片缩放%", style="Dim.TLabel").pack(anchor="w")
    ttk.Spinbox(g3, from_=5, to=100, textvariable=self.overlay_scale_var, width=8, command=self._beauty_preview_draw_v25).pack(anchor="w", pady=3)

    ttk.Button(left, text="应用并关闭", style="Accent.TButton", command=win.destroy).pack(fill="x", pady=(10, 4))
    ttk.Label(left, text="拖拽标记：十字星即最终中心点。EN/CN 字幕默认按基础布局；拖拽后才会覆盖基础布局。", style="Dim.TLabel", wraplength=330).pack(fill="x")
    self._beauty_canvas_v24 = tk.Canvas(right, width=405, height=720, bg="#111111", highlightthickness=1, highlightbackground=C_BORDER)
    self._beauty_canvas_v24.pack(anchor="center", expand=True)
    self._beauty_drag_item_v24 = None
    self._beauty_canvas_v24.bind("<ButtonPress-1>", self._beauty_canvas_press_v25)
    self._beauty_canvas_v24.bind("<B1-Motion>", self._beauty_canvas_drag_v25)
    self._beauty_canvas_v24.bind("<ButtonRelease-1>", lambda e: setattr(self, "_beauty_drag_item_v24", None))
    self._beauty_preview_draw_v25()


def _render_options_v25(self) -> Dict[str, Any]:
    # Same as V24, but visual positions are no longer enabled by default.
    opts = _render_options_v24(self)
    try:
        opts["use_visual_positions"] = bool(self.v24_use_visual_positions.get())
    except Exception:
        opts["use_visual_positions"] = False
    return opts


def _postprocess_video_v25(self, src: Path, dst: Path, options: Dict[str, Any], resolution: str, work: Path) -> Path:
    title_enabled = bool(options.get("title_enabled", False))
    title_text = str(options.get("title_text", "") or "").strip()
    watermark_enabled = bool(options.get("watermark_enabled", False))
    watermark_text = str(options.get("watermark_text", "") or "").strip()
    overlay_path = Path(options.get("overlay_image_path", "") or "") if str(options.get("overlay_image_path", "") or "").strip() else None
    if (not title_enabled or not title_text) and (not watermark_enabled or not watermark_text) and not (overlay_path and overlay_path.exists()):
        shutil.copy2(src, dst)
        return dst
    ff = self.ffmpeg.ffmpeg
    w, h = parse_resolution(resolution)
    cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(src)]
    filters = []
    cur = "[0:v]"
    vid_idx = 0
    fontfile = _v25_drawtext_fontfile()
    def next_label():
        nonlocal vid_idx
        vid_idx += 1
        return f"[v{vid_idx}]"
    def color_hex(name):
        return FF_COLOR_HEX_V21.get(str(name or "white"), "#FFFFFF")
    if title_enabled and title_text:
        title_file = work / "_title_text_v25.txt"; title_file.write_text(title_text, "utf-8")
        title_path = _ffmpeg_escape_path_v21(title_file)
        fs = int(options.get("title_font_size", 28))
        x = max(0, min(w-10, int(w * float(options.get("title_x_pct", 50.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("title_y_pct", 4.0)) / 100.0)))
        bar_h = max(56, int(fs * 2.2))
        out = next_label()
        filters.append(
            f"{cur}drawbox=x=0:y=0:w=iw:h={bar_h}:color=black@0.40:t=fill,"
            f"drawtext={fontfile}textfile='{title_path}':reload=1:fontcolor={color_hex(options.get('title_color','white'))}:fontsize={fs}:x={x}-text_w/2:y={y}:shadowcolor=black@0.45:shadowx=1:shadowy=1{out}"
        )
        cur = out
    if watermark_enabled and watermark_text:
        wm_file = work / "_wm_text_v25.txt"; wm_file.write_text(watermark_text, "utf-8")
        wm_path = _ffmpeg_escape_path_v21(wm_file)
        fs = int(options.get("watermark_font_size", 24))
        x = max(0, min(w-10, int(w * float(options.get("watermark_x_pct", 82.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("watermark_y_pct", 93.0)) / 100.0)))
        out = next_label()
        filters.append(
            f"{cur}drawtext={fontfile}textfile='{wm_path}':reload=1:fontcolor={color_hex(options.get('watermark_color','white'))}@0.65:fontsize={fs}:x={x}-text_w/2:y={y}-text_h/2:shadowcolor=black@0.45:shadowx=1:shadowy=1{out}"
        )
        cur = out
    if overlay_path and overlay_path.exists():
        cmd += ["-i", str(overlay_path)]
        scale_percent = max(5, min(100, int(options.get("overlay_scale_percent", 28) or 28)))
        target_w = max(48, int(w * scale_percent / 100.0))
        filters.append(f"[1:v]scale={target_w}:-1[ovr1]")
        x = max(0, min(w-10, int(w * float(options.get("overlay_x_pct", 82.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("overlay_y_pct", 82.0)) / 100.0)))
        out = next_label()
        filters.append(f"{cur}[ovr1]overlay={x}-w/2:{y}-h/2:format=auto{out}")
        cur = out
    if not filters:
        shutil.copy2(src, dst)
        return dst
    cmd += ["-filter_complex", ";".join(filters), "-map", cur, "-map", "0:a?", "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p", "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2", "-movflags", "+faststart", str(dst)]
    r = self.ffmpeg.run(cmd, "V25视频美化/水印/图片拖拽定位", 1200)
    if r.returncode != 0 or not dst.exists() or dst.stat().st_size < 2048:
        self.log("V25视频美化处理失败，降级使用未美化版本。", "warn")
        shutil.copy2(src, dst)
    return dst


# Activate V25 overrides.
MainApp._build_render_options = _build_render_options_v25
MainApp._toggle_basic_render_v25 = _toggle_basic_render_v25
MainApp._open_beauty_workbench_v25 = _open_beauty_workbench_v25
