MainApp._beauty_canvas_press_v25 = _beauty_canvas_press_v25
MainApp._beauty_canvas_drag_v25 = _beauty_canvas_drag_v25
MainApp._render_options = _render_options_v25
RenderServiceV17._postprocess_video_v21 = _postprocess_video_v25
APP_TITLE = "PlayPhrase Studio Clean v25 · 字幕分开布局修复+可视化操作台增强+无AI版"


# ──────────────────────────────────────────────────────────────────────
# V26: sync new render options to manual render and batch render
# 把精选工作台的 V22/V23/V25 渲染选项同步到手动渲染 / 批量渲染。
# ──────────────────────────────────────────────────────────────────────

def _safe_get_combo_v26(var_map: Dict[str, tk.Variable], key: str, options, default_idx: int = 0):
    try:
        label = var_map[key].get()
        return next((v for k, v in options if k == label), options[default_idx][1])
    except Exception:
        return options[default_idx][1]


def _safe_int_var_v26(obj: Any, name: str, default: int) -> int:
    try:
        v = getattr(obj, name)
        return int(v.get())
    except Exception:
        return int(default)


def _add_render_sync_panel_v26(self, parent, prefix: str, compact: bool = False):
    """Add a synchronized V26 render option panel to batch/manual pages."""
    if getattr(self, f"_{prefix}_v26_panel_ready", False):
        return
    setattr(self, f"_{prefix}_v26_panel_ready", True)

    box = ttk.LabelFrame(parent, text="V26 同步渲染选项（与精选工作台同源）", padding=8)
    box.pack(fill="x", padx=14, pady=(6, 10))
    vars_map: Dict[str, tk.Variable] = {}
    setattr(self, f"{prefix}_v26_vars", vars_map)

    def combo(label, key, options, default_idx=0, width=20, col=0):
        row = ttk.Frame(box)
        row.pack(fill="x", pady=2)
        ttk.Label(row, text=label, width=12).pack(side="left")
        var = tk.StringVar(value=options[default_idx][0])
        cb = ttk.Combobox(row, state="readonly", textvariable=var, values=[x[0] for x in options], width=width)
        cb.pack(side="left", fill="x", expand=True)
        vars_map[key] = var
        return var

    def spin(label, attr_name, default, frm, to, width=8):
        row = ttk.Frame(box)
        row.pack(fill="x", pady=2)
        ttk.Label(row, text=label, width=12).pack(side="left")
        var = tk.IntVar(value=default)
        ttk.Spinbox(row, from_=frm, to=to, textvariable=var, width=width).pack(side="left")
        setattr(self, f"{prefix}_{attr_name}", var)
        return var

    def entry(label, attr_name, default=""):
        row = ttk.Frame(box)
        row.pack(fill="x", pady=2)
        ttk.Label(row, text=label, width=12).pack(side="left")
        var = tk.StringVar(value=default)
        ttk.Entry(row, textvariable=var).pack(side="left", fill="x", expand=True)
        setattr(self, f"{prefix}_{attr_name}", var)
        return var

    def check(label, attr_name, default=False):
        var = tk.BooleanVar(value=default)
        ttk.Checkbutton(box, text=label, variable=var).pack(anchor="w", pady=2)
        setattr(self, f"{prefix}_{attr_name}", var)
        return var

    combo("渲染方式", "fit_mode", RENDER_FIT_MODE_OPTIONS_V22, 0)
    combo("字幕排列", "subtitle_arrangement", SUBTITLE_ARRANGEMENT_OPTIONS_V21, 0)
    combo("字幕位置", "subtitle_position", SUBTITLE_POSITION_OPTIONS_V21, 0)
    combo("英文底色", "en_base_v26", COLOR_OPTIONS, 0)
    combo("英文覆盖", "en_cover_v26", COLOR_OPTIONS, 3 if len(COLOR_OPTIONS) > 3 else 0)
    combo("中文底色", "zh_base_v26", COLOR_OPTIONS, 0)
    combo("中文覆盖", "zh_cover_v26", COLOR_OPTIONS, 12 if len(COLOR_OPTIONS) > 12 else 2)
    spin("英文字号", "en_font_size_var_v26", 55, 24, 96)
    spin("中文字幕号", "zh_font_size_var_v26", 40, 18, 80)

    ttk.Separator(box).pack(fill="x", pady=6)
    combo("黑边美化", "beauty_mode", BEAUTY_MODE_OPTIONS_V21, 0)
    check("启用顶部标题栏", "title_enable_var_v26", False)
    combo("标题预设", "title_preset", TITLE_PRESET_OPTIONS_V21, 0)
    entry("自定义标题", "title_text_var_v26", "")
    spin("标题字号", "title_font_size_var_v26", 28, 18, 72)
    combo("标题颜色", "title_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)

