    check("启用文字水印", "watermark_enable_var_v26", False)
    entry("水印文字", "watermark_text_var_v26", "")
    spin("水印字号", "watermark_font_size_var_v26", 24, 14, 60)
    combo("水印颜色", "watermark_color", TEXT_STYLE_COLOR_OPTIONS_V23, 0)

    row = ttk.Frame(box); row.pack(fill="x", pady=2)
    ttk.Label(row, text="本地图片", width=12).pack(side="left")
