def _beauty_canvas_press_v27(self, event):
    cvs = self._beauty_canvas_v24
    hits = cvs.find_overlapping(event.x-14, event.y-14, event.x+14, event.y+14)
    chosen = None
    for iid in reversed(hits):
        if getattr(self, "_beauty_items_v24", {}).get(iid):
            chosen = iid
            break
    if chosen is None:
        hit = cvs.find_closest(event.x, event.y)
        chosen = hit[0] if hit else None
    self._beauty_drag_item_v24 = chosen
    self._beauty_drag_last_xy_v27 = (event.x, event.y)
    self._beauty_drag_group_v27 = getattr(self, "_beauty_items_v24", {}).get(chosen)
    if chosen and self._beauty_drag_group_v27 in ("en", "zh"):
        try:
            self.v24_use_visual_positions.set(True)
        except Exception:
            pass


def _beauty_canvas_drag_v27(self, event):
    iid = getattr(self, "_beauty_drag_item_v24", None)
    group = getattr(self, "_beauty_drag_group_v27", None)
    if not iid or not group:
        return
    cvs = self._beauty_canvas_v24
    last = getattr(self, "_beauty_drag_last_xy_v27", (event.x, event.y))
    dx, dy = event.x - last[0], event.y - last[1]
    if abs(dx) < 1 and abs(dy) < 1:
        return
    self._beauty_drag_last_xy_v27 = (event.x, event.y)
    # Move only lightweight overlay objects belonging to the same group; do not redraw background during drag.
    for obj_id, obj_group in list(getattr(self, "_beauty_items_v24", {}).items()):
        if obj_group == group:
            try:
                cvs.move(obj_id, dx, dy)
            except Exception:
                pass
    cw, ch = 405, 720
    x_pct = max(0.0, min(100.0, event.x * 100.0 / cw))
    y_pct = max(0.0, min(100.0, event.y * 100.0 / ch))
    try:
        if group == "en":
            self.v24_en_x_pct.set(x_pct); self.v24_en_y_pct.set(y_pct); self.v24_use_visual_positions.set(True)
        elif group == "zh":
            self.v24_zh_x_pct.set(x_pct); self.v24_zh_y_pct.set(y_pct); self.v24_use_visual_positions.set(True)
        elif group == "title":
            self.v24_title_x_pct.set(x_pct); self.v24_title_y_pct.set(y_pct)
        elif group == "wm":
            self.v24_wm_x_pct.set(x_pct); self.v24_wm_y_pct.set(y_pct)
        elif group == "img":
            self.v24_img_x_pct.set(x_pct); self.v24_img_y_pct.set(y_pct)
    except Exception:
        pass


def _beauty_canvas_release_v27(self, event=None):
    self._beauty_drag_item_v24 = None
    self._beauty_drag_group_v27 = None
    try:
        self.after_idle(self._beauty_preview_draw_v25)
    except Exception:
        pass


