def _ensure_multi_watermarks_v28(self):
    if not hasattr(self, "multi_watermarks_v28") or self.multi_watermarks_v28 is None:
        self.multi_watermarks_v28 = []
    return self.multi_watermarks_v28


def _refresh_multi_watermark_list_v28(self):
    lb = getattr(self, "_multi_wm_listbox_v28", None)
    if not lb:
        return
    lb.delete(0, "end")
    for i, wm in enumerate(_ensure_multi_watermarks_v28(self), 1):
        text = str(wm.get("text", "") or "WM").strip()
        size = wm.get("font_size", 24)
        color = wm.get("color", "white")
        x = wm.get("x_pct", 82.0)
        y = wm.get("y_pct", 93.0)
        lb.insert("end", f"{i}. {text[:24]} | {size}px | {color} | x={x:.1f}% y={y:.1f}%")


def _selected_multi_wm_index_v28(self):
    lb = getattr(self, "_multi_wm_listbox_v28", None)
    if not lb:
        return None
    sel = lb.curselection()
    if not sel:
        return None
    return int(sel[0])


def _multi_wm_fill_form_v28(self, idx=None):
    _ensure_multi_watermarks_v28(self)
    if idx is None:
        idx = _selected_multi_wm_index_v28(self)
    if idx is None or idx < 0 or idx >= len(self.multi_watermarks_v28):
        return
    wm = self.multi_watermarks_v28[idx]
    try:
        self.multi_wm_text_var_v28.set(str(wm.get("text", "")))
        self.multi_wm_size_var_v28.set(int(wm.get("font_size", 24)))
        self.multi_wm_x_var_v28.set(float(wm.get("x_pct", 82.0)))
        self.multi_wm_y_var_v28.set(float(wm.get("y_pct", 93.0)))
        self.multi_wm_color_var_v28.set(_value_to_label_v21(str(wm.get("color", "white")), TEXT_STYLE_COLOR_OPTIONS_V23))
    except Exception:
        pass


def _multi_wm_form_to_dict_v28(self):
    try:
        color = _combo_to_value_v21(self.multi_wm_color_var_v28.get(), TEXT_STYLE_COLOR_OPTIONS_V23)
    except Exception:
        color = "white"
    return {
        "text": (self.multi_wm_text_var_v28.get() or "").strip() or "WM",
        "font_size": int(float(self.multi_wm_size_var_v28.get() or 24)),
        "color": color,
        "x_pct": max(0.0, min(100.0, float(self.multi_wm_x_var_v28.get() or 82.0))),
        "y_pct": max(0.0, min(100.0, float(self.multi_wm_y_var_v28.get() or 93.0))),
    }


def _multi_wm_add_v28(self):
    _ensure_multi_watermarks_v28(self)
    self.multi_watermarks_v28.append(_multi_wm_form_to_dict_v28(self))
    _refresh_multi_watermark_list_v28(self)
    try:
        self._beauty_preview_draw_v25()
    except Exception:
        pass


def _multi_wm_update_v28(self):
    idx = _selected_multi_wm_index_v28(self)
    if idx is None:
        messagebox.showwarning("提示", "请先选中要更新的水印。")
        return
    self.multi_watermarks_v28[idx] = _multi_wm_form_to_dict_v28(self)
    _refresh_multi_watermark_list_v28(self)
    try:
        self._beauty_preview_draw_v25()
    except Exception:
        pass


def _multi_wm_delete_v28(self):
    idx = _selected_multi_wm_index_v28(self)
    if idx is None:
        return
    try:
        del self.multi_watermarks_v28[idx]
    except Exception:
        pass
    _refresh_multi_watermark_list_v28(self)
    try:
        self._beauty_preview_draw_v25()
    except Exception:
        pass


def _multi_wm_clear_v28(self):
    _ensure_multi_watermarks_v28(self).clear()
    _refresh_multi_watermark_list_v28(self)
    try:
        self._beauty_preview_draw_v25()
    except Exception:
        pass


