def _ensure_multi_watermarks_v31(self):
    if not hasattr(self, "multi_watermarks_v28") or self.multi_watermarks_v28 is None:
        self.multi_watermarks_v28 = []
    # normalize existing V28 items to V31 schema
    out = []
    for wm in list(self.multi_watermarks_v28):
        try:
            out.append({
                "text": str(wm.get("text", "") or "WM"),
                "font_size": int(float(wm.get("font_size", 24) or 24)),
                "color": str(wm.get("color", "white") or "white"),
                "opacity": float(wm.get("opacity", 0.65) if wm.get("opacity", None) is not None else 0.65),
                "x_pct": max(0.0, min(100.0, float(wm.get("x_pct", 82.0) or 82.0))),
                "y_pct": max(0.0, min(100.0, float(wm.get("y_pct", 93.0) or 93.0))),
            })
        except Exception:
            pass
    self.multi_watermarks_v28 = out
    return self.multi_watermarks_v28


def _refresh_multi_watermark_list_v31(self):
    lb = getattr(self, "_multi_wm_listbox_v28", None)
    if not lb:
        return
    lb.delete(0, "end")
    for i, wm in enumerate(_ensure_multi_watermarks_v31(self), 1):
        text = str(wm.get("text", "") or "WM").strip()
        size = int(wm.get("font_size", 24) or 24)
        color = wm.get("color", "white")
        op = float(wm.get("opacity", 0.65) or 0.65)
        x = float(wm.get("x_pct", 82.0) or 82.0)
        y = float(wm.get("y_pct", 93.0) or 93.0)
        lb.insert("end", f"{i}. {text[:22]} | {size}px | {color} | {int(op*100)}% | x={x:.1f}% y={y:.1f}%")


def _selected_multi_wm_index_v31(self):
    lb = getattr(self, "_multi_wm_listbox_v28", None)
    if not lb:
        return None
    sel = lb.curselection()
    if not sel:
        return None
    return int(sel[0])


def _multi_wm_fill_form_v31(self, idx=None):
    items = _ensure_multi_watermarks_v31(self)
    if idx is None:
        idx = _selected_multi_wm_index_v31(self)
    if idx is None or idx < 0 or idx >= len(items):
        return
    wm = items[idx]
    try:
        self.multi_wm_text_var_v28.set(str(wm.get("text", "")))
        self.multi_wm_size_var_v28.set(int(wm.get("font_size", 24)))
        self.multi_wm_x_var_v28.set(float(wm.get("x_pct", 82.0)))
        self.multi_wm_y_var_v28.set(float(wm.get("y_pct", 93.0)))
        if hasattr(self, "multi_wm_opacity_var_v31"):
            self.multi_wm_opacity_var_v31.set(int(round(float(wm.get("opacity", 0.65)) * 100)))
        self.multi_wm_color_var_v28.set(_value_to_label_v21(str(wm.get("color", "white")), TEXT_STYLE_COLOR_OPTIONS_V23))
    except Exception:
        pass


def _multi_wm_form_to_dict_v31(self):
    try:
        color = _combo_to_value_v21(self.multi_wm_color_var_v28.get(), TEXT_STYLE_COLOR_OPTIONS_V23)
    except Exception:
        color = "white"
    try:
        op = max(0.05, min(1.0, float(getattr(self, "multi_wm_opacity_var_v31", tk.IntVar(value=65)).get()) / 100.0))
    except Exception:
        op = 0.65
    return {
        "text": (self.multi_wm_text_var_v28.get() or "").strip() or "WM",
        "font_size": int(float(self.multi_wm_size_var_v28.get() or 24)),
        "color": color,
        "opacity": op,
        "x_pct": max(0.0, min(100.0, float(self.multi_wm_x_var_v28.get() or 82.0))),
        "y_pct": max(0.0, min(100.0, float(self.multi_wm_y_var_v28.get() or 93.0))),
    }


def _multi_wm_add_v31(self):
    _ensure_multi_watermarks_v31(self).append(_multi_wm_form_to_dict_v31(self))
    _refresh_multi_watermark_list_v31(self)
    try: self._beauty_preview_draw_v31()
    except Exception: pass


def _multi_wm_update_v31(self):
    idx = _selected_multi_wm_index_v31(self)
    if idx is None:
        messagebox.showwarning("提示", "请先选中要更新的水印。")
        return
    _ensure_multi_watermarks_v31(self)[idx] = _multi_wm_form_to_dict_v31(self)
    _refresh_multi_watermark_list_v31(self)
    try: self._beauty_preview_draw_v31()
    except Exception: pass


def _multi_wm_delete_v31(self):
    idx = _selected_multi_wm_index_v31(self)
    if idx is None:
        return
    try:
        del _ensure_multi_watermarks_v31(self)[idx]
    except Exception:
        pass
    _refresh_multi_watermark_list_v31(self)
    try: self._beauty_preview_draw_v31()
    except Exception: pass


def _multi_wm_clear_v31(self):
    _ensure_multi_watermarks_v31(self).clear()
    _refresh_multi_watermark_list_v31(self)
    try: self._beauty_preview_draw_v31()
    except Exception: pass


def _open_multi_watermark_manager_v31(self):
    _ensure_multi_watermarks_v31(self)
    if getattr(self, "_multi_wm_win_v28", None) and self._multi_wm_win_v28.winfo_exists():
        self._multi_wm_win_v28.lift()
