    btns = ttk.Frame(left); btns.pack(fill="x", pady=4)
    ttk.Button(btns, text="添加", command=self._multi_wm_add_v31).pack(side="left", padx=3)
    ttk.Button(btns, text="更新选中", command=self._multi_wm_update_v31).pack(side="left", padx=3)
    ttk.Button(btns, text="删除选中", command=self._multi_wm_delete_v31).pack(side="left", padx=3)
