    ttk.Button(btns, text="打开美化操作台", command=self._open_beauty_workbench_v25).pack(side="left", padx=3)

    self.multi_wm_text_var_v28 = tk.StringVar(value="Crush33442")
    self.multi_wm_size_var_v28 = tk.IntVar(value=24)
    self.multi_wm_color_var_v28 = tk.StringVar(value=TEXT_STYLE_COLOR_OPTIONS_V23[0][0])
    self.multi_wm_opacity_var_v31 = tk.IntVar(value=65)
    self.multi_wm_x_var_v28 = tk.DoubleVar(value=82.0)
    self.multi_wm_y_var_v28 = tk.DoubleVar(value=93.0)

    def row(label, widget):
        f = ttk.Frame(right); f.pack(fill="x", pady=4)
