    row("字号", ttk.Spinbox(right, from_=12, to=120, textvariable=self.multi_wm_size_var_v28, width=10))
    row("颜色", ttk.Combobox(right, state="readonly", textvariable=self.multi_wm_color_var_v28, values=[x[0] for x in TEXT_STYLE_COLOR_OPTIONS_V23], width=20))
