    row("Y百分比", ttk.Spinbox(right, from_=0, to=100, increment=0.5, textvariable=self.multi_wm_y_var_v28, width=10))
    ttk.Label(right, text="说明：X/Y 是视频画面百分比坐标；也可以在【美化操作台】里拖拽水印十字星。", style="Dim.TLabel", wraplength=270).pack(fill="x", pady=10)
    ttk.Button(right, text="关闭", style="Accent.TButton", command=win.destroy).pack(fill="x", pady=6)
