def _render_options_v31(self) -> Dict[str, Any]:
    # Use the currently active render option collector, then force V31 multi-watermark payload into options.
    opts = _render_options_v28(self)
    try:
        opts["watermarks"] = [dict(x) for x in _ensure_multi_watermarks_v31(self)]
    except Exception:
        opts["watermarks"] = []
    return opts


def _beauty_preview_draw_v31(self):
    # Draw base V25 preview first, then overlay V31 multi-watermarks as actual draggable items.
    try:
        _beauty_preview_draw_v25(self)
    except Exception:
        return
    cvs = getattr(self, "_beauty_canvas_v24", None)
    if not cvs:
        return
    cw, ch = 405, 720
    items = []
    for idx, wm in enumerate(_ensure_multi_watermarks_v31(self)):
        try:
            x = cw * float(wm.get("x_pct", 82.0)) / 100.0
            y = ch * float(wm.get("y_pct", 93.0)) / 100.0
            text = str(wm.get("text", "WM") or "WM")
            label = f"WM{idx+1}  {text[:18]}"
            color_label = _value_to_label_v21(str(wm.get("color", "white")), TEXT_STYLE_COLOR_OPTIONS_V23)
            color = self._v24_hex(color_label)
            iid = cvs.create_text(x, y, text=label, fill=color, font=("Microsoft YaHei UI", max(9, int(wm.get("font_size", 24)//2)), "bold"))
            name = f"mwm:{idx}"
            items.append((name, iid))
            for hid in _draw_cross_handle_v25(cvs, x, y, f"WM{idx+1}", "#FF8A00"):
                items.append((name, hid))
        except Exception:
            continue
    if not hasattr(self, "_beauty_items_v24") or not isinstance(self._beauty_items_v24, dict):
        self._beauty_items_v24 = {}
    for name, iid in items:
        self._beauty_items_v24[iid] = name
        cvs.addtag_withtag("drag", iid)
    try:
        cvs.configure(cursor="crosshair")
    except Exception:
        pass


def _beauty_canvas_press_v31(self, event):
    cvs = self._beauty_canvas_v24
    hits = cvs.find_overlapping(event.x-12, event.y-12, event.x+12, event.y+12)
    chosen = None
    for iid in reversed(hits):
        if getattr(self, "_beauty_items_v24", {}).get(iid):
            chosen = iid
            break
    if chosen is None:
        hit = cvs.find_closest(event.x, event.y)
        chosen = hit[0] if hit else None
    self._beauty_drag_item_v24 = chosen
    name = getattr(self, "_beauty_items_v24", {}).get(chosen)
    if name in ("en", "zh"):
        try: self.v24_use_visual_positions.set(True)
        except Exception: pass


def _beauty_canvas_drag_v31(self, event):
    iid = getattr(self, "_beauty_drag_item_v24", None)
    if not iid:
        return
    name = getattr(self, "_beauty_items_v24", {}).get(iid)
    if not name:
        return
    cw, ch = 405, 720
    x_pct = max(0.0, min(100.0, event.x * 100.0 / cw))
    y_pct = max(0.0, min(100.0, event.y * 100.0 / ch))
    if isinstance(name, str) and name.startswith("mwm:"):
        try:
            idx = int(name.split(":", 1)[1])
            wms = _ensure_multi_watermarks_v31(self)
            if 0 <= idx < len(wms):
                wms[idx]["x_pct"] = x_pct
                wms[idx]["y_pct"] = y_pct
                _refresh_multi_watermark_list_v31(self)
        except Exception:
            pass
    else:
        # Original V25 drag logic for EN/CN/TITLE/single WM/IMG.
        if name == "en":
            self.v24_en_x_pct.set(x_pct); self.v24_en_y_pct.set(y_pct); self.v24_use_visual_positions.set(True)
        elif name == "zh":
            self.v24_zh_x_pct.set(x_pct); self.v24_zh_y_pct.set(y_pct); self.v24_use_visual_positions.set(True)
        elif name == "title":
            self.v24_title_x_pct.set(x_pct); self.v24_title_y_pct.set(y_pct)
        elif name == "wm":
            self.v24_wm_x_pct.set(x_pct); self.v24_wm_y_pct.set(y_pct)
        elif name == "img":
            self.v24_img_x_pct.set(x_pct); self.v24_img_y_pct.set(y_pct)
    # Throttle redraw to reduce dragging lag.
    now = time.time()
    if now - getattr(self, "_v31_last_drag_redraw", 0) > 0.045:
        self._v31_last_drag_redraw = now
        try: self.after_idle(self._beauty_preview_draw_v31)
        except Exception: pass


def _postprocess_video_v31(self, src: Path, dst: Path, options: Dict[str, Any], resolution: str, work: Path) -> Path:
    # Robust copy of V28 with opacity support and explicit log count.
    title_enabled = bool(options.get("title_enabled", False))
    title_text = str(options.get("title_text", "") or "").strip()
    watermark_enabled = bool(options.get("watermark_enabled", False))
    watermark_text = str(options.get("watermark_text", "") or "").strip()
    watermarks = list(options.get("watermarks", []) or [])
    overlay_path = Path(options.get("overlay_image_path", "") or "") if str(options.get("overlay_image_path", "") or "").strip() else None
    if (not title_enabled or not title_text) and (not watermark_enabled or not watermark_text) and not watermarks and not (overlay_path and overlay_path.exists()):
        shutil.copy2(src, dst)
        return dst
    ff = self.ffmpeg.ffmpeg
    w, h = parse_resolution(resolution)
    cmd = [ff, "-y", "-hide_banner", "-loglevel", "warning", "-i", str(src)]
    filters = []
    cur = "[0:v]"
    vid_idx = 0
    fontfile = _v25_drawtext_fontfile()
    def next_label():
        nonlocal vid_idx
        vid_idx += 1
        return f"[v{vid_idx}]"
    def color_hex(name):
        return FF_COLOR_HEX_V21.get(str(name or "white"), "#FFFFFF")
    def add_drawtext(text_value, font_size, color_name, x_pct, y_pct, alpha=0.65, prefix="wm"):
        nonlocal cur
        if not str(text_value or "").strip():
            return
        idx2 = len(filters) + 1
        txt_file = work / f"_{prefix}_text_v31_{idx2}.txt"
        txt_file.write_text(str(text_value), "utf-8")
        txt_path = _ffmpeg_escape_path_v21(txt_file)
        fs = int(font_size or 24)
        x = max(0, min(w-10, int(w * float(x_pct) / 100.0)))
        y = max(0, min(h-10, int(h * float(y_pct) / 100.0)))
        a = max(0.05, min(1.0, float(alpha or 0.65)))
        out = next_label()
        filters.append(
            f"{cur}drawtext={fontfile}textfile='{txt_path}':reload=1:"
            f"fontcolor={color_hex(color_name)}@{a}:fontsize={fs}:"
            f"x={x}-text_w/2:y={y}-text_h/2:"
            f"shadowcolor=black@0.55:shadowx=2:shadowy=2{out}"
        )
        cur = out
    if title_enabled and title_text:
        title_file = work / "_title_text_v31.txt"
        title_file.write_text(title_text, "utf-8")
        title_path = _ffmpeg_escape_path_v21(title_file)
        fs = int(options.get("title_font_size", 28))
        x = max(0, min(w-10, int(w * float(options.get("title_x_pct", 50.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("title_y_pct", 4.0)) / 100.0)))
        bar_h = max(56, int(fs * 2.2))
        out = next_label()
        filters.append(
            f"{cur}drawbox=x=0:y=0:w=iw:h={bar_h}:color=black@0.40:t=fill,"
            f"drawtext={fontfile}textfile='{title_path}':reload=1:"
            f"fontcolor={color_hex(options.get('title_color','white'))}:fontsize={fs}:"
            f"x={x}-text_w/2:y={y}:shadowcolor=black@0.45:shadowx=1:shadowy=1{out}"
        )
        cur = out
    if watermark_enabled and watermark_text:
        add_drawtext(watermark_text, int(options.get("watermark_font_size", 24)), options.get("watermark_color", "white"), float(options.get("watermark_x_pct", 82.0)), float(options.get("watermark_y_pct", 93.0)), 0.65, "single_wm")
    for wm in watermarks:
        try:
            add_drawtext(
                str(wm.get("text", "") or ""),
                int(wm.get("font_size", 24) or 24),
                str(wm.get("color", "white") or "white"),
                float(wm.get("x_pct", 82.0) or 82.0),
                float(wm.get("y_pct", 93.0) or 93.0),
                float(wm.get("opacity", 0.65) or 0.65),
                "multi_wm",
            )
        except Exception:
            continue
    if overlay_path and overlay_path.exists():
        cmd += ["-i", str(overlay_path)]
        scale_percent = max(5, min(100, int(options.get("overlay_scale_percent", 28) or 28)))
        target_w = max(48, int(w * scale_percent / 100.0))
        filters.append(f"[1:v]scale={target_w}:-1[ovr1]")
        x = max(0, min(w-10, int(w * float(options.get("overlay_x_pct", 82.0)) / 100.0)))
        y = max(0, min(h-10, int(h * float(options.get("overlay_y_pct", 82.0)) / 100.0)))
        out = next_label()
        filters.append(f"{cur}[ovr1]overlay={x}-w/2:{y}-h/2:format=auto{out}")
        cur = out
    if not filters:
        shutil.copy2(src, dst)
        return dst
    cmd += [
        "-filter_complex", ";".join(filters),
        "-map", cur, "-map", "0:a?",
        "-c:v", "libx264", "-crf", "22", "-preset", "veryfast", "-pix_fmt", "yuv420p",
        "-c:a", "aac", "-b:a", "160k", "-ar", "48000", "-ac", "2",
        "-movflags", "+faststart", str(dst)
    ]
    r = self.ffmpeg.run(cmd, f"V31视频美化/多水印生效检查 count={len(watermarks)}", 1200)
    if r.returncode != 0 or not dst.exists() or dst.stat().st_size < 2048:
        self.log("V31视频美化/多水印处理失败，降级使用未美化版本。", "warn")
        shutil.copy2(src, dst)
    return dst


def _main_init_v31(self):
    _old_main_init_v31(self)
    try:
        self.log("【V31新功能上线】多水印自由设置已启用：文字/字号/颜色/透明度/X/Y百分比；听写模式标签页已上线。", "ok")
        self.log("【V31提示】多水印需点击【多水印管理】添加；最终渲染日志会显示 count=水印数量。", "info")
    except Exception:
        pass


