def _tk_safe_config_v32(widget, **kw):
    try:
        widget.configure(**kw)
    except Exception:
        pass


def _frame_card_v32(parent, bg="#111827", padx=10, pady=10):
    f = tk.Frame(parent, bg=bg, bd=0, highlightthickness=1, highlightbackground="#263244")
    f.pack_propagate(True)
    return f


def _dictation_status_text_v32(m):
    st = m.get("status", "pending")
    mark = "✓" if st == "correct" else "✗" if st == "wrong" else "·"
    return mark


def _speed_float_v32(value: str) -> float:
    m = re.search(r"([0-9.]+)", str(value or "1.0"))
    try:
        return max(0.2, min(2.0, float(m.group(1)))) if m else 1.0
    except Exception:
        return 1.0


def _build_ui_v32(self):
    _old_build_ui_v32(self)
    try:
        # Add a dedicated resource platform tab before log. It is independent from the dictation control panel.
        self.tab_resource_platform_v32 = ttk.Frame(self.nb)
        log_index = None
        for i in range(self.nb.index("end")):
            if "日志" in self.nb.tab(i, "text"):
                log_index = i
                break
        if log_index is None:
            self.nb.add(self.tab_resource_platform_v32, text="  我的资源站  ")
        else:
            self.nb.insert(log_index, self.tab_resource_platform_v32, text="  我的资源站  ")
        self._build_resource_platform_v32()
        self.log("【V32新功能上线】听写模式重构：素材池可折叠/可拉伸、组合快捷键、资源站独立标签页、多发音引擎、纯文本翻译接入。", "ok")
    except Exception as e:
        try: self.log(f"V32资源站标签页加载失败：{e}", "warn")
        except Exception: pass


