    ttk.Button(f, text="浏览", command=self._resource_browse_path_v32).pack(side="left", padx=4)
    btns=ttk.Frame(left); btns.pack(fill="x", pady=8)
    ttk.Button(btns, text="添加资源", style="Accent.TButton", command=self._resource_add_v32).pack(side="left", padx=3)
    ttk.Button(btns, text="删除选中", command=self._resource_delete_v32).pack(side="left", padx=3)
