# ──────────────────────────────────────────────────────────────────────
# V35 dictation/resource fixes
# 1) Translation queue/cache to avoid UI freezing.
# 2) Original-clip audio engine uses local linked media first.
# 3) Dictation material sentences support copy / right-click menu.
# 4) Resource platform scanner classifies show/season/episode/media/subtitle status.
# ──────────────────────────────────────────────────────────────────────
import queue as _queue_v35
import hashlib as _hashlib_v35

MEDIA_EXTS_V35 = {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v", ".mp3", ".wav", ".flac", ".m4a", ".aac", ".ogg"}
SUB_EXTS_V35 = {".srt", ".ass", ".ssa", ".vtt", ".txt"}

def _v35_safe_after(self, delay, fn, *args):
    try:
        self.after(delay, lambda: fn(*args))
    except Exception:
        try:
            fn(*args)
        except Exception:
            pass

def _v35_get_dict_items(self):
    for name in ("dict_items_v33", "dict_items_v32", "dict_items", "dictation_items"):
        if hasattr(self, name):
            v = getattr(self, name)
            if isinstance(v, list):
                return v
    self.dict_items_v33 = []
    return self.dict_items_v33

def _v35_get_dict_index(self):
    for name in ("dict_index_v33", "dict_index_v32", "dict_index", "dictation_index"):
        if hasattr(self, name):
            try:
                return int(getattr(self, name))
            except Exception:
                pass
    return 0

def _v35_set_dict_index(self, idx):
    for name in ("dict_index_v33", "dict_index_v32", "dict_index", "dictation_index"):
        if hasattr(self, name):
            try:
                setattr(self, name, idx)
            except Exception:
                pass
    self.dict_index_v33 = idx

def _v35_current_item(self):
    items = _v35_get_dict_items(self)
    idx = _v35_get_dict_index(self)
    if 0 <= idx < len(items):
        return items[idx]
    return None

def _v35_item_text(item):
    if isinstance(item, dict):
        return str(item.get("text") or item.get("en") or item.get("line") or item.get("sentence") or "")
    try:
        return str(getattr(item, "text", "") or item)
    except Exception:
        return str(item or "")

def _v35_item_zh(item):
    if isinstance(item, dict):
        return str(item.get("zh") or item.get("cn") or item.get("translation") or "")
    try:
        return str(getattr(item, "zh", "") or "")
    except Exception:
        return ""

def _v35_set_item_zh(item, zh):
    if isinstance(item, dict):
        item["zh"] = zh
        item["translation"] = zh
    else:
        try:
            setattr(item, "zh", zh)
        except Exception:
            pass

def _v35_item_local_media(item):
    if isinstance(item, dict):
        for k in ("local_path", "media_path", "audio_path", "video_path", "path", "file"):
            p = item.get(k)
            if p and Path(str(p)).exists():
                return Path(str(p))
        clip = item.get("clip")
        if clip is not None:
            for k in ("local_path", "media_path", "audio_path", "video_path"):
                p = getattr(clip, k, None)
                if p and Path(str(p)).exists():
                    return Path(str(p))
    else:
        for k in ("local_path", "media_path", "audio_path", "video_path", "path"):
            p = getattr(item, k, None)
            if p and Path(str(p)).exists():
                return Path(str(p))
    return None

def _v35_update_cn_display(self, item=None):
    item = item if item is not None else _v35_current_item(self)
    zh = _v35_item_zh(item)
    if not zh:
        return
    # Different V30+ versions use different variables.
    for var_name in ("dict_cn_prompt_var_v33", "dict_cn_var", "dict_zh_var", "dictation_cn_var"):
        if hasattr(self, var_name):
            try:
                getattr(self, var_name).set(zh)
            except Exception:
                pass
    # Fallback: known label area stringvar might be absent.
    try:
        if hasattr(self, "dict_hint_var_v33"):
            self.dict_hint_var_v33.set("中文释义：" + zh)
    except Exception:
        pass

def _v35_translation_engine(self):
    # Prefer dictation-specific engine, then render engine, then smart.
    for name in ("dict_translate_engine_var_v35", "dict_translate_engine_var_v34", "dict_translate_engine_var_v32"):
        if hasattr(self, name):
            try:
                return str(getattr(self, name).get() or "smart")
            except Exception:
                pass
    return "smart"

def _v35_log(self, msg, level="info"):
    try:
        self.log(msg, level)
    except Exception:
        print(msg)

def _v35_init_translation_queue(self):
    if getattr(self, "_dict_translate_queue_ready_v35", False):
        return
    self._dict_translate_queue_ready_v35 = True
    self._dict_translate_queue_v35 = _queue_v35.Queue()
    self._dict_translate_cache_v35 = getattr(self, "_dict_translate_cache_v35", {})
    self._dict_translate_busy_v35 = False

    def worker():
        while True:
            payload = self._dict_translate_queue_v35.get()
            if payload is None:
                break
            idx, item, text, engine = payload
            key = (engine, text)
            try:
                if key in self._dict_translate_cache_v35:
                    zh = self._dict_translate_cache_v35[key]
                else:
                    zh = ""
                    try:
                        zh = self.translator.translate_one(text, engine)
                    except Exception as e:
                        _v35_log(self, f"听写后台翻译失败：{type(e).__name__}: {e}", "warn")
                    zh = zh or ""
                    self._dict_translate_cache_v35[key] = zh
                def apply():
                    # Make sure item still exists; allow stale update but never freeze UI.
                    if zh:
                        _v35_set_item_zh(item, zh)
                        cur = _v35_current_item(self)
                        if cur is item or _v35_item_text(cur) == text:
                            _v35_update_cn_display(self, item)
                    try:
                        if hasattr(self, "dict_translate_status_var_v35"):
                            self.dict_translate_status_var_v35.set(f"已翻译：{text[:28]} -> {zh[:28]}")
                    except Exception:
                        pass
                _v35_safe_after(self, 0, apply)
            finally:
                self._dict_translate_queue_v35.task_done()

    import threading
    threading.Thread(target=worker, daemon=True).start()

def _v35_enqueue_translate_current(self, force=False):
    _v35_init_translation_queue(self)
    item = _v35_current_item(self)
    if not item:
        return
    text = _v35_item_text(item)
    if not text:
        return
    if _v35_item_zh(item) and not force:
        _v35_update_cn_display(self, item)
        return
    engine = _v35_translation_engine(self)
    if engine in ("none", "manual", "不翻译"):
        engine = "smart"
    # non-blocking: queue only
    try:
        if hasattr(self, "dict_translate_status_var_v35"):
            self.dict_translate_status_var_v35.set("后台翻译中：" + text[:45])
    except Exception:
        pass
    self._dict_translate_queue_v35.put((_v35_get_dict_index(self), item, text, engine))

def _v35_enqueue_translate_all(self, limit=200):
    _v35_init_translation_queue(self)
    engine = _v35_translation_engine(self)
    if engine in ("none", "manual", "不翻译"):
        engine = "smart"
    count = 0
    for idx, item in enumerate(_v35_get_dict_items(self)):
        text = _v35_item_text(item)
        if text and not _v35_item_zh(item):
            self._dict_translate_queue_v35.put((idx, item, text, engine))
            count += 1
            if count >= limit:
                break
    _v35_log(self, f"听写后台翻译已入队：{count} 条；UI不会卡顿。", "info")

def _v35_patch_refresh_current(self):
    # Wrap existing refresh functions if present.
    for name in ("_dict_refresh_current_v33", "_dict_refresh_current_v32", "_dict_refresh_current"):
        fn = globals().get(name)
        if callable(fn) and not getattr(fn, "_v35_wrapped", False):
            def make_wrap(old):
                def wrapped(app_self, *a, **kw):
                    r = old(app_self, *a, **kw)
                    try:
                        _v35_enqueue_translate_current(app_self, force=False)
                    except Exception:
                        pass
                    return r
                wrapped._v35_wrapped = True
                return wrapped
            globals()[name] = make_wrap(fn)

def _v35_copy_current_sentence(self):
    item = _v35_current_item(self)
    text = _v35_item_text(item)
    zh = _v35_item_zh(item)
    content = text if not zh else text + "\n" + zh
    if content.strip():
        try:
            self.clipboard_clear()
            self.clipboard_append(content)
            self.update()
        except Exception:
            pass
        _v35_log(self, "已复制听写句子。", "ok")

def _v35_copy_selected_sentence(self):
    try:
        lb = getattr(self, "dict_mango_pool_list", None)
        if lb is not None:
            sel = lb.curselection()
            if sel:
                _v35_set_dict_index(self, int(sel[0]))
    except Exception:
        pass
    _v35_copy_current_sentence(self)

def _v35_show_pool_context_menu(self, event):
    menu = tk.Menu(self, tearoff=0)
    menu.add_command(label="复制当前句子", command=lambda: _v35_copy_selected_sentence(self))
    menu.add_command(label="复制英文", command=lambda: _v35_copy_current_en(self))
    menu.add_command(label="复制中文", command=lambda: _v35_copy_current_zh(self))
    try:
        menu.tk_popup(event.x_root, event.y_root)
    finally:
        menu.grab_release()

def _v35_copy_current_en(self):
    item = _v35_current_item(self)
    text = _v35_item_text(item)
    if text:
        self.clipboard_clear(); self.clipboard_append(text); self.update()

def _v35_copy_current_zh(self):
    item = _v35_current_item(self)
    zh = _v35_item_zh(item)
    if zh:
        self.clipboard_clear(); self.clipboard_append(zh); self.update()

def _v35_no_window_kwargs():
    if os.name != "nt":
        return {}
    si = subprocess.STARTUPINFO()
    si.dwFlags |= subprocess.STARTF_USESHOWWINDOW
    return {
        "creationflags": getattr(subprocess, "CREATE_NO_WINDOW", 0),
        "startupinfo": si,
    }

def _v35_play_original_media(self):
    item = _v35_current_item(self)
    media = _v35_item_local_media(item)
    if not media:
        _v35_log(self, "原片引擎：当前听写素材没有关联本地视频/音频，改用TTS。", "warn")
        return False
    try:
        # Prefer internal Qt player if app has it.
        if hasattr(self, "player_client") and self.player_client:
            try:
                self.player_client.play(str(media))
                return True
            except Exception:
                pass
        if os.name == "nt":
            os.startfile(str(media))
        else:
            subprocess.Popen(["xdg-open", str(media)], **_v35_no_window_kwargs())
        _v35_log(self, f"原片引擎已调用本地资源：{media}", "ok")
        return True
    except Exception as e:
        _v35_log(self, f"原片引擎调用失败：{type(e).__name__}: {e}", "warn")
        return False

def _v35_patch_play_current(self):
    # Patch common play functions: if engine is original media, use local resource.
    for name in ("_dict_play_current_v33", "_dict_play_current_v32", "_dict_play_current"):
        fn = globals().get(name)
        if callable(fn) and not getattr(fn, "_v35_wrapped", False):
            def make_wrap(old):
                def wrapped(app_self, *a, **kw):
                    eng = ""
                    for var in ("dict_tts_engine_v33", "dict_tts_engine_v32", "dict_tts_engine_var"):
                        if hasattr(app_self, var):
                            try:
                                eng = str(getattr(app_self, var).get())
                            except Exception:
                                pass
                    if "原片" in eng or "系统播放器" in eng:
                        if _v35_play_original_media(app_self):
                            return
                    return old(app_self, *a, **kw)
                wrapped._v35_wrapped = True
                return wrapped
            globals()[name] = make_wrap(fn)

def _v35_scan_resource_dir(root: Path):
    root = Path(root)
    rows = []
    if not root.exists():
        return rows
    # group subtitles by stem and nearby language hint
    all_files = [p for p in root.rglob("*") if p.is_file()]
    subtitles = [p for p in all_files if p.suffix.lower() in SUB_EXTS_V35]
    sub_by_stem = {}
    for s in subtitles:
        stem = s.stem.lower()
        sub_by_stem.setdefault(stem, []).append(s)
        # remove language suffix like .en/.zh in stem
        stem2 = re.sub(r"[\._-](en|eng|english|zh|chi|chs|cht|cn|中文|英文)$", "", stem, flags=re.I)
        sub_by_stem.setdefault(stem2, []).append(s)
    media_files = [p for p in all_files if p.suffix.lower() in MEDIA_EXTS_V35]
    for p in media_files:
        rel_parts = p.relative_to(root).parts
        show = rel_parts[0] if len(rel_parts) > 1 else root.name
        full = str(p)
        season = ""
        episode = ""
        m = re.search(r"(?:S|Season[\s._-]*)(\d{1,2})", full, re.I)
        if m:
            season = f"S{int(m.group(1)):02d}"
        m = re.search(r"(?:E|EP|Episode[\s._-]*)(\d{1,3})", full, re.I)
        if m:
            episode = f"E{int(m.group(1)):02d}"
        if not season:
            # common Chinese season dirs
            for part in rel_parts:
                m = re.search(r"第\s*(\d+)\s*季", part)
                if m:
                    season = f"S{int(m.group(1)):02d}"
        if not episode:
            m = re.search(r"第\s*(\d+)\s*[集话]", p.stem)
            if m:
                episode = f"E{int(m.group(1)):02d}"
        media_type = "视频" if p.suffix.lower() in {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"} else "音频"
        candidates = sub_by_stem.get(p.stem.lower(), [])
        stem2 = re.sub(r"[\._-](en|eng|english|zh|chi|chs|cht|cn|中文|英文)$", "", p.stem.lower(), flags=re.I)
        candidates += sub_by_stem.get(stem2, [])
        sub_names = " ".join(s.name.lower() for s in candidates)
        has_en = bool(re.search(r"(\.en\.|_en\.|-en\.|eng|english|英文)", sub_names)) or bool(candidates)
        has_zh = bool(re.search(r"(\.zh\.|_zh\.|-zh\.|chs|cht|chi|cn|中文|简体|繁体)", sub_names))
        sub_status = "双字幕" if has_en and has_zh else ("英文字幕" if has_en else ("中文字幕" if has_zh else "缺字幕"))
        rows.append({
            "show": show,
            "season": season or "未知季",
            "episode": episode or "未知集",
            "type": media_type,
            "subtitle": sub_status,
            "path": str(p),
            "name": p.name,
        })
    return rows

def _v35_resource_scan_dialog(self):
    d = filedialog.askdirectory(title="选择本地资源站目录")
    if not d:
        return
    rows = _v35_scan_resource_dir(Path(d))
    self.resource_items_v35 = rows
    _v35_render_resource_platform(self)
    _v35_log(self, f"我的资源站扫描完成：{len(rows)} 个媒体文件。", "ok")

def _v35_render_resource_platform(self):
    # If resource tab exists, rebuild with detailed table; otherwise do nothing.
    tab = getattr(self, "tab_resource", None) or getattr(self, "tab_resources", None) or getattr(self, "tab_resource_platform", None)
    if tab is None:
        return
    try:
        for ch in tab.winfo_children():
            ch.destroy()
    except Exception:
        pass
    top = ttk.Frame(tab, padding=12)
    top.pack(fill="x")
    ttk.Label(top, text="我的资源站 · 本地/在线资源管理", style="H.TLabel").pack(side="left")
    ttk.Button(top, text="扫描本地目录", command=lambda: _v35_resource_scan_dialog(self)).pack(side="right", padx=4)
    ttk.Button(top, text="同步选中到听写", command=lambda: _v35_sync_selected_resources_to_dictation(self)).pack(side="right", padx=4)

    cols = ("show", "season", "episode", "type", "subtitle", "name", "path")
    tree = ttk.Treeview(tab, columns=cols, show="headings", height=18)
    headings = {
        "show": "剧名/资源组", "season": "季", "episode": "集", "type": "类型",
        "subtitle": "字幕状态", "name": "文件名", "path": "路径"
    }
    widths = {"show": 160, "season": 70, "episode": 70, "type": 60, "subtitle": 100, "name": 260, "path": 460}
    for c in cols:
        tree.heading(c, text=headings[c])
        tree.column(c, width=widths[c], anchor="w")
    tree.pack(fill="both", expand=True, padx=12, pady=8)
    self.resource_tree_v35 = tree
    for i, row in enumerate(getattr(self, "resource_items_v35", [])):
        tree.insert("", "end", iid=str(i), values=[row.get(c, "") for c in cols])

def _v35_sync_selected_resources_to_dictation(self):
    rows = getattr(self, "resource_items_v35", [])
    sel = []
    try:
        for iid in self.resource_tree_v35.selection():
            idx = int(iid)
            if 0 <= idx < len(rows):
                sel.append(rows[idx])
    except Exception:
        pass
    if not sel:
        sel = rows[:50]
    items = []
    for r in sel:
        p = r.get("path", "")
        label = " / ".join([r.get("show",""), r.get("season",""), r.get("episode",""), r.get("name","")])
        items.append({
            "text": label,
            "zh": "",
            "local_path": p,
            "media_path": p,
            "resource_meta": r,
        })
    if items:
        self.dict_items_v33 = items
        self.dict_index_v33 = 0
        try:
            _dict_refresh_pool_v33(self)
            _dict_refresh_current_v33(self)
        except Exception:
            pass
        _v35_log(self, f"已同步资源站资源到听写素材池：{len(items)} 条。", "ok")

def _v35_bind_copy_pool(self):
    for lb_name in ("dict_mango_pool_list", "dict_pool_list", "dict_listbox"):
        if hasattr(self, lb_name):
            lb = getattr(self, lb_name)
            try:
                lb.bind("<Control-c>", lambda e: (_v35_copy_selected_sentence(self), "break"))
                lb.bind("<Button-3>", lambda e: _v35_show_pool_context_menu(self, e))
            except Exception:
                pass
    try:
        self.bind_all("<Control-c>", lambda e: None if str(self.focus_get()).lower().endswith("entry") else (_v35_copy_selected_sentence(self), "break"))
    except Exception:
        pass

def _v35_add_translation_controls(self):
    # Try to add a small status var if missing; this does not disturb layout.
    if not hasattr(self, "dict_translate_status_var_v35"):
        self.dict_translate_status_var_v35 = tk.StringVar(value="翻译：后台自动")
    # If a control panel exists, add compact controls once.
    if getattr(self, "_dict_translation_controls_added_v35", False):
        return
    parent = getattr(self, "dict_mango_control_panel", None)
    if parent is None:
        return
    try:
        box = ttk.LabelFrame(parent, text="翻译加速/后台队列", padding=8)
        box.pack(fill="x", padx=12, pady=8)
        self.dict_translate_engine_var_v35 = tk.StringVar(value="smart")
        ttk.Combobox(box, textvariable=self.dict_translate_engine_var_v35,
                     values=["smart", "opus", "argos", "tencent", "baidu", "deepl", "google", "manual"],
                     state="readonly", width=18).pack(fill="x", pady=2)
        ttk.Button(box, text="后台翻译当前", command=lambda: _v35_enqueue_translate_current(self, force=True)).pack(fill="x", pady=2)
        ttk.Button(box, text="后台翻译全部", command=lambda: _v35_enqueue_translate_all(self)).pack(fill="x", pady=2)
        ttk.Label(box, textvariable=self.dict_translate_status_var_v35, style="Dim.TLabel", wraplength=260).pack(fill="x", pady=2)
        self._dict_translation_controls_added_v35 = True
    except Exception:
        pass

_old_main_init_v35 = MainApp.__init__
def _main_init_v35(self):
    _old_main_init_v35(self)
    try:
        _v35_patch_refresh_current(self)
        _v35_patch_play_current(self)
        _v35_init_translation_queue(self)
        _v35_bind_copy_pool(self)
        _v35_add_translation_controls(self)
        _v35_render_resource_platform(self)
        self.log("【V35新功能上线】听写翻译改为后台队列+缓存，避免卡顿；原片发音优先调用本地资源；素材句子支持右键/Ctrl+C复制。", "ok")
        self.log("【V35资源站】本地目录扫描已支持剧名/季/集/视频音频/字幕状态/中英双字幕缺失识别。", "ok")
    except Exception as e:
        try:
            self.log(f"V35补丁初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v35
APP_TITLE = "PlayPhrase Studio Clean v35 · 听写翻译加速+资源站细分版"


