def _ensure_beauty_vars_v36(self):
    try:
        if callable(globals().get('_ensure_visual_vars_v25')):
            _ensure_visual_vars_v25(self)
        elif callable(globals().get('_ensure_visual_vars_v24')):
            _ensure_visual_vars_v24(self)
    except Exception:
        pass
    if not hasattr(self, 'render_vars') or self.render_vars is None:
        self.render_vars = {}
    def combo_var(key, options, default_idx=0):
        if key not in self.render_vars or self.render_vars.get(key) is None:
            self.render_vars[key] = tk.StringVar(value=options[default_idx][0])
        return self.render_vars[key]
    try: combo_var('beauty_mode', BEAUTY_MODE_OPTIONS_V21, 0)
    except Exception: pass
    try: combo_var('title_preset', TITLE_PRESET_OPTIONS_V21, 0)
    except Exception: pass
    try: combo_var('title_color', TEXT_STYLE_COLOR_OPTIONS_V23, 0)
    except Exception: pass
    try: combo_var('watermark_color', TEXT_STYLE_COLOR_OPTIONS_V23, 0)
    except Exception: pass
    try: combo_var('overlay_position', OVERLAY_POSITION_OPTIONS_V21, 0)
    except Exception: pass
    try: combo_var('en_cover', COLOR_OPTIONS, 2)
    except Exception: pass
    try: combo_var('zh_cover', COLOR_OPTIONS, 5 if len(COLOR_OPTIONS)>5 else 2)
    except Exception: pass
    # Basic Boolean/Text/Size vars
    for name, ctor, val in [
        ('v24_use_visual_positions', tk.BooleanVar, False),
        ('title_enable_var', tk.BooleanVar, False),
        ('watermark_enable_var', tk.BooleanVar, False),
        ('title_text_var', tk.StringVar, ''),
        ('watermark_text_var', tk.StringVar, ''),
        ('overlay_image_var', tk.StringVar, ''),
        ('title_font_size_var', tk.IntVar, 28),
        ('watermark_font_size_var', tk.IntVar, 24),
        ('overlay_scale_var', tk.IntVar, 28),
        ('v24_en_x_pct', tk.DoubleVar, 50.0), ('v24_en_y_pct', tk.DoubleVar, 20.0),
        ('v24_zh_x_pct', tk.DoubleVar, 50.0), ('v24_zh_y_pct', tk.DoubleVar, 86.0),
        ('v24_title_x_pct', tk.DoubleVar, 50.0), ('v24_title_y_pct', tk.DoubleVar, 5.0),
        ('v24_wm_x_pct', tk.DoubleVar, 82.0), ('v24_wm_y_pct', tk.DoubleVar, 93.0),
        ('v24_img_x_pct', tk.DoubleVar, 82.0), ('v24_img_y_pct', tk.DoubleVar, 82.0),
    ]:
        if not hasattr(self, name):
            try: setattr(self, name, ctor(value=val))
            except TypeError: setattr(self, name, ctor())
    try:
        if not hasattr(self, 'multi_watermarks_v28') or self.multi_watermarks_v28 is None:
            self.multi_watermarks_v28=[]
    except Exception:
        self.multi_watermarks_v28=[]


def _v36_combo_value(label, options, default=None):
    for k,v in options:
        if label == k or label == v:
            return v
    return default if default is not None else (options[0][1] if options else label)


def _v36_label_for_value(value, options):
    for k,v in options:
        if value == v or value == k:
            return k
    return options[0][0] if options else str(value)


def _v36_color_hex(self, raw):
    try:
        val=str(raw or 'white')
        for opts in (globals().get('TEXT_STYLE_COLOR_OPTIONS_V23', []), globals().get('COLOR_OPTIONS', [])):
            for label, key in opts:
                if val == label:
                    val=key; break
        return globals().get('FF_COLOR_HEX_V21', {}).get(val, '#FFFFFF')
    except Exception:
        return '#FFFFFF'


