def _beauty_preview_draw_v36(self):
    cvs=getattr(self,'_beauty_canvas_v36',None)
    if not cvs: return
    try:
        cw=int(cvs.winfo_width() or 480); ch=int(cvs.winfo_height() or 760)
    except Exception:
        cw,ch=480,760
    cvs.delete('all')
    mode='none'
    try: mode=_v36_combo_value(self.render_vars.get('beauty_mode').get(),BEAUTY_MODE_OPTIONS_V21,'none')
    except Exception: pass
    if mode=='blur_bg':
        cvs.create_rectangle(0,0,cw,ch,fill='#2a2a2a',outline='')
        for i in range(16): cvs.create_oval(-60+i*38,60+i*40,180+i*38,260+i*40,fill='#333843',outline='')
        cvs.create_text(cw/2,ch/2,text='模糊背景填充',fill='#6b7280',font=('Microsoft YaHei UI',22,'bold'))
    elif mode=='gradient_bg':
        for y in range(0,ch,6):
            r=int(15+55*y/ch); b=int(45+75*y/ch); cvs.create_rectangle(0,y,cw,y+6,fill=f'#{r:02x}163{min(160,b):02x}',outline='')
    elif mode=='ai_expand':
        cvs.create_rectangle(0,0,cw,ch,fill='#161a22',outline='')
        cvs.create_text(cw/2,ch/2,text='AI智能扩图实验预览',fill='#778195',font=('Microsoft YaHei UI',20,'bold'))
    else:
        cvs.create_rectangle(0,0,cw,ch,fill='#111111',outline='')
    # video rectangle
    vx1,vy1,vx2,vy2=42,82,cw-42,ch-82
    cvs.create_rectangle(vx1,vy1,vx2,vy2,fill='#232323',outline='#666')
    cvs.create_text(cw/2,(vy1+vy2)/2,text='当前视频画面预览区',fill='#8b8b8b',font=('Microsoft YaHei UI',18,'bold'))
    # summary
    try:
        summary=[]
        for k in ('resolution','fit_mode','subtitle_position','subtitle_arrangement'):
            if k in self.render_vars: summary.append(self.render_vars[k].get())
        self._beauty_summary_v36.set('\n'.join(summary) or '基础渲染参数未读取')
    except Exception: pass
    # preview text fallback
    en='EN  English subtitle preview'
    zh='CN  中文字幕预览'
    try:
        if self.pool:
            en='EN  '+(self.pool[0].text[:45] if getattr(self.pool[0],'text','') else 'English subtitle preview')
            zh='CN  '+(getattr(self.pool[0],'zh','')[:28] or '中文字幕预览')
    except Exception: pass
    self._beauty_item_tags_v36={}
    def cross(tag,xpct,ypct,label,color,font_size=15):
        x=cw*float(xpct)/100; y=ch*float(ypct)/100
        cvs.create_line(x-12,y,x+12,y,fill=color,width=2,tags=(tag,'drag'))
        cvs.create_line(x,y-12,x,y+12,fill=color,width=2,tags=(tag,'drag'))
        item=cvs.create_text(x,y-18,text=label,fill=color,font=('Microsoft YaHei UI',font_size,'bold'),tags=(tag,'drag'))
        self._beauty_item_tags_v36[item]=tag
        return item
    if bool(self.title_enable_var.get()):
        title=self.title_text_var.get() or _v36_combo_value(self.render_vars.get('title_preset',tk.StringVar(value='')).get(),TITLE_PRESET_OPTIONS_V21,'TITLE') or 'TITLE'
        cross('title',self.v24_title_x_pct.get(),self.v24_title_y_pct.get(),'TITLE  '+title,_v36_color_hex(self,self.render_vars.get('title_color',tk.StringVar(value='白色')).get()),14)
    cross('en',self.v24_en_x_pct.get(),self.v24_en_y_pct.get(),en,_v36_color_hex(self,_v36_combo_value(self.render_vars.get('en_cover',tk.StringVar(value='黄色')).get(),COLOR_OPTIONS,'yellow')),16)
    cross('zh',self.v24_zh_x_pct.get(),self.v24_zh_y_pct.get(),zh,_v36_color_hex(self,_v36_combo_value(self.render_vars.get('zh_cover',tk.StringVar(value='绿色')).get(),COLOR_OPTIONS,'green')),13)
    if bool(self.watermark_enable_var.get()):
        cross('wm',self.v24_wm_x_pct.get(),self.v24_wm_y_pct.get(),'WM  '+(self.watermark_text_var.get() or 'watermark'),_v36_color_hex(self,self.render_vars.get('watermark_color',tk.StringVar(value='白色')).get()),12)
    try:
        for i,wm in enumerate(getattr(self,'multi_watermarks_v28',[]) or [],1):
            cross(f'mwm{i-1}',wm.get('x_pct',82),wm.get('y_pct',93),f'MW{i}  '+str(wm.get('text','WM'))[:18],_v36_color_hex(self,wm.get('color','white')),11)
    except Exception: pass
    if self.overlay_image_var.get():
        cross('img',self.v24_img_x_pct.get(),self.v24_img_y_pct.get(),'IMG  图片遮罩', '#60a5fa',12)
        try: cvs.create_rectangle(cw*self.v24_img_x_pct.get()/100-40,ch*self.v24_img_y_pct.get()/100-28,cw*self.v24_img_x_pct.get()/100+40,ch*self.v24_img_y_pct.get()/100+28,outline='#60a5fa',dash=(4,2))
        except Exception: pass


def _beauty_canvas_press_v36(self,event):
    cvs=getattr(self,'_beauty_canvas_v36',None)
    if not cvs: return
    item=cvs.find_closest(event.x,event.y)
    if not item: return
    tags=cvs.gettags(item[0])
    drag_tags=[t for t in tags if t not in ('drag','current')]
    if drag_tags:
        self._beauty_drag_item_v36=drag_tags[0]


def _beauty_canvas_drag_v36(self,event):
    tag=getattr(self,'_beauty_drag_item_v36',None)
    cvs=getattr(self,'_beauty_canvas_v36',None)
    if not tag or not cvs: return
    cw=max(cvs.winfo_width(),1); ch=max(cvs.winfo_height(),1)
    xp=max(0,min(100,event.x*100/cw)); yp=max(0,min(100,event.y*100/ch))
    try:
        if tag=='en': self.v24_en_x_pct.set(xp); self.v24_en_y_pct.set(yp); self.v24_use_visual_positions.set(True)
        elif tag=='zh': self.v24_zh_x_pct.set(xp); self.v24_zh_y_pct.set(yp); self.v24_use_visual_positions.set(True)
        elif tag=='title': self.v24_title_x_pct.set(xp); self.v24_title_y_pct.set(yp)
        elif tag=='wm': self.v24_wm_x_pct.set(xp); self.v24_wm_y_pct.set(yp)
        elif tag=='img': self.v24_img_x_pct.set(xp); self.v24_img_y_pct.set(yp)
        elif tag.startswith('mwm'):
            idx=int(tag[3:]); self.multi_watermarks_v28[idx]['x_pct']=xp; self.multi_watermarks_v28[idx]['y_pct']=yp
    except Exception: pass
    self._beauty_preview_draw_v36()


def _beauty_canvas_release_v36(self,event):
    self._beauty_drag_item_v36=None
    try: self._beauty_preview_draw_v36()
    except Exception: pass

