DICTATION_BLOCK_POS_OPTIONS_V37 = [
    ("名词", "n."), ("动词", "v."), ("形容词", "adj."), ("副词", "adv."),
    ("介词", "prep."), ("连词", "conj."), ("代词", "pron."), ("冠词", "art."),
    ("专有名词", "proper n."), ("人名", "person"), ("地名", "place"), ("短语", "phrase"),
]

# ---------- V37: robust shortcut rebinding ----------
def _shortcut_to_tk_event_v37(s: str) -> str:
    # Reuse V34 parser if present, then normalize Return/space.
    try:
        seq = _shortcut_to_tk_event_v34(s)
    except Exception:
        seq = ""
    return seq


def _shortcut_variants_v37(shortcut: str):
    seq = _shortcut_to_tk_event_v37(shortcut)
    out = []
    if seq:
        out.append(seq)
        # Letter variants: <Control-r> and <Control-R> are different in some Tk states.
        m = re.match(r"<(.*-)?([a-zA-Z])>$", seq)
        if m:
            prefix = m.group(1) or ""
            key = m.group(2)
            out.append(f"<{prefix}{key.lower()}>")
            out.append(f"<{prefix}{key.upper()}>")
    # remove duplicates, keep order
    seen, final = set(), []
    for x in out:
        if x and x not in seen:
            seen.add(x); final.append(x)
    return final


def _dictation_unbind_old_shortcuts_v37(self):
    # Remove old single-letter bindings from V30 plus every previous custom binding.
    seqs = set(getattr(self, "_dictation_bound_sequences_v37", []))
    seqs.update(getattr(self, "_dictation_bound_sequences_v34", []))
    # V30 old unsafe keys and V32/V34 defaults.
    legacy = [
        "<Key-r>", "<Key-R>", "<Key-s>", "<Key-S>", "<Key-t>", "<Key-T>", "<Key-v>", "<Key-V>", "<Key-c>", "<Key-C>",
        "<Left>", "<Right>", "<F11>", "<Control-Left>", "<Control-Right>", "<Control-r>", "<Control-R>",
        "<Control-H>", "<Control-h>", "<Control-Shift-S>", "<Control-Shift-s>", "<Control-Shift-C>", "<Control-Shift-c>",
        "<Control-space>", "<Return>", "<Control-s>", "<Control-S>", "<Control-d>", "<Control-D>",
    ]
    seqs.update(legacy)
    try:
        data = getattr(self, "dictation_shortcuts_v34", {}) or {}
        for v in data.values():
            seqs.update(_shortcut_variants_v37(v))
    except Exception:
        pass
    for seq in list(seqs):
        try: self.unbind_all(seq)
        except Exception: pass
        try:
            if hasattr(self, "tab_dictation"):
                self.tab_dictation.unbind_all(seq)
        except Exception: pass
    self._dictation_bound_sequences_v37 = []


def _dictation_action_map_v37(self):
    # Use latest available methods, fallback gracefully.
    def get(name, fallback=None):
        return getattr(self, name, fallback if fallback else (lambda: None))
    return {
        "主播放/重复播放": get("_dictation_replay_current_v30"),
        "暂停/继续": get("_dictation_pause_v30"),
        "上一句": get("_dictation_prev_v30"),
        "下一句": get("_dictation_next_v30"),
        "提交答案": get("_dictation_submit_v30"),
        "下一条提示": get("_dictation_next_hint_v30"),
        "长句拆分": get("_dictation_split_current_v30"),
        "显示/隐藏中文": get("_dictation_toggle_cn_v30"),
        "窗口/全屏": get("_dictation_fullscreen_toggle_v30"),
        "保存进度": get("_dictation_save_progress_v30"),
        "加入错题本": get("_dictation_add_wrong_current_v30"),
        "显示答案": lambda: _dictation_show_answer_v37(self),
        "打开分块听写": lambda: _open_segment_dictation_panel_v37(self),
    }


def _dictation_load_shortcuts_v37(self):
    # Merge V34 stored config + V37 additions.
    defaults = dict(DICTATION_DEFAULT_SHORTCUTS_V34) if 'DICTATION_DEFAULT_SHORTCUTS_V34' in globals() else {
        "主播放/重复播放": "Ctrl+R", "暂停/继续": "Ctrl+Space", "上一句": "Ctrl+Left", "下一句": "Ctrl+Right",
        "提交答案": "Enter", "下一条提示": "Ctrl+H", "长句拆分": "Ctrl+Shift+S", "显示/隐藏中文": "Ctrl+Shift+C",
        "窗口/全屏": "F11", "保存进度": "Ctrl+S", "加入错题本": "Ctrl+D",
    }
    defaults.setdefault("显示答案", "Ctrl+J")
    defaults.setdefault("打开分块听写", "Ctrl+Shift+B")
    stored = {}
    try:
        stored = dict(self.cfg.get("dictation_shortcuts_v34", {}) or {})
        stored.update(dict(self.cfg.get("dictation_shortcuts_v37", {}) or {}))
    except Exception:
        stored = {}
    data = dict(defaults)
    for k, v in stored.items():
        try:
            ok, _ = _is_safe_shortcut_v34(v)
        except Exception:
            ok = bool(v)
        if k in data and ok:
            data[k] = v
    self.dictation_shortcuts_v34 = data
    self.dictation_shortcuts_v37 = data
    return data


def _dictation_save_shortcuts_v37(self):
    try:
        data = dict(getattr(self, "dictation_shortcuts_v37", getattr(self, "dictation_shortcuts_v34", {})))
        self.cfg["dictation_shortcuts_v34"] = data
        self.cfg["dictation_shortcuts_v37"] = data
        self._save_config()
    except Exception:
        pass


def _dictation_rebind_shortcuts_v37(self):
    _dictation_unbind_old_shortcuts_v37(self)
    data = _dictation_load_shortcuts_v37(self)
    actions = _dictation_action_map_v37(self)
    bound = []
    for func, shortcut in data.items():
        cmd = actions.get(func)
        if not cmd: continue
        for seq in _shortcut_variants_v37(shortcut):
            def handler(e, c=cmd):
                try:
                    # Do not steal Enter from non-dictation text widgets except dictation submit.
                    c()
                except Exception as ex:
                    try: self.log(f"快捷键执行失败：{type(ex).__name__}: {ex}", "warn")
                    except Exception: pass
                return "break"
            try:
                self.bind_all(seq, handler)
                bound.append(seq)
            except Exception:
                pass
    self._dictation_bound_sequences_v37 = bound
    try: self.log("V37听写快捷键已真实重新绑定：" + ", ".join(bound), "ok")
    except Exception: pass
    return bound


def _dictation_refresh_shortcut_tree_v37(self):
    try:
        _dictation_load_shortcuts_v37(self)
        tree = self.dictation_shortcut_tree_v30
        for iid in tree.get_children(): tree.delete(iid)
        for i, (func, key) in enumerate(self.dictation_shortcuts_v37.items()):
            tree.insert("", "end", iid=str(i), values=(func, key))
    except Exception:
        pass


def _dictation_open_shortcut_editor_v37(self):
    _dictation_load_shortcuts_v37(self)
    win = tk.Toplevel(self)
    win.title("听写快捷键自定义｜V37真实生效版")
    win.geometry("700x560")
    try: win.transient(self); win.grab_set()
    except Exception: pass
    frm = ttk.Frame(win, padding=12); frm.pack(fill="both", expand=True)
    ttk.Label(frm, text="快捷键自定义：保存后立即生效；禁止单独英文字母，避免输入英文时误触。", style="H.TLabel").pack(anchor="w", pady=(0,8))
    tree = ttk.Treeview(frm, columns=("func","key"), show="headings", height=15)
    tree.heading("func", text="功能"); tree.heading("key", text="快捷键")
    tree.column("func", width=310); tree.column("key", width=190)
    tree.pack(fill="both", expand=True)
    for i,(func,key) in enumerate(self.dictation_shortcuts_v37.items()):
        tree.insert("", "end", iid=str(i), values=(func,key))
    row=ttk.Frame(frm); row.pack(fill="x", pady=8)
    ttk.Label(row, text="新快捷键：").pack(side="left")
    key_var=tk.StringVar(value="Ctrl+R")
    ttk.Entry(row, textvariable=key_var, width=26).pack(side="left", padx=6)
    msg=tk.StringVar(value="示例：Ctrl+R / Ctrl+Shift+C / Alt+Right / Enter / F11。不能用单独字母。")
    ttk.Label(frm, textvariable=msg, style="Dim.TLabel", wraplength=650).pack(fill="x")
    def load_sel(_=None):
        sel=tree.selection()
        if sel:
            vals=tree.item(sel[0],"values")
            if vals: key_var.set(vals[1])
    tree.bind("<<TreeviewSelect>>", load_sel)
    def apply_one():
        sel=tree.selection()
        if not sel:
            msg.set("❌ 请先选择一个功能。")
            return
        func=tree.item(sel[0],"values")[0]
        key=key_var.get().strip()
        try:
            ok, why = _is_safe_shortcut_v34(key)
        except Exception:
            ok, why = (bool(key), "")
        if not ok:
            msg.set("❌ " + why); return
        norm_key=key.lower().replace(" ","")
        for f,k in self.dictation_shortcuts_v37.items():
            if f!=func and k.lower().replace(" ","")==norm_key:
                msg.set(f"❌ 与【{f}】冲突。")
                return
        self.dictation_shortcuts_v37[func]=key
        self.dictation_shortcuts_v34=self.dictation_shortcuts_v37
        tree.item(sel[0], values=(func,key))
        msg.set("✅ 已修改。点击【保存并立即生效】完成真实绑定。")
    def restore_default():
        self.dictation_shortcuts_v37 = _dictation_load_shortcuts_v37(self)
        self.dictation_shortcuts_v37.update({
            "主播放/重复播放":"Ctrl+R", "暂停/继续":"Ctrl+Space", "上一句":"Ctrl+Left", "下一句":"Ctrl+Right",
            "提交答案":"Enter", "下一条提示":"Ctrl+H", "长句拆分":"Ctrl+Shift+S", "显示/隐藏中文":"Ctrl+Shift+C",
            "窗口/全屏":"F11", "保存进度":"Ctrl+S", "加入错题本":"Ctrl+D", "显示答案":"Ctrl+J", "打开分块听写":"Ctrl+Shift+B",
        })
        self.dictation_shortcuts_v34=self.dictation_shortcuts_v37
        for iid in tree.get_children(): tree.delete(iid)
        for i,(func,key) in enumerate(self.dictation_shortcuts_v37.items()): tree.insert("","end",iid=str(i),values=(func,key))
        msg.set("已恢复默认，点击保存生效。")
    def save_all():
        _dictation_save_shortcuts_v37(self)
        _dictation_rebind_shortcuts_v37(self)
        _dictation_refresh_shortcut_tree_v37(self)
        win.destroy()
    btns=ttk.Frame(frm); btns.pack(fill="x", pady=10)
    ttk.Button(btns, text="应用到选中功能", command=apply_one).pack(side="left", padx=4)
    ttk.Button(btns, text="恢复默认", command=restore_default).pack(side="left", padx=4)
    ttk.Button(btns, text="保存并立即生效", style="Accent.TButton", command=save_all).pack(side="right", padx=4)


def _dictation_patch_shortcut_panel_v37(self):
    try:
        _dictation_load_shortcuts_v37(self)
        _dictation_refresh_shortcut_tree_v37(self)
        parent = self.dictation_shortcut_tree_v30.master
        if not getattr(self, "_shortcut_panel_v37_added", False):
            btn = ttk.Frame(parent); btn.pack(fill="x", pady=6)
            ttk.Button(btn, text="自定义快捷键", style="Accent.TButton", command=lambda: _dictation_open_shortcut_editor_v37(self)).pack(side="left", padx=3)
            ttk.Button(btn, text="重新绑定并测试", command=lambda: _dictation_rebind_shortcuts_v37(self)).pack(side="left", padx=3)
            ttk.Label(parent, text="V37：保存后会先解除旧快捷键，再真实绑定新快捷键。", style="Dim.TLabel", wraplength=300).pack(fill="x", pady=3)
            self._shortcut_panel_v37_added=True
        _dictation_rebind_shortcuts_v37(self)
    except Exception as e:
        try: self.log(f"V37快捷键面板补丁失败：{e}", "warn")
        except Exception: pass


def _dictation_show_answer_v37(self):
    try:
        m = self._dictation_current_material_v30()
        ans = m.get("text", "") if m else ""
        if hasattr(self, "dictation_result_var_v30"):
            self.dictation_result_var_v30.set("答案：" + ans)
        if hasattr(self, "dictation_input_v30"):
            self.dictation_input_v30.delete("1.0", "end")
            self.dictation_input_v30.insert("end", ans)
    except Exception:
        pass

# ---------- V37 Recite Mode ----------
def _recite_parse_words_v37(path: Path):
    txt = Path(path).read_text("utf-8-sig", errors="ignore")
    words=[]
    for raw in txt.splitlines():
        s=raw.strip()
        if not s: continue
        # pure word document only: accept word, word - cn, word\tcn, word,cn
        parts=re.split(r"\t|,|：|:| - |—|--", s, maxsplit=1)
        word=parts[0].strip()
        cn=parts[1].strip() if len(parts)>1 else ""
        if re.fullmatch(r"[A-Za-z][A-Za-z'\-]*", word):
            words.append({"word":word,"cn":cn,"pos":"","ipa":""})
    return words


def _recite_current_v37(self):
    arr=getattr(self,"recite_words_v37",[])
    idx=getattr(self,"recite_index_v37",0)
    if 0<=idx<len(arr): return arr[idx]
    return None


def _recite_refresh_v37(self):
    item=_recite_current_v37(self)
    total=len(getattr(self,"recite_words_v37",[]))
    idx=getattr(self,"recite_index_v37",0)
    if not item:
        self.recite_word_var_v37.set("导入纯单词文档")
        self.recite_info_var_v37.set("仅支持纯单词列表：word 或 word - 中文")
        self.recite_progress_var_v37.set("0/0")
        return
    word=item.get("word","")
    cn=item.get("cn","")
    self.recite_word_var_v37.set(word)
    self.recite_info_var_v37.set(f"{item.get('pos','')}  {cn}".strip() or "输入正确自动进入下一个；输入错误立即发音。")
    self.recite_progress_var_v37.set(f"{idx+1}/{total}")
    try:
        self.recite_entry_v37.delete(0,"end")
        self.recite_entry_v37.focus_set()
    except Exception: pass


def _recite_speak_v37(self, text):
    try:
        if hasattr(self,"_dictation_speak_text_v32"):
            self._dictation_speak_text_v32(text)
            return
    except Exception: pass
    try:
        _dictation_speak_text_v34(self,text)
    except Exception:
        try: self.bell()
        except Exception: pass


def _recite_submit_v37(self):
    item=_recite_current_v37(self)
    if not item: return
    ans=self.recite_answer_var_v37.get().strip()
    word=item.get("word","")
    if ans.lower()==word.lower():
        self.recite_feedback_var_v37.set("✅ 正确，自动跳转")
        self.recite_index_v37=min(getattr(self,"recite_index_v37",0)+1, len(getattr(self,"recite_words_v37",[]))-1)
        self.after(180, lambda: _recite_refresh_v37(self))
    else:
        self.recite_feedback_var_v37.set(f"❌ 错误：{ans}｜请重听")
        _recite_speak_v37(self, word)


def _recite_play_all_v37(self):
    arr=getattr(self,"recite_words_v37",[])
    def worker():
        for it in arr:
            _recite_speak_v37(self, it.get("word",""))
    threading.Thread(target=worker,daemon=True).start()


def _recite_import_v37(self):
    f=filedialog.askopenfilename(title="导入纯单词文档", filetypes=[("Text","*.txt *.csv"),("All","*.*")])
    if not f: return
    words=_recite_parse_words_v37(Path(f))
    if not words:
        messagebox.showwarning("提示","未识别到纯单词列表。背诵模式仅限制纯单词文档使用。")
        return
    self.recite_words_v37=words
    self.recite_index_v37=0
    _recite_refresh_v37(self)


