# ---------- V37 Segmented Dictation ----------
def _split_blocks_v37(text: str):
    toks=re.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+|[^\sA-Za-z\d]", text or "")
    blocks=[]
    phrase=[]
    for t in toks:
        if re.fullmatch(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+",t):
            phrase.append(t)
            if len(phrase)>=2:
                blocks.append(" ".join(phrase)); phrase=[]
        else:
            if phrase: blocks.append(" ".join(phrase)); phrase=[]
    if phrase: blocks.append(" ".join(phrase))
    return blocks or ([text] if text else [])


def _guess_pos_v37(block: str):
    w=(block or "").split()[0].lower() if block else ""
    if w in {"a","an","the"}: return "冠词"
    if w in {"in","on","at","from","to","with","for","of","by","about","around"}: return "介词"
    if w.endswith("ly"): return "副词"
    if w.endswith("ing") or w.endswith("ed"): return "动词形式"
    if w and w[0].isupper(): return "专有名词"
    if len(block.split())>1: return "短语"
    return "词性提示"


def _open_segment_dictation_panel_v37(self):
    m=None
    try: m=self._dictation_current_material_v30()
    except Exception: pass
    text=(m or {}).get("text","") if isinstance(m,dict) else ""
    zh=(m or {}).get("zh","") if isinstance(m,dict) else ""
    win=tk.Toplevel(self); win.title("分块横线听写｜中文-英文块对应")
    win.geometry("980x620")
    dark="#0f172a"; card="#172033"; fg="#e5e7eb"; muted="#94a3b8"; accent="#8b5cf6"
    root=tk.Frame(win,bg=dark); root.pack(fill="both",expand=True)
    top=tk.Frame(root,bg=dark); top.pack(fill="x",padx=20,pady=16)
    show_cn=tk.BooleanVar(value=True)
    cn_var=tk.StringVar(value=zh or "中文默认显示；可隐藏。")
    tk.Checkbutton(top,text="显示中文",variable=show_cn,bg=dark,fg=fg,selectcolor=card,command=lambda:cn_lbl.configure(text=cn_var.get() if show_cn.get() else "中文已隐藏")).pack(side="left")
    tk.Button(top,text="重新分块",bg=accent,fg="white",bd=0,padx=14,pady=6,command=lambda:draw()).pack(side="right")
    cn_lbl=tk.Label(root,text=cn_var.get(),bg=dark,fg=fg,font=("Microsoft YaHei UI",18,"bold"),wraplength=900,justify="center")
    cn_lbl.pack(pady=(20,30))
    area=tk.Frame(root,bg=dark); area.pack(fill="both",expand=True,padx=30)
    result_var=tk.StringVar(value="每个横线对应一个英文单词/短语块；下方显示词性/短语提示。")
    def draw():
        for ch in area.winfo_children(): ch.destroy()
        blocks=_split_blocks_v37(text)
        entries=[]
        row=None
        for i,b in enumerate(blocks):
            if i%4==0:
                row=tk.Frame(area,bg=dark); row.pack(fill="x",pady=12)
            box=tk.Frame(row,bg=dark); box.pack(side="left",padx=12)
            width=max(8,min(28,len(b)+2))
            e=tk.Entry(box,width=width,justify="center",bg=dark,fg=fg,insertbackground=accent,relief="flat",font=("Consolas",18,"bold"))
            e.pack()
            cvs=tk.Canvas(box,width=max(80,width*14),height=10,bg=dark,highlightthickness=0); cvs.pack()
            cvs.create_line(4,5,max(76,width*14-4),5,fill=accent,width=3)
            tk.Label(box,text=_guess_pos_v37(b),bg=dark,fg=muted,font=("Microsoft YaHei UI",9)).pack()
            entries.append((e,b))
        def check():
            ok=0
            for e,b in entries:
                if e.get().strip().lower()==b.lower():
                    e.configure(fg="#22c55e"); ok+=1
                else:
                    e.configure(fg="#ef4444")
            result_var.set(f"正确块：{ok}/{len(entries)}")
        tk.Button(area,text="提交核对",bg=accent,fg="white",bd=0,padx=18,pady=8,command=check).pack(pady=22)
    draw()
    tk.Label(root,textvariable=result_var,bg=dark,fg=muted,font=("Microsoft YaHei UI",12)).pack(pady=10)

