# ──────────────────────────────────────────────────────────────────────
# V38 Dictation Audio Effects + Better Voice + Settings Center
# 只补听写/背诵/设置，不改美化视频渲染主链。
# ──────────────────────────────────────────────────────────────────────
import threading as _threading_v38
import subprocess as _subprocess_v38
import tempfile as _tempfile_v38
import json as _json_v38

V38_TTS_VOICES = {
    "美音 Jenny 女声 Edge": {"engine": "edge", "voice": "en-US-JennyNeural", "accent": "US"},
    "美音 Guy 男声 Edge": {"engine": "edge", "voice": "en-US-GuyNeural", "accent": "US"},
    "美音 Aria 女声 Edge": {"engine": "edge", "voice": "en-US-AriaNeural", "accent": "US"},
    "英音 Sonia 女声 Edge": {"engine": "edge", "voice": "en-GB-SoniaNeural", "accent": "UK"},
    "英音 Ryan 男声 Edge": {"engine": "edge", "voice": "en-GB-RyanNeural", "accent": "UK"},
    "英音 Libby 女声 Edge": {"engine": "edge", "voice": "en-GB-LibbyNeural", "accent": "UK"},
    "Windows SAPI 本地": {"engine": "sapi", "voice": "", "accent": "LOCAL"},
    "pyttsx3 本地": {"engine": "pyttsx3", "voice": "", "accent": "LOCAL"},
    "原片音频 / 系统播放器": {"engine": "original", "voice": "", "accent": "ORIGINAL"},
}

V38_SOUND_NAMES = {
    "type": "输入按键音",
    "word_ok": "单词/短语正确音",
    "sentence_ok": "整句正确提示音",
    "wrong": "错误提示音",
}

def _v38_no_window_kwargs():
    if os.name != "nt":
        return {}
    si = _subprocess_v38.STARTUPINFO()
    si.dwFlags |= _subprocess_v38.STARTF_USESHOWWINDOW
    return {"creationflags": getattr(_subprocess_v38, "CREATE_NO_WINDOW", 0), "startupinfo": si}

def _v38_get_cfg(self):
    if not hasattr(self, "dict_audio_settings_v38"):
        self.dict_audio_settings_v38 = {
            "sound_enabled": True,
            "type_sound": True,
            "word_ok_sound": True,
            "sentence_ok_sound": True,
            "wrong_sound": True,
            "sound_volume": 70,
            "tts_voice": "美音 Jenny 女声 Edge",
            "tts_rate": 1.0,
            "tts_volume": 100,
            "space_check_block": True,
            "enter_submit_sentence": True,
            "auto_jump_block": True,
            "wrong_replay": True,
        }
    return self.dict_audio_settings_v38

def _v38_beep(self, kind="type"):
    cfg = _v38_get_cfg(self)
    if not cfg.get("sound_enabled", True):
        return
    flag_map = {
        "type": "type_sound",
        "word_ok": "word_ok_sound",
        "sentence_ok": "sentence_ok_sound",
        "wrong": "wrong_sound",
    }
    if not cfg.get(flag_map.get(kind, "sound_enabled"), True):
        return
    try:
        import winsound
        # Windows beep set: simple but instant and no black console.
        if kind == "type":
            winsound.Beep(900, 25)
        elif kind == "word_ok":
            winsound.Beep(1320, 70)
        elif kind == "sentence_ok":
            winsound.Beep(880, 60); winsound.Beep(1320, 90)
        elif kind == "wrong":
            winsound.Beep(260, 130)
        else:
            winsound.MessageBeep()
    except Exception:
        try:
            self.bell()
        except Exception:
            pass

def _v38_words(text):
    return re.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|[0-9]+|[^\s]", text or "")

def _v38_blocks(text):
    # Basic block segmentation: punctuation + short function chunks. This is fast and deterministic.
    raw = re.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|[0-9]+|[.,!?;:]", text or "")
    blocks = []
    cur = []
    for tok in raw:
        if tok in ".,!?;:":
            if cur:
                blocks.append(" ".join(cur))
                cur = []
            continue
        cur.append(tok)
        if len(cur) >= 3:
            blocks.append(" ".join(cur))
            cur = []
    if cur:
        blocks.append(" ".join(cur))
    return blocks or ([text] if text else [])

def _v38_guess_pos(block):
    w = (block or "").strip().lower()
    if not w:
        return ""
    prep = {"in","on","at","from","to","for","with","by","of","about","into","over","under","through","after","before"}
    det = {"a","an","the","this","that","these","those","my","your","his","her","its","our","their"}
    aux = {"am","is","are","was","were","be","been","being","do","does","did","have","has","had","will","would","can","could","may","might","must","should"}
    adv = {"very","really","quickly","slowly","never","always","often","sometimes","here","there","now","then"}
    if " " in w:
        return "短语"
    if w in prep:
        return "介词"
    if w in det:
        return "限定词"
    if w in aux or w.endswith("ed") or w.endswith("ing"):
        return "动词"
    if w.endswith("ly") or w in adv:
        return "副词"
    if w.endswith(("ous","ful","ive","al","able","ible","less","ic")):
        return "形容词"
    if w and w[0].isupper():
        return "专有名词"
    return "名词/动词"

def _v38_current_text(self):
    # Compatible with previous V33/V37 implementations.
    for fn in ("_dict_current_text_v33",):
        if fn in globals() and callable(globals()[fn]):
            try:
                return globals()[fn](self)
            except Exception:
                pass
    for name in ("dict_items_v33", "dict_items_v32", "dict_items", "dictation_items"):
        if hasattr(self, name):
            items = getattr(self, name)
            idx = int(getattr(self, "dict_index_v33", getattr(self, "dict_index_v32", 0)) or 0)
            if isinstance(items, list) and 0 <= idx < len(items):
                it = items[idx]
                if isinstance(it, dict):
                    return str(it.get("text") or it.get("en") or "")
                return str(getattr(it, "text", it))
    return ""

def _v38_current_zh(self):
    for fn in ("_dict_current_zh_v33",):
        if fn in globals() and callable(globals()[fn]):
            try:
                return globals()[fn](self)
            except Exception:
                pass
    for name in ("dict_items_v33", "dict_items_v32", "dict_items", "dictation_items"):
        if hasattr(self, name):
            items = getattr(self, name)
            idx = int(getattr(self, "dict_index_v33", getattr(self, "dict_index_v32", 0)) or 0)
            if isinstance(items, list) and 0 <= idx < len(items):
                it = items[idx]
                if isinstance(it, dict):
                    return str(it.get("zh") or it.get("cn") or "")
                return str(getattr(it, "zh", ""))
    return ""

def _v38_rate_to_edge(rate):
    try:
        r = float(rate)
    except Exception:
        r = 1.0
    pct = int((r - 1.0) * 100)
    if pct >= 0:
        return f"+{pct}%"
    return f"{pct}%"

def _v38_speak(self, text=None, force_voice=None):
    text = text or _v38_current_text(self)
    if not text:
        return
    cfg = _v38_get_cfg(self)
    voice_name = force_voice or cfg.get("tts_voice", "美音 Jenny 女声 Edge")
    spec = V38_TTS_VOICES.get(voice_name, V38_TTS_VOICES["Windows SAPI 本地"])
    rate = float(cfg.get("tts_rate", 1.0) or 1.0)
    volume = int(cfg.get("tts_volume", 100) or 100)

    def run():
        try:
            if spec["engine"] == "edge":
                # Edge-TTS command path: no black window. If not installed, fallback to SAPI.
                tmp = Path(_tempfile_v38.gettempdir()) / ("pp_tts_v38_" + str(abs(hash(text))) + ".mp3")
                cmd = [
                    sys.executable, "-m", "edge_tts",
                    "--voice", spec["voice"],
                    "--rate", _v38_rate_to_edge(rate),
                    "--volume", f"{max(0, min(volume, 100))}%",
                    "--text", text,
                    "--write-media", str(tmp),
                ]
                r = _subprocess_v38.run(cmd, capture_output=True, text=True, timeout=30, **_v38_no_window_kwargs())
                if r.returncode == 0 and tmp.exists():
                    if os.name == "nt":
                        os.startfile(str(tmp))
                    else:
                        _subprocess_v38.Popen(["xdg-open", str(tmp)], **_v38_no_window_kwargs())
                    return
            if spec["engine"] == "pyttsx3":
                import pyttsx3
                tts = pyttsx3.init()
                tts.setProperty("rate", int(180 * rate))
                tts.setProperty("volume", max(0, min(volume, 100)) / 100.0)
                tts.say(text)
                tts.runAndWait()
                return
            # Windows SAPI fallback.
            if os.name == "nt":
                import win32com.client
                speaker = win32com.client.Dispatch("SAPI.SpVoice")
                speaker.Rate = int((rate - 1.0) * 5)
                speaker.Volume = max(0, min(volume, 100))
                speaker.Speak(text)
            else:
                try:
                    _subprocess_v38.Popen(["say", text], **_v38_no_window_kwargs())
                except Exception:
                    pass
        except Exception as e:
            try:
                self.log(f"V38发音失败：{type(e).__name__}: {e}", "warn")
            except Exception:
                pass
            try:
                self.bell()
            except Exception:
                pass
    _threading_v38.Thread(target=run, daemon=True).start()

def _v38_draw_segment_input(self):
    text = _v38_current_text(self)
    zh = _v38_current_zh(self)
    blocks = _v38_blocks(text)
    if not hasattr(self, "dict_segment_entries_v38"):
        self.dict_segment_entries_v38 = []
    # Create or rebuild segment panel when available.
    parent = getattr(self, "dict_segment_panel_v38", None)
    if parent is None:
        # Try to attach below central entry in existing dictation UI.
        target = getattr(self, "dict_answer_entry_v33", None)
        if target is not None:
            try:
                parent = tk.Frame(target.master, bg=target.master.cget("bg"))
                parent.pack(fill="x", padx=140, pady=(8, 4))
                self.dict_segment_panel_v38 = parent
            except Exception:
                return
        else:
            return
    try:
        for ch in parent.winfo_children():
            ch.destroy()
    except Exception:
        pass
    self.dict_segment_entries_v38 = []
    bg = parent.cget("bg") if hasattr(parent, "cget") else "#0b0f17"
    if zh:
        tk.Label(parent, text=zh, bg=bg, fg="#e5e7eb", font=("Microsoft YaHei UI", 18, "bold")).pack(pady=(2, 12))
    line = tk.Frame(parent, bg=bg)
    line.pack(anchor="center")
    for i, b in enumerate(blocks):
        cell = tk.Frame(line, bg=bg)
        cell.pack(side="left", padx=5, pady=4)
        width = max(5, min(18, len(b) + 1))
        ent = tk.Entry(cell, width=width, justify="center", bg=bg, fg="#e5e7eb",
                       insertbackground="#8b5cf6", relief="flat", font=("Consolas", 16, "bold"))
        ent.pack()
        canvas = tk.Canvas(cell, width=max(50, width * 12), height=5, bg=bg, highlightthickness=0)
        canvas.pack()
        canvas.create_line(2, 2, max(48, width * 12 - 2), 2, fill="#8b5cf6", width=3)
        tk.Label(cell, text=_v38_guess_pos(b), bg=bg, fg="#8b95a7", font=("Microsoft YaHei UI", 9)).pack()
        ent.bind("<space>", lambda e, idx=i: (_v38_check_block(self, idx), "break"))
        ent.bind("<Return>", lambda e: (_v38_submit_sentence(self), "break"))
        ent.bind("<KeyPress>", lambda e: _v38_beep(self, "type"))
        self.dict_segment_entries_v38.append((b, ent))
    self.dict_segment_index_v38 = 0
    if self.dict_segment_entries_v38:
        self.dict_segment_entries_v38[0][1].focus_set()

def _v38_check_block(self, idx=None):
    if not hasattr(self, "dict_segment_entries_v38") or not self.dict_segment_entries_v38:
        return False
    if idx is None:
        idx = getattr(self, "dict_segment_index_v38", 0)
    if idx < 0 or idx >= len(self.dict_segment_entries_v38):
        return False
    target, ent = self.dict_segment_entries_v38[idx]
    ans = ent.get().strip()
    ok = ans.lower() == target.lower()
    if ok:
        ent.configure(fg="#22c55e")
        _v38_beep(self, "word_ok")
        self.dict_segment_index_v38 = min(idx + 1, len(self.dict_segment_entries_v38)-1)
        if idx + 1 < len(self.dict_segment_entries_v38):
            self.dict_segment_entries_v38[idx + 1][1].focus_set()
        return True
    else:
        ent.configure(fg="#ef4444")
        _v38_beep(self, "wrong")
        if _v38_get_cfg(self).get("wrong_replay", True):
            _v38_speak(self, target)
        return False

def _v38_submit_sentence(self):
    if hasattr(self, "dict_segment_entries_v38") and self.dict_segment_entries_v38:
        all_ok = True
        for i in range(len(self.dict_segment_entries_v38)):
            all_ok = _v38_check_block(self, i) and all_ok
        if all_ok:
            _v38_beep(self, "sentence_ok")
            # auto next if supported
            try:
                if bool(getattr(self, "dict_auto_next_v33").get()):
                    if "_dict_next_v33" in globals():
                        globals()["_dict_next_v33"](self)
            except Exception:
                pass
        return
    # fallback existing submit
    for name in ("_dict_submit_v33", "_dict_submit_v32", "_dict_submit"):
        fn = globals().get(name)
        if callable(fn):
            return fn(self)

def _v38_open_settings_center(self):
    cfg = _v38_get_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置")
    win.geometry("980x720")
    win.configure(bg="#f3f4f6")

    shell = tk.Frame(win, bg="#ffffff", bd=0, highlightthickness=0)
    shell.pack(fill="both", expand=True, padx=22, pady=22)

    left = tk.Frame(shell, bg="#ffffff", width=220)
    left.pack(side="left", fill="y")
    left.pack_propagate(False)
    sep = tk.Frame(shell, bg="#e5e7eb", width=1)
    sep.pack(side="left", fill="y", padx=(0, 18))

    right_outer = tk.Frame(shell, bg="#ffffff")
    right_outer.pack(side="left", fill="both", expand=True)
    title = tk.Label(right_outer, text="设置", bg="#ffffff", fg="#374151", font=("Microsoft YaHei UI", 20, "bold"))
    title.pack(anchor="center", pady=(12, 6))

    canvas = tk.Canvas(right_outer, bg="#ffffff", highlightthickness=0)
    scroll = ttk.Scrollbar(right_outer, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=scroll.set)
    scroll.pack(side="right", fill="y")
    canvas.pack(side="left", fill="both", expand=True)
    content = tk.Frame(canvas, bg="#ffffff")
    window_id = canvas.create_window((0, 0), window=content, anchor="nw")
    content.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfigure(window_id, width=e.width))

    cats = ["通用设置", "遗忘曲线设置", "单词设置", "文章设置", "音效设置", "快捷键设置", "数据管理", "关于"]
    def show_cat(name):
        for ch in content.winfo_children():
            ch.destroy()
        title.configure(text=name)
        if name == "音效设置":
            _v38_settings_audio_page(self, content, cfg)
        elif name == "快捷键设置":
            _v38_settings_hotkey_page(self, content)
        else:
            tk.Label(content, text=f"{name}：此页预留扩展。", bg="#ffffff", fg="#6b7280", font=("Microsoft YaHei UI", 14)).pack(anchor="w", padx=20, pady=20)

    for cat in cats:
        b = tk.Button(left, text=("🔊  " if cat=="音效设置" else "⚙  ") + cat, anchor="w",
                      bg="#ffffff", fg="#374151", bd=0, padx=18, pady=12,
                      font=("Microsoft YaHei UI", 12), command=lambda c=cat: show_cat(c))
        b.pack(fill="x", padx=12, pady=2)
    show_cat("音效设置")

def _v38_scale(parent, text, key, frm, to, cfg):
    row = tk.Frame(parent, bg="#ffffff")
    row.pack(fill="x", padx=24, pady=12)
    tk.Label(row, text=text, bg="#ffffff", fg="#374151", font=("Microsoft YaHei UI", 12, "bold")).pack(anchor="w")
    val = tk.DoubleVar(value=float(cfg.get(key, frm)))
    scale = tk.Scale(row, from_=frm, to=to, orient="horizontal", resolution=1 if to>10 else 0.1,
                     variable=val, bg="#ffffff", fg="#374151", troughcolor="#e5e7eb",
                     activebackground="#3b82f6", highlightthickness=0, length=520)
    scale.pack(side="left", fill="x", expand=True)
    lab = tk.Label(row, text=str(cfg.get(key, frm)), bg="#ffffff", fg="#374151", width=8)
    lab.pack(side="left")
    def on_change(_=None):
        v = val.get()
        cfg[key] = int(v) if to > 10 else float(v)
        lab.configure(text=str(cfg[key]))
    scale.configure(command=lambda v: on_change())
    return scale

def _v38_settings_audio_page(self, parent, cfg):
    tk.Label(parent, text="TTS 声色", bg="#ffffff", fg="#374151", font=("Microsoft YaHei UI", 16, "bold")).pack(anchor="w", padx=24, pady=(12, 10))
    row = tk.Frame(parent, bg="#ffffff")
    row.pack(fill="x", padx=24, pady=8)
    tk.Label(row, text="TTS 声色", bg="#ffffff", fg="#374151", font=("Microsoft YaHei UI", 12)).pack(side="left")
    voice_var = tk.StringVar(value=cfg.get("tts_voice", "美音 Jenny 女声 Edge"))
    cb = ttk.Combobox(row, textvariable=voice_var, values=list(V38_TTS_VOICES.keys()), state="readonly", width=36)
    cb.pack(side="right")
    def save_voice(*_):
        cfg["tts_voice"] = voice_var.get()
    cb.bind("<<ComboboxSelected>>", save_voice)
    tk.Button(parent, text="试听句子：How are you? I am fine, thank you. And you?",
              bg="#3b82f6", fg="#ffffff", bd=0, padx=14, pady=8,
              command=lambda: _v38_speak(self, "How are you? I am fine, thank you. And you?", voice_var.get())).pack(anchor="w", padx=24, pady=8)

    tk.Label(parent, text="文章音效", bg="#ffffff", fg="#374151", font=("Microsoft YaHei UI", 16, "bold")).pack(anchor="w", padx=24, pady=(20, 6))
    for label, key in [("输入按键音", "type_sound"), ("单词/短语正确音", "word_ok_sound"), ("整句正确提示音", "sentence_ok_sound"), ("错误提示音", "wrong_sound")]:
        var = tk.BooleanVar(value=bool(cfg.get(key, True)))
        chk = tk.Checkbutton(parent, text=label, variable=var, bg="#ffffff", fg="#374151",
                             command=lambda k=key, v=var: cfg.__setitem__(k, bool(v.get())))
        chk.pack(anchor="w", padx=24, pady=3)

    _v38_scale(parent, "音效音量", "sound_volume", 0, 100, cfg)
    _v38_scale(parent, "TTS 音量", "tts_volume", 0, 100, cfg)
    _v38_scale(parent, "TTS 倍速", "tts_rate", 0.5, 3.0, cfg)

def _v38_settings_hotkey_page(self, parent):
    tk.Label(parent, text="快捷键设置", bg="#ffffff", fg="#374151", font=("Microsoft YaHei UI", 16, "bold")).pack(anchor="w", padx=24, pady=16)
    tk.Label(parent, text="禁止单独英文字母快捷键，防止输入英文时误触。推荐 Ctrl / Alt / Shift 组合键。",
             bg="#ffffff", fg="#f97316", font=("Microsoft YaHei UI", 11)).pack(anchor="w", padx=24, pady=6)
    defaults = {
        "播放/重复": "Ctrl+R",
        "判断当前块": "Space",
        "提交整句": "Enter",
        "下一提示": "Ctrl+H",
        "显示/隐藏中文": "Ctrl+Shift+C",
        "分块横线模式": "Ctrl+Shift+B",
    }
    if not hasattr(self, "dict_hotkeys_v38"):
        self.dict_hotkeys_v38 = dict(defaults)
    for action, default in defaults.items():
        row = tk.Frame(parent, bg="#ffffff")
        row.pack(fill="x", padx=24, pady=5)
        tk.Label(row, text=action, bg="#ffffff", fg="#374151", width=18, anchor="w").pack(side="left")
        var = tk.StringVar(value=self.dict_hotkeys_v38.get(action, default))
        ent = ttk.Entry(row, textvariable=var, width=24)
        ent.pack(side="left")
        def save(a=action, v=var):
            hk = v.get().strip()
            if re.fullmatch(r"[A-Za-z]", hk):
                messagebox.showwarning("快捷键非法", "不能设置单独英文字母快捷键。")
                return
            self.dict_hotkeys_v38[a] = hk
            _v38_apply_hotkeys(self)
            messagebox.showinfo("已保存", f"{a} -> {hk}")
        ttk.Button(row, text="保存并生效", command=save).pack(side="left", padx=8)

def _v38_hotkey_to_tk(seq):
    s = seq.strip()
    mapping = {
        "Ctrl": "Control",
        "Alt": "Alt",
        "Shift": "Shift",
        "Space": "space",
        "Enter": "Return",
        "Left": "Left",
        "Right": "Right",
    }
    parts = s.split("+")
    if len(parts) == 1:
        key = mapping.get(parts[0], parts[0])
        return f"<{key}>"
    key = mapping.get(parts[-1], parts[-1])
    mods = "-".join(mapping.get(p, p) for p in parts[:-1])
    return f"<{mods}-{key}>"

def _v38_apply_hotkeys(self):
    if not hasattr(self, "dict_hotkeys_v38"):
        return
    actions = {
        "播放/重复": lambda e: (_v38_speak(self), "break"),
        "判断当前块": lambda e: (_v38_check_block(self), "break"),
        "提交整句": lambda e: (_v38_submit_sentence(self), "break"),
        "下一提示": lambda e: (_v38_next_hint_fallback(self), "break"),
        "显示/隐藏中文": lambda e: (_v38_toggle_cn_fallback(self), "break"),
        "分块横线模式": lambda e: (_v38_draw_segment_input(self), "break"),
    }
    for action, seq in self.dict_hotkeys_v38.items():
        if action in actions:
            try:
                self.bind_all(_v38_hotkey_to_tk(seq), actions[action])
            except Exception:
                pass

def _v38_next_hint_fallback(self):
    if "_dict_next_hint_v33" in globals():
        try: return globals()["_dict_next_hint_v33"](self)
        except Exception: pass
    _v38_beep(self, "type")

def _v38_toggle_cn_fallback(self):
    try:
        if hasattr(self, "dict_cn_prompt_var_v33"):
            cur = self.dict_cn_prompt_var_v33.get()
            zh = _v38_current_zh(self)
            self.dict_cn_prompt_var_v33.set("" if cur and zh in cur else (zh or "无中文"))
    except Exception:
        pass

# Wrap current refresh to redraw segment blocks when item changes.
def _v38_patch_refresh():
    for name in ("_dict_refresh_current_v33", "_dict_refresh_current_v32"):
        fn = globals().get(name)
        if callable(fn) and not getattr(fn, "_v38_wrapped", False):
            def make_wrap(old):
                def wrapped(app_self, *a, **kw):
                    r = old(app_self, *a, **kw)
                    try:
                        _v38_draw_segment_input(app_self)
                    except Exception:
                        pass
                    return r
                wrapped._v38_wrapped = True
                return wrapped
            globals()[name] = make_wrap(fn)

_old_main_init_v38 = MainApp.__init__
def _main_init_v38(self):
    _old_main_init_v38(self)
    try:
        _v38_patch_refresh()
        _v38_get_cfg(self)
        _v38_apply_hotkeys(self)
        # Add settings button into dictation UI if possible.
        parent = getattr(self, "dict_mango_control_panel", None)
        if parent is not None and not getattr(self, "_v38_settings_btn_added", False):
            ttk.Button(parent, text="高级设置中心 · 音效/TTS/快捷键", command=lambda: _v38_open_settings_center(self)).pack(fill="x", padx=12, pady=8)
            self._v38_settings_btn_added = True
        # Bind entry sounds and segment mode.
        try:
            if hasattr(self, "dict_answer_entry_v33"):
                self.dict_answer_entry_v33.bind("<KeyPress>", lambda e: _v38_beep(self, "type"), add="+")
                self.dict_answer_entry_v33.bind("<space>", lambda e: (_v38_check_block(self), "break"), add="+")
                self.dict_answer_entry_v33.bind("<Return>", lambda e: (_v38_submit_sentence(self), "break"), add="+")
        except Exception:
            pass
        try:
            _v38_draw_segment_input(self)
        except Exception:
            pass
        self.log("【V38新功能上线】听写音效系统/单词块Space判断/Enter整句提交/英美TTS角色/高级设置中心已启用。", "ok")
        self.log("V38发音：新增 Edge-TTS 英音/美音角色；若未安装 edge-tts 会自动回退到 Windows SAPI。", "info")
    except Exception as e:
        try:
            self.log(f"V38初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v38
APP_TITLE = "PlayPhrase Studio Clean v38 · 听写音效+英美TTS+高级设置版"


# ──────────────────────────────────────────────────────────────────────
# V39 Sentence Mode + Split Mode Dictation Chain
# 整句模式 ↔ 拆分练习：同一句先拆分学习，再返回整句听写。
# ──────────────────────────────────────────────────────────────────────

V39_FUNCTION_WORDS = {
    "a","an","the","this","that","these","those","my","your","his","her","its","our","their",
    "is","am","are","was","were","be","been","being","do","does","did","have","has","had",
    "will","would","can","could","may","might","must","should","shall",
    "in","on","at","from","to","for","with","by","of","about","into","over","under","through",
    "and","but","or","so","because","if","when","while","which","who","what","where","why","how"
}

def _v39_current_text(self):
    # Compatible with V38/V33
    if "_v38_current_text" in globals():
        try:
            return globals()["_v38_current_text"](self)
        except Exception:
            pass
    if "_dict_current_text_v33" in globals():
        try:
            return globals()["_dict_current_text_v33"](self)
        except Exception:
            pass
    return ""

def _v39_current_zh(self):
    if "_v38_current_zh" in globals():
        try:
            return globals()["_v38_current_zh"](self)
        except Exception:
            pass
    if "_dict_current_zh_v33" in globals():
        try:
            return globals()["_dict_current_zh_v33"](self)
        except Exception:
            pass
    return ""

def _v39_guess_pos(block: str) -> str:
    if "_v38_guess_pos" in globals():
        try:
            return globals()["_v38_guess_pos"](block)
        except Exception:
            pass
    w = (block or "").strip().lower()
    if not w:
        return ""
    if " " in w:
        return "短语"
    if w in {"in","on","at","from","to","for","with","by","of","about","into","over","under","through"}:
        return "介词"
    if w in {"a","an","the","this","that","these","those"}:
        return "限定词"
    if w.endswith("ly"):
        return "副词"
    if w.endswith(("ed","ing")):
        return "动词"
    return "名/动"

def _v39_sentence_chunks(text: str):
    """Phrase-like chunker: keeps prepositional phrases and small noun groups together."""
    words = re.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|[0-9]+|[.,!?;:]", text or "")
    chunks = []
    cur = []
    for tok in words:
        low = tok.lower()
        if tok in ".,!?;:":
            if cur:
                chunks.append(" ".join(cur)); cur = []
            continue
        # Start a new phrase before wh/determiner/helper when current is long enough.
        if cur and low in {"which","who","what","where","why","how","when","does","do","did","is","are","was","were","will","would","can","could"}:
            chunks.append(" ".join(cur)); cur = [tok]; continue
        cur.append(tok)
        # Split after short grammar units or 2-3 word phrases.
        if len(cur) >= 3:
            chunks.append(" ".join(cur)); cur = []
        elif len(cur) >= 2 and low in {"from","to","in","on","at","with","for","of"}:
            chunks.append(" ".join(cur)); cur = []
    if cur:
        chunks.append(" ".join(cur))
    # Refine obvious cases: Which platform | does | the train | to Riverdale | leave | from
    s = " ".join(words)
    m = re.match(r"(?i)^(which\s+platform)\s+(does)\s+(the\s+train)\s+(to\s+[A-Za-z]+)\s+(leave)\s+(from)\??$", s)
    if m:
        return [m.group(i) for i in range(1, 7)]
    return [c for c in chunks if c.strip()] or ([text] if text else [])

def _v39_split_zh(zh: str, chunks):
    """Best-effort Chinese cue chunks. If not enough info, reuse the whole Chinese cue."""
    zh = zh or ""
    if not zh:
        return [""] * len(chunks)
    # Very simple punctuation split; if lengths mismatch, use full zh for first/current and blank others.
    parts = [p.strip() for p in re.split(r"[，,。！？?；;：:、]", zh) if p.strip()]
    if len(parts) >= len(chunks):
        return parts[:len(chunks)]
    if len(chunks) <= 1:
        return [zh]
    # For train-platform pattern, create a useful cue if Chinese contains station/platform.
    if "站台" in zh and "火车" in zh:
        cues = []
        for c in chunks:
            low = c.lower()
            if "which platform" in low:
                cues.append("哪一个站台")
            elif low == "does":
                cues.append("助动词")
            elif "the train" in low:
                cues.append("这趟火车")
            elif low.startswith("to "):
                cues.append("到某地")
            elif low == "leave":
                cues.append("离开 / 出发")
            elif low == "from":
                cues.append("从……")
            else:
                cues.append(zh)
        return cues
    return [zh] + [""] * (len(chunks)-1)

def _v39_beep(self, kind):
    if "_v38_beep" in globals():
        try:
            return globals()["_v38_beep"](self, kind)
        except Exception:
            pass
    try:
        self.bell()
    except Exception:
        pass

def _v39_speak(self, text):
    if "_v38_speak" in globals():
        try:
            return globals()["_v38_speak"](self, text)
        except Exception:
            pass

def _v39_ensure_mode_vars(self):
    if not hasattr(self, "dict_mode_v39"):
        self.dict_mode_v39 = tk.StringVar(value="sentence")  # sentence / split
    if not hasattr(self, "dict_split_index_v39"):
        self.dict_split_index_v39 = 0
    if not hasattr(self, "dict_split_done_v39"):
        self.dict_split_done_v39 = set()

def _v39_mode_label(self):
    _v39_ensure_mode_vars(self)
    return "整句模式" if self.dict_mode_v39.get() == "sentence" else "拆分模式"

def _v39_toggle_mode(self):
    _v39_ensure_mode_vars(self)
    if self.dict_mode_v39.get() == "sentence":
        self.dict_mode_v39.set("split")
        self.dict_split_index_v39 = 0
        self.dict_split_done_v39 = set()
    else:
        self.dict_mode_v39.set("sentence")
    _v39_render_sentence_split_area(self)

def _v39_check_current_split_block(self):
    _v39_ensure_mode_vars(self)
    text = _v39_current_text(self)
    chunks = _v39_sentence_chunks(text)
    idx = max(0, min(getattr(self, "dict_split_index_v39", 0), len(chunks)-1))
    if not chunks:
        return False
    target = chunks[idx]
    ent = getattr(self, "dict_split_entry_v39", None)
    ans = ent.get().strip() if ent is not None else ""
    ok = ans.lower() == target.lower()
    if ok:
        _v39_beep(self, "word_ok")
        self.dict_split_done_v39.add(idx)
        if idx + 1 < len(chunks):
            self.dict_split_index_v39 = idx + 1
            _v39_render_sentence_split_area(self)
        else:
            _v39_beep(self, "sentence_ok")
            try:
                if hasattr(self, "dict_result_var_v33"):
                    self.dict_result_var_v33.set("✅ 拆分练习完成，可以返回整句模式。")
            except Exception:
                pass
        return True
    else:
        _v39_beep(self, "wrong")
        _v39_speak(self, target)
        try:
            if hasattr(self, "dict_result_var_v33"):
                self.dict_result_var_v33.set(f"❌ 当前块不正确：{target}")
        except Exception:
            pass
        return False

def _v39_submit_whole_sentence(self):
    if "_v38_submit_sentence" in globals():
        try:
            return globals()["_v38_submit_sentence"](self)
        except Exception:
            pass
    if "_dict_submit_v33" in globals():
        try:
            return globals()["_dict_submit_v33"](self)
        except Exception:
            pass

def _v39_draw_underline(canvas, width, active=False):
    color = "#8b5cf6" if active else "#e5e7eb"
    try:
        canvas.delete("all")
        canvas.create_line(2, 3, max(20, width-2), 3, fill=color, width=3)
    except Exception:
        pass

def _v39_render_sentence_split_area(self):
    _v39_ensure_mode_vars(self)
    text = _v39_current_text(self)
    zh = _v39_current_zh(self)
    chunks = _v39_sentence_chunks(text)
    zh_chunks = _v39_split_zh(zh, chunks)
    mode = self.dict_mode_v39.get()

    parent = getattr(self, "dict_v39_area", None)
    if parent is None:
        # Prefer the center stage under answer entry if available.
        target = getattr(self, "dict_answer_entry_v33", None)
        if target is not None:
            try:
                parent = tk.Frame(target.master, bg=target.master.cget("bg"))
                # Put it after entry if possible.
                parent.pack(fill="x", padx=90, pady=(12, 6), before=getattr(self, "dict_hint_var_v33", None))
            except Exception:
                try:
                    parent = tk.Frame(target.master, bg=target.master.cget("bg"))
                    parent.pack(fill="x", padx=90, pady=(12, 6))
                except Exception:
                    return
        else:
            return
        self.dict_v39_area = parent

    try:
        for ch in parent.winfo_children():
            ch.destroy()
    except Exception:
        pass

    bg = parent.cget("bg") if hasattr(parent, "cget") else "#0b0f17"
    fg = "#374151" if bg.lower() in ("#ffffff", "white") else "#e5e7eb"
    muted = "#6b7280" if bg.lower() in ("#ffffff", "white") else "#8b95a7"

    if mode == "sentence":
        tk.Label(parent, text=zh or "中文提示：暂无翻译", bg=bg, fg=fg,
                 font=("Microsoft YaHei UI", 22, "bold")).pack(pady=(6, 14))
        tk.Button(parent, text="拆分练习", bg="#ffffff" if bg != "#ffffff" else "#f9fafb",
                  fg="#111827", bd=1, relief="solid", padx=18, pady=8,
                  font=("Microsoft YaHei UI", 12, "bold"), command=lambda: _v39_toggle_mode(self)).pack(pady=(0, 18))
        line = tk.Frame(parent, bg=bg)
        line.pack(anchor="center", fill="x")
        for i, c in enumerate(chunks):
            cell = tk.Frame(line, bg=bg)
            cell.pack(side="left", padx=4, pady=3, expand=True)
            w = max(60, min(230, len(c) * 16))
            can = tk.Canvas(cell, width=w, height=8, bg=bg, highlightthickness=0)
            can.pack()
            _v39_draw_underline(can, w, active=(i == 0))
            tk.Label(cell, text=_v39_guess_pos(c), bg=bg, fg=muted, font=("Microsoft YaHei UI", 9, "bold")).pack()
        hint = "整句模式：先听整句；需要降难度时点击【拆分练习】。Enter 提交整句。"
        tk.Label(parent, text=hint, bg=bg, fg=muted, font=("Microsoft YaHei UI", 10)).pack(pady=(14, 0))
    else:
        idx = max(0, min(getattr(self, "dict_split_index_v39", 0), max(len(chunks)-1, 0)))
        cue = zh_chunks[idx] if idx < len(zh_chunks) else (zh or "")
        tk.Label(parent, text=cue or "当前块中文提示", bg=bg, fg=fg,
                 font=("Microsoft YaHei UI", 24, "bold")).pack(pady=(6, 14))
        top = tk.Frame(parent, bg=bg)
        top.pack(pady=(0, 14))
        tk.Button(top, text="返回句子", bg="#ffffff" if bg != "#ffffff" else "#f9fafb",
                  fg="#111827", bd=1, relief="solid", padx=18, pady=8,
                  font=("Microsoft YaHei UI", 12, "bold"), command=lambda: _v39_toggle_mode(self)).pack(side="left", padx=8)
        tk.Button(top, text="播放当前块", bg="#8b5cf6", fg="#ffffff", bd=0, padx=18, pady=8,
                  font=("Microsoft YaHei UI", 12, "bold"), command=lambda: _v39_speak(self, chunks[idx] if chunks else text)).pack(side="left", padx=8)
        wrap = tk.Frame(parent, bg=bg)
        wrap.pack(anchor="center")
        target = chunks[idx] if chunks else ""
        ew = max(8, min(28, len(target) + 2))
        ent = tk.Entry(wrap, width=ew, justify="center", bg=bg, fg=fg, insertbackground="#8b5cf6",
                       relief="flat", font=("Consolas", 24, "bold"))
        ent.pack()
        self.dict_split_entry_v39 = ent
        can = tk.Canvas(wrap, width=max(120, ew*18), height=10, bg=bg, highlightthickness=0)
        can.pack()
        _v39_draw_underline(can, max(120, ew*18), active=True)
        tk.Label(wrap, text=_v39_guess_pos(target), bg=bg, fg=muted,
                 font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(4, 0))
        ent.bind("<space>", lambda e: (_v39_check_current_split_block(self), "break"))
        ent.bind("<Return>", lambda e: (_v39_submit_whole_sentence(self), "break"))
        try:
            ent.focus_set()
        except Exception:
            pass
        # Mini progress under split.
        prog = tk.Frame(parent, bg=bg)
        prog.pack(pady=(18, 0))
        for i, c in enumerate(chunks):
            width = max(40, min(130, len(c)*10))
            color = "#22c55e" if i in getattr(self, "dict_split_done_v39", set()) else ("#8b5cf6" if i == idx else "#e5e7eb")
            segment = tk.Canvas(prog, width=width, height=6, bg=bg, highlightthickness=0)
            segment.pack(side="left", padx=3)
            segment.create_line(2, 3, width-2, 3, fill=color, width=3)
        tk.Label(parent, text="拆分模式：Space 判断当前块；正确后自动进入下一块；全部完成后返回整句。",
                 bg=bg, fg=muted, font=("Microsoft YaHei UI", 10)).pack(pady=(12, 0))

def _v39_patch_refresh():
    for name in ("_dict_refresh_current_v33", "_dict_refresh_current_v32", "_dict_refresh_current"):
        fn = globals().get(name)
        if callable(fn) and not getattr(fn, "_v39_wrapped", False):
            def make_wrap(old):
                def wrapped(app_self, *a, **kw):
                    r = old(app_self, *a, **kw)
                    try:
                        _v39_ensure_mode_vars(app_self)
                        app_self.dict_split_index_v39 = 0
                        app_self.dict_split_done_v39 = set()
                        _v39_render_sentence_split_area(app_self)
                    except Exception:
                        pass
                    return r
                wrapped._v39_wrapped = True
                return wrapped
            globals()[name] = make_wrap(fn)

def _v39_apply_hotkeys(self):
    try:
        self.bind_all("<Control-Shift-B>", lambda e: (_v39_toggle_mode(self), "break"))
        self.bind_all("<space>", lambda e: (_v39_check_current_split_block(self), "break") if getattr(self, "dict_mode_v39", tk.StringVar(value="sentence")).get() == "split" else None)
        self.bind_all("<Return>", lambda e: (_v39_submit_whole_sentence(self), "break"))
    except Exception:
        pass

_old_main_init_v39 = MainApp.__init__
def _main_init_v39(self):
    _old_main_init_v39(self)
    try:
        _v39_ensure_mode_vars(self)
        _v39_patch_refresh()
        _v39_apply_hotkeys(self)
        _v39_render_sentence_split_area(self)
        try:
            self.log("【V39新功能上线】听写新增整句模式 ↔ 拆分模式：同一句可先拆分块练习，再返回整句听写。", "ok")
            self.log("V39操作：Ctrl+Shift+B 切换整句/拆分；拆分模式 Space 判断当前块，Enter 提交整句。", "info")
        except Exception:
            pass
    except Exception as e:
        try:
            self.log(f"V39整句/拆分模式初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v39
APP_TITLE = "PlayPhrase Studio Clean v39 · 整句/拆分双模式听写版"


# ──────────────────────────────────────────────────────────────────────
# V40 Dictation input-stage rebuild + silent pronunciation + semantic split
# 只修听写/发音/拆分显示，不动美化视频功能主链。
# ──────────────────────────────────────────────────────────────────────
import threading as _threading_v40
import tempfile as _tempfile_v40
import subprocess as _subprocess_v40
import ctypes as _ctypes_v40
import uuid as _uuid_v40

V40_BG = "#0b111d"
V40_CARD = "#111827"
V40_TEXT = "#f3f4f6"
V40_MUTED = "#94a3b8"
V40_PURPLE = "#8b5cf6"
V40_OK = "#22c55e"
V40_BAD = "#ef4444"
V40_LINE = "#dbe3f0"

def _v40_no_window_kwargs():
    if os.name != "nt":
        return {}
    si = _subprocess_v40.STARTUPINFO()
    si.dwFlags |= _subprocess_v40.STARTF_USESHOWWINDOW
    return {"creationflags": getattr(_subprocess_v40, "CREATE_NO_WINDOW", 0), "startupinfo": si}

def _v40_log(self, msg, level="info"):
    try:
        self.log(msg, level)
    except Exception:
        print(msg)

def _v40_current_text(self):
    for fn in ("_v39_current_text", "_v38_current_text", "_dict_current_text_v33"):
        if fn in globals() and callable(globals()[fn]):
            try:
                t = globals()[fn](self)
                if t:
                    return t
            except Exception:
                pass
    for name in ("dict_items_v33", "dict_items_v32", "dict_items"):
        if hasattr(self, name):
            items = getattr(self, name)
            idx = int(getattr(self, "dict_index_v33", getattr(self, "dict_index_v32", 0)) or 0)
            if isinstance(items, list) and 0 <= idx < len(items):
                it = items[idx]
                if isinstance(it, dict):
                    return str(it.get("text") or it.get("en") or it.get("line") or "")
                return str(getattr(it, "text", it))
    return ""

def _v40_current_zh(self):
    for fn in ("_v39_current_zh", "_v38_current_zh", "_dict_current_zh_v33"):
        if fn in globals() and callable(globals()[fn]):
            try:
                z = globals()[fn](self)
                if z:
                    return z
            except Exception:
                pass
    for name in ("dict_items_v33", "dict_items_v32", "dict_items"):
        if hasattr(self, name):
            items = getattr(self, name)
            idx = int(getattr(self, "dict_index_v33", getattr(self, "dict_index_v32", 0)) or 0)
            if isinstance(items, list) and 0 <= idx < len(items):
                it = items[idx]
                if isinstance(it, dict):
                    return str(it.get("zh") or it.get("cn") or "")
                return str(getattr(it, "zh", ""))
    return ""

def _v40_beep(self, kind="type"):
    if "_v38_beep" in globals():
        try:
            return globals()["_v38_beep"](self, kind)
        except Exception:
            pass
    try:
        import winsound
        if kind == "ok":
            winsound.Beep(1200, 70)
        elif kind == "bad":
            winsound.Beep(240, 140)
        elif kind == "sentence":
            winsound.Beep(900, 60); winsound.Beep(1300, 90)
        else:
            winsound.Beep(850, 20)
    except Exception:
        try:
            self.bell()
        except Exception:
            pass

def _v40_mci_play_file(path: Path):
    """Play audio silently via WinMM MCI; no external player, no black window."""
    if os.name != "nt":
        # Non-Windows fallback: no console window.
        try:
            _subprocess_v40.Popen(["xdg-open", str(path)], **_v40_no_window_kwargs())
        except Exception:
            pass
        return
    alias = "ppv40_" + _uuid_v40.uuid4().hex[:10]
    winmm = _ctypes_v40.windll.winmm
    def mci(cmd):
        buf = _ctypes_v40.create_unicode_buffer(512)
        winmm.mciSendStringW(cmd, buf, 511, 0)
        return buf.value
    p = str(path).replace('"', '')
    mci(f'open "{p}" type mpegvideo alias {alias}')
    mci(f'play {alias}')
    # close later; do not block UI
    def closer():
        import time
        time.sleep(20)
        try:
            mci(f"close {alias}")
        except Exception:
            pass
    _threading_v40.Thread(target=closer, daemon=True).start()

def _v40_edge_tts_to_file(self, text, voice="en-US-JennyNeural", rate="+0%"):
    out = Path(_tempfile_v40.gettempdir()) / ("pp_edge_v40_" + str(abs(hash((text, voice, rate)))) + ".mp3")
    if out.exists() and out.stat().st_size > 1000:
        return out
    cmd = [
        sys.executable, "-m", "edge_tts",
        "--voice", voice,
        "--rate", rate,
        "--text", text,
        "--write-media", str(out),
    ]
    r = _subprocess_v40.run(cmd, capture_output=True, text=True, timeout=45, **_v40_no_window_kwargs())
    if r.returncode == 0 and out.exists() and out.stat().st_size > 1000:
        return out
    return None

def _v40_sapi_speak(self, text, rate=0, volume=100):
    if os.name != "nt":
        return False
    try:
        import win32com.client
        speaker = win32com.client.Dispatch("SAPI.SpVoice")
        speaker.Rate = int(rate)
        speaker.Volume = int(volume)
        speaker.Speak(text)
        return True
    except Exception:
        return False

def _v40_voice_spec(self):
    # Prefer V38 config if present.
    voice_name = None
    try:
        if hasattr(self, "dict_audio_settings_v38"):
            voice_name = self.dict_audio_settings_v38.get("tts_voice")
    except Exception:
        pass
    voice_name = voice_name or "美音 Jenny 女声 Edge"
    edge_map = {
        "美音 Jenny 女声 Edge": "en-US-JennyNeural",
        "美音 Guy 男声 Edge": "en-US-GuyNeural",
        "美音 Aria 女声 Edge": "en-US-AriaNeural",
        "英音 Sonia 女声 Edge": "en-GB-SoniaNeural",
        "英音 Ryan 男声 Edge": "en-GB-RyanNeural",
        "英音 Libby 女声 Edge": "en-GB-LibbyNeural",
    }
    return voice_name, edge_map.get(voice_name, "en-US-JennyNeural")

def _v40_speak_silent(self, text=None):
    text = text or _v40_current_text(self)
    if not text:
        return
    def run():
        voice_name, edge_voice = _v40_voice_spec(self)
        # Edge neural first; if unavailable, silent SAPI fallback.
        try:
            f = _v40_edge_tts_to_file(self, text, edge_voice, "+0%")
            if f:
                _v40_mci_play_file(f)
                return
        except Exception as e:
            _v40_log(self, f"V40 Edge-TTS 静默播放失败，回退 SAPI：{type(e).__name__}: {e}", "warn")
        if not _v40_sapi_speak(self, text):
            try:
                self.bell()
            except Exception:
                pass
    _threading_v40.Thread(target=run, daemon=True).start()

def _v40_tokens(text):
    return re.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|[0-9]+|[.,!?;:]", text or "")

def _v40_semantic_chunks(text):
    """More semantic split, not raw sentence output. Designed for dictation display blocks."""
    words = [w for w in _v40_tokens(text) if not re.fullmatch(r"[.,!?;:]", w)]
    if not words:
        return []
    s = " ".join(words)
    # Common question pattern.
    m = re.match(r"(?i)^(which\s+platform)\s+(does)\s+(the\s+train)\s+(to\s+[A-Za-z]+)\s+(leave)\s+(from)$", s)
    if m:
        return [{"text": m.group(i), "role": ["疑问名词短语", "助动词", "主语名词短语", "方向介词短语", "谓语动词", "来源介词"][i-1]} for i in range(1, 7)]
    chunks = []
    cur = []
    role = "短语"
    preps = {"to","from","in","on","at","with","for","by","of","about","into","over","under","through","around"}
    conj = {"and","but","or","so","because","when","while","if","that","which","who","where"}
    aux = {"do","does","did","is","are","was","were","will","would","can","could","should","have","has","had"}
    i = 0
    while i < len(words):
        w = words[i]
        low = w.lower()
        if low in conj and cur:
            chunks.append({"text": " ".join(cur), "role": role})
            cur = [w]; role = "连接词/从句标记"; i += 1; continue
        if low in preps:
            if cur:
                chunks.append({"text": " ".join(cur), "role": role})
            cur = [w]; role = "介词短语"
            # consume following determiner/noun/adjective tokens up to 3
            j = i + 1
            while j < len(words) and len(cur) < 4 and words[j].lower() not in conj:
                cur.append(words[j]); j += 1
            chunks.append({"text": " ".join(cur), "role": role})
            cur = []; role = "短语"; i = j; continue
        if low in aux and not cur:
            chunks.append({"text": w, "role": "助动词"})
            i += 1; continue
        if not cur:
            role = "名词短语/谓语块"
        cur.append(w)
        if len(cur) >= 3:
            chunks.append({"text": " ".join(cur), "role": role})
            cur = []; role = "短语"
        i += 1
    if cur:
        chunks.append({"text": " ".join(cur), "role": role})
    return chunks or [{"text": text, "role": "整句"}]

def _v40_chinese_cues(zh, chunks):
    zh = zh or ""
    if not chunks:
        return []
    # Pattern-aware cue for platform train sentence.
    if "站台" in zh and "火车" in zh:
        cues = []
        for ch in chunks:
            low = ch["text"].lower()
            if "which platform" in low: cues.append("哪一个站台")
            elif low == "does": cues.append("助动词")
            elif "the train" in low: cues.append("这趟火车")
            elif low.startswith("to "): cues.append("到哪里")
            elif low == "leave": cues.append("离开 / 出发")
            elif low == "from": cues.append("从……")
            else: cues.append(zh)
        return cues
    parts = [p.strip() for p in re.split(r"[，,。！？?；;：:、]", zh) if p.strip()]
    if len(parts) >= len(chunks):
        return parts[:len(chunks)]
    return [zh] + [""] * (len(chunks)-1)

def _v40_get_input_stage_parent(self):
    # Try to reuse central stage. If no compatible area, return None.
    target = getattr(self, "dict_answer_entry_v33", None)
    if target is not None:
        return target.master
    return getattr(self, "tab_dictation", None)

def _v40_clear_old_black_prompt(self):
    # Hide/remove old large black prompt if available.
    for name in ("dict_v39_area", "dict_segment_panel_v38"):
        w = getattr(self, name, None)
        if w is not None:
            try: w.destroy()
            except Exception: pass
            try: delattr(self, name)
            except Exception: pass

def _v40_rebuild_input_ui(self):
    parent = _v40_get_input_stage_parent(self)
    if parent is None:
        return
    _v40_clear_old_black_prompt(self)
    old = getattr(self, "dict_input_stage_v40", None)
    if old is not None:
        try: old.destroy()
        except Exception: pass
    # Use the parent background to blend, no extra black frame.
    try:
        bg = parent.cget("bg")
    except Exception:
        bg = "#ffffff"
    fg = "#374151" if bg.lower() in ("#ffffff", "white", "#f9fafb") else V40_TEXT
    muted = "#6b7280" if fg == "#374151" else V40_MUTED

    stage = tk.Frame(parent, bg=bg)
    stage.pack(fill="both", expand=True, padx=20, pady=16)
    self.dict_input_stage_v40 = stage

    text = _v40_current_text(self)
    zh = _v40_current_zh(self) or "中文翻译/提示将自动显示"
    self.dict_mode_v40 = getattr(self, "dict_mode_v40", tk.StringVar(value="sentence"))

    top = tk.Frame(stage, bg=bg)
    top.pack(fill="x", pady=(10, 16))
    self.dict_zh_label_v40 = tk.Label(top, text=zh, bg=bg, fg=fg, font=("Microsoft YaHei UI", 24, "bold"))
    self.dict_zh_label_v40.pack(anchor="center")

    btn_text = "拆分练习" if self.dict_mode_v40.get() == "sentence" else "返回句子"
    tk.Button(stage, text=btn_text, bg="#ffffff", fg="#111827", bd=1, relief="solid",
              font=("Microsoft YaHei UI", 11, "bold"), padx=18, pady=8,
              command=lambda: _v40_toggle_sentence_split(self)).pack(pady=(0, 34))

    if self.dict_mode_v40.get() == "sentence":
        _v40_render_sentence_lines(self, stage, text, zh, bg, fg, muted)
    else:
        _v40_render_split_focus(self, stage, text, zh, bg, fg, muted)

def _v40_render_sentence_lines(self, parent, text, zh, bg, fg, muted):
    chunks = _v40_semantic_chunks(text)
    line = tk.Frame(parent, bg=bg)
    line.pack(anchor="center", pady=(8, 20))
    self.dict_sentence_entries_v40 = []
    for idx, ch in enumerate(chunks):
        cell = tk.Frame(line, bg=bg)
        cell.pack(side="left", padx=5, pady=4)
        width = max(5, min(22, len(ch["text"]) + 1))
        ent = tk.Entry(cell, width=width, justify="center", bg=bg, fg=fg,
                       insertbackground=V40_PURPLE, relief="flat", bd=0,
                       font=("Consolas", 18, "bold"))
        ent.pack()
        canvas = tk.Canvas(cell, width=max(54, width*13), height=7, bg=bg, highlightthickness=0)
        canvas.pack()
        canvas.create_line(2, 3, max(50, width*13-2), 3, fill=V40_PURPLE if idx == 0 else V40_LINE, width=3)
        tk.Label(cell, text=ch["role"], bg=bg, fg=muted, font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(3,0))
        ent.bind("<KeyPress>", lambda e: _v40_beep(self, "type"))
        ent.bind("<space>", lambda e, i=idx: (_v40_check_sentence_block(self, i), "break"))
        ent.bind("<Return>", lambda e: (_v40_submit_sentence_all(self), "break"))
        self.dict_sentence_entries_v40.append((ch["text"], ent, canvas))
    if self.dict_sentence_entries_v40:
        self.dict_sentence_entries_v40[0][1].focus_set()
    tk.Label(parent, text="整句模式：可以直接逐块输入；Space 判断当前块，Enter 提交整句；也可点“拆分练习”逐段练。",
             bg=bg, fg=muted, font=("Microsoft YaHei UI", 11)).pack(anchor="center", pady=(16, 0))

def _v40_render_split_focus(self, parent, text, zh, bg, fg, muted):
    chunks = _v40_semantic_chunks(text)
    cues = _v40_chinese_cues(zh, chunks)
    if not hasattr(self, "dict_split_idx_v40"):
        self.dict_split_idx_v40 = 0
    idx = max(0, min(self.dict_split_idx_v40, max(len(chunks)-1, 0)))
    current = chunks[idx] if chunks else {"text": "", "role": ""}
    cue = cues[idx] if idx < len(cues) else (zh or "")
    tk.Label(parent, text=cue or "当前分块提示", bg=bg, fg=fg, font=("Microsoft YaHei UI", 28, "bold")).pack(pady=(0, 24))
    wrap = tk.Frame(parent, bg=bg)
    wrap.pack(anchor="center")
    width = max(8, min(30, len(current["text"]) + 2))
    ent = tk.Entry(wrap, width=width, justify="center", bg=bg, fg=fg, insertbackground=V40_PURPLE,
                   relief="flat", bd=0, font=("Consolas", 24, "bold"))
    ent.pack()
    can = tk.Canvas(wrap, width=max(110, width*18), height=8, bg=bg, highlightthickness=0)
    can.pack()
    can.create_line(2, 4, max(105, width*18-2), 4, fill=V40_PURPLE, width=3)
    tk.Label(wrap, text=current["role"], bg=bg, fg=muted, font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(5,0))
    ent.bind("<space>", lambda e: (_v40_check_split_current(self), "break"))
    ent.bind("<Return>", lambda e: (_v40_submit_sentence_all(self), "break"))
    ent.bind("<KeyPress>", lambda e: _v40_beep(self, "type"))
    self.dict_split_entry_v40 = ent
    ent.focus_set()

    progress = tk.Frame(parent, bg=bg)
    progress.pack(pady=(28, 8))
    done = getattr(self, "dict_split_done_v40", set())
    for i, ch in enumerate(chunks):
        w = max(52, min(150, len(ch["text"]) * 12))
        cc = V40_OK if i in done else (V40_PURPLE if i == idx else V40_LINE)
        cv = tk.Canvas(progress, width=w, height=7, bg=bg, highlightthickness=0)
        cv.pack(side="left", padx=3)
        cv.create_line(2, 3, w-2, 3, fill=cc, width=3)
    tk.Label(parent, text="拆分模式：只显示当前句子成分块；Space 判断，正确自动进入下一块，全部完成后返回整句。",
             bg=bg, fg=muted, font=("Microsoft YaHei UI", 11)).pack(pady=(10,0))

def _v40_toggle_sentence_split(self):
    self.dict_mode_v40 = getattr(self, "dict_mode_v40", tk.StringVar(value="sentence"))
    if self.dict_mode_v40.get() == "sentence":
        self.dict_mode_v40.set("split")
        self.dict_split_idx_v40 = 0
        self.dict_split_done_v40 = set()
    else:
        self.dict_mode_v40.set("sentence")
    _v40_rebuild_input_ui(self)

def _v40_check_sentence_block(self, idx):
    if not hasattr(self, "dict_sentence_entries_v40"):
        return False
    if idx < 0 or idx >= len(self.dict_sentence_entries_v40):
        return False
    target, ent, can = self.dict_sentence_entries_v40[idx]
    ok = ent.get().strip().lower() == target.lower()
    if ok:
        ent.configure(fg=V40_OK)
        can.delete("all"); can.create_line(2,3,max(50,int(can.cget("width"))-2),3,fill=V40_OK,width=3)
        _v40_beep(self, "word_ok")
        if idx + 1 < len(self.dict_sentence_entries_v40):
            self.dict_sentence_entries_v40[idx+1][1].focus_set()
        return True
    ent.configure(fg=V40_BAD)
    _v40_beep(self, "wrong")
    _v40_speak_silent(self, target)
    return False

def _v40_check_split_current(self):
    chunks = _v40_semantic_chunks(_v40_current_text(self))
    if not chunks:
        return False
    idx = max(0, min(getattr(self, "dict_split_idx_v40", 0), len(chunks)-1))
    target = chunks[idx]["text"]
    ent = getattr(self, "dict_split_entry_v40", None)
    ans = ent.get().strip() if ent is not None else ""
    if ans.lower() == target.lower():
        _v40_beep(self, "word_ok")
        self.dict_split_done_v40 = getattr(self, "dict_split_done_v40", set())
        self.dict_split_done_v40.add(idx)
        if idx + 1 < len(chunks):
            self.dict_split_idx_v40 = idx + 1
            _v40_rebuild_input_ui(self)
        else:
            _v40_beep(self, "sentence_ok")
            try:
                if hasattr(self, "dict_result_var_v33"):
                    self.dict_result_var_v33.set("✅ 拆分完成，可以返回整句模式。")
            except Exception: pass
        return True
    _v40_beep(self, "wrong")
    _v40_speak_silent(self, target)
    return False

def _v40_submit_sentence_all(self):
    # If sentence UI entries exist, validate all.
    ok_all = True
    if hasattr(self, "dict_sentence_entries_v40") and self.dict_sentence_entries_v40:
        for i in range(len(self.dict_sentence_entries_v40)):
            ok_all = _v40_check_sentence_block(self, i) and ok_all
        if ok_all:
            _v40_beep(self, "sentence_ok")
            try:
                if hasattr(self, "dict_result_var_v33"):
                    self.dict_result_var_v33.set("✅ 整句正确")
            except Exception: pass
        return ok_all
    # If in split, check current block.
    if getattr(getattr(self, "dict_mode_v40", None), "get", lambda:"sentence")() == "split":
        return _v40_check_split_current(self)
    return False

def _v40_patch_play_buttons(self):
    # Replace visible play buttons in dictation with silent TTS when possible.
    try:
        self.bind_all("<Control-r>", lambda e: (_v40_speak_silent(self), "break"))
    except Exception:
        pass

def _v40_patch_refresh_current():
    for name in ("_dict_refresh_current_v33", "_dict_refresh_current_v32", "_dict_refresh_current"):
        fn = globals().get(name)
        if callable(fn) and not getattr(fn, "_v40_wrapped", False):
            def make_wrap(old):
                def wrapped(app_self, *a, **kw):
                    r = old(app_self, *a, **kw)
                    try:
                        _v40_rebuild_input_ui(app_self)
                    except Exception as e:
                        _v40_log(app_self, f"V40输入区重绘失败：{type(e).__name__}: {e}", "warn")
                    return r
                wrapped._v40_wrapped = True
                return wrapped
            globals()[name] = make_wrap(fn)

_old_main_init_v40 = MainApp.__init__
def _main_init_v40(self):
    _old_main_init_v40(self)
    try:
        _v40_patch_refresh_current()
        _v40_patch_play_buttons(self)
        # Do not show old black frame prompt. Rebuild into clean line UI.
        _v40_rebuild_input_ui(self)
        self.log("【V40新功能上线】听写输入区已重构为横线分块输入；发音改为静默播放，不再弹出黑框/外部播放窗。", "ok")
        self.log("V40拆分：拆分模式只显示当前句子成分块；整句模式显示所有横线块。Space 判断块，Enter 提交整句。", "info")
        self.log("V40发音建议：高质量语音优先使用 Edge Neural / Azure Neural；本地 SAPI 只作为兜底。", "info")
    except Exception as e:
        try:
            self.log(f"V40初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v40
APP_TITLE = "PlayPhrase Studio Clean v40 · 静默发音+横线分块输入版"


# ──────────────────────────────────────────────────────────────────────
# V41 Dictation material router + multi-accent neural voice selector
# 从精选池 / 本地视频字幕组合 / TXT/SRT 三类素材分别路由：视频播放、音频播放、翻译缓存。
# 只修听写模式资源与发音路由，不改美化视频主链。
# ──────────────────────────────────────────────────────────────────────
import threading as _threading_v41
import subprocess as _subprocess_v41
import tempfile as _tempfile_v41
import hashlib as _hashlib_v41
import json as _json_v41
import os as _os_v41
from pathlib import Path as _Path_v41

V41_VIDEO_EXTS = {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"}
V41_AUDIO_EXTS = {".mp3", ".wav", ".flac", ".m4a", ".aac", ".ogg"}
V41_TEXT_EXTS = {".txt", ".srt", ".ass", ".ssa", ".vtt"}
V41_MEDIA_EXTS = V41_VIDEO_EXTS | V41_AUDIO_EXTS

# Edge/Azure neural voice list. Edge-TTS 可直接用；Azure 可以复用同名 voice。
V41_VOICE_PRESETS = {
    "美音 Jenny 女声": {"engine": "edge", "voice": "en-US-JennyNeural", "accent": "US", "gender": "Female"},
    "美音 Aria 女声": {"engine": "edge", "voice": "en-US-AriaNeural", "accent": "US", "gender": "Female"},
    "美音 Guy 男声": {"engine": "edge", "voice": "en-US-GuyNeural", "accent": "US", "gender": "Male"},
    "英音 Sonia 女声": {"engine": "edge", "voice": "en-GB-SoniaNeural", "accent": "UK", "gender": "Female"},
    "英音 Libby 女声": {"engine": "edge", "voice": "en-GB-LibbyNeural", "accent": "UK", "gender": "Female"},
    "英音 Ryan 男声": {"engine": "edge", "voice": "en-GB-RyanNeural", "accent": "UK", "gender": "Male"},
    "加拿大 Clara 女声": {"engine": "edge", "voice": "en-CA-ClaraNeural", "accent": "CA", "gender": "Female"},
    "加拿大 Liam 男声": {"engine": "edge", "voice": "en-CA-LiamNeural", "accent": "CA", "gender": "Male"},
    "澳洲 Natasha 女声": {"engine": "edge", "voice": "en-AU-NatashaNeural", "accent": "AU", "gender": "Female"},
    "澳洲 William 男声": {"engine": "edge", "voice": "en-AU-WilliamNeural", "accent": "AU", "gender": "Male"},
    "爱尔兰 Emily 女声": {"engine": "edge", "voice": "en-IE-EmilyNeural", "accent": "IE", "gender": "Female"},
    "印度 Neerja 女声": {"engine": "edge", "voice": "en-IN-NeerjaNeural", "accent": "IN", "gender": "Female"},
    "印度 Prabhat 男声": {"engine": "edge", "voice": "en-IN-PrabhatNeural", "accent": "IN", "gender": "Male"},
    "Windows SAPI 本地兜底": {"engine": "sapi", "voice": "", "accent": "LOCAL", "gender": ""},
    "原片音频/视频源": {"engine": "original", "voice": "", "accent": "ORIGINAL", "gender": ""},
}

def _v41_log(self, msg, level="info"):
    try:
        self.log(msg, level)
    except Exception:
        print(msg)

def _v41_no_window_kwargs():
    if _os_v41.name != "nt":
        return {}
    si = _subprocess_v41.STARTUPINFO()
    si.dwFlags |= _subprocess_v41.STARTF_USESHOWWINDOW
    return {"creationflags": getattr(_subprocess_v41, "CREATE_NO_WINDOW", 0), "startupinfo": si}

def _v41_current_item(self):
    # Compatible with v33-v40.
    for name in ("dict_items_v33", "dict_items_v32", "dict_items", "dictation_items"):
        if hasattr(self, name):
            items = getattr(self, name)
            idx = int(getattr(self, "dict_index_v33", getattr(self, "dict_index_v32", getattr(self, "dict_index", 0))) or 0)
            if isinstance(items, list) and 0 <= idx < len(items):
                return items[idx]
    return None

def _v41_item_text(item):
    if isinstance(item, dict):
        return str(item.get("text") or item.get("en") or item.get("line") or item.get("sentence") or "")
    try:
        return str(getattr(item, "text", "") or item or "")
    except Exception:
        return ""

def _v41_item_zh(item):
    if isinstance(item, dict):
        return str(item.get("zh") or item.get("cn") or item.get("translation") or "")
    try:
        return str(getattr(item, "zh", "") or "")
    except Exception:
        return ""

def _v41_set_item_zh(item, zh):
    if isinstance(item, dict):
        item["zh"] = zh
        item["translation"] = zh
    else:
        try:
            setattr(item, "zh", zh)
        except Exception:
            pass

def _v41_find_first_path(item):
    """Find local path from dict/clip/resource meta."""
    paths = []
    if isinstance(item, dict):
        for k in ("local_path", "media_path", "audio_path", "video_path", "path", "file", "subtitle_path", "text_path"):
            if item.get(k):
                paths.append(item.get(k))
        for nested in ("clip", "resource_meta"):
            obj = item.get(nested)
            if isinstance(obj, dict):
                for k in ("local_path", "media_path", "audio_path", "video_path", "path", "file", "subtitle_path"):
                    if obj.get(k):
                        paths.append(obj.get(k))
            elif obj is not None:
                for k in ("local_path", "media_path", "audio_path", "video_path", "path"):
                    p = getattr(obj, k, None)
                    if p:
                        paths.append(p)
    else:
        for k in ("local_path", "media_path", "audio_path", "video_path", "path"):
            p = getattr(item, k, None)
            if p:
                paths.append(p)
    for p in paths:
        try:
            pp = _Path_v41(str(p))
            if pp.exists():
                return pp
        except Exception:
            pass
    return None

def _v41_item_video_url(item):
    if isinstance(item, dict):
        for k in ("video_url", "url", "remote_url"):
            if item.get(k) and str(item.get(k)).startswith(("http://", "https://")):
                return str(item.get(k))
        clip = item.get("clip")
        if clip is not None:
            for k in ("video_url", "url"):
                v = getattr(clip, k, None)
                if v and str(v).startswith(("http://", "https://")):
                    return str(v)
    else:
        for k in ("video_url", "url"):
            v = getattr(item, k, None)
            if v and str(v).startswith(("http://", "https://")):
                return str(v)
    return ""

def _v41_detect_material_type(item):
    """Return: playphrase_video / local_video_subtitle / local_audio / text_only / unknown."""
    p = _v41_find_first_path(item)
    url = _v41_item_video_url(item)
    if url:
        return "playphrase_video"
    if p:
        ext = p.suffix.lower()
        if ext in V41_VIDEO_EXTS:
            return "local_video_subtitle"
        if ext in V41_AUDIO_EXTS:
            return "local_audio"
        if ext in V41_TEXT_EXTS:
            return "text_only"
    text = _v41_item_text(item)
    if text:
        return "text_only"
    return "unknown"

def _v41_find_subtitle_for_media(media: _Path_v41):
    if not media:
        return None
    base = media.with_suffix("")
    candidates = []
    for ext in (".srt", ".ass", ".ssa", ".vtt", ".txt"):
        candidates.append(base.with_suffix(ext))
        candidates.append(_Path_v41(str(base) + ".en" + ext))
        candidates.append(_Path_v41(str(base) + ".eng" + ext))
        candidates.append(_Path_v41(str(base) + ".zh" + ext))
        candidates.append(_Path_v41(str(base) + ".chs" + ext))
    for c in candidates:
        if c.exists():
            return c
    try:
        nearby = list(media.parent.glob(media.stem + "*"))
        for p in nearby:
            if p.suffix.lower() in V41_TEXT_EXTS:
                return p
    except Exception:
        pass
    return None

def _v41_translation_cache_path_for_item(item):
    p = _v41_find_first_path(item)
    if p:
        if p.suffix.lower() in V41_VIDEO_EXTS:
            sub = _v41_find_subtitle_for_media(p)
            if sub:
                return _Path_v41(str(sub.with_suffix("")) + ".zh_cache.json")
            return _Path_v41(str(p.with_suffix("")) + ".zh_cache.json")
        if p.suffix.lower() in V41_TEXT_EXTS:
            return _Path_v41(str(p.with_suffix("")) + ".zh_cache.json")
        if p.suffix.lower() in V41_AUDIO_EXTS:
            return _Path_v41(str(p.with_suffix("")) + ".zh_cache.json")
    text = _v41_item_text(item)
    h = _hashlib_v41.md5(text.encode("utf-8", errors="ignore")).hexdigest()[:16]
    root = _Path_v41("playphrase_cache") / "dictation_translation"
    root.mkdir(parents=True, exist_ok=True)
    return root / f"{h}.zh_cache.json"

def _v41_load_cached_translation(item):
    fp = _v41_translation_cache_path_for_item(item)
    try:
        if fp and fp.exists():
            data = _json_v41.loads(fp.read_text("utf-8"))
            if isinstance(data, dict):
                return str(data.get("zh") or "")
    except Exception:
        pass
    return ""

def _v41_save_cached_translation(item, zh):
    fp = _v41_translation_cache_path_for_item(item)
    try:
        if fp:
            fp.parent.mkdir(parents=True, exist_ok=True)
            fp.write_text(_json_v41.dumps({"zh": zh, "text": _v41_item_text(item)}, ensure_ascii=False, indent=2), "utf-8")
    except Exception:
        pass

def _v41_update_cn_display(self, zh):
    for name in ("dict_cn_prompt_var_v33", "dict_cn_var", "dict_zh_var", "dictation_cn_var"):
        if hasattr(self, name):
            try:
                getattr(self, name).set(zh)
            except Exception:
                pass
    try:
        # v40 line UI uses label
        if hasattr(self, "dict_zh_label_v40"):
            self.dict_zh_label_v40.configure(text=zh)
    except Exception:
        pass

def _v41_translate_item_async(self, item=None, force=False):
    item = item or _v41_current_item(self)
    if not item:
        return
    cached = _v41_load_cached_translation(item)
    if cached and not force:
        _v41_set_item_zh(item, cached)
        _v41_update_cn_display(self, cached)
        return
    text = _v41_item_text(item)
    if not text:
        return
    def run():
        zh = ""
        try:
            # Use existing translator. Avoid UI blocking.
            engine = "smart"
            for n in ("dict_translate_engine_var_v35", "dict_translate_engine_var_v34", "dict_translate_engine_var_v32"):
                if hasattr(self, n):
                    try:
                        engine = getattr(self, n).get() or "smart"
                    except Exception:
                        pass
            if hasattr(self, "translator"):
                zh = self.translator.translate_one(text, engine)
        except Exception as e:
            _v41_log(self, f"V41后台翻译失败：{type(e).__name__}: {e}", "warn")
        if zh:
            _v41_set_item_zh(item, zh)
            _v41_save_cached_translation(item, zh)
            try:
                self.after(0, lambda: _v41_update_cn_display(self, zh))
            except Exception:
                _v41_update_cn_display(self, zh)
    _threading_v41.Thread(target=run, daemon=True).start()

def _v41_play_video_current(self):
    item = _v41_current_item(self)
    if not item:
        return
    typ = _v41_detect_material_type(item)
    p = _v41_find_first_path(item)
    url = _v41_item_video_url(item)
    if typ == "text_only":
        _v41_log(self, "TXT/SRT 纯文本素材不支持视频播放；请使用播放音频/TTS。", "warn")
        return
    if typ == "local_video_subtitle" and p:
        try:
            # Prefer Qt helper/client if available
            if hasattr(self, "player_client") and self.player_client:
                try:
                    self.player_client.play(str(p))
                    return
                except Exception:
                    pass
            if _os_v41.name == "nt":
                _os_v41.startfile(str(p))
            else:
                _subprocess_v41.Popen(["xdg-open", str(p)], **_v41_no_window_kwargs())
            _v41_log(self, f"视频播放：本地视频源 {p}", "ok")
            _v41_translate_item_async(self, item, force=False)
            return
        except Exception as e:
            _v41_log(self, f"本地视频播放失败：{type(e).__name__}: {e}", "warn")
    if typ == "playphrase_video":
        # If already cached locally, use local path; otherwise open URL as remote source.
        if p and p.suffix.lower() in V41_VIDEO_EXTS:
            try:
                if _os_v41.name == "nt":
                    _os_v41.startfile(str(p))
                else:
                    _subprocess_v41.Popen(["xdg-open", str(p)], **_v41_no_window_kwargs())
                return
            except Exception:
                pass
        if url:
            try:
                if _os_v41.name == "nt":
                    _os_v41.startfile(url)
                else:
                    _subprocess_v41.Popen(["xdg-open", url], **_v41_no_window_kwargs())
                _v41_log(self, "视频播放：在线视频源/PlayPhrase URL。", "ok")
                return
            except Exception as e:
                _v41_log(self, f"在线视频源打开失败：{type(e).__name__}: {e}", "warn")
    _v41_log(self, "当前素材没有可用视频源。", "warn")

def _v41_mci_play(path: _Path_v41):
    if _os_v41.name != "nt":
        try:
            _subprocess_v41.Popen(["xdg-open", str(path)], **_v41_no_window_kwargs())
        except Exception:
            pass
        return
    import ctypes, uuid, time
    alias = "ppv41_" + uuid.uuid4().hex[:10]
    winmm = ctypes.windll.winmm
    def mci(cmd):
        buf = ctypes.create_unicode_buffer(512)
        winmm.mciSendStringW(cmd, buf, 511, 0)
        return buf.value
    target = str(path).replace('"', "")
    mci(f'open "{target}" type mpegvideo alias {alias}')
    mci(f'play {alias}')
    def closer():
        time.sleep(30)
        try:
            mci(f"close {alias}")
        except Exception:
            pass
    _threading_v41.Thread(target=closer, daemon=True).start()

def _v41_edge_tts(text, voice_name=None):
    preset = V41_VOICE_PRESETS.get(voice_name or "", None)
    voice = (preset or V41_VOICE_PRESETS["美音 Jenny 女声"])["voice"] or "en-US-JennyNeural"
    out = _Path_v41(_tempfile_v41.gettempdir()) / ("pp_v41_tts_" + _hashlib_v41.md5((voice + text).encode("utf-8", errors="ignore")).hexdigest() + ".mp3")
    if out.exists() and out.stat().st_size > 1000:
        return out
    cmd = [sys.executable, "-m", "edge_tts", "--voice", voice, "--text", text, "--write-media", str(out)]
    r = _subprocess_v41.run(cmd, capture_output=True, text=True, timeout=45, **_v41_no_window_kwargs())
    if r.returncode == 0 and out.exists() and out.stat().st_size > 1000:
        return out
    return None

def _v41_sapi_speak(text):
    if _os_v41.name != "nt":
        return False
    try:
        import win32com.client
        speaker = win32com.client.Dispatch("SAPI.SpVoice")
        speaker.Speak(text)
        return True
    except Exception:
        return False

def _v41_play_audio_current(self):
    item = _v41_current_item(self)
    if not item:
        return
    typ = _v41_detect_material_type(item)
    p = _v41_find_first_path(item)
    text = _v41_item_text(item)
    # For local audio, play silently with MCI.
    if p and p.suffix.lower() in V41_AUDIO_EXTS:
        _v41_mci_play(p)
        _v41_log(self, f"音频播放：本地音频源 {p}", "ok")
        _v41_translate_item_async(self, item, force=False)
        return
    # For local video, audio mode should not show picture. Try to extract/position rough audio. 
    # If segment timing is unavailable, play TTS to avoid showing video.
    if typ == "local_video_subtitle" and p and p.suffix.lower() in V41_VIDEO_EXTS:
        # If item has audio clip path extracted, play it; otherwise use TTS of current sentence.
        audio_path = None
        if isinstance(item, dict):
            audio_path = item.get("audio_path")
        if audio_path and _Path_v41(str(audio_path)).exists():
            _v41_mci_play(_Path_v41(str(audio_path)))
            return
        _v41_log(self, "本地视频音频模式：未找到独立音频切片，改用发音引擎静默朗读当前句。", "info")
    # Text/SRT or fallback: use TTS engine.
    voice_name = None
    for n in ("dict_tts_voice_var_v41", "dict_tts_engine_v33", "dict_tts_engine_v32"):
        if hasattr(self, n):
            try:
                voice_name = getattr(self, n).get()
            except Exception:
                pass
    def run():
        try:
            preset = V41_VOICE_PRESETS.get(voice_name or "", None)
            if preset and preset["engine"] == "original":
                if p and p.suffix.lower() in V41_MEDIA_EXTS:
                    _v41_mci_play(p)
                    return
            f = _v41_edge_tts(text, voice_name)
            if f:
                _v41_mci_play(f)
                return
        except Exception as e:
            _v41_log(self, f"V41 Edge发音失败，回退SAPI：{type(e).__name__}: {e}", "warn")
        if text:
            _v41_sapi_speak(text)
    _threading_v41.Thread(target=run, daemon=True).start()
    _v41_translate_item_async(self, item, force=False)

def _v41_patch_existing_play(self):
    # Replace Ctrl+R / main play with audio route. Video has dedicated button.
    try:
        self.bind_all("<Control-r>", lambda e: (_v41_play_audio_current(self), "break"))
    except Exception:
        pass

def _v41_add_route_panel(self):
    """Add material-routing controls into dictation control panel without destroying existing UI."""
    parent = getattr(self, "dict_mango_control_panel", None)
    if parent is None:
        # fallback right panel not available
        return
    if getattr(self, "_v41_route_panel_added", False):
        return
    try:
        box = ttk.LabelFrame(parent, text="素材播放路由 V41", padding=8)
        box.pack(fill="x", padx=12, pady=8)
        self.dict_tts_voice_var_v41 = tk.StringVar(value="美音 Jenny 女声")
        ttk.Label(box, text="发音角色/地区").pack(anchor="w")
        ttk.Combobox(box, textvariable=self.dict_tts_voice_var_v41,
                     values=list(V41_VOICE_PRESETS.keys()), state="readonly", width=28).pack(fill="x", pady=3)
        ttk.Button(box, text="播放视频（仅视频素材）", command=lambda: _v41_play_video_current(self)).pack(fill="x", pady=3)
        ttk.Button(box, text="播放音频 / TTS（无黑框）", command=lambda: _v41_play_audio_current(self)).pack(fill="x", pady=3)
        ttk.Button(box, text="后台翻译并缓存", command=lambda: _v41_translate_item_async(self, force=True)).pack(fill="x", pady=3)
        self.dict_material_status_var_v41 = tk.StringVar(value="素材路由：等待选择")
        ttk.Label(box, textvariable=self.dict_material_status_var_v41, style="Dim.TLabel", wraplength=260).pack(fill="x", pady=3)
        self._v41_route_panel_added = True
    except Exception as e:
        _v41_log(self, f"V41播放路由面板添加失败：{type(e).__name__}: {e}", "warn")

def _v41_update_material_status(self):
    item = _v41_current_item(self)
    if not item:
        return
    typ = _v41_detect_material_type(item)
    p = _v41_find_first_path(item)
    msg = {
        "playphrase_video": "精选池/PlayPhrase：视频=本地缓存或在线视频；音频=本地切片或TTS。",
        "local_video_subtitle": "本地视频+字幕：视频=原生播放；音频=无画面播放/引擎；翻译=缓存写入。",
        "local_audio": "本地音频：视频不可用；音频=本地音频；翻译=缓存。",
        "text_only": "TXT/SRT：不支持视频；音频=本地音频或TTS；翻译=缓存。",
        "unknown": "未知素材：请检查路径/URL。",
    }.get(typ, typ)
    if p:
        msg += f"\n路径：{p}"
    try:
        if hasattr(self, "dict_material_status_var_v41"):
            self.dict_material_status_var_v41.set(msg)
    except Exception:
        pass

def _v41_patch_refresh_current():
    for name in ("_dict_refresh_current_v33", "_dict_refresh_current_v32", "_dict_refresh_current"):
        fn = globals().get(name)
        if callable(fn) and not getattr(fn, "_v41_wrapped", False):
            def make_wrap(old):
                def wrapped(app_self, *a, **kw):
                    r = old(app_self, *a, **kw)
                    try:
                        _v41_update_material_status(app_self)
                        _v41_translate_item_async(app_self, force=False)
                    except Exception:
                        pass
                    return r
                wrapped._v41_wrapped = True
                return wrapped
            globals()[name] = make_wrap(fn)

def _v41_enhance_resource_scan(self):
    """Patch resource scanner result to preserve paths and type meta, if resource_items_v35 exists."""
    try:
        rows = getattr(self, "resource_items_v35", None)
        if isinstance(rows, list):
            for r in rows:
                if isinstance(r, dict):
                    p = _Path_v41(str(r.get("path","")))
                    if p.exists():
                        r["media_path"] = str(p)
                        r["source_type"] = "local_video_subtitle" if p.suffix.lower() in V41_VIDEO_EXTS else ("local_audio" if p.suffix.lower() in V41_AUDIO_EXTS else "text_only")
                        sub = _v41_find_subtitle_for_media(p) if p.suffix.lower() in V41_VIDEO_EXTS else None
                        if sub:
                            r["subtitle_path"] = str(sub)
    except Exception:
        pass

_old_main_init_v41 = MainApp.__init__
def _main_init_v41(self):
    _old_main_init_v41(self)
    try:
        _v41_patch_refresh_current()
        _v41_patch_existing_play(self)
        _v41_add_route_panel(self)
        _v41_enhance_resource_scan(self)
        _v41_update_material_status(self)
        self.log("【V41新功能上线】听写素材已按来源路由：精选池/本地视频字幕/TXT-SRT 分别处理视频、音频、翻译缓存。", "ok")
        self.log("V41发音角色：已增加美音/英音/加拿大/澳洲/印度等 Edge Neural 角色；Ctrl+R 默认走无黑框音频/TTS。", "ok")
    except Exception as e:
        try:
            self.log(f"V41初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v41
APP_TITLE = "PlayPhrase Studio Clean v41 · 听写素材路由+多地区发音版"


