V42_VIDEO_EXTS = {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"}
V42_AUDIO_EXTS = {".mp3", ".wav", ".flac", ".m4a", ".aac", ".ogg", ".wma"}
V42_TEXT_EXTS = {".txt", ".srt", ".ass", ".ssa", ".vtt", ".csv"}
V42_MEDIA_EXTS = V42_VIDEO_EXTS | V42_AUDIO_EXTS

