def _v45_recite_auto_check(self):
    word=(getattr(self,"recite_word_var_v37",tk.StringVar()).get() or "").strip()
    ans=(getattr(self,"recite_answer_var_v37",tk.StringVar()).get() or "").strip()
    if not word or not ans: return
    if ans.lower()==word.lower():
        try:
            self.recite_line_canvas_v45.delete("all"); self.recite_line_canvas_v45.create_line(2,4,418,4,fill="#22c55e",width=3)
            self.recite_feedback_var_v37.set("✅ 正确，自动进入下一个。")
        except Exception: pass
        try: self.after(350,lambda:_recite_next_v37(self))
        except Exception: pass
    elif len(ans)>=len(word):
        try:
            self.recite_line_canvas_v45.delete("all"); self.recite_line_canvas_v45.create_line(2,4,418,4,fill="#ef4444",width=3)
            self.recite_feedback_var_v37.set("❌ 错误，立即发音。")
        except Exception: pass
        _v45_speak_edge_api(self,word)

