# ──────────────────────────────────────────────────────────────────────
# V46: single-screen dictation + open hotkeys + precise word feedback + recite playlist
# 目标：
# 1) 开放单键快捷键；全部听写按钮加入设置，并同步底部快捷键显示。
# 2) 取消旧“盲听模式”大窗口/传统输入框；中间学习区只保留一个横线界面，按钮集中到底部。
# 3) 整句播放=整句呈现；拆分播放=句子成分逐个呈现；“下一行继续拆分”改为“自动跳转下一行”。
# 4) 错误提示精确到词位：正确词变绿；漏词/多词/拼写/词形/介词等错误分类。
# 5) 背诵模式补齐：单词列表、排序、点击发音、选中播放、全文播放、横线输入。
# 只修听写/背诵/快捷键/资源站展示；不动美化视频渲染主链。
# ──────────────────────────────────────────────────────────────────────
import difflib as _difflib_v46
import threading as _threading_v46
import time as _time_v46
from pathlib import Path as _Path_v46

V46_BG = "#090D16"
V46_CARD = "#05070D"
V46_TEXT = "#F9FAFB"
V46_MUTED = "#94A3B8"
V46_LINE = "#CBD5E1"
V46_ACTIVE = "#8B5CF6"
V46_OK = "#22C55E"
V46_BAD = "#EF4444"
V46_WARN = "#F59E0B"
V46_BLUE = "#60A5FA"

def _v46_log(self, msg, level="info"):
    try:
        self.log(msg, level)
    except Exception:
        print(msg)

def _v46_norm(s):
    try:
        return norm(s)
    except Exception:
        return re.sub(r"\s+", " ", str(s or "")).strip()

def _v46_tokens(s):
    return re.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v46_current_material(self):
    for name, idxn in [
        ("dictation_materials_v30", "dictation_index_v30"),
        ("dict_items_v33", "dict_index_v33"),
        ("dict_items_v32", "dict_index_v32"),
        ("dict_items", "dict_index"),
    ]:
        try:
            arr = getattr(self, name, None)
            idx = int(getattr(self, idxn, 0))
            if isinstance(arr, list) and 0 <= idx < len(arr):
                return arr[idx]
        except Exception:
            pass
    return None

def _v46_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(getattr(m, "text", "") or m or "")

def _v46_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or "")
    return str(getattr(m, "zh", "") or "")

def _v46_item_path(m):
    paths = []
    if isinstance(m, dict):
        for k in ("local_path", "media_path", "video_path", "audio_path", "path", "file", "subtitle_path"):
            if m.get(k): paths.append(m.get(k))
        for nested in ("clip", "resource_meta"):
            obj = m.get(nested)
            if isinstance(obj, dict):
                for k in ("local_path", "media_path", "video_path", "audio_path", "path", "file"):
                    if obj.get(k): paths.append(obj.get(k))
            elif obj:
                for k in ("local_path", "media_path", "video_path", "audio_path", "path"):
                    v = getattr(obj, k, None)
                    if v: paths.append(v)
    elif m:
        for k in ("local_path", "media_path", "video_path", "audio_path", "path"):
            v = getattr(m, k, None)
            if v: paths.append(v)
    for p in paths:
        try:
            pp = _Path_v46(str(p))
            if pp.exists(): return pp
        except Exception:
            pass
    return None

def _v46_item_url(m):
    if isinstance(m, dict):
        for k in ("video_url", "url", "remote_url"):
            v = m.get(k)
            if v and str(v).startswith(("http://", "https://")):
                return str(v)
        c = m.get("clip")
        if c:
            for k in ("video_url", "url"):
                v = getattr(c, k, None)
                if v and str(v).startswith(("http://", "https://")):
                    return str(v)
    return ""

def _v46_source_bucket(m):
    p = _v46_item_path(m)
    u = _v46_item_url(m)
    st = str(m.get("source_type","")) if isinstance(m, dict) else ""
    if u or "online" in st or "playphrase" in st:
        return "在线"
    if p and p.suffix.lower() in {".txt",".srt",".ass",".ssa",".vtt",".csv"}:
        return "文本"
    if p:
        return "本地"
    return "文本"

def _v46_source_parts(m):
    p = _v46_item_path(m)
    if p:
        # keep tree readable, use last 4 directories
        return [str(x) for x in p.parts[-5:-1]] or [p.parent.name]
    u = _v46_item_url(m)
    if u:
        return ["在线URL"]
    title = str(m.get("title") or m.get("keyword") or "纯文本") if isinstance(m, dict) else "纯文本"
    return [title or "纯文本"]

def _v46_semantic_chunks(text):
    # Reuse V45/V40 semantic chunkers if available.
    for fn in ("_v45_semantic_chunks", "_v40_semantic_chunks"):
        if fn in globals():
            try:
                out = globals()[fn](text)
                if out:
                    return [{"text": x.get("text", str(x)), "role": x.get("role", "句子成分")} if isinstance(x, dict) else {"text": str(x), "role": "句子成分"} for x in out]
            except Exception:
                pass
    toks = _v46_tokens(text)
    return [{"text": t, "role": _v46_guess_role(t)} for t in toks]

def _v46_guess_role(block):
    b = str(block or "").strip()
    low = b.lower()
    if " " in b:
        return "句子成分"
    if low in {"do","does","did","is","are","was","were","will","would","can","could","should","have","has","had","am"}:
        return "助动词"
    if low in {"to","from","in","on","at","with","for","of","by","about","around","into","over","under","through"}:
        return "介词"
    if low in {"a","an","the","this","that","these","those","my","your","his","her","our","their"}:
        return "限定词"
    if low.endswith("ly"):
        return "副词"
    if low.endswith(("ed","ing")):
        return "动词"
    if b[:1].isupper():
        return "专有名词"
    return "词性提示"

def _v46_simple_stem(w):
    w = str(w or "").lower()
    for suf in ("ies","ied"):
        if w.endswith(suf) and len(w) > len(suf)+1:
            return w[:-3] + "y"
    for suf in ("ing","ed","es","s"):
        if w.endswith(suf) and len(w) > len(suf)+2:
            return w[:-len(suf)]
    return w

def _v46_word_error_type(ans, tgt, role=""):
    a = str(ans or "").strip().lower()
    t = str(tgt or "").strip().lower()
    if not a:
        return "漏词", V46_BAD
    if a == t:
        return "正确", V46_OK
    role_l = str(role or "")
    preps = {"to","from","in","on","at","with","for","of","by","about","around","into","over","under","through"}
    dets = {"a","an","the","this","that","these","those"}
    if t in preps and a in preps:
        return "介词错误", V46_WARN
    if t in dets and a in dets:
        return "限定词错误", V46_WARN
    if _v46_simple_stem(a) == _v46_simple_stem(t):
        return "词形错误", V46_WARN
    sim = _difflib_v46.SequenceMatcher(None, a, t).ratio()
    if sim >= 0.74:
        return "拼写错误", V46_WARN
    return "用词错误", V46_BAD

def _v46_analyze_phrase(ans, target, role=""):
    a_words = _v46_tokens(ans)
    t_words = _v46_tokens(target)
    results = []
    for i, tw in enumerate(t_words):
        aw = a_words[i] if i < len(a_words) else ""
        err, color = _v46_word_error_type(aw, tw, role)
        results.append({"pos": i+1, "answer": aw, "target": tw, "type": err, "color": color})
    if len(a_words) > len(t_words):
        for j, extra in enumerate(a_words[len(t_words):], len(t_words)+1):
            results.append({"pos": j, "answer": extra, "target": "", "type": "多词", "color": V46_BAD})
    ok = bool(t_words) and len(a_words) == len(t_words) and all(x["type"] == "正确" for x in results)
    return ok, results

def _v46_beep(self, kind="type"):
    try:
        import winsound
        if kind == "ok":
            winsound.Beep(1200, 55)
        elif kind == "sentence":
            winsound.Beep(880, 55); winsound.Beep(1320, 80)
        elif kind == "bad":
            winsound.Beep(260, 110)
        else:
            winsound.Beep(760, 18)
    except Exception:
        try: self.bell()
        except Exception: pass

# ---------------- Shortcut system ----------------
def _v46_default_hotkeys():
    return {
        "主播放/当前音频": "R",
        "视频播放": "V",
        "暂停/继续": "P",
        "上一句": "Left",
        "下一句": "Right",
        "判断当前块": "Space",
        "提交整句": "Enter",
        "提示": "H",
        "整句/拆分切换": "S",
        "显示/隐藏中文": "C",
        "跳过当前块": "K",
        "自动跳转下一行": "A",
        "窗口/全屏": "F11",
        "隐藏/显示素材池": "L",
        "复制当前句": "Ctrl+C",
        "保存进度": "Ctrl+S",
        "加载进度": "Ctrl+O",
    }

def _v46_get_hotkeys(self):
    if not hasattr(self, "dict_hotkeys_v46"):
        old = {}
        try:
            old = dict(getattr(self, "dict_hotkeys_v42", {}) or {})
        except Exception:
            old = {}
        self.dict_hotkeys_v46 = _v46_default_hotkeys()
        # preserve useful old mappings
        mapping = {
            "主播放/音频": "主播放/当前音频",
            "视频播放": "视频播放",
            "暂停/继续": "暂停/继续",
            "判断当前块": "判断当前块",
            "提交整句": "提交整句",
            "上一句": "上一句",
            "下一句": "下一句",
            "提示": "提示",
            "拆分/整句": "整句/拆分切换",
            "显示/隐藏中文": "显示/隐藏中文",
        }
        for k, v in old.items():
            if k in mapping:
                self.dict_hotkeys_v46[mapping[k]] = v
    return self.dict_hotkeys_v46

def _v46_hotkey_to_tk(seq):
    s = str(seq or "").strip()
    if not s:
        raise ValueError("快捷键不能为空")
    s = s.replace(" ", "+")
    parts = [p for p in re.split(r"\+", s) if p]
    alias = {
        "ctrl": "Control", "control": "Control",
        "alt": "Alt", "shift": "Shift",
        "space": "space", "enter": "Return", "return": "Return",
        "esc": "Escape", "escape": "Escape",
        "left": "Left", "right": "Right", "up": "Up", "down": "Down",
        "f1":"F1","f2":"F2","f3":"F3","f4":"F4","f5":"F5","f6":"F6","f7":"F7","f8":"F8","f9":"F9","f10":"F10","f11":"F11","f12":"F12",
    }
    if len(parts) == 1:
        key = alias.get(parts[0].lower(), parts[0])
        if len(key) == 1 and key.isalpha():
            key = key.lower()
        return f"<{key}>"
    mods = [alias.get(p.lower(), p) for p in parts[:-1]]
    key = alias.get(parts[-1].lower(), parts[-1])
    if len(key) == 1 and key.isalpha():
        key = key.lower()
    return "<" + "-".join(mods + [key]) + ">"

def _v46_focus_is_text_input(self):
    try:
        w = self.focus_get()
        return isinstance(w, (tk.Entry, tk.Text, ttk.Entry))
    except Exception:
        return False

def _v46_action_map(self):
    return {
        "主播放/当前音频": lambda: _v46_play_current(self),
        "视频播放": lambda: _v46_video_play(self),
        "暂停/继续": lambda: _v46_pause(self),
        "上一句": lambda: _v46_prev(self),
        "下一句": lambda: _v46_next(self),
        "判断当前块": lambda: _v46_force_check_current(self),
        "提交整句": lambda: _v46_submit_all(self),
        "提示": lambda: _v46_show_hint(self),
        "整句/拆分切换": lambda: _v46_toggle_play_mode(self),
        "显示/隐藏中文": lambda: _v46_toggle_cn(self),
        "跳过当前块": lambda: _v46_skip_current_chunk(self),
        "自动跳转下一行": lambda: _v46_toggle_auto_next_line(self),
        "窗口/全屏": lambda: getattr(self, "_dictation_fullscreen_toggle_v30", lambda: None)(),
        "隐藏/显示素材池": lambda: getattr(self, "_dictation_toggle_pool_v32", lambda: None)(),
        "复制当前句": lambda: _v46_copy_current(self),
        "保存进度": lambda: getattr(self, "_dictation_save_progress_v30", lambda: None)(),
        "加载进度": lambda: getattr(self, "_dictation_load_progress_v30", lambda: None)(),
    }

def _v46_unbind_known(self):
    keys = set()
    for v in list(_v46_default_hotkeys().values()) + list(getattr(self, "dict_hotkeys_v46", {}).values()):
        try: keys.add(_v46_hotkey_to_tk(v))
        except Exception: pass
    # include old keys
    for v in ["R","r","V","v","P","p","S","s","C","c","H","h","K","k","A","a","L","l","Space","Enter","Left","Right","Ctrl+R","Ctrl+Space","Ctrl+Left","Ctrl+Right","Ctrl+H","Ctrl+Shift+B","Ctrl+Shift+C","F11"]:
        try: keys.add(_v46_hotkey_to_tk(v))
        except Exception: pass
    for k in keys:
        try: self.unbind_all(k)
        except Exception: pass

def _v46_bind_hotkeys(self):
    _v46_unbind_known(self)
    hotkeys = _v46_get_hotkeys(self)
    actions = _v46_action_map(self)
    errors = []
    for action, hk in hotkeys.items():
        if action not in actions: 
            continue
        try:
            seq = _v46_hotkey_to_tk(hk)
            is_plain_letter = bool(re.fullmatch(r"[A-Za-z]", str(hk).strip()))
            def handler(e=None, act=action, plain=is_plain_letter):
                # Open single-key hotkeys are allowed. To avoid breaking English typing,
                # plain letters do not fire while cursor is inside an Entry/Text.
                if plain and _v46_focus_is_text_input(self):
                    return None
                try:
                    actions[act]()
                except Exception as ex:
                    _v46_log(self, f"快捷键执行失败 {act}: {type(ex).__name__}: {ex}", "warn")
                return "break"
            self.bind_all(seq, handler)
        except Exception as e:
            errors.append(f"{action}:{hk}({e})")
    _v46_refresh_shortcut_display(self)
    if errors:
        _v46_log(self, "V46快捷键绑定部分失败：" + "；".join(errors), "warn")
    else:
        _v46_log(self, "V46快捷键已绑定：开放单键；保存后同步到底部显示面板。", "ok")

def _v46_refresh_shortcut_display(self):
    hotkeys = _v46_get_hotkeys(self)
    # right settings tree
    try:
        tree = self.dictation_shortcut_tree_v30
        tree.delete(*tree.get_children())
        for i, (a, h) in enumerate(hotkeys.items()):
            tree.insert("", "end", iid=str(i), values=(a, h))
    except Exception:
        pass
    # bottom button labels
    try:
        for action, btn in getattr(self, "dict_v46_bottom_buttons", {}).items():
            hk = hotkeys.get(action, "")
            base = action.replace("/当前音频", "").replace("整句/拆分切换", "整句/拆分")
            btn.configure(text=f"{base} {hk}")
    except Exception:
        pass

def _v46_open_shortcut_editor(self):
    win = tk.Toplevel(self)
    win.title("V46 快捷键设置｜开放单键")
    win.geometry("720x620")
    frm = ttk.Frame(win, padding=14); frm.pack(fill="both", expand=True)
    ttk.Label(frm, text="快捷键设置：支持单键 / Ctrl / Alt / Shift / Enter / Space / F11", style="H.TLabel").pack(anchor="w")
    ttk.Label(frm, text="说明：已开放单个按键；但单独英文字母在输入框聚焦时不会触发，以免干扰英文打字。", style="Dim.TLabel", wraplength=660).pack(anchor="w", pady=(4,10))
    canvas = tk.Canvas(frm, highlightthickness=0)
    scroll = ttk.Scrollbar(frm, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=scroll.set)
    scroll.pack(side="right", fill="y")
    canvas.pack(side="left", fill="both", expand=True)
    inner = ttk.Frame(canvas)
    win_id = canvas.create_window((0,0), window=inner, anchor="nw")
    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfigure(win_id, width=e.width))
    vars_ = {}
    for action, hk in _v46_get_hotkeys(self).items():
        row = ttk.Frame(inner); row.pack(fill="x", pady=4)
        ttk.Label(row, text=action, width=18).pack(side="left")
        sv = tk.StringVar(value=hk); vars_[action] = sv
        ttk.Entry(row, textvariable=sv, width=24).pack(side="left", padx=8)
        ttk.Label(row, text="例：R / Space / Enter / Ctrl+R / F11", style="Dim.TLabel").pack(side="left")
    def save():
        new = {}
        used = {}
        for a, sv in vars_.items():
            hk = sv.get().strip()
            try:
                seq = _v46_hotkey_to_tk(hk)
            except Exception as e:
                messagebox.showwarning("快捷键非法", f"{a}: {hk}\n{e}")
                return
            if seq in used:
                messagebox.showwarning("快捷键冲突", f"{a} 与 {used[seq]} 使用了同一快捷键：{hk}")
                return
            used[seq] = a
            new[a] = hk
        self.dict_hotkeys_v46 = new
        _v46_bind_hotkeys(self)
        _v46_refresh_shortcut_display(self)
        messagebox.showinfo("已生效", "快捷键已保存，并已同步到底部快捷键显示面板。")
    btns = ttk.Frame(frm); btns.pack(fill="x", pady=(10,0))
    ttk.Button(btns, text="恢复默认", command=lambda: [vars_[k].set(v) for k, v in _v46_default_hotkeys().items() if k in vars_]).pack(side="left")
    ttk.Button(btns, text="保存并立即生效", style="Accent.TButton", command=save).pack(side="right")

# ---------------- unified dictation UI ----------------
def _v46_get_chunks(self):
    m = _v46_current_material(self)
    if not isinstance(m, dict):
        return _v46_semantic_chunks(_v46_item_text(m))
    text = _v46_item_text(m)
    chunks = m.get("_v46_chunks")
    if not chunks or m.get("_v46_chunks_text") != text:
        chunks = _v46_semantic_chunks(text)
        m["_v46_chunks"] = chunks
        m["_v46_chunks_text"] = text
        m["_v46_chunk_index"] = 0
    return chunks

def _v46_play_mode(self):
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    return self.dict_play_mode_v46.get()

def _v46_set_play_mode(self, mode):
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value=mode)
    self.dict_play_mode_v46.set(mode)
    _v46_render_learning_area(self)

def _v46_toggle_play_mode(self):
    _v46_set_play_mode(self, "拆分播放" if _v46_play_mode(self) == "整句播放" else "整句播放")

def _v46_toggle_auto_next_line(self):
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    self.dict_auto_next_line_v46.set(not self.dict_auto_next_line_v46.get())
    _v46_render_learning_area(self)

def _v46_toggle_cn(self):
    try:
        self.dictation_show_cn_v30.set(not self.dictation_show_cn_v30.get())
    except Exception:
        pass
    _v46_render_learning_area(self)

def _v46_copy_current(self):
    m = _v46_current_material(self)
    txt = _v46_item_text(m)
    zh = _v46_item_zh(m)
    data = txt if not zh else txt + "\n" + zh
    try:
        self.clipboard_clear(); self.clipboard_append(data); self.update()
        _v46_status(self, "已复制当前句/台词。", ok=True)
    except Exception:
        pass

def _v46_show_hint(self):
    m = _v46_current_material(self)
    chunks = _v46_get_chunks(self)
    idx = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
    if _v46_play_mode(self) == "拆分播放" and chunks:
        ch = chunks[max(0, min(idx, len(chunks)-1))]
        _v46_status(self, f"提示：当前块属于【{ch.get('role','句子成分')}】，共 {len(_v46_tokens(ch.get('text','')))} 个词。")
    else:
        _v46_status(self, f"提示：整句共 {len(_v46_tokens(_v46_item_text(m)))} 个词，{len(chunks)} 个句子成分块。")

def _v46_status(self, msg, ok=False, bad=False):
    try:
        self.dict_v46_status_var.set(msg)
        if hasattr(self, "dict_v46_status_label"):
            self.dict_v46_status_label.configure(fg=V46_OK if ok else V46_BAD if bad else V46_MUTED)
    except Exception:
        pass
    try:
        self.dictation_feedback_var_v30.set(msg)
    except Exception:
        pass

def _v46_rebuild_center_panel(self):
    center = getattr(self, "dictation_center_panel_v32", None)
    if center is None:
        return
    for ch in center.winfo_children():
        try: ch.destroy()
        except Exception: pass
    center.configure(bg=V46_BG)
    # top meta
    top = tk.Frame(center, bg=V46_BG)
    top.pack(fill="x", padx=18, pady=(10, 0))
    if not hasattr(self, "dictation_target_meta_var_v30"):
        self.dictation_target_meta_var_v30 = tk.StringVar(value="")
    tk.Label(top, textvariable=self.dictation_target_meta_var_v30, bg=V46_BG, fg="#A7F3D0", font=FONT_BOLD).pack(side="left")
    ttk.Button(top, text="窗口/全屏", command=lambda: _v46_action_map(self)["窗口/全屏"]()).pack(side="right", padx=4)
    ttk.Button(top, text="隐藏素材池", command=lambda: _v46_action_map(self)["隐藏/显示素材池"]()).pack(side="right", padx=4)

    self.dict_v46_study = tk.Frame(center, bg=V46_BG)
    self.dict_v46_study.pack(fill="both", expand=True, padx=18, pady=10)

    self.dict_v46_status_var = tk.StringVar(value="等待输入")
    self.dict_v46_status_label = tk.Label(center, textvariable=self.dict_v46_status_var, bg=V46_BG, fg=V46_MUTED, font=("Microsoft YaHei UI", 11, "bold"), wraplength=1000)
    self.dict_v46_status_label.pack(fill="x", padx=18, pady=(0, 6))

    bottom = tk.Frame(center, bg=V46_BG)
    bottom.pack(fill="x", padx=18, pady=(0, 12))
    self.dict_v46_bottom_buttons = {}
    button_order = [
        ("主播放/当前音频", _v46_play_current),
        ("视频播放", _v46_video_play),
        ("暂停/继续", _v46_pause),
        ("上一句", _v46_prev),
        ("下一句", _v46_next),
        ("判断当前块", _v46_force_check_current),
        ("提交整句", _v46_submit_all),
        ("提示", _v46_show_hint),
        ("整句/拆分切换", _v46_toggle_play_mode),
        ("显示/隐藏中文", _v46_toggle_cn),
        ("跳过当前块", _v46_skip_current_chunk),
        ("自动跳转下一行", _v46_toggle_auto_next_line),
        ("复制当前句", _v46_copy_current),
    ]
    for action, fn in button_order:
        btn = ttk.Button(bottom, text=action, command=lambda f=fn: f(self))
        btn.pack(side="left", padx=3, pady=3)
        self.dict_v46_bottom_buttons[action] = btn
    ttk.Button(bottom, text="快捷键设置", style="Accent.TButton", command=lambda: _v46_open_shortcut_editor(self)).pack(side="right", padx=3)
    _v46_refresh_shortcut_display(self)
    _v46_render_learning_area(self)

def _v46_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in parent.winfo_children():
        try: ch.destroy()
        except Exception: pass
    m = _v46_current_material(self)
    bg = V46_BG
    if not m:
        tk.Label(parent, text="请先导入或选择听写素材", bg=bg, fg=V46_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return
    chunks = _v46_get_chunks(self)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    try:
        show_cn = bool(self.dictation_show_cn_v30.get())
    except Exception:
        show_cn = True
    zh = _v46_item_zh(m) or "中文翻译/提示将自动显示"
    if show_cn:
        tk.Label(parent, text=zh, bg=bg, fg=V46_TEXT, font=("Microsoft YaHei UI", 24, "bold"), wraplength=1060, justify="center").pack(pady=(24, 12))
    else:
        tk.Label(parent, text="盲听模式：中文翻译和提示已隐藏", bg=bg, fg=V46_MUTED, font=("Microsoft YaHei UI", 18, "bold")).pack(pady=(24, 12))
    controls = tk.Frame(parent, bg=bg)
    controls.pack(pady=(2, 22))
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    ttk.Combobox(controls, textvariable=self.dict_play_mode_v46, values=["整句播放", "拆分播放"], state="readonly", width=12).pack(side="left", padx=5)
    ttk.Button(controls, text="播放当前", command=lambda: _v46_play_current(self)).pack(side="left", padx=5)
    ttk.Button(controls, text="跳过当前块", command=lambda: _v46_skip_current_chunk(self)).pack(side="left", padx=5)
    ttk.Checkbutton(controls, text="自动跳转下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=8)
    try:
        controls.winfo_children()[0].bind("<<ComboboxSelected>>", lambda e: _v46_render_learning_area(self))
    except Exception:
        pass

    mode = _v46_play_mode(self)
    idx = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
    idx = max(0, min(idx, max(len(chunks)-1, 0)))
    show_chunks = [chunks[idx]] if mode == "拆分播放" and chunks else chunks
    line = tk.Frame(parent, bg=bg)
    line.pack(anchor="center", pady=(22, 8))
    self.dict_v46_entries = []
    for n, ch in enumerate(show_chunks):
        real_idx = idx if mode == "拆分播放" else n
        tx = ch.get("text", "")
        role = ch.get("role") or _v46_guess_role(tx)
        cell = tk.Frame(line, bg=bg)
        cell.pack(side="left", padx=8, pady=6)
        width = max(7, min(28, len(tx)+2))
        sv = tk.StringVar()
        ent = tk.Entry(cell, textvariable=sv, width=width, justify="center", bg=bg, fg=V46_TEXT, insertbackground=V46_ACTIVE, relief="flat", bd=0, font=("Consolas", 20, "bold"))
        ent.pack()
        cw = max(78, width*15)
        cv = tk.Canvas(cell, width=cw, height=8, bg=bg, highlightthickness=0)
        cv.pack()
        cv.create_line(2,4,cw-2,4,fill=V46_ACTIVE if n == 0 else V46_LINE, width=3)
        tk.Label(cell, text=role, bg=bg, fg=V46_MUTED, font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
        fb = tk.Frame(cell, bg=bg)
        fb.pack(pady=(6,0))
        _v46_draw_word_feedback(fb, [], _v46_tokens(tx))
        item = {"idx": real_idx, "target": tx, "role": role, "var": sv, "entry": ent, "line": cv, "w": cw, "feedback": fb}
        self.dict_v46_entries.append(item)
        ent.bind("<KeyRelease>", lambda e, it=item: _v46_auto_check_entry(self, it))
        ent.bind("<space>", lambda e, it=item: (_v46_force_check_entry(self, it), "break"))
        ent.bind("<Return>", lambda e: (_v46_submit_all(self), "break"))
        ent.bind("<KeyPress>", lambda e: _v46_beep(self, "type"))
    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    text_desc = "整句播放：整句音频 + 所有横线；拆分播放：当前句子成分音频 + 当前横线。"
    _v46_status(self, text_desc)

def _v46_draw_word_feedback(frame, results, target_words):
    for ch in frame.winfo_children():
        try: ch.destroy()
        except Exception: pass
    if not results:
        for tw in target_words:
            tk.Label(frame, text="＿", bg=V46_BG, fg=V46_MUTED, font=("Microsoft YaHei UI", 8)).pack(side="left", padx=2)
        return
    for r in results:
        label = r["target"] if r["type"] == "正确" else (r["answer"] or "∅")
        label = f"{r['pos']}:{label}"
        tk.Label(frame, text=label, bg=V46_BG, fg=r["color"], font=("Microsoft YaHei UI", 8, "bold")).pack(side="left", padx=2)

def _v46_auto_check_entry(self, item):
    ans = item["var"].get()
    target = item["target"]
    ok, results = _v46_analyze_phrase(ans, target, item.get("role",""))
    _v46_draw_word_feedback(item["feedback"], results, _v46_tokens(target))
    # line status: green when all words right; red if full length and errors; yellow for partial
    if ok:
        item["entry"].configure(fg=V46_OK)
        _v46_set_line(item, V46_OK)
        _v46_beep(self, "ok")
        _v46_status(self, f"✅ 正确：{target}", ok=True)
        if _v46_play_mode(self) == "拆分播放":
            self.after(280, lambda: _v46_skip_current_chunk(self, already_correct=True))
        else:
            # focus next unfinished entry
            for it in getattr(self, "dict_v46_entries", []):
                if it["idx"] > item["idx"]:
                    try: it["entry"].focus_set()
                    except Exception: pass
                    break
        return True
    # precise message
    if ans.strip():
        has_full = len(_v46_tokens(ans)) >= len(_v46_tokens(target))
        wrongs = [r for r in results if r["type"] != "正确"]
        if has_full and wrongs:
            item["entry"].configure(fg=V46_BAD)
            _v46_set_line(item, V46_BAD)
            _v46_beep(self, "bad")
            msg = "；".join([f"第{r['pos']}词 {r['type']}：输入[{r['answer'] or '空'}] / 应为[{r['target']}]" for r in wrongs[:4]])
            _v46_status(self, "❌ " + msg, bad=True)
        else:
            item["entry"].configure(fg=V46_WARN)
            _v46_set_line(item, V46_WARN)
            correct = [r["target"] for r in results if r["type"] == "正确"]
            _v46_status(self, ("已识别正确：" + ", ".join(correct)) if correct else "继续输入……")
    return False

def _v46_set_line(item, color):
    try:
        item["line"].delete("all")
        item["line"].create_line(2,4,item["w"]-2,4,fill=color,width=3)
    except Exception:
        pass

def _v46_force_check_entry(self, item):
    ok = _v46_auto_check_entry(self, item)
    if not ok:
        try:
            _v46_speak_text(self, item["target"])
        except Exception:
            pass
    return ok

def _v46_force_check_current(self):
    entries = getattr(self, "dict_v46_entries", [])
    if not entries: return False
    try:
        focus = self.focus_get()
        for it in entries:
            if it["entry"] == focus:
                return _v46_force_check_entry(self, it)
    except Exception:
        pass
    return _v46_force_check_entry(self, entries[0])

def _v46_submit_all(self):
    entries = getattr(self, "dict_v46_entries", [])
    if not entries: return False
    all_ok = True
    for it in entries:
        all_ok = _v46_force_check_entry(self, it) and all_ok
    if all_ok:
        _v46_beep(self, "sentence")
        m = _v46_current_material(self)
        if isinstance(m, dict):
            m["status"] = "correct"
        _v46_status(self, "✅ 整句/当前展示块全部正确。", ok=True)
        if _v46_play_mode(self) == "整句播放" and getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
            self.after(450, lambda: _v46_next(self))
    else:
        _v46_status(self, "仍有错误：绿色=正确词；黄色=拼写/词形/词类问题；红色=漏词/多词/用词错误。", bad=True)
    return all_ok

def _v46_skip_current_chunk(self, already_correct=False):
    m = _v46_current_material(self)
    chunks = _v46_get_chunks(self)
    if not isinstance(m, dict) or not chunks:
        return
    idx = int(m.get("_v46_chunk_index", 0))
    if idx + 1 < len(chunks):
        m["_v46_chunk_index"] = idx + 1
        _v46_render_learning_area(self)
        if _v46_play_mode(self) == "拆分播放":
            self.after(120, lambda: _v46_play_current(self))
    else:
        m["_v46_chunk_index"] = 0
        if getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
            _v46_next(self)
            if _v46_play_mode(self) == "拆分播放":
                self.after(160, lambda: _v46_play_current(self))
        else:
            _v46_render_learning_area(self)
            _v46_status(self, "当前行拆分完成。", ok=True)

def _v46_play_current(self):
    m = _v46_current_material(self)
    if not m: return
    text = _v46_item_text(m)
    if _v46_play_mode(self) == "拆分播放":
        chunks = _v46_get_chunks(self)
        idx = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
        if chunks:
            text = chunks[max(0, min(idx, len(chunks)-1))].get("text","") or text
    _v46_speak_text(self, text)

def _v46_speak_text(self, text):
    # Edge API from V45/V44 preferred.
    for fn in ("_v45_speak_edge_api", "_v44_speak_text"):
        if fn in globals():
            try:
                return globals()[fn](self, text)
            except Exception:
                pass
    try:
        self.bell()
    except Exception:
        pass

def _v46_video_play(self):
    for fn in ("_v44_play_video", "_v42_play_video"):
        if fn in globals():
            try: return globals()[fn](self)
            except Exception: pass
    _v46_status(self, "当前素材不支持视频播放。", bad=True)

def _v46_pause(self):
    try:
        self.play_status.set("暂停/继续：TTS短音频无需暂停；视频请用播放器控制。")
    except Exception:
        pass

def _v46_prev(self):
    try:
        if getattr(self, "dictation_materials_v30", None):
            self.dictation_index_v30 = max(0, self.dictation_index_v30 - 1)
            _v46_refresh_current(self)
    except Exception:
        pass

def _v46_next(self):
    try:
        if getattr(self, "dictation_materials_v30", None):
            self.dictation_index_v30 = min(len(self.dictation_materials_v30)-1, self.dictation_index_v30 + 1)
            _v46_refresh_current(self)
    except Exception:
        pass

def _v46_refresh_current(self):
    mats = getattr(self, "dictation_materials_v30", [])
    if mats:
        self.dictation_index_v30 = max(0, min(getattr(self, "dictation_index_v30", 0), len(mats)-1))
        try: self.dict_index_v33 = self.dictation_index_v30
        except Exception: pass
    m = _v46_current_material(self)
    if hasattr(self, "dictation_target_meta_var_v30"):
        if m:
            self.dictation_target_meta_var_v30.set(f"{getattr(self,'dictation_index_v30',0)+1}/{len(mats)}｜{m.get('title','')} {m.get('year','')}｜关键词：{m.get('keyword','')}")
        else:
            self.dictation_target_meta_var_v30.set("当前材料：无")
    _v46_refresh_material_tree(self)
    _v46_render_learning_area(self)
    try:
        self._dictation_update_stats_v30()
    except Exception:
        pass

# ---------------- material tree ----------------
def _v46_install_material_tree(self):
    left = getattr(self, "dictation_left_panel_v32", None)
    if left is None:
        return
    for ch in left.winfo_children():
        try: ch.destroy()
        except Exception: pass
    left.configure(bg="#101827")
    head = tk.Frame(left, bg="#101827")
    head.pack(fill="x", padx=10, pady=(10,4))
    tk.Label(head, text="听写素材池", bg="#101827", fg=V46_TEXT, font=("Microsoft YaHei UI", 12, "bold")).pack(side="left")
    ttk.Button(head, text="隐藏", width=6, command=lambda: _v46_action_map(self)["隐藏/显示素材池"]()).pack(side="right")
    self.dict_v46_source_filter = tk.StringVar(value="全部")
    ttk.Combobox(left, textvariable=self.dict_v46_source_filter, state="readonly", values=["全部","在线","本地","文本"]).pack(fill="x", padx=10, pady=5)
    try:
        left.winfo_children()[-1].bind("<<ComboboxSelected>>", lambda e: _v46_refresh_material_tree(self))
    except Exception:
        pass
    tree = ttk.Treeview(left, show="tree", height=22)
    tree.pack(fill="both", expand=True, padx=10, pady=6)
    tree.bind("<<TreeviewSelect>>", lambda e: _v46_on_tree_select(self))
    self.dict_material_tree_v46 = tree
    btn = tk.Frame(left, bg="#101827")
    btn.pack(fill="x", padx=8, pady=6)
    ttk.Button(btn, text="导入精选池", command=getattr(self, "_dictation_import_pool_v30", lambda: None)).pack(side="left", padx=2)
    ttk.Button(btn, text="导入TXT/SRT", command=getattr(self, "_dictation_import_text_v30", getattr(self, "_dictation_import_txt_v30", lambda: None))).pack(side="left", padx=2)
    ttk.Button(btn, text="清空", command=getattr(self, "_dictation_clear_materials_v30", lambda: None)).pack(side="left", padx=2)
    btn2 = tk.Frame(left, bg="#101827")
    btn2.pack(fill="x", padx=8, pady=(0,6))
    ttk.Button(btn2, text="保存进度", command=getattr(self, "_dictation_save_progress_v30", lambda: None)).pack(side="left", padx=2)
    ttk.Button(btn2, text="加载进度", command=getattr(self, "_dictation_load_progress_v30", lambda: None)).pack(side="left", padx=2)
    tk.Label(left, text="树状目录按 在线 / 本地 / 文本 三类管理；路径来自资源站同步或系统文件路径。", bg="#101827", fg=V46_MUTED, wraplength=260, justify="left", font=FONT_SMALL).pack(fill="x", padx=10, pady=(0,10))
    _v46_refresh_material_tree(self)

def _v46_refresh_material_tree(self):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None:
        return
    tree.delete(*tree.get_children())
    filter_ = getattr(self, "dict_v46_source_filter", tk.StringVar(value="全部")).get()
    roots = {}
    for bucket in ["在线","本地","文本"]:
        if filter_ not in ("全部", bucket):
            continue
        roots[bucket] = tree.insert("", "end", text=bucket + "素材", open=True, values=("ROOT", bucket))
    node_map = {}
    mats = getattr(self, "dictation_materials_v30", [])
    for i, m in enumerate(mats):
        bucket = _v46_source_bucket(m)
        if bucket not in roots:
            continue
        parent = roots[bucket]
        acc = bucket
        for part in _v46_source_parts(m):
            part = str(part)[:80] or "未分类"
            acc += "/" + part
            if acc not in node_map:
                node_map[acc] = tree.insert(parent, "end", text=part, open=False, values=("DIR", acc))
            parent = node_map[acc]
        mark = "✓" if isinstance(m, dict) and m.get("status") == "correct" else "✗" if isinstance(m, dict) and m.get("status") == "wrong" else "·"
        text = _v46_item_text(m)
        iid = f"item_{i}"
        tree.insert(parent, "end", iid=iid, text=f"{mark} {i+1:03d}. {text[:72]}", values=("ITEM", str(i)))
    # select current
    try:
        cur = f"item_{getattr(self,'dictation_index_v30',0)}"
        if tree.exists(cur):
            tree.selection_set(cur); tree.see(cur)
    except Exception:
        pass

def _v46_on_tree_select(self):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None: return
    sel = tree.selection()
    if not sel: return
    vals = tree.item(sel[0], "values")
    if vals and vals[0] == "ITEM":
        try:
            self.dictation_index_v30 = int(vals[1])
            self.dict_index_v33 = self.dictation_index_v30
            _v46_refresh_current(self)
        except Exception:
            pass

# ---------------- recite mode ----------------
def _v46_rebuild_recite_mode(self):
    tab = getattr(self, "tab_recite_v37", None)
    if tab is None:
        return
    for ch in tab.winfo_children():
        try: ch.destroy()
        except Exception: pass
    bg = "#111827"; fg = "#E5E7EB"; muted = "#94A3B8"; accent = "#8B5CF6"
