# ---------------- My resource station V48 ----------------
def _v48_resource_root(self):
    if not hasattr(self, "resource_root_var_v48"):
        self.resource_root_var_v48 = tk.StringVar(value=str(_Path_v48.cwd() / "playphrase_resource_library"))
    return _Path_v48(self.resource_root_var_v48.get()).expanduser()

def _v48_resource_index_path(self):
    return _v48_resource_root(self) / ".resource_index_v48.json"

def _v48_empty_resource_index():
    return {"version":48, "mounted":{}, "records":[], "created_at":_time_v48.strftime("%Y-%m-%d %H:%M:%S")}

def _v48_load_resource_index(self):
    fp = _v48_resource_index_path(self)
    if not fp.exists():
        return _v48_empty_resource_index()
    try:
        data = _json_v48.loads(fp.read_text("utf-8"))
        data.setdefault("mounted", {})
        data.setdefault("records", [])
        return data
    except Exception:
        return _v48_empty_resource_index()

def _v48_save_resource_index(self, data):
    root = _v48_resource_root(self)
    root.mkdir(parents=True, exist_ok=True)
    data["updated_at"] = _time_v48.strftime("%Y-%m-%d %H:%M:%S")
    _v48_resource_index_path(self).write_text(_json_v48.dumps(data, ensure_ascii=False, indent=2), "utf-8")

def _v48_resource_init_dirs(self):
    root = _v48_resource_root(self)
    root.mkdir(parents=True, exist_ok=True)
    idx = _v48_load_resource_index(self)
    for top in V48_RESOURCE_TOPS:
        tdir = root / _v48_safe_name(top)
        tdir.mkdir(parents=True, exist_ok=True)
        for folder in ("默认文件夹", "自定义"):
            (tdir / folder).mkdir(parents=True, exist_ok=True)
            idx.setdefault("mounted", {}).setdefault(f"{top}/{folder}", [])
    _v48_save_resource_index(self, idx)
    _v48_refresh_resource_tree(self)
    _v48_refresh_resource_files(self)

def _v48_selected_resource_folder(self):
    tree = getattr(self, "resource_tree_v48", None)
    if not tree:
        return None
    sel = tree.selection()
    if not sel:
        return None
    vals = tree.item(sel[0], "values")
    if vals and vals[0] == "FOLDER":
        return vals[1], vals[2]
    if vals and vals[0] == "TOP":
        top = vals[1]
        return top, "默认文件夹"
    return None

def _v48_resource_folder_dir(self, top, folder):
    return _v48_resource_root(self) / _v48_safe_name(top) / _v48_safe_name(folder)

def _v48_new_resource_folder(self):
    selected = _v48_selected_resource_folder(self)
    top = selected[0] if selected else (getattr(self, "resource_top_select_v48", tk.StringVar(value="本地素材")).get())
    name = _simpledialog_v48.askstring("新建文件夹", f"在【{top}】下创建文件夹：")
    if not name:
        return
    _v48_resource_folder_dir(self, top, name).mkdir(parents=True, exist_ok=True)
    idx = _v48_load_resource_index(self)
    idx.setdefault("mounted", {}).setdefault(f"{top}/{name}", [])
    _v48_save_resource_index(self, idx)
    _v48_refresh_resource_tree(self)

def _v48_make_resource_record(fp, top, folder, origin="分类目录"):
    fp = _Path_v48(fp)
    ext = fp.suffix.lower()
    if ext in V48_VIDEO_EXTS:
        typ = "视频"; source_type = "local_video"
    elif ext in V48_AUDIO_EXTS:
        typ = "音频"; source_type = "local_audio"
    elif ext in V48_TEXT_EXTS:
        typ = "文本"; source_type = "text"
    else:
        return None
    subtitle_path = ""
    if typ == "视频":
        for e in [".srt",".ass",".ssa",".vtt",".txt"]:
            cand = fp.with_suffix(e)
            if cand.exists():
                subtitle_path = str(cand); source_type = "local_video_subtitle"; break
    return {
        "id": f"{top}/{folder}/{fp}",
        "top": top,
        "folder": folder,
        "origin": origin,
        "type": typ,
        "source_type": source_type,
        "name": fp.name,
        "path": str(fp),
        "subtitle_path": subtitle_path,
        "updated_at": _time_v48.strftime("%Y-%m-%d %H:%M:%S"),
    }

def _v48_scan_resource_folder_rows(self, top, folder):
    idx = _v48_load_resource_index(self)
    key = f"{top}/{folder}"
    roots = [_v48_resource_folder_dir(self, top, folder)]
    roots.extend([_Path_v48(p) for p in idx.get("mounted", {}).get(key, [])])
    rows = []
    for root in roots:
        if not root.exists():
            continue
        files = [root] if root.is_file() else [p for p in root.rglob("*") if p.is_file()]
        for fp in files:
            if fp.suffix.lower() not in (V48_VIDEO_EXTS | V48_AUDIO_EXTS | V48_TEXT_EXTS):
                continue
            rec = _v48_make_resource_record(fp, top, folder, origin=("外部路径" if not str(fp).startswith(str(_v48_resource_folder_dir(self, top, folder))) else "分类目录"))
            if rec:
                rows.append(rec)
    return rows

def _v48_refresh_resource_tree(self):
    tree = getattr(self, "resource_tree_v48", None)
    if not tree:
        return
    tree.delete(*tree.get_children())
    root = _v48_resource_root(self)
    root.mkdir(parents=True, exist_ok=True)
    rid = tree.insert("", "end", text=f"资源站：{root}", open=True, values=("ROOT", str(root)))
    for top in V48_RESOURCE_TOPS:
        tdir = root / _v48_safe_name(top)
        tdir.mkdir(parents=True, exist_ok=True)
        tid = tree.insert(rid, "end", text=f"📁 {top}", open=True, values=("TOP", top))
        folders = [p.name for p in tdir.iterdir() if p.is_dir()]
        if not folders:
            (tdir / "默认文件夹").mkdir(exist_ok=True)
            folders = ["默认文件夹"]
        for folder in sorted(folders):
            tree.insert(tid, "end", text=f"📂 {folder}", open=False, values=("FOLDER", top, folder))

def _v48_resource_tree_select(self, event=None):
    _v48_refresh_resource_files(self)

def _v48_scan_selected_resource_folder_async(self):
    selected = _v48_selected_resource_folder(self)
    if not selected:
        _messagebox_v48.showwarning("提示", "请先选择一个资源站文件夹。")
        return
    top, folder = selected
    _v48_status_any(self, f"正在后台扫描：{top}/{folder} ...")
    def worker():
        rows = _v48_scan_resource_folder_rows(self, top, folder)
        idx = _v48_load_resource_index(self)
        old = [r for r in idx.get("records", []) if not (r.get("top") == top and r.get("folder") == folder)]
        idx["records"] = old + rows
        _v48_save_resource_index(self, idx)
        try:
            self.after(0, lambda: (_v48_refresh_resource_files(self), _v48_log(self, f"后台扫描完成：{len(rows)} 条。", "ok")))
        except Exception:
            pass
    _threading_v48.Thread(target=worker, daemon=True).start()

def _v48_refresh_resource_files(self):
    tree = getattr(self, "resource_file_tree_v48", None)
    if not tree:
        return
    tree.delete(*tree.get_children())
    selected = _v48_selected_resource_folder(self)
    idx = _v48_load_resource_index(self)
    if selected:
        top, folder = selected
        rows = [r for r in idx.get("records", []) if r.get("top") == top and r.get("folder") == folder]
    else:
        rows = idx.get("records", [])
    self.resource_file_rows_v48 = rows
    for i, r in enumerate(rows):
        vals = (r.get("type",""), r.get("name",""), r.get("origin",""), r.get("source_type",""), r.get("subtitle_path",""), r.get("path",""))
        tree.insert("", "end", iid=str(i), values=vals)
    try:
        self.resource_count_var_v48.set(f"{len(rows)} 个资源")
    except Exception:
        pass

def _v48_add_resource_folder_path(self):
    selected = _v48_selected_resource_folder(self)
    if not selected:
        _messagebox_v48.showwarning("提示", "请先选择左侧一个资源站文件夹。")
        return
    top, folder = selected
    d = _filedialog_v48.askdirectory(title="添加外部文件夹路径")
    if not d:
        return
    idx = _v48_load_resource_index(self)
    key = f"{top}/{folder}"
    idx.setdefault("mounted", {}).setdefault(key, [])
    if d not in idx["mounted"][key]:
        idx["mounted"][key].append(d)
    _v48_save_resource_index(self, idx)
    _v48_scan_selected_resource_folder_async(self)

def _v48_add_resource_files(self):
    selected = _v48_selected_resource_folder(self)
    if not selected:
        _messagebox_v48.showwarning("提示", "请先选择左侧一个资源站文件夹。")
        return
    top, folder = selected
    files = _filedialog_v48.askopenfilenames(title="添加文件路径")
    if not files:
        return
    idx = _v48_load_resource_index(self)
    key = f"{top}/{folder}"
    idx.setdefault("mounted", {}).setdefault(key, [])
    for f in files:
        if f not in idx["mounted"][key]:
            idx["mounted"][key].append(f)
    _v48_save_resource_index(self, idx)
    _v48_scan_selected_resource_folder_async(self)

def _v48_sync_resource_to_dictation_async(self):
    tree = getattr(self, "resource_file_tree_v48", None)
    rows = getattr(self, "resource_file_rows_v48", [])
    if not tree:
        return
    selected_rows = []
    for iid in tree.selection():
        try:
            selected_rows.append(rows[int(iid)])
        except Exception:
            pass
    if not selected_rows:
        selected_rows = rows
    if not selected_rows:
        _messagebox_v48.showwarning("提示", "没有可同步的资源。")
        return
    _v48_status_any(self, "正在后台同步到听写素材池，文件多时请稍等……")
    def worker():
        mats = []
        max_items = 20000
        for r in selected_rows:
            p = _Path_v48(r.get("path",""))
            if r.get("type") == "视频" and p.exists():
                sub = r.get("subtitle_path", "")
                lines = _v48_parse_text_lines(sub) if sub else []
                if lines:
                    for line in lines:
                        mats.append({"text": line, "zh": "", "title": r.get("name",""), "local_path": str(p), "media_path": str(p), "subtitle_path": sub, "source_type": "local_video_subtitle", "resource_meta": r})
                        if len(mats) >= max_items: break
                else:
                    mats.append({"text": p.stem.replace("_"," "), "zh": "", "title": r.get("name",""), "local_path": str(p), "media_path": str(p), "source_type": "local_video", "resource_meta": r})
            elif r.get("type") == "音频" and p.exists():
                mats.append({"text": p.stem.replace("_"," "), "zh": "", "title": r.get("name",""), "local_path": str(p), "audio_path": str(p), "source_type": "local_audio", "resource_meta": r})
            elif r.get("type") == "文本" and p.exists():
                for line in _v48_parse_text_lines(p):
                    mats.append({"text": line, "zh": "", "title": p.name, "local_path": str(p), "source_type": "text", "resource_meta": r})
                    if len(mats) >= max_items: break
            if len(mats) >= max_items:
                break
        def finish():
            self.dictation_materials_v30 = mats
            self.dictation_index_v30 = 0
            self.dict_items_v33 = mats
            self.dict_index_v33 = 0
            try:
                if hasattr(self, "_dictation_refresh_material_list_v30"):
                    self._dictation_refresh_material_list_v30()
                if hasattr(self, "_dictation_refresh_current_v30"):
                    self._dictation_refresh_current_v30()
                if hasattr(self, "nb") and hasattr(self, "tab_dictation"):
                    self.nb.select(self.tab_dictation)
            except Exception:
                pass
            _v48_log(self, f"同步完成：{len(mats)} 条听写素材。", "ok")
        try:
            self.after(0, finish)
        except Exception:
            pass
    _threading_v48.Thread(target=worker, daemon=True).start()

def _v48_rebuild_resource_station(self):
    tab = getattr(self, "tab_resource_platform_v32", None) or getattr(self, "tab_resource", None) or getattr(self, "tab_resources", None)
    if tab is None:
        return
    for ch in tab.winfo_children():
        try: ch.destroy()
        except Exception: pass
    root_bg = "#F4F7FA"
    outer = ttk.Frame(tab, padding=10)
    outer.pack(fill="both", expand=True)

    top = ttk.Frame(outer)
    top.pack(fill="x", pady=(0,8))
    if not hasattr(self, "resource_root_var_v48"):
        self.resource_root_var_v48 = tk.StringVar(value=str(_Path_v48.cwd() / "playphrase_resource_library"))
    ttk.Label(top, text="我的资源站 V48").pack(side="left")
    ttk.Entry(top, textvariable=self.resource_root_var_v48, width=78).pack(side="left", padx=8)
    ttk.Button(top, text="选择根目录", command=lambda: _v48_choose_resource_root(self)).pack(side="left", padx=3)
    ttk.Button(top, text="初始化目录", command=lambda: _v48_resource_init_dirs(self)).pack(side="left", padx=3)
    ttk.Button(top, text="新建文件夹", command=lambda: _v48_new_resource_folder(self)).pack(side="left", padx=3)
    ttk.Button(top, text="添加文件路径", command=lambda: _v48_add_resource_files(self)).pack(side="left", padx=3)
    ttk.Button(top, text="添加文件夹路径", command=lambda: _v48_add_resource_folder_path(self)).pack(side="left", padx=3)
    ttk.Button(top, text="后台扫描", command=lambda: _v48_scan_selected_resource_folder_async(self)).pack(side="left", padx=3)
    ttk.Button(top, text="后台同步到听写", command=lambda: _v48_sync_resource_to_dictation_async(self)).pack(side="right", padx=3)

    pane = ttk.Panedwindow(outer, orient="horizontal")
    pane.pack(fill="both", expand=True)
    left = ttk.Frame(pane, padding=4)
    right = ttk.Frame(pane, padding=4)
    pane.add(left, weight=1)
    pane.add(right, weight=4)

    ttk.Label(left, text="目录树（一级类别 / 二级文件夹）").pack(anchor="w")
    self.resource_tree_v48 = ttk.Treeview(left, show="tree", height=30)
    self.resource_tree_v48.pack(fill="both", expand=True)
    self.resource_tree_v48.bind("<<TreeviewSelect>>", lambda e: _v48_resource_tree_select(self))

    self.resource_count_var_v48 = tk.StringVar(value="0 个资源")
    ttk.Label(right, textvariable=self.resource_count_var_v48).pack(anchor="w")
    frame = ttk.Frame(right)
    frame.pack(fill="both", expand=True)
    cols = ("type","name","origin","source_type","subtitle","path")
    self.resource_file_tree_v48 = ttk.Treeview(frame, columns=cols, show="headings", height=28)
    vs = ttk.Scrollbar(frame, orient="vertical", command=self.resource_file_tree_v48.yview)
    hs = ttk.Scrollbar(frame, orient="horizontal", command=self.resource_file_tree_v48.xview)
    self.resource_file_tree_v48.configure(yscrollcommand=vs.set, xscrollcommand=hs.set)
    heads = {"type":"类型","name":"文件名","origin":"来源","source_type":"源类型","subtitle":"字幕/歌词","path":"路径/URL"}
    widths = {"type":60,"name":260,"origin":90,"source_type":150,"subtitle":260,"path":780}
    for c in cols:
        self.resource_file_tree_v48.heading(c, text=heads[c])
        self.resource_file_tree_v48.column(c, width=widths[c], anchor="w")
    self.resource_file_tree_v48.grid(row=0, column=0, sticky="nsew")
    vs.grid(row=0, column=1, sticky="ns")
    hs.grid(row=1, column=0, sticky="ew")
    frame.rowconfigure(0, weight=1); frame.columnconfigure(0, weight=1)
    ttk.Label(outer, text="说明：大量文件扫描与同步已改为后台线程；右侧文件列表带纵向/横向滚动条，像 Windows 文件浏览器一样拖拽查看。").pack(fill="x", pady=(8,0))
    _v48_resource_init_dirs(self)

def _v48_choose_resource_root(self):
    d = _filedialog_v48.askdirectory(title="选择我的资源站根目录")
    if not d:
        return
    self.resource_root_var_v48.set(d)
    _v48_resource_init_dirs(self)

# ---------------- patch installers ----------------
def _v48_patch_audio_functions(self):
    # Repeat / speaker buttons use managed logic.
    try:
        globals()["_v46_speak_text"] = lambda app, text: _v48_speak_managed(app, text, force=True)
        globals()["_v45_speak_edge_api"] = globals().get("_v45_speak_edge_api")  # keep raw; managed calls it
        globals()["_recite_speak_v37"] = lambda app, text: _v48_speak_managed(app, text, force=True)
        globals()["_v48_speak_text"] = lambda app, text: _v48_speak_managed(app, text, force=True)
    except Exception:
        pass

def _v48_patch_resource_functions(self):
    try:
        globals()["_v47_rebuild_resource_platform"] = lambda app: _v48_rebuild_resource_station(app)
        globals()["_v44_rebuild_resource_platform"] = lambda app: _v48_rebuild_resource_station(app)
        globals()["_v42_build_resource_platform"] = lambda app: _v48_rebuild_resource_station(app)
    except Exception:
        pass

_old_main_init_v48 = MainApp.__init__
def _main_init_v48(self):
    _old_main_init_v48(self)
    try:
        _v48_patch_audio_functions(self)
        _v48_patch_resource_functions(self)
        _v48_bind_ctrl_repeat(self)
        _v48_rebuild_recite_mode(self)
        _v48_rebuild_resource_station(self)
        self.log("【V48上线】背诵模式：选中即发音、自动跳转立即发音、Ctrl 单键重复发音节流逻辑已接入。", "ok")
        self.log("【V48上线】背诵学习目录已落地：一级目录/二级文件夹/文件路径；支持文本、歌词、音频，不识别视频。", "ok")
        self.log("【V48上线】我的资源站已改成 Windows 风格两级目录树 + 可滚动文件列表；扫描/同步改后台线程避免卡死。", "ok")
    except Exception as e:
        try:
            self.log(f"V48初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v48
APP_TITLE = "PlayPhrase Studio Clean v48 · 背诵资源站/重复发音/后台同步版"


# ──────────────────────────────────────────────────────────────────────
# V49: Resource Manager + non-blocking scan + file-type state machine + single learning area
# 目标：
# 1) 加载路径不卡死：添加路径只记录，不立即深度扫描；扫描/同步全部后台线程。
# 2) 资源平台做成独立工作台按钮：增删查改目录/文件夹/路径都在资源平台完成。
# 3) 主界面只学习：左侧可折叠/可拉伸目录树；右侧学习区；选中文件不会播放，必须点“加载当前文件”。
# 4) 三种文件：歌词文件=音频+文本；听写文件=只有音频；资料文件=只有英文文本。
# 5) 三种模式：歌词模式/听写模式/盲听模式。
# 6) 空格只确认当前单词；正确词绿并跳下一个；整句完成才跳下一句；拆分语块完成后才允许自动下一句。
# 只修学习/资源/扫描/输入逻辑；不动美化视频主链。
# ──────────────────────────────────────────────────────────────────────
import os as _os_v49
import re as _re_v49
import json as _json_v49
import time as _time_v49
import threading as _threading_v49
import subprocess as _subprocess_v49
from pathlib import Path as _Path_v49

try:
    import tkinter as _tk_v49
    from tkinter import ttk as _ttk_v49, filedialog as _filedialog_v49, messagebox as _messagebox_v49, simpledialog as _simpledialog_v49
except Exception:
    pass

V49_AUDIO_EXTS = {'.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg', '.wma'}
V49_TEXT_EXTS = {'.txt', '.csv', '.srt', '.vtt', '.lrc', '.ass', '.ssa'}
V49_VIDEO_EXTS = {'.mp4', '.mkv', '.avi', '.mov', '.webm', '.m4v'}
V49_LEARN_CATEGORIES = [
    '四六级', '专四专八', '考研', '托福', '雅思', '计算机', '启蒙英语', '少儿英语',
    '医药专业', '护理英语', '心理学专业', 'AI英语', '商务英语', '影视音乐', '自定义'
]
V49_BG = '#0b1220'
V49_PANEL = '#111827'
V49_CARD = '#0f172a'
V49_TEXT = '#e5e7eb'
V49_MUTED = '#94a3b8'
V49_ACCENT = '#8b5cf6'
V49_OK = '#22c55e'
V49_BAD = '#ef4444'
V49_WARN = '#f59e0b'

def _v49_log(self, msg, level='info'):
    try: self.log(msg, level)
    except Exception: print(msg)

def _v49_safe(s):
    return _re_v49.sub(r'[\\/:*?"<>|]+', '_', str(s or '').strip())[:120] or '未命名'

def _v49_root(self):
    if not hasattr(self, 'learn_root_var_v49'):
        self.learn_root_var_v49 = tk.StringVar(value=str(_Path_v49.cwd() / 'playphrase_learning_library'))
    return _Path_v49(self.learn_root_var_v49.get()).expanduser()

def _v49_index_path(self):
    return _v49_root(self) / '.learning_resource_index_v49.json'

def _v49_empty_index():
    return {'version': 49, 'mounted': {}, 'records': [], 'progress': {}, 'created_at': _time_v49.strftime('%Y-%m-%d %H:%M:%S')}

def _v49_load_index(self):
    fp = _v49_index_path(self)
    if not fp.exists():
        return _v49_empty_index()
    try:
        data = _json_v49.loads(fp.read_text('utf-8'))
        data.setdefault('mounted', {})
        data.setdefault('records', [])
        data.setdefault('progress', {})
        return data
    except Exception:
        return _v49_empty_index()

def _v49_save_index(self, data):
    root = _v49_root(self)
    root.mkdir(parents=True, exist_ok=True)
    data['updated_at'] = _time_v49.strftime('%Y-%m-%d %H:%M:%S')
    _v49_index_path(self).write_text(_json_v49.dumps(data, ensure_ascii=False, indent=2), 'utf-8')

def _v49_cat_dir(self, cat):
    return _v49_root(self) / _v49_safe(cat)

def _v49_folder_dir(self, cat, folder):
    return _v49_cat_dir(self, cat) / _v49_safe(folder)

def _v49_init_dirs(self):
    root = _v49_root(self); root.mkdir(parents=True, exist_ok=True)
    idx = _v49_load_index(self)
    for cat in V49_LEARN_CATEGORIES:
        d = _v49_cat_dir(self, cat); d.mkdir(parents=True, exist_ok=True)
        (d / '默认文件夹').mkdir(parents=True, exist_ok=True)
        idx.setdefault('mounted', {}).setdefault(f'{cat}/默认文件夹', [])
    _v49_save_index(self, idx)
    _v49_refresh_main_tree(self)
    _v49_refresh_file_list(self)
    _v49_set_status(self, f'学习资源目录已初始化：{root}')

def _v49_parse_text_lines(path):
    try:
        raw = _Path_v49(path).read_text('utf-8-sig', errors='ignore')
    except Exception:
        return []
    out = []
    for raw_line in raw.splitlines():
        s = raw_line.strip()
        s = _re_v49.sub(r'^\[[0-9:.]+\]', '', s).strip()
        if not s or '-->' in s or _re_v49.fullmatch(r'\d+', s):
            continue
        s = _re_v49.sub(r'<[^>]+>', '', s).strip()
        if s:
            out.append(s)
    return out

def _v49_is_english_content(lines):
    joined = '\n'.join(lines[:100])
    latin = len(_re_v49.findall(r'[A-Za-z]', joined))
    cjk = len(_re_v49.findall(r'[\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]', joined))
    return latin >= 5 and latin >= cjk

def _v49_is_english_line(s):
    latin = len(_re_v49.findall(r'[A-Za-z]', str(s)))
    cjk = len(_re_v49.findall(r'[\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]', str(s)))
    return latin >= max(2, cjk * 2)

def _v49_find_pair(path):
    p = _Path_v49(path)
    if p.suffix.lower() in V49_AUDIO_EXTS:
        for ext in ['.lrc', '.srt', '.vtt', '.txt', '.csv']:
            q = p.with_suffix(ext)
            if q.exists():
                return str(q)
    if p.suffix.lower() in V49_TEXT_EXTS:
        for ext in ['.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg', '.wma']:
            q = p.with_suffix(ext)
            if q.exists():
                return str(q)
    return ''

def _v49_file_kind(path):
    p = _Path_v49(path)
    ext = p.suffix.lower()
    if ext in V49_VIDEO_EXTS:
        return None
    if ext in V49_AUDIO_EXTS:
        pair = _v49_find_pair(p)
        return '歌词文件' if pair else '听写文件'
    if ext in V49_TEXT_EXTS:
        lines = _v49_parse_text_lines(p)
        if not _v49_is_english_content(lines):
            return None
        pair = _v49_find_pair(p)
        return '歌词文件' if pair else '资料文件'
    return None

def _v49_record_from_file(path, cat, folder, origin='外部路径'):
    p = _Path_v49(path)
    kind = _v49_file_kind(p)
    if not kind:
        return None
    pair = _v49_find_pair(p)
    audio = ''
    text = ''
    if p.suffix.lower() in V49_AUDIO_EXTS:
        audio = str(p)
        text = pair
    else:
        text = str(p)
        audio = pair
    lines = _v49_parse_text_lines(text) if text else []
    return {
        'id': f'{cat}/{folder}/{p.resolve() if p.exists() else p}',
        'category': cat,
        'folder': folder,
        'origin': origin,
        'kind': kind,
        'name': p.name,
        'path': str(p),
        'audio_path': audio,
        'text_path': text,
        'pair_status': '音频+文本' if audio and text else ('只有音频' if audio else '只有文本'),
        'line_count': len(lines),
        'updated_at': _time_v49.strftime('%Y-%m-%d %H:%M:%S'),
    }

def _v49_selected_folder(self):
    tree = getattr(self, 'learn_tree_v49', None)
    if tree is None:
        return None
    sel = tree.selection()
    if not sel:
        return None
    vals = tree.item(sel[0], 'values')
    if vals and vals[0] == 'FOLDER':
        return vals[1], vals[2]
    if vals and vals[0] == 'CAT':
        cat = vals[1]
        d = _v49_cat_dir(self, cat)
        folders = [p.name for p in d.iterdir() if p.is_dir()] if d.exists() else []
        return cat, (folders[0] if folders else '默认文件夹')
    return None

def _v49_refresh_main_tree(self):
    tree = getattr(self, 'learn_tree_v49', None)
    if tree is None: return
    tree.delete(*tree.get_children())
    root = _v49_root(self); root.mkdir(parents=True, exist_ok=True)
    rid = tree.insert('', 'end', text=f'学习资源库：{root}', open=True, values=('ROOT', str(root)))
    cats = set(V49_LEARN_CATEGORIES)
    cats.update([p.name for p in root.iterdir() if p.is_dir()])
    for cat in sorted(cats):
        cd = _v49_cat_dir(self, cat); cd.mkdir(parents=True, exist_ok=True)
        cid = tree.insert(rid, 'end', text=f'📁 {cat}', open=True, values=('CAT', cat))
        folders = [p.name for p in cd.iterdir() if p.is_dir()]
        if not folders:
            (cd / '默认文件夹').mkdir(exist_ok=True); folders = ['默认文件夹']
        for folder in sorted(folders):
            tree.insert(cid, 'end', text=f'📂 {folder}', open=False, values=('FOLDER', cat, folder))
    try: tree.selection_set(rid)
    except Exception: pass

def _v49_get_records_for_selected(self):
    idx = _v49_load_index(self)
    folder = _v49_selected_folder(self)
    rows = idx.get('records', [])
    if folder:
        cat, fol = folder
        rows = [r for r in rows if r.get('category') == cat and r.get('folder') == fol]
    return rows

def _v49_refresh_file_list(self):
    tree = getattr(self, 'learn_file_tree_v49', None)
    if tree is None: return
    tree.delete(*tree.get_children())
    rows = _v49_get_records_for_selected(self)
    self.learn_rows_v49 = rows
    for i, r in enumerate(rows):
        vals = (r.get('kind',''), r.get('name',''), r.get('pair_status',''), r.get('line_count',''), r.get('origin',''), r.get('path',''))
        tree.insert('', 'end', iid=str(i), values=vals)
    try: self.learn_file_count_var_v49.set(f'{len(rows)} 个学习资源')
    except Exception: pass

def _v49_tree_selected(self, event=None):
    _v49_refresh_file_list(self)

def _v49_new_category(self):
    name = _simpledialog_v49.askstring('新建一级目录', '输入目录名称：')
    if not name: return
    d = _v49_cat_dir(self, name); d.mkdir(parents=True, exist_ok=True)
    (d / '默认文件夹').mkdir(exist_ok=True)
    idx = _v49_load_index(self)
    idx.setdefault('mounted', {}).setdefault(f'{name}/默认文件夹', [])
    _v49_save_index(self, idx)
    _v49_refresh_main_tree(self)

def _v49_new_folder(self):
    selected = _v49_selected_folder(self)
    cat = selected[0] if selected else (_simpledialog_v49.askstring('所属目录', '输入所属一级目录：') or '自定义')
    name = _simpledialog_v49.askstring('新建二级文件夹', f'在【{cat}】下创建文件夹：')
    if not name: return
    _v49_folder_dir(self, cat, name).mkdir(parents=True, exist_ok=True)
    idx = _v49_load_index(self)
    idx.setdefault('mounted', {}).setdefault(f'{cat}/{name}', [])
    _v49_save_index(self, idx)
    _v49_refresh_main_tree(self)

def _v49_delete_selected_node(self):
    tree = getattr(self, 'learn_tree_v49', None)
    if tree is None or not tree.selection(): return
    vals = tree.item(tree.selection()[0], 'values')
    idx = _v49_load_index(self)
    if vals and vals[0] == 'CAT':
        cat = vals[1]
        if not _messagebox_v49.askyesno('删除目录', f'确定删除目录记录【{cat}】？不会删除外部挂载源文件，但会删除库内同名文件夹。'):
            return
        d = _v49_cat_dir(self, cat)
        try:
            if d.exists():
                import shutil; shutil.rmtree(d)
        except Exception as e:
            _v49_log(self, f'删除目录失败：{e}', 'warn')
        idx['records'] = [r for r in idx.get('records', []) if r.get('category') != cat]
        idx['mounted'] = {k:v for k,v in idx.get('mounted', {}).items() if not k.startswith(cat + '/')}
        _v49_save_index(self, idx)
    elif vals and vals[0] == 'FOLDER':
        cat, folder = vals[1], vals[2]
        if not _messagebox_v49.askyesno('删除文件夹', f'确定删除文件夹记录【{cat}/{folder}】？不会删除外部源文件。'):
            return
        d = _v49_folder_dir(self, cat, folder)
        try:
            if d.exists():
                import shutil; shutil.rmtree(d)
        except Exception as e:
            _v49_log(self, f'删除文件夹失败：{e}', 'warn')
        key = f'{cat}/{folder}'
        idx['records'] = [r for r in idx.get('records', []) if not (r.get('category') == cat and r.get('folder') == folder)]
        idx.get('mounted', {}).pop(key, None)
        _v49_save_index(self, idx)
    _v49_refresh_main_tree(self); _v49_refresh_file_list(self)

def _v49_rename_selected_node(self):
    tree = getattr(self, 'learn_tree_v49', None)
    if tree is None or not tree.selection(): return
    vals = tree.item(tree.selection()[0], 'values')
    idx = _v49_load_index(self)
    if vals and vals[0] == 'CAT':
        old = vals[1]
        new = _simpledialog_v49.askstring('重命名目录', '输入新目录名：', initialvalue=old)
        if not new or new == old: return
        old_dir, new_dir = _v49_cat_dir(self, old), _v49_cat_dir(self, new)
        try:
            if old_dir.exists(): old_dir.rename(new_dir)
            else: new_dir.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            _messagebox_v49.showerror('失败', str(e)); return
        for r in idx.get('records', []):
            if r.get('category') == old: r['category'] = new
        idx['mounted'] = {k.replace(old + '/', new + '/', 1) if k.startswith(old + '/') else k: v for k,v in idx.get('mounted', {}).items()}
        _v49_save_index(self, idx)
    elif vals and vals[0] == 'FOLDER':
        cat, old = vals[1], vals[2]
        new = _simpledialog_v49.askstring('重命名文件夹', '输入新文件夹名：', initialvalue=old)
        if not new or new == old: return
        old_dir, new_dir = _v49_folder_dir(self, cat, old), _v49_folder_dir(self, cat, new)
        try:
            if old_dir.exists(): old_dir.rename(new_dir)
            else: new_dir.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            _messagebox_v49.showerror('失败', str(e)); return
        for r in idx.get('records', []):
            if r.get('category') == cat and r.get('folder') == old: r['folder'] = new
        old_key, new_key = f'{cat}/{old}', f'{cat}/{new}'
        if old_key in idx.get('mounted', {}): idx['mounted'][new_key] = idx['mounted'].pop(old_key)
        _v49_save_index(self, idx)
    _v49_refresh_main_tree(self); _v49_refresh_file_list(self)

def _v49_search_resources(self):
    q = getattr(self, 'learn_search_var_v49', tk.StringVar()).get().strip().lower()
    tree = getattr(self, 'learn_file_tree_v49', None)
    if tree is None: return
    rows = _v49_get_records_for_selected(self)
    if q:
        rows = [r for r in rows if q in r.get('name','').lower() or q in r.get('path','').lower() or q in r.get('kind','').lower()]
    tree.delete(*tree.get_children())
    self.learn_rows_v49 = rows
    for i, r in enumerate(rows):
        vals = (r.get('kind',''), r.get('name',''), r.get('pair_status',''), r.get('line_count',''), r.get('origin',''), r.get('path',''))
        tree.insert('', 'end', iid=str(i), values=vals)
    try: self.learn_file_count_var_v49.set(f'搜索结果：{len(rows)} 个')
    except Exception: pass

def _v49_add_path_no_scan(self, is_folder=True):
    folder = _v49_selected_folder(self)
    if not folder:
        _messagebox_v49.showwarning('提示', '请先选择左侧二级文件夹。')
        return
    cat, fol = folder
    if is_folder:
        paths = [_filedialog_v49.askdirectory(title='选择本地文件夹路径')]
        paths = [p for p in paths if p]
    else:
        paths = list(_filedialog_v49.askopenfilenames(title='选择文件路径', filetypes=[('Learning files', '*.txt *.csv *.srt *.vtt *.lrc *.mp3 *.wav *.flac *.m4a *.aac *.ogg'), ('All','*.*')]))
    if not paths: return
    idx = _v49_load_index(self)
    key = f'{cat}/{fol}'
    idx.setdefault('mounted', {}).setdefault(key, [])
    for p in paths:
        if p not in idx['mounted'][key]: idx['mounted'][key].append(p)
    _v49_save_index(self, idx)
    _v49_set_status(self, f'已记录路径 {len(paths)} 个。未立即深度扫描，避免卡死；点击【后台扫描当前文件夹】更新文件列表。')

def _v49_scan_selected_async(self):
    folder = _v49_selected_folder(self)
    if not folder:
        _messagebox_v49.showwarning('提示', '请先选择左侧二级文件夹。')
        return
    cat, fol = folder
    _v49_set_status(self, f'后台扫描中：{cat}/{fol} ...')
    def worker():
        idx = _v49_load_index(self)
        key = f'{cat}/{fol}'
        roots = [_v49_folder_dir(self, cat, fol)]
        roots.extend(_Path_v49(p) for p in idx.get('mounted', {}).get(key, []))
        rows = []
        for root in roots:
            if not root or not root.exists(): continue
            files = [root] if root.is_file() else [p for p in root.rglob('*') if p.is_file()]
            for fp in files:
                if fp.suffix.lower() in V49_VIDEO_EXTS: continue
                if fp.suffix.lower() not in (V49_AUDIO_EXTS | V49_TEXT_EXTS): continue
                rec = _v49_record_from_file(fp, cat, fol, origin=('库内文件夹' if str(fp).startswith(str(_v49_folder_dir(self, cat, fol))) else '外部路径'))
                if rec: rows.append(rec)
        old = [r for r in idx.get('records', []) if not (r.get('category') == cat and r.get('folder') == fol)]
        idx['records'] = old + rows
        _v49_save_index(self, idx)
        try: self.after(0, lambda: (_v49_refresh_file_list(self), _v49_set_status(self, f'后台扫描完成：{len(rows)} 个有效学习资源。')))
        except Exception: pass
    _threading_v49.Thread(target=worker, daemon=True).start()

def _v49_selected_record(self):
    tree = getattr(self, 'learn_file_tree_v49', None)
    rows = getattr(self, 'learn_rows_v49', [])
    if tree is None: return None
    sel = tree.selection()
    if not sel: return None
    try:
        i = int(sel[0]); return rows[i] if 0 <= i < len(rows) else None
    except Exception: return None

def _v49_save_progress(self):
    rec = getattr(self, 'current_learning_record_v49', None)
    if not rec: return
    idx = _v49_load_index(self)
    idx.setdefault('progress', {})[rec.get('id','')] = {
        'line_index': int(getattr(self, 'learn_line_index_v49', 0)),
        'chunk_index': int(getattr(self, 'learn_chunk_index_v49', 0)),
        'word_index': int(getattr(self, 'learn_word_index_v49', 0)),
        'mode': getattr(self, 'learn_mode_var_v49', tk.StringVar(value='听写模式')).get(),
        'play_mode': getattr(self, 'learn_play_mode_var_v49', tk.StringVar(value='整句播放')).get(),
        'saved_at': _time_v49.strftime('%Y-%m-%d %H:%M:%S'),
    }
    _v49_save_index(self, idx)
    self.learn_dirty_v49 = False
    _v49_set_status(self, '学习进度已保存。')

def _v49_load_record(self):
    rec = _v49_selected_record(self)
    if not rec:
        _messagebox_v49.showwarning('提示', '请先在右侧资源文件展示台选中文件。')
        return
    if getattr(self, 'learn_dirty_v49', False):
        ans = _messagebox_v49.askyesnocancel('保存进度', '当前学习进度未保存。加载新文件前是否保存？\n是=保存并加载；否=不保存直接加载；取消=停止加载。')
        if ans is None: return
        if ans: _v49_save_progress(self)
    _v49_load_record_direct(self, rec)

def _v49_load_record_direct(self, rec):
    self.current_learning_record_v49 = rec
    idx = _v49_load_index(self)
    progress = idx.get('progress', {}).get(rec.get('id',''), {})
    self.learn_line_index_v49 = int(progress.get('line_index', 0) or 0)
    self.learn_chunk_index_v49 = int(progress.get('chunk_index', 0) or 0)
    self.learn_word_index_v49 = int(progress.get('word_index', 0) or 0)
    if progress.get('mode') and hasattr(self, 'learn_mode_var_v49'):
        self.learn_mode_var_v49.set(progress['mode'])
    if progress.get('play_mode') and hasattr(self, 'learn_play_mode_var_v49'):
        self.learn_play_mode_var_v49.set(progress['play_mode'])
    lines = []
    if rec.get('text_path'):
        lines = _v49_parse_text_lines(rec.get('text_path'))
    if not lines and rec.get('kind') == '资料文件':
        lines = _v49_parse_text_lines(rec.get('path'))
    if not lines and rec.get('kind') == '听写文件':
        lines = [rec.get('name','').rsplit('.',1)[0]]
    self.learn_lines_v49 = lines
    self.learn_dirty_v49 = False
    _v49_render_learning_line(self)
    _v49_set_status(self, f'已加载：{rec.get("name")}｜{rec.get("kind")}｜{len(lines)} 行')

def _v49_translate_if_needed(self, line):
    if not line: return ''
    if _v49_is_english_line(line):
        return '中文翻译准备中……'
    return line

def _v49_line_chunks(line):
    toks = _re_v49.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(line))
    chunks = []
    cur = []
    for w in toks:
        cur.append(w)
        if len(cur) >= 3:
            chunks.append(' '.join(cur)); cur = []
    if cur: chunks.append(' '.join(cur))
    return chunks or [line]

def _v49_current_target_text(self):
    lines = getattr(self, 'learn_lines_v49', [])
    if not lines: return ''
    line = lines[max(0, min(int(getattr(self, 'learn_line_index_v49', 0)), len(lines)-1))]
    mode = getattr(self, 'learn_mode_var_v49', tk.StringVar(value='听写模式')).get()
    play_mode = getattr(self, 'learn_play_mode_var_v49', tk.StringVar(value='整句播放')).get()
    if mode == '听写模式' and play_mode == '拆分语块':
        chunks = _v49_line_chunks(line)
        ci = max(0, min(int(getattr(self, 'learn_chunk_index_v49', 0)), len(chunks)-1))
        return chunks[ci]
    return line

def _v49_render_learning_line(self):
    area = getattr(self, 'learn_area_v49', None)
    if area is None: return
    for ch in area.winfo_children():
        try: ch.destroy()
        except Exception: pass
    lines = getattr(self, 'learn_lines_v49', [])
    if not lines:
        tk.Label(area, text='请在左侧选择资源文件，点击【加载当前文件】开始学习', bg=V49_BG, fg=V49_TEXT, font=('Microsoft YaHei UI', 22, 'bold')).pack(expand=True)
        return
    idx = max(0, min(int(getattr(self, 'learn_line_index_v49', 0)), len(lines)-1))
    self.learn_line_index_v49 = idx
    line = lines[idx]
    mode = self.learn_mode_var_v49.get()
    play_mode = self.learn_play_mode_var_v49.get()
    top = tk.Frame(area, bg=V49_BG); top.pack(fill='x', pady=(18,8))
    tk.Label(top, text=f'{idx+1}/{len(lines)} ｜ {mode} ｜ {play_mode}', bg=V49_BG, fg=V49_MUTED, font=('Consolas', 12, 'bold')).pack(side='right', padx=12)
    zh = _v49_translate_if_needed(self, line)
    if mode == '盲听模式': prompt = '盲听模式：不显示中文翻译，请直接默写英文。'
    elif mode == '歌词模式': prompt = zh if not _v49_is_english_line(zh) else '歌词模式：声音与字幕同步显示。'
    else: prompt = zh
    tk.Label(area, text=prompt, bg=V49_BG, fg=V49_TEXT, font=('Microsoft YaHei UI', 24, 'bold'), wraplength=1000, justify='center').pack(pady=(12,18))
    target = _v49_current_target_text(self)
    words = _re_v49.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", target)
    self.learn_current_words_v49 = words
    self.learn_word_index_v49 = max(0, min(int(getattr(self, 'learn_word_index_v49', 0)), max(len(words)-1,0)))
    line_frame = tk.Frame(area, bg=V49_BG); line_frame.pack(anchor='center', pady=(22,12))
    self.learn_word_entries_v49 = []
    for wi, w in enumerate(words):
        cell = tk.Frame(line_frame, bg=V49_BG); cell.pack(side='left', padx=4, pady=6)
        width = max(4, min(18, len(w)+1))
        var = tk.StringVar()
        ent = tk.Entry(cell, textvariable=var, width=width, justify='center', bg=V49_BG, fg=V49_TEXT, insertbackground=V49_ACCENT, relief='flat', bd=0, font=('Consolas', 18, 'bold'))
        ent.pack()
        cw = max(48, width*14)
        cv = tk.Canvas(cell, width=cw, height=7, bg=V49_BG, highlightthickness=0); cv.pack()
        cv.create_line(2,3,cw-2,3,fill=V49_ACCENT if wi == self.learn_word_index_v49 else '#CBD5E1',width=3)
        item = {'word': w, 'var': var, 'entry': ent, 'line': cv, 'w': cw, 'index': wi}
        self.learn_word_entries_v49.append(item)
        ent.bind('<KeyRelease>', lambda e, it=item: _v49_live_word_feedback(self, it))
        ent.bind('<space>', lambda e, it=item: (_v49_confirm_word(self, it), 'break'))
        ent.bind('<Return>', lambda e: (_v49_submit_line(self), 'break'))
    if self.learn_word_entries_v49:
        self.learn_word_entries_v49[self.learn_word_index_v49]['entry'].focus_set()
    if mode == '歌词模式':
        lyric = tk.Text(area, bg=V49_CARD, fg=V49_TEXT, relief='flat', wrap='word', height=8, font=('Microsoft YaHei UI', 11))
        lyric.pack(fill='both', expand=True, padx=16, pady=16)
        for l in lines[max(0, idx-5): idx+8]:
            if _v49_is_english_line(l): lyric.insert('end', l + '\n', ('en',))
            else: lyric.insert('end', l + '\n', ('other',))
        lyric.tag_config('en', foreground='#93c5fd')
        lyric.tag_config('other', foreground='#e5e7eb')
        lyric.configure(state='disabled')
    self.learn_dirty_v49 = True

def _v49_set_word_line(item, color):
    try:
        item['line'].delete('all')
        item['line'].create_line(2,3,item['w']-2,3,fill=color,width=3)
    except Exception: pass

def _v49_live_word_feedback(self, item):
    ans = item['var'].get().strip(); tgt = item['word']
    try:
        if '_v48_beep' in globals(): globals()['_v48_beep'](self, 'type')
    except Exception: pass
    if not ans:
        item['entry'].configure(fg=V49_TEXT); _v49_set_word_line(item, V49_ACCENT if item['index'] == getattr(self, 'learn_word_index_v49', 0) else '#CBD5E1'); return
    if ans.lower() == tgt.lower():
        item['entry'].configure(fg=V49_OK); _v49_set_word_line(item, V49_OK)
    elif len(ans) >= len(tgt):
        item['entry'].configure(fg=V49_BAD); _v49_set_word_line(item, V49_BAD)
    else:
        item['entry'].configure(fg=V49_WARN); _v49_set_word_line(item, V49_WARN)

def _v49_confirm_word(self, item=None):
    entries = getattr(self, 'learn_word_entries_v49', [])
    if not entries: return False
    if item is None:
        idx = int(getattr(self, 'learn_word_index_v49', 0)); item = entries[max(0, min(idx, len(entries)-1))]
    ans = item['var'].get().strip(); tgt = item['word']
    if ans.lower() == tgt.lower():
        item['entry'].configure(fg=V49_OK); _v49_set_word_line(item, V49_OK)
        try:
            if '_v48_beep' in globals(): globals()['_v48_beep'](self, 'ok')
        except Exception: pass
        next_i = item['index'] + 1
        if next_i < len(entries):
            self.learn_word_index_v49 = next_i
            entries[next_i]['entry'].focus_set(); _v49_set_word_line(entries[next_i], V49_ACCENT)
        else:
            _v49_submit_line(self)
        return True
    try:
        if '_v48_beep' in globals(): globals()['_v48_beep'](self, 'bad')
    except Exception: pass
    item['entry'].configure(fg=V49_BAD); _v49_set_word_line(item, V49_BAD)
    _v49_set_status(self, f'❌ 当前词错误：输入[{ans or "空"}]，应为[{tgt}]')
    return False

def _v49_submit_line(self):
    entries = getattr(self, 'learn_word_entries_v49', [])
    if not entries: return False
    ok = True
    for it in entries:
        ans = it['var'].get().strip()
        if ans.lower() == it['word'].lower():
            it['entry'].configure(fg=V49_OK); _v49_set_word_line(it, V49_OK)
        else:
            it['entry'].configure(fg=V49_BAD); _v49_set_word_line(it, V49_BAD); ok = False
    if ok:
        try:
            if '_v48_beep' in globals(): globals()['_v48_beep'](self, 'sentence')
        except Exception: pass
        _v49_set_status(self, '✅ 当前句/语块全部正确。')
        mode = self.learn_mode_var_v49.get(); play_mode = self.learn_play_mode_var_v49.get()
        if mode == '听写模式' and play_mode == '拆分语块':
            chunks = _v49_line_chunks(getattr(self, 'learn_lines_v49', [''])[getattr(self, 'learn_line_index_v49',0)])
            ci = int(getattr(self, 'learn_chunk_index_v49', 0))
            if ci + 1 < len(chunks):
                self.learn_chunk_index_v49 = ci + 1; self.learn_word_index_v49 = 0
                _v49_render_learning_line(self); _v49_play_current(self); return True
        if getattr(self, 'learn_auto_next_var_v49', tk.BooleanVar(value=True)).get():
            _v49_next_line(self, play=True)
    else:
        _v49_set_status(self, '仍有错误：绿色正确，红色错误；空格确认当前单词。')
    return ok

def _v49_next_line(self, play=False):
    lines = getattr(self, 'learn_lines_v49', [])
    if not lines: return
    self.learn_line_index_v49 = min(len(lines)-1, int(getattr(self, 'learn_line_index_v49', 0)) + 1)
    self.learn_chunk_index_v49 = 0; self.learn_word_index_v49 = 0
    _v49_render_learning_line(self); _v49_save_progress(self)
    if play: _v49_play_current(self)

def _v49_prev_line(self):
    lines = getattr(self, 'learn_lines_v49', [])
    if not lines: return
    self.learn_line_index_v49 = max(0, int(getattr(self, 'learn_line_index_v49', 0)) - 1)
    self.learn_chunk_index_v49 = 0; self.learn_word_index_v49 = 0
    _v49_render_learning_line(self)

def _v49_play_current(self):
    rec = getattr(self, 'current_learning_record_v49', None)
    mode = getattr(self, 'learn_mode_var_v49', tk.StringVar(value='听写模式')).get()
    if rec and rec.get('audio_path') and mode in ('歌词模式', '听写模式', '盲听模式'):
        p = _Path_v49(rec.get('audio_path'))
        if p.exists():
            try:
                for fn in ('_v44_mci_play', '_v45_mci_play'):
                    if fn in globals(): globals()[fn](p); return
            except Exception as e:
                _v49_set_status(self, f'本地音频播放失败，改用发音引擎：{e}')
    text = _v49_current_target_text(self)
    try:
        if '_v48_speak_managed' in globals(): globals()['_v48_speak_managed'](self, text, force=True); return
    except Exception: pass
    for fn in ('_v45_speak_edge_api', '_v44_speak_text'):
        if fn in globals():
            try: return globals()[fn](self, text)
            except Exception: pass

def _v49_set_status(self, msg):
    try: self.learn_status_var_v49.set(msg)
    except Exception:
        try: self.recite_status_var_v48.set(msg)
        except Exception: pass

def _v49_open_resource_platform(self):
    win = tk.Toplevel(self)
    win.title('学习资源平台 V49：增删查改目录 / 添加路径 / 后台扫描')
    win.geometry('1280x760')
    root = ttk.Frame(win, padding=10); root.pack(fill='both', expand=True)
    top = ttk.Frame(root); top.pack(fill='x', pady=(0,8))
    ttk.Label(top, text='学习资源根目录').pack(side='left')
    ttk.Entry(top, textvariable=self.learn_root_var_v49, width=90).pack(side='left', padx=8)
    ttk.Button(top, text='选择根目录', command=lambda: _v49_choose_root(self)).pack(side='left', padx=3)
    ttk.Button(top, text='初始化目录', command=lambda: _v49_init_dirs(self)).pack(side='left', padx=3)
    ttk.Button(top, text='打开根目录', command=lambda: _v49_open_root(self)).pack(side='left', padx=3)
    bar = ttk.Frame(root); bar.pack(fill='x', pady=(0,8))
    ttk.Button(bar, text='新建目录', command=lambda: _v49_new_category(self)).pack(side='left', padx=3)
    ttk.Button(bar, text='新建文件夹', command=lambda: _v49_new_folder(self)).pack(side='left', padx=3)
    ttk.Button(bar, text='重命名', command=lambda: _v49_rename_selected_node(self)).pack(side='left', padx=3)
    ttk.Button(bar, text='删除', command=lambda: _v49_delete_selected_node(self)).pack(side='left', padx=3)
    ttk.Button(bar, text='添加文件路径', command=lambda: _v49_add_path_no_scan(self, is_folder=False)).pack(side='left', padx=3)
    ttk.Button(bar, text='添加文件夹路径', command=lambda: _v49_add_path_no_scan(self, is_folder=True)).pack(side='left', padx=3)
    ttk.Button(bar, text='后台扫描当前文件夹', command=lambda: _v49_scan_selected_async(self)).pack(side='left', padx=3)
    ttk.Button(bar, text='刷新列表', command=lambda: (_v49_refresh_main_tree(self), _v49_refresh_file_list(self))).pack(side='left', padx=3)
    self.learn_search_var_v49 = getattr(self, 'learn_search_var_v49', tk.StringVar())
    ttk.Label(bar, text='查找').pack(side='left', padx=(18,3))
    ttk.Entry(bar, textvariable=self.learn_search_var_v49, width=28).pack(side='left')
    ttk.Button(bar, text='查找', command=lambda: _v49_search_resources(self)).pack(side='left', padx=3)
    ttk.Button(bar, text='选定并返回主界面', command=lambda: (win.destroy(), _v49_refresh_main_tree(self), _v49_refresh_file_list(self))).pack(side='right', padx=3)
    ttk.Label(root, text='提示：添加路径只记录，不会立即深度扫描；点击【后台扫描当前文件夹】才更新文件列表，避免卡死。').pack(fill='x', pady=(4,0))

def _v49_choose_root(self):
    d = _filedialog_v49.askdirectory(title='选择学习资源根目录')
    if not d: return
    self.learn_root_var_v49.set(d); _v49_init_dirs(self)

def _v49_open_root(self):
    root = _v49_root(self); root.mkdir(parents=True, exist_ok=True)
    try:
        if _os_v49.name == 'nt': _os_v49.startfile(str(root))
        else: _subprocess_v49.Popen(['xdg-open', str(root)])
    except Exception: pass

def _v49_rebuild_main_learning_ui(self):
    tab = getattr(self, 'tab_recite_v37', None)
    if tab is None: return
    for ch in tab.winfo_children():
        try: ch.destroy()
        except Exception: pass
    if not hasattr(self, 'learn_root_var_v49'):
        self.learn_root_var_v49 = tk.StringVar(value=str(_Path_v49.cwd() / 'playphrase_learning_library'))
    self.learn_mode_var_v49 = tk.StringVar(value='听写模式')
    self.learn_play_mode_var_v49 = tk.StringVar(value='整句播放')
    self.learn_auto_next_var_v49 = tk.BooleanVar(value=True)
    self.learn_status_var_v49 = tk.StringVar(value='先到资源平台创建/扫描资源，然后在左侧选择文件并加载。')
    self.learn_dirty_v49 = False
    bg = V49_BG
    root = tk.Frame(tab, bg=bg); root.pack(fill='both', expand=True)
    top = tk.Frame(root, bg=bg); top.pack(fill='x', padx=10, pady=8)
    ttk.Button(top, text='资源平台', style='Accent.TButton', command=lambda: _v49_open_resource_platform(self)).pack(side='left', padx=4)
    ttk.Button(top, text='隐藏/显示左侧资源树', command=lambda: _v49_toggle_left(self)).pack(side='left', padx=4)
    ttk.Button(top, text='加载当前文件', command=lambda: _v49_load_record(self)).pack(side='left', padx=4)
    ttk.Button(top, text='保存进度', command=lambda: _v49_save_progress(self)).pack(side='left', padx=4)
    ttk.Button(top, text='播放当前', command=lambda: _v49_play_current(self)).pack(side='left', padx=4)
    ttk.Button(top, text='上一句', command=lambda: _v49_prev_line(self)).pack(side='left', padx=4)
    ttk.Button(top, text='下一句', command=lambda: _v49_next_line(self, play=False)).pack(side='left', padx=4)
    ttk.Combobox(top, textvariable=self.learn_mode_var_v49, values=['歌词模式', '听写模式', '盲听模式'], width=10, state='readonly').pack(side='left', padx=8)
    ttk.Combobox(top, textvariable=self.learn_play_mode_var_v49, values=['整句播放', '拆分语块'], width=10, state='readonly').pack(side='left', padx=4)
    ttk.Checkbutton(top, text='自动跳转下一句', variable=self.learn_auto_next_var_v49).pack(side='left', padx=6)
    body = tk.PanedWindow(root, orient='horizontal', bg=bg, sashwidth=8, sashrelief='flat')
    body.pack(fill='both', expand=True, padx=10, pady=4)
    left = tk.Frame(body, bg=V49_PANEL, width=420)
    main = tk.Frame(body, bg=bg)
    body.add(left, minsize=0); body.add(main, minsize=620)
    self.learn_paned_v49 = body; self.learn_left_v49 = left
    tk.Label(left, text='资源所在位置 / 同级文件', bg=V49_PANEL, fg=V49_TEXT, font=('Microsoft YaHei UI', 11, 'bold')).pack(anchor='w', padx=10, pady=(10,4))
    self.learn_tree_v49 = ttk.Treeview(left, show='tree', height=12)
    self.learn_tree_v49.pack(fill='both', expand=True, padx=10, pady=4)
    self.learn_tree_v49.bind('<<TreeviewSelect>>', lambda e: _v49_tree_selected(self))
    self.learn_file_count_var_v49 = tk.StringVar(value='0 个学习资源')
    tk.Label(left, textvariable=self.learn_file_count_var_v49, bg=V49_PANEL, fg=V49_MUTED).pack(anchor='w', padx=10)
    table_frame = tk.Frame(left, bg=V49_PANEL); table_frame.pack(fill='both', expand=True, padx=10, pady=(2,10))
    cols = ('kind','name','pair','lines','origin','path')
    self.learn_file_tree_v49 = ttk.Treeview(table_frame, columns=cols, show='headings', height=14)
    vs = ttk.Scrollbar(table_frame, orient='vertical', command=self.learn_file_tree_v49.yview)
    hs = ttk.Scrollbar(table_frame, orient='horizontal', command=self.learn_file_tree_v49.xview)
    self.learn_file_tree_v49.configure(yscrollcommand=vs.set, xscrollcommand=hs.set)
    heads = {'kind':'类型','name':'文件名','pair':'链接','lines':'行数','origin':'来源','path':'路径'}
    widths = {'kind':80,'name':180,'pair':90,'lines':50,'origin':80,'path':520}
    for c in cols:
        self.learn_file_tree_v49.heading(c, text=heads[c]); self.learn_file_tree_v49.column(c, width=widths[c], anchor='w')
    self.learn_file_tree_v49.grid(row=0, column=0, sticky='nsew')
    vs.grid(row=0, column=1, sticky='ns'); hs.grid(row=1, column=0, sticky='ew')
    table_frame.rowconfigure(0, weight=1); table_frame.columnconfigure(0, weight=1)
    self.learn_file_tree_v49.bind('<Double-Button-1>', lambda e: _v49_load_record(self))
    self.learn_area_v49 = tk.Frame(main, bg=bg); self.learn_area_v49.pack(fill='both', expand=True)
    tk.Label(main, textvariable=self.learn_status_var_v49, bg=bg, fg=V49_MUTED, font=('Microsoft YaHei UI', 11), anchor='w').pack(fill='x', padx=10, pady=(0,8))
    _v49_init_dirs(self); _v49_render_learning_line(self)

def _v49_toggle_left(self):
    try:
        panes = self.learn_paned_v49.panes()
        if str(self.learn_left_v49) in panes:
            self.learn_paned_v49.forget(self.learn_left_v49)
        else:
            self.learn_paned_v49.add(self.learn_left_v49, minsize=0)
    except Exception: pass

def _v49_patch_old_resource_station(self):
    tab = getattr(self, 'tab_resource_platform_v32', None) or getattr(self, 'tab_resource', None) or getattr(self, 'tab_resources', None)
    if tab is None: return
    for ch in tab.winfo_children():
        try: ch.destroy()
        except Exception: pass
    box = ttk.Frame(tab, padding=24); box.pack(fill='both', expand=True)
    ttk.Label(box, text='我的资源站已改为独立资源平台').pack(anchor='w')
    ttk.Label(box, text='资源平台用于增删查改目录、记录路径、后台扫描；学习主界面只显示选中的资源位置和文件列表。').pack(anchor='w', pady=8)
    ttk.Button(box, text='打开资源平台', style='Accent.TButton', command=lambda: _v49_open_resource_platform(self)).pack(anchor='w', pady=8)

def _v49_patch_methods(self):
    try:
        globals()['_v48_rebuild_recite_mode'] = lambda app: _v49_rebuild_main_learning_ui(app)
        globals()['_v48_rebuild_resource_station'] = lambda app: _v49_patch_old_resource_station(app)
        globals()['_v47_rebuild_resource_platform'] = lambda app: _v49_patch_old_resource_station(app)
    except Exception: pass
    try:
        self.bind_all('<KeyPress-Control_L>', lambda e: (globals()['_v48_speak_managed'](self, _v49_current_target_text(self), repeat=True), 'break') if '_v48_speak_managed' in globals() else None)
        self.bind_all('<KeyPress-Control_R>', lambda e: (globals()['_v48_speak_managed'](self, _v49_current_target_text(self), repeat=True), 'break') if '_v48_speak_managed' in globals() else None)
    except Exception: pass

_old_main_init_v49 = MainApp.__init__
def _main_init_v49(self):
    _old_main_init_v49(self)
    try:
        _v49_patch_methods(self)
        _v49_rebuild_main_learning_ui(self)
        _v49_patch_old_resource_station(self)
        self.log('【V49上线】加载路径不再直接深度扫描；添加路径只记录，后台扫描才更新列表，避免卡死。', 'ok')
        self.log('【V49上线】资源平台独立化：增删查改目录/文件夹/路径在资源平台完成；主界面只用于学习。', 'ok')
        self.log('【V49上线】文件状态机：歌词文件=音频+文本；听写文件=只有音频；资料文件=英文文本。', 'ok')
        self.log('【V49上线】学习区支持歌词模式/听写模式/盲听模式；空格确认当前单词，整句/语块完成后才跳转。', 'ok')
    except Exception as e:
        try: self.log(f'V49初始化失败：{type(e).__name__}: {e}', 'err')
        except Exception: pass

MainApp.__init__ = _main_init_v49
APP_TITLE = 'PlayPhrase Studio Clean v49 · 独立资源平台+不卡顿加载+三文件三模式版'


# ──────────────────────────────────────────────────────────────────────
# V50: 双资源库 + 精选池安全导入 + 本地视频递归扫描恢复
# 修复：V49 听写加载精选池卡死；恢复本地递归扫描视频+字幕；资源平台听写/背诵目录独立。
# ──────────────────────────────────────────────────────────────────────
import os as _os_v50
import re as _re_v50
import json as _json_v50
import time as _time_v50
import threading as _threading_v50
import subprocess as _subprocess_v50
from pathlib import Path as _Path_v50

try:
    from tkinter import filedialog as _filedialog_v50, messagebox as _messagebox_v50, simpledialog as _simpledialog_v50
except Exception:
    pass

V50_VIDEO_EXTS = {'.mp4', '.mkv', '.avi', '.mov', '.webm', '.m4v'}
V50_AUDIO_EXTS = {'.mp3', '.wav', '.flac', '.m4a', '.aac', '.ogg', '.wma'}
V50_TEXT_EXTS = {'.txt', '.srt', '.ass', '.ssa', '.vtt', '.csv', '.lrc'}
V50_SUB_EXTS = {'.srt', '.ass', '.ssa', '.vtt', '.txt'}
V50_MAX_SYNC_ITEMS = 8000
V50_DISPLAY_LIMIT = 3000
V50_DICT_TOPS = {
    'PlayPhrase在线精选': ['精选池', '搜索缓存', '自定义在线'],
    '本地视频字幕': ['影视剧', '课程视频', '短视频', '演讲采访', '自定义视频'],
    '本地文本资源': ['口语句子', '考试听写', '教材课文', '自定义文本'],
}
V50_RECITE_TOPS = {
    '背诵文本资料': ['四六级', '专四专八', '考研', '托福', '雅思', '计算机', '医药专业', 'AI英语', '自定义'],
    '音频歌词资料': ['YouTube音乐', '播客', '歌曲', '听力音频', '自定义音频'],
    '纯单词文档': ['单词本', '短语本', '专业词汇', '自定义词表'],
}

def _v50_log(self, msg, level='info'):
    try: self.log(msg, level)
    except Exception: print(msg)

def _v50_safe(s):
    return _re_v50.sub(r'[\\/:*?"<>|]+', '_', str(s or '').strip())[:120] or '未命名'

def _v50_root(self):
    if not hasattr(self, 'resource_hub_root_var_v50'):
        self.resource_hub_root_var_v50 = tk.StringVar(value=str(_Path_v50.cwd() / 'playphrase_resource_hub_v50'))
    return _Path_v50(self.resource_hub_root_var_v50.get()).expanduser()

def _v50_mode_root(self, mode):
    return _v50_root(self) / ('dictation' if mode == 'dictation' else 'recite')

def _v50_index_path(self, mode):
    return _v50_mode_root(self, mode) / ('.dictation_resource_index_v50.json' if mode == 'dictation' else '.recite_resource_index_v50.json')

def _v50_struct(mode):
    return V50_DICT_TOPS if mode == 'dictation' else V50_RECITE_TOPS

def _v50_load_index(self, mode):
    fp = _v50_index_path(self, mode)
    if not fp.exists():
        return {'version': 50, 'mode': mode, 'mounted': {}, 'records': [], 'created_at': _time_v50.strftime('%Y-%m-%d %H:%M:%S')}
    try:
        data = _json_v50.loads(fp.read_text('utf-8'))
        data.setdefault('mounted', {}); data.setdefault('records', [])
        return data
    except Exception:
        return {'version': 50, 'mode': mode, 'mounted': {}, 'records': []}

def _v50_save_index(self, mode, data):
    root = _v50_mode_root(self, mode); root.mkdir(parents=True, exist_ok=True)
    data['updated_at'] = _time_v50.strftime('%Y-%m-%d %H:%M:%S')
    _v50_index_path(self, mode).write_text(_json_v50.dumps(data, ensure_ascii=False, indent=2), 'utf-8')

def _v50_cat_dir(self, mode, top, folder):
    return _v50_mode_root(self, mode) / _v50_safe(top) / _v50_safe(folder)

def _v50_init_dirs(self):
    for mode in ('dictation', 'recite'):
        idx = _v50_load_index(self, mode)
        for top, folders in _v50_struct(mode).items():
            for folder in folders:
                _v50_cat_dir(self, mode, top, folder).mkdir(parents=True, exist_ok=True)
                idx.setdefault('mounted', {}).setdefault(f'{top}/{folder}', [])
        _v50_save_index(self, mode, idx)

def _v50_read_lines(path):
    try: raw = _Path_v50(path).read_text('utf-8-sig', errors='ignore')
    except Exception: return []
    out=[]
    for line in raw.splitlines():
        s=line.strip()
        s=_re_v50.sub(r'^\[[0-9:.]+\]', '', s).strip()
        if not s or '-->' in s or _re_v50.fullmatch(r'\d+', s): continue
        s=_re_v50.sub(r'<[^>]+>', '', s).strip()
        if s: out.append(s)
    return out

def _v50_is_english_text(path):
    sample='\n'.join(_v50_read_lines(path)[:80])
    latin=len(_re_v50.findall(r'[A-Za-z]', sample)); cjk=len(_re_v50.findall(r'[\u4e00-\u9fff]', sample))
    return latin >= 5 and latin >= cjk

def _v50_find_sub(video):
    p=_Path_v50(video); cands=[]
    for ext in ['.srt','.ass','.ssa','.vtt','.txt']:
        for tag in ['', '.en', '.eng', '.english', '.zh', '.chs', '.cht', '.cn', '_en', '_zh', '.bilingual', '.双语']:
            cands.append(_Path_v50(str(p.with_suffix('')) + tag + ext))
    try: cands += [x for x in p.parent.glob(p.stem+'*') if x.suffix.lower() in V50_SUB_EXTS]
    except Exception: pass
    seen=set(); out=[]
    for c in cands:
        if c.exists() and str(c) not in seen:
            out.append(c); seen.add(str(c))
    out.sort(key=lambda x: (0 if _re_v50.search(r'双语|bilingual|en|eng|english', x.name, _re_v50.I) else 1, len(x.name)))
    return str(out[0]) if out else ''

def _v50_make_record(self, mode, top, folder, path_or_url, origin='外部路径'):
    s=str(path_or_url)
    if mode=='dictation' and (s.startswith(('http://','https://')) or top=='PlayPhrase在线精选'):
        return {'id':f'dictation|{top}|{folder}|{s}','mode':'dictation','top':top,'folder':folder,'origin':origin,'resource_type':'在线PlayPhrase','kind':'online','name':s[:100],'path':s,'video_url':s if s.startswith(('http://','https://')) else '', 'subtitle_path':'','line_count':'','status':'待解析'}
    p=_Path_v50(s); ext=p.suffix.lower()
    if mode=='dictation':
        if ext in V50_VIDEO_EXTS:
            sub=_v50_find_sub(p)
            return {'id':f'dictation|{top}|{folder}|{p}','mode':'dictation','top':top,'folder':folder,'origin':origin,'resource_type':'本地视频字幕','kind':'video','name':p.name,'path':str(p),'video_path':str(p),'subtitle_path':sub,'line_count':len(_v50_read_lines(sub)) if sub else 0,'status':'视频+字幕' if sub else '缺字幕'}
        if ext in V50_TEXT_EXTS and _v50_is_english_text(p):
            return {'id':f'dictation|{top}|{folder}|{p}','mode':'dictation','top':top,'folder':folder,'origin':origin,'resource_type':'本地文本资源','kind':'text','name':p.name,'path':str(p),'subtitle_path':str(p),'line_count':len(_v50_read_lines(p)),'status':'英文文本'}
        return None
    # recite: no video
    if ext in V50_VIDEO_EXTS: return None
    audio=''; text=''
    if ext in V50_AUDIO_EXTS:
        audio=str(p)
        for e in ['.lrc','.srt','.vtt','.txt','.csv']:
            if p.with_suffix(e).exists(): text=str(p.with_suffix(e)); break
        return {'id':f'recite|{top}|{folder}|{p}','mode':'recite','top':top,'folder':folder,'origin':origin,'resource_type':'音频歌词资料' if text else '音频资料','kind':'audio','name':p.name,'path':str(p),'audio_path':audio,'text_path':text,'line_count':len(_v50_read_lines(text)) if text else 0,'status':'音频+文本' if text else '只有音频'}
    if ext in V50_TEXT_EXTS and _v50_is_english_text(p):
        text=str(p)
        for e in ['.mp3','.wav','.flac','.m4a','.aac','.ogg','.wma']:
            if p.with_suffix(e).exists(): audio=str(p.with_suffix(e)); break
        return {'id':f'recite|{top}|{folder}|{p}','mode':'recite','top':top,'folder':folder,'origin':origin,'resource_type':'歌词文件' if audio else '资料文件','kind':'text','name':p.name,'path':str(p),'audio_path':audio,'text_path':text,'line_count':len(_v50_read_lines(text)),'status':'音频+文本' if audio else '英文文本'}
    return None

def _v50_selected_folder(self, mode):
    tree=getattr(self, f'{mode}_tree_v50', None)
    if not tree or not tree.selection(): return None
    vals=tree.item(tree.selection()[0], 'values')
    if vals and vals[0]=='FOLDER': return vals[1], vals[2]
    if vals and vals[0]=='TOP':
        top=vals[1]; folders=list(_v50_struct(mode).get(top, ['默认']))
        return top, folders[0]
    return None

def _v50_refresh_tree(self, mode):
    tree=getattr(self, f'{mode}_tree_v50', None)
    if not tree: return
    tree.delete(*tree.get_children())
    root=_v50_mode_root(self, mode); root.mkdir(parents=True, exist_ok=True)
    rid=tree.insert('', 'end', text=('听写资源库：' if mode=='dictation' else '背诵资源库：')+str(root), open=True, values=('ROOT',str(root)))
    for top, defaults in _v50_struct(mode).items():
        tdir=root/_v50_safe(top); tdir.mkdir(parents=True, exist_ok=True)
        tid=tree.insert(rid,'end',text='📁 '+top,open=True,values=('TOP',top))
        folders=set(defaults); folders.update([p.name for p in tdir.iterdir() if p.is_dir()])
        for folder in sorted(folders):
            (tdir/_v50_safe(folder)).mkdir(parents=True, exist_ok=True)
            tree.insert(tid,'end',text='📂 '+folder,open=False,values=('FOLDER',top,folder))

def _v50_rows(self, mode):
    idx=_v50_load_index(self, mode); rows=idx.get('records', [])
    sel=_v50_selected_folder(self, mode)
    if sel:
        top,folder=sel; rows=[r for r in rows if r.get('top')==top and r.get('folder')==folder]
    qv=getattr(self, f'{mode}_search_v50', None); q=qv.get().lower().strip() if qv else ''
    if q: rows=[r for r in rows if q in r.get('name','').lower() or q in r.get('path','').lower() or q in r.get('resource_type','').lower()]
    return rows

def _v50_refresh_table(self, mode):
    table=getattr(self, f'{mode}_table_v50', None)
    if not table: return
    table.delete(*table.get_children())
    rows=_v50_rows(self, mode); setattr(self, f'{mode}_rows_v50', rows)
    for i,r in enumerate(rows[:V50_DISPLAY_LIMIT]):
        table.insert('', 'end', iid=str(i), values=(r.get('resource_type',''), r.get('name',''), r.get('status',''), r.get('line_count',''), r.get('origin',''), r.get('path','')))
    cv=getattr(self, f'{mode}_count_v50', None)
    if cv: cv.set(f'{len(rows)} 条资源' + (f'（仅显示前 {V50_DISPLAY_LIMIT} 条）' if len(rows)>V50_DISPLAY_LIMIT else ''))

def _v50_add_path(self, mode, is_folder=True):
    sel=_v50_selected_folder(self, mode)
    if not sel:
        _messagebox_v50.showwarning('提示','请先选择左侧资源文件夹。'); return
    top,folder=sel
    paths=[]
    if is_folder:
        d=_filedialog_v50.askdirectory(title='选择要记录的文件夹路径')
        if d: paths=[d]
    else:
        paths=list(_filedialog_v50.askopenfilenames(title='选择要记录的文件路径'))
    if not paths: return
    idx=_v50_load_index(self, mode); key=f'{top}/{folder}'
    idx.setdefault('mounted',{}).setdefault(key,[])
    for p in paths:
        if p not in idx['mounted'][key]: idx['mounted'][key].append(p)
    _v50_save_index(self, mode, idx)
    _v50_status(self, mode, f'已记录 {len(paths)} 个路径。不会立刻扫描，点击后台扫描才递归解析，避免卡死。')

def _v50_scan_async(self, mode):
    sel=_v50_selected_folder(self, mode)
    if not sel:
        _messagebox_v50.showwarning('提示','请先选择左侧资源文件夹。'); return
    top,folder=sel; _v50_status(self, mode, f'后台扫描中：{top}/{folder} ...')
    def worker():
        idx=_v50_load_index(self, mode); key=f'{top}/{folder}'
        roots=[_v50_cat_dir(self, mode, top, folder)] + [_Path_v50(p) for p in idx.get('mounted',{}).get(key,[])]
        rows=[]
        for root in roots:
            if not root.exists(): continue
            files=[root] if root.is_file() else [x for x in root.rglob('*') if x.is_file()]
            for fp in files:
                if fp.suffix.lower() not in (V50_VIDEO_EXTS|V50_AUDIO_EXTS|V50_TEXT_EXTS): continue
                rec=_v50_make_record(self, mode, top, folder, fp, origin='库内目录' if str(fp).startswith(str(_v50_cat_dir(self,mode,top,folder))) else '外部路径')
                if rec: rows.append(rec)
        old=[r for r in idx.get('records',[]) if not (r.get('top')==top and r.get('folder')==folder)]
        idx['records']=old+rows; _v50_save_index(self, mode, idx)
        try: self.after(0, lambda: (_v50_refresh_table(self, mode), _v50_status(self, mode, f'扫描完成：{len(rows)} 条有效资源。')))
        except Exception: pass
    _threading_v50.Thread(target=worker, daemon=True).start()

def _v50_status(self, mode, msg):
    var=getattr(self, f'{mode}_status_v50', None)
    if var: var.set(msg)
    else: _v50_log(self,msg,'info')

def _v50_add_online(self):
    sel=_v50_selected_folder(self,'dictation') or ('PlayPhrase在线精选','自定义在线')
    url=_simpledialog_v50.askstring('添加在线资源','输入 PlayPhrase URL 或在线资源标识：')
    if not url: return
    rec=_v50_make_record(self,'dictation',sel[0],sel[1],url,origin='在线URL')
    idx=_v50_load_index(self,'dictation')
    idx['records']=[r for r in idx.get('records',[]) if r.get('id')!=rec['id']] + [rec]
    _v50_save_index(self,'dictation',idx); _v50_refresh_table(self,'dictation')

def _v50_selected_rows(self, mode):
    table=getattr(self, f'{mode}_table_v50', None); rows=getattr(self, f'{mode}_rows_v50', [])
    if not table: return []
    out=[]
    for iid in table.selection():
        try:
            i=int(iid)
            if 0<=i<len(rows): out.append(rows[i])
        except Exception: pass
    return out

def _v50_apply_dictation(self, mats, label=''):
    self.dictation_materials_v30=mats or []
    self.dictation_index_v30=0
    self.dict_items_v33=self.dictation_materials_v30
    self.dict_index_v33=0
    try:
        if '_v46_refresh_material_tree' in globals(): globals()['_v46_refresh_material_tree'](self)
        elif hasattr(self,'_dictation_refresh_material_list_v30'): self._dictation_refresh_material_list_v30()
    except Exception: pass
    try:
        if hasattr(self,'_dictation_refresh_current_v30'): self._dictation_refresh_current_v30()
    except Exception: pass
    try:
        if hasattr(self,'nb') and hasattr(self,'tab_dictation'): self.nb.select(self.tab_dictation)
    except Exception: pass
    _v50_log(self, f'已加载听写素材 {len(self.dictation_materials_v30)} 条 {label}', 'ok')

def _v50_sync_to_dictation_async(self):
    rows=_v50_selected_rows(self,'dictation') or _v50_rows(self,'dictation')
    if not rows:
        _messagebox_v50.showwarning('提示','没有可同步的听写资源。'); return
    if len(rows)>300 and not _messagebox_v50.askyesno('数量较多', f'将后台解析 {len(rows)} 个资源，最多导入 {V50_MAX_SYNC_ITEMS} 条。继续吗？'):
        return
    _v50_status(self,'dictation','后台同步到听写素材池中……')
    def worker():
        mats=[]
        for r in rows:
            if len(mats)>=V50_MAX_SYNC_ITEMS: break
            rt=r.get('resource_type')
            if rt=='在线PlayPhrase':
                mats.append({'text':r.get('name','online resource'),'zh':'','title':r.get('name',''),'video_url':r.get('video_url') or r.get('path',''),'source_type':'online_playphrase','resource_meta':r})
            elif rt=='本地视频字幕':
                video=r.get('video_path') or r.get('path',''); sub=r.get('subtitle_path',''); lines=_v50_read_lines(sub) if sub else []
                if lines:
                    for line in lines:
                        mats.append({'text':line,'zh':'','title':r.get('name',''),'local_path':video,'media_path':video,'subtitle_path':sub,'source_type':'local_video_subtitle','resource_meta':r})
                        if len(mats)>=V50_MAX_SYNC_ITEMS: break
                else:
                    mats.append({'text':_Path_v50(video).stem.replace('_',' '),'zh':'','title':r.get('name',''),'local_path':video,'media_path':video,'source_type':'local_video_no_subtitle','resource_meta':r})
            elif rt=='本地文本资源':
                p=r.get('subtitle_path') or r.get('path')
                for line in _v50_read_lines(p):
                    mats.append({'text':line,'zh':'','title':r.get('name',''),'local_path':p,'source_type':'local_text','resource_meta':r})
                    if len(mats)>=V50_MAX_SYNC_ITEMS: break
        try: self.after(0, lambda: (_v50_apply_dictation(self,mats,'V50资源库'), _v50_status(self,'dictation',f'同步完成：{len(mats)} 条。')))
        except Exception: pass
    _threading_v50.Thread(target=worker, daemon=True).start()

# 精选池安全导入：只搬数据，不翻译、不渲染、不缓存预览。
def _v50_obj_text(obj):
    if isinstance(obj,str): return obj.strip()
    if isinstance(obj,dict):
        for k in ('text','en','line','sentence','phrase','subtitle','title'):
            v=obj.get(k)
            if isinstance(v,str) and v.strip(): return v.strip()
        for k in ('clip','item'):
            if obj.get(k) is not None:
                t=_v50_obj_text(obj.get(k))
                if t: return t
    for k in ('text','en','line','sentence','phrase','subtitle','title'):
        try:
            v=getattr(obj,k,None)
            if isinstance(v,str) and v.strip(): return v.strip()
        except Exception: pass
    return ''

def _v50_obj_zh(obj):
    if isinstance(obj,dict):
        for k in ('zh','cn','translation','chinese'):
            v=obj.get(k)
            if isinstance(v,str) and v.strip(): return v.strip()
        for k in ('clip','item'):
            if obj.get(k) is not None:
                z=_v50_obj_zh(obj.get(k))
                if z: return z
    for k in ('zh','cn','translation','chinese'):
        try:
            v=getattr(obj,k,None)
            if isinstance(v,str) and v.strip(): return v.strip()
        except Exception: pass
    return ''

def _v50_obj_meta(obj):
    data={'local_path':'','video_url':'','title':'','year':'','keyword':''}
    def pull(o):
        if o is None: return
        if isinstance(o,dict):
            for k in ('local_path','media_path','video_path','cached_path','path','file'):
                if o.get(k) and not data['local_path']: data['local_path']=str(o.get(k))
            for k in ('url','video_url','remote_url'):
                if o.get(k) and not data['video_url']: data['video_url']=str(o.get(k))
            for k in ('title','year','keyword'):
                if o.get(k) and not data[k]: data[k]=str(o.get(k))
            for k in ('clip','item','resource_meta'): pull(o.get(k))
        else:
            for k in ('local_path','media_path','video_path','cached_path','path','file'):
                try:
                    v=getattr(o,k,None)
                    if v and not data['local_path']: data['local_path']=str(v)
                except Exception: pass
            for k in ('url','video_url','remote_url'):
                try:
                    v=getattr(o,k,None)
                    if v and not data['video_url']: data['video_url']=str(v)
                except Exception: pass
            for k in ('title','year','keyword'):
                try:
                    v=getattr(o,k,None)
                    if v and not data[k]: data[k]=str(v)
                except Exception: pass
    pull(obj); return data

def _v50_import_pool_async(self):
    def worker():
        candidates=[]
        for name in ('selection_pool','selected_pool','selected_clips','curated_pool','pool_items','selection_pool_items','render_selection_pool','favorite_items','playlist_items'):
            try:
                val=getattr(self,name,None)
                if isinstance(val,(list,tuple)) and val: candidates.append((name,list(val)))
            except Exception: pass
        if not candidates:
            for name in dir(self):
                if name.startswith('_'): continue
                if any(x in name.lower() for x in ('pool','selected','clip')):
                    try:
                        val=getattr(self,name)
                        if isinstance(val,(list,tuple)) and val and len(val)<20000: candidates.append((name,list(val)))
                    except Exception: pass
        best=('',[])
        for name, arr in candidates:
            score=sum(1 for x in arr[:50] if _v50_obj_text(x))
            if score and len(arr)>len(best[1]): best=(name,arr)
        name, arr=best; mats=[]
        for obj in arr[:V50_MAX_SYNC_ITEMS]:
            text=_v50_obj_text(obj)
            if not text: continue
            meta=_v50_obj_meta(obj)
            mats.append({'text':text,'zh':_v50_obj_zh(obj),'title':meta.get('title',''),'year':meta.get('year',''),'keyword':meta.get('keyword',''),'local_path':meta.get('local_path',''),'media_path':meta.get('local_path',''),'video_url':meta.get('video_url',''),'source_type':'online_playphrase_pool','resource_meta':{'pool_attr':name},'clip':obj if isinstance(obj,dict) else None})
        def finish():
            if not mats:
                _messagebox_v50.showwarning('精选池为空','没有找到可导入的精选池数据。'); return
            _v50_apply_dictation(self,mats,f'精选池:{name}')
        try: self.after(0, finish)
        except Exception: pass
    _v50_log(self,'V50安全导入精选池：后台收集，不触发翻译/渲染/预缓存。','info')
    _threading_v50.Thread(target=worker, daemon=True).start()

