# ──────────────────────────────────────────────────────────────────────
# V51: 精选池彻底安全导入 + PlayPhrase下载转本地 + 听写/背诵标签改名 + 在线资源不入平台目录
# 修复点：
# 1) 旧“导入精选池/从精选池导入/加载PlayPhrase精选池”按钮创建时已经绑定旧函数，V50只改方法不够。
#    V51启动后会递归重绑所有相关按钮，彻底绕开旧重刷新/翻译/缓存链。
# 2) 安全导入只读取 self.pool，绝不 dir(self) 扫描全对象，避免点击即卡死。
# 3) 在线PlayPhrase资源不再进资源平台建目录/登记路径；只在听写训练中临时加载文本。
# 4) 可选“导入时下载到本地”：下载后转入 本地视频字幕/play phrase网站学习资源。
# 5) 标签改名：听写模式 -> 听写训练；背诵模式 -> 背诵听忆。
# ──────────────────────────────────────────────────────────────────────
import os as _os_v51
import re as _re_v51
import json as _json_v51
import time as _time_v51
import shutil as _shutil_v51
import threading as _threading_v51
from pathlib import Path as _Path_v51

V51_POOL_MAX = 8000
V51_PP_LOCAL_FOLDER = 'play phrase网站学习资源'

# 在线资源不再作为资源平台目录；只有本地视频字幕和本地文本资源。
try:
    V50_DICTATION_TOPS.clear()
    V50_DICTATION_TOPS.update({
        '本地视频字幕': [V51_PP_LOCAL_FOLDER, '影视剧', '课程视频', '短视频', '演讲采访', '自定义视频'],
        '本地文本资源': ['口语句子', '考试听写', '教材课文', '自定义文本'],
    })
except Exception:
    pass

def _v51_log(self, msg, level='info'):
    try: self.log(msg, level)
    except Exception: print(msg)

def _v51_safe(s, n=80):
    s = _re_v51.sub(r'[\\/:*?"<>|]+', '_', str(s or '').strip())
    s = _re_v51.sub(r'\s+', ' ', s).strip()
    return (s[:n] or 'untitled')

def _v51_pool_list(self):
    """只读明确的精选池 self.pool；不扫描 dir(self)，避免冻结。"""
    try:
        pool = getattr(self, 'pool', None)
        if isinstance(pool, (list, tuple)):
            return list(pool)
    except Exception:
        pass
    # 少量兼容已知别名，不做全对象扫描。
    for name in ('selection_pool', 'selected_pool', 'selected_clips', 'pool_items'):
        try:
            val = getattr(self, name, None)
            if isinstance(val, (list, tuple)) and val:
                return list(val)
        except Exception:
            pass
    return []

def _v51_clip_text(c):
    if isinstance(c, str): return c.strip()
    if isinstance(c, dict):
        for k in ('text','en','line','sentence','phrase','subtitle','title'):
            v = c.get(k)
            if isinstance(v, str) and v.strip(): return v.strip()
        for k in ('clip','item'):
            if c.get(k) is not None:
                t = _v51_clip_text(c.get(k))
                if t: return t
    for k in ('text','en','line','sentence','phrase','subtitle','title'):
        try:
            v = getattr(c, k, None)
            if isinstance(v, str) and v.strip(): return v.strip()
        except Exception: pass
    return ''

def _v51_clip_zh(c):
    if isinstance(c, dict):
        for k in ('zh','cn','translation','chinese'):
            v = c.get(k)
            if isinstance(v, str) and v.strip(): return v.strip()
        for k in ('clip','item'):
            if c.get(k) is not None:
                z = _v51_clip_zh(c.get(k))
                if z: return z
    for k in ('zh','cn','translation','chinese'):
        try:
            v = getattr(c, k, None)
            if isinstance(v, str) and v.strip(): return v.strip()
        except Exception: pass
    return ''

def _v51_clip_meta(c):
    data = {'local_path':'','video_url':'','title':'','year':'','keyword':'','clip_id':''}
    def pull(o):
        if o is None: return
        if isinstance(o, dict):
            for k in ('local_path','media_path','video_path','cached_path','path','file'):
                v = o.get(k)
                if v and not data['local_path']: data['local_path'] = str(v)
            for k in ('url','video_url','remote_url'):
                v = o.get(k)
                if v and not data['video_url']: data['video_url'] = str(v)
            for k in ('title','year','keyword','clip_id','id'):
                v = o.get(k)
                kk = 'clip_id' if k == 'id' else k
                if v and not data.get(kk): data[kk] = str(v)
            for k in ('clip','item','resource_meta'):
                pull(o.get(k))
        else:
            for k in ('local_path','media_path','video_path','cached_path','path','file'):
                try:
                    v = getattr(o, k, None)
                    if v and not data['local_path']: data['local_path'] = str(v)
                except Exception: pass
            for k in ('url','video_url','remote_url'):
                try:
                    v = getattr(o, k, None)
                    if v and not data['video_url']: data['video_url'] = str(v)
                except Exception: pass
            for k in ('title','year','keyword','clip_id'):
                try:
                    v = getattr(o, k, None)
                    if v and not data.get(k): data[k] = str(v)
                except Exception: pass
    pull(c)
    return data

def _v51_apply_dictation_fast(self, mats, label=''):
    """轻量应用到听写训练：不触发翻译/渲染/缓存预览。"""
    self.dictation_materials_v30 = mats or []
    self.dictation_index_v30 = 0
    try:
        self.dict_items_v33 = self.dictation_materials_v30
        self.dict_index_v33 = 0
    except Exception:
        pass
    try:
        if '_v46_refresh_material_tree' in globals():
            globals()['_v46_refresh_material_tree'](self)
        elif hasattr(self, 'dictation_material_list_v30'):
            lb = self.dictation_material_list_v30
            lb.delete(0, 'end')
            for i, m in enumerate(self.dictation_materials_v30[:3000], 1):
                lb.insert('end', f'· {i:03d}. {str(m.get("text", ""))[:80]}')
    except Exception:
        pass
    try:
        if hasattr(self, '_dictation_refresh_current_v30'):
            self._dictation_refresh_current_v30()
    except Exception:
        # 某些版本旧刷新会操作已销毁控件，忽略，不影响材料已加载。
        pass
    try:
        if hasattr(self, 'nb') and hasattr(self, 'tab_dictation'):
            self.nb.select(self.tab_dictation)
    except Exception:
        pass
    _v51_log(self, f'听写训练已安全加载精选池文本 {len(self.dictation_materials_v30)} 条 {label}', 'ok')

def _v51_import_pool_safe(self, download=False):
    """点击按钮立即返回；后台只构建材料列表。"""
    try:
        pool = _v51_pool_list(self)
    except Exception:
        pool = []
    if not pool:
        try: messagebox.showwarning('精选池为空', '请先在精选工作台加入精选池。')
        except Exception: pass
        return
    _v51_log(self, f'V51开始安全导入精选池：{len(pool)} 条；download={download}', 'info')
    def worker():
        mats = []
        for c in pool[:V51_POOL_MAX]:
            text = _v51_clip_text(c)
            if not text: continue
            meta = _v51_clip_meta(c)
            mats.append({
                'text': text,
                'zh': _v51_clip_zh(c),
                'title': meta.get('title',''),
                'year': meta.get('year',''),
                'keyword': meta.get('keyword',''),
                'local_path': meta.get('local_path',''),
                'media_path': meta.get('local_path',''),
                'video_url': meta.get('video_url',''),
                'source_type': 'playphrase_online_pool',
                'resource_meta': {'origin': 'playphrase_pool', 'clip_id': meta.get('clip_id','')},
                # 保留原对象引用，不做序列化，不写资源平台。
                'clip': c if isinstance(c, dict) else None,
            })
        def finish():
            if not mats:
                try: messagebox.showwarning('精选池无有效文本', '精选池存在，但没有读取到可听写的英文文本。')
                except Exception: pass
                return
            _v51_apply_dictation_fast(self, mats, 'PlayPhrase在线精选池')
            if download:
                _v51_download_pool_to_local_async(self, pool)
        try: self.after(0, finish)
        except Exception: pass
    _threading_v51.Thread(target=worker, daemon=True).start()

def _v51_pp_local_dir(self):
    try:
        root = _v50_dict_root(self)
    except Exception:
        root = _Path_v51.cwd() / 'playphrase_resource_hub_v50' / 'dictation'
    d = root / '本地视频字幕' / V51_PP_LOCAL_FOLDER
    d.mkdir(parents=True, exist_ok=True)
    return d

def _v51_download_pool_to_local_async(self, pool=None):
    pool = list(pool if pool is not None else _v51_pool_list(self))
    if not pool:
        try: messagebox.showwarning('精选池为空', '没有可下载的精选池。')
        except Exception: pass
        return
    target_dir = _v51_pp_local_dir(self)
    _v51_log(self, f'开始后台下载精选池视频到：{target_dir}', 'info')
    def worker():
        ok = 0
        records = []
        # 尝试使用现有 PlayPhrase service/session/cache，不新建重链路。
        session = None
        try:
            srv = self._active_search_service()
            session = getattr(srv, 'session', None)
        except Exception:
            try: session = getattr(getattr(self, 'search_service', None), 'session', None)
            except Exception: session = None
        for i, c in enumerate(pool[:V51_POOL_MAX], 1):
            text = _v51_clip_text(c)
            meta = _v51_clip_meta(c)
            src_path = meta.get('local_path','')
            copied = ''
            try:
                if src_path and _Path_v51(src_path).exists():
                    src = _Path_v51(src_path)
                    dest = target_dir / (f'{i:04d}_{_v51_safe(text, 40)}{src.suffix or ".mp4"}')
                    if not dest.exists(): _shutil_v51.copy2(src, dest)
                    copied = str(dest); ok += 1
                elif getattr(self, 'cache', None) is not None and session is not None:
                    # c 是 Clip dataclass 时可直接 ensure_cached。
                    local = self.cache.ensure_cached(c, session, getattr(self, 'ffmpeg', None))
                    if local and _Path_v51(local).exists():
                        src = _Path_v51(local)
                        dest = target_dir / (f'{i:04d}_{_v51_safe(text, 40)}{src.suffix or ".mp4"}')
                        if not dest.exists(): _shutil_v51.copy2(src, dest)
                        copied = str(dest); ok += 1
            except Exception as e:
                _v51_log(self, f'精选池第{i}条下载/复制失败：{type(e).__name__}: {e}', 'warn')
            # 生成同名字幕文本，至少保证本地学习目录里有字幕信息。
            if copied:
                try:
                    sub = _Path_v51(copied).with_suffix('.txt')
                    zh = _v51_clip_zh(c)
                    sub.write_text(text + ('\n' + zh if zh else '') + '\n', 'utf-8')
                    records.append(_v51_make_local_pp_record(self, copied, str(sub), text))
                except Exception:
                    pass
        # 更新听写本地资源索引，不登记在线路径，只登记已下载本地文件。
        try:
            idx = _v50_load_index(self, 'dictation')
            old = [r for r in idx.get('records', []) if not (r.get('top') == '本地视频字幕' and r.get('folder') == V51_PP_LOCAL_FOLDER)]
            idx['records'] = old + records
            idx.setdefault('mounted', {}).setdefault(f'本地视频字幕/{V51_PP_LOCAL_FOLDER}', [])
            _v50_save_index(self, 'dictation', idx)
        except Exception:
            pass
        try:
            self.after(0, lambda: _v51_log(self, f'精选池下载完成：{ok}/{len(pool)} 个视频已转入本地目录：{target_dir}', 'ok' if ok else 'warn'))
        except Exception:
            pass
    _threading_v51.Thread(target=worker, daemon=True).start()

def _v51_make_local_pp_record(self, video_path, subtitle_path, text=''):
    p = _Path_v51(video_path)
    try: line_count = len(_v50_read_text_lines(subtitle_path))
    except Exception: line_count = 1
    return {
        'id': f'dictation|本地视频字幕|{V51_PP_LOCAL_FOLDER}|{p.resolve() if p.exists() else p}',
        'mode': 'dictation',
        'top': '本地视频字幕',
        'folder': V51_PP_LOCAL_FOLDER,
        'origin': 'PlayPhrase下载',
        'resource_type': '本地视频字幕',
        'kind': 'video',
        'name': p.name,
        'path': str(p),
        'video_path': str(p),
        'subtitle_path': subtitle_path,
        'audio_path': '',
        'line_count': line_count,
        'status': 'PlayPhrase本地视频+字幕',
    }

def _v51_rebind_pool_buttons(self):
    """递归重绑已有按钮，解决按钮在旧 init 阶段已绑定旧卡死函数的问题。"""
    download_var = getattr(self, 'dict_pool_download_local_var_v51', None)
    def should_patch(text):
        t = str(text or '')
        return ('精选池' in t and any(x in t for x in ('导入','加载'))) or t.strip() in ('从精选池导入','导入精选池')
    def walk(w):
        try:
            text = w.cget('text')
            if should_patch(text):
                w.configure(command=lambda: _v51_import_pool_safe(self, bool(getattr(self, 'dict_pool_download_local_var_v51', tk.BooleanVar(value=False)).get())))
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass
    _v51_log(self, 'V51已重绑所有“导入/加载精选池”按钮到安全导入函数。', 'ok')

def _v51_install_dictation_topbar(self):
    tab = getattr(self, 'tab_dictation', None)
    if tab is None or getattr(self, '_v51_dictation_topbar', False):
        return
    bar = tk.Frame(tab, bg='#0b1220')
    try:
        bar.pack(fill='x', padx=8, pady=4, before=tab.winfo_children()[0] if tab.winfo_children() else None)
    except Exception:
        bar.pack(fill='x', padx=8, pady=4)
    self.dict_pool_download_local_var_v51 = tk.BooleanVar(value=False)
    tk.Label(bar, text='听写训练资源：', bg='#0b1220', fg='#e5e7eb', font=('Microsoft YaHei UI', 10, 'bold')).pack(side='left', padx=(4,6))
    ttk.Button(bar, text='加载精选池文本', command=lambda: _v51_import_pool_safe(self, False)).pack(side='left', padx=3)
    ttk.Checkbutton(bar, text='导入时下载到本地', variable=self.dict_pool_download_local_var_v51).pack(side='left', padx=6)
