# V52: 真正防卡死精选池导入 + 本地视频递归扫描保留 + 美化视频真实预览修复
# 关键修复：
# 1) 彻底绕开旧听写刷新链：导入精选池只设置材料 + 分批刷新轻量列表，不调用旧重刷新/翻译/渲染/预缓存。
# 2) 所有“加载/导入/从精选池导入”按钮强制重绑；包括 V50/V51 两排按钮。
# 3) 在线 PlayPhrase 仍不进资源平台；勾选下载才进入 本地视频字幕/play phrase网站学习资源。
# 4) 资源平台保留完全体；听写/背诵资源独立；本地递归扫描视频+字幕保留。
# 5) 美化视频操作台预览恢复：优先真实预览帧；没有预览帧则后台生成，不再只显示黑底文本。
# ──────────────────────────────────────────────────────────────────────
import os as _os_v52
import re as _re_v52
import time as _time_v52
import threading as _threading_v52
from pathlib import Path as _Path_v52

V52_POOL_MAX = 3000
V52_UI_BATCH = 200
V52_PP_LOCAL_FOLDER = "play phrase网站学习资源"

def _v52_log(self, msg, level="info"):
    try:
        self.log(msg, level)
    except Exception:
        print(msg)

def _v52_clip_text(c):
    # Fast, non-recursive deep object traversal.
    if c is None:
        return ""
    if isinstance(c, str):
        return c.strip()
    if isinstance(c, dict):
        for k in ("text", "en", "line", "sentence", "phrase", "subtitle", "title"):
            v = c.get(k)
            if isinstance(v, str) and v.strip():
                return v.strip()
        inner = c.get("clip") or c.get("item")
        if inner is not None and inner is not c:
            return _v52_clip_text(inner)
        return ""
    for k in ("text", "en", "line", "sentence", "phrase", "subtitle", "title"):
        try:
            v = getattr(c, k, None)
            if isinstance(v, str) and v.strip():
                return v.strip()
        except Exception:
            pass
    return ""

def _v52_clip_zh(c):
    if c is None:
        return ""
    if isinstance(c, dict):
        for k in ("zh", "cn", "translation", "chinese"):
            v = c.get(k)
            if isinstance(v, str) and v.strip():
                return v.strip()
        inner = c.get("clip") or c.get("item")
        if inner is not None and inner is not c:
            return _v52_clip_zh(inner)
        return ""
    for k in ("zh", "cn", "translation", "chinese"):
        try:
            v = getattr(c, k, None)
            if isinstance(v, str) and v.strip():
                return v.strip()
        except Exception:
            pass
    return ""

def _v52_clip_meta(c):
    data = {"local_path": "", "video_url": "", "title": "", "year": "", "keyword": "", "clip_id": "", "preview_path": ""}
    def pull_obj(o, depth=0):
        if o is None or depth > 2:
            return
        if isinstance(o, dict):
            for k in ("local_path", "media_path", "video_path", "cached_path", "path", "file"):
                v = o.get(k)
                if v and not data["local_path"]:
                    data["local_path"] = str(v)
            for k in ("url", "video_url", "remote_url"):
                v = o.get(k)
                if v and not data["video_url"]:
                    data["video_url"] = str(v)
            for k in ("title", "year", "keyword", "clip_id", "id", "preview_path"):
                v = o.get(k)
                kk = "clip_id" if k == "id" else k
                if v and not data.get(kk):
                    data[kk] = str(v)
            inner = o.get("clip") or o.get("item")
            if inner is not None and inner is not o:
                pull_obj(inner, depth+1)
        else:
            for k in ("local_path", "media_path", "video_path", "cached_path", "path", "file"):
                try:
                    v = getattr(o, k, None)
                    if v and not data["local_path"]:
                        data["local_path"] = str(v)
                except Exception:
                    pass
            for k in ("url", "video_url", "remote_url"):
                try:
                    v = getattr(o, k, None)
                    if v and not data["video_url"]:
                        data["video_url"] = str(v)
                except Exception:
                    pass
            for k in ("title", "year", "keyword", "clip_id", "preview_path"):
                try:
                    v = getattr(o, k, None)
                    if v and not data.get(k):
                        data[k] = str(v)
                except Exception:
                    pass
    pull_obj(c)
    return data

def _v52_pool_list(self):
    # 只读明确池，不 dir(self)，避免大对象扫描。
    for name in ("pool", "selection_pool", "selected_pool", "selected_clips", "pool_items"):
        try:
            val = getattr(self, name, None)
            if isinstance(val, (list, tuple)):
                return list(val)
        except Exception:
            pass
    return []

def _v52_set_status(self, msg):
    for attr in ("dict_v46_status_var", "learn_status_var_v49", "recite_status_var_v48"):
        try:
            v = getattr(self, attr, None)
            if v is not None:
                v.set(msg)
                return
        except Exception:
            pass
    _v52_log(self, msg, "info")

def _v52_destroy_old_dictation_extra_topbars(self):
    # 保留最新 V52 顶栏，隐藏以前 V50/V51 重复按钮，避免用户点到旧 command。
    tab = getattr(self, "tab_dictation", None)
    if tab is None:
        return
    try:
        for ch in list(tab.winfo_children()):
            if ch is getattr(self, "dict_v52_topbar", None):
                continue
            texts = []
            try:
                for w in ch.winfo_children():
                    try:
                        texts.append(str(w.cget("text")))
                    except Exception:
                        pass
            except Exception:
                pass
            joined = " ".join(texts)
            if ("V50听写资源" in joined) or ("听写训练资源" in joined) or ("加载PlayPhrase精选池" in joined) or ("加载精选池文本" in joined):
                try:
                    ch.pack_forget()
                except Exception:
                    pass
                try:
                    ch.grid_remove()
                except Exception:
                    pass
    except Exception:
        pass

