    tk.Label(bar, text="听写训练资源：", bg="#0b1220", fg="#e5e7eb", font=("Microsoft YaHei UI", 10, "bold")).pack(side="left", padx=(4, 6))
    ttk.Button(bar, text="① 安全加载精选池文本", command=lambda: _v52_import_pool_safe(self, download=False)).pack(side="left", padx=3)
    ttk.Checkbutton(bar, text="同时下载到本地", variable=self.dict_pool_download_local_var_v52).pack(side="left", padx=6)
