    tk.Label(row, textvariable=self.sfx_volume_v54, bg='#151322', fg='#e5e7eb', font=('Consolas',12)).pack(side='left', padx=(0,10))
    ttk.Scale(row, from_=0.0, to=1.0, variable=self.sfx_volume_v54, command=lambda e:_v54_save_settings(self)).pack(side='left', fill='x', expand=True)
    ttk.Button(row, text='测试音效', command=lambda:_v54_play_sound(self,'sentence')).pack(side='left', padx=10)
    _v54_grid(inner,self,'⌨ 按键音','输入字母、数字、符号时播放；已节流，快速打字不会卡顿。',V54_CLICK,self.sfx_click_v54,'click')
    _v54_grid(inner,self,'❌ 错误音','输入错误、过早按空格、判断失败时播放。',V54_ERROR,self.sfx_error_v54,'error')
    _v54_grid(inner,self,'✅ 单词正确音','单词/语块判断正确时播放。',V54_OK,self.sfx_correct_v54,'correct')
    _v54_grid(inner,self,'🏁 整句完成音','整句或整段全部正确时播放。',V54_SENT,self.sfx_sentence_v54,'sentence')
    _v54_grid(inner,self,'⏰ 时间警告音','计时训练接近结束时播放。',V54_WARN,self.sfx_warning_v54,'warning')
    bottom = tk.Frame(inner, bg='#151322'); bottom.pack(fill='x', padx=18, pady=18)
