def _v56_patch_segment_popup(self):
    globals()["_open_segment_dictation_panel_v37"] = lambda app: _v56_inline_split_mode(app)
    globals()["_v38_draw_segment_input"] = lambda app: _v56_inline_split_mode(app)
    _v56_remove_old_segment_buttons(self)

# ---------------- 本地视频+字幕 / 文本素材扫描 ----------------
def _v56_time_to_seconds(t):
    t = str(t).strip().replace(",", ".")
    m = _re_v56.match(r"(?:(\d+):)?(\d{1,2}):(\d{1,2}(?:\.\d+)?)", t)
    if not m:
        return 0.0
    h = float(m.group(1) or 0)
    mi = float(m.group(2) or 0)
    s = float(m.group(3) or 0)
    return h * 3600 + mi * 60 + s

def _v56_parse_subtitle(path):
    p = _Path_v56(path)
    try:
        raw = p.read_text("utf-8-sig", errors="ignore")
    except Exception:
        return []
    # SRT/VTT timing blocks
    blocks = _re_v56.split(r"\n\s*\n", raw.replace("\r\n", "\n").replace("\r", "\n"))
    out = []
    for b in blocks:
        lines = [x.strip() for x in b.splitlines() if x.strip()]
        if not lines:
            continue
        time_line = ""
        for l in lines:
            if "-->" in l:
                time_line = l
                break
        start = end = 0.0
        texts = []
        if time_line:
            parts = [x.strip() for x in time_line.split("-->", 1)]
            start = _v56_time_to_seconds(parts[0])
            end = _v56_time_to_seconds(_re_v56.split(r"\s+", parts[1])[0])
            for l in lines:
                if l == time_line or _re_v56.fullmatch(r"\d+", l):
                    continue
                texts.append(_re_v56.sub(r"<[^>]+>", "", l).strip())
        else:
            texts = [_re_v56.sub(r"<[^>]+>", "", l).strip() for l in lines if not _re_v56.fullmatch(r"\d+", l)]
        if not texts:
            continue
        en_lines = [x for x in texts if len(_re_v56.findall(r"[A-Za-z]", x)) >= max(2, len(_re_v56.findall(r"[\u4e00-\u9fff]", x))*2)]
        zh_lines = [x for x in texts if x not in en_lines]
        if en_lines:
            out.append({"text": " ".join(en_lines).strip(), "zh": " ".join(zh_lines).strip(), "start": start, "end": end})
    # Plain text fallback
    if not out:
        for l in raw.splitlines():
            s = l.strip()
            if not s or _re_v56.fullmatch(r"\d+", s) or "-->" in s:
                continue
            if len(_re_v56.findall(r"[A-Za-z]", s)) >= 2:
                out.append({"text": s, "zh": "", "start": 0.0, "end": 0.0})
    return out

def _v56_find_sub_for_video(video):
    p = _Path_v56(video)
    cands = []
    for ext in (".srt",".ass",".ssa",".vtt",".txt"):
        cands.append(p.with_suffix(ext))
        cands.extend(p.parent.glob(p.stem + "*" + ext))
    seen = set()
    out = []
    for c in cands:
        try:
            if c.exists() and c.suffix.lower() in V56_SUB_EXTS and str(c) not in seen:
                out.append(c); seen.add(str(c))
        except Exception:
            pass
    out.sort(key=lambda x: (0 if _re_v56.search(r"双语|bilingual|en|eng|english|zh|chs|cht", x.name, _re_v56.I) else 1, len(x.name)))
    return out[0] if out else None

def _v56_material_from_sub_line(video, sub, item, title=""):
    return {
        "text": item.get("text",""),
        "zh": item.get("zh",""),
        "title": title or (_Path_v56(video).stem if video else _Path_v56(sub).stem),
        "local_path": str(video) if video else str(sub),
        "media_path": str(video) if video else "",
        "video_path": str(video) if video else "",
        "subtitle_path": str(sub) if sub else "",
        "start": float(item.get("start") or 0),
        "end": float(item.get("end") or 0),
        "source_type": "local_video_subtitle" if video else "local_text",
        "kind": "video" if video else "text",
    }

def _v56_scan_video_folder(folder):
    root = _Path_v56(folder)
    records = []
    materials = []
    if not root.exists():
        return records, materials
    videos = [p for p in root.rglob("*") if p.is_file() and p.suffix.lower() in V56_VIDEO_EXTS]
    for v in videos:
        sub = _v56_find_sub_for_video(v)
        status = "缺字幕"
        line_count = 0
        if sub:
            lines = _v56_parse_subtitle(sub)
            line_count = len(lines)
            status = "视频+字幕" if lines else "字幕无有效英文"
            for item in lines:
                if item.get("text"):
                    materials.append(_v56_material_from_sub_line(v, sub, item, v.stem))
        records.append({"type":"本地视频字幕", "name":v.name, "status":status, "lines":line_count, "path":str(v), "subtitle":str(sub or "")})
    return records, materials

def _v56_scan_text_folder(path):
    root = _Path_v56(path)
    files = []
    if root.is_file():
        files = [root]
    elif root.exists():
        files = [p for p in root.rglob("*") if p.is_file() and p.suffix.lower() in V56_TEXT_EXTS]
    records = []
    materials = []
    for f in files:
        lines = _v56_parse_subtitle(f)
        if not lines:
            continue
        records.append({"type":"本地文本", "name":f.name, "status":"英文文本", "lines":len(lines), "path":str(f), "subtitle":str(f)})
        for item in lines:
            if item.get("text"):
                materials.append(_v56_material_from_sub_line("", f, item, f.stem))
    return records, materials

def _v56_apply_materials(self, materials, bucket_name="本地"):
    if not materials:
        try: messagebox.showwarning("无有效素材", "没有扫描到可用英文台词/句子。")
        except Exception: pass
        return
    old = getattr(self, "dictation_materials_v30", []) or []
    old.extend(materials)
    self.dictation_materials_v30 = old
    try: self.dict_items_v33 = old
    except Exception: pass
    self.dictation_index_v30 = max(0, len(old) - len(materials))
    if "_v46_refresh_material_tree" in globals():
        _v46_refresh_material_tree(self)
    if "_v46_refresh_current" in globals():
        _v46_refresh_current(self)
    try:
        self.nb.select(self.tab_dictation)
    except Exception:
        pass
    try: _v46_status(self, f"已加载 {len(materials)} 条{bucket_name}素材。", ok=True)
    except Exception: pass

def _v56_add_local_video_path(self):
    folder = filedialog.askdirectory(title="选择本地视频+字幕文件夹")
    if not folder:
        return
    self.v56_last_video_folder = folder
    _v46_status(self, f"后台递归扫描视频+字幕：{folder}")
    def worker():
        records, materials = _v56_scan_video_folder(folder)
        self.v56_local_video_records = records
        def done():
            _v56_apply_materials(self, materials, "本地视频字幕")
            _v46_status(self, f"扫描完成：视频文件 {len(records)} 个，导入台词 {len(materials)} 条。", ok=True)
        try: self.after(0, done)
        except Exception: pass
    _threading_v56.Thread(target=worker, daemon=True).start()

def _v56_add_text_path(self):
    path = filedialog.askopenfilename(title="选择文本/SRT/VTT文件", filetypes=[("Text/Subtitles","*.txt *.srt *.vtt *.csv *.lrc"), ("All","*.*")])
    if not path:
        folder = filedialog.askdirectory(title="或选择文本资源文件夹")
        path = folder
    if not path:
        return
    self.v56_last_text_path = path
    _v46_status(self, f"后台递归扫描文本素材：{path}")
    def worker():
        records, materials = _v56_scan_text_folder(path)
        self.v56_text_records = records
        def done():
            _v56_apply_materials(self, materials, "文本")
            _v46_status(self, f"文本扫描完成：文件 {len(records)} 个，导入句子 {len(materials)} 条。", ok=True)
        try: self.after(0, done)
        except Exception: pass
    _threading_v56.Thread(target=worker, daemon=True).start()

def _v56_open_resource_browser(self):
    win = tk.Toplevel(self)
    win.title("听写训练本地资源浏览器｜视频字幕 / 文本")
    win.geometry("1180x740")
    root = ttk.Frame(win, padding=10); root.pack(fill="both", expand=True)
    top = ttk.Frame(root); top.pack(fill="x")
    ttk.Button(top, text="添加并扫描视频字幕目录", command=lambda:_v56_add_local_video_path(self)).pack(side="left", padx=4)
    ttk.Button(top, text="添加并扫描文本素材", command=lambda:_v56_add_text_path(self)).pack(side="left", padx=4)
    ttk.Button(top, text="刷新显示", command=lambda: refresh()).pack(side="left", padx=4)
    ttk.Label(top, text="选择资源后可加载到听写素材池；素材树会按路径像 Windows 文件系统一样展开。").pack(side="left", padx=12)
    cols = ("type","name","status","lines","path","subtitle")
    table = ttk.Treeview(root, columns=cols, show="headings", height=26)
    vs = ttk.Scrollbar(root, orient="vertical", command=table.yview)
    hs = ttk.Scrollbar(root, orient="horizontal", command=table.xview)
    table.configure(yscrollcommand=vs.set, xscrollcommand=hs.set)
    heads = {"type":"类型","name":"文件名","status":"状态","lines":"行数","path":"视频/文本路径","subtitle":"字幕路径"}
    widths = {"type":120,"name":240,"status":120,"lines":60,"path":520,"subtitle":520}
    for c in cols:
        table.heading(c, text=heads[c]); table.column(c, width=widths[c], anchor="w")
    table.pack(fill="both", expand=True, pady=8)
    vs.pack(side="right", fill="y")
    hs.pack(fill="x")
    def all_records():
        return (getattr(self, "v56_local_video_records", []) or []) + (getattr(self, "v56_text_records", []) or [])
    def refresh():
        table.delete(*table.get_children())
        for i, r in enumerate(all_records()):
            table.insert("", "end", iid=str(i), values=(r.get("type",""), r.get("name",""), r.get("status",""), r.get("lines",""), r.get("path",""), r.get("subtitle","")))
    def load_selected():
        rows = all_records()
        mats = []
        for iid in table.selection():
            try:
                r = rows[int(iid)]
            except Exception:
                continue
            if r.get("type") == "本地视频字幕" and r.get("subtitle"):
                for item in _v56_parse_subtitle(r["subtitle"]):
                    mats.append(_v56_material_from_sub_line(r["path"], r["subtitle"], item, _Path_v56(r["path"]).stem))
            elif r.get("type") == "本地文本":
                for item in _v56_parse_subtitle(r["path"]):
                    mats.append(_v56_material_from_sub_line("", r["path"], item, _Path_v56(r["path"]).stem))
        _v56_apply_materials(self, mats, "选中资源")
    btns = ttk.Frame(root); btns.pack(fill="x")
    ttk.Button(btns, text="加载选中资源到听写素材池", style="Accent.TButton", command=load_selected).pack(side="left", padx=4)
    ttk.Button(btns, text="关闭", command=win.destroy).pack(side="right", padx=4)
    refresh()

def _v56_refresh_resources(self):
    # 重新扫描上次路径
    todo = []
    if getattr(self, "v56_last_video_folder", ""):
        todo.append(("video", self.v56_last_video_folder))
    if getattr(self, "v56_last_text_path", ""):
        todo.append(("text", self.v56_last_text_path))
    if not todo:
        try:
            _v46_refresh_material_tree(self)
            _v46_status(self, "已刷新当前素材树；没有记录上次扫描路径。", ok=True)
        except Exception:
            pass
        return
    def worker():
        mats = []
        for typ, path in todo:
            if typ == "video":
                rec, mm = _v56_scan_video_folder(path)
                self.v56_local_video_records = rec
                mats.extend(mm)
            else:
                rec, mm = _v56_scan_text_folder(path)
                self.v56_text_records = rec
                mats.extend(mm)
        def done():
            # 不清空旧在线素材；追加刷新导入路径会造成重复，这里先按 path+text 去重。
            old = getattr(self, "dictation_materials_v30", []) or []
            seen = {(str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text",""))) for m in old if isinstance(m, dict)}
            add = []
            for m in mats:
                key = (str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text","")))
                if key not in seen:
                    add.append(m); seen.add(key)
            old.extend(add)
            self.dictation_materials_v30 = old
            try: self.dict_items_v33 = old
            except Exception: pass
            _v46_refresh_material_tree(self)
            _v46_status(self, f"资源刷新完成：新增 {len(add)} 条。", ok=True)
        try: self.after(0, done)
        except Exception: pass
    _threading_v56.Thread(target=worker, daemon=True).start()

# ---------------- 播放：音频/视频按钮从播放设置移到训练区 ----------------
def _v56_find_ffmpeg(self):
    try:
        ff = getattr(getattr(self, "ffmpeg", None), "ffmpeg", "")
        if ff and _Path_v56(ff).exists(): return ff
    except Exception:
        pass
    for p in ("C:/ffmpeg/bin/ffmpeg.exe", "C:/ffmpeg/ffmpeg.exe"):
        if _Path_v56(p).exists(): return p
    return "ffmpeg"

def _v56_play_current_audio(self):
    m = _v46_current_material(self) if "_v46_current_material" in globals() else None
    if not m:
        _v46_status(self, "当前没有选中台词，不能播放音频。", bad=True); return
    video = str(m.get("video_path") or m.get("media_path") or m.get("local_path") or "") if isinstance(m, dict) else ""
    start = float(m.get("start") or 0) if isinstance(m, dict) else 0.0
    end = float(m.get("end") or 0) if isinstance(m, dict) else 0.0
    if video and _Path_v56(video).exists() and end > start:
        out = _Path_v56(_tempfile_v56.gettempdir()) / f"pp_v56_audio_{int(_time_v56.time()*1000)}.wav"
        ff = _v56_find_ffmpeg(self)
        cmd = [ff, "-y", "-hide_banner", "-loglevel", "error", "-ss", f"{start:.3f}", "-to", f"{end:.3f}", "-i", video, "-vn", "-ac", "1", "-ar", "22050", str(out)]
        def worker():
            try:
                flags = 0
                if _os_v56.name == "nt":
                    flags = getattr(_subprocess_v56, "CREATE_NO_WINDOW", 0)
                r = _subprocess_v56.run(cmd, stdout=_subprocess_v56.DEVNULL, stderr=_subprocess_v56.DEVNULL, creationflags=flags, timeout=30)
                if r.returncode == 0 and out.exists() and out.stat().st_size > 1000:
                    import winsound
                    winsound.PlaySound(str(out), winsound.SND_FILENAME | winsound.SND_ASYNC)
                    _v46_status(self, "正在播放当前台词音频片段。", ok=True)
                else:
                    self.after(0, lambda:_v46_status(self, "音频片段提取失败，改用发音引擎。", bad=True))
                    self.after(0, lambda:_v55_speak_text(self, _v46_item_text(m), mode="chunk") if "_v55_speak_text" in globals() else None)
            except Exception as e:
                try: self.after(0, lambda:_v46_status(self, f"音频播放失败：{type(e).__name__}: {e}", bad=True))
                except Exception: pass
        _threading_v56.Thread(target=worker, daemon=True).start()
        return
    # 文本素材或无时间轴：TTS
    if "_v55_speak_text" in globals():
        return _v55_speak_text(self, _v46_item_text(m), mode="chunk")
    return _v46_speak_text(self, _v46_item_text(m))

def _v56_play_current_video(self):
    m = _v46_current_material(self) if "_v46_current_material" in globals() else None
    if not m:
        _v46_status(self, "当前没有选中台词，不能播放视频。", bad=True); return
    video = str(m.get("video_path") or m.get("media_path") or m.get("local_path") or "") if isinstance(m, dict) else ""
    if not video or not _Path_v56(video).exists() or _Path_v56(video).suffix.lower() not in V56_VIDEO_EXTS:
        _v46_status(self, "当前素材不是本地视频资源；请先扫描并加载视频+字幕。", bad=True); return
    # 把 local_path 放好，尽量复用已有 Qt 播放器。
    try:
        m["local_path"] = video
        m["media_path"] = video
        if "_v44_play_video" in globals():
            return _v44_play_video(self)
        if "_v42_play_video" in globals():
            return _v42_play_video(self)
    except Exception as e:
        _v46_status(self, f"内置视频播放失败，使用系统播放器：{e}", bad=True)
    try:
        if _os_v56.name == "nt":
            _os_v56.startfile(video)
        else:
            _subprocess_v56.Popen(["xdg-open", video])
    except Exception:
        pass

def _v56_strip_video_audio_play_settings(self):
    # 旧“播放设置”里的视频/音频模式删除，仅保留速度/次数等非源选择项。
    def walk(w):
        try:
            txt = str(w.cget("text"))
            if txt.strip() in ("视频/音频模式", "视频音频模式", "音频/视频模式") or "视频/音频模式" in txt:
                parent = w.master
                try: parent.pack_forget()
                except Exception: pass
                try: parent.grid_remove()
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

# ---------------- 输入区：Text + 单词级颜色 ----------------
def _v56_norm_spaces(s, keep_trailing=False):
    s = str(s or "").replace("\n", " ").replace("\t", " ")
    trailing = bool(_re_v56.search(r"\s$", s))
    s = _re_v56.sub(r"\s+", " ", s).strip()
    if keep_trailing and trailing and s:
        s += " "
    return s

def _v56_widget_get(w):
    try:
        if isinstance(w, tk.Text):
            return w.get("1.0", "end-1c")
        return w.get()
    except Exception:
        return ""

def _v56_widget_set(w, text):
    try:
        if isinstance(w, tk.Text):
            w.delete("1.0", "end")
            w.insert("1.0", text)
        else:
            w.delete(0, "end"); w.insert(0, text)
    except Exception:
        pass

def _v56_word_spans(s):
    return [(m.group(0), m.start(), m.end()) for m in _re_v56.finditer(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))]

def _v56_tag_words(item, final=False):
    w = item["entry"]
    text = _v56_widget_get(w)
    target = item["target"]
    norm = _v56_norm_spaces(text, keep_trailing=text.endswith(" "))
    if norm != text:
        _v56_widget_set(w, norm)
        text = norm
    target_words = _v56_tokens(target) if "_v56_tokens" in globals() else _v55_tokens(target) if "_v55_tokens" in globals() else _re_v56.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", target)
    spans = _v56_word_spans(text)
    exact = " ".join([x[0] for x in spans]).lower() == " ".join(target_words).lower() and len(spans) == len(target_words)
    try:
        w.tag_configure("input", foreground=V56_INPUT)
        w.tag_configure("ok", foreground=V56_OK)
        w.tag_configure("bad", foreground=V56_BAD)
        w.tag_remove("input", "1.0", "end")
        w.tag_remove("ok", "1.0", "end")
        w.tag_remove("bad", "1.0", "end")
    except Exception:
        pass
    results = []
    completed_count = len(spans) if text.endswith(" ") else max(0, len(spans)-1)
    if exact:
        completed_count = len(spans)
    for i, (word, a, b) in enumerate(spans):
        tw = target_words[i] if i < len(target_words) else ""
        if exact or (i < len(target_words) and i < completed_count and word.lower() == tw.lower()):
            tag, color, typ = "ok", V56_OK, "正确"
        elif final:
            tag, color, typ = ("ok", V56_OK, "正确") if (i < len(target_words) and word.lower() == tw.lower()) else ("bad", V56_BAD, "错误")
        else:
            tag, color, typ = "input", V56_INPUT, "输入中"
        try:
            w.tag_add(tag, f"1.0+{a}c", f"1.0+{b}c")
        except Exception:
            try: w.configure(fg=color)
            except Exception: pass
        if i < len(target_words):
            results.append({"pos": i+1, "answer": word, "target": tw, "type": typ, "color": color, "partial": typ=="输入中"})
    # 缺失词在最终判定时显示红色
    if final and len(spans) < len(target_words):
        for j in range(len(spans), len(target_words)):
            results.append({"pos": j+1, "answer": "", "target": target_words[j], "type": "缺词", "color": V56_BAD})
    # 横线颜色：精确全绿；最终错误红；其他紫
    if exact:
        _v46_set_line(item, V56_OK)
    elif final:
        _v46_set_line(item, V56_BAD)
    else:
        _v46_set_line(item, V56_INPUT)
    # 下方反馈持久
    try:
        _v55_draw_feedback(item["feedback"], results, target_words)
    except Exception:
        try:
            _v46_draw_word_feedback(item["feedback"], results, target_words)
        except Exception:
            pass
    return exact, results

def _v56_live_entry(self, item):
    exact, results = _v56_tag_words(item, final=False)
    if exact:
        _v46_status(self, "当前语块全部正确。", ok=True)
    else:
        correct = [r["target"] for r in results if r.get("type") == "正确"]
        wrong = [r for r in results if r.get("type") in ("错误","缺词")]
        if wrong:
            _v46_status(self, "错误提示：" + "；".join([f"第{r['pos']}词：{r['type']}，输入[{r.get('answer') or '空'}]，应为[{r.get('target')}]" for r in wrong]), bad=True)
        elif correct:
            _v46_status(self, "已确认正确：" + " / ".join(correct), ok=True)
        else:
            _v46_status(self, "紫色=输入中；绿色=已确认正确；红色=Space/Enter最终判定错误。")
    return exact

def _v56_final_entry(self, item):
    exact, results = _v56_tag_words(item, final=True)
    if exact:
        try: _v46_beep(self, "ok")
        except Exception: pass
        _v46_status(self, "✅ 当前语块正确。", ok=True)
        return True
    try: _v46_beep(self, "bad")
    except Exception: pass
    wrong = [r for r in results if r.get("type") != "正确"]
    if len(wrong) == len(results):
        head = "全错："
    else:
        head = "错误部分："
    _v46_status(self, "❌ " + head + "；".join([f"第{r['pos']}词 {r['type']}：输入[{r.get('answer') or '空'}] / 应为[{r.get('target')}]" for r in wrong[:8]]), bad=True)
    return False

def _v56_space_entry(self, item):
    w = item["entry"]
    text = _v56_norm_spaces(_v56_widget_get(w), keep_trailing=False)
    target_words = _v55_tokens(item["target"]) if "_v55_tokens" in globals() else _v56_tokens(item["target"])
    words = _v55_tokens(text) if "_v55_tokens" in globals() else _v56_tokens(text)
    if not text:
        return "break"
    # 已输入到目标词数：Space 不再插入尾空格，直接最终判定
    if len(words) >= len(target_words):
        _v56_widget_set(w, text)
        ok = _v56_final_entry(self, item)
        if ok and _v46_play_mode(self) == "拆分播放":
            m = _v46_current_material(self)
            chunks = _v46_get_chunks(self)
            ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
            if isinstance(m, dict) and ci + 1 < len(chunks):
                m["_v46_chunk_index"] = ci + 1
                self.after(180, lambda: (_v46_render_learning_area(self), _v46_play_current(self)))
            elif getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
                self.after(250, lambda: _v46_next(self))
        return "break"
    # 中间空格：最多一个空格，判断已完成词；错误暂时仍紫色
    _v56_widget_set(w, text + " ")
    _v56_live_entry(self, item)
    return "break"

def _v56_submit_all(self):
    entries = getattr(self, "dict_v46_entries", [])
    if not entries:
        return False
    ok = True
    for it in entries:
        ok = _v56_final_entry(self, it) and ok
    if ok:
        try: _v46_beep(self, "sentence")
        except Exception: pass
        m = _v46_current_material(self)
        if isinstance(m, dict): m["status"] = "correct"
        _v46_status(self, "✅ 当前句/全部语块正确。", ok=True)
        if _v46_play_mode(self) == "整句播放" and getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
            self.after(450, lambda: _v46_next(self))
    return ok

def _v56_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in parent.winfo_children():
        try: ch.destroy()
        except Exception: pass
    m = _v46_current_material(self)
    bg = V56_BG
    if not m:
        tk.Label(parent, text="请先导入或选择听写素材", bg=bg, fg=V56_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return
    chunks = _v46_get_chunks(self)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    show_cn = bool(getattr(self, "dictation_show_cn_v30", tk.BooleanVar(value=False)).get())
    zh = _v46_item_zh(m) or "中文翻译/提示将自动显示"
    if show_cn:
        tk.Label(parent, text=zh, bg=bg, fg=V56_TEXT, font=("Microsoft YaHei UI", 24, "bold"), wraplength=1060, justify="center").pack(pady=(24, 12))
    else:
        tk.Label(parent, text="盲听模式：中文翻译和提示已隐藏", bg=bg, fg=V56_MUTED, font=("Microsoft YaHei UI", 18, "bold")).pack(pady=(24, 12))

    controls = tk.Frame(parent, bg=bg)
    controls.pack(pady=(2, 18))
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    cb = ttk.Combobox(controls, textvariable=self.dict_play_mode_v46, values=["整句播放", "拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=5)
    ttk.Button(controls, text="加载台词音频播放", command=lambda:_v56_play_current_audio(self)).pack(side="left", padx=5)
    ttk.Button(controls, text="加载台词视频播放", command=lambda:_v56_play_current_video(self)).pack(side="left", padx=5)
    ttk.Button(controls, text="跳过当前块", command=lambda:_v46_skip_current_chunk(self)).pack(side="left", padx=5)
    ttk.Checkbutton(controls, text="自动跳转下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=8)
    try: cb.bind("<<ComboboxSelected>>", lambda e:_v56_render_learning_area(self))
    except Exception: pass

    mode = _v46_play_mode(self)
    idx = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
    idx = max(0, min(idx, max(len(chunks)-1, 0)))
    show_chunks = [chunks[idx]] if mode == "拆分播放" and chunks else chunks
    line = tk.Frame(parent, bg=bg)
    line.pack(anchor="center", pady=(20, 8))
    self.dict_v46_entries = []
    for n, ch in enumerate(show_chunks):
        real_idx = idx if mode == "拆分播放" and chunks else n
        tx = ch.get("text","")
        role = ch.get("role") or (_v55_role_for_chunk(tx) if "_v55_role_for_chunk" in globals() else "句子成分")
        cell = tk.Frame(line, bg=bg)
        cell.pack(side="left", padx=10, pady=6)
        width = max(8, min(34, len(tx)+2))
        ent = tk.Text(cell, width=width, height=1, wrap="none", bg=bg, fg=V56_INPUT, insertbackground=V56_INPUT, relief="flat", bd=0, font=("Consolas", 20, "bold"), undo=False)
        ent.pack()
        cw = max(90, width*15)
        cv = tk.Canvas(cell, width=cw, height=8, bg=bg, highlightthickness=0)
        cv.pack()
        cv.create_line(2,4,cw-2,4,fill=V56_INPUT if n == 0 else V56_LINE, width=3)
        tk.Label(cell, text=role, bg=bg, fg=V56_MUTED, font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
        fb = tk.Frame(cell, bg=bg)
        fb.pack(pady=(6,0))
        try: _v55_draw_feedback(fb, [], _v55_tokens(tx))
        except Exception: pass
        item = {"idx": real_idx, "target": tx, "role": role, "entry": ent, "line": cv, "w": cw, "feedback": fb}
        self.dict_v46_entries.append(item)
        ent.bind("<KeyRelease>", lambda e, it=item: _v56_live_entry(self, it))
        ent.bind("<space>", lambda e, it=item: _v56_space_entry(self, it))
        ent.bind("<Return>", lambda e: (_v56_submit_all(self), "break"))
    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    _v46_status(self, "输入规则：单词间仅一个空格；Space 判定当前词/语块；紫=输入中，绿=正确，红=最终错误。")

# ---------------- 左侧素材池按钮与动作 ----------------
def _v56_install_material_buttons(self):
    left = getattr(self, "dictation_left_panel_v32", None)
    if left is None or getattr(self, "_v56_material_buttons_installed", False):
        return
    box = tk.Frame(left, bg="#101827")
    try:
        # 尽量放到素材池按钮区上方/下方都可以
        box.pack(fill="x", padx=8, pady=(2, 6))
    except Exception:
        return
    ttk.Button(box, text="添加本地视频字幕路径", command=lambda:_v56_add_local_video_path(self)).pack(side="left", padx=2, pady=2)
    ttk.Button(box, text="添加文本路径", command=lambda:_v56_add_text_path(self)).pack(side="left", padx=2, pady=2)
    box2 = tk.Frame(left, bg="#101827"); box2.pack(fill="x", padx=8, pady=(0,6))
    ttk.Button(box2, text="资源浏览器", command=lambda:_v56_open_resource_browser(self)).pack(side="left", padx=2, pady=2)
    ttk.Button(box2, text="复制选中台词", command=lambda:_v55_copy_selected_line(self) if "_v55_copy_selected_line" in globals() else None).pack(side="left", padx=2, pady=2)
    ttk.Button(box2, text="刷新资源目录", command=lambda:_v56_refresh_resources(self)).pack(side="left", padx=2, pady=2)
    self._v56_material_buttons_installed = True

def _v56_rebind_buttons(self):
    def walk(w):
        try:
            txt = str(w.cget("text"))
            if txt == "音效设置":
                w.configure(command=lambda:_v56_open_sound_settings(self))
            if "资源平台" in txt and "_v54_open_resource_platform" in globals():
                w.configure(command=lambda:_v54_open_resource_platform(self))
            if "下载精选池到本地" in txt and "_v55_download_pool_to_local_async" in globals():
                w.configure(command=lambda:_v55_download_pool_to_local_async(self))
            if "视频播放" == txt or txt.startswith("视频播放 "):
                w.configure(text="加载台词视频播放", command=lambda:_v56_play_current_video(self))
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

