def _v56_open_shortcut_editor(self):
    win = tk.Toplevel(self)
    win.title("听写训练快捷键设置 V56｜支持 Ctrl 单键")
    win.geometry("780x680")
    frm = ttk.Frame(win, padding=14); frm.pack(fill="both", expand=True)
    ttk.Label(frm, text="快捷键设置：允许 Ctrl 单键，也允许 Ctrl+Space / Enter / F11 / 方向键。", style="H.TLabel").pack(anchor="w")
    ttk.Label(frm, text="注意：单独英文字母在输入框聚焦时不会触发快捷键，避免打字冲突。Ctrl 单键可设置为整句播放。", style="Dim.TLabel", wraplength=720).pack(anchor="w", pady=(4,10))
    canvas = tk.Canvas(frm, highlightthickness=0)
    scroll = ttk.Scrollbar(frm, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=scroll.set)
    scroll.pack(side="right", fill="y"); canvas.pack(side="left", fill="both", expand=True)
    inner = ttk.Frame(canvas); win_id = canvas.create_window((0,0), window=inner, anchor="nw")
    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfigure(win_id, width=e.width))
    current = dict(_v56_default_hotkeys())
    current.update(getattr(self, "dict_hotkeys_v46", {}) or {})
    vars_ = {}
    for action, hk in current.items():
        row = ttk.Frame(inner); row.pack(fill="x", pady=4)
        ttk.Label(row, text=action, width=22).pack(side="left")
        sv = tk.StringVar(value=hk); vars_[action] = sv
        ttk.Entry(row, textvariable=sv, width=24).pack(side="left", padx=8)
        ttk.Label(row, text="例：Ctrl / Space / Enter / Ctrl+R / Ctrl+Alt+V / F5", style="Dim.TLabel").pack(side="left")
    def save():
        new = {}
        used = {}
        for a, sv in vars_.items():
            hk = sv.get().strip()
            try:
                seqs = _v55_hotkey_to_tk_multi(hk) if "_v55_hotkey_to_tk_multi" in globals() else [_v46_hotkey_to_tk(hk)]
            except Exception as e:
                messagebox.showwarning("快捷键非法", f"{a}: {hk}\n{e}")
                return
            for seq in seqs:
                if seq in used:
                    messagebox.showwarning("快捷键冲突", f"{a} 与 {used[seq]} 使用了同一快捷键：{hk}")
                    return
                used[seq] = a
            new[a] = hk
        self.dict_hotkeys_v46 = new
        _v55_bind_hotkeys(self) if "_v55_bind_hotkeys" in globals() else _v46_bind_hotkeys(self)
        _v46_refresh_shortcut_display(self)
        messagebox.showinfo("已生效", "快捷键已保存并立即生效。")
    btns = ttk.Frame(frm); btns.pack(fill="x", pady=(10,0))
    ttk.Button(btns, text="恢复默认", command=lambda:[vars_[k].set(v) for k,v in _v56_default_hotkeys().items() if k in vars_]).pack(side="left")
    ttk.Button(btns, text="保存并立即生效", style="Accent.TButton", command=save).pack(side="right")

# ---------------- 应用补丁 ----------------
def _v56_patch_globals(self):
    globals()["_v46_render_learning_area"] = _v56_render_learning_area
    globals()["_v46_submit_all"] = _v56_submit_all
    globals()["_v46_video_play"] = _v56_play_current_video
    globals()["_v46_play_current"] = _v56_play_current_audio
    globals()["_v46_action_map"] = _v56_action_map
    globals()["_v46_default_hotkeys"] = _v56_default_hotkeys
    globals()["_v46_open_shortcut_editor"] = _v56_open_shortcut_editor
    globals()["_v55_open_shortcut_editor"] = _v56_open_shortcut_editor

_old_main_init_v56 = MainApp.__init__
def _main_init_v56(self):
    _old_main_init_v56(self)
    try:
        _v56_init_scope_vars(self)
        _v56_patch_globals(self)
        _v56_patch_segment_popup(self)
        _v56_cleanup_duplicate_sound_bars(self) if "_v56_cleanup_duplicate_sound_bars" in globals() else None
        _v56_remove_old_segment_buttons(self)
        _v56_strip_video_audio_play_settings(self)
        _v56_install_material_buttons(self)
        _v56_rebind_buttons(self)
        try:
            self.bind_all("<KeyPress>", lambda e:_v56_sound_key_hook(self, e), add="+")
        except Exception:
            pass
        try:
            self.after(300, lambda: (_v56_patch_globals(self), _v56_patch_segment_popup(self), _v56_strip_video_audio_play_settings(self), _v56_install_material_buttons(self), _v56_rebind_buttons(self)))
            self.after(1200, lambda: (_v56_remove_old_segment_buttons(self), _v56_install_material_buttons(self), _v56_rebind_buttons(self)))
        except Exception:
            pass
        self.log("【V56上线】旧分块横线独立弹窗已移除；拆分训练统一在中间主界面。", "ok")
        self.log("【V56上线】本地素材支持递归扫描视频+字幕；文本素材支持递归扫描 TXT/SRT/VTT。", "ok")
        self.log("【V56上线】输入区已改为单词级颜色：紫=输入中，绿=正确，红=最终错误，错误提示持久显示。", "ok")
        self.log("【V56上线】音效设置新增应用范围与按键范围控制。", "ok")
    except Exception as e:
        try: self.log(f"V56初始化失败：{type(e).__name__}: {e}", "err")
        except Exception: pass

MainApp.__init__ = _main_init_v56
