# ──────────────────────────────────────────────────────────────────────
# V57: 听写训练全覆盖修复版
# 这版不是只补一个点，而是把旧链里会反复覆盖/复活的入口全部重新接管：
# 1) 彻底移除旧“分块横线听写”弹窗按钮和旧弹窗函数，拆分训练只在中间主界面。
# 2) 音效设置按钮去重；按键音真正只由 V57 键盘范围控制，不再被 V38/V40/V46/V53 旧 KeyPress 蜂鸣抢走。
# 3) 语块分割重写：按主句/从句/插入语/连接词优先，保护 take turns / set up / rule out 等短语。
# 4) 词性提示细分：人称代词/物主代词/名词/动词/副词/形容词/连词/介词/短语/冠词/助动词等。
# 5) 播放规则重写：当前筛选无素材时不播放；整句播放期间全部忽略重复播放；语块末尾 ≤0.1s 只排队一次。
# 6) PlayPhrase 下载本地化增强：优先 ClipCache，其次 local_path/URL；同步写字幕；翻译 Google→百度→OPUS。
# 7) 素材池补齐复制选中台词/刷新资源目录；快捷键面板支持 Ctrl 单键。
# 8) 横线输入颜色最终规则：输入中紫；已完成且正确的词绿；错误在 Space/Enter 最终判定后红；提示持久显示。
# ──────────────────────────────────────────────────────────────────────
import os as _os_v57
import re as _re_v57
import json as _json_v57
import time as _time_v57
import shutil as _shutil_v57
import threading as _threading_v57
import subprocess as _subprocess_v57
from pathlib import Path as _Path_v57

V57_INPUT = "#8B5CF6"
V57_OK = "#22C55E"
V57_BAD = "#EF4444"
V57_MUTED = "#94A3B8"
V57_LINE = "#CBD5E1"
V57_BG = globals().get("V46_BG", "#0b1220")
V57_TEXT = globals().get("V46_TEXT", "#E5E7EB")
V57_VIDEO_EXTS = {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"}
V57_PP_FOLDER = "play phrase网站学习资源"

V57_PROTECTED_PHRASES = [
    "take turns", "set up", "rule out", "find out", "figure out", "come up with",
    "look for", "look after", "look up", "look into", "look forward to",
    "give up", "give in", "get up", "get out", "get over", "go on", "go through",
    "put up", "put off", "run into", "run out", "make sure", "make up", "take care",
    "take off", "take over", "pay attention", "break down", "bring up", "carry out",
    "check out", "work out", "show up", "pick up", "hang out", "at least", "a few",
    "a little", "no matter", "as long as", "as soon as", "in order to", "rather than",
]
V57_PRON = {"i","me","you","he","him","she","her","it","we","us","they","them"}
V57_POSS = {"my","your","his","her","its","our","their","mine","yours","hers","ours","theirs"}
V57_ART = {"a","an","the"}
V57_CONJ = {"and","but","or","nor","so","yet","for","because","although","though","if","when","while","before","after","since","unless","until","whereas","whether","that"}
V57_PREP = {"to","from","in","on","at","with","for","of","by","about","around","into","over","under","through","between","among","against","during","without","within","across","behind","beside","beyond","toward","towards","off","up","down","out"}
V57_AUX = {"am","is","are","was","were","be","been","being","do","does","did","have","has","had","will","would","shall","should","can","could","may","might","must","need"}
V57_VERB_HINTS = {"go","goes","went","gone","make","makes","made","take","takes","took","taken","set","sets","rule","rules","ruled","turn","turns","sleep","sleeps","sleeping","help","helps","helped","say","says","said","get","gets","got","give","gives","gave","given","see","sees","saw","seen","know","knows","knew","known"}

def _v57_log(self, msg, level="info"):
    try: self.log(msg, level)
    except Exception: print(msg)

def _v57_tokens(s):
    return _re_v57.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v57_norm_space(s, keep_trailing=False):
    s = str(s or "").replace("\n", " ").replace("\t", " ")
    trailing = bool(_re_v57.search(r"\s$", s))
    s = _re_v57.sub(r"\s+", " ", s).strip()
    if keep_trailing and trailing and s:
        return s + " "
    return s

def _v57_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or m.get("phrase") or "")
    return str(getattr(m, "text", "") or m or "")

def _v57_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or m.get("chinese") or "")
    return str(getattr(m, "zh", "") or "")

# ---------------- 音效：旧 KeyPress 蜂鸣统一关掉，V57 独占按键音 ----------------
def _v57_beep(self, kind="type"):
    # 旧 Entry 里绑定的 _v38/_v40/_v43/_v46_beep(type) 没有 event 信息，会误触发。
    # 所以 type/click 统一不播放；只有 V57 的 KeyPress 钩子按范围决定。
    k = str(kind or "").lower()
    if k in ("type", "click"):
        return
    ev = "correct" if k in ("ok","correct") else "sentence" if k in ("sentence","done","success") else "error"
    try:
        if "_v54_play_sound" in globals():
            globals()["_v54_play_sound"](self, ev)
        elif "_v53_play_sound" in globals():
            globals()["_v53_play_sound"](self, ev)
        else:
            self.bell()
    except Exception:
        try: self.bell()
        except Exception: pass

def _v57_global_key_sound(self, event=None):
    try:
        # 只在输入区触发
        w = self.focus_get()
        if not isinstance(w, (tk.Entry, ttk.Entry, tk.Text)):
            return
        allowed_widget = False
        for it in getattr(self, "dict_v46_entries", []) or []:
            try:
                if str(w) == str(it.get("entry")):
                    allowed_widget = True
            except Exception:
                pass
        for a in ("recite_entry_v37", "recite_entry_v48", "recite_entry_v46"):
            try:
                if str(w) == str(getattr(self, a, "")):
                    allowed_widget = True
            except Exception:
                pass
        # 默认不在其他设置框发按键音
        try:
            if not allowed_widget and not bool(getattr(self, "v56_scope_other_tabs_var", tk.BooleanVar(value=False)).get()):
                return
        except Exception:
            if not allowed_widget:
                return

        ch = getattr(event, "char", "")
        ks = getattr(event, "keysym", "")
        # 默认方案：只有 26 个英文大小写字母。若 V56 范围设置开启更多键，则尊重设置。
        def var_on(name, default=False):
            try: return bool(getattr(self, f"v56_{name}_var").get())
            except Exception: return default
        trigger = False
        if len(ch) == 1 and ("a" <= ch.lower() <= "z"):
            trigger = var_on("letters", True)
        elif ks.startswith("KP_"):
            trigger = var_on("numpad", False)
        elif len(ch) == 1 and ch.isdigit():
            trigger = var_on("digits", False)
        elif len(ch) == 1 and not ch.isalnum():
            trigger = var_on("symbols", False)
        elif ks in ("Control_L", "Control_R"):
            trigger = var_on("ctrl", False)
        elif ks in ("space", "Space"):
            trigger = var_on("space", False)
        elif ks in ("Alt_L", "Alt_R"):
            trigger = var_on("alt", False)
        elif ks in ("Shift_L", "Shift_R"):
            trigger = var_on("shift", False)
        elif ks in ("Return", "Enter", "KP_Enter"):
            trigger = var_on("enter", False)
        elif ks in ("Left","Right","Up","Down"):
            trigger = var_on("arrows", False)
        if not trigger:
            return
        now = _time_v57.time()
        if now - getattr(self, "_v57_last_key_sfx", 0.0) < 0.045:
            return
        self._v57_last_key_sfx = now
        # 打开 V55/V54 包装的闸门
        self._v55_allow_click_once = True
        if "_v54_play_sound" in globals():
            globals()["_v54_play_sound"](self, "click")
        elif "_v53_play_sound" in globals():
            globals()["_v53_play_sound"](self, "click")
    except Exception:
        pass

# ---------------- 语块分割 / 词性提示 ----------------
def _v57_classify_word(w):
    low = str(w or "").lower()
    if not low: return "空"
    if low in V57_PRON: return "人称代词"
    if low in V57_POSS: return "物主代词"
    if low in V57_ART: return "冠词"
    if low in V57_CONJ: return "连词"
    if low in V57_PREP: return "介词"
    if low in V57_AUX: return "助动词"
    if low in V57_VERB_HINTS or low.endswith(("ing","ed","en","ize","ise","fy")): return "动词"
    if low.endswith("ly"): return "副词"
    if low.endswith(("ous","ful","ive","able","ible","al","ic","less","ary","ent","ant")): return "形容词"
    if str(w)[:1].isupper(): return "专有名词"
    return "名词"

def _v57_phrase_in(text):
    low = " ".join(_v57_tokens(text)).lower()
    for ph in sorted(V57_PROTECTED_PHRASES, key=len, reverse=True):
        if _re_v57.search(r"\b" + _re_v57.escape(ph).replace(r"\ ", r"\s+") + r"\b", low):
            return ph
    return ""

def _v57_role_for_chunk(text):
    words = _v57_tokens(text)
    ph = _v57_phrase_in(text)
    if ph:
        return "短语：" + ph
    if not words:
        return "句子成分"
    lows = [w.lower() for w in words]
    if lows[0] in V57_CONJ:
        return "连接词/从句"
    if "," in str(text):
        return "插入语/补充成分"
    tags = []
    for w in words:
        tag = _v57_classify_word(w)
        if tag not in tags:
            tags.append(tag)
    # 主语+谓语结构识别
    if any(t in ("人称代词","名词","专有名词") for t in tags[:2]) and any(w in V57_AUX or w in V57_VERB_HINTS or w.endswith(("ing","ed")) for w in lows):
        if "主句/谓语结构" not in tags:
            tags.insert(0, "主句/谓语结构")
    return " + ".join(tags[:4])

def _v57_split_by_major_clause(text):
    text = _v57_norm_space(text)
    if not text: return []
    # 标点优先：插入语、并列句、从句自然切分
    raw = [p.strip(" ,;:") for p in _re_v57.split(r"([,;:])", text) if p and p.strip(" ,;:")]
    parts = []
    for seg in raw:
        toks = _v57_tokens(seg)
        if not toks: continue
        if len(toks) <= 8:
            parts.append(" ".join(toks)); continue
        cur = []
        for w in toks:
            lw = w.lower()
            # 从句/连接词边界，但不能把短语动词里的 up/out/off 等误当边界
            if cur and lw in {"because","although","though","when","while","if","unless","until","but","and","so","which","that"} and len(cur) >= 3:
                parts.append(" ".join(cur))
                cur = [w]
            else:
                cur.append(w)
        if cur: parts.append(" ".join(cur))
    return parts or [text]

def _v57_chunk_segment(seg):
    words = _v57_tokens(seg)
    if not words:
        return []
    lows = [w.lower() for w in words]
    out = []
    i = 0
    buffer = []
    def flush_buffer_to(next_part=None):
        nonlocal buffer
        if next_part is not None:
            if buffer:
                res = " ".join(buffer + [next_part])
                buffer = []
                return res
            return next_part
        if buffer:
            out.append(" ".join(buffer))
            buffer = []

    while i < len(words):
        lw = lows[i]
        # set up + object
        if i+1 < len(words) and lw == "set" and lows[i+1] == "up":
            part = [words[i], words[i+1]]
            if i+2 < len(words) and lows[i+2] not in V57_CONJ:
                part.append(words[i+2])
                i += 3
            else:
                i += 2
            out.append(flush_buffer_to(" ".join(part)))
            continue
        # take turns + optional gerund
        if i+1 < len(words) and lw == "take" and lows[i+1] == "turns":
            part = [words[i], words[i+1]]
            if i+2 < len(words) and lows[i+2].endswith("ing"):
                part.append(words[i+2])
                i += 3
            else:
                i += 2
            out.append(flush_buffer_to(" ".join(part)))
            continue
        # rule out + object
        if i+1 < len(words) and lw == "rule" and lows[i+1] == "out":
            part = [words[i], words[i+1]]
            j = i + 2
            while j < len(words) and len(part) < 5 and lows[j] not in V57_CONJ:
                part.append(words[j]); j += 1
            i = j
            out.append(flush_buffer_to(" ".join(part)))
            continue
        # general 2-3 word protected phrase
        matched = None
        for n in (4,3,2):
            if i+n <= len(words):
                cand = " ".join(lows[i:i+n])
                if cand in V57_PROTECTED_PHRASES:
                    matched = " ".join(words[i:i+n]); i += n; break
        if matched:
            out.append(flush_buffer_to(matched)); continue
        # buffer subject/modal/determiner into next semantic chunk
        if lw in V57_PRON or lw in V57_POSS or lw in V57_AUX or lw in V57_ART:
            buffer.append(words[i]); i += 1
            # Don't let buffer grow forever
            if len(buffer) >= 3:
                out.append(" ".join(buffer)); buffer = []
            continue
        # noun/verb/adjective chunk, collect up to 3-4 words, stop before protected phrase
        part = [words[i]]; i += 1
        while i < len(words) and len(part) < 4:
            nxt2 = " ".join(lows[i:i+2])
            if lows[i] in V57_CONJ or nxt2 in V57_PROTECTED_PHRASES or (lows[i] in {"set","take","rule"}):
                break
            part.append(words[i]); i += 1
        out.append(flush_buffer_to(" ".join(part)))
    flush_buffer_to()
    # 合并过短残块
    merged = []
    for p in out:
        if not p or not p.strip(): continue
        if merged and len(_v57_tokens(p)) == 1 and _v57_tokens(p)[0].lower() not in V57_PRON:
            merged[-1] = merged[-1] + " " + p
        else:
            merged.append(p)
    return merged

def _v57_smart_chunks(text):
    text = _v57_norm_space(text)
    chunks = []
    for seg in _v57_split_by_major_clause(text):
        for part in _v57_chunk_segment(seg):
            part = _v57_norm_space(part)
            if part:
                chunks.append({"text": part, "role": _v57_role_for_chunk(part)})
    return chunks or [{"text": text, "role": _v57_role_for_chunk(text)}]

def _v57_get_chunks(self):
    m = _v46_current_material(self) if "_v46_current_material" in globals() else None
    text = _v57_item_text(m)
    if isinstance(m, dict) and m.get("_v57_chunks_text") == text and m.get("_v57_chunks"):
        return m["_v57_chunks"]
    chunks = _v57_smart_chunks(text)
    if isinstance(m, dict):
        m["_v57_chunks"] = chunks
        m["_v57_chunks_text"] = text
        m.setdefault("_v46_chunk_index", 0)
    return chunks

# ---------------- 当前素材 / 筛选 / 播放 ----------------
def _v57_bucket(m):
    try:
        return _v46_source_bucket(m)
    except Exception:
        st = str(m.get("source_type","")) if isinstance(m, dict) else ""
        if "video" in st or "local" in st: return "本地"
        if "text" in st: return "文本"
        return "在线"

def _v57_current_material(self):
    mats = getattr(self, "dictation_materials_v30", None)
    if not isinstance(mats, list):
        mats = getattr(self, "dict_items_v33", [])
    filt = getattr(self, "dict_v46_source_filter", tk.StringVar(value="全部")).get() if hasattr(self, "dict_v46_source_filter") else "全部"
    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    if not isinstance(mats, list) or not mats:
        return None
    if 0 <= idx < len(mats):
        m = mats[idx]
        if filt in ("全部", _v57_bucket(m)):
            return m
    # 筛选不匹配：不偷播旧素材，返回 None
    return None

def _v57_filter_change(self):
    filt = getattr(self, "dict_v46_source_filter", tk.StringVar(value="全部")).get()
    mats = getattr(self, "dictation_materials_v30", []) or []
    new_idx = None
    for i, m in enumerate(mats):
        if filt == "全部" or _v57_bucket(m) == filt:
            new_idx = i
            break
    if new_idx is None:
        self.dictation_index_v30 = 0
        try: self.dict_index_v33 = 0
        except Exception: pass
        try: _v46_refresh_material_tree(self)
        except Exception: pass
        try: _v46_render_learning_area(self)
        except Exception: pass
        try: _v46_status(self, f"当前【{filt}】素材池为空；播放键/Space 不会播放旧素材。", bad=True)
        except Exception: pass
        return
    self.dictation_index_v30 = new_idx
    try: self.dict_index_v33 = new_idx
    except Exception: pass
    try: _v46_refresh_current(self)
    except Exception: pass

def _v57_audio_remaining(self):
    return float(getattr(self, "_v57_audio_until", 0.0) or 0.0) - _time_v57.time()

def _v57_est_dur(text):
    return max(0.7, min(14.0, 0.36 * max(1, len(_v57_tokens(text))) + 0.45))

def _v57_speak_text(self, text, mode="chunk"):
    text = _v57_norm_space(text)
    if not text:
        return
    m = _v57_current_material(self)
    if m is None:
        try: _v46_status(self, "当前素材池没有选中素材，不播放。", bad=True)
        except Exception: pass
        return
    remain = _v57_audio_remaining(self)
    cur_mode = getattr(self, "_v57_audio_mode", "")
    if remain > 0:
        if cur_mode == "sentence":
            try: _v46_status(self, "整句播放中：重复语块/整句播放命令已忽略。")
            except Exception: pass
            return
        if cur_mode == "chunk":
            if remain > 0.1:
                try: _v46_status(self, "语块播放中：距离结束 >0.1s，重复命令已忽略。")
                except Exception: pass
                return
            if getattr(self, "_v57_audio_queued", False):
                try: _v46_status(self, "语块播放末尾已排队一次，不累计。")
                except Exception: pass
                return
            self._v57_audio_queued = True
            self.after(max(20, int(remain*1000)+20), lambda: _v57_speak_text(self, text, mode))
            return
    self._v57_audio_mode = mode
    self._v57_audio_queued = False
    self._v57_audio_until = _time_v57.time() + _v57_est_dur(text)
    # 调旧 Edge-TTS API，不走 cmd 黑框
    for fn in ("_v45_speak_edge_api", "_v44_speak_text", "_v40_speak_text"):
        if fn in globals():
            try:
                return globals()[fn](self, text)
            except Exception:
                pass
    try: self.bell()
    except Exception: pass

def _v57_play_current(self):
    m = _v57_current_material(self)
    if not m:
        try: _v46_status(self, "当前素材池为空或没有选中素材。", bad=True)
        except Exception: pass
        return
    text = _v57_item_text(m)
    mode = "sentence"
    if getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get() == "拆分播放":
        chunks = _v57_get_chunks(self)
        ci = int(m.get("_v46_chunk_index", 0) if isinstance(m, dict) else 0)
        ci = max(0, min(ci, len(chunks)-1)) if chunks else 0
        if chunks:
            text = chunks[ci]["text"]
        mode = "chunk"
    _v57_speak_text(self, text, mode=mode)

# ---------------- PlayPhrase 下载：视频+字幕+翻译+索引 ----------------
def _v57_pool_list(self):
    for name in ("pool", "selection_pool", "selected_pool", "selected_clips", "pool_items"):
        try:
            v = getattr(self, name, None)
            if isinstance(v, (list, tuple)) and v:
                return list(v)
        except Exception:
            pass
    return []

def _v57_clip_field(obj, names):
    if isinstance(obj, dict):
        for n in names:
            if obj.get(n): return str(obj.get(n))
        for n in ("clip","item","resource_meta"):
            if obj.get(n):
                v = _v57_clip_field(obj.get(n), names)
                if v: return v
    for n in names:
        try:
            v = getattr(obj, n, None)
            if v: return str(v)
        except Exception:
            pass
    return ""

def _v57_clip_text(obj):
    return _v57_clip_field(obj, ("text","en","line","sentence","phrase","subtitle","title")).strip()

def _v57_clip_zh(obj):
    return _v57_clip_field(obj, ("zh","cn","translation","chinese")).strip()

def _v57_pp_dir(self):
    try:
        if hasattr(self, "v54_resource_root_var") and self.v54_resource_root_var.get():
            root = _Path_v57(self.v54_resource_root_var.get())
        elif hasattr(self, "resource_hub_root_var_v50") and self.resource_hub_root_var_v50.get():
            root = _Path_v57(self.resource_hub_root_var_v50.get())
        else:
            root = _Path_v57.cwd() / "playphrase_resource_hub_v57"
    except Exception:
        root = _Path_v57.cwd() / "playphrase_resource_hub_v57"
    d = root / "dictation" / "本地视频字幕" / V57_PP_FOLDER
    d.mkdir(parents=True, exist_ok=True)
    return d

def _v57_translate(self, text):
    text = _v57_norm_space(text)
    if not text: return ""
    # Google -> 百度 -> OPUS。各种版本的函数名都尝试。
    candidates = [
        ("_google_translate_v19", (text, "en", "zh")),
        ("_google_translate", (text, "en", "zh")),
        ("_baidu_translate_v18", (text,)),
        ("_baidu_translate_v19", (text, "en", "zh")),
        ("_opus_translate_v19", (text, "en", "zh")),
    ]
    for name, args in candidates:
        fn = globals().get(name)
        if not callable(fn):
            # 也可能是 self 方法
            fn = getattr(self, name, None)
        if not callable(fn):
            continue
        try:
            z = fn(self, *args) if getattr(fn, "__self__", None) is None and name in globals() else fn(*args)
            z = _v57_norm_space(z)
            if z and z.lower() != text.lower():
                return z
        except Exception as e:
            try: self.log(f"V57翻译引擎 {name} 失败：{type(e).__name__}: {e}", "warn")
            except Exception: pass
    return ""

def _v57_download_one(self, clip, i, target_dir, session=None):
    text = _v57_clip_text(clip) or f"clip_{i}"
    local = _v57_clip_field(clip, ("local_path","media_path","video_path","cached_path","path","file"))
    url = _v57_clip_field(clip, ("video_url","url","remote_url","source_url","source-url"))
    dest = None

    # 1. 已有本地文件
    try:
        if local and _Path_v57(local).exists() and _Path_v57(local).suffix.lower() in V57_VIDEO_EXTS:
            src = _Path_v57(local)
            dest = target_dir / f"{i:04d}_{_v57_safe_name(text, 48)}{src.suffix or '.mp4'}"
            if not dest.exists():
                _shutil_v57.copy2(src, dest)
    except Exception as e:
        _v57_log(self, f"第{i}条复制本地缓存失败：{type(e).__name__}: {e}", "warn")

    # 2. ClipCache
    if dest is None or not dest.exists():
        try:
            cache = getattr(self, "cache", None)
            if cache is not None:
                srv = None
                try: srv = self._active_search_service()
                except Exception: pass
                sess = session or getattr(srv, "session", None)
                if sess is None:
                    try:
                        import requests
                        sess = requests.Session()
                    except Exception:
                        sess = None
                if sess is not None:
                    p = cache.ensure_cached(clip, sess, getattr(self, "ffmpeg", None))
                    if p and _Path_v57(p).exists():
                        src = _Path_v57(p)
                        dest = target_dir / f"{i:04d}_{_v57_safe_name(text, 48)}{src.suffix or '.mp4'}"
                        if not dest.exists():
                            _shutil_v57.copy2(src, dest)
                try:
                    if srv: srv.close()
                except Exception: pass
        except Exception as e:
            _v57_log(self, f"第{i}条 ClipCache 下载失败：{type(e).__name__}: {e}", "warn")

    # 3. URL 直接下载
    if (dest is None or not dest.exists()) and url:
        try:
            import requests
            sess = session or requests.Session()
            sess.headers.update({"user-agent":"Mozilla/5.0", "referer":"https://www.playphrase.me/", "origin":"https://www.playphrase.me"})
            ext = _Path_v57(url.split("?")[0]).suffix.lower()
            if ext not in V57_VIDEO_EXTS: ext = ".mp4"
            dest = target_dir / f"{i:04d}_{_v57_safe_name(text, 48)}{ext}"
            tmp = dest.with_suffix(dest.suffix + ".tmp")
            with sess.get(url, stream=True, timeout=90, allow_redirects=True, headers={"Range":"bytes=0-"}) as r:
                ct = (r.headers.get("content-type") or "").lower()
                if r.status_code in (200,206) and "text/html" not in ct and "json" not in ct:
                    with open(tmp, "wb") as f:
                        for chunk in r.iter_content(1024*256):
                            if chunk: f.write(chunk)
                    if tmp.exists() and tmp.stat().st_size > 8192:
                        tmp.replace(dest)
        except Exception as e:
            _v57_log(self, f"第{i}条 URL 直接下载失败：{type(e).__name__}: {e}", "warn")

    if dest is None or not dest.exists() or dest.stat().st_size <= 8192:
        _v57_log(self, f"第{i}条无可下载视频：text={text[:60]} url={url[:80]} local={local}", "warn")
        return None

    zh = _v57_clip_zh(clip) or _v57_translate(self, text)
    sub = dest.with_suffix(".txt")
    try:
        sub.write_text(text + ("\n" + zh if zh else "") + "\n", "utf-8")
    except Exception:
        pass
    return {
        "id": f"dictation|本地视频字幕|{V57_PP_FOLDER}|{dest}",
        "mode": "dictation",
        "top": "本地视频字幕",
        "folder": V57_PP_FOLDER,
        "origin": "PlayPhrase下载",
        "resource_type": "本地视频字幕",
        "kind": "video",
        "name": dest.name,
        "path": str(dest),
        "video_path": str(dest),
        "media_path": str(dest),
        "local_path": str(dest),
        "subtitle_path": str(sub),
        "line_count": 1,
        "status": "PlayPhrase本地视频+字幕",
        "text": text,
        "zh": zh,
        "source_type": "local_video_subtitle",
    }

def _v57_safe_name(s, n=80):
    s = _re_v57.sub(r'[\\/:*?"<>|]+', "_", str(s or "").strip())
    s = _re_v57.sub(r"\s+", " ", s)
    return (s[:n] or "untitled").strip()

def _v57_download_pool_to_local_async(self):
    pool = _v57_pool_list(self)
    if not pool:
        try: messagebox.showwarning("精选池为空", "没有可下载的精选池。")
        except Exception: pass
        return
    target = _v57_pp_dir(self)
    try: _v46_status(self, f"后台下载精选池视频+字幕：{target}")
    except Exception: pass
    def worker():
        records, ok = [], 0
        for i, clip in enumerate(pool, 1):
            rec = _v57_download_one(self, clip, i, target)
            if rec:
                records.append(rec); ok += 1
            if i % 3 == 0:
                try: self.after(0, lambda n=i,k=ok: _v46_status(self, f"下载中：{k}/{n}"))
                except Exception: pass

        # 同步到资源索引
        try:
            if "_v54_index" in globals() and "_v54_save_index" in globals():
                fp, data = _v54_index(self, "dictation")
                old = [r for r in data.get("records", []) if not (r.get("top")=="本地视频字幕" and r.get("folder")==V57_PP_FOLDER)]
                data["records"] = old + records
                data.setdefault("mounted", {}).setdefault(f"本地视频字幕/{V57_PP_FOLDER}", [str(target)])
                _v54_save_index(self, "dictation", data)
        except Exception as e:
            _v57_log(self, f"V57同步V54索引失败：{type(e).__name__}: {e}", "warn")
        try:
            if "_v50_load_index" in globals() and "_v50_save_index" in globals():
                data = _v50_load_index(self, "dictation")
                old = [r for r in data.get("records", []) if not (r.get("top")=="本地视频字幕" and r.get("folder")==V57_PP_FOLDER)]
                data["records"] = old + records
                data.setdefault("mounted", {}).setdefault(f"本地视频字幕/{V57_PP_FOLDER}", [str(target)])
                _v50_save_index(self, "dictation", data)
        except Exception:
            pass

        # 同步到听写本地素材
        mats = []
        for r in records:
            mats.append({
                "text": r.get("text",""),
                "zh": r.get("zh",""),
                "title": r.get("name",""),
                "local_path": r.get("video_path",""),
                "media_path": r.get("video_path",""),
                "video_path": r.get("video_path",""),
                "subtitle_path": r.get("subtitle_path",""),
                "source_type": "local_video_subtitle",
                "kind": "video",
            })
        def done():
            if mats:
                old = getattr(self, "dictation_materials_v30", []) or []
                old.extend(mats)
                self.dictation_materials_v30 = old
                try: self.dict_items_v33 = old
                except Exception: pass
                try: _v46_refresh_material_tree(self)
                except Exception: pass
            try: _v46_status(self, f"精选池下载/复制完成：{ok}/{len(pool)}；目录：{target}", ok=ok>0, bad=ok==0)
            except Exception: pass
        try: self.after(0, done)
        except Exception: pass
    _threading_v57.Thread(target=worker, daemon=True).start()

# ---------------- 输入区：单词级颜色 + 持久错误提示 ----------------
def _v57_widget_get(w):
    try:
        if isinstance(w, tk.Text): return w.get("1.0", "end-1c")
        return w.get()
    except Exception: return ""

def _v57_widget_set(w, s):
    s = str(s)
    try:
        if isinstance(w, tk.Text):
            w.delete("1.0", "end")
            w.insert("1.0", s)
        else:
            w.delete(0, "end")
            w.insert(0, s)
    except Exception:
        pass

def _v57_word_spans(s):
    return [(m.group(0), m.start(), m.end()) for m in _re_v57.finditer(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))]

def _v57_draw_feedback(frame, results, target_words):
    for ch in frame.winfo_children():
        try: ch.destroy()
        except Exception: pass
    if not results:
        for _ in target_words:
            tk.Label(frame, text="—", bg=V57_BG, fg=V57_MUTED, font=("Microsoft YaHei UI", 8)).pack(side="left", padx=2)
        return
    for r in results:
        color = r.get("color", V57_INPUT)
        text = f"{r.get('pos')}:{r.get('answer') or r.get('target') or '∅'}"
        tk.Label(frame, text=text, bg=V57_BG, fg=color, font=("Microsoft YaHei UI", 8, "bold")).pack(side="left", padx=2)

def _v57_tag_entry(item, final=False):
    w = item["entry"]
    raw = _v57_widget_get(w)
    # 严格空格：最多一个空格；末尾只有在中间输入时保留一个
    norm = _v57_norm_space(raw, keep_trailing=raw.endswith(" ") and not final)
    if norm != raw:
        _v57_widget_set(w, norm)
        raw = norm
    target = item["target"]
    target_words = _v57_tokens(target)
    spans = _v57_word_spans(raw)
    current_words = [x[0] for x in spans]
    exact = len(current_words) == len(target_words) and " ".join(current_words).lower() == " ".join(target_words).lower()

    try:
        w.tag_configure("v57_input", foreground=V57_INPUT)
        w.tag_configure("v57_ok", foreground=V57_OK)
        w.tag_configure("v57_bad", foreground=V57_BAD)
        for tag in ("v57_input","v57_ok","v57_bad"):
            w.tag_remove(tag, "1.0", "end")
    except Exception:
        pass

    results = []
    trailing = raw.endswith(" ")
    completed = len(spans) if trailing else max(0, len(spans)-1)
    if exact:
        completed = len(spans)

    for i, (word, a, b) in enumerate(spans):
        tw = target_words[i] if i < len(target_words) else ""
        if i < len(target_words) and (exact or (i < completed and word.lower() == tw.lower())):
            tag, color, typ = "v57_ok", V57_OK, "正确"
        elif final:
            tag, color, typ = ("v57_ok", V57_OK, "正确") if (i < len(target_words) and word.lower() == tw.lower()) else ("v57_bad", V57_BAD, "错误")
        else:
            # 关键：未最终判定的错误/半截词全部紫，不红
            tag, color, typ = "v57_input", V57_INPUT, "输入中"
        try:
            w.tag_add(tag, f"1.0+{a}c", f"1.0+{b}c")
        except Exception:
            try: w.configure(fg=color)
            except Exception: pass
        results.append({"pos": i+1, "answer": word, "target": tw, "type": typ, "color": color, "partial": typ=="输入中"})

    if final and len(spans) < len(target_words):
        for j in range(len(spans), len(target_words)):
            results.append({"pos": j+1, "answer": "", "target": target_words[j], "type": "缺词", "color": V57_BAD})

    # 横线颜色：只要最终全对绿；最终有错红；否则紫
    try:
        _v46_set_line(item, V57_OK if exact else V57_BAD if final else V57_INPUT)
    except Exception:
        pass
    _v57_draw_feedback(item["feedback"], results, target_words)
    return exact, results

def _v57_live_entry(self, item):
    ok, results = _v57_tag_entry(item, final=False)
    if ok:
        try: _v46_status(self, "✅ 当前语块全部正确。", ok=True)
        except Exception: pass
    else:
        correct = [r["target"] for r in results if r.get("type") == "正确"]
        if correct:
            try: _v46_status(self, "已确认正确：" + " / ".join(correct), ok=True)
            except Exception: pass
        else:
            try: _v46_status(self, "紫色=输入中；绿色=已完成且正确；红色=最终判定错误。")
            except Exception: pass
    return ok

def _v57_final_entry(self, item):
    ok, results = _v57_tag_entry(item, final=True)
    if ok:
        try: _v46_beep(self, "ok")
        except Exception: pass
        try: _v46_status(self, "✅ 当前语块正确。", ok=True)
        except Exception: pass
        return True
    try: _v46_beep(self, "bad")
    except Exception: pass
    wrong = [r for r in results if r.get("type") != "正确"]
    all_wrong = len(wrong) == len(results)
    msg = ("全错：" if all_wrong else "错误部分：") + "；".join([f"第{r['pos']}词 {r['type']}：输入[{r.get('answer') or '空'}] / 应为[{r.get('target') or '空'}]" for r in wrong[:8]])
    try: _v46_status(self, "❌ " + msg, bad=True)
    except Exception: pass
    return False

def _v57_space_entry(self, item):
    raw = _v57_widget_get(item["entry"])
    text = _v57_norm_space(raw, keep_trailing=False)
    target_words = _v57_tokens(item["target"])
    words = _v57_tokens(text)
    if not words:
        return "break"
    if len(words) >= len(target_words):
        _v57_widget_set(item["entry"], text)
        ok = _v57_final_entry(self, item)
        if ok and getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get() == "拆分播放":
            m = _v57_current_material(self)
            chunks = _v57_get_chunks(self)
            ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
            if isinstance(m, dict) and ci + 1 < len(chunks):
                m["_v46_chunk_index"] = ci + 1
                self.after(180, lambda: (_v46_render_learning_area(self), _v57_play_current(self)))
            elif getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
                self.after(260, lambda: _v46_next(self))
        return "break"
    _v57_widget_set(item["entry"], text + " ")
    _v57_live_entry(self, item)
    return "break"

def _v57_submit_all(self):
    entries = getattr(self, "dict_v46_entries", [])
    if not entries: return False
    ok = True
    for it in entries:
        ok = _v57_final_entry(self, it) and ok
    if ok:
        try: _v46_beep(self, "sentence")
        except Exception: pass
        m = _v57_current_material(self)
        if isinstance(m, dict): m["status"] = "correct"
        try: _v46_status(self, "✅ 当前句/全部语块正确。", ok=True)
        except Exception: pass
        if getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get() == "整句播放" and getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
            self.after(450, lambda: _v46_next(self))
    return ok

def _v57_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None: return
    for ch in parent.winfo_children():
        try: ch.destroy()
        except Exception: pass
    m = _v57_current_material(self)
    if not m:
        tk.Label(parent, text="当前分类没有素材；请在左侧选择/导入资源", bg=V57_BG, fg=V57_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return

    chunks = _v57_get_chunks(self)
    show_cn = bool(getattr(self, "dictation_show_cn_v30", tk.BooleanVar(value=False)).get())
    zh = _v57_item_zh(m) or "中文翻译/提示未加载"
    if show_cn:
        tk.Label(parent, text=zh, bg=V57_BG, fg=V57_TEXT, font=("Microsoft YaHei UI", 22, "bold"), wraplength=1080, justify="center").pack(pady=(24, 12))
    else:
        tk.Label(parent, text="盲听模式：中文翻译和提示已隐藏", bg=V57_BG, fg=V57_MUTED, font=("Microsoft YaHei UI", 18, "bold")).pack(pady=(24, 12))

    controls = tk.Frame(parent, bg=V57_BG); controls.pack(pady=(2, 18))
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    cb = ttk.Combobox(controls, textvariable=self.dict_play_mode_v46, values=["整句播放","拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=5)
    ttk.Button(controls, text="加载台词音频播放", command=lambda: _v56_play_current_audio(self) if "_v56_play_current_audio" in globals() else _v57_play_current(self)).pack(side="left", padx=5)
    ttk.Button(controls, text="加载台词视频播放", command=lambda: _v56_play_current_video(self) if "_v56_play_current_video" in globals() else None).pack(side="left", padx=5)
    ttk.Button(controls, text="跳过当前块", command=lambda: _v46_skip_current_chunk(self)).pack(side="left", padx=5)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    ttk.Checkbutton(controls, text="自动跳转下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=8)
    cb.bind("<<ComboboxSelected>>", lambda e: _v57_render_learning_area(self))

    mode = getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get()
    ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
    ci = max(0, min(ci, len(chunks)-1)) if chunks else 0
    show_chunks = [chunks[ci]] if mode == "拆分播放" and chunks else chunks

    line = tk.Frame(parent, bg=V57_BG)
    line.pack(anchor="center", pady=(20, 8))
    self.dict_v46_entries = []
    for n, ch in enumerate(show_chunks):
        real_idx = ci if mode == "拆分播放" else n
        tx = ch.get("text", "")
        role = ch.get("role") or _v57_role_for_chunk(tx)
        cell = tk.Frame(line, bg=V57_BG); cell.pack(side="left", padx=12, pady=6)
        width = max(8, min(38, len(tx)+2))
        ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V57_BG, fg=V57_INPUT, insertbackground=V57_INPUT, relief="flat", bd=0, font=("Consolas", 20, "bold"), undo=False)
        ent.pack()
        cw = max(96, width*15)
        cv = tk.Canvas(cell, width=cw, height=8, bg=V57_BG, highlightthickness=0); cv.pack()
        cv.create_line(2, 4, cw-2, 4, fill=V57_INPUT if n == 0 else V57_LINE, width=3)
        tk.Label(cell, text=role, bg=V57_BG, fg=V57_MUTED, font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
        fb = tk.Frame(cell, bg=V57_BG); fb.pack(pady=(6,0))
        _v57_draw_feedback(fb, [], _v57_tokens(tx))
        item = {"idx": real_idx, "target": tx, "role": role, "entry": ent, "line": cv, "w": cw, "feedback": fb}
        self.dict_v46_entries.append(item)
        ent.bind("<KeyRelease>", lambda e, it=item: _v57_live_entry(self, it))
        ent.bind("<space>", lambda e, it=item: _v57_space_entry(self, it))
        ent.bind("<Return>", lambda e: (_v57_submit_all(self), "break"))
    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    try: _v46_status(self, "输入规则：一个单词后按 Space；紫=输入中，绿=正确，红=最终错误；错误提示会保留。")
    except Exception: pass

# ---------------- 素材池增强 / 快捷键 / 清理按钮 ----------------
def _v57_copy_selected_line(self):
    m = _v57_current_material(self)
    if not m:
        return
    text = _v57_item_text(m)
    zh = _v57_item_zh(m)
    try:
        self.clipboard_clear()
        self.clipboard_append(text + ("\n" + zh if zh else ""))
        self.update()
        _v46_status(self, "已复制选中台词。", ok=True)
    except Exception:
        pass

def _v57_refresh_resources(self):
    if "_v56_refresh_resources" in globals():
        try:
            return _v56_refresh_resources(self)
        except Exception:
            pass
    try: _v46_refresh_material_tree(self)
    except Exception: pass
    try: _v46_status(self, "已刷新素材树。", ok=True)
    except Exception: pass

def _v57_install_material_buttons(self):
    left = getattr(self, "dictation_left_panel_v32", None)
    if left is None or getattr(self, "_v57_material_buttons_installed", False):
        return
    box = tk.Frame(left, bg="#101827")
    try: box.pack(fill="x", padx=8, pady=(2, 6))
    except Exception: return
    ttk.Button(box, text="复制选中台词", command=lambda: _v57_copy_selected_line(self)).pack(side="left", padx=2, pady=2)
    ttk.Button(box, text="刷新资源目录", command=lambda: _v57_refresh_resources(self)).pack(side="left", padx=2, pady=2)
    # 如果 V56 的路径扫描函数存在，也补上入口
    if "_v56_add_local_video_path" in globals():
        ttk.Button(box, text="添加本地视频字幕路径", command=lambda: _v56_add_local_video_path(self)).pack(side="left", padx=2, pady=2)
    if "_v56_add_text_path" in globals():
        ttk.Button(box, text="添加文本路径", command=lambda: _v56_add_text_path(self)).pack(side="left", padx=2, pady=2)
    self._v57_material_buttons_installed = True

def _v57_action_map(self):
    try: base = _v46_action_map_original_v57(self)
    except Exception: base = {}
    base.update({
        "主播放/当前音频": lambda: _v57_play_current(self),
        "整句播放": lambda: _v57_play_current(self),
        "播放当前": lambda: _v57_play_current(self),
        "复制选中台词": lambda: _v57_copy_selected_line(self),
        "刷新资源目录": lambda: _v57_refresh_resources(self),
        "下载精选池到本地": lambda: _v57_download_pool_to_local_async(self),
    })
    return base

def _v57_hotkey_to_tk(seq):
    s = str(seq or "").strip()
    low = s.lower()
    if low in ("ctrl","control"): return ["<KeyPress-Control_L>","<KeyPress-Control_R>"]
    if low == "alt": return ["<KeyPress-Alt_L>","<KeyPress-Alt_R>"]
    if low == "shift": return ["<KeyPress-Shift_L>","<KeyPress-Shift_R>"]
    if low == "space": return ["<space>"]
    if low in ("enter","return"): return ["<Return>"]
    if low.startswith("ctrl+"):
        key = s.split("+",1)[1]
        if key.lower() == "space": return ["<Control-space>"]
        return [f"<Control-{key}>"]
    try:
        return [_v46_hotkey_to_tk(s)]
    except Exception:
        return []

def _v57_bind_hotkeys(self):
    # 先解绑常见全局，尤其 Ctrl 旧链
    for seq in ["<KeyPress-Control_L>","<KeyPress-Control_R>","<Control-r>","<Control-R>","<Control-space>","<space>","<Return>"]:
        try: self.unbind_all(seq)
        except Exception: pass
    hot = getattr(self, "dict_hotkeys_v46", {}) or {}
    defaults = {"主播放/当前音频":"Ctrl+R","整句播放":"Ctrl","复制选中台词":"Ctrl+C","刷新资源目录":"F5"}
    for k,v in defaults.items():
        hot.setdefault(k,v)
    self.dict_hotkeys_v46 = hot
    actions = _v57_action_map(self)
    for action, hk in hot.items():
        if action not in actions:
            continue
        for seq in _v57_hotkey_to_tk(hk):
            def handler(e=None, act=action):
                # 单字母快捷键在输入框内无效，避免打字冲突；Ctrl 允许。
                try:
                    if _re_v57.fullmatch(r"[A-Za-z]", str(hk).strip()) and isinstance(self.focus_get(), (tk.Entry, ttk.Entry, tk.Text)):
                        return None
                except Exception:
                    pass
                actions[act]()
                return "break"
            try: self.bind_all(seq, handler)
            except Exception: pass

def _v57_open_shortcut_editor(self):
    # 基于 V56 面板，若存在则调用；否则简化面板。
    if "_v56_open_shortcut_editor" in globals():
        try: return _v56_open_shortcut_editor(self)
        except Exception: pass
    win = tk.Toplevel(self); win.title("快捷键设置 V57")
    win.geometry("720x520")
    frm = ttk.Frame(win, padding=12); frm.pack(fill="both", expand=True)
    acts = ["主播放/当前音频","整句播放","复制选中台词","刷新资源目录","下载精选池到本地"]
    vars_ = {}
    hot = getattr(self, "dict_hotkeys_v46", {}) or {}
    for a in acts:
        row = ttk.Frame(frm); row.pack(fill="x", pady=5)
        ttk.Label(row, text=a, width=22).pack(side="left")
        sv = tk.StringVar(value=hot.get(a, "Ctrl" if a=="整句播放" else ""))
        vars_[a]=sv
        ttk.Entry(row, textvariable=sv, width=24).pack(side="left")
    def save():
        self.dict_hotkeys_v46 = {a:sv.get().strip() for a,sv in vars_.items()}
        _v57_bind_hotkeys(self)
        messagebox.showinfo("完成","快捷键已保存并立即生效。")
    ttk.Button(frm, text="保存并立即生效", command=save).pack(anchor="e", pady=10)

def _v57_cleanup_buttons(self):
    # 1) 音效按钮去重：保留一个“音效设置”，移除测试音按钮
    seen_sound = False
    def walk(w):
        nonlocal seen_sound
        try:
            txt = str(w.cget("text"))
            if txt in ("测试按键音","测试错误音","测试正确音"):
                for meth in ("pack_forget","grid_remove","place_forget"):
                    try: getattr(w, meth)()
                    except Exception: pass
            if txt == "音效设置":
                if seen_sound:
                    for meth in ("pack_forget","grid_remove","place_forget"):
                        try: getattr(w, meth)()
                        except Exception: pass
                else:
                    seen_sound = True
                    if "_v56_open_sound_settings" in globals():
                        try: w.configure(command=lambda: _v56_open_sound_settings(self))
                        except Exception: pass
            if "分块横线听写" in txt or "方块横线" in txt or txt.strip() in ("..","…"):
                for meth in ("pack_forget","grid_remove","place_forget"):
                    try: getattr(w, meth)()
                    except Exception: pass
            if "下载精选池到本地" in txt:
                try: w.configure(command=lambda: _v57_download_pool_to_local_async(self))
                except Exception: pass
            if txt == "快捷键设置":
                try: w.configure(command=lambda: _v57_open_shortcut_editor(self))
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

# ---------------- 全局接管 ----------------
def _v57_patch_globals(self):
    # 保存原 action map
    if "_v46_action_map_original_v57" not in globals() and "_v46_action_map" in globals():
        globals()["_v46_action_map_original_v57"] = globals()["_v46_action_map"]
    for name in ("_v38_beep","_v40_beep","_v43_beep","_v46_beep","_v48_beep","_v53_beep"):
        globals()[name] = _v57_beep
    globals()["_v53_global_key_sound"] = _v57_global_key_sound
    globals()["_v46_semantic_chunks"] = _v57_smart_chunks
    globals()["_v55_smart_chunks"] = _v57_smart_chunks
    globals()["_v46_get_chunks"] = _v57_get_chunks
    globals()["_v46_current_material"] = _v57_current_material
    globals()["_v46_render_learning_area"] = _v57_render_learning_area
    globals()["_v46_submit_all"] = _v57_submit_all
    globals()["_v46_play_current"] = _v57_play_current
    globals()["_v46_speak_text"] = _v57_speak_text
    globals()["_v48_speak_managed"] = lambda app, *a, **k: _v57_play_current(app)
    globals()["_v46_action_map"] = _v57_action_map
    globals()["_v46_bind_hotkeys"] = _v57_bind_hotkeys
    globals()["_v46_open_shortcut_editor"] = _v57_open_shortcut_editor
    globals()["_open_segment_dictation_panel_v37"] = lambda app: (_v57_render_learning_area(app), _v46_status(app, "旧分块弹窗已移除，请使用中间主界面的拆分播放。", ok=True))
    globals()["_v38_draw_segment_input"] = lambda app: (_v57_render_learning_area(app), None)
    globals()["_v52_download_pool_to_local_async"] = lambda app, pool=None: _v57_download_pool_to_local_async(app)
    globals()["_v55_download_pool_to_local_async"] = lambda app: _v57_download_pool_to_local_async(app)
    globals()["_v56_download_pool_to_local_async"] = lambda app: _v57_download_pool_to_local_async(app)

_old_main_init_v57 = MainApp.__init__
def _main_init_v57(self):
    _old_main_init_v57(self)
    try:
        _v57_patch_globals(self)
        _v57_cleanup_buttons(self)
        _v57_install_material_buttons(self)
        # 绑定 V57 独占按键音，并重新绑定快捷键
        try: self.bind_all("<KeyPress>", lambda e: _v57_global_key_sound(self, e), add="+")
        except Exception: pass
        try: _v57_bind_hotkeys(self)
        except Exception: pass
        # 资源筛选 combobox 重新绑定，切空分类时不会偷播旧素材
        try:
            for ch in getattr(self, "dictation_left_panel_v32").winfo_children():
                if isinstance(ch, ttk.Combobox):
                    ch.bind("<<ComboboxSelected>>", lambda e: _v57_filter_change(self), add="")
        except Exception:
            pass
        try:
            self.after(300, lambda: (_v57_patch_globals(self), _v57_cleanup_buttons(self), _v57_install_material_buttons(self), _v57_bind_hotkeys(self)))
            self.after(1000, lambda: (_v57_cleanup_buttons(self), _v57_bind_hotkeys(self)))
            self.after(2000, lambda: (_v57_cleanup_buttons(self),))
        except Exception:
            pass
        self.log("【V57上线】旧分块横线弹窗/方块横线入口已彻底接管并移除。", "ok")
        self.log("【V57上线】按键音只由 V57 范围控制；旧 KeyPress 蜂鸣已关闭。", "ok")
        self.log("【V57上线】语块切分重写：保护 take turns / set up / rule out 等短语，按主句/从句/插入语优先切分。", "ok")
        self.log("【V57上线】输入颜色规则重写：输入中紫色，已完成正确词绿色，最终错误红色，提示持久显示。", "ok")
        self.log("【V57上线】播放/下载/快捷键/素材复制刷新已重新接管。", "ok")
    except Exception as e:
        try: self.log(f"V57初始化失败：{type(e).__name__}: {e}", "err")
        except Exception: pass

MainApp.__init__ = _main_init_v57
APP_TITLE = "PlayPhrase Studio Clean v57 · 听写训练全覆盖修复版"


# ──────────────────────────────────────────────────────────────────────
# V58: 听写训练强制接管版
# 这版专门修复 V57 仍然“没有完全改全”的根因：
# - 旧 UI 已经创建好的按钮 command 没有被全部重绑；
# - V56/V57 action_map 存在递归链，导致快捷键/按钮部分不生效；
# - V37/V46 素材树刷新会 selection_set 触发 TreeviewSelect，再进旧刷新链；
# - 旧 KeyPress 全局绑定仍在，导致非字母也可能触发音效；
# - PlayPhrase 下载只看 self.pool，若按钮链改成轻量材料后就找不到原始 Clip。
# ──────────────────────────────────────────────────────────────────────
import os as _os_v58
import re as _re_v58
import time as _time_v58
import json as _json_v58
import shutil as _shutil_v58
import threading as _threading_v58
from pathlib import Path as _Path_v58

V58_INPUT = "#8B5CF6"
V58_OK = "#22C55E"
V58_BAD = "#EF4444"
V58_MUTED = "#94A3B8"
V58_LINE = "#CBD5E1"
V58_BG = globals().get("V46_BG", "#0b1220")
V58_TEXT = globals().get("V46_TEXT", "#E5E7EB")
V58_VIDEO_EXTS = {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"}
V58_SUB_EXTS = {".srt", ".ass", ".ssa", ".vtt", ".txt"}
V58_TEXT_EXTS = {".txt", ".srt", ".vtt", ".csv", ".lrc"}
V58_PP_FOLDER = "play phrase网站学习资源"

V58_PROTECTED = [
    "take turns", "set up", "rule out", "find out", "figure out", "come up with",
    "look for", "look after", "look up", "look into", "look forward to",
    "give up", "give in", "give out", "get up", "get out", "get over", "go on",
    "go through", "put up", "put off", "run into", "run out", "make sure",
    "make up", "take care", "take off", "take over", "pay attention", "break down",
    "bring up", "carry out", "check out", "work out", "show up", "pick up",
    "hang out", "at least", "a few", "a little", "no matter", "as long as",
    "as soon as", "in order to", "rather than",
]
V58_PRON = {"i","me","you","he","him","she","her","it","we","us","they","them"}
V58_POSS = {"my","your","his","her","its","our","their","mine","yours","hers","ours","theirs"}
V58_ART = {"a","an","the"}
V58_CONJ = {"and","but","or","nor","so","yet","for","because","although","though","if","when","while","before","after","since","unless","until","whereas","whether","that","which"}
V58_PREP = {"to","from","in","on","at","with","for","of","by","about","around","into","over","under","through","between","among","against","during","without","within","across","behind","beside","beyond","toward","towards","off","up","down","out"}
V58_AUX = {"am","is","are","was","were","be","been","being","do","does","did","have","has","had","will","would","shall","should","can","could","may","might","must","need"}
V58_VERBS = {"go","goes","went","gone","make","makes","made","take","takes","took","taken","set","sets","rule","rules","ruled","turn","turns","sleep","sleeps","sleeping","help","helps","helped","say","says","said","get","gets","got","give","gives","gave","given","see","sees","saw","seen","know","knows","knew","known","be","is","are","was","were","have","has","had","do","does","did"}

def _v58_log(self, msg, level="info"):
    try:
        self.log(msg, level)
    except Exception:
        print(msg)

def _v58_tokens(s):
    return _re_v58.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v58_norm(s, keep_trailing=False):
    s = str(s or "").replace("\n", " ").replace("\t", " ")
    trailing = bool(_re_v58.search(r"\s$", s))
    s = _re_v58.sub(r"\s+", " ", s).strip()
    return s + " " if keep_trailing and trailing and s else s

def _v58_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or m.get("phrase") or "")
    return str(getattr(m, "text", "") or m or "")

def _v58_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or m.get("chinese") or "")
    return str(getattr(m, "zh", "") or "")

def _v58_item_path(m):
    if isinstance(m, dict):
        for k in ("video_path", "media_path", "local_path", "path", "subtitle_path"):
            v = m.get(k)
            if v:
                try:
                    return _Path_v58(v)
                except Exception:
                    pass
    for k in ("video_path", "media_path", "local_path", "path"):
        try:
            v = getattr(m, k, "")
            if v:
                return _Path_v58(v)
        except Exception:
            pass
    return None

def _v58_bucket(m):
    if isinstance(m, dict):
        st = str(m.get("source_type","")).lower()
        if "online" in st or "playphrase_online" in st:
            return "在线"
        if "local_text" in st or st == "text":
            return "文本"
        if "local_video" in st or "video" in st or m.get("video_path"):
            return "本地"
        p = _v58_item_path(m)
        if p and p.suffix.lower() in V58_TEXT_EXTS:
            return "文本"
        if p:
            return "本地"
    try:
        return _v46_source_bucket(m)
    except Exception:
        return "文本"

def _v58_source_parts(m):
    p = _v58_item_path(m)
    if p:
        parts = list(p.parts)
        return [str(x) for x in parts[-5:-1]] or [p.parent.name]
    if isinstance(m, dict):
        return [str(m.get("title") or m.get("keyword") or "在线精选")]
    return ["纯文本"]

# ---------------- 语块分割 ----------------
def _v58_classify_word(w):
    low = str(w or "").lower()
    if not low: return "空"
    if low in V58_PRON: return "人称代词"
    if low in V58_POSS: return "物主代词"
    if low in V58_ART: return "冠词"
    if low in V58_CONJ: return "连词"
    if low in V58_PREP: return "介词"
    if low in V58_AUX: return "助动词"
    if low in V58_VERBS or low.endswith(("ing","ed","en","ize","ise","fy")): return "动词"
    if low.endswith("ly"): return "副词"
    if low.endswith(("ous","ful","ive","able","ible","al","ic","less","ary","ent","ant")): return "形容词"
    if str(w)[:1].isupper(): return "专有名词"
    return "名词"

def _v58_role(text):
    toks = _v58_tokens(text)
    low_text = " ".join(t.lower() for t in toks)
    for ph in sorted(V58_PROTECTED, key=len, reverse=True):
        if _re_v58.search(r"\b" + _re_v58.escape(ph).replace(r"\ ", r"\s+") + r"\b", low_text):
            return "短语：" + ph
    if not toks:
        return "句子成分"
    lows = [t.lower() for t in toks]
    tags = []
    if lows[0] in V58_CONJ:
        tags.append("连接词/从句")
    if any(x in lows for x in V58_AUX) or any(x in V58_VERBS for x in lows):
        if any(x in lows for x in V58_PRON) or any(_v58_classify_word(x) in ("名词", "专有名词") for x in toks):
            tags.append("主句/谓语结构")
    for t in toks:
        tag = _v58_classify_word(t)
        if tag not in tags:
            tags.append(tag)
    return " + ".join(tags[:4])

def _v58_chunk_segment(words):
    lows = [w.lower() for w in words]
    out, buf, i = [], [], 0

    def attach(part):
        nonlocal buf
        if buf:
            out.append(" ".join(buf + [part]))
            buf = []
        else:
            out.append(part)

    while i < len(words):
        lw = lows[i]

        # Subject/modal/determiner buffer, attach to next semantic block.
        if lw in V58_PRON or lw in V58_POSS or lw in V58_AUX or lw in V58_ART:
            buf.append(words[i])
            i += 1
            if len(buf) >= 3:
                out.append(" ".join(buf)); buf = []
            continue

        # set up + object
        if i + 1 < len(words) and lw == "set" and lows[i+1] == "up":
            part = [words[i], words[i+1]]
            if i + 2 < len(words) and lows[i+2] not in V58_CONJ:
                part.append(words[i+2]); i += 3
            else:
                i += 2
            attach(" ".join(part)); continue

        # take turns + optional gerund
        if i + 1 < len(words) and lw == "take" and lows[i+1] == "turns":
            part = [words[i], words[i+1]]
            if i + 2 < len(words) and lows[i+2].endswith("ing"):
                part.append(words[i+2]); i += 3
            else:
                i += 2
            attach(" ".join(part)); continue

        # rule out + object phrase
        if i + 1 < len(words) and lw == "rule" and lows[i+1] == "out":
            part = [words[i], words[i+1]]
            j = i + 2
            while j < len(words) and len(part) < 5 and lows[j] not in V58_CONJ:
                part.append(words[j]); j += 1
            i = j
            attach(" ".join(part)); continue

        # general protected phrases 4/3/2 words
        hit = None
        for n in (4,3,2):
            if i+n <= len(words):
                cand = " ".join(lows[i:i+n])
                if cand in V58_PROTECTED:
                    hit = " ".join(words[i:i+n])
                    i += n
                    break
        if hit:
            attach(hit); continue

        # general chunk: 3-4 words, stop before protected phrase/connector.
        part = [words[i]]
        i += 1
        while i < len(words) and len(part) < 4:
            nxt2 = " ".join(lows[i:i+2])
            if lows[i] in V58_CONJ or nxt2 in V58_PROTECTED or lows[i] in {"set", "take", "rule"}:
                break
            part.append(words[i]); i += 1
        attach(" ".join(part))
    if buf:
        if out:
            out[-1] = out[-1] + " " + " ".join(buf)
        else:
            out.append(" ".join(buf))
    return [x for x in out if x.strip()]

def _v58_smart_chunks(text):
    text = _v58_norm(text)
    if not text:
        return []
    raw_parts = []
    for seg in _re_v58.split(r"[,;:]+", text):
        seg = _v58_norm(seg)
        if not seg: continue
        toks = _v58_tokens(seg)
        if len(toks) <= 8:
            raw_parts.append(toks)
            continue
        cur = []
        for w in toks:
            lw = w.lower()
            if cur and lw in {"because","although","though","when","while","if","unless","until","but","and","so","which","that"} and len(cur) >= 3:
                raw_parts.append(cur); cur = [w]
            else:
                cur.append(w)
        if cur: raw_parts.append(cur)
    chunks = []
    for words in raw_parts:
        for part in _v58_chunk_segment(words):
            chunks.append({"text": part, "role": _v58_role(part)})
    return chunks or [{"text": text, "role": _v58_role(text)}]

def _v58_get_chunks(self):
    m = _v58_current_material(self)
    text = _v58_item_text(m)
    if isinstance(m, dict) and m.get("_v58_chunks_text") == text and m.get("_v58_chunks"):
        return m["_v58_chunks"]
    chunks = _v58_smart_chunks(text)
    if isinstance(m, dict):
        m["_v58_chunks"] = chunks
        m["_v58_chunks_text"] = text
        m.setdefault("_v46_chunk_index", 0)
    return chunks

# ---------------- 素材树：避免刷新递归 ----------------
def _v58_filter(self):
    try:
        return getattr(self, "dict_v46_source_filter").get()
    except Exception:
        return "全部"

def _v58_current_material(self):
    mats = getattr(self, "dictation_materials_v30", None)
    if not isinstance(mats, list):
        mats = getattr(self, "dict_items_v33", [])
    if not isinstance(mats, list) or not mats:
        return None
    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    if not (0 <= idx < len(mats)):
        return None
    m = mats[idx]
    filt = _v58_filter(self)
    if filt not in ("全部", "", _v58_bucket(m)):
        return None
    return m

def _v58_first_index_for_filter(self, filt=None):
    filt = filt or _v58_filter(self)
    mats = getattr(self, "dictation_materials_v30", []) or []
    for i, m in enumerate(mats):
        if filt in ("全部", "", _v58_bucket(m)):
            return i
    return None

def _v58_refresh_material_tree(self):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None:
        return
    self._v58_tree_refreshing = True
    try:
        tree.delete(*tree.get_children())
        filt = _v58_filter(self)
        roots, node_map = {}, {}
        for bucket in ["在线", "本地", "文本"]:
            if filt not in ("全部", bucket): continue
            roots[bucket] = tree.insert("", "end", text=bucket + "素材", open=True, values=("ROOT", bucket))
        mats = getattr(self, "dictation_materials_v30", []) or []
        for i, m in enumerate(mats):
            bucket = _v58_bucket(m)
            if bucket not in roots: continue
            parent, acc = roots[bucket], bucket
            for part in _v58_source_parts(m):
                part = str(part)[:80] or "未分类"
                acc += "/" + part
                if acc not in node_map:
                    node_map[acc] = tree.insert(parent, "end", text=part, open=True if bucket == "本地" else False, values=("DIR", acc))
                parent = node_map[acc]
            mark = "✓" if isinstance(m, dict) and m.get("status") == "correct" else "·"
            text = _v58_item_text(m)
            tree.insert(parent, "end", iid=f"item_{i}", text=f"{mark} {i+1:03d}. {text[:80]}", values=("ITEM", str(i)))
        cur = f"item_{getattr(self, 'dictation_index_v30', 0)}"
        if tree.exists(cur):
            tree.selection_set(cur); tree.see(cur)
    finally:
        self._v58_tree_refreshing = False

def _v58_on_tree_select(self):
    if getattr(self, "_v58_tree_refreshing", False):
        return
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None: return
    sel = tree.selection()
    if not sel: return
    vals = tree.item(sel[0], "values")
    if vals and vals[0] == "ITEM":
        try:
            self.dictation_index_v30 = int(vals[1])
            self.dict_index_v33 = self.dictation_index_v30
            _v58_refresh_current(self)
        except Exception as e:
            _v58_log(self, f"素材选择失败：{e}", "warn")

def _v58_filter_change(self):
    idx = _v58_first_index_for_filter(self)
    if idx is None:
        self.dictation_index_v30 = 0
        try: self.dict_index_v33 = 0
        except Exception: pass
        _v58_refresh_material_tree(self)
        _v58_render_learning_area(self)
        try: _v46_status(self, f"当前【{_v58_filter(self)}】素材池为空；播放/Space 不会播放旧素材。", bad=True)
        except Exception: pass
        return
    self.dictation_index_v30 = idx
    try: self.dict_index_v33 = idx
    except Exception: pass
    _v58_refresh_current(self)

def _v58_refresh_current(self):
    m = _v58_current_material(self)
    try:
        if hasattr(self, "dictation_target_meta_var_v30"):
            if m:
                mats = getattr(self, "dictation_materials_v30", []) or []
                self.dictation_target_meta_var_v30.set(f"{getattr(self,'dictation_index_v30',0)+1}/{len(mats)}｜{_v58_bucket(m)}｜{str(m.get('title','') if isinstance(m,dict) else '')}")
            else:
                self.dictation_target_meta_var_v30.set("当前材料：无")
    except Exception:
        pass
    _v58_refresh_material_tree(self)
    _v58_render_learning_area(self)

# ---------------- 输入区：单词级颜色 ----------------
def _v58_widget_get(w):
    try:
        return w.get("1.0", "end-1c") if isinstance(w, tk.Text) else w.get()
    except Exception:
        return ""

def _v58_widget_set(w, text):
    try:
        if isinstance(w, tk.Text):
            w.delete("1.0", "end"); w.insert("1.0", text)
        else:
            w.delete(0, "end"); w.insert(0, text)
    except Exception:
        pass

def _v58_word_spans(s):
    return [(m.group(0), m.start(), m.end()) for m in _re_v58.finditer(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))]

def _v58_draw_feedback(frame, results, target_words):
    for ch in frame.winfo_children():
        try: ch.destroy()
        except Exception: pass
    if not results:
        for _ in target_words:
            tk.Label(frame, text="—", bg=V58_BG, fg=V58_MUTED, font=("Microsoft YaHei UI", 8)).pack(side="left", padx=2)
        return
    for r in results:
        text = f"{r.get('pos')}:{r.get('answer') or r.get('target') or '∅'}"
        tk.Label(frame, text=text, bg=V58_BG, fg=r.get("color", V58_INPUT), font=("Microsoft YaHei UI", 8, "bold")).pack(side="left", padx=2)

def _v58_set_line(item, color):
    try:
        item["line"].delete("all")
        item["line"].create_line(2, 4, item.get("w", 120)-2, 4, fill=color, width=3)
    except Exception:
        pass

def _v58_tag_entry(self, item, final=False):
    w = item["entry"]
    raw = _v58_widget_get(w)
    norm = _v58_norm(raw, keep_trailing=raw.endswith(" ") and not final)
    if norm != raw:
        _v58_widget_set(w, norm)
        raw = norm
    target_words = _v58_tokens(item["target"])
    spans = _v58_word_spans(raw)
    words = [x[0] for x in spans]
    exact = len(words) == len(target_words) and " ".join(words).lower() == " ".join(target_words).lower()
    try:
        for tag, color in [("v58_input", V58_INPUT), ("v58_ok", V58_OK), ("v58_bad", V58_BAD)]:
            w.tag_configure(tag, foreground=color)
            w.tag_remove(tag, "1.0", "end")
    except Exception:
        pass
    completed = len(spans) if raw.endswith(" ") else max(0, len(spans)-1)
    if exact: completed = len(spans)
    results = []
    for i, (word, a, b) in enumerate(spans):
        tw = target_words[i] if i < len(target_words) else ""
        if i < len(target_words) and (exact or (i < completed and word.lower() == tw.lower())):
            tag, color, typ = "v58_ok", V58_OK, "正确"
        elif final:
            tag, color, typ = ("v58_ok", V58_OK, "正确") if i < len(target_words) and word.lower() == tw.lower() else ("v58_bad", V58_BAD, "错误")
        else:
            tag, color, typ = "v58_input", V58_INPUT, "输入中"
        try: w.tag_add(tag, f"1.0+{a}c", f"1.0+{b}c")
        except Exception: pass
        results.append({"pos": i+1, "answer": word, "target": tw, "type": typ, "color": color})
    if final and len(spans) < len(target_words):
        for j in range(len(spans), len(target_words)):
            results.append({"pos": j+1, "answer": "", "target": target_words[j], "type": "缺词", "color": V58_BAD})
    _v58_set_line(item, V58_OK if exact else V58_BAD if final else V58_INPUT)
    _v58_draw_feedback(item["feedback"], results, target_words)
    return exact, results

def _v58_live_entry(self, item):
    ok, results = _v58_tag_entry(self, item, final=False)
    if ok:
        try: _v46_status(self, "✅ 当前语块全部正确。", ok=True)
        except Exception: pass
    else:
        correct = [r["target"] for r in results if r.get("type") == "正确"]
        try:
            if correct:
                _v46_status(self, "已确认正确：" + " / ".join(correct), ok=True)
            else:
                _v46_status(self, "紫色=输入中；绿色=已完成且正确；红色=Space/Enter最终错误。")
        except Exception:
            pass
    return ok

def _v58_final_entry(self, item):
    ok, results = _v58_tag_entry(self, item, final=True)
    if ok:
        try: _v46_beep(self, "ok")
        except Exception: pass
        try: _v46_status(self, "✅ 当前语块正确。", ok=True)
        except Exception: pass
        return True
    try: _v46_beep(self, "bad")
    except Exception: pass
    wrong = [r for r in results if r.get("type") != "正确"]
    head = "全错：" if len(wrong) == len(results) else "错误部分："
    msg = head + "；".join([f"第{r['pos']}词 {r['type']}：输入[{r.get('answer') or '空'}] / 应为[{r.get('target') or '空'}]" for r in wrong[:8]])
    try: _v46_status(self, "❌ " + msg, bad=True)
    except Exception: pass
    return False

def _v58_space_entry(self, item):
    text = _v58_norm(_v58_widget_get(item["entry"]), keep_trailing=False)
    words = _v58_tokens(text)
    target_words = _v58_tokens(item["target"])
    if not words: return "break"
    if len(words) >= len(target_words):
        _v58_widget_set(item["entry"], text)
        ok = _v58_final_entry(self, item)
        if ok and getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get() == "拆分播放":
            m = _v58_current_material(self)
            chunks = _v58_get_chunks(self)
            ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
            if isinstance(m, dict) and ci + 1 < len(chunks):
                m["_v46_chunk_index"] = ci + 1
                self.after(180, lambda: (_v58_render_learning_area(self), _v58_play_current(self)))
            elif getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
                self.after(260, lambda: _v46_next(self))
        return "break"
    _v58_widget_set(item["entry"], text + " ")
    _v58_live_entry(self, item)
    return "break"

def _v58_submit_all(self):
    ok = True
    for it in getattr(self, "dict_v46_entries", []) or []:
        ok = _v58_final_entry(self, it) and ok
    if ok and getattr(self, "dict_v46_entries", None):
        try: _v46_beep(self, "sentence")
        except Exception: pass
        m = _v58_current_material(self)
        if isinstance(m, dict): m["status"] = "correct"
        try: _v46_status(self, "✅ 当前句/全部语块正确。", ok=True)
        except Exception: pass
        if getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get() == "整句播放" and getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get():
            self.after(450, lambda: _v46_next(self))
    return ok

# ---------------- 播放规则 ----------------
def _v58_audio_remaining(self):
    return float(getattr(self, "_v58_audio_until", 0.0) or 0.0) - _time_v58.time()

def _v58_est_dur(text):
    return max(0.7, min(14.0, 0.36 * max(1, len(_v58_tokens(text))) + 0.45))

def _v58_speak_text(self, text, mode="chunk"):
    text = _v58_norm(text)
    if not text: return
    if _v58_current_material(self) is None:
        try: _v46_status(self, "当前素材池为空或没有选中素材，不播放旧素材。", bad=True)
        except Exception: pass
        return
    remain = _v58_audio_remaining(self)
    cur_mode = getattr(self, "_v58_audio_mode", "")
    if remain > 0:
        if cur_mode == "sentence":
            try: _v46_status(self, "整句播放中：重复语块/整句播放命令全部忽略。")
            except Exception: pass
            return
        if cur_mode == "chunk":
            if remain > 0.1:
                try: _v46_status(self, "语块播放中：距离结束 >0.1s，重复命令忽略。")
                except Exception: pass
                return
            if getattr(self, "_v58_audio_queued", False):
                try: _v46_status(self, "语块播放末尾已排队一次，不累计。")
                except Exception: pass
                return
            self._v58_audio_queued = True
            self.after(max(20, int(remain*1000)+20), lambda: _v58_speak_text(self, text, mode))
            return
    self._v58_audio_mode = mode
    self._v58_audio_queued = False
    self._v58_audio_until = _time_v58.time() + _v58_est_dur(text)
    for fn in ("_v45_speak_edge_api", "_v44_speak_text", "_v40_speak_text"):
        if fn in globals():
            try: return globals()[fn](self, text)
            except Exception: pass
    try: self.bell()
    except Exception: pass

def _v58_play_current(self):
    m = _v58_current_material(self)
    if not m:
        try: _v46_status(self, "当前素材池为空或没有选中素材。", bad=True)
        except Exception: pass
        return
    text = _v58_item_text(m)
    mode = "sentence"
    if getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get() == "拆分播放":
        chunks = _v58_get_chunks(self)
        ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
        if chunks:
            text = chunks[max(0, min(ci, len(chunks)-1))]["text"]
        mode = "chunk"
    _v58_speak_text(self, text, mode=mode)

# ---------------- 渲染学习区 ----------------
def _v58_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in parent.winfo_children():
        try: ch.destroy()
        except Exception: pass
    m = _v58_current_material(self)
    if not m:
        tk.Label(parent, text="当前分类没有素材；请在左侧选择/导入资源", bg=V58_BG, fg=V58_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return
    chunks = _v58_get_chunks(self)
    show_cn = bool(getattr(self, "dictation_show_cn_v30", tk.BooleanVar(value=False)).get())
    zh = _v58_item_zh(m) or "中文翻译/提示未加载"
    if show_cn:
        tk.Label(parent, text=zh, bg=V58_BG, fg=V58_TEXT, font=("Microsoft YaHei UI", 22, "bold"), wraplength=1080, justify="center").pack(pady=(24, 12))
    else:
        tk.Label(parent, text="盲听模式：中文翻译和提示已隐藏", bg=V58_BG, fg=V58_MUTED, font=("Microsoft YaHei UI", 18, "bold")).pack(pady=(24, 12))
    controls = tk.Frame(parent, bg=V58_BG); controls.pack(pady=(2, 18))
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    cb = ttk.Combobox(controls, textvariable=self.dict_play_mode_v46, values=["整句播放","拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=5)
    ttk.Button(controls, text="加载台词音频播放", command=lambda: _v58_play_current(self)).pack(side="left", padx=5)
    if "_v56_play_current_video" in globals():
        ttk.Button(controls, text="加载台词视频播放", command=lambda: _v56_play_current_video(self)).pack(side="left", padx=5)
    ttk.Button(controls, text="跳过当前块", command=lambda: _v46_skip_current_chunk(self)).pack(side="left", padx=5)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    ttk.Checkbutton(controls, text="自动跳转下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=8)
    cb.bind("<<ComboboxSelected>>", lambda e: _v58_render_learning_area(self))

    mode = getattr(self, "dict_play_mode_v46", tk.StringVar(value="整句播放")).get()
    ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
    ci = max(0, min(ci, len(chunks)-1)) if chunks else 0
    show_chunks = [chunks[ci]] if mode == "拆分播放" and chunks else chunks
    line = tk.Frame(parent, bg=V58_BG); line.pack(anchor="center", pady=(20, 8))
    self.dict_v46_entries = []
    for n, ch in enumerate(show_chunks):
        tx, role = ch.get("text",""), ch.get("role") or _v58_role(ch.get("text",""))
        cell = tk.Frame(line, bg=V58_BG); cell.pack(side="left", padx=12, pady=6)
        width = max(8, min(38, len(tx)+2))
        ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V58_BG, fg=V58_INPUT, insertbackground=V58_INPUT, relief="flat", bd=0, font=("Consolas", 20, "bold"), undo=False)
        ent.pack()
        cw = max(96, width*15)
        cv = tk.Canvas(cell, width=cw, height=8, bg=V58_BG, highlightthickness=0); cv.pack()
        cv.create_line(2,4,cw-2,4, fill=V58_INPUT if n == 0 else V58_LINE, width=3)
        tk.Label(cell, text=role, bg=V58_BG, fg=V58_MUTED, font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
        fb = tk.Frame(cell, bg=V58_BG); fb.pack(pady=(6,0))
        _v58_draw_feedback(fb, [], _v58_tokens(tx))
        item = {"idx": n, "target": tx, "role": role, "entry": ent, "line": cv, "w": cw, "feedback": fb}
        self.dict_v46_entries.append(item)
        ent.bind("<KeyRelease>", lambda e, it=item: _v58_live_entry(self, it))
        ent.bind("<space>", lambda e, it=item: _v58_space_entry(self, it))
        ent.bind("<Return>", lambda e: (_v58_submit_all(self), "break"))
    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    try: _v46_status(self, "输入规则：一个单词后按 Space；紫=输入中，绿=正确，红=最终错误；错误提示保留。")
    except Exception: pass

# ---------------- 资源扫描 / 下载 ----------------
def _v58_safe_name(s, n=80):
    s = _re_v58.sub(r'[\\/:*?"<>|]+', "_", str(s or "").strip())
    s = _re_v58.sub(r"\s+", " ", s)
    return (s[:n] or "untitled").strip()

def _v58_pool_candidates(self):
    pool = []
    for name in ("pool", "selection_pool", "selected_pool", "selected_clips", "pool_items"):
        try:
            v = getattr(self, name, None)
            if isinstance(v, (list, tuple)) and v:
                pool.extend(list(v))
        except Exception: pass
    # 轻量导入后的在线素材也作为候选
    try:
        for m in getattr(self, "dictation_materials_v30", []) or []:
            if isinstance(m, dict) and _v58_bucket(m) == "在线":
                pool.append(m)
    except Exception: pass
    # 去重
    seen, out = set(), []
    for c in pool:
        key = str(id(c))
        if isinstance(c, dict):
            key = str(c.get("clip_id") or c.get("video_url") or c.get("url") or c.get("text") or id(c))
        else:
            key = str(getattr(c, "clip_id", "") or getattr(c, "video_url", "") or getattr(c, "text", "") or id(c))
        if key not in seen:
            seen.add(key); out.append(c)
    return out

def _v58_field(obj, names):
    if isinstance(obj, dict):
        for n in names:
            if obj.get(n): return str(obj.get(n))
        for n in ("clip", "item", "resource_meta"):
            if obj.get(n):
                v = _v58_field(obj.get(n), names)
                if v: return v
    for n in names:
        try:
            v = getattr(obj, n, None)
            if v: return str(v)
        except Exception: pass
    return ""

def _v58_translate(self, text):
    text = _v58_norm(text)
    if not text: return ""
    # Google -> 百度 -> OPUS
    for name, args in [
        ("_google_translate_v19", (text, "en", "zh")),
        ("_google_translate", (text, "en", "zh")),
        ("_baidu_translate_v18", (text,)),
        ("_baidu_translate_v19", (text, "en", "zh")),
        ("_opus_translate_v19", (text, "en", "zh")),
    ]:
        fn = globals().get(name) or getattr(self, name, None)
        if not callable(fn): continue
        try:
            z = fn(self, *args) if name in globals() and getattr(fn, "__self__", None) is None else fn(*args)
            z = _v58_norm(z)
            if z and z.lower() != text.lower():
                return z
        except Exception as e:
            try: self.log(f"V58翻译 {name} 失败：{type(e).__name__}: {e}", "warn")
            except Exception: pass
    return ""

def _v58_pp_dir(self):
    try:
        if hasattr(self, "v54_resource_root_var") and self.v54_resource_root_var.get():
            root = _Path_v58(self.v54_resource_root_var.get())
        elif hasattr(self, "resource_hub_root_var_v50") and self.resource_hub_root_var_v50.get():
            root = _Path_v58(self.resource_hub_root_var_v50.get())
        else:
            root = _Path_v58.cwd() / "playphrase_resource_hub_v58"
    except Exception:
        root = _Path_v58.cwd() / "playphrase_resource_hub_v58"
    d = root / "dictation" / "本地视频字幕" / V58_PP_FOLDER
    d.mkdir(parents=True, exist_ok=True)
    return d

def _v58_download_one(self, clip, i, target, session=None):
    text = _v58_field(clip, ("text","en","line","sentence","phrase","subtitle","title")) or f"clip_{i}"
    zh = _v58_field(clip, ("zh","cn","translation","chinese"))
    local = _v58_field(clip, ("local_path","media_path","video_path","cached_path","path","file"))
    url = _v58_field(clip, ("video_url","url","remote_url","source_url"))
    dest = None

    if local and _Path_v58(local).exists() and _Path_v58(local).suffix.lower() in V58_VIDEO_EXTS:
        src = _Path_v58(local)
        dest = target / f"{i:04d}_{_v58_safe_name(text, 48)}{src.suffix or '.mp4'}"
        if not dest.exists():
            _shutil_v58.copy2(src, dest)

    if dest is None or not dest.exists():
        try:
            cache = getattr(self, "cache", None)
            if cache is not None and not isinstance(clip, dict):
                sess = session
                if sess is None:
                    try: sess = self._active_search_service().session
                    except Exception: sess = None
                if sess is not None:
                    p = cache.ensure_cached(clip, sess, getattr(self, "ffmpeg", None))
                    if p and _Path_v58(p).exists():
                        src = _Path_v58(p)
                        dest = target / f"{i:04d}_{_v58_safe_name(text, 48)}{src.suffix or '.mp4'}"
                        if not dest.exists():
                            _shutil_v58.copy2(src, dest)
        except Exception as e:
            _v58_log(self, f"第{i}条 ClipCache 下载失败：{type(e).__name__}: {e}", "warn")

    if (dest is None or not dest.exists()) and url:
        try:
            import requests
            sess = session or requests.Session()
            sess.headers.update({"user-agent":"Mozilla/5.0", "referer":"https://www.playphrase.me/", "origin":"https://www.playphrase.me"})
            ext = _Path_v58(url.split("?")[0]).suffix.lower()
            if ext not in V58_VIDEO_EXTS: ext = ".mp4"
            dest = target / f"{i:04d}_{_v58_safe_name(text, 48)}{ext}"
            tmp = dest.with_suffix(dest.suffix + ".tmp")
            with sess.get(url, stream=True, timeout=90, allow_redirects=True, headers={"Range":"bytes=0-"}) as r:
                ct = (r.headers.get("content-type") or "").lower()
                if r.status_code in (200,206) and "text/html" not in ct and "json" not in ct:
                    with open(tmp, "wb") as f:
                        for chunk in r.iter_content(1024*256):
                            if chunk: f.write(chunk)
                    if tmp.exists() and tmp.stat().st_size > 8192:
                        tmp.replace(dest)
        except Exception as e:
            _v58_log(self, f"第{i}条 URL 下载失败：{type(e).__name__}: {e}", "warn")

    if dest is None or not dest.exists() or dest.stat().st_size <= 8192:
        _v58_log(self, f"第{i}条未下载成功：text={text[:50]} url={url[:70]} local={local}", "warn")
        return None

    if not zh:
        zh = _v58_translate(self, text)
    sub = dest.with_suffix(".txt")
    try: sub.write_text(text + ("\n" + zh if zh else "") + "\n", "utf-8")
    except Exception: pass
    return {
        "text": text, "zh": zh, "title": dest.name,
        "local_path": str(dest), "media_path": str(dest), "video_path": str(dest),
        "subtitle_path": str(sub), "source_type": "local_video_subtitle", "kind": "video",
        "top": "本地视频字幕", "folder": V58_PP_FOLDER, "path": str(dest),
        "name": dest.name, "line_count": 1, "status": "PlayPhrase本地视频+字幕"
    }

def _v58_download_pool_to_local_async(self):
    pool = _v58_pool_candidates(self)
    if not pool:
        try: messagebox.showwarning("精选池为空", "没有可下载的精选池/在线素材。")
        except Exception: pass
        return
    target = _v58_pp_dir(self)
    try: _v46_status(self, f"后台下载精选池视频+字幕：{target}")
    except Exception: pass

    def worker():
        records, ok = [], 0
        session = None
        try: session = self._active_search_service().session
        except Exception: session = None
        for i, clip in enumerate(pool, 1):
            rec = _v58_download_one(self, clip, i, target, session=session)
            if rec:
                records.append(rec); ok += 1
            if i % 3 == 0:
                try: self.after(0, lambda n=i,k=ok: _v46_status(self, f"下载中：{k}/{n}"))
                except Exception: pass
        def done():
            if records:
                old = getattr(self, "dictation_materials_v30", []) or []
                old.extend(records)
                self.dictation_materials_v30 = old
                try: self.dict_items_v33 = old
                except Exception: pass
                _v58_refresh_material_tree(self)
            try: _v46_status(self, f"精选池下载/复制完成：{ok}/{len(pool)}；目录：{target}", ok=ok>0, bad=ok==0)
            except Exception: pass
        try: self.after(0, done)
        except Exception: pass
    _threading_v58.Thread(target=worker, daemon=True).start()

