    ttk.Button(b1, text="下载精选池到本地", command=lambda: _v58_download_pool_to_local_async(self) if "_v58_download_pool_to_local_async" in globals() else None).pack(side="left", padx=2)

    b2 = tk.Frame(left, bg=V61_PANEL)
    b2.pack(fill="x", padx=8, pady=2)
