    ttk.Button(b2, text="添加文本路径", command=lambda: _v59_add_text_path_for_training(self) if "_v59_add_text_path_for_training" in globals() else None).pack(side="left", padx=2)

    b3 = tk.Frame(left, bg=V61_PANEL)
