    ttk.Button(b3, text="刷新资源目录", command=lambda: _v60_sync_hub_to_dictation(self) if "_v60_sync_hub_to_dictation" in globals() else _v61_refresh_material_tree(self)).pack(side="left", padx=2)
    ttk.Button(b3, text="清空", command=getattr(self, "_dictation_clear_materials_v30", lambda: None)).pack(side="left", padx=2)

