def _v63_cfg_path(self):
    try:
        root = Path.cwd()
    except Exception:
        root = _Path_v63(".")
    return root / "pp_studio_v63_settings.json"

def _v63_load_cfg(self):
    if hasattr(self, "v63_cfg") and isinstance(self.v63_cfg, dict):
        return self.v63_cfg
    cfg = {
        "theme_name": "our theme",
        "theme": dict(V63_THEME_PRESETS["our theme"]),
        "paths": {
            "resource_root": str(_Path_v63.cwd() / "playphrase_resource_hub_v63"),
            "output_root": str(_Path_v63.cwd() / "playphrase_output"),
            "cache_root": str(_Path_v63.cwd() / "clip_cache"),
            "dictionary_root": str(_Path_v63.cwd() / "dictionaries"),
        },
        "display": {
            "key_tips": True,
            "out_of_focus_warning": False,
            "caps_lock_warning": True,
            "left_material_pool": True,
            "right_hint_box": True,
            "bottom_buttons": True,
            "top_toolbar": True,
        },
        "caret": {
            "smooth": "medium",
            "style": "bar",
            "pace_caret": False,
            "pace_mode": "off",
            "pace_value": 100,
            "blink": True,
            "width": 2,
        },
        "sound": {
            "volume": 0.8,
            "key_sound": "typewriter",
            "error_sound": "missed punch",
            "correct_sound": "ding",
            "sentence_sound": "success",
            "key_letters": True,
            "key_digits": False,
            "key_symbols": False,
            "key_numpad": False,
            "key_ctrl": False,
            "key_space": False,
            "key_enter": False,
            "scope_dictation_recite": True,
            "scope_other_tabs": False,
        },
    }
    try:
        fp = _v63_cfg_path(self)
        if fp.exists():
            data = _json_v63.loads(fp.read_text("utf-8"))
            def merge(a, b):
                for k, v in b.items():
                    if isinstance(v, dict) and isinstance(a.get(k), dict):
                        merge(a[k], v)
                    else:
                        a[k] = v
            merge(cfg, data)
    except Exception:
        pass
    self.v63_cfg = cfg
    return cfg

def _v63_save_cfg(self):
    cfg = _v63_load_cfg(self)
    try:
        _v63_cfg_path(self).write_text(_json_v63.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
    except Exception as e:
        try: self.log(f"V63设置保存失败：{type(e).__name__}: {e}", "warn")
        except Exception: pass

def _v63_apply_theme(self, theme=None):
    cfg = _v63_load_cfg(self)
    theme = theme or cfg.get("theme") or V63_THEME_PRESETS["our theme"]
    cfg["theme"] = dict(theme)
    try:
        global V62_BG, V62_PANEL, V62_TEXT, V62_MUTED, V62_INPUT, V62_OK, V62_BAD, V62_LINE
        V62_BG = theme.get("background", V62_BG)
        V62_PANEL = theme.get("main", V62_PANEL)
        V62_TEXT = theme.get("text", V62_TEXT)
        V62_MUTED = theme.get("sub_alt", V62_MUTED)
        V62_INPUT = theme.get("caret", V62_INPUT)
        V62_BAD = theme.get("error", V62_BAD)
        V62_LINE = theme.get("sub", V62_LINE)
    except Exception:
        pass
    def walk(w):
        try:
            cls = w.winfo_class()
            if cls in ("Frame", "TFrame", "Labelframe"):
                try: w.configure(bg=theme.get("background"))
                except Exception: pass
            elif cls in ("Label",):
                try: w.configure(bg=theme.get("background"), fg=theme.get("text"))
                except Exception: pass
            elif cls in ("Text", "Entry"):
                try: w.configure(bg=theme.get("main"), fg=theme.get("text"), insertbackground=theme.get("caret"))
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in w.winfo_children():
                walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

def _v63_open_path(path):
    p = _Path_v63(str(path)).expanduser()
    try: p.mkdir(parents=True, exist_ok=True)
    except Exception: pass
    try:
        if sys.platform.startswith("win"):
            _os_v63.startfile(str(p))
        elif sys.platform == "darwin":
            subprocess.Popen(["open", str(p)])
        else:
            subprocess.Popen(["xdg-open", str(p)])
    except Exception:
        pass

def _v63_apply_display(self):
    cfg = _v63_load_cfg(self)
    disp = cfg.get("display", {})
    def show_hide(obj, show):
        try:
            if show:
                obj.pack(fill="both", expand=True) if not obj.winfo_ismapped() else None
            else:
                obj.pack_forget()
        except Exception:
            try:
                if show: obj.grid()
                else: obj.grid_remove()
            except Exception: pass
    try:
        if hasattr(self, "dictation_left_panel_v32"):
            if disp.get("left_material_pool", True):
                self.dictation_left_panel_v32.pack(side="left", fill="both", expand=False)
            else:
                self.dictation_left_panel_v32.pack_forget()
    except Exception: pass
    try:
        if hasattr(self, "dict_v62_side_label"):
            parent = self.dict_v62_side_label.master
            if disp.get("right_hint_box", True):
                parent.place(relx=1.0, x=-18, y=60, anchor="ne", width=330, height=165)
            else:
                parent.place_forget()
    except Exception: pass
    try:
        if hasattr(self, "dict_v46_bottom_buttons"):
            for b in self.dict_v46_bottom_buttons.values():
                if disp.get("bottom_buttons", True):
                    b.pack(side="left", padx=4, pady=3)
                else:
                    b.pack_forget()
    except Exception: pass

def _v63_apply_caret_settings(self):
    cfg = _v63_load_cfg(self).get("caret", {})
    theme = _v63_load_cfg(self).get("theme", {})
    insertwidth = int(cfg.get("width", 2) or 2)
    blink = bool(cfg.get("blink", True))
    color = theme.get("caret", "#8B5CF6")
    def walk(w):
        try:
            if isinstance(w, tk.Text) or isinstance(w, tk.Entry):
                w.configure(insertwidth=insertwidth, insertbackground=color, insertofftime=(300 if blink else 0), insertontime=(600 if blink else 0))
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

# ---------------- Ctrl+H 六级提示逻辑 ----------------
def _v63_tokens(s):
    return _re_v63.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v63_clean_word(w):
    toks = _v63_tokens(w)
    return toks[0].lower() if toks else ""

def _v63_focused_hint_word(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    focus = None
    try: focus = self.focus_get()
    except Exception: pass
    chosen = None
    for it in entries:
        try:
            if str(focus) == str(it.get("entry")):
                chosen = it
                break
        except Exception:
            pass
    if chosen is None and entries:
        chosen = entries[0]
    if not chosen:
        return "", 0, None
    target_words = _v63_tokens(chosen.get("target", ""))
    if not target_words:
        return "", 0, chosen
    try:
        raw = chosen["entry"].get("1.0", "end-1c")
    except Exception:
        raw = ""
    typed = _v63_tokens(raw)
    if not typed:
        idx = 0
    elif raw.endswith(" "):
        idx = min(len(typed), len(target_words) - 1)
    else:
        idx = min(max(0, len(typed) - 1), len(target_words) - 1)
    return target_words[idx], idx, chosen

def _v63_arpa_to_ipa(phones):
    out = []
    for p in str(phones or "").split():
        base = _re_v63.sub(r"\d", "", p)
        stress = _re_v63.search(r"\d", p)
        ipa = V63_ARPA_TO_IPA.get(base, base.lower())
        if stress and stress.group(0) == "1":
            ipa = "ˈ" + ipa
        elif stress and stress.group(0) == "2":
            ipa = "ˌ" + ipa
        out.append(ipa)
    s = "".join(out)
    s = s.replace("ˈ", " ˈ").replace("ˌ", " ˌ").strip()
    return "/" + s + "/" if s else ""

def _v63_ipa(word):
    w = _v63_clean_word(word)
    if not w: return "无目标词"
    if w in V63_WORD_LEXICON and V63_WORD_LEXICON[w].get("ipa"):
        return V63_WORD_LEXICON[w]["ipa"]
    try:
        import pronouncing
        phones = pronouncing.phones_for_word(w)
        if phones:
            return _v63_arpa_to_ipa(phones[0])
    except Exception:
        pass
    return "本地未检索到美式音标；可在词典库补充。"

def _v63_homophones(word):
    w = _v63_clean_word(word)
    if not w: return []
    if w in V63_WORD_LEXICON:
        vals = V63_WORD_LEXICON[w].get("homophones") or []
        if vals: return vals
    try:
        import pronouncing
        phones = pronouncing.phones_for_word(w)
        if phones:
            res = pronouncing.search("^" + phones[0] + "$")
            return [x for x in res if x.lower() != w][:12]
    except Exception:
        pass
    return []

def _v63_wordnet(word):
    w = _v63_clean_word(word)
    syn, ant, defs = set(), set(), []
    try:
        from nltk.corpus import wordnet as wn
        synsets = wn.synsets(w)
        for ss in synsets[:5]:
            if ss.definition():
                defs.append(ss.definition())
            for lemma in ss.lemmas():
                name = lemma.name().replace("_", " ")
                if name.lower() != w:
                    syn.add(name)
                for a in lemma.antonyms():
                    ant.add(a.name().replace("_", " "))
    except Exception:
        pass
    return sorted(syn)[:10], sorted(ant)[:10], defs[:3]

def _v63_syn_ant(word):
    w = _v63_clean_word(word)
    syn = list(V63_WORD_LEXICON.get(w, {}).get("syn") or [])
    ant = list(V63_WORD_LEXICON.get(w, {}).get("ant") or [])
    s2, a2, _ = _v63_wordnet(w)
    for x in s2:
        if x not in syn: syn.append(x)
    for x in a2:
        if x not in ant: ant.append(x)
    return syn[:10], ant[:10]

def _v63_definition(word):
    w = _v63_clean_word(word)
    if w in V63_WORD_LEXICON and V63_WORD_LEXICON[w].get("def"):
        return V63_WORD_LEXICON[w]["def"]
    _, _, defs = _v63_wordnet(w)
    if defs:
        return defs[0]
    return "No local English definition found. You can add this word to the local dictionary."

def _v63_homographs(word):
    w = _v63_clean_word(word)
    vals = V63_WORD_LEXICON.get(w, {}).get("homographs") or []
    if vals: return vals
    try:
        import pronouncing
        phones = pronouncing.phones_for_word(w)
        if len(set(phones)) >= 2:
            return ["multiple pronunciations: " + "; ".join(phones[:4])]
    except Exception:
        pass
    return []

def _v63_show_hint(self):
    word, idx, item = _v63_focused_hint_word(self)
    if not word:
        _v63_set_hint_text(self, "提示：当前没有可提示的目标单词。", "bad")
        return "break"
    m = _v62_current_material(self) if "_v62_current_material" in globals() else None
    mat_idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    chunk_idx = 0
    try:
        chunk_idx = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
    except Exception:
        chunk_idx = 0
    key = f"{mat_idx}:{chunk_idx}:{idx}:{word.lower()}"
    if not hasattr(self, "dict_v63_hint_stage"):
        self.dict_v63_hint_stage = {}
    stage = int(self.dict_v63_hint_stage.get(key, 0) or 0) + 1
    if stage > 6:
        stage = 1
    self.dict_v63_hint_stage[key] = stage

    w = _v63_clean_word(word)
    if stage == 1:
        msg = f"① 音标提示｜{word}：AmE {_v63_ipa(w)}"
    elif stage == 2:
        hs = _v63_homophones(w)
        msg = f"② 同音词提示｜{word}：" + (" / ".join(hs) if hs else "本地未找到可靠同音词。")
    elif stage == 3:
        syn, ant = _v63_syn_ant(w)
        msg = f"③ 近反义词提示｜{word}：近义词：{', '.join(syn) if syn else '暂无'}；反义词：{', '.join(ant) if ant else '暂无'}"
    elif stage == 4:
        msg = f"④ 首尾字母提示｜{word}：{w[:1]}…{w[-1:] if len(w)>1 else w[:1]}，共 {len(w)} 个字母。"
    elif stage == 5:
        msg = f"⑤ 英文释义提示｜{word}：{_v63_definition(w)}"
    else:
        hg = _v63_homographs(w)
        msg = f"⑥ 同形词/答案提示｜{word}：" + ("；".join(hg) if hg else f"没有可靠同形词，正确答案：{word}")
    _v63_set_hint_text(self, msg, "hint")
    return "break"

def _v63_set_hint_text(self, msg, level="hint"):
    color = "#38BDF8" if level == "hint" else V63_BAD
    try:
        if not hasattr(self, "dict_v63_hint_var"):
            self.dict_v63_hint_var = tk.StringVar(value="")
        self.dict_v63_hint_var.set(msg)
        if hasattr(self, "dict_v63_hint_label"):
            self.dict_v63_hint_label.configure(fg=color)
    except Exception:
        pass
    try:
        if "_v62_set_feedback" in globals():
            _v62_set_feedback(self, msg, "info", auto_clear=False)
    except Exception:
        pass

def _v63_hide_difficulty_widgets(self):
    bad_words = ("难度", "difficulty", "提示次数已达", "difficulty/hint")
    def walk(w):
        try:
            text = str(w.cget("text")).lower()
            if any(x.lower() in text for x in bad_words):
                try: w.pack_forget()
                except Exception: pass
                try: w.grid_remove()
                except Exception: pass
                try: w.place_forget()
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

# ---------------- 设置中心 ----------------
def _v63_row(parent, title, desc=""):
    row = tk.Frame(parent, bg=V63_PANEL)
    row.pack(fill="x", pady=8)
    left = tk.Frame(row, bg=V63_PANEL)
    left.pack(side="left", fill="x", expand=True)
    tk.Label(left, text=title, bg=V63_PANEL, fg=V63_TEXT, font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w")
    if desc:
        tk.Label(left, text=desc, bg=V63_PANEL, fg=V63_MUTED, wraplength=680, justify="left").pack(anchor="w")
    return row

def _v63_setting_check(parent, text, var):
    cb = ttk.Checkbutton(parent, text=text, variable=var)
    cb.pack(side="left", padx=8, pady=4)
    return cb

def _v63_open_settings_panel(self):
    cfg = _v63_load_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置中心 V63｜主题 / 音效 / 路径 / 显示隐藏 / 光标特效")
    win.geometry("1280x820")
    win.configure(bg=cfg["theme"].get("background", V63_BG))
    outer = tk.Frame(win, bg=cfg["theme"].get("background", V63_BG))
    outer.pack(fill="both", expand=True, padx=18, pady=14)
    tk.Label(outer, text="设置中心", bg=cfg["theme"].get("background", V63_BG), fg=cfg["theme"].get("text", V63_TEXT), font=("Microsoft YaHei UI", 18, "bold")).pack(anchor="w")
    tk.Label(outer, text="音效设置、主题配色、路径、显示隐藏、光标特效全部集中在这里。难度设置已移除，Ctrl+H 提示不再受难度限制。", bg=cfg["theme"].get("background", V63_BG), fg=V63_MUTED).pack(anchor="w", pady=(2, 10))

    nb = ttk.Notebook(outer)
    nb.pack(fill="both", expand=True)
    tab_theme = tk.Frame(nb, bg=V63_PANEL)
    tab_sound = tk.Frame(nb, bg=V63_PANEL)
    tab_path = tk.Frame(nb, bg=V63_PANEL)
    tab_display = tk.Frame(nb, bg=V63_PANEL)
    tab_caret = tk.Frame(nb, bg=V63_PANEL)
    tab_hint = tk.Frame(nb, bg=V63_PANEL)
    nb.add(tab_theme, text="主题颜色")
    nb.add(tab_sound, text="音效")
    nb.add(tab_path, text="路径")
    nb.add(tab_display, text="显示/隐藏")
    nb.add(tab_caret, text="光标特效")
    nb.add(tab_hint, text="Ctrl+H提示")

    # Theme tab
    theme_canvas = tk.Canvas(tab_theme, bg=V63_PANEL, highlightthickness=0)
    theme_scroll = ttk.Scrollbar(tab_theme, orient="vertical", command=theme_canvas.yview)
    theme_canvas.configure(yscrollcommand=theme_scroll.set)
    theme_scroll.pack(side="right", fill="y")
    theme_canvas.pack(side="left", fill="both", expand=True)
    theme_inner = tk.Frame(theme_canvas, bg=V63_PANEL)
    theme_canvas.create_window((0,0), window=theme_inner, anchor="nw")
    theme_inner.bind("<Configure>", lambda e: theme_canvas.configure(scrollregion=theme_canvas.bbox("all")))

    tk.Label(theme_inner, text="预设主题", bg=V63_PANEL, fg=V63_TEXT, font=("Microsoft YaHei UI", 14, "bold")).pack(anchor="w", pady=8)
    grid = tk.Frame(theme_inner, bg=V63_PANEL); grid.pack(fill="x")
    theme_vars = {k: tk.StringVar(value=v) for k,v in cfg["theme"].items()}
    def load_theme(name):
        th = dict(V63_THEME_PRESETS[name])
        cfg["theme_name"] = name
        cfg["theme"] = th
        for k,v in th.items():
            if k in theme_vars: theme_vars[k].set(v)
        _v63_apply_theme(self, th)
        _v63_save_cfg(self)
    col = 0; row = 0
    for name, th in V63_THEME_PRESETS.items():
        b = tk.Button(grid, text=name, bg=th["main"], fg=th["caret"], relief="flat", command=lambda n=name: load_theme(n), font=("Consolas", 10, "bold"))
        b.grid(row=row, column=col, sticky="ew", padx=5, pady=5, ipadx=18, ipady=6)
        col += 1
        if col >= 4:
            col = 0; row += 1
    for i in range(4): grid.columnconfigure(i, weight=1)
    tk.Label(theme_inner, text="自定义颜色", bg=V63_PANEL, fg=V63_TEXT, font=("Microsoft YaHei UI", 14, "bold")).pack(anchor="w", pady=(18,6))
    custom = tk.Frame(theme_inner, bg=V63_PANEL); custom.pack(fill="x")
    labels = [("background","背景"),("main","主区域"),("caret","光标/高亮"),("error","错误"),("sub","辅助"),("sub_alt","辅助2"),("text","文字"),("extra_error","额外错误")]
    for i,(key,label) in enumerate(labels):
        r = tk.Frame(custom, bg=V63_PANEL)
        r.grid(row=i//2, column=i%2, sticky="ew", padx=8, pady=6)
        tk.Label(r, text=label, bg=V63_PANEL, fg=V63_TEXT, width=10, anchor="w").pack(side="left")
        e = ttk.Entry(r, textvariable=theme_vars[key], width=18)
        e.pack(side="left", padx=6)
        def pick(k=key):
            try:
                from tkinter import colorchooser
                c = colorchooser.askcolor(color=theme_vars[k].get())[1]
                if c: theme_vars[k].set(c)
            except Exception: pass
        ttk.Button(r, text="取色", command=pick).pack(side="left")
    for i in range(2): custom.columnconfigure(i, weight=1)
    def save_custom_theme():
        th = {k:v.get().strip() or cfg["theme"].get(k, "#000000") for k,v in theme_vars.items()}
        cfg["theme_name"] = "custom"
        cfg["theme"] = th
        _v63_apply_theme(self, th)
        _v63_save_cfg(self)
    ttk.Button(theme_inner, text="保存并应用自定义主题", command=save_custom_theme).pack(anchor="e", pady=14)

    # Sound tab
    sound_vars = {}
    s_cfg = cfg["sound"]
    tk.Label(tab_sound, text="音效设置", bg=V63_PANEL, fg=V63_TEXT, font=("Microsoft YaHei UI", 14, "bold")).pack(anchor="w", padx=12, pady=(12,4))
    r = _v63_row(tab_sound, "音量", "统一控制按键音、错误音、正确音、整句完成音的音量。")
    sound_vars["volume"] = tk.DoubleVar(value=float(s_cfg.get("volume", 0.8)))
    ttk.Scale(r, from_=0, to=1, variable=sound_vars["volume"]).pack(side="right", fill="x", expand=True, padx=20)
    for key, title, values in [
        ("key_sound", "按键音", ["off","click","beep","pop","typewriter","sine","square","triangle","pentatonic","rubber keys"]),
        ("error_sound", "错误音", ["off","damage","triangle","square","missed punch","pop"]),
        ("correct_sound", "正确音", ["off","ding","success","click","pop"]),
        ("sentence_sound", "句子完成音", ["off","success","ding","pentatonic"]),
    ]:
        row = _v63_row(tab_sound, title)
        sound_vars[key] = tk.StringVar(value=str(s_cfg.get(key, values[0])))
        ttk.Combobox(row, values=values, textvariable=sound_vars[key], state="readonly", width=24).pack(side="right", padx=20)
    scope = _v63_row(tab_sound, "按键音应用范围", "默认只对 26 个英文字母生效；其他按键需要显式开启。")
    for key, text in [
        ("key_letters","26个英文字母"), ("key_digits","数字"), ("key_symbols","符号"), ("key_numpad","小键盘"),
        ("key_ctrl","Ctrl"), ("key_space","Space"), ("key_enter","Enter"),
        ("scope_dictation_recite","听写/背诵"), ("scope_other_tabs","其他标签页"),
    ]:
        sound_vars[key] = tk.BooleanVar(value=bool(s_cfg.get(key, False if key!="key_letters" else True)))
        _v63_setting_check(scope, text, sound_vars[key])
    test = tk.Frame(tab_sound, bg=V63_PANEL); test.pack(fill="x", padx=12, pady=10)
    for text, kind in [("测试按键音","click"),("测试错误音","error"),("测试正确音","correct"),("测试完成音","sentence")]:
        ttk.Button(test, text=text, command=lambda k=kind: _v63_play_setting_sound(self, k)).pack(side="left", padx=6)
    def save_sound():
        for k,v in sound_vars.items():
            s_cfg[k] = v.get()
        _v63_save_cfg(self)
        _v63_patch_sound_vars(self)
