def _v63_choose_dir(var):
    d = filedialog.askdirectory()
    if d:
        var.set(d)

def _v63_play_setting_sound(self, kind):
    try:
        if kind == "click":
            if "_v54_play_sound" in globals(): return _v54_play_sound(self, "click")
            if "_v53_play_sound" in globals(): return _v53_play_sound(self, "click")
        if kind in ("error","correct","sentence"):
            if "_v54_play_sound" in globals(): return _v54_play_sound(self, kind)
            if "_v53_play_sound" in globals(): return _v53_play_sound(self, kind)
        self.bell()
    except Exception:
        pass

def _v63_patch_sound_vars(self):
    cfg = _v63_load_cfg(self).get("sound", {})
    pairs = {
        "v56_letters_var": "key_letters",
        "v56_digits_var": "key_digits",
        "v56_symbols_var": "key_symbols",
        "v56_numpad_var": "key_numpad",
        "v56_ctrl_var": "key_ctrl",
        "v56_space_var": "key_space",
        "v56_enter_var": "key_enter",
        "v56_scope_other_tabs_var": "scope_other_tabs",
    }
    for attr, key in pairs.items():
        try:
            if not hasattr(self, attr): setattr(self, attr, tk.BooleanVar(value=bool(cfg.get(key, False))))
            else: getattr(self, attr).set(bool(cfg.get(key, False)))
        except Exception: pass

def _v63_rebuild_bottom_controls(self):
    if "_v62_rebuild_bottom_controls" in globals():
        try: _v62_rebuild_bottom_controls(self)
        except Exception: pass
    # replace hint button command/text
    try:
        btns = getattr(self, "dict_v46_bottom_buttons", {})
        for txt, b in list(btns.items()):
            if "提示" in txt:
                b.configure(text="提示 Ctrl+H", command=lambda: _v63_show_hint(self))
    except Exception:
        pass

def _v63_add_hint_box_to_learning_area(self):
    # If the current render already created a right side box, add a dedicated hint line.
    try:
        parent = getattr(self, "dict_v62_side_label").master
        if hasattr(self, "dict_v63_hint_label") and str(self.dict_v63_hint_label) in [str(x) for x in parent.winfo_children()]:
            return
        tk.Label(parent, text="Ctrl+H 提示链", bg="#0f172a", fg="#38BDF8", font=("Microsoft YaHei UI", 10, "bold")).pack(anchor="w", padx=10, pady=(2,0))
        if not hasattr(self, "dict_v63_hint_var"):
            self.dict_v63_hint_var = tk.StringVar(value="")
        self.dict_v63_hint_label = tk.Label(parent, textvariable=self.dict_v63_hint_var, bg="#0f172a", fg="#38BDF8", wraplength=300, justify="left", font=("Microsoft YaHei UI", 9, "bold"))
        self.dict_v63_hint_label.pack(fill="x", padx=10, pady=(0,6))
    except Exception:
        pass

def _v63_render_learning_area(self):
    if "_v62_render_learning_area" in globals():
        _v62_render_learning_area(self)
    _v63_add_hint_box_to_learning_area(self)
    _v63_apply_caret_settings(self)

def _v63_rebuild_right_panel(self):
    if "_v62_rebuild_right_panel" in globals():
        try: _v62_rebuild_right_panel(self)
        except Exception: pass
    right = getattr(self, "dictation_right_panel_v32", None)
    if right is None: return
    # Add global settings button at top if not exists
    if getattr(self, "_v63_settings_button_added", False):
        return
    try:
        top = tk.Frame(right, bg=V63_PANEL)
        top.pack(fill="x", padx=8, pady=(4,2), before=right.winfo_children()[0] if right.winfo_children() else None)
        ttk.Button(top, text="设置中心 V63", command=lambda: _v63_open_settings_panel(self)).pack(fill="x")
        self._v63_settings_button_added = True
    except Exception:
        pass

def _v63_cleanup_buttons(self):
    def walk(w):
        try:
            txt = str(w.cget("text"))
            low = txt.lower()
            if "设置" in txt or "settings" in low or "音效设置" in txt:
                if "难度" not in txt:
                    try: w.configure(command=lambda: _v63_open_settings_panel(self))
                    except Exception: pass
            if txt.strip() in ("提示", "提示 Ctrl+H") or "Ctrl+H" in txt:
                try: w.configure(text="提示 Ctrl+H", command=lambda: _v63_show_hint(self))
                except Exception: pass
            if "难度" in txt or "difficulty" in low:
                try: w.pack_forget()
                except Exception: pass
                try: w.grid_remove()
                except Exception: pass
                try: w.place_forget()
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

# ---------------- 全局接管 ----------------
def _v63_patch_globals(self):
    globals()["_v46_show_hint"] = lambda app: _v63_show_hint(app)
    globals()["_dictation_next_hint_v30"] = lambda app: _v63_show_hint(app)
    globals()["_v38_next_hint_fallback"] = lambda app: _v63_show_hint(app)
    globals()["_v62_render_learning_area"] = _v63_render_learning_area
    globals()["_v63_open_settings_panel"] = _v63_open_settings_panel
    globals()["_v38_open_settings_center"] = lambda app: _v63_open_settings_panel(app)
    globals()["_v53_open_sound_settings"] = lambda app: _v63_open_settings_panel(app)
    globals()["_v54_open_sound_settings"] = lambda app: _v63_open_settings_panel(app)
    globals()["_v56_open_sound_settings"] = lambda app: _v63_open_settings_panel(app)
    globals()["_v62_rebuild_bottom_controls"] = _v63_rebuild_bottom_controls
    globals()["_v62_rebuild_right_panel"] = _v63_rebuild_right_panel
    try:
        self.bind_all("<Control-h>", lambda e: _v63_show_hint(self))
        self.bind_all("<Control-H>", lambda e: _v63_show_hint(self))
    except Exception:
        pass

_old_main_init_v63 = MainApp.__init__
def _main_init_v63(self):
    _old_main_init_v63(self)
    try:
        _v63_load_cfg(self)
        _v63_patch_globals(self)
        _v63_patch_sound_vars(self)
        _v63_apply_theme(self)
        _v63_apply_display(self)
        _v63_apply_caret_settings(self)
        _v63_hide_difficulty_widgets(self)
        _v63_cleanup_buttons(self)
        try: _v63_rebuild_bottom_controls(self)
        except Exception: pass
        try: _v63_rebuild_right_panel(self)
        except Exception: pass
        try:
            self.after(300, lambda: (_v63_patch_globals(self), _v63_cleanup_buttons(self), _v63_rebuild_bottom_controls(self), _v63_rebuild_right_panel(self)))
            self.after(1300, lambda: (_v63_cleanup_buttons(self), _v63_apply_display(self), _v63_apply_caret_settings(self)))
        except Exception: pass
        self.log("【V63上线】Ctrl+H 六级提示链已接管：音标/同音词/近反义词/首尾字母/英文释义/同形词或答案。", "ok")
        self.log("【V63上线】难度设置已从听写提示逻辑移除，提示次数不再受难度限制。", "ok")
        self.log("【V63上线】设置中心重构：音效、主题、路径、显示隐藏、光标特效集中管理。", "ok")
    except Exception as e:
        try: self.log(f"V63初始化失败：{type(e).__name__}: {e}", "err")
        except Exception: pass

MainApp.__init__ = _main_init_v63
APP_TITLE = "PlayPhrase Studio Clean v63 · CtrlH提示链与设置中心重构版"


# ──────────────────────────────────────────────────────────────────────
# V64：听写训练语块呈现 + 自动拆分设置 + 纯中文设置入口
# 本版落实：
# 1) 整句模式：仍按语块呈现；多个单词可共用一条横线。
# 2) 拆分模式：每个单词一条横线；横线宽度最大 8 个字符，间距压缩。
# 3) 自动拆分：只作用于“整句模式”；超长句默认拆分，其余默认不拆，用户可在设置中勾选。
# 4) 句长类型：≤8超短句，9-12短句，13-20中句，21-32长句，>32超长句。
# 5) 保留颜色逻辑：紫色输入中，绿色正确，红色最终错误。
# 6) 新增纯中文设置页：“听写自动拆分”，同时继续保留 V63 音效/主题/路径等设置。
# ──────────────────────────────────────────────────────────────────────
import re as _re_v64
import json as _json_v64
import time as _time_v64
from pathlib import Path as _Path_v64

V64_BG = globals().get("V62_BG", "#0b1220")
V64_PANEL = globals().get("V62_PANEL", "#111827")
V64_TEXT = globals().get("V62_TEXT", "#E5E7EB")
V64_MUTED = globals().get("V62_MUTED", "#94A3B8")
V64_INPUT = globals().get("V62_INPUT", "#8B5CF6")
V64_OK = globals().get("V62_OK", "#22C55E")
V64_BAD = globals().get("V62_BAD", "#EF4444")
V64_LINE = globals().get("V62_LINE", "#CBD5E1")

V64_SPLIT_LABELS = {
    "ultra_short": "超短句（≤8词）",
    "short": "短句（9-12词）",
    "medium": "中句（13-20词）",
    "long": "长句（21-32词）",
    "super_long": "超长句（32词以上）",
}

V64_PROTECTED_PHRASES = [
    "take turns", "set up", "rule out", "find out", "figure out", "come up with",
    "look for", "look after", "look up", "look into", "look forward to",
    "give up", "give in", "get up", "get out", "get over",
    "go on", "go through", "put up", "put off", "run into", "run out",
    "make sure", "make up", "take care", "take off", "take over",
    "pay attention", "break down", "bring up", "carry out", "check out",
    "work out", "show up", "pick up", "hang out", "at least", "a few",
    "a little", "no matter", "as long as", "as soon as", "in order to",
    "rather than", "even if", "even though", "so that", "such as",
]

V64_CONNECTORS = {
    "and", "but", "or", "because", "although", "though", "when", "while",
    "if", "unless", "until", "which", "that", "who", "where", "why", "how",
    "before", "after", "since", "so", "yet",
}

def _v64_tokens(s):
    return _re_v64.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v64_norm(s):
    return _re_v64.sub(r"\s+", " ", str(s or "").replace("\n", " ").replace("\t", " ")).strip()

def _v64_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or m.get("phrase") or "")
    return str(getattr(m, "text", "") or m or "")

def _v64_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or m.get("chinese") or "")
    return str(getattr(m, "zh", "") or "")

def _v64_current_material(self):
    if "_v62_current_material" in globals():
        try:
            return _v62_current_material(self)
        except Exception:
            pass
    mats = getattr(self, "dictation_materials_v30", []) or []
    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    return mats[idx] if 0 <= idx < len(mats) else None

def _v64_sentence_type_by_count(n):
    if n <= 8:
        return "ultra_short"
    if n <= 12:
        return "short"
    if n <= 20:
        return "medium"
    if n <= 32:
        return "long"
    return "super_long"

def _v64_sentence_type_cn(n):
    return V64_SPLIT_LABELS[_v64_sentence_type_by_count(n)]

def _v64_default_split_cfg():
    return {
        "ultra_short": False,
        "short": False,
        "medium": False,
        "long": False,
        "super_long": True,
    }

def _v64_cfg(self):
    # 复用 V63 设置文件，避免再生成第三套配置。
    if "_v63_load_cfg" in globals():
        try:
            cfg = _v63_load_cfg(self)
        except Exception:
            cfg = {}
    else:
        cfg = getattr(self, "v63_cfg", {}) if hasattr(self, "v63_cfg") else {}
    if not isinstance(cfg, dict):
        cfg = {}
    cfg.setdefault("dictation", {})
    cfg["dictation"].setdefault("auto_split", _v64_default_split_cfg())
    # 兜底修正：超长句必须默认 True，除非用户已经显式保存了 False
    for k, v in _v64_default_split_cfg().items():
        cfg["dictation"]["auto_split"].setdefault(k, v)
    self.v63_cfg = cfg
    return cfg

def _v64_save_cfg(self):
    if "_v63_save_cfg" in globals():
        try:
            return _v63_save_cfg(self)
        except Exception:
            pass
    try:
        (_Path_v64.cwd() / "pp_studio_v63_settings.json").write_text(_json_v64.dumps(getattr(self, "v63_cfg", {}), ensure_ascii=False, indent=2), "utf-8")
    except Exception:
        pass

def _v64_should_split_sentence(self, word_count):
    cfg = _v64_cfg(self)
    st = _v64_sentence_type_by_count(word_count)
    auto = cfg.get("dictation", {}).get("auto_split", _v64_default_split_cfg())
    return bool(auto.get(st, st == "super_long"))

def _v64_classify_word(w):
    if "_v62_classify_word" in globals():
        try:
            return _v62_classify_word(w)
        except Exception:
            pass
    low = str(w or "").lower()
    if low in {"a","an","the"}:
        return "冠词"
    if low in {"and","but","or","because","if","when","while","that","which","who"}:
        return "连接词/从句"
    if low in {"to","from","in","on","at","with","for","of","by","about"}:
        return "介词"
    if low.endswith("ly"):
        return "副词"
    if low.endswith(("ing","ed")):
        return "动词"
    return "名词"

def _v64_role(text, force_word=False):
    toks = _v64_tokens(text)
    if not toks:
        return "语块"
    if force_word or len(toks) == 1:
        return _v64_classify_word(toks[0])
    lowline = " ".join(t.lower() for t in toks)
    for ph in sorted(V64_PROTECTED_PHRASES, key=len, reverse=True):
        if _re_v64.search(r"\b" + _re_v64.escape(ph).replace(r"\ ", r"\s+") + r"\b", lowline):
            return "固定短语：" + ph
    if toks[0].lower() in V64_CONNECTORS:
        return "连接词/从句 + 语块"
    try:
        return _v62_role(text) if "_v62_role" in globals() else "语块"
    except Exception:
        return "语块"

def _v64_protect_sequence(words, lows, i):
    # 返回 (文本, 消耗词数)，保护固定短语。
    for n in (4, 3, 2):
        if i + n <= len(words) and " ".join(lows[i:i+n]) in V64_PROTECTED_PHRASES:
            return " ".join(words[i:i+n]), n
    return "", 0

def _v64_phrase_chunks(text, max_words=4):
    words = _v64_tokens(text)
    if not words:
        return []
    lows = [w.lower() for w in words]
    out = []
    buf = []
    i = 0

    def flush():
        nonlocal buf
        if buf:
            s = " ".join(buf)
            out.append({"text": s, "role": _v64_role(s), "unit": "phrase"})
            buf = []

    while i < len(words):
        lw = lows[i]

        # 连接词/从句边界：前面已有内容时，先断开；连接词归入后续语块。
        if lw in V64_CONNECTORS and buf:
            flush()
            buf = [words[i]]
            i += 1
            continue

        hit, hit_n = _v64_protect_sequence(words, lows, i)
        if hit:
            # 如果固定短语前面已有 2 个以上词，先断开，避免短语被挤到杂乱语块里。
            if buf and len(buf) >= 2:
                flush()
            buf.append(hit)
            i += hit_n
        else:
            buf.append(words[i])
            i += 1

        # 介词/连接词后可稍微延长，否则按 3-4 词控制。
        limit = max_words
        if buf and buf[0].lower() in V64_CONNECTORS:
            limit = max_words + 1
        if len(" ".join(buf).split()) >= limit:
            flush()

    flush()
    return out or [{"text": _v64_norm(text), "role": _v64_role(text), "unit": "phrase"}]

def _v64_word_chunks(text):
    chunks = []
    for w in _v64_tokens(text):
        chunks.append({"text": w, "role": _v64_role(w, force_word=True), "unit": "word"})
    return chunks

def _v64_get_chunks(self, mode=None):
    m = _v64_current_material(self)
    text = _v64_item_text(m)
    words = _v64_tokens(text)
    mode = mode or getattr(getattr(self, "dict_play_mode_v46", None), "get", lambda: "整句播放")()

    if mode == "拆分播放":
        return _v64_word_chunks(text)

    # 整句模式：始终以“语块”数据结构呈现。
    # 未勾选自动拆分时，整句作为一个大语块；勾选后拆成多个短语语块。
    should_split = _v64_should_split_sentence(self, len(words))
    if should_split:
        max_words = 3 if len(words) <= 12 else 4
        return _v64_phrase_chunks(text, max_words=max_words)
    return [{"text": _v64_norm(text), "role": "整句语块：" + _v64_sentence_type_cn(len(words)), "unit": "phrase"}]

def _v64_get_current_play_text(self):
    m = _v64_current_material(self)
    if not m:
        return ""
    mode = getattr(getattr(self, "dict_play_mode_v46", None), "get", lambda: "整句播放")()
    if mode == "拆分播放":
        chunks = _v64_get_chunks(self, mode="拆分播放")
        ci = int(m.get("_v46_chunk_index", 0)) if isinstance(m, dict) else 0
        if chunks:
            return chunks[max(0, min(ci, len(chunks)-1))]["text"]
    return _v64_item_text(m)

def _v64_play_current(self):
    text = _v64_get_current_play_text(self)
    if not text:
        try:
            _v62_set_feedback(self, "当前没有可播放素材。", "bad")
        except Exception:
            pass
        return
    if "_v62_speak_text" in globals():
        try:
            return _v62_speak_text(self, text, "sentence")
        except Exception:
            pass
    try:
        self.bell()
    except Exception:
        pass

def _v64_wget(w):
    try:
        return w.get("1.0", "end-1c") if isinstance(w, tk.Text) else w.get()
    except Exception:
        return ""

def _v64_wset(w, text):
    try:
        if isinstance(w, tk.Text):
            w.delete("1.0", "end")
            w.insert("1.0", text)
        else:
            w.delete(0, "end")
            w.insert(0, text)
    except Exception:
        pass

def _v64_width_for_chunk(text, mode):
    toks = _v64_tokens(text)
    if mode == "拆分播放":
        # 横线最大 8 个字符；长单词输入框仍可横向滚动，横线不变长。
        return max(3, min(8, len(toks[0]) + 1 if toks else 4))
    # 整句模式允许多个词共用横线，但不能无限超宽。
    return max(8, min(42, len(text) + 2))

def _v64_canvas_width(width_chars):
    return max(58, min(650, int(width_chars * 15)))

def _v64_reset_chunk_index_if_needed(self):
    m = _v64_current_material(self)
    if isinstance(m, dict):
        mode = getattr(getattr(self, "dict_play_mode_v46", None), "get", lambda: "整句播放")()
        text = _v64_item_text(m)
        key = f"{mode}:{text}:{_v64_should_split_sentence(self, len(_v64_tokens(text)))}"
        if m.get("_v64_render_key") != key:
            m["_v64_render_key"] = key
            m["_v46_chunk_index"] = 0

def _v64_set_feedback(self, msg, level="info", auto_clear=False):
    if "_v62_set_feedback" in globals():
        try:
            return _v62_set_feedback(self, msg, level, auto_clear)
        except Exception:
            pass
    try:
        if not hasattr(self, "dict_v62_bottom_var"):
            self.dict_v62_bottom_var = tk.StringVar(value="")
        self.dict_v62_bottom_var.set(msg)
    except Exception:
        pass

def _v64_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in parent.winfo_children():
        try:
            ch.destroy()
        except Exception:
            pass

    m = _v64_current_material(self)
    if not m:
        tk.Label(parent, text="当前分类没有素材；请在左侧选择或导入资源",
                 bg=V64_BG, fg=V64_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return

    _v64_reset_chunk_index_if_needed(self)

    # 右侧固定提示盒，纯中文。
    side = tk.Frame(parent, bg="#0f172a", bd=1, relief="solid")
    side.place(relx=1.0, x=-18, y=60, anchor="ne", width=360, height=190)
    tk.Label(side, text="固定提示", bg="#0f172a", fg=V64_TEXT,
             font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w", padx=10, pady=(8, 2))
    if not hasattr(self, "dict_v62_side_var"):
        self.dict_v62_side_var = tk.StringVar(value="")
    self.dict_v62_side_label = tk.Label(side, textvariable=self.dict_v62_side_var, bg="#0f172a",
                                        fg=V64_MUTED, wraplength=330, justify="left",
                                        font=("Microsoft YaHei UI", 10, "bold"))
    self.dict_v62_side_label.pack(fill="both", expand=True, padx=10, pady=(0, 8))
    # Ctrl+H 提示行
    if not hasattr(self, "dict_v63_hint_var"):
        self.dict_v63_hint_var = tk.StringVar(value="")
    tk.Label(side, text="Ctrl+H 提示", bg="#0f172a", fg="#38BDF8",
             font=("Microsoft YaHei UI", 10, "bold")).pack(anchor="w", padx=10)
    self.dict_v63_hint_label = tk.Label(side, textvariable=self.dict_v63_hint_var, bg="#0f172a",
                                        fg="#38BDF8", wraplength=330, justify="left",
                                        font=("Microsoft YaHei UI", 9, "bold"))
    self.dict_v63_hint_label.pack(fill="x", padx=10, pady=(0, 6))

    text = _v64_item_text(m)
    word_count = len(_v64_tokens(text))
    sent_type = _v64_sentence_type_cn(word_count)

    show_cn = bool(getattr(self, "dictation_show_cn_v30", tk.BooleanVar(value=False)).get())
    zh = _v64_item_zh(m) or "中文翻译或提示未加载"
    title_text = zh if show_cn else "盲听模式：中文翻译和提示已隐藏"
    tk.Label(parent, text=title_text, bg=V64_BG, fg=V64_TEXT if show_cn else V64_MUTED,
             font=("Microsoft YaHei UI", 20, "bold"), wraplength=900,
             justify="center").pack(pady=(22, 8))

    controls = tk.Frame(parent, bg=V64_BG)
    controls.pack(pady=(2, 10))
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    cb = ttk.Combobox(controls, textvariable=self.dict_play_mode_v46,
                      values=["整句播放", "拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=5)
    cb.bind("<<ComboboxSelected>>", lambda e: _v64_render_learning_area(self))
    ttk.Button(controls, text="播放当前音频", command=lambda: _v64_play_current(self)).pack(side="left", padx=5)
    if "_v56_play_current_video" in globals():
        ttk.Button(controls, text="播放当前视频", command=lambda: _v56_play_current_video(self)).pack(side="left", padx=5)
    ttk.Button(controls, text="跳过当前块", command=lambda: _v62_skip_chunk(self) if "_v62_skip_chunk" in globals() else None).pack(side="left", padx=5)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    ttk.Checkbutton(controls, text="自动跳到下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=8)

    auto_status = "已启用自动拆分" if _v64_should_split_sentence(self, word_count) else "未启用自动拆分"
    tk.Label(parent, text=f"句长：{word_count}词｜类型：{sent_type}｜整句模式：{auto_status}｜拆分模式：逐词横线",
             bg=V64_BG, fg=V64_MUTED, font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(0, 8))

    mode = self.dict_play_mode_v46.get()
    chunks = _v64_get_chunks(self, mode=mode)

    # 呈现区：自动换行，避免超长句挤出屏幕。
    board = tk.Frame(parent, bg=V64_BG)
    board.pack(anchor="center", pady=(8, 8), padx=18)
    self.dict_v46_entries = []

    max_units_per_row = 9 if mode == "拆分播放" else 4
    current_row = None
    current_units = 0
    current_chars = 0

    for n, ch in enumerate(chunks):
        tx = ch.get("text", "")
        role = ch.get("role") or _v64_role(tx, force_word=(mode == "拆分播放"))
        width = _v64_width_for_chunk(tx, mode)
        projected = current_chars + width

        if current_row is None or current_units >= max_units_per_row or projected > (72 if mode == "拆分播放" else 92):
            current_row = tk.Frame(board, bg=V64_BG)
            current_row.pack(anchor="center", pady=(7 if mode == "拆分播放" else 9))
            current_units = 0
            current_chars = 0

        cell = tk.Frame(current_row, bg=V64_BG)
        cell.pack(side="left", padx=(5 if mode == "拆分播放" else 10), pady=3)

        ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V64_BG, fg=V64_INPUT,
                      insertbackground=V64_INPUT, relief="flat", bd=0,
                      font=("Consolas", 19 if mode == "拆分播放" else 20, "bold"), undo=False)
        ent.pack()
        cw = _v64_canvas_width(width)
        cv = tk.Canvas(cell, width=cw, height=8, bg=V64_BG, highlightthickness=0)
        cv.pack()
        cv.create_line(2, 4, cw - 2, 4, fill=V64_INPUT if n == 0 else V64_LINE, width=3)

        tk.Label(cell, text=role, bg=V64_BG, fg=V64_MUTED,
                 font=("Microsoft YaHei UI", 8 if mode == "拆分播放" else 9, "bold")).pack(pady=(3, 0))

        fb = tk.Frame(cell, bg=V64_BG)
        fb.pack(pady=(4, 0))
        try:
            _v62_draw_feedback(fb, [], _v64_tokens(tx))
        except Exception:
            pass

        item = {"idx": n, "target": tx, "role": role, "entry": ent, "line": cv, "w": cw, "feedback": fb}
        self.dict_v46_entries.append(item)

        # 保留 V62 颜色判定：紫色输入中、绿色正确、红色最终错误。
        if "_v62_live_entry" in globals():
            ent.bind("<KeyRelease>", lambda e, it=item: _v62_live_entry(self, it))
        if "_v62_space_entry" in globals():
            ent.bind("<space>", lambda e, it=item: _v62_space_entry(self, it))
        if "_v62_submit_all" in globals():
            ent.bind("<Return>", lambda e: (_v62_submit_all(self), "break"))

        current_units += 1
        current_chars += width + 2

    if not hasattr(self, "dict_v62_bottom_var"):
        self.dict_v62_bottom_var = tk.StringVar(value="")
    msg = tk.Frame(parent, bg=V64_BG)
    msg.pack(fill="x", side="bottom", pady=(8, 16))
    self.dict_v62_bottom_label = tk.Label(msg, textvariable=self.dict_v62_bottom_var, bg=V64_BG,
                                          fg=V64_MUTED, font=("Microsoft YaHei UI", 12, "bold"),
                                          wraplength=1100, justify="center")
    self.dict_v62_bottom_label.pack(anchor="center")

    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    _v64_set_feedback(self, "输入规则：紫色=输入中；绿色=正确；红色=最终错误。整句模式按语块，拆分模式逐词横线。", "info")

def _v64_refresh_current(self):
    try:
        if "_v62_refresh_current" in globals():
            # 不直接调用旧渲染，避免旧学习区覆盖 V64；只更新标题。
            m = _v64_current_material(self)
            mats = getattr(self, "dictation_materials_v30", []) or []
            title = ""
            try:
                title = _v62_group_file(m) if "_v62_group_file" in globals() else "当前素材"
            except Exception:
                title = "当前素材"
            try:
                self.dictation_target_meta_var_v30.set(f"{int(getattr(self,'dictation_index_v30',0) or 0)+1}/{len(mats)}｜{title}")
            except Exception:
                pass
        _v64_render_learning_area(self)
        if "_v62_highlight_tree_current" in globals():
            try:
                _v62_highlight_tree_current(self)
            except Exception:
                pass
    except Exception:
        _v64_render_learning_area(self)

def _v64_open_auto_split_settings(self):
    cfg = _v64_cfg(self)
    auto = cfg.get("dictation", {}).get("auto_split", _v64_default_split_cfg())

    win = tk.Toplevel(self)
    win.title("听写自动拆分设置")
    win.geometry("760x560")
    win.configure(bg=V64_PANEL)

    outer = tk.Frame(win, bg=V64_PANEL)
    outer.pack(fill="both", expand=True, padx=18, pady=16)

    tk.Label(outer, text="听写自动拆分", bg=V64_PANEL, fg=V64_TEXT,
             font=("Microsoft YaHei UI", 18, "bold")).pack(anchor="w")
    tk.Label(outer, text="该功能只作用于【整句模式】。拆分模式固定为逐词横线，不受这里控制。",
             bg=V64_PANEL, fg=V64_MUTED, font=("Microsoft YaHei UI", 10, "bold"),
             wraplength=700, justify="left").pack(anchor="w", pady=(4, 14))

    vars_ = {}
    for key, label in V64_SPLIT_LABELS.items():
        row = tk.Frame(outer, bg=V64_PANEL)
        row.pack(fill="x", pady=8)
        vars_[key] = tk.BooleanVar(value=bool(auto.get(key, key == "super_long")))
        ttk.Checkbutton(row, text=label, variable=vars_[key]).pack(side="left")
        desc = "默认开启：超长句太长，默认拆成语块。" if key == "super_long" else "默认关闭：不勾选时整句作为一个大语块。"
        tk.Label(row, text=desc, bg=V64_PANEL, fg=V64_MUTED).pack(side="left", padx=12)

    tk.Label(outer, text="规则说明：整句模式下，开启的句型会拆成多个语块；未开启的句型会作为一个整句语块。拆分模式始终每个单词一条横线。",
             bg=V64_PANEL, fg=V64_TEXT, wraplength=700, justify="left").pack(anchor="w", pady=(18, 8))

    def save():
        cfg = _v64_cfg(self)
        cfg.setdefault("dictation", {})["auto_split"] = {k: bool(v.get()) for k, v in vars_.items()}
        _v64_save_cfg(self)
        _v64_render_learning_area(self)
        try:
            messagebox.showinfo("已保存", "听写自动拆分设置已保存并立即生效。")
        except Exception:
            pass

    btns = tk.Frame(outer, bg=V64_PANEL)
    btns.pack(fill="x", side="bottom", pady=12)
    ttk.Button(btns, text="恢复默认（只拆超长句）",
               command=lambda: [vars_[k].set(k == "super_long") for k in vars_]).pack(side="left")
    ttk.Button(btns, text="保存并立即生效", command=save).pack(side="right")

def _v64_open_settings_panel(self):
    # 纯中文设置入口：先提供 V64 自动拆分页；同时保留 V63 设置中心入口，不丢音效/主题/路径等功能。
    win = tk.Toplevel(self)
    win.title("设置中心 V64")
    win.geometry("960x680")
    win.configure(bg=V64_PANEL)
    outer = tk.Frame(win, bg=V64_PANEL)
    outer.pack(fill="both", expand=True, padx=16, pady=14)

    tk.Label(outer, text="设置中心", bg=V64_PANEL, fg=V64_TEXT,
             font=("Microsoft YaHei UI", 18, "bold")).pack(anchor="w")
    tk.Label(outer, text="界面入口已中文化。自动拆分属于听写训练设置；音效、主题、路径、显示隐藏、光标特效继续保留。",
             bg=V64_PANEL, fg=V64_MUTED, wraplength=880, justify="left").pack(anchor="w", pady=(4, 10))

