    if not isinstance(cfg, dict):
        cfg = {}
    cfg.setdefault("paths", {})
    cfg["paths"].setdefault("resource_root", str(_Path_v65.cwd() / "playphrase_resource_hub_v54"))
    cfg["paths"].setdefault("output_root", str(_Path_v65.cwd() / "playphrase_output"))
    cfg["paths"].setdefault("cache_root", str(_Path_v65.cwd() / "clip_cache"))
    cfg.setdefault("display", {})
    cfg["display"].setdefault("left_material_pool", True)
    cfg["display"].setdefault("right_control_panel", True)
    cfg["display"].setdefault("top_import_bar", True)
    cfg["display"].setdefault("bottom_buttons", True)
