# ---------------- 去除主界面重复按钮 ----------------
def _v65_should_remove_button(text):
    t = str(text or "").strip()
    # 主界面不要再堆重复入口；设置/资源入口集中到右侧控制台和“我的资源站”页。
    remove_exact = {
        "快捷键设置", "听写自动拆分", "设置中心 V63", "设置中心 V64",
        "高级设置中心 · 音效/TTS/快捷键",
    }
    if t in remove_exact:
        return True
    # 资源平台按钮只保留右侧控制台里的一个；主工具区重复的直接删。
    if t == "资源平台":
        return True
    return False

def _v65_dedupe_buttons(self):
    # 删除重复的主界面按钮，不影响“我的资源站”标签页内部的资源平台功能。
    seen = {}
    def walk(w, in_resource_platform=False, in_right_panel=False):
        try:
            # 资源平台顶层窗口不清理，否则会误删资源平台自己的工具按钮。
            title = ""
            try:
                title = str(w.winfo_toplevel().title())
            except Exception:
                title = ""
            in_resource_platform = in_resource_platform or ("资源平台" in title and "PlayPhrase" not in title)
        except Exception:
            pass
        try:
            in_right_panel = in_right_panel or (hasattr(self, "dictation_right_panel_v32") and str(w).startswith(str(self.dictation_right_panel_v32)))
        except Exception:
            pass
        try:
            txt = str(w.cget("text")).strip()
            if not in_resource_platform:
                if _v65_should_remove_button(txt):
                    # 右侧控制台内部设置入口由 V65 重建，不保留旧按钮。
                    try: w.destroy()
                    except Exception:
                        try: w.pack_forget()
                        except Exception: pass
                    return
                if txt in {"设置中心", "打开资源平台"}:
                    # 同类按钮全局只留一个，且优先留右侧控制台内的。
                    key = txt
                    old = seen.get(key)
                    if old is not None:
                        try: w.destroy()
                        except Exception:
                            try: w.pack_forget()
                            except Exception: pass
                        return
                    seen[key] = w
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch, in_resource_platform, in_right_panel)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

# ---------------- 右侧控制台隐藏/显示 + 学习区全屏 ----------------
def _v65_right_panel_visible(self):
    cfg = _v65_cfg(self)
    return bool(cfg.get("display", {}).get("right_control_panel", True))

def _v65_show_right_button(self):
    tab = getattr(self, "tab_dictation", None)
    if tab is None:
        return
    if getattr(self, "dict_v65_show_right_btn", None) and self.dict_v65_show_right_btn.winfo_exists():
        return
    try:
        btn = ttk.Button(tab, text="显示右侧控制台", command=lambda: _v65_toggle_right_panel(self, True))
        btn.place(relx=1.0, x=-12, y=46, anchor="ne")
        self.dict_v65_show_right_btn = btn
    except Exception:
        pass

def _v65_hide_show_right_button(self):
    try:
        if getattr(self, "dict_v65_show_right_btn", None):
            self.dict_v65_show_right_btn.destroy()
            self.dict_v65_show_right_btn = None
    except Exception:
        pass

def _v65_toggle_right_panel(self, show=None):
    cfg = _v65_cfg(self)
    cur = _v65_right_panel_visible(self)
    show = (not cur) if show is None else bool(show)
    cfg.setdefault("display", {})["right_control_panel"] = show
    _v65_save_cfg(self)
    try:
        rp = getattr(self, "dictation_right_panel_v32", None)
        if rp is not None:
            if show:
                rp.pack(side="right", fill="y")
                _v65_hide_show_right_button(self)
            else:
                rp.pack_forget()
                _v65_show_right_button(self)
    except Exception:
        pass

def _v65_toggle_left_panel(self, show=None):
    cfg = _v65_cfg(self)
    cur = bool(cfg.get("display", {}).get("left_material_pool", True))
    show = (not cur) if show is None else bool(show)
    cfg.setdefault("display", {})["left_material_pool"] = show
    _v65_save_cfg(self)
    try:
        lp = getattr(self, "dictation_left_panel_v32", None)
        if lp is not None:
            if show:
                lp.pack(side="left", fill="both")
            else:
                lp.pack_forget()
    except Exception:
        pass

def _v65_apply_display(self):
    cfg = _v65_cfg(self)
    disp = cfg.get("display", {})
    _v65_toggle_left_panel(self, bool(disp.get("left_material_pool", True)))
    _v65_toggle_right_panel(self, bool(disp.get("right_control_panel", True)))
    # 底部按钮区：只隐藏 V46 注册过的按钮，不误删输入区。
    try:
        for b in getattr(self, "dict_v46_bottom_buttons", {}).values():
            if bool(disp.get("bottom_buttons", True)):
                if not b.winfo_ismapped():
                    b.pack(side="left", padx=4, pady=3)
            else:
                b.pack_forget()
    except Exception:
        pass

def _v65_toggle_learning_fullscreen(self):
    # 学习区沉浸模式：隐藏素材池/控制台；根窗口 F11 全屏；再按恢复。
    cur = bool(getattr(self, "_v65_learning_fullscreen", False))
    self._v65_learning_fullscreen = not cur
    if not cur:
        try:
            self.attributes("-fullscreen", True)
        except Exception:
            pass
        try: _v65_toggle_left_panel(self, False)
        except Exception: pass
        try: _v65_toggle_right_panel(self, False)
        except Exception: pass
        _v65_set_feedback(self, "已进入学习区全屏：F11 或窗口/全屏按钮可恢复。", "ok", auto_clear=True)
    else:
        try:
            self.attributes("-fullscreen", False)
        except Exception:
            pass
        cfg = _v65_cfg(self)
        try: _v65_toggle_left_panel(self, bool(cfg.get("display", {}).get("left_material_pool", True)))
        except Exception: pass
        try: _v65_toggle_right_panel(self, bool(cfg.get("display", {}).get("right_control_panel", True)))
        except Exception: pass
        _v65_set_feedback(self, "已退出学习区全屏。", "ok", auto_clear=True)

# ---------------- 资源解析与加载 ----------------
def _v65_clean_filename_text(name):
    stem = _Path_v65(str(name)).stem
    # PlayPhrase 下载常见：0001_It doesn't have to make sense 或 0001.xxx
    stem = _re_v65.sub(r"^\d{1,6}[_\-. ]*", "", stem)
    stem = stem.replace("_", " ").replace("-", " ")
    stem = _re_v65.sub(r"\b(1080p|720p|2160p|x264|x265|h264|h265|web|dl|bluray|aac)\b", " ", stem, flags=_re_v65.I)
    stem = _re_v65.sub(r"\s+", " ", stem).strip()
    return stem

def _v65_text_has_english(s):
    return len(_re_v65.findall(r"[A-Za-z]", str(s or ""))) >= 2

def _v65_parse_srt_time(t):
    t = str(t or "").replace(",", ".")
    parts = t.split(":")
    try:
        if len(parts) == 3:
            return int(parts[0])*3600 + int(parts[1])*60 + float(parts[2])
        if len(parts) == 2:
            return int(parts[0])*60 + float(parts[1])
    except Exception:
        return 0.0
    return 0.0

def _v65_parse_subtitle(path):
    p = _Path_v65(str(path or ""))
    if not p.exists():
        return []
    try:
        raw = p.read_text("utf-8-sig", errors="ignore")
    except Exception:
        return []
    raw = raw.replace("\r\n", "\n").replace("\r", "\n")
    out = []
    time_re = _re_v65.compile(r"(?P<s>\d{1,2}:\d{2}(?::\d{2})?[,\.]\d{1,3})\s*-->\s*(?P<e>\d{1,2}:\d{2}(?::\d{2})?[,\.]\d{1,3})")
    blocks = _re_v65.split(r"\n\s*\n", raw)
    for b in blocks:
        lines = [x.strip() for x in b.splitlines() if x.strip()]
        if not lines:
            continue
        st = et = 0.0
        texts = []
        for line in lines:
            mt = time_re.search(line)
            if mt:
                st = _v65_parse_srt_time(mt.group("s"))
                et = _v65_parse_srt_time(mt.group("e"))
                continue
            if _re_v65.fullmatch(r"\d+", line):
                continue
            line = _re_v65.sub(r"<[^>]+>", "", line).strip()
            if line:
                texts.append(line)
        if not texts:
            continue
        en, zh = [], []
        for t in texts:
            if len(_re_v65.findall(r"[A-Za-z]", t)) >= max(2, len(_re_v65.findall(r"[\u4e00-\u9fff]", t))*2):
                en.append(t)
            elif _re_v65.search(r"[\u4e00-\u9fff]", t):
                zh.append(t)
            elif _v65_text_has_english(t):
                en.append(t)
        if en:
            out.append({"text": " ".join(en), "zh": " ".join(zh), "start": st, "end": et})
    if out:
        return out
    # 普通 TXT：一行一句
    for line in raw.splitlines():
        line = _re_v65.sub(r"<[^>]+>", "", line).strip()
        if not line or "-->" in line or _re_v65.fullmatch(r"\d+", line):
            continue
        if _v65_text_has_english(line):
            out.append({"text": line, "zh": "", "start": 0.0, "end": 0.0})
    return out

def _v65_find_sub_for_video(video):
    if "_v60_find_sub" in globals():
        try:
            found = _v60_find_sub(video)
            if found:
                return _Path_v65(found)
        except Exception:
            pass
    if "_v59_find_sub" in globals():
        try:
            found = _v59_find_sub(video)
            if found:
                return _Path_v65(found)
        except Exception:
            pass
    p = _Path_v65(str(video))
    if not p.exists():
        return None
    cands = []
    for ext in V65_SUB_EXTS:
        cands.append(p.with_suffix(ext))
        try: cands.extend(p.parent.glob(p.stem + "*" + ext))
        except Exception: pass
    for c in cands:
        try:
            if c.exists():
                return c
        except Exception:
            pass
    return None

def _v65_materials_from_record(record):
    mats, skipped = [], []
    if not isinstance(record, dict):
        return mats, ["非法资源记录"]
    path = record.get("path") or record.get("video_path") or record.get("media_path") or record.get("subtitle_path") or record.get("text_path") or record.get("audio_path")
    name = record.get("name") or (_Path_v65(path).name if path else "未命名")
    ext = _Path_v65(str(path or name)).suffix.lower()
    typ = str(record.get("type") or "")
    status = str(record.get("status") or "")

    # 视频资源：优先字幕；缺字幕时从 PlayPhrase 文件名生成一条台词。
    if ext in V65_VIDEO_EXTS or "视频" in typ or "视频" in status:
        video = record.get("video_path") or record.get("media_path") or record.get("local_path") or record.get("path")
        sub = record.get("subtitle_path") or ""
        if not sub or not _Path_v65(str(sub)).exists():
            found = _v65_find_sub_for_video(video)
            sub = str(found or "")
        if sub:
            lines = _v65_parse_subtitle(sub)
            if lines:
                for item in lines:
                    mats.append({
                        "text": item.get("text", ""),
                        "zh": item.get("zh", ""),
                        "start": float(item.get("start") or 0),
                        "end": float(item.get("end") or 0),
                        "title": name,
                        "local_path": str(video or ""),
                        "media_path": str(video or ""),
                        "video_path": str(video or ""),
                        "subtitle_path": str(sub),
                        "kind": "video",
                        "source_type": "local_video_subtitle",
                    })
                return mats, skipped
        # 缺字幕兜底：PlayPhrase 文件名一般就是台词。
        fallback = _v65_clean_filename_text(name or path)
        if _v65_text_has_english(fallback):
            mats.append({
                "text": fallback,
                "zh": "",
                "start": 0.0,
                "end": 0.0,
                "title": name,
                "local_path": str(video or path or ""),
                "media_path": str(video or path or ""),
                "video_path": str(video or path or ""),
                "subtitle_path": "",
                "kind": "video",
                "source_type": "local_video_filename_fallback",
            })
            return mats, [f"{name}：缺字幕，已用文件名兜底生成台词"]
        return [], [f"{name}：缺字幕，且文件名无法提取英文台词"]

    # 文本/字幕资源
    if ext in V65_TEXT_EXTS or "文本" in typ or "字幕" in typ:
        text_path = record.get("subtitle_path") or record.get("text_path") or record.get("path")
        lines = _v65_parse_subtitle(text_path)
        if not lines:
            return [], [f"{name}：文本/字幕无英文内容"]
        for item in lines:
            mats.append({
                "text": item.get("text", ""),
                "zh": item.get("zh", ""),
                "start": float(item.get("start") or 0),
                "end": float(item.get("end") or 0),
                "title": name,
                "local_path": str(text_path or ""),
                "subtitle_path": str(text_path or ""),
                "kind": "text",
                "source_type": "local_text",
            })
        return mats, skipped

    # 音频资源：如果有同名字幕/文本则加载，否则作为盲听音频。
    if ext in V65_AUDIO_EXTS or "音频" in typ:
        audio = record.get("audio_path") or record.get("path")
        p = _Path_v65(str(audio or ""))
        sub = None
        for e in [".srt", ".vtt", ".lrc", ".txt"]:
            c = p.with_suffix(e)
            if c.exists():
                sub = c
                break
        if sub:
            lines = _v65_parse_subtitle(sub)
            for item in lines:
                mats.append({
                    "text": item.get("text", ""),
                    "zh": item.get("zh", ""),
                    "start": float(item.get("start") or 0),
                    "end": float(item.get("end") or 0),
                    "title": name,
                    "audio_path": str(audio or ""),
                    "local_path": str(audio or ""),
                    "subtitle_path": str(sub),
                    "kind": "audio_text",
                    "source_type": "local_audio_text",
                })
            return mats, skipped
        fallback = _v65_clean_filename_text(name)
        if _v65_text_has_english(fallback):
            mats.append({
                "text": fallback,
                "zh": "",
                "start": 0.0,
                "end": 0.0,
                "title": name,
                "audio_path": str(audio or ""),
                "local_path": str(audio or ""),
                "kind": "audio_filename_fallback",
                "source_type": "local_audio",
            })
            return mats, [f"{name}：缺字幕/歌词，已用文件名兜底"]
        return [], [f"{name}：只有音频，未找到同名字幕/歌词"]

    return [], [f"{name}：暂不支持类型 {typ or ext}"]

def _v65_load_records_to_dictation(self, records, clear_existing=False):
    all_mats, skipped = [], []
    for r in records or []:
        mats, sk = _v65_materials_from_record(r)
        all_mats.extend([m for m in mats if _v65_text_has_english(m.get("text", ""))])
        skipped.extend(sk)
    if not all_mats:
        msg = "没有加载到可练习台词。"
        if skipped:
            msg += " 原因：" + "；".join(skipped[:8])
        try:
            messagebox.showwarning("资源加载失败", msg)
        except Exception:
            pass
        _v65_set_feedback(self, msg, "bad")
        return 0
    old = [] if clear_existing else (getattr(self, "dictation_materials_v30", []) or [])
    seen = {(str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text",""))) for m in old if isinstance(m, dict)}
    add = []
    for m in all_mats:
        key = (str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text","")))
        if key not in seen:
            add.append(m)
            seen.add(key)
    old.extend(add)
    self.dictation_materials_v30 = old
    try: self.dict_items_v33 = old
    except Exception: pass
    if add:
        self.dictation_index_v30 = max(0, len(old) - len(add))
        try: self.dict_index_v33 = self.dictation_index_v30
        except Exception: pass
    try:
        if "_v62_refresh_material_tree" in globals():
            _v62_refresh_material_tree(self)
        elif "_v61_refresh_material_tree" in globals():
            _v61_refresh_material_tree(self)
    except Exception:
        pass
    try:
        if "_v64_refresh_current" in globals():
            _v64_refresh_current(self)
        elif "_v62_refresh_current" in globals():
            _v62_refresh_current(self)
    except Exception:
        pass
    msg = f"已加载 {len(add)} 条到听写训练。"
    if skipped:
        msg += f" 跳过/兜底提示 {len(skipped)} 条：{skipped[0]}"
    _v65_set_feedback(self, msg, "ok" if add else "bad", auto_clear=False)
    return len(add)

def _v65_collect_selected_resource_records(self, mode="dictation"):
    table = getattr(self, f"v59_{mode}_table", None) or getattr(self, f"v54_{mode}_table", None)
    rows = getattr(self, f"v59_{mode}_rows", []) or getattr(self, f"v54_{mode}_rows", [])
    selected = []
    if table is not None:
        for iid in table.selection():
            try:
                selected.append(rows[int(iid)])
            except Exception:
                # 某些 TreeView iid 不是数字时，从 values 还原。
                try:
                    vals = table.item(iid, "values")
                    if vals:
                        selected.append({"type": vals[0], "name": vals[1], "status": vals[2], "lines": vals[3], "origin": vals[4], "path": vals[5]})
                except Exception:
                    pass
    if not selected:
        # 如果没选中，加载当前表可见记录；用户在文件夹下点“加载选中”时不再什么都不发生。
        selected = list(rows)
    return selected

def _v65_load_selected_to_training(self, mode="dictation"):
    if mode != "dictation":
        try:
            messagebox.showinfo("提示", "当前修复重点为听写训练；背诵资源继续沿用原链。")
        except Exception:
            pass
        return
    selected = _v65_collect_selected_resource_records(self, "dictation")
    if not selected:
        try:
            messagebox.showwarning("提示", "当前资源平台没有可加载资源。")
        except Exception:
            pass
        return
    n = _v65_load_records_to_dictation(self, selected, clear_existing=False)
    if n:
        try:
            self.nb.select(self.tab_dictation)
        except Exception:
            pass

def _v65_sync_hub_to_dictation(self):
    # 从资源平台索引同步全部可用记录。
    data = None
    if "_v59_index" in globals():
        try:
            _, data = _v59_index(self, "dictation")
        except Exception:
            data = None
    if not data:
        return _v65_set_feedback(self, "未找到资源平台索引。", "bad")
    return _v65_load_records_to_dictation(self, data.get("records", []), clear_existing=False)

# ---------------- 在线资源下载/补下载 ----------------
def _v65_clip_to_material(c):
    text = str(getattr(c, "text", "") or getattr(c, "en", "") or "")
    zh = str(getattr(c, "zh", "") or "")
    url = str(getattr(c, "video_url", "") or getattr(c, "url", "") or "")
    keyword = str(getattr(c, "keyword", "") or "")
    title = _v65_clean_filename_text(text)[:80] or keyword or "online_clip"
    return {"text": text, "zh": zh, "url": url, "video_url": url, "keyword": keyword, "title": title, "source_type": "online_pool"}

def _v65_get_online_pool_materials(self):
    clips = []
    try:
        clips = list(getattr(self, "pool", []) or [])
    except Exception:
        clips = []
    mats = []
    for c in clips:
        m = _v65_clip_to_material(c)
        if _v65_text_has_english(m.get("text")):
            mats.append(m)
    if not mats:
        for m in getattr(self, "dictation_materials_v30", []) or []:
            if isinstance(m, dict) and str(m.get("source_type","")).startswith("online"):
                mats.append(m)
    return mats

def _v65_make_srt_line(idx, text, start=0.0, end=3.0):
    def fmt(sec):
        sec = max(0.0, float(sec or 0))
        h = int(sec // 3600); sec -= h*3600
        m = int(sec // 60); sec -= m*60
        s = int(sec); ms = int(round((sec - s)*1000))
        return f"{h:02d}:{m:02d}:{s:02d},{ms:03d}"
    return f"{idx}\n{fmt(start)} --> {fmt(end)}\n{text}\n\n"

def _v65_safe_filename(s, suffix=".mp4"):
    s = _v65_clean_filename_text(s) or "clip"
    s = _re_v65.sub(r'[\\/:*?"<>|]+', "_", s)
    s = _re_v65.sub(r"\s+", "_", s).strip("_")
    return (s[:80] or "clip") + suffix

def _v65_download_file(url, out_path, timeout=45):
    if not url:
        return False, "无视频URL"
    try:
        import requests
        r = requests.get(url, timeout=timeout, stream=True)
        if r.status_code >= 400:
            return False, f"HTTP {r.status_code}"
        out_path.parent.mkdir(parents=True, exist_ok=True)
        with out_path.open("wb") as f:
            for chunk in r.iter_content(chunk_size=1024*512):
                if chunk:
                    f.write(chunk)
        return True, "OK"
    except Exception as e:
        return False, f"{type(e).__name__}: {e}"

def _v65_translate_text(self, text, engine=None):
    engine = engine or _v65_cfg(self).get("loading", {}).get("online_translate_engine", "OPUS-MT 本地")
    # 尽量复用项目已有翻译链。
    try:
        tr = getattr(self, "translator", None)
        if tr and hasattr(tr, "translate"):
            return tr.translate(text, engine)
    except Exception:
        pass
    for fn_name in ("_opus_translate_v19", "_v60_opus_translate", "_v58_translate_one", "_smart_translate_v30"):
        fn = getattr(self, fn_name, None) or globals().get(fn_name)
        if callable(fn):
            try:
                # 兼容 bound/unbound
                try:
                    res = fn(text, "en", "zh")
                except TypeError:
                    res = fn(self, text, "en", "zh")
                if res:
                    return str(res)
            except Exception:
                pass
    return ""

def _v65_register_download_records(self, records):
    if not records:
        return
    if "_v59_index" in globals() and "_v59_save_index" in globals():
        try:
            fp, data = _v59_index(self, "dictation")
            old = data.setdefault("records", [])
            keys = {str(r.get("path") or r.get("video_path") or r.get("name")) for r in old}
            for r in records:
                key = str(r.get("path") or r.get("video_path") or r.get("name"))
                if key not in keys:
                    old.append(r); keys.add(key)
            _v59_save_index(self, "dictation", data)
        except Exception as e:
            _v65_log(self, f"注册资源索引失败：{type(e).__name__}: {e}", "warn")

def _v65_download_online_resources_to_local(self, materials=None):
    mats = list(materials or _v65_get_online_pool_materials(self))
    if not mats:
        try:
            messagebox.showwarning("提示", "没有可下载的在线精选池资源。")
        except Exception:
            pass
        return
    cfg = _v65_cfg(self).get("loading", {})
    target = _v65_dictation_download_root(self)
    _v65_set_feedback(self, f"开始下载在线资源到：{target}", "info")
    def worker():
        records = []
        ok_count = 0
        for i, m in enumerate(mats, 1):
            text = str(m.get("text") or "")
            zh = str(m.get("zh") or "")
            if not zh and cfg.get("online_write_translate_subtitle", True):
                zh = _v65_translate_text(self, text, cfg.get("online_translate_engine"))
            base = f"{i:04d}_" + _v65_safe_filename(text, "").strip("_")
            base = _re_v65.sub(r'[\\/:*?"<>|]+', "_", base)[:95] or f"{i:04d}_clip"
            video_path = target / (base + ".mp4")
            en_srt = target / (base + ".en.srt")
            zh_srt = target / (base + ".zh.srt")
            url = m.get("video_url") or m.get("url") or ""
            downloaded = False
            if cfg.get("online_download_video", True) and url:
                downloaded, why = _v65_download_file(url, video_path)
                if not downloaded:
                    _v65_log(self, f"视频下载失败 {i}/{len(mats)}：{why}", "warn")
            if cfg.get("online_write_origin_subtitle", True):
                en_srt.write_text(_v65_make_srt_line(1, text), "utf-8")
            if cfg.get("online_write_translate_subtitle", True) and zh:
                zh_srt.write_text(_v65_make_srt_line(1, zh), "utf-8")
            record = {
                "mode": "dictation",
                "top": "本地视频字幕",
                "folder": "play phrase网站学习资源",
                "type": "本地视频字幕",
                "name": video_path.name if downloaded else en_srt.name,
                "status": "PlayPhrase本地视频" if downloaded else "在线字幕已落地",
                "lines": 1,
                "origin": "PlayPhrase下载",
                "path": str(video_path if downloaded else en_srt),
                "video_path": str(video_path if downloaded else ""),
                "media_path": str(video_path if downloaded else ""),
                "local_path": str(video_path if downloaded else en_srt),
                "subtitle_path": str(en_srt),
                "source_type": "local_video_subtitle" if downloaded else "local_text",
            }
            records.append(record)
            ok_count += 1
            try:
                self.after(0, lambda c=ok_count, total=len(mats): _v65_set_feedback(self, f"在线资源下载/落地：{c}/{total}", "info"))
            except Exception:
                pass
        _v65_register_download_records(self, records)
        try:
            self.after(0, lambda: (_v65_after_resource_changed(self), _v65_set_feedback(self, f"在线资源已落地 {ok_count} 条，并刷新资源平台/素材树。", "ok")))
        except Exception:
            pass
    _threading_v65.Thread(target=worker, daemon=True).start()

def _v65_after_resource_changed(self):
    try:
        if "_v59_refresh_tree" in globals():
            _v59_refresh_tree(self, "dictation")
        if "_v59_refresh_table" in globals():
            _v59_refresh_table(self, "dictation")
    except Exception:
        pass
    try:
        if "_v62_refresh_material_tree" in globals():
            _v62_refresh_material_tree(self)
    except Exception:
        pass

def _v65_import_pool_safe(self):
    # 安全加载精选池文本；如设置勾选，同时下载到本地。
    mats = _v65_get_online_pool_materials(self)
    if not mats:
        try:
            messagebox.showwarning("提示", "精选池为空，无法加载。")
        except Exception:
            pass
        return
    records = []
    for i, m in enumerate(mats, 1):
        records.append({
            "type": "本地文本资源",
            "name": f"在线精选池_{i:04d}.txt",
            "status": "在线文本",
            "lines": 1,
            "origin": "在线精选池",
            "path": "",
            "source_type": "online_pool",
            "text": m.get("text", ""),
            "zh": m.get("zh", ""),
            "url": m.get("url") or m.get("video_url") or "",
        })
    # 直接转素材，不走文件解析。
    old = getattr(self, "dictation_materials_v30", []) or []
    for m in mats:
        old.append({
            "text": m.get("text",""),
            "zh": m.get("zh",""),
            "url": m.get("url") or m.get("video_url") or "",
            "video_url": m.get("url") or m.get("video_url") or "",
            "keyword": m.get("keyword",""),
            "title": m.get("title","在线精选池"),
            "source_type": "online_pool",
            "kind": "online",
        })
    self.dictation_materials_v30 = old
    if old:
        self.dictation_index_v30 = max(0, len(old)-len(mats))
    try:
        if "_v62_refresh_material_tree" in globals(): _v62_refresh_material_tree(self)
        if "_v64_refresh_current" in globals(): _v64_refresh_current(self)
    except Exception:
        pass
    _v65_set_feedback(self, f"已安全加载精选池文本 {len(mats)} 条。", "ok")
    if _v65_cfg(self).get("loading", {}).get("online_download_on_load", False):
        _v65_download_online_resources_to_local(self, mats)

# ---------------- 文本翻译写回 / TTS缓存 ----------------
def _v65_current_text_materials(self):
    mats = []
    for m in getattr(self, "dictation_materials_v30", []) or []:
        if isinstance(m, dict) and (m.get("kind") == "text" or "text" in str(m.get("source_type",""))):
            mats.append(m)
    return mats

def _v65_translate_text_materials_writeback(self):
    mats = _v65_current_text_materials(self)
    if not mats:
        try: messagebox.showwarning("提示", "当前没有文本素材。")
        except Exception: pass
        return
    engine = _v65_cfg(self).get("loading", {}).get("text_translate_engine", "OPUS-MT 本地")
    def worker():
        by_file = {}
        for i, m in enumerate(mats, 1):
            if not m.get("zh"):
                m["zh"] = _v65_translate_text(self, m.get("text",""), engine)
            fp = m.get("subtitle_path") or m.get("local_path")
            if fp:
                by_file.setdefault(fp, []).append(m)
            try:
                self.after(0, lambda i=i: _v65_set_feedback(self, f"文本翻译写回处理中：{i}/{len(mats)}", "info"))
            except Exception: pass
        for fp, items in by_file.items():
            p = _Path_v65(fp)
            out = p.with_name(p.stem + ".zh_cache.txt")
            lines = []
            for item in items:
                lines.append(item.get("text",""))
                if item.get("zh"): lines.append(item.get("zh",""))
                lines.append("")
            try:
                out.write_text("\n".join(lines), "utf-8")
            except Exception as e:
                _v65_log(self, f"写入翻译缓存失败：{out} {e}", "warn")
        try:
            self.after(0, lambda: _v65_set_feedback(self, "文本翻译已写入本地 zh_cache 文件，下次可直接读取。", "ok"))
        except Exception: pass
    _threading_v65.Thread(target=worker, daemon=True).start()

async def _v65_edge_save_mp3(text, out_path, voice="en-US-JennyNeural"):
    import edge_tts
    communicate = edge_tts.Communicate(text, voice=voice)
    await communicate.save(str(out_path))

def _v65_cache_tts_for_texts(self, full=False):
    mats = _v65_current_text_materials()
    if not mats:
        try: messagebox.showwarning("提示", "当前没有文本素材。")
        except Exception: pass
        return
    cfg = _v65_cfg(self).get("loading", {})
    engine = cfg.get("text_tts_engine", "Edge-TTS")
    if "Edge" not in engine:
        try:
            messagebox.showwarning("提示", "当前仅实装 Edge-TTS 的音频缓存；其他发音引擎需要另接 API。")
        except Exception:
            pass
        return
    target = _v65_resource_root(self) / "dictation" / "本地文本资源" / "_tts_cache"
    target.mkdir(parents=True, exist_ok=True)
    def worker():
        try:
            import asyncio
            if full:
                text = "\n".join(m.get("text","") for m in mats if m.get("text"))
                out = target / ("全文音频_" + _time_v65.strftime("%Y%m%d_%H%M%S") + ".mp3")
                asyncio.run(_v65_edge_save_mp3(text, out))
                self.after(0, lambda: _v65_set_feedback(self, f"全文音频已写入：{out}", "ok"))
            else:
                for i, m in enumerate(mats, 1):
                    safe = _v65_safe_filename(m.get("text",""), ".mp3")
                    out = target / f"{i:04d}_{safe}"
                    if not out.exists():
                        asyncio.run(_v65_edge_save_mp3(m.get("text",""), out))
                    m["audio_path"] = str(out)
                    self.after(0, lambda i=i: _v65_set_feedback(self, f"单句音频缓存：{i}/{len(mats)}", "info"))
                self.after(0, lambda: _v65_set_feedback(self, f"单句音频已缓存到：{target}", "ok"))
        except Exception as e:
            try:
                self.after(0, lambda: _v65_set_feedback(self, f"TTS音频缓存失败：{type(e).__name__}: {e}", "bad"))
            except Exception:
                pass
    _threading_v65.Thread(target=worker, daemon=True).start()

# ---------------- 中文设置中心：加载设置/显示隐藏/入口集中 ----------------
def _v65_setting_row(parent, title, desc=""):
    row = tk.Frame(parent, bg=V65_PANEL)
    row.pack(fill="x", padx=14, pady=7)
    left = tk.Frame(row, bg=V65_PANEL)
    left.pack(side="left", fill="x", expand=True)
    tk.Label(left, text=title, bg=V65_PANEL, fg=V65_TEXT, font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w")
    if desc:
        tk.Label(left, text=desc, bg=V65_PANEL, fg=V65_MUTED, wraplength=690, justify="left").pack(anchor="w")
    return row

def _v65_open_settings_center(self):
    cfg = _v65_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置中心 V65")
    win.geometry("1080x760")
    win.configure(bg=V65_PANEL)
    outer = tk.Frame(win, bg=V65_PANEL)
