def _v65_choose_dir(var):
    d = filedialog.askdirectory()
    if d:
        var.set(d)

def _v65_open_dir(path):
    p = _Path_v65(str(path or ".")).expanduser()
    p.mkdir(parents=True, exist_ok=True)
    try:
        if _sys_v65.platform.startswith("win"):
            _os_v65.startfile(str(p))
        elif _sys_v65.platform == "darwin":
            _subprocess_v65.Popen(["open", str(p)])
        else:
            _subprocess_v65.Popen(["xdg-open", str(p)])
    except Exception:
        pass

