def _v65_rebuild_right_panel(self):
    right = getattr(self, "dictation_right_panel_v32", None)
    if right is None:
        return
    for ch in list(right.winfo_children()):
        try: ch.destroy()
        except Exception: pass
    right.configure(width=360)
    header = tk.Frame(right, bg=V65_PANEL)
    header.pack(fill="x", padx=8, pady=(8, 4))
