    ttk.Button(header, text="隐藏", width=6, command=lambda: _v65_toggle_right_panel(self, False)).pack(side="right")

    nb = ttk.Notebook(right)
    nb.pack(fill="both", expand=True, padx=8, pady=6)
    t_core = ttk.Frame(nb, padding=8)
    t_res = ttk.Frame(nb, padding=8)
    t_set = ttk.Frame(nb, padding=8)
