    ttk.Button(t_res, text="从资源平台加载选中", command=lambda: _v65_load_selected_to_training(self, "dictation")).pack(fill="x", pady=4)
    ttk.Button(t_res, text="同步资源平台到素材池", command=lambda: _v65_sync_hub_to_dictation(self)).pack(fill="x", pady=4)
    ttk.Button(t_res, text="添加本地视频字幕路径", command=lambda: _v59_add_local_video_path_for_training(self) if "_v59_add_local_video_path_for_training" in globals() else None).pack(fill="x", pady=4)
    ttk.Button(t_res, text="添加文本路径", command=lambda: _v59_add_text_path_for_training(self) if "_v59_add_text_path_for_training" in globals() else None).pack(fill="x", pady=4)
    ttk.Button(t_res, text="刷新素材树", command=lambda: _v62_refresh_material_tree(self) if "_v62_refresh_material_tree" in globals() else None).pack(fill="x", pady=4)

