def _v65_rebind_global_buttons(self):
    def walk(w):
        try:
            txt = str(w.cget("text")).strip()
            if txt in {"窗口/全屏", "窗口/全屏 F11", "学习区全屏 F11"}:
                w.configure(text="学习区全屏 F11", command=lambda: _v65_toggle_learning_fullscreen(self))
            elif txt in {"设置中心", "设置中心 V63", "设置中心 V64"}:
                w.configure(text="设置中心", command=lambda: _v65_open_settings_center(self))
            elif txt == "加载选中到听写训练":
                w.configure(command=lambda: _v65_load_selected_to_training(self, "dictation"))
            elif txt == "从精选池导入" or txt == "导入精选池":
                w.configure(command=lambda: _v65_import_pool_safe(self))
            elif txt == "刷新素材树" or txt == "刷新素材":
                try: w.configure(command=lambda: _v62_refresh_material_tree(self))
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v65_patch_globals(self):
    globals()["_v65_open_settings_center"] = _v65_open_settings_center
    globals()["_v63_open_settings_panel"] = _v65_open_settings_center
    globals()["_v64_open_settings_panel"] = _v65_open_settings_center
    globals()["_v38_open_settings_center"] = lambda app: _v65_open_settings_center(app)
    globals()["_v53_open_sound_settings"] = lambda app: _v65_open_settings_center(app)
    globals()["_v54_open_sound_settings"] = lambda app: _v65_open_settings_center(app)
    globals()["_v56_open_sound_settings"] = lambda app: _v65_open_settings_center(app)
    globals()["_v59_load_selected_to_training"] = _v65_load_selected_to_training
    globals()["_v60_load_records_to_dictation"] = _v65_load_records_to_dictation
    globals()["_v59_sync_hub_to_dictation"] = _v65_sync_hub_to_dictation
    globals()["_v65_toggle_learning_fullscreen"] = _v65_toggle_learning_fullscreen
    try:
        self.bind_all("<F11>", lambda e: (_v65_toggle_learning_fullscreen(self), "break"))
    except Exception:
        pass

_old_main_init_v65 = MainApp.__init__
def _main_init_v65(self):
    _old_main_init_v65(self)
    try:
        _v65_cfg(self)
        _v65_patch_globals(self)
        _v65_rebuild_right_panel(self)
        _v65_dedupe_buttons(self)
        _v65_rebind_global_buttons(self)
        _v65_apply_display(self)
        try:
            self.after(350, lambda: (_v65_patch_globals(self), _v65_rebuild_right_panel(self), _v65_dedupe_buttons(self), _v65_rebind_global_buttons(self), _v65_apply_display(self)))
            self.after(1500, lambda: (_v65_dedupe_buttons(self), _v65_rebind_global_buttons(self)))
        except Exception:
            pass
        self.log("【V65上线】听写训练主界面按钮已去冗余：设置/快捷键/自动拆分集中到设置中心。", "ok")
        self.log("【V65上线】右侧控制台可隐藏/显示；F11为学习区沉浸全屏。", "ok")
        self.log("【V65上线】资源平台本地视频字幕可加载到听写素材池；缺字幕时从PlayPhrase文件名兜底。", "ok")
        self.log("【V65上线】设置中心新增加载设置：本地/在线/文本模式，支持在线资源后补下载与文本翻译/TTS缓存。", "ok")
    except Exception as e:
        try:
            self.log(f"V65初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v65
APP_TITLE = "PlayPhrase Studio Clean v65 · 去冗余与加载设置重构版"


