# V66：固定提示下移 + 台词树展开 + 学习区清空 + 播放前置条件/缓存策略
# ──────────────────────────────────────────────────────────────────────
import os as _os_v66
import re as _re_v66
import time as _time_v66
import json as _json_v66
import tempfile as _tempfile_v66
import threading as _threading_v66
from pathlib import Path as _Path_v66

V66_BG = globals().get("V65_BG", "#0b1220")
V66_PANEL = globals().get("V65_PANEL", "#111827")
V66_TEXT = globals().get("V65_TEXT", "#E5E7EB")
V66_MUTED = globals().get("V65_MUTED", "#94A3B8")
V66_OK = globals().get("V65_OK", "#22C55E")
V66_BAD = globals().get("V65_BAD", "#EF4444")
V66_INPUT = globals().get("V64_INPUT", "#8B5CF6")
V66_LINE = globals().get("V64_LINE", "#CBD5E1")

def _v66_cfg(self):
    cfg = _v65_cfg(self) if "_v65_cfg" in globals() else getattr(self, "v63_cfg", {})
    if not isinstance(cfg, dict): cfg = {}
    cfg.setdefault("loading", {})
    cfg["loading"].setdefault("play_source_required", True)
    cfg["loading"].setdefault("text_support_video", False)
    cfg["loading"].setdefault("online_storage_mode", "缓存学习")
    cfg["loading"].setdefault("online_cache_keep_after_exit", False)
    cfg["loading"].setdefault("online_download_on_video_play", True)
    cfg["loading"].setdefault("cache_root", str(_Path_v66.cwd() / "clip_cache" / "online_temp"))
    self.v63_cfg = cfg
    return cfg

def _v66_save_cfg(self):
    if "_v65_save_cfg" in globals():
        try: return _v65_save_cfg(self)
        except Exception: pass
    try:
        (_Path_v66.cwd() / "pp_studio_v63_settings.json").write_text(_json_v66.dumps(_v66_cfg(self), ensure_ascii=False, indent=2), "utf-8")
    except Exception: pass

def _v66_set_feedback(self, msg, level="info", auto_clear=False):
    if "_v65_set_feedback" in globals():
        try: return _v65_set_feedback(self, msg, level, auto_clear)
        except Exception: pass
    if "_v64_set_feedback" in globals():
        try: return _v64_set_feedback(self, msg, level, auto_clear)
        except Exception: pass

# ---------- 固定提示下移 ----------
def _v66_relocate_fixed_hint(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    # 移除 V64/V65 右侧 place 固定提示，避免遮挡输入横线。
    try:
        side_parent = getattr(self, "dict_v62_side_label", None).master
        side_parent.destroy()
    except Exception:
        pass
    try:
        old = getattr(self, "dict_v66_hint_panel", None)
        if old and old.winfo_exists():
            old.destroy()
    except Exception:
        pass

    msg_widget = getattr(self, "dict_v62_bottom_label", None)
    panel = tk.Frame(parent, bg="#0f172a", bd=1, relief="solid")
    try:
        if msg_widget and msg_widget.winfo_exists():
            panel.pack(fill="x", padx=160, pady=(12, 6), before=msg_widget.master)
        else:
            panel.pack(fill="x", padx=160, pady=(12, 6))
    except Exception:
        panel.pack(fill="x", padx=160, pady=(12, 6))
    self.dict_v66_hint_panel = panel

    tk.Label(panel, text="固定提示", bg="#0f172a", fg=V66_TEXT,
             font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w", padx=12, pady=(8, 2))
    if not hasattr(self, "dict_v62_side_var"):
        self.dict_v62_side_var = tk.StringVar(value="")
    self.dict_v62_side_label = tk.Label(panel, textvariable=self.dict_v62_side_var, bg="#0f172a",
                                        fg=V66_MUTED, wraplength=1100, justify="left",
                                        font=("Microsoft YaHei UI", 10, "bold"))
    self.dict_v62_side_label.pack(fill="x", padx=12, pady=(0, 4))
    if not hasattr(self, "dict_v63_hint_var"):
        self.dict_v63_hint_var = tk.StringVar(value="")
    self.dict_v63_hint_label = tk.Label(panel, textvariable=self.dict_v63_hint_var, bg="#0f172a",
                                        fg="#38BDF8", wraplength=1100, justify="left",
                                        font=("Microsoft YaHei UI", 10, "bold"))
    self.dict_v63_hint_label.pack(fill="x", padx=12, pady=(0, 8))

def _v66_render_learning_area(self):
    if "_v64_render_learning_area" in globals():
        _v64_render_learning_area(self)
    _v66_relocate_fixed_hint(self)

# ---------- 学习区清空 ----------
def _v66_clear_learning_area(self):
    try:
        self.dictation_materials_v30 = []
        self.dict_items_v33 = []
        self.dictation_index_v30 = 0
        self.dict_index_v33 = 0
    except Exception:
        pass
    try:
        tree = getattr(self, "dict_material_tree_v46", None)
        if tree is not None:
            tree.delete(*tree.get_children())
    except Exception:
        pass
    parent = getattr(self, "dict_v46_study", None)
    if parent is not None:
        for ch in list(parent.winfo_children()):
            try: ch.destroy()
            except Exception: pass
        tk.Label(parent, text="学习区已清空；请从左侧素材池或资源平台重新加载素材",
                 bg=V66_BG, fg=V66_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
    _v66_set_feedback(self, "学习区已清空。", "ok")

# ---------- 台词树展开：文件节点下必须能看到台词 ----------
def _v66_item_text(m):
    if "_v62_item_text" in globals():
        try: return _v62_item_text(m)
        except Exception: pass
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

def _v66_refresh_material_tree(self):
    # 复用 V62 分页树，但让 200 句以内文件直接展开台词；文件选择也能自动填充第一页。
    if "_v62_refresh_material_tree" in globals():
        _v62_refresh_material_tree(self)
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None: return
    mats = getattr(self, "dictation_materials_v30", []) or []
    try:
        for file_iid, idxs in list(getattr(self, "dict_v62_node_map", {}).items()):
            if not str(file_iid).startswith("v62_file_"):
                continue
            # 句数少的资源直接显示台词，避免“只看到视频文件，看不到台词”。
            if len(idxs) <= 200 and not tree.get_children(file_iid):
                for idx in idxs:
                    if idx >= len(mats): continue
                    text = _v66_item_text(mats[idx])
                    try:
                        tree.insert(file_iid, "end", iid=f"v66_item_{idx}", text=f"· {idx+1:04d}. {text[:180]}", values=("ITEM", str(idx)))
                    except Exception:
                        pass
                try: tree.item(file_iid, open=True)
                except Exception: pass
            # 如果文件下只有分页，也打开文件节点让用户看到分页入口。
            if len(idxs) > 200:
                try: tree.item(file_iid, open=True)
                except Exception: pass
    except Exception:
        pass

def _v66_on_tree_select(self, event=None):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None or not tree.selection(): return
    iid = tree.selection()[0]
    vals = tree.item(iid, "values")
    if vals and vals[0] == "FILE":
        # 选中文件时自动填充第一分页，且选中第一句。
        children = tree.get_children(iid)
        if children:
            first = children[0]
            fvals = tree.item(first, "values")
            if fvals and fvals[0] == "PAGE":
                if "_v62_populate_page" in globals():
                    try: _v62_populate_page(self, first)
                    except Exception: pass
                sub = tree.get_children(first)
                if sub:
                    try: tree.selection_set(sub[0]); tree.see(sub[0])
                    except Exception: pass
                    vals = tree.item(sub[0], "values")
                    if vals and vals[0] == "ITEM":
                        return _v62_select_index(self, int(vals[1]))
        idxs = getattr(self, "dict_v62_node_map", {}).get(iid) or []
        if idxs and "_v62_select_index" in globals():
            return _v62_select_index(self, idxs[0])
    if vals and vals[0] == "PAGE":
        if "_v62_populate_page" in globals():
            try: _v62_populate_page(self, iid)
            except Exception: pass
        sub = tree.get_children(iid)
        if sub:
            try: tree.selection_set(sub[0]); tree.see(sub[0])
            except Exception: pass
            vals = tree.item(sub[0], "values")
            if vals and vals[0] == "ITEM":
                return _v62_select_index(self, int(vals[1]))
    if vals and vals[0] == "ITEM":
        return _v62_select_index(self, int(vals[1]))
    if "_v62_on_tree_select" in globals():
        return _v62_on_tree_select(self, event)

# ---------- 资源加载增强：视频优先加载台词 ----------
def _v66_extract_text_from_filename(path_or_name):
    name = _Path_v66(str(path_or_name)).stem
    name = _re_v66.sub(r"^\d{1,6}[_\-. ]*", "", name)
    name = name.replace("_", " ").replace("-", " ")
    name = _re_v66.sub(r"\[[^\]]+\]|\([^\)]*\)", " ", name)
    name = _re_v66.sub(r"\b(1080p|720p|2160p|x264|x265|h264|h265|web|dl|bluray|aac|mp4|mkv)\b", " ", name, flags=_re_v66.I)
    name = _re_v66.sub(r"\s+", " ", name).strip(" ._-")
    return name

def _v66_find_sidecar_sub(video_path):
    p = _Path_v66(str(video_path or ""))
    if not p.exists(): return None
    for ext in [".srt", ".ass", ".ssa", ".vtt", ".txt", ".lrc"]:
        c = p.with_suffix(ext)
        if c.exists(): return c
    for ext in [".srt", ".ass", ".ssa", ".vtt", ".txt", ".lrc"]:
        for c in p.parent.glob(p.stem + "*" + ext):
            if c.exists(): return c
    return None

def _v66_parse_text_or_sub(path):
    if "_v65_parse_subtitle" in globals():
        try: return _v65_parse_subtitle(path)
        except Exception: pass
    p = _Path_v66(path)
    if not p.exists(): return []
    raw = p.read_text("utf-8-sig", errors="ignore")
    out = []
    for line in raw.splitlines():
        line = _re_v66.sub(r"<[^>]+>", "", line).strip()
        if not line or "-->" in line or _re_v66.fullmatch(r"\d+", line): continue
        if _re_v66.search(r"[A-Za-z]{2,}", line):
            out.append({"text": line, "zh": "", "start": 0.0, "end": 0.0})
    return out

def _v66_record_to_materials(record):
    if "_v65_materials_from_record" in globals():
        try:
            mats, skipped = _v65_materials_from_record(record)
            # 如果 v65 只产出文件名兜底，也继续返回；如果为空则继续增强。
            if mats: return mats, skipped
        except Exception:
            pass
    path = ""
    if isinstance(record, dict):
        path = record.get("video_path") or record.get("media_path") or record.get("local_path") or record.get("path") or ""
    if not path:
        return [], ["资源记录没有路径"]
    p = _Path_v66(str(path))
    ext = p.suffix.lower()
    mats = []
    if ext in {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"}:
        sub = _v66_find_sidecar_sub(p)
        if sub:
            lines = _v66_parse_text_or_sub(sub)
            for it in lines:
                mats.append({
                    "text": it.get("text",""), "zh": it.get("zh",""),
                    "start": float(it.get("start") or 0), "end": float(it.get("end") or 0),
                    "title": p.name, "local_path": str(p), "media_path": str(p), "video_path": str(p),
                    "subtitle_path": str(sub), "kind": "video", "source_type": "local_video_subtitle",
                })
        if not mats:
            txt = _v66_extract_text_from_filename(p.name)
            if _re_v66.search(r"[A-Za-z]{2,}", txt):
                mats.append({
                    "text": txt, "zh": "", "start": 0.0, "end": 0.0,
                    "title": p.name, "local_path": str(p), "media_path": str(p), "video_path": str(p),
                    "subtitle_path": "", "kind": "video", "source_type": "local_video_filename_fallback",
                })
        return mats, ([] if mats else [f"{p.name}：没有字幕，也无法从文件名提取台词"])
    if ext in {".srt", ".ass", ".ssa", ".vtt", ".txt", ".lrc"}:
        lines = _v66_parse_text_or_sub(p)
        for it in lines:
            mats.append({"text": it.get("text",""), "zh": it.get("zh",""), "start": float(it.get("start") or 0), "end": float(it.get("end") or 0), "title": p.name, "local_path": str(p), "subtitle_path": str(p), "kind": "text", "source_type": "local_text"})
        return mats, ([] if mats else [f"{p.name}：没有识别到英文台词"])
    return [], [f"{p.name}：不支持的资源类型"]

def _v66_load_records_to_dictation(self, records, clear_existing=False):
    all_mats, skipped = [], []
    for r in records or []:
        mats, sk = _v66_record_to_materials(r)
        all_mats.extend([m for m in mats if _re_v66.search(r"[A-Za-z]{2,}", str(m.get("text","")))])
        skipped.extend(sk)
    if not all_mats:
        msg = "没有加载到台词。"
        if skipped: msg += " " + "；".join(skipped[:6])
        _v66_set_feedback(self, msg, "bad")
        try: messagebox.showwarning("资源加载失败", msg)
        except Exception: pass
        return 0
    old = [] if clear_existing else (getattr(self, "dictation_materials_v30", []) or [])
    seen = {(str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text",""))) for m in old if isinstance(m, dict)}
    add = []
    for m in all_mats:
        key = (str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text","")))
        if key not in seen:
            add.append(m); seen.add(key)
    old.extend(add)
    self.dictation_materials_v30 = old
    try: self.dict_items_v33 = old
    except Exception: pass
    if add:
        self.dictation_index_v30 = max(0, len(old)-len(add))
        try: self.dict_index_v33 = self.dictation_index_v30
        except Exception: pass
    _v66_refresh_material_tree(self)
    try:
        if "_v64_refresh_current" in globals(): _v64_refresh_current(self)
        elif "_v62_refresh_current" in globals(): _v62_refresh_current(self)
    except Exception: pass
    _v66_set_feedback(self, f"已加载台词 {len(add)} 条到听写训练。", "ok")
    return len(add)

# ---------- 播放前置条件：音频/视频加载 ----------
def _v66_current_material(self):
    if "_v64_current_material" in globals():
        try: return _v64_current_material(self)
        except Exception: pass
    mats = getattr(self, "dictation_materials_v30", []) or []
    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    return mats[idx] if 0 <= idx < len(mats) else None

def _v66_is_text_material(m):
    if not isinstance(m, dict): return False
    kind = str(m.get("kind","")).lower()
    src = str(m.get("source_type","")).lower()
    p = str(m.get("local_path") or m.get("subtitle_path") or "")
    return kind == "text" or "text" in src or _Path_v66(p).suffix.lower() in {".txt",".srt",".vtt",".lrc",".csv"}

def _v66_play_audio(self):
    m = _v66_current_material(self)
    if not m:
        return _v66_set_feedback(self, "没有选中素材，不能播放音频。", "bad")
    # 本地音频 / 视频定点音频 / 文本TTS
    if m.get("audio_path") and _Path_v66(str(m.get("audio_path"))).exists():
        try:
            if _os_v66.name == "nt": _os_v66.startfile(str(m.get("audio_path")))
            return
        except Exception: pass
    if m.get("video_path") or m.get("media_path") or m.get("local_path"):
        # 视频素材播放音频仍可复用项目已有 chunk/audio 逻辑。
        if "_v64_play_current" in globals():
            return _v64_play_current(self)
    # 文本资源：用TTS发音。
    if "_v64_play_current" in globals():
        return _v64_play_current(self)
    _v66_set_feedback(self, "当前没有可用音频路径，且TTS不可用。", "bad")

def _v66_cache_or_download_online_video(self, m):
    url = str(m.get("video_url") or m.get("url") or "")
    if not url:
        return ""
    cfg = _v66_cfg(self).get("loading", {})
    storage = cfg.get("online_storage_mode", "缓存学习")
    if storage == "存储到本地资源":
        root = _v65_dictation_download_root(self) if "_v65_dictation_download_root" in globals() else (_Path_v66.cwd() / "playphrase_resource_hub_v54" / "dictation" / "本地视频字幕" / "play phrase网站学习资源" / _time_v66.strftime("%Y-%m-%d"))
    else:
        root = _Path_v66(cfg.get("cache_root") or (_Path_v66(_tempfile_v66.gettempdir()) / "playphrase_online_cache"))
    root.mkdir(parents=True, exist_ok=True)
    name = _re_v66.sub(r'[\\/:*?"<>|]+', "_", (_v66_extract_text_from_filename(m.get("title") or m.get("text") or "clip")[:80] or "clip")) + ".mp4"
    out = root / name
    if out.exists() and out.stat().st_size > 1024:
        return str(out)
    if "_v65_download_file" in globals():
        ok, why = _v65_download_file(url, out)
    else:
        ok, why = False, "缺少下载函数"
    if ok:
        m["video_path"] = str(out); m["media_path"] = str(out); m["local_path"] = str(out)
        # 缓存模式：注册退出删除；存储模式：刷新资源平台。
        if storage == "缓存学习" and not cfg.get("online_cache_keep_after_exit", False):
            self._v66_temp_files = getattr(self, "_v66_temp_files", [])
            self._v66_temp_files.append(str(out))
        elif storage == "存储到本地资源" and "_v65_register_download_records" in globals():
            try:
                en_srt = out.with_suffix(".en.srt")
                en_srt.write_text(f"1\n00:00:00,000 --> 00:00:03,000\n{m.get('text','')}\n\n", "utf-8")
                _v65_register_download_records(self, [{"type":"本地视频字幕","name":out.name,"status":"PlayPhrase本地视频","lines":1,"origin":"在线下载","path":str(out),"video_path":str(out),"local_path":str(out),"media_path":str(out),"subtitle_path":str(en_srt)}])
                _v65_after_resource_changed(self)
            except Exception: pass
        return str(out)
    _v66_set_feedback(self, f"在线视频下载失败：{why}", "bad")
    return ""

def _v66_play_video(self):
    m = _v66_current_material(self)
    if not m:
        return _v66_set_feedback(self, "没有选中素材，不能播放视频。", "bad")
    if _v66_is_text_material(m) and not (m.get("video_path") or m.get("media_path")):
        return _v66_set_feedback(self, "文本资源不支持视频播放；请使用音频/TTS。", "bad")
    video = str(m.get("video_path") or m.get("media_path") or "")
    if not video and str(m.get("source_type","")).startswith("online"):
        video = _v66_cache_or_download_online_video(self, m)
    if not video and m.get("local_path") and _Path_v66(str(m.get("local_path"))).suffix.lower() in {".mp4",".mkv",".avi",".mov",".webm",".m4v"}:
        video = str(m.get("local_path"))
    if not video or not _Path_v66(video).exists():
        return _v66_set_feedback(self, "当前素材没有可用视频。在线素材请在设置中心选择缓存学习或存储到本地。", "bad")
    m["video_path"] = video; m["media_path"] = video; m["local_path"] = video
    if "_v56_play_current_video" in globals():
        return _v56_play_current_video(self)
    try:
        if _os_v66.name == "nt": _os_v66.startfile(video)
    except Exception as e:
        _v66_set_feedback(self, f"视频播放失败：{e}", "bad")

def _v66_cleanup_temp_files(self):
    for p in getattr(self, "_v66_temp_files", []) or []:
        try:
            _Path_v66(p).unlink(missing_ok=True)
        except Exception:
            pass

# ---------- 设置中心添加播放/缓存策略 ----------
def _v66_open_settings_center(self):
    win = tk.Toplevel(self)
    win.title("设置中心 V66")
    win.geometry("1120x760")
    win.configure(bg=V66_PANEL)
    outer = tk.Frame(win, bg=V66_PANEL)
    outer.pack(fill="both", expand=True, padx=14, pady=12)
    tk.Label(outer, text="设置中心", bg=V66_PANEL, fg=V66_TEXT, font=("Microsoft YaHei UI", 18, "bold")).pack(anchor="w")
    tk.Label(outer, text="播放前置条件、在线缓存/本地存储、显示隐藏、自动拆分、加载设置统一在这里。",
             bg=V66_PANEL, fg=V66_MUTED).pack(anchor="w", pady=(4,10))

    nb = ttk.Notebook(outer); nb.pack(fill="both", expand=True)
    tab_play = tk.Frame(nb, bg=V66_PANEL); nb.add(tab_play, text="播放/缓存")
    tab_load = tk.Frame(nb, bg=V66_PANEL); nb.add(tab_load, text="加载设置")
    tab_display = tk.Frame(nb, bg=V66_PANEL); nb.add(tab_display, text="显示隐藏")
    tab_more = tk.Frame(nb, bg=V66_PANEL); nb.add(tab_more, text="更多设置")

    cfg = _v66_cfg(self); load = cfg["loading"]; disp = cfg.setdefault("display", {})
    def row(parent, title, desc=""):
        r=tk.Frame(parent,bg=V66_PANEL); r.pack(fill="x",padx=14,pady=8)
        l=tk.Frame(r,bg=V66_PANEL); l.pack(side="left",fill="x",expand=True)
        tk.Label(l,text=title,bg=V66_PANEL,fg=V66_TEXT,font=("Microsoft YaHei UI",11,"bold")).pack(anchor="w")
        if desc: tk.Label(l,text=desc,bg=V66_PANEL,fg=V66_MUTED,wraplength=720,justify="left").pack(anchor="w")
        return r

    play_vars={}
    play_vars["play_source_required"]=tk.BooleanVar(value=bool(load.get("play_source_required", True)))
    r=row(tab_play,"播放前置条件","必须先选择加载音频或视频。文本资源不支持视频播放，只支持TTS/音频缓存。")
    ttk.Checkbutton(r,text="开启",variable=play_vars["play_source_required"]).pack(side="right",padx=12)
    play_vars["online_storage_mode"]=tk.StringVar(value=load.get("online_storage_mode","缓存学习"))
    r=row(tab_play,"在线资源视频处理","缓存学习：临时下载，退出后不保留；存储到本地资源：写入 play phrase网站学习资源 日期文件夹并刷新资源平台。")
    ttk.Combobox(r,values=["缓存学习","存储到本地资源"],textvariable=play_vars["online_storage_mode"],state="readonly",width=20).pack(side="right",padx=12)
    play_vars["online_cache_keep_after_exit"]=tk.BooleanVar(value=bool(load.get("online_cache_keep_after_exit", False)))
    r=row(tab_play,"缓存退出后保留","默认关闭。关闭时，在线临时视频退出后删除，不写入本地资源库。")
    ttk.Checkbutton(r,text="保留缓存",variable=play_vars["online_cache_keep_after_exit"]).pack(side="right",padx=12)
    play_vars["online_download_on_video_play"]=tk.BooleanVar(value=bool(load.get("online_download_on_video_play", True)))
    r=row(tab_play,"播放在线素材时临时下载视频","在线资源选择视频播放时自动缓存视频；如果关闭则只允许文本/音频。")
    ttk.Checkbutton(r,text="开启",variable=play_vars["online_download_on_video_play"]).pack(side="right",padx=12)

    # 加载设置复用 V65 入口，但不再额外弹多个设置中心。
    tk.Label(tab_load,text="加载设置",bg=V66_PANEL,fg=V66_TEXT,font=("Microsoft YaHei UI",14,"bold")).pack(anchor="w",padx=14,pady=(14,4))
    ttk.Button(tab_load,text="安全加载精选池文本",command=lambda:_v65_import_pool_safe(self) if "_v65_import_pool_safe" in globals() else None).pack(anchor="w",padx=14,pady=6)
    ttk.Button(tab_load,text="后补下载在线资源到本地",command=lambda:_v65_download_online_resources_to_local(self) if "_v65_download_online_resources_to_local" in globals() else None).pack(anchor="w",padx=14,pady=6)
    ttk.Button(tab_load,text="文本全文翻译并写回",command=lambda:_v65_translate_text_materials_writeback(self) if "_v65_translate_text_materials_writeback" in globals() else None).pack(anchor="w",padx=14,pady=6)
    ttk.Button(tab_load,text="生成单句音频缓存",command=lambda:_v65_cache_tts_for_texts(self, full=False) if "_v65_cache_tts_for_texts" in globals() else None).pack(anchor="w",padx=14,pady=6)
    ttk.Button(tab_load,text="生成全文音频缓存",command=lambda:_v65_cache_tts_for_texts(self, full=True) if "_v65_cache_tts_for_texts" in globals() else None).pack(anchor="w",padx=14,pady=6)

    dvars={}
    for key,title in [("left_material_pool","左侧素材池"),("right_control_panel","右侧控制台"),("bottom_buttons","底部按钮区")]:
        dvars[key]=tk.BooleanVar(value=bool(disp.get(key, True)))
        r=row(tab_display,title,"显示或隐藏该区域。")
        ttk.Checkbutton(r,text="显示",variable=dvars[key]).pack(side="right",padx=12)

    if "_v63_open_settings_panel" in globals():
        ttk.Button(tab_more,text="打开综合设置（主题/音效/光标/Ctrl+H）",command=lambda:_v63_open_settings_panel(self)).pack(anchor="w",padx=14,pady=12)
    if "_v64_open_auto_split_settings" in globals():
        ttk.Button(tab_more,text="打开听写自动拆分设置",command=lambda:_v64_open_auto_split_settings(self)).pack(anchor="w",padx=14,pady=6)

    def save():
        for k,v in play_vars.items(): load[k]=v.get()
        for k,v in dvars.items(): disp[k]=bool(v.get())
        _v66_save_cfg(self)
        if "_v65_apply_display" in globals():
            try:_v65_apply_display(self)
            except Exception:pass
        try: messagebox.showinfo("已保存","设置已保存并立即生效。")
        except Exception: pass
    ttk.Button(outer,text="保存全部设置",command=save).pack(anchor="e",pady=8)

# ---------- 右侧/底部按钮修正 ----------
def _v66_rebuild_right_panel(self):
    if "_v65_rebuild_right_panel" in globals():
        try: _v65_rebuild_right_panel(self)
        except Exception: pass
    # 在右侧核心区增加清空；按钮命令切到 V66 音频/视频。
    right=getattr(self,"dictation_right_panel_v32",None)
    if right is None:return
    def walk(w):
        try:
            txt=str(w.cget("text")).strip()
            if txt in {"播放当前音频 Ctrl","播放当前音频"}:
                w.configure(command=lambda:_v66_play_audio(self))
            elif txt in {"播放当前视频","加载台词视频播放"}:
                w.configure(command=lambda:_v66_play_video(self))
            elif txt=="设置中心":
                w.configure(command=lambda:_v66_open_settings_center(self))
        except Exception: pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception: pass
    walk(right)
    if not getattr(self,"_v66_clear_right_added",False):
        try:
            # 找第一个 Notebook 的核心页
            for nb in right.winfo_children():
                if nb.winfo_class() == "TNotebook":
                    core = nb.winfo_children()[0]
                    ttk.Button(core,text="清空学习区",command=lambda:_v66_clear_learning_area(self)).pack(fill="x",pady=4)
                    self._v66_clear_right_added=True
                    break
        except Exception: pass

def _v66_rebind_buttons(self):
    def walk(w):
        try:
            txt=str(w.cget("text")).strip()
            if txt in {"播放当前音频","主播放 Ctrl","主播放 Ctrl+R"}:
                w.configure(text="播放当前音频", command=lambda:_v66_play_audio(self))
            elif txt in {"加载台词视频播放","播放当前视频"}:
                w.configure(text="播放当前视频", command=lambda:_v66_play_video(self))
            elif txt in {"窗口/全屏","学习区全屏 F11"} and "_v65_toggle_learning_fullscreen" in globals():
                w.configure(text="学习区全屏 F11", command=lambda:_v65_toggle_learning_fullscreen(self))
            elif txt in {"设置中心","设置中心 V65","设置中心 V64","设置中心 V63"}:
                w.configure(text="设置中心", command=lambda:_v66_open_settings_center(self))
        except Exception: pass
        try:
            for ch in w.winfo_children(): walk(ch)
        except Exception: pass
    walk(self)
    # 底部增加“清空学习区”按钮，避免只剩上一句/下一句。
    if not getattr(self,"_v66_clear_bottom_added",False):
        try:
            parent=None
            for b in getattr(self,"dict_v46_bottom_buttons",{}).values():
                parent=b.master; break
            if parent is not None:
                ttk.Button(parent,text="清空学习区",command=lambda:_v66_clear_learning_area(self)).pack(side="left",padx=4,pady=3)
                self._v66_clear_bottom_added=True
        except Exception: pass

def _v66_patch_globals(self):
    globals()["_v66_render_learning_area"]=_v66_render_learning_area
    globals()["_v64_render_learning_area"]=_v66_render_learning_area
    globals()["_v62_refresh_material_tree"]=_v66_refresh_material_tree
    globals()["_v62_on_tree_select"]=_v66_on_tree_select
    globals()["_v65_load_records_to_dictation"]=_v66_load_records_to_dictation
    globals()["_v60_load_records_to_dictation"]=_v66_load_records_to_dictation
    globals()["_v59_load_records_to_dictation"]=_v66_load_records_to_dictation
    globals()["_v65_open_settings_center"]=_v66_open_settings_center
    globals()["_v65_rebuild_right_panel"]=_v66_rebuild_right_panel
    globals()["_v64_play_current"]=_v66_play_audio
    globals()["_v56_play_current_video"]=_v66_play_video
    try:
        self.protocol("WM_DELETE_WINDOW", lambda: (_v66_cleanup_temp_files(self), self.destroy()))
    except Exception: pass

_old_main_init_v66 = MainApp.__init__
def _main_init_v66(self):
    _old_main_init_v66(self)
    try:
        _v66_cfg(self)
        _v66_patch_globals(self)
        _v66_rebuild_right_panel(self)
        _v66_rebind_buttons(self)
        try:
            tree=getattr(self,"dict_material_tree_v46",None)
            if tree is not None:
                tree.bind("<<TreeviewSelect>>", lambda e:_v66_on_tree_select(self,e))
                tree.bind("<<TreeviewOpen>>", lambda e:_v66_on_tree_select(self,e))
        except Exception: pass
        try:
            self.after(350, lambda:(_v66_patch_globals(self),_v66_rebuild_right_panel(self),_v66_rebind_buttons(self),_v66_relocate_fixed_hint(self)))
            self.after(1400, lambda:(_v66_rebind_buttons(self),_v66_refresh_material_tree(self)))
        except Exception: pass
        self.log("【V66上线】固定提示已下移到输入横线下方，不再遮挡。", "ok")
        self.log("【V66上线】素材树文件节点可直接展开台词；选中文件/分页会自动选中第一句。", "ok")
        self.log("【V66上线】新增清空学习区；音频/视频播放按前置条件区分，文本不支持视频。", "ok")
        self.log("【V66上线】在线资源默认缓存学习，退出不保留；可在设置中心改为存储到本地资源。", "ok")
    except Exception as e:
        try:self.log(f"V66初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:pass

MainApp.__init__=_main_init_v66
APP_TITLE="PlayPhrase Studio Clean v66 · 固定提示与播放缓存逻辑修复版"


# ──────────────────────────────────────────────────────────────────────
# V67：设置中心完整回归 + 资源/在线素材可加载 + 渲染递归修复
# 重点修复：
# 1) 所有 V67 弹窗底部都有【关闭】按钮；资源平台也补关闭按钮。
# 2) 听写设置集中放入设置中心：不再在主界面重复堆放“听写自动拆分/快捷键设置/多个设置中心”。
# 3) 设置中心恢复：路径设置、音效设置、主题颜色、显示隐藏、播放/缓存、加载设置、自动拆分。
# 4) 修复 V66 渲染递归导致“点素材树不进学习区”的问题。
# 5) 资源平台选中的本地视频/字幕/文本资源可以真正加载到听写训练。
# 6) 在线精选池双击/选择后能进学习区；“同时下载到本地”不再卡在下载中。
# ──────────────────────────────────────────────────────────────────────
