        ("online_cache_keep_after_exit", "缓存退出后保留", "默认关闭。关闭时在线临时视频退出后删除。", "bool", None),
        ("online_download_video", "下载视频文件", "开启后后补下载/同时下载会尝试保存视频。无URL时仍写入字幕。", "bool", None),
