        ("online_translate_engine", "在线资源翻译引擎", "默认 OPUS-MT 本地。", "combo", ["OPUS-MT 本地", "Argos 本地", "Google 在线", "百度API", "腾讯API", "DeepL"]),
        ("online_write_origin_subtitle", "写入原文字幕", "生成 .en.srt。", "bool", None),
