def _v68_cfg(self):
    if "_v67_cfg" in globals():
        try:
            cfg = _v67_cfg(self)
        except Exception:
            cfg = {}
    else:
        cfg = getattr(self, "v63_cfg", {}) if hasattr(self, "v63_cfg") else {}
    if not isinstance(cfg, dict):
        cfg = {}
    cfg.setdefault("dictation", {})
    cfg["dictation"].setdefault("online_chunk_calibration", False)
    cfg["dictation"].setdefault("chunk_strategy", "结构优先")
    cfg["dictation"].setdefault("split_inner_gap", 3)
    cfg["dictation"].setdefault("split_group_gap", 10)
    cfg.setdefault("display", {})
    cfg["display"].setdefault("show_operation_tips", True)
    cfg.setdefault("paths", {})
    cfg["paths"].setdefault("operation_log", str(_Path_v68.cwd() / "playphrase_output" / "operation_status.log"))
    self.v63_cfg = cfg
    return cfg

def _v68_save_cfg(self):
    if "_v67_save_cfg" in globals():
        try:
            return _v67_save_cfg(self)
        except Exception:
            pass
    try:
        (_Path_v68.cwd() / "pp_studio_v68_settings.json").write_text(_json_v68.dumps(_v68_cfg(self), ensure_ascii=False, indent=2), "utf-8")
    except Exception:
        pass

def _v68_now():
    return _time_v68.strftime("%H:%M:%S")

def _v68_notice(self, msg, level="info", mode="dictation"):
    # 所有操作都给界面提示，同时写日志。
    msg = str(msg)
    full = f"[{_v68_now()}] {msg}"
    try:
        if hasattr(self, "dict_v68_notice_var"):
            self.dict_v68_notice_var.set(full)
    except Exception:
        pass
    try:
        if mode in ("dictation", "recite") and hasattr(self, f"v59_{mode}_status"):
            getattr(self, f"v59_{mode}_status").set(full)
    except Exception:
        pass
    try:
        if "_v67_status" in globals():
            _v67_status(self, msg, level)
        elif "_v65_set_feedback" in globals():
            _v65_set_feedback(self, msg, level)
    except Exception:
        pass
    try:
        self.log(msg, "ok" if level == "ok" else ("err" if level in ("bad","err") else "info"))
    except Exception:
        pass
    try:
        p = _Path_v68(_v68_cfg(self).get("paths", {}).get("operation_log", "operation_status.log"))
        p.parent.mkdir(parents=True, exist_ok=True)
        with p.open("a", encoding="utf-8") as f:
            f.write(full + "\n")
    except Exception:
        pass

# ---------- 语块智能拆分 ----------
def _v68_words(text):
    return _re_v68.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(text or ""))

def _v68_protect_phrases(words):
    low = [w.lower() for w in words]
    used = [False] * len(words)
    groups = []
    i = 0
    phrase_map = sorted([p.split() for p in _V68_FIXED_PHRASES], key=len, reverse=True)
    while i < len(words):
        hit = None
        for ph in phrase_map:
            n = len(ph)
            if i + n <= len(words) and low[i:i+n] == ph:
                hit = n
                break
        if hit:
            groups.append(words[i:i+hit])
            for j in range(i, i+hit):
                used[j] = True
            i += hit
        else:
            groups.append([words[i]])
            i += 1
    return groups

def _v68_role_for_group(group):
    low = [x.lower() for x in group]
    if " ".join(low) in _V68_FIXED_PHRASES:
        return "固定短语"
    if low and low[0] in _V68_CONJ:
        return "连接词/从句"
    if low and low[0] in _V68_PREP:
        return "介词短语"
    if low and low[0] in _V68_ART:
        return "冠词 + 名词短语"
    if any(x in {"am","is","are","was","were","be","been","being","have","has","had","do","does","did","will","would","can","could","should","may","might","must"} for x in low):
        return "主句/谓语结构"
    if all(x in _V68_PRON for x in low[:1]):
        return "人称/物主代词"
    if len(group) >= 3:
        return "名词短语/谓语块"
    return "语块"

def _v68_merge_singletons(groups, max_len=4):
    merged = []
    buf = []
    for g in groups:
        # 连接词单独成块；固定短语单独保护
        text = " ".join(x.lower() for x in g)
        if text in _V68_FIXED_PHRASES or (g and g[0].lower() in _V68_CONJ):
            if buf:
                merged.append(buf); buf = []
            merged.append(g)
        else:
            if len(buf) + len(g) <= max_len:
                buf += g
            else:
                if buf: merged.append(buf)
                buf = list(g)
    if buf:
        merged.append(buf)
    return merged

def _v68_smart_chunks(self, text, mode=None):
    words = _v68_words(text)
    if not words:
        return []
    cfg = _v68_cfg(self).get("dictation", {})
    # 联网校准：这里保留真实开关，但没有 API/网络配置时不会阻塞。
    if cfg.get("online_chunk_calibration", False):
        _v68_notice(self, "联网校准已开启：当前未配置在线句法服务，已使用本地结构拆分兜底。", "info")
    protected = _v68_protect_phrases(words)
    groups = _v68_merge_singletons(protected, max_len=4)
    # 再按长度控制，防止一个语块过长。
    final = []
    for g in groups:
        if len(g) <= 5:
            final.append(g)
        else:
            for i in range(0, len(g), 4):
                final.append(g[i:i+4])
    return [{"text": " ".join(g), "words": g, "role": _v68_role_for_group(g), "unit": "phrase"} for g in final]

def _v68_sentence_type_count(n):
    if n <= 8: return "超短句"
    if n <= 12: return "短句"
    if n <= 20: return "中句"
    if n <= 32: return "长句"
    return "超长句"

def _v68_width(text, mode):
    if mode == "拆分播放":
        return max(3, min(8, len(str(text)) + 1))
    return max(8, min(42, len(str(text)) + 2))

# ---------- 听写学习区重构：拆分模式也按语块成组 ----------
def _v68_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in list(parent.winfo_children()):
        try: ch.destroy()
        except Exception: pass

    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        tk.Label(parent, text="当前没有素材：请从左侧素材池或资源平台加载",
                 bg=V68_BG, fg=V68_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return

    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    idx = max(0, min(idx, len(mats)-1))
    self.dictation_index_v30 = idx
    m = mats[idx]
    text = (str(m.get("text") or m.get("en") or "") if isinstance(m, dict) else str(m))
    zh = (str(m.get("zh") or m.get("cn") or m.get("translation") or "") if isinstance(m, dict) else "")
    words = _v68_words(text)
    mode = getattr(getattr(self, "dict_play_mode_v46", None), "get", lambda: "整句播放")()
    if mode not in ("整句播放", "拆分播放"):
        mode = "整句播放"

    top = tk.Frame(parent, bg=V68_BG)
    top.pack(fill="x", pady=(16, 4))
    show_cn = True
    try:
        show_cn = bool(getattr(self, "dictation_show_cn_v30", tk.BooleanVar(value=True)).get())
    except Exception:
        pass
    tk.Label(top, text=(zh if show_cn and zh else ("中文翻译/提示未加载" if show_cn else "盲听模式：中文翻译和提示已隐藏")),
             bg=V68_BG, fg=V68_TEXT if show_cn else V68_MUTED,
             font=("Microsoft YaHei UI", 20, "bold"), wraplength=1150, justify="center").pack(anchor="center")

    ctl = tk.Frame(parent, bg=V68_BG)
    ctl.pack(anchor="center", pady=(5, 7))
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    cb = ttk.Combobox(ctl, textvariable=self.dict_play_mode_v46, values=["整句播放", "拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=4)
    cb.bind("<<ComboboxSelected>>", lambda e: _v68_render_learning_area(self))
    ttk.Button(ctl, text="播放音频", command=lambda: _v68_play_audio(self)).pack(side="left", padx=4)
    ttk.Button(ctl, text="播放视频", command=lambda: _v68_play_video(self)).pack(side="left", padx=4)
    ttk.Button(ctl, text="跳过当前块", command=lambda: _v62_skip_chunk(self) if "_v62_skip_chunk" in globals() else None).pack(side="left", padx=4)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    ttk.Checkbutton(ctl, text="自动跳到下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=7)

    chunks = _v68_smart_chunks(self, text, mode)
    sent_type = _v68_sentence_type_count(len(words))
    tk.Label(parent, text=f"句长：{len(words)}词｜类型：{sent_type}｜呈现：语块分组｜拆分模式：组内间隔3字符，组间间隔10字符",
             bg=V68_BG, fg=V68_MUTED, font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(0, 6))

    board = tk.Frame(parent, bg=V68_BG)
    board.pack(anchor="center", padx=16, pady=(4, 6))
    self.dict_v46_entries = []

    if mode == "拆分播放":
        # 语块分组，组内每个单词一条横线。
        line = None
        used_chars = 0
        max_chars = 92
        inner_gap_px = 3 * 8
        group_gap_px = 10 * 8
        for gi, ch in enumerate(chunks):
            g_words = ch.get("words") or _v68_words(ch.get("text",""))
            group_chars = sum(min(8, max(3, len(w)+1)) for w in g_words) + (len(g_words)-1)*3 + 10
            if line is None or used_chars + group_chars > max_chars:
                line = tk.Frame(board, bg=V68_BG)
                line.pack(anchor="center", pady=8)
                used_chars = 0
            group_frame = tk.Frame(line, bg=V68_BG)
            group_frame.pack(side="left", padx=(group_gap_px if gi else 0, 0), pady=2)
            word_row = tk.Frame(group_frame, bg=V68_BG)
            word_row.pack(anchor="center")
            role = ch.get("role") or "语块"
            for wi, w in enumerate(g_words):
                cell = tk.Frame(word_row, bg=V68_BG)
                cell.pack(side="left", padx=(0 if wi == 0 else inner_gap_px, 0))
                width = _v68_width(w, mode)
                ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V68_BG, fg=V68_INPUT,
                              insertbackground=V68_INPUT, relief="flat", bd=0,
                              font=("Consolas", 19, "bold"), undo=False)
                ent.pack()
                cw = max(58, min(120, width * 15))
                cv = tk.Canvas(cell, width=cw, height=8, bg=V68_BG, highlightthickness=0)
                cv.pack()
                cv.create_line(2, 4, cw-2, 4, fill=V68_INPUT if not self.dict_v46_entries else V68_LINE, width=3)
                item = {"idx": len(self.dict_v46_entries), "target": w, "role": role, "entry": ent, "line": cv, "w": cw, "group": gi}
                self.dict_v46_entries.append(item)
                if "_v62_live_entry" in globals(): ent.bind("<KeyRelease>", lambda e, it=item: _v62_live_entry(self, it))
                if "_v62_space_entry" in globals(): ent.bind("<space>", lambda e, it=item: _v62_space_entry(self, it))
                if "_v62_submit_all" in globals(): ent.bind("<Return>", lambda e: (_v62_submit_all(self), "break"))
                ent.bind("<Control-h>", lambda e: (_v68_hint_current(self), "break"))
            tk.Label(group_frame, text=role, bg=V68_BG, fg=V68_MUTED,
                     font=("Microsoft YaHei UI", 8, "bold")).pack(anchor="center", pady=(4,0))
            used_chars += group_chars
    else:
        # 整句模式：每个语块一条横线，可多个单词共用横线。
        line = None
        used_chars = 0
        max_chars = 96
        for gi, ch in enumerate(chunks):
            tx = ch.get("text","")
            width = _v68_width(tx, mode)
            if line is None or used_chars + width > max_chars:
                line = tk.Frame(board, bg=V68_BG)
                line.pack(anchor="center", pady=8)
                used_chars = 0
            cell = tk.Frame(line, bg=V68_BG)
            cell.pack(side="left", padx=20, pady=2)
            ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V68_BG, fg=V68_INPUT,
                          insertbackground=V68_INPUT, relief="flat", bd=0,
                          font=("Consolas", 20, "bold"), undo=False)
            ent.pack()
            cw = max(130, min(600, width * 15))
            cv = tk.Canvas(cell, width=cw, height=8, bg=V68_BG, highlightthickness=0)
            cv.pack()
            cv.create_line(2, 4, cw-2, 4, fill=V68_INPUT if gi == 0 else V68_LINE, width=3)
            role = ch.get("role") or "语块"
            tk.Label(cell, text=role, bg=V68_BG, fg=V68_MUTED,
                     font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
            item = {"idx": len(self.dict_v46_entries), "target": tx, "role": role, "entry": ent, "line": cv, "w": cw, "group": gi}
            self.dict_v46_entries.append(item)
            if "_v62_live_entry" in globals(): ent.bind("<KeyRelease>", lambda e, it=item: _v62_live_entry(self, it))
            if "_v62_space_entry" in globals(): ent.bind("<space>", lambda e, it=item: _v62_space_entry(self, it))
            if "_v62_submit_all" in globals(): ent.bind("<Return>", lambda e: (_v62_submit_all(self), "break"))
            ent.bind("<Control-h>", lambda e: (_v68_hint_current(self), "break"))
            used_chars += width + 6

    hint_panel = tk.Frame(parent, bg="#0f172a", bd=1, relief="solid")
    hint_panel.pack(fill="x", padx=120, pady=(16, 6))
    tk.Label(hint_panel, text="固定提示 / 六步提示", bg="#0f172a", fg=V68_TEXT,
             font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w", padx=12, pady=(8, 2))
    if not hasattr(self, "dict_v62_side_var"):
        self.dict_v62_side_var = tk.StringVar(value="")
    self.dict_v62_side_var.set("按 Ctrl+H：音标 → 同音词 → 近反义词 → 首尾字母 → 英文释义 → 同形词/答案。")
    tk.Label(hint_panel, textvariable=self.dict_v62_side_var, bg="#0f172a", fg=V68_MUTED,
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0, 4))
    if not hasattr(self, "dict_v63_hint_var"):
        self.dict_v63_hint_var = tk.StringVar(value="")
    self.dict_v63_hint_var.set("")
    tk.Label(hint_panel, textvariable=self.dict_v63_hint_var, bg="#0f172a", fg="#38BDF8",
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0, 8))

    if not hasattr(self, "dict_v68_notice_var"):
        self.dict_v68_notice_var = tk.StringVar(value="就绪")
    tk.Label(parent, textvariable=self.dict_v68_notice_var, bg="#07111f", fg=V68_MUTED,
             font=("Microsoft YaHei UI", 11, "bold"), anchor="w").pack(fill="x", padx=18, pady=(4, 0), side="bottom")

    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    _v68_notice(self, "学习区已刷新：语块分组和六步提示已就绪。", "ok")

def _v68_refresh_current(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    try:
        if hasattr(self, "dictation_target_meta_var_v30"):
            m = mats[idx] if 0 <= idx < len(mats) else {}
            text = _v68_item_text(m) if "_v68_item_text" in globals() else (m.get("text","") if isinstance(m,dict) else "")
            self.dictation_target_meta_var_v30.set(f"{idx+1}/{len(mats)}｜{text[:80]}")
    except Exception:
        pass
    _v68_render_learning_area(self)

def _v68_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

# ---------- 六步提示 ----------
def _v68_active_target(self):
    focus = None
    try: focus = self.focus_get()
    except Exception: pass
    entries = getattr(self, "dict_v46_entries", []) or []
    for item in entries:
        if item.get("entry") is focus:
            return item
    return entries[0] if entries else None

def _v68_base_word(target):
    toks = _v68_words(target)
    return toks[0].lower() if toks else str(target or "").strip().lower()

def _v68_hint_current(self):
    item = _v68_active_target(self)
    if not item:
        _v68_notice(self, "当前没有可提示的输入块。", "bad")
        return
    target = str(item.get("target") or "")
    word = _v68_base_word(target)
    self._v68_hint_step = (getattr(self, "_v68_hint_step", 0) % 6) + 1
    step = self._v68_hint_step
    role = item.get("role", "语块")
    if step == 1:
        val = _V68_COMMON_IPA.get(word, f"未命中本地音标；可在设置中心配置本地词典目录后扩展。目标词：{word}")
        title = "① 音标提示"
    elif step == 2:
        val = " / ".join(_V68_HOMOPHONES.get(word, [])) or "本地未记录同音词。"
        title = "② 同音词提示"
    elif step == 3:
        d = _V68_SYNONYMS.get(word, {})
        val = f"近义：{', '.join(d.get('近义', [])) or '未记录'}；反义：{', '.join(d.get('反义', [])) or '未记录'}"
        title = "③ 近义/反义提示"
    elif step == 4:
        if len(word) >= 2:
            val = f"首字母：{word[0]}；末尾字母：{word[-1]}；长度：{len(word)}"
        else:
            val = f"答案长度：{len(word)}"
        title = "④ 首尾字母提示"
    elif step == 5:
        val = _V68_DEFS.get(word, "本地释义未命中；建议接入本地词典或在线词典 API 做校准。")
        title = "⑤ 英文释义提示"
    else:
        # 同形词没有则给答案
        val = f"正确答案：{target}"
        title = "⑥ 同形词/答案提示"
    msg = f"{title}｜当前块：{target}｜结构：{role}\n{val}"
    try:
        self.dict_v63_hint_var.set(msg)
        self.dict_v62_side_var.set("六步提示已固定显示；继续按 Ctrl+H 切换下一层提示。")
    except Exception:
        pass
    _v68_notice(self, f"提示更新：{title}", "info")

# ---------- 资源平台内嵌到“我的资源站”标签 ----------
def _v68_build_resource_platform_inline(self):
    p = getattr(self, "tab_resource_platform_v32", None)
    if p is None:
        return
    for child in list(p.winfo_children()):
        try: child.destroy()
        except Exception: pass
    _v59_init_dirs(self)
    outer = ttk.Frame(p, padding=10)
    outer.pack(fill="both", expand=True)
    top = ttk.Frame(outer)
    top.pack(fill="x", pady=(0, 8))
    ttk.Label(top, text="资源平台根目录").pack(side="left")
    ttk.Entry(top, textvariable=self.v54_resource_root_var, width=90).pack(side="left", padx=8)
    ttk.Button(top, text="选择根目录", command=lambda: (_v59_choose_root(self), _v68_notice(self, "资源平台根目录已选择/更新。", "ok"))).pack(side="left", padx=3)
    ttk.Button(top, text="初始化目录", command=lambda: (_v59_init_dirs(self), _v59_refresh_tree(self, "dictation"), _v59_refresh_tree(self, "recite"), _v68_notice(self, "资源平台目录已初始化。", "ok"))).pack(side="left", padx=3)
    if not hasattr(self, "resource_v68_status_var"):
        self.resource_v68_status_var = tk.StringVar(value="就绪：资源平台直接显示在此标签页。")
    ttk.Label(top, textvariable=self.resource_v68_status_var).pack(side="left", padx=16)
    nb = ttk.Notebook(outer)
    nb.pack(fill="both", expand=True)
    t1 = ttk.Frame(nb)
    t2 = ttk.Frame(nb)
    nb.add(t1, text="听写资源库")
    nb.add(t2, text="背诵资源库")
    _v68_build_platform_tab(self, t1, "dictation")
    _v68_build_platform_tab(self, t2, "recite")
    _v68_notice(self, "资源平台已在【我的资源站】标签页内直接显示。", "ok")

def _v68_build_platform_tab(self, parent, mode):
    root = ttk.Frame(parent, padding=10)
    root.pack(fill="both", expand=True)
    top = ttk.Frame(root)
    top.pack(fill="x", pady=(0, 8))
    ttk.Label(top, text="听写资源库" if mode == "dictation" else "背诵资源库").pack(side="left")
    ops = [
        ("新建文件夹", lambda: (_v59_new_folder(self, mode), _v68_notice(self, "已执行新建文件夹。", "ok", mode))),
        ("删除文件夹", lambda: (_v59_delete_folder(self, mode), _v68_notice(self, "已执行删除文件夹。", "ok", mode))),
        ("添加文件路径并扫描", lambda: _v68_add_path(self, mode, False)),
        ("添加文件夹路径并扫描", lambda: _v68_add_path(self, mode, True)),
        ("后台扫描", lambda: _v68_scan_selected_async(self, mode)),
        ("刷新", lambda: (_v59_refresh_tree(self, mode), _v68_refresh_table(self, mode), _v68_notice(self, "资源列表已刷新。", "ok", mode))),
    ]
    for text, cmd in ops:
        ttk.Button(top, text=text, command=cmd).pack(side="left", padx=3)
    if mode == "dictation":
        ttk.Button(top, text="加载选中到听写训练", style="Accent.TButton", command=lambda: _v68_load_selected_to_training(self, "dictation")).pack(side="left", padx=12)
    setattr(self, f"v59_{mode}_search", tk.StringVar())
    ttk.Label(top, text="搜索").pack(side="left", padx=(18, 3))
    ttk.Entry(top, textvariable=getattr(self, f"v59_{mode}_search"), width=24).pack(side="left")
    ttk.Button(top, text="查找", command=lambda: _v68_refresh_table(self, mode)).pack(side="left", padx=3)

    pane = ttk.Panedwindow(root, orient="horizontal")
    pane.pack(fill="both", expand=True)
    left = ttk.Frame(pane, padding=4)
    right = ttk.Frame(pane, padding=4)
    pane.add(left, weight=1)
    pane.add(right, weight=4)

    tree = ttk.Treeview(left, show="tree", height=30)
    y1 = ttk.Scrollbar(left, orient="vertical", command=tree.yview)
    tree.configure(yscrollcommand=y1.set)
    tree.pack(side="left", fill="both", expand=True)
    y1.pack(side="right", fill="y")
    setattr(self, f"v59_{mode}_tree", tree)
    setattr(self, f"v54_{mode}_tree", tree)
    tree.bind("<<TreeviewSelect>>", lambda e: _v68_refresh_table(self, mode))

    cnt = tk.StringVar(value="0 条资源")
    setattr(self, f"v59_{mode}_count", cnt)
    setattr(self, f"v54_{mode}_count", cnt)
    ttk.Label(right, textvariable=cnt).pack(anchor="w")
    frame = ttk.Frame(right)
    frame.pack(fill="both", expand=True)
    cols = ("type", "name", "status", "lines", "origin", "path")
    table = ttk.Treeview(frame, columns=cols, show="headings", height=28)
    setattr(self, f"v59_{mode}_table", table)
    setattr(self, f"v54_{mode}_table", table)
    vs = ttk.Scrollbar(frame, orient="vertical", command=table.yview)
    hs = ttk.Scrollbar(frame, orient="horizontal", command=table.xview)
    table.configure(yscrollcommand=vs.set, xscrollcommand=hs.set)
    heads = {"type":"类型","name":"文件名","status":"状态","lines":"行数","origin":"来源","path":"路径"}
    widths = {"type":120,"name":300,"status":150,"lines":70,"origin":110,"path":900}
    for c in cols:
        table.heading(c, text=heads[c])
        table.column(c, width=widths[c], anchor="w")
    table.grid(row=0, column=0, sticky="nsew")
    vs.grid(row=0, column=1, sticky="ns")
    hs.grid(row=1, column=0, sticky="ew")
    frame.rowconfigure(0, weight=1)
    frame.columnconfigure(0, weight=1)
    table.bind("<Double-1>", lambda e: _v68_load_selected_to_training(self, mode) if mode=="dictation" else _v68_notice(self, "背诵资源双击加载后续独立处理。", "info", mode))

    st = tk.StringVar(value="就绪：添加路径后自动后台扫描，扫描和加载都有提示。")
    setattr(self, f"v59_{mode}_status", st)
    setattr(self, f"v54_{mode}_status", st)
    ttk.Label(root, textvariable=st).pack(fill="x", pady=(8, 0))
    _v59_refresh_tree(self, mode)
    _v68_refresh_table(self, mode)

def _v68_add_path(self, mode, is_folder):
    _v68_notice(self, "请选择要添加的文件夹/文件。", "info", mode)
    if "_v59_add_path" in globals():
        _v59_add_path(self, mode, is_folder)
        _v68_notice(self, "路径已登记，正在后台扫描；扫描完成后资源表会刷新。", "info", mode)

def _v68_scan_selected_async(self, mode):
    _v68_notice(self, "开始后台递归扫描，请稍候。", "info", mode)
    if "_v59_scan_selected_async" in globals():
        return _v59_scan_selected_async(self, mode)
    _v68_notice(self, "当前版本没有找到扫描函数。", "bad", mode)

# ---------- 表格分批刷新，避免卡顿 ----------
def _v68_selected_folder(self, mode):
    if "_v59_selected_folder" in globals():
        try: return _v59_selected_folder(self, mode)
        except Exception: return None
    return None

def _v68_refresh_table(self, mode):
    table = getattr(self, f"v59_{mode}_table", None) or getattr(self, f"v54_{mode}_table", None)
    if table is None:
        return
    try: table.delete(*table.get_children())
    except Exception: pass
    try:
        _, data = _v59_index(self, mode)
        rows = data.get("records", [])
    except Exception:
        rows = []
    sel = _v68_selected_folder(self, mode)
    if sel:
        top, fol = sel
        rows = [r for r in rows if r.get("top") == top and (not fol or r.get("folder") == fol)]
    qv = getattr(self, f"v59_{mode}_search", None) or getattr(self, f"v54_{mode}_search", None)
    q = qv.get().lower().strip() if qv else ""
    if q:
        rows = [r for r in rows if q in r.get("name","").lower() or q in r.get("path","").lower() or q in r.get("type","").lower() or q in r.get("status","").lower()]
    setattr(self, f"v59_{mode}_rows", rows)
    max_rows = globals().get("V59_MAX_TABLE_ROWS", 5000)
    rows_show = rows[:max_rows]
    cv = getattr(self, f"v59_{mode}_count", None) or getattr(self, f"v54_{mode}_count", None)
    if cv:
        cv.set(f"{len(rows)} 条资源" + (f"（分批显示前 {max_rows}）" if len(rows) > max_rows else ""))
    _v68_notice(self, f"正在刷新资源表：{len(rows_show)} 条。", "info", mode)

    def insert_batch(start=0, batch=180):
        end = min(start + batch, len(rows_show))
        for i in range(start, end):
            r = rows_show[i]
            try:
                table.insert("", "end", iid=str(i), values=(r.get("type",""), r.get("name",""), r.get("status",""), r.get("lines",""), r.get("origin",""), r.get("path","")))
            except Exception:
                pass
        if end < len(rows_show):
            try:
                table.after(1, lambda: insert_batch(end, batch))
            except Exception:
                insert_batch(end, batch)
        else:
            _v68_notice(self, f"资源表刷新完成：显示 {len(rows_show)} 条。", "ok", mode)
    insert_batch(0)

# ---------- 资源加载 ----------
def _v68_load_records_to_dictation(self, records, clear_existing=False):
    if "_v67_load_records_to_dictation" in globals():
        n = _v67_load_records_to_dictation(self, records, clear_existing=clear_existing)
    else:
        n = 0
    if n:
        _v68_notice(self, f"资源加载完成：{n} 条台词已进入听写训练。", "ok")
    else:
        _v68_notice(self, "资源加载失败或没有可练习台词。", "bad")
    return n

def _v68_collect_selected_resource_records(self, mode="dictation"):
    if "_v67_collect_selected_resource_records" in globals():
        try:
            return _v67_collect_selected_resource_records(self, mode)
        except Exception:
            pass
    table = getattr(self, f"v59_{mode}_table", None) or getattr(self, f"v54_{mode}_table", None)
    rows = getattr(self, f"v59_{mode}_rows", []) or getattr(self, f"v54_{mode}_rows", [])
    selected = []
    if table is not None:
        for iid in table.selection():
            try: selected.append(rows[int(iid)])
            except Exception: pass
    return selected or rows[:500]

def _v68_load_selected_to_training(self, mode="dictation"):
    if mode != "dictation":
        _v68_notice(self, "背诵资源加载链后续独立处理；当前只加载听写训练。", "info", mode)
        return
    records = _v68_collect_selected_resource_records(self, mode)
    if not records:
        _v68_notice(self, "没有选中资源，也没有可加载列表。", "bad", mode)
        return
    _v68_notice(self, f"开始加载选中资源：{len(records)} 条记录。", "info", mode)
    def worker():
        try:
            self.after(0, lambda: _v68_load_records_to_dictation(self, records, clear_existing=False))
        except Exception:
            pass
    _threading_v68.Thread(target=worker, daemon=True).start()

