def _v69_deep_update(a, b):
    for k, v in b.items():
        if isinstance(v, dict):
            a.setdefault(k, {})
            if isinstance(a[k], dict):
                _v69_deep_update(a[k], v)
            else:
                a[k] = dict(v)
        else:
            a.setdefault(k, v)
    return a

def _v69_cfg(self):
    cfg = {}
    try:
        p = _v69_json_path(self)
        if p.exists():
            cfg = _json_v69.loads(p.read_text("utf-8"))
    except Exception:
        cfg = {}
    if not isinstance(cfg, dict):
        cfg = {}
    cfg = _v69_deep_update(cfg, _v69_default_cfg())
    self.v69_cfg = cfg
    try:
        self.v63_cfg = cfg
    except Exception:
        pass
    return cfg

def _v69_save_cfg(self):
    cfg = getattr(self, "v69_cfg", None) or _v69_cfg(self)
    try:
        p = _v69_json_path(self)
        p.write_text(_json_v69.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
    except Exception as e:
        _v69_notice(self, f"设置保存失败：{type(e).__name__}: {e}", "bad")

def _v69_now():
    return _time_v69.strftime("%H:%M:%S")

def _v69_notice(self, msg, level="info", scope="dictation"):
    msg = str(msg)
    full = f"[{_v69_now()}] {msg}"
    for attr in ["dict_v69_notice_var", "resource_v69_status_var"]:
        try:
            if hasattr(self, attr):
                getattr(self, attr).set(full)
        except Exception:
            pass
    try:
        if scope in ("dictation", "recite") and hasattr(self, f"v69_{scope}_status"):
            getattr(self, f"v69_{scope}_status").set(full)
    except Exception:
        pass
    try:
        if hasattr(self, "status_var"):
            self.status_var.set(msg)
    except Exception:
        pass
    try:
        self.log(msg, "ok" if level == "ok" else ("err" if level in ("bad", "err") else "info"))
    except Exception:
        pass
    try:
        p = _Path_v69(_v69_cfg(self)["paths"]["operation_log"])
        p.parent.mkdir(parents=True, exist_ok=True)
        with p.open("a", encoding="utf-8") as f:
            f.write(full + "\n")
    except Exception:
        pass

# ── 文本/字幕解析 ─────────────────────────────────────────────────────
def _v69_has_en(s):
    return bool(_re_v69.search(r"[A-Za-z]{2,}", str(s or "")))

def _v69_clean_text(s):
    s = _re_v69.sub(r"<[^>]+>", "", str(s or ""))
    s = _re_v69.sub(r"\{\\.*?\}", "", s)
    return _re_v69.sub(r"\s+", " ", s).strip()

def _v69_parse_time(t):
    t = str(t or "").replace(",", ".")
    ps = t.split(":")
    try:
        if len(ps) == 3:
            return int(ps[0]) * 3600 + int(ps[1]) * 60 + float(ps[2])
        if len(ps) == 2:
            return int(ps[0]) * 60 + float(ps[1])
    except Exception:
        return 0.0
    return 0.0

def _v69_parse_subtitle_or_text(path):
    p = _Path_v69(str(path))
    if not p.exists():
        return []
    raw = p.read_text("utf-8-sig", errors="ignore").replace("\r\n", "\n").replace("\r", "\n")
    out = []
    time_re = _re_v69.compile(r"(?P<s>\d{1,2}:\d{2}(?::\d{2})?[,\.]\d{1,3})\s*-->\s*(?P<e>\d{1,2}:\d{2}(?::\d{2})?[,\.]\d{1,3})")
    blocks = _re_v69.split(r"\n\s*\n", raw)
    for b in blocks:
        lines = [x.strip() for x in b.splitlines() if x.strip()]
        if not lines:
            continue
        st = et = 0.0
        en, zh = [], []
        for line in lines:
            if _re_v69.fullmatch(r"\d+", line):
                continue
            mt = time_re.search(line)
            if mt:
                st = _v69_parse_time(mt.group("s")); et = _v69_parse_time(mt.group("e"))
                continue
            line = _v69_clean_text(line)
            if not line:
                continue
            if _v69_has_en(line):
                en.append(line)
            elif _re_v69.search(r"[\u4e00-\u9fff]", line):
                zh.append(line)
        if en:
            out.append({"text": " ".join(en), "zh": " ".join(zh), "start": st, "end": et})
    if out:
        return out

    # 普通 TXT/LRC 兜底
    for line in raw.splitlines():
        line = _v69_clean_text(_re_v69.sub(r"^\[\d{1,2}:\d{2}(?:\.\d{1,3})?\]", "", line))
        if not line or "-->" in line or _re_v69.fullmatch(r"\d+", line):
            continue
        if _v69_has_en(line):
            out.append({"text": line, "zh": "", "start": 0.0, "end": 0.0})
    return out

def _v69_sidecar_sub(video_path):
    p = _Path_v69(str(video_path))
    if not p.exists():
        return None
    for ext in [".srt", ".ass", ".ssa", ".vtt", ".txt", ".lrc"]:
        c = p.with_suffix(ext)
        if c.exists():
            return c
    for ext in [".srt", ".ass", ".ssa", ".vtt", ".txt", ".lrc"]:
        for c in p.parent.glob(p.stem + "*" + ext):
            if c.exists():
                return c
    return None

def _v69_filename_text(path):
    name = _Path_v69(str(path)).stem
    name = _re_v69.sub(r"^\d{1,6}[_\-. ]*", "", name)
    name = _re_v69.sub(r"\[[^\]]+\]|\([^\)]*\)", " ", name)
    name = name.replace("_", " ").replace("-", " ")
    name = _re_v69.sub(r"\b(1080p|720p|2160p|x264|x265|h264|h265|web|dl|bluray|aac|mp4|mkv|avi|hevc)\b", " ", name, flags=_re_v69.I)
    return _re_v69.sub(r"\s+", " ", name).strip(" ._-")

def _v69_record_to_materials(record):
    if not isinstance(record, dict):
        return [], ["非法资源记录"]
    direct_text = str(record.get("text") or record.get("en") or "")
    if direct_text and _v69_has_en(direct_text):
        return [{
            "text": direct_text,
            "zh": str(record.get("zh") or record.get("cn") or record.get("translation") or ""),
            "title": str(record.get("title") or record.get("name") or "在线精选池"),
            "source_type": str(record.get("source_type") or "online_pool"),
            "kind": str(record.get("kind") or "online"),
            "url": str(record.get("url") or record.get("video_url") or ""),
            "video_url": str(record.get("video_url") or record.get("url") or ""),
        }], []

    path = str(record.get("video_path") or record.get("media_path") or record.get("local_path") or record.get("subtitle_path") or record.get("audio_path") or record.get("path") or "")
    p = _Path_v69(path)
    name = str(record.get("name") or p.name or "未命名")
    ext = p.suffix.lower()
    mats, skipped = [], []

    if ext in V69_VIDEO_EXTS:
        sub = record.get("subtitle_path") or ""
        if not sub or not _Path_v69(str(sub)).exists():
            found = _v69_sidecar_sub(p)
            sub = str(found) if found else ""
        if sub:
            lines = _v69_parse_subtitle_or_text(sub)
            for it in lines:
                mats.append({
                    "text": it["text"], "zh": it.get("zh",""),
                    "start": float(it.get("start") or 0), "end": float(it.get("end") or 0),
                    "title": name, "kind": "video", "source_type": "local_video_subtitle",
                    "local_path": str(p), "media_path": str(p), "video_path": str(p), "subtitle_path": sub,
                })
        if not mats:
            ft = _v69_filename_text(p)
            if _v69_has_en(ft):
                mats.append({
                    "text": ft, "zh": "", "start": 0.0, "end": 0.0,
                    "title": name, "kind": "video", "source_type": "local_video_filename_fallback",
                    "local_path": str(p), "media_path": str(p), "video_path": str(p), "subtitle_path": "",
                })
        if not mats:
            skipped.append(f"{name}：没有同名字幕，也无法从文件名提取英文台词")
        return mats, skipped

    if ext in V69_TEXT_EXTS:
        lines = _v69_parse_subtitle_or_text(p)
        for it in lines:
            mats.append({
                "text": it["text"], "zh": it.get("zh",""),
                "start": float(it.get("start") or 0), "end": float(it.get("end") or 0),
                "title": name, "kind": "text", "source_type": "local_text",
                "local_path": str(p), "subtitle_path": str(p),
            })
        if not mats:
            skipped.append(f"{name}：文本中没有识别到英文句子")
        return mats, skipped

    if ext in V69_AUDIO_EXTS:
        sub = None
        for e in [".srt", ".vtt", ".lrc", ".txt"]:
            c = p.with_suffix(e)
            if c.exists():
                sub = c; break
        if sub:
            lines = _v69_parse_subtitle_or_text(sub)
            for it in lines:
                mats.append({
                    "text": it["text"], "zh": it.get("zh",""),
                    "start": float(it.get("start") or 0), "end": float(it.get("end") or 0),
                    "title": name, "kind": "audio_text", "source_type": "local_audio_text",
                    "audio_path": str(p), "local_path": str(p), "subtitle_path": str(sub),
                })
        if not mats:
            skipped.append(f"{name}：音频没有同名字幕/歌词")
        return mats, skipped

    skipped.append(f"{name}：不支持的资源类型")
    return mats, skipped

# ── 语块拆分 ──────────────────────────────────────────────────────────
def _v69_words(s):
    return _re_v69.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v69_sentence_type(n):
    if n <= 8: return "超短句"
    if n <= 12: return "短句"
    if n <= 20: return "中句"
    if n <= 32: return "长句"
    return "超长句"

def _v69_protect_phrases(words):
    low = [w.lower() for w in words]
    phrase_map = sorted([p.split() for p in V69_PHRASES], key=len, reverse=True)
    groups, i = [], 0
    while i < len(words):
        hit = None
        for ph in phrase_map:
            n = len(ph)
            if i + n <= len(words) and low[i:i+n] == ph:
                hit = n
                break
        if hit:
            groups.append(words[i:i+hit]); i += hit
        else:
            groups.append([words[i]]); i += 1
    return groups

def _v69_role(group):
    low = [x.lower() for x in group]
    txt = " ".join(low)
    if txt in V69_PHRASES:
        return "固定短语"
    if low and low[0] in V69_CONJ:
        return "连接词/从句"
    if low and low[0] in V69_PREP:
        return "介词短语"
    if low and low[0] in V69_ART:
        return "冠词 + 名词短语"
    if any(x in V69_AUX for x in low):
        return "主句/谓语结构"
    if low and low[0] in V69_PRON:
        return "人称/物主代词"
    if len(group) >= 3:
        return "名词短语/谓语块"
    return "语块"

def _v69_chunks(self, text, mode="整句播放"):
    words = _v69_words(text)
    if not words:
        return []
    cfg = _v69_cfg(self)["dictation"]
    if cfg.get("online_chunk_calibration"):
        _v69_notice(self, "联网校准开关已开启：当前没有配置在线句法服务，使用本地结构拆分兜底。", "info")
    base = _v69_protect_phrases(words)

    # 按结构轻量合并，保护固定短语和从句连接点
    groups, buf = [], []
    def flush():
        nonlocal buf
        if buf:
            groups.append(buf); buf = []
    for g in base:
        low0 = g[0].lower() if g else ""
        txt = " ".join(x.lower() for x in g)
        if txt in V69_PHRASES or low0 in V69_CONJ:
            flush()
            groups.append(g)
        elif low0 in V69_PREP:
            flush()
            groups.append(g)
        else:
            if len(buf) + len(g) <= 4:
                buf += g
            else:
                flush()
                buf = list(g)
    flush()

    # 防止过长
    final = []
    for g in groups:
        if len(g) <= 5:
            final.append(g)
        else:
            for i in range(0, len(g), 4):
                final.append(g[i:i+4])

    return [{"text": " ".join(g), "words": g, "role": _v69_role(g)} for g in final]

def _v69_current_material(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    idx = int(getattr(self, "dictation_index_v30", 0) or 0)
    if 0 <= idx < len(mats):
        return mats[idx]
    return None

def _v69_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

def _v69_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or "")
    return ""

def _v69_width(text, mode):
    if mode == "拆分播放":
        return max(3, min(8, len(str(text)) + 1))
    return max(8, min(42, len(str(text)) + 2))

# ── 学习区渲染 ───────────────────────────────────────────────────────
def _v69_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in list(parent.winfo_children()):
        try: ch.destroy()
        except Exception: pass

    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        tk.Label(parent, text="当前没有素材：请从左侧素材池或资源平台加载",
                 bg=V69_BG, fg=V69_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        if not hasattr(self, "dict_v69_notice_var"):
            self.dict_v69_notice_var = tk.StringVar(value="等待加载素材")
        tk.Label(parent, textvariable=self.dict_v69_notice_var, bg="#07111f", fg=V69_MUTED,
                 font=("Microsoft YaHei UI", 11, "bold"), anchor="w").pack(fill="x", side="bottom")
        return

    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats)-1))
    self.dictation_index_v30 = idx
    try: self.dict_index_v33 = idx
    except Exception: pass
    m = mats[idx]
    text = _v69_item_text(m)
    zh = _v69_item_zh(m)
    words = _v69_words(text)
    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    mode = self.dict_play_mode_v46.get() if self.dict_play_mode_v46.get() in ("整句播放", "拆分播放") else "整句播放"

    if hasattr(self, "dictation_target_meta_var_v30"):
        try:
            self.dictation_target_meta_var_v30.set(f"{idx+1}/{len(mats)}｜{text[:100]}")
        except Exception:
            pass

    show_cn = True
    try:
        show_cn = bool(getattr(self, "dictation_show_cn_v30", tk.BooleanVar(value=True)).get())
    except Exception:
        pass
    tk.Label(parent, text=(zh if show_cn and zh else ("中文翻译/提示未加载" if show_cn else "盲听模式：中文翻译和提示已隐藏")),
             bg=V69_BG, fg=V69_TEXT if show_cn else V69_MUTED,
             font=("Microsoft YaHei UI", 20, "bold"), wraplength=1150, justify="center").pack(pady=(18, 8))

    ctl = tk.Frame(parent, bg=V69_BG)
    ctl.pack(pady=(2, 8))
    cb = ttk.Combobox(ctl, textvariable=self.dict_play_mode_v46, values=["整句播放", "拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=4)
    cb.bind("<<ComboboxSelected>>", lambda e: _v69_render_learning_area(self))
    ttk.Button(ctl, text="播放音频", command=lambda: _v69_play_audio(self)).pack(side="left", padx=4)
    ttk.Button(ctl, text="播放视频", command=lambda: _v69_play_video(self)).pack(side="left", padx=4)
    ttk.Button(ctl, text="跳过当前块", command=lambda: _v69_next(self)).pack(side="left", padx=4)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    ttk.Checkbutton(ctl, text="自动跳到下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=7)

    tk.Label(parent, text=f"句长：{len(words)}词｜类型：{_v69_sentence_type(len(words))}｜呈现：语块分组｜拆分模式：组内间隔3字符，组间间隔10字符",
             bg=V69_BG, fg=V69_MUTED, font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(0, 6))

    chunks = _v69_chunks(self, text, mode)
    board = tk.Frame(parent, bg=V69_BG)
    board.pack(anchor="center", padx=16, pady=(4, 6))
    self.dict_v46_entries = []

    if mode == "拆分播放":
        line = None
        used_chars = 0
        max_chars = 92
        inner_gap_px = 3 * 8
        group_gap_px = 10 * 8
        for gi, ch in enumerate(chunks):
            g_words = ch["words"]
            group_chars = sum(min(8, max(3, len(w)+1)) for w in g_words) + max(0, len(g_words)-1) * 3 + 10
            if line is None or used_chars + group_chars > max_chars:
                line = tk.Frame(board, bg=V69_BG)
                line.pack(anchor="center", pady=8)
                used_chars = 0
            group = tk.Frame(line, bg=V69_BG)
            group.pack(side="left", padx=(group_gap_px if used_chars else 0, 0))
            word_row = tk.Frame(group, bg=V69_BG)
            word_row.pack(anchor="center")
            for wi, w in enumerate(g_words):
                cell = tk.Frame(word_row, bg=V69_BG)
                cell.pack(side="left", padx=(0 if wi == 0 else inner_gap_px, 0))
                width = _v69_width(w, mode)
                ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V69_BG, fg=V69_INPUT,
                              insertbackground=V69_INPUT, relief="flat", bd=0,
                              font=("Consolas", 19, "bold"), undo=False)
                ent.pack()
                cw = max(58, min(120, width * 15))
                cv = tk.Canvas(cell, width=cw, height=8, bg=V69_BG, highlightthickness=0)
                cv.pack()
                cv.create_line(2, 4, cw-2, 4, fill=V69_INPUT if not self.dict_v46_entries else V69_LINE, width=3)
                item = {"idx": len(self.dict_v46_entries), "target": w, "role": ch["role"], "entry": ent, "line": cv, "w": cw, "group": gi}
                self.dict_v46_entries.append(item)
                ent.bind("<KeyRelease>", lambda e, it=item: _v69_live_color(self, it))
                ent.bind("<space>", lambda e, it=item: (_v69_judge_block(self, it), "break"))
                ent.bind("<Return>", lambda e: (_v69_submit_all(self), "break"))
                ent.bind("<Control-h>", lambda e: (_v69_hint_current(self), "break"))
            tk.Label(group, text=ch["role"], bg=V69_BG, fg=V69_MUTED,
                     font=("Microsoft YaHei UI", 8, "bold")).pack(pady=(4,0))
            used_chars += group_chars
    else:
        line = None
        used_chars = 0
        max_chars = 96
        for gi, ch in enumerate(chunks):
            tx = ch["text"]
            width = _v69_width(tx, mode)
            if line is None or used_chars + width > max_chars:
                line = tk.Frame(board, bg=V69_BG)
                line.pack(anchor="center", pady=8)
                used_chars = 0
            cell = tk.Frame(line, bg=V69_BG)
            cell.pack(side="left", padx=20, pady=2)
            ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V69_BG, fg=V69_INPUT,
                          insertbackground=V69_INPUT, relief="flat", bd=0,
                          font=("Consolas", 20, "bold"), undo=False)
            ent.pack()
            cw = max(130, min(600, width * 15))
            cv = tk.Canvas(cell, width=cw, height=8, bg=V69_BG, highlightthickness=0)
            cv.pack()
            cv.create_line(2, 4, cw-2, 4, fill=V69_INPUT if gi == 0 else V69_LINE, width=3)
            tk.Label(cell, text=ch["role"], bg=V69_BG, fg=V69_MUTED,
                     font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
            item = {"idx": len(self.dict_v46_entries), "target": tx, "role": ch["role"], "entry": ent, "line": cv, "w": cw, "group": gi}
            self.dict_v46_entries.append(item)
            ent.bind("<KeyRelease>", lambda e, it=item: _v69_live_color(self, it))
            ent.bind("<space>", lambda e, it=item: (_v69_judge_block(self, it), "break"))
            ent.bind("<Return>", lambda e: (_v69_submit_all(self), "break"))
            ent.bind("<Control-h>", lambda e: (_v69_hint_current(self), "break"))
            used_chars += width + 6

    hint_panel = tk.Frame(parent, bg="#0f172a", bd=1, relief="solid")
    hint_panel.pack(fill="x", padx=120, pady=(16, 6))
    tk.Label(hint_panel, text="固定提示 / 六步提示", bg="#0f172a", fg=V69_TEXT,
             font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w", padx=12, pady=(8, 2))
    if not hasattr(self, "dict_v62_side_var"):
        self.dict_v62_side_var = tk.StringVar()
    self.dict_v62_side_var.set("按 Ctrl+H：音标 → 同音词 → 近反义词 → 首尾字母 → 英文释义 → 同形词/答案。")
    tk.Label(hint_panel, textvariable=self.dict_v62_side_var, bg="#0f172a", fg=V69_MUTED,
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0,4))
    if not hasattr(self, "dict_v63_hint_var"):
        self.dict_v63_hint_var = tk.StringVar()
    tk.Label(hint_panel, textvariable=self.dict_v63_hint_var, bg="#0f172a", fg="#38BDF8",
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0,8))

    if not hasattr(self, "dict_v69_notice_var"):
        self.dict_v69_notice_var = tk.StringVar(value="就绪")
    tk.Label(parent, textvariable=self.dict_v69_notice_var, bg="#07111f", fg=V69_MUTED,
             font=("Microsoft YaHei UI", 11, "bold"), anchor="w").pack(fill="x", padx=18, pady=(4,0), side="bottom")
    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    _v69_notice(self, "学习区已刷新，素材已进入听写训练。", "ok")

def _v69_live_color(self, item):
    ent = item["entry"]
    val = ent.get("1.0", "end-1c").strip()
    target = str(item["target"]).strip()
    try:
        item["line"].delete("all")
        color = V69_INPUT
        # 只要已完成的前缀正确，就保持绿色；最终错误才红色
        if val and target.lower().startswith(val.lower()):
            color = V69_OK if val.lower() == target.lower() else V69_INPUT
        elif val:
            color = V69_BAD
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        ent.configure(fg=color)
    except Exception:
        pass

def _v69_judge_block(self, item):
    ent = item["entry"]
    val = _re_v69.sub(r"\s+", " ", ent.get("1.0", "end-1c")).strip()
    target = _re_v69.sub(r"\s+", " ", str(item["target"])).strip()
    ok = val.lower() == target.lower()
    color = V69_OK if ok else V69_BAD
    try:
        item["line"].delete("all")
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        ent.configure(fg=color)
    except Exception:
        pass
    if ok:
        _v69_notice(self, f"当前块正确：{target}", "ok")
        nxt = item["idx"] + 1
        entries = getattr(self, "dict_v46_entries", []) or []
        if nxt < len(entries):
            entries[nxt]["entry"].focus_set()
        else:
            if bool(getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get()):
                _v69_next(self)
    else:
        _v69_notice(self, f"当前块错误｜你输入：{val or '空'}｜目标结构：{item.get('role','语块')}", "bad")
    return ok

def _v69_submit_all(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    ok_all = True
    for it in entries:
        ok_all = _v69_judge_block(self, it) and ok_all
    if ok_all:
        _v69_notice(self, "整句全部正确。", "ok")
        if bool(getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get()):
            _v69_next(self)
    return ok_all

def _v69_next(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        return
    self.dictation_index_v30 = min(len(mats)-1, int(getattr(self, "dictation_index_v30", 0) or 0) + 1)
    try: self.dict_index_v33 = self.dictation_index_v30
    except Exception: pass
    _v69_render_learning_area(self)

def _v69_prev(self):
    self.dictation_index_v30 = max(0, int(getattr(self, "dictation_index_v30", 0) or 0) - 1)
    try: self.dict_index_v33 = self.dictation_index_v30
    except Exception: pass
    _v69_render_learning_area(self)

# ── 六步提示 ─────────────────────────────────────────────────────────
def _v69_active_item(self):
    focus = None
    try: focus = self.focus_get()
    except Exception: pass
    entries = getattr(self, "dict_v46_entries", []) or []
    for it in entries:
        if it.get("entry") is focus:
            return it
    return entries[0] if entries else None

def _v69_base_word(s):
    w = _v69_words(s)
    return w[0].lower() if w else str(s or "").lower().strip()

def _v69_hint_current(self):
    item = _v69_active_item(self)
    if not item:
        _v69_notice(self, "当前没有可提示的输入块。", "bad")
        return
    target = str(item.get("target") or "")
    word = _v69_base_word(target)
    step = (int(getattr(self, "_v69_hint_step", 0) or 0) % 6) + 1
    self._v69_hint_step = step
    if step == 1:
        title = "① 音标提示"; body = V69_IPA.get(word, f"本地音标未命中：{word}。可在设置中心配置本地词典目录。")
    elif step == 2:
        title = "② 同音词提示"; body = " / ".join(V69_HOMOPHONES.get(word, [])) or "本地未记录同音词。"
    elif step == 3:
        title = "③ 近义/反义提示"; d = V69_SYN.get(word, {}); body = f"近义：{', '.join(d.get('近义', [])) or '未记录'}；反义：{', '.join(d.get('反义', [])) or '未记录'}"
    elif step == 4:
        title = "④ 首尾字母提示"; body = f"首字母：{word[:1] or '无'}；末尾字母：{word[-1:] or '无'}；长度：{len(word)}"
    elif step == 5:
        title = "⑤ 英文释义提示"; body = V69_DEF.get(word, "本地释义未命中；后续可接入本地词典/在线词典 API 校准。")
    else:
        title = "⑥ 同形词/答案提示"; body = f"正确答案：{target}"
    msg = f"{title}｜当前块：{target}｜结构：{item.get('role','语块')}\n{body}"
    try:
        self.dict_v63_hint_var.set(msg)
        self.dict_v62_side_var.set("六步提示已固定显示；继续按 Ctrl+H 切换下一层。")
    except Exception:
        pass
    _v69_notice(self, f"六步提示更新：{title}", "info")

# ── 素材树 / 加载主链 ───────────────────────────────────────────────
def _v69_refresh_material_tree(self):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None:
        return
    try:
        tree.delete(*tree.get_children())
    except Exception:
        return
    mats = getattr(self, "dictation_materials_v30", []) or []
    self.v69_material_index = {}
    buckets = {"在线素材": [], "本地素材": [], "文本素材": []}
    for i, m in enumerate(mats):
        src = str(m.get("source_type","")) if isinstance(m, dict) else ""
        if src.startswith("online"):
            buckets["在线素材"].append(i)
        elif "text" in src:
            buckets["文本素材"].append(i)
        else:
            buckets["本地素材"].append(i)
    page_size = 200
    for bucket, idxs in buckets.items():
        root = tree.insert("", "end", text=f"{bucket}｜{len(idxs)}条", open=True, values=("DIR", bucket))
        groups = {}
        for idx in idxs:
            m = mats[idx]
            title = str(m.get("title") or m.get("subtitle_path") or m.get("local_path") or "未命名")
            groups.setdefault(title, []).append(idx)
        for title, ids in groups.items():
            fid = tree.insert(root, "end", text=f"📄 {_Path_v69(title).name if '\\' in title or '/' in title else title}｜{len(ids)}句", open=(len(ids)<=60), values=("FILE", title))
            self.v69_material_index[fid] = ids
            if len(ids) <= page_size:
                for idx in ids:
                    text = _v69_item_text(mats[idx])
                    iid = tree.insert(fid, "end", text=f"· {idx+1:04d}. {text[:180]}", values=("ITEM", str(idx)))
                    self.v69_material_index[iid] = [idx]
            else:
                for start in range(0, len(ids), page_size):
                    end = min(start+page_size, len(ids))
                    pid = tree.insert(fid, "end", text=f"▶ {start+1:04d}-{end:04d}", values=("PAGE", str(start), str(end)))
                    self.v69_material_index[pid] = ids[start:end]
    _v69_notice(self, f"听写素材树已刷新：{len(mats)} 条。", "ok")

def _v69_on_material_select(self, event=None):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None or not tree.selection():
        return
    iid = tree.selection()[0]
    vals = tree.item(iid, "values")
    ids = getattr(self, "v69_material_index", {}).get(iid, [])
    if vals and vals[0] == "ITEM" and vals[1].isdigit():
        ids = [int(vals[1])]
    if not ids:
        return
    self.dictation_index_v30 = ids[0]
    try: self.dict_index_v33 = ids[0]
    except Exception: pass
    _v69_render_learning_area(self)
    _v69_notice(self, f"已加载素材到学习区：第 {ids[0]+1} 条。", "ok")

def _v69_load_materials(self, materials, clear_existing=False):
    materials = [m for m in materials if _v69_has_en(_v69_item_text(m))]
    if not materials:
        _v69_notice(self, "没有可加载的英文台词/文本。", "bad")
        return 0
    old = [] if clear_existing else list(getattr(self, "dictation_materials_v30", []) or [])
    seen = {(str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text",""))) for m in old if isinstance(m, dict)}
    add = []
    for m in materials:
        key = (str(m.get("local_path","")), str(m.get("subtitle_path","")), str(m.get("text","")))
        if key not in seen:
            add.append(m); seen.add(key)
    old.extend(add)
    self.dictation_materials_v30 = old
    try: self.dict_items_v33 = old
    except Exception: pass
    if add:
        self.dictation_index_v30 = len(old) - len(add)
        try: self.dict_index_v33 = self.dictation_index_v30
        except Exception: pass
    _v69_refresh_material_tree(self)
    _v69_render_learning_area(self)
    try: self.nb.select(self.tab_dictation)
    except Exception: pass
    _v69_notice(self, f"素材加载完成：新增 {len(add)} 条，素材池累计 {len(old)} 条。", "ok")
    return len(add)

def _v69_load_records_to_dictation(self, records, clear_existing=False):
    records = records or []
    _v69_notice(self, f"开始解析资源记录：{len(records)} 条。", "info")
    all_mats, skipped = [], []
    for r in records:
        mats, sk = _v69_record_to_materials(r)
        all_mats.extend(mats)
        skipped.extend(sk)
    if skipped:
        _v69_notice(self, "部分资源跳过：" + "；".join(skipped[:5]), "info")
    return _v69_load_materials(self, all_mats, clear_existing=clear_existing)

# ── 我的资源站内嵌平台 ───────────────────────────────────────────────
def _v69_index_path(self, mode):
    root = _Path_v69(_v69_cfg(self)["paths"]["resource_root"])
    root.mkdir(parents=True, exist_ok=True)
    return root / f"{mode}_resources_v69.json"

def _v69_load_index(self, mode):
    p = _v69_index_path(self, mode)
    try:
        if p.exists():
            data = _json_v69.loads(p.read_text("utf-8"))
            if isinstance(data, dict) and isinstance(data.get("records"), list):
                return data
    except Exception:
        pass
    return {"records": []}

def _v69_save_index(self, mode, data):
    p = _v69_index_path(self, mode)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(_json_v69.dumps(data, ensure_ascii=False, indent=2), "utf-8")

def _v69_scan_path(path, mode="dictation"):
    root = _Path_v69(str(path))
    files = []
    if root.is_file():
        files = [root]
    elif root.is_dir():
        for ext in list(V69_VIDEO_EXTS | V69_AUDIO_EXTS | V69_TEXT_EXTS):
            files.extend(root.rglob("*" + ext))
    records = []
    for p in files:
        ext = p.suffix.lower()
        if mode == "recite" and ext in V69_VIDEO_EXTS:
            continue
        typ = "视频" if ext in V69_VIDEO_EXTS else ("音频" if ext in V69_AUDIO_EXTS else "文本/字幕")
        sub = ""
        status = "待解析"
        lines = 0
        if ext in V69_VIDEO_EXTS:
            found = _v69_sidecar_sub(p)
            if found:
                sub = str(found)
                parsed = _v69_parse_subtitle_or_text(found)
                lines = len(parsed)
                status = "视频+字幕" if lines else "视频+字幕但无英文"
            else:
                status = "仅视频/缺字幕"
        elif ext in V69_TEXT_EXTS:
            parsed = _v69_parse_subtitle_or_text(p)
            lines = len(parsed)
            status = "文本可练习" if lines else "文本无英文"
        elif ext in V69_AUDIO_EXTS:
            side = None
            for e in [".srt",".vtt",".lrc",".txt"]:
                c = p.with_suffix(e)
                if c.exists():
                    side = c; break
            if side:
                sub = str(side)
                lines = len(_v69_parse_subtitle_or_text(side))
                status = "音频+歌词/字幕"
            else:
                status = "仅音频/缺文本"
        records.append({
            "type": typ, "name": p.name, "status": status, "lines": lines,
            "origin": "本地扫描", "path": str(p), "local_path": str(p),
            "video_path": str(p) if ext in V69_VIDEO_EXTS else "",
            "audio_path": str(p) if ext in V69_AUDIO_EXTS else "",
            "subtitle_path": sub,
            "source_type": "local_video_subtitle" if ext in V69_VIDEO_EXTS else ("local_audio_text" if ext in V69_AUDIO_EXTS else "local_text"),
        })
    return records

def _v69_build_resource_platform_inline(self):
    p = getattr(self, "tab_resource_platform_v32", None)
    if p is None:
        return
    for ch in list(p.winfo_children()):
        try: ch.destroy()
        except Exception: pass

    cfg = _v69_cfg(self)
    outer = ttk.Frame(p, padding=10)
    outer.pack(fill="both", expand=True)
    top = ttk.Frame(outer)
    top.pack(fill="x", pady=(0, 8))
    ttk.Label(top, text="资源平台根目录").pack(side="left")
    self.v69_resource_root_var = tk.StringVar(value=cfg["paths"]["resource_root"])
    ttk.Entry(top, textvariable=self.v69_resource_root_var, width=90).pack(side="left", padx=8)

    def choose_root():
        d = filedialog.askdirectory()
        if d:
            self.v69_resource_root_var.set(d)
            cfg["paths"]["resource_root"] = d
            _v69_save_cfg(self)
            _v69_notice(self, "资源平台根目录已更新。", "ok")

    def init_root():
        root = _Path_v69(self.v69_resource_root_var.get())
        for sub in ["dictation/本地视频字幕", "dictation/本地文本资源", "dictation/play phrase网站学习资源", "recite/单词文本", "recite/音频歌词"]:
            (root / sub).mkdir(parents=True, exist_ok=True)
        cfg["paths"]["resource_root"] = str(root)
        _v69_save_cfg(self)
        _v69_notice(self, "资源平台目录已初始化。", "ok")

    ttk.Button(top, text="选择根目录", command=choose_root).pack(side="left", padx=3)
    ttk.Button(top, text="初始化目录", command=init_root).pack(side="left", padx=3)
    self.resource_v69_status_var = tk.StringVar(value="就绪：资源平台已直接显示。")
    ttk.Label(top, textvariable=self.resource_v69_status_var).pack(side="left", padx=14)

    nb = ttk.Notebook(outer)
    nb.pack(fill="both", expand=True)
    t1 = ttk.Frame(nb); t2 = ttk.Frame(nb)
    nb.add(t1, text="听写资源库")
    nb.add(t2, text="背诵资源库")
    _v69_build_resource_tab(self, t1, "dictation")
    _v69_build_resource_tab(self, t2, "recite")

def _v69_build_resource_tab(self, parent, mode):
    root = ttk.Frame(parent, padding=8)
    root.pack(fill="both", expand=True)
    bar = ttk.Frame(root)
    bar.pack(fill="x", pady=(0, 8))

    def add_file():
        paths = filedialog.askopenfilenames(filetypes=[("可识别资源", "*.mp4 *.mkv *.avi *.mov *.webm *.mp3 *.wav *.flac *.m4a *.txt *.srt *.vtt *.lrc *.csv"), ("全部文件", "*.*")])
        if paths:
            _v69_register_paths_async(self, mode, list(paths))

    def add_folder():
        d = filedialog.askdirectory()
        if d:
            _v69_register_paths_async(self, mode, [d])

    ttk.Button(bar, text="添加文件并扫描", command=add_file).pack(side="left", padx=3)
    ttk.Button(bar, text="添加文件夹并递归扫描", command=add_folder).pack(side="left", padx=3)
    ttk.Button(bar, text="刷新", command=lambda: _v69_refresh_resource_table(self, mode)).pack(side="left", padx=3)
    if mode == "dictation":
        ttk.Button(bar, text="加载选中到听写训练", command=lambda: _v69_load_selected_resource(self, mode)).pack(side="left", padx=12)
    ttk.Label(bar, text="搜索").pack(side="left", padx=(18, 3))
    setattr(self, f"v69_{mode}_search", tk.StringVar())
    ttk.Entry(bar, textvariable=getattr(self, f"v69_{mode}_search"), width=24).pack(side="left")
    ttk.Button(bar, text="查找", command=lambda: _v69_refresh_resource_table(self, mode)).pack(side="left", padx=3)

    cols = ("type", "name", "status", "lines", "origin", "path")
    frame = ttk.Frame(root)
    frame.pack(fill="both", expand=True)
    table = ttk.Treeview(frame, columns=cols, show="headings", height=30)
    vs = ttk.Scrollbar(frame, orient="vertical", command=table.yview)
    hs = ttk.Scrollbar(frame, orient="horizontal", command=table.xview)
    table.configure(yscrollcommand=vs.set, xscrollcommand=hs.set)
    heads = {"type":"类型","name":"文件名","status":"状态","lines":"行数","origin":"来源","path":"路径"}
    widths = {"type":100,"name":340,"status":170,"lines":70,"origin":110,"path":900}
    for c in cols:
        table.heading(c, text=heads[c]); table.column(c, width=widths[c], anchor="w")
    table.grid(row=0, column=0, sticky="nsew")
    vs.grid(row=0, column=1, sticky="ns")
    hs.grid(row=1, column=0, sticky="ew")
    frame.rowconfigure(0, weight=1); frame.columnconfigure(0, weight=1)
    setattr(self, f"v69_{mode}_table", table)
    setattr(self, f"v69_{mode}_rows", [])
    setattr(self, f"v69_{mode}_status", tk.StringVar(value="就绪：扫描/加载都会显示提示。"))
    ttk.Label(root, textvariable=getattr(self, f"v69_{mode}_status")).pack(fill="x", pady=(8,0))
    table.bind("<Double-1>", lambda e: _v69_load_selected_resource(self, mode) if mode == "dictation" else _v69_notice(self, "背诵资源加载链后续独立处理。", "info", mode))
    _v69_refresh_resource_table(self, mode)

def _v69_register_paths_async(self, mode, paths):
    _v69_notice(self, f"开始后台扫描：{len(paths)} 个路径。", "info", mode)
    def worker():
        records = []
        for path in paths:
            try:
                records.extend(_v69_scan_path(path, mode))
            except Exception as e:
                _v69_notice(self, f"扫描失败：{path}｜{type(e).__name__}: {e}", "bad", mode)
        def finish():
            data = _v69_load_index(self, mode)
            old = data.setdefault("records", [])
            keys = {r.get("path","") for r in old}
            add = 0
            for r in records:
                if r.get("path") not in keys:
                    old.append(r); keys.add(r.get("path")); add += 1
            _v69_save_index(self, mode, data)
            _v69_refresh_resource_table(self, mode)
            _v69_notice(self, f"后台扫描完成：新增 {add} 条，扫描到 {len(records)} 条。", "ok", mode)
        try: self.after(0, finish)
        except Exception: pass
    _threading_v69.Thread(target=worker, daemon=True).start()

def _v69_refresh_resource_table(self, mode):
    table = getattr(self, f"v69_{mode}_table", None)
    if table is None:
        return
    try: table.delete(*table.get_children())
    except Exception: pass
    data = _v69_load_index(self, mode)
    rows = data.get("records", [])
    qv = getattr(self, f"v69_{mode}_search", None)
    q = qv.get().lower().strip() if qv else ""
    if q:
        rows = [r for r in rows if q in r.get("name","").lower() or q in r.get("path","").lower() or q in r.get("status","").lower() or q in r.get("type","").lower()]
    setattr(self, f"v69_{mode}_rows", rows)
    _v69_notice(self, f"刷新资源表：{len(rows)} 条，正在分批显示。", "info", mode)

    def insert_batch(start=0, batch=180):
        end = min(start + batch, len(rows))
        for i in range(start, end):
            r = rows[i]
            try:
                table.insert("", "end", iid=str(i), values=(r.get("type",""), r.get("name",""), r.get("status",""), r.get("lines",""), r.get("origin",""), r.get("path","")))
            except Exception:
                pass
        if end < len(rows):
            try: table.after(1, lambda: insert_batch(end, batch))
            except Exception: insert_batch(end, batch)
        else:
            _v69_notice(self, f"资源表刷新完成：{len(rows)} 条。", "ok", mode)
    insert_batch()

def _v69_load_selected_resource(self, mode="dictation"):
    if mode != "dictation":
        _v69_notice(self, "背诵资源加载链独立处理，当前不会加载到听写训练。", "info", mode)
        return
    table = getattr(self, f"v69_{mode}_table", None)
    rows = getattr(self, f"v69_{mode}_rows", []) or []
    selected = []
    if table is not None:
        for iid in table.selection():
            try: selected.append(rows[int(iid)])
            except Exception: pass
    if not selected:
        _v69_notice(self, "请先在资源表中选中资源。", "bad", mode)
        return
    _v69_notice(self, f"开始加载选中资源：{len(selected)} 条。", "info", mode)
    def worker():
        mats, skipped = [], []
        for r in selected:
            m, sk = _v69_record_to_materials(r)
            mats.extend(m); skipped.extend(sk)
        def finish():
            if skipped:
                _v69_notice(self, "部分资源跳过：" + "；".join(skipped[:5]), "info", mode)
            _v69_load_materials(self, mats, clear_existing=False)
        try: self.after(0, finish)
        except Exception: pass
    _threading_v69.Thread(target=worker, daemon=True).start()

# ── 精选池 / 下载 / 播放 ─────────────────────────────────────────────
def _v69_clip_to_mat(c, i=0):
    def get(obj, name, default=""):
        if isinstance(obj, dict):
            return obj.get(name, default)
        return getattr(obj, name, default)
    text = str(get(c, "text") or get(c, "en") or get(c, "sentence") or "")
    zh = str(get(c, "zh") or get(c, "cn") or get(c, "translation") or "")
    url = str(get(c, "video_url") or get(c, "url") or "")
    title = _v69_filename_text(text)[:80] if text else f"在线精选池_{i:04d}"
    return {"text": text, "zh": zh, "url": url, "video_url": url, "title": title, "kind": "online", "source_type": "online_pool"}

def _v69_import_pool_safe(self):
    clips = list(getattr(self, "pool", []) or [])
    mats = [_v69_clip_to_mat(c, i+1) for i, c in enumerate(clips)]
    mats = [m for m in mats if _v69_has_en(m.get("text",""))]
    if not mats:
        _v69_notice(self, "精选池为空或没有英文台词，无法加载。", "bad")
        return
    _v69_notice(self, f"安全加载精选池文本：{len(mats)} 条。", "info")
    _v69_load_materials(self, mats, clear_existing=False)
    dl = bool(_v69_cfg(self)["loading"].get("online_download_on_load", False))
    try:
        dl = dl or bool(getattr(self, "dict_pool_download_local_var_v52").get())
    except Exception:
        pass
    if dl:
        _v69_download_online_to_local(self, mats)

def _v69_safe_name(s, n=80):
    s = _v69_filename_text(s) or "clip"
    s = _re_v69.sub(r'[\\/:*?"<>|]+', "_", s)
    return _re_v69.sub(r"\s+", "_", s).strip("_")[:n] or "clip"

def _v69_srt_line(i, text, start=0.0, end=3.0):
    def fmt(sec):
        sec = max(0.0, float(sec or 0))
        h = int(sec//3600); sec -= h*3600
        m = int(sec//60); sec -= m*60
        s = int(sec); ms = int(round((sec-s)*1000))
        return f"{h:02d}:{m:02d}:{s:02d},{ms:03d}"
    return f"{i}\n{fmt(start)} --> {fmt(end)}\n{text}\n\n"

def _v69_translate(self, text, engine=None):
    # 不再阻塞；本地引擎不可用就返回空，界面给提示。
    for fn_name in ["_opus_translate_v19", "_smart_translate_v30"]:
        fn = globals().get(fn_name) or getattr(self, fn_name, None)
        if callable(fn):
            try:
                try: r = fn(self, text, "en", "zh")
                except TypeError: r = fn(text, "en", "zh")
                if r: return str(r)
            except Exception:
                pass
    return ""

def _v69_download_file(url, out, timeout=16):
    if not url:
        return False, "无URL"
    try:
        import requests
        r = requests.get(url, timeout=timeout, stream=True)
        if r.status_code >= 400:
            return False, f"HTTP {r.status_code}"
        out.parent.mkdir(parents=True, exist_ok=True)
        with out.open("wb") as f:
            for chunk in r.iter_content(1024*512):
                if chunk: f.write(chunk)
        return out.exists() and out.stat().st_size > 1024, "OK"
    except Exception as e:
        return False, f"{type(e).__name__}: {e}"

def _v69_download_root(self):
    root = _Path_v69(_v69_cfg(self)["paths"]["resource_root"])
    p = root / "dictation" / "play phrase网站学习资源" / _time_v69.strftime("%Y-%m-%d")
    p.mkdir(parents=True, exist_ok=True)
    return p

def _v69_download_online_to_local(self, mats=None):
    if mats is None:
        mats = [m for m in getattr(self, "dictation_materials_v30", []) or [] if isinstance(m, dict) and str(m.get("source_type","")).startswith("online")]
    mats = list(mats or [])
    if not mats:
        _v69_notice(self, "没有可下载的在线素材。", "bad")
        return
    cfg = _v69_cfg(self)["loading"]
    target = _v69_download_root(self)
    _v69_notice(self, f"开始后台下载/落地在线素材：0/{len(mats)}。", "info")
    def worker():
        records = []
        for i, m in enumerate(mats, 1):
            text = _v69_item_text(m)
            zh = _v69_item_zh(m)
            if not zh and cfg.get("online_write_translate_subtitle", True):
                zh = _v69_translate(self, text, cfg.get("online_translate_engine"))
            base = f"{i:04d}_{_v69_safe_name(text, 70)}"
            video = target / (base + ".mp4")
            en_srt = target / (base + ".en.srt")
            zh_srt = target / (base + ".zh.srt")
            downloaded, why = False, ""
            if cfg.get("online_download_video", True) and (m.get("video_url") or m.get("url")):
                downloaded, why = _v69_download_file(m.get("video_url") or m.get("url"), video)
            if cfg.get("online_write_origin_subtitle", True):
                en_srt.write_text(_v69_srt_line(1, text), "utf-8")
            if cfg.get("online_write_translate_subtitle", True) and zh:
                zh_srt.write_text(_v69_srt_line(1, zh), "utf-8")
            records.append({
                "type": "视频" if downloaded else "文本/字幕",
                "name": video.name if downloaded else en_srt.name,
                "status": "视频+字幕" if downloaded else ("只落地字幕" if not why else f"只落地字幕：{why}"),
                "lines": 1,
                "origin": "PlayPhrase在线落地",
                "path": str(video if downloaded else en_srt),
                "local_path": str(video if downloaded else en_srt),
                "video_path": str(video if downloaded else ""),
                "media_path": str(video if downloaded else ""),
                "subtitle_path": str(en_srt),
                "source_type": "local_video_subtitle" if downloaded else "local_text",
            })
            try:
                self.after(0, lambda i=i: _v69_notice(self, f"下载/落地在线素材：{i}/{len(mats)}。", "info"))
            except Exception:
                pass
        def finish():
            data = _v69_load_index(self, "dictation")
            old = data.setdefault("records", [])
            keys = {r.get("path","") for r in old}
            add = 0
            for r in records:
                if r["path"] not in keys:
                    old.append(r); keys.add(r["path"]); add += 1
            _v69_save_index(self, "dictation", data)
            _v69_refresh_resource_table(self, "dictation")
            _v69_notice(self, f"在线素材下载/落地完成：新增 {add} 条，已刷新资源平台。", "ok")
        try: self.after(0, finish)
        except Exception: pass
    _threading_v69.Thread(target=worker, daemon=True).start()

def _v69_find_ffmpeg(self):
    for name in ["_v56_find_ffmpeg", "_find_ffmpeg"]:
        fn = globals().get(name) or getattr(self, name, None)
        if callable(fn):
            try:
                r = fn(self) if name in globals() else fn()
                if r: return r
            except Exception:
                pass
    return "ffmpeg"

def _v69_play_audio(self):
    m = _v69_current_material(self)
    if not m:
        _v69_notice(self, "没有选中素材，无法播放音频。", "bad")
        return
    video = str(m.get("video_path") or m.get("media_path") or "")
    start = float(m.get("start") or 0)
    end = float(m.get("end") or 0)
    if video and _Path_v69(video).exists() and end > start:
        out = _Path_v69(_tempfile_v69.gettempdir()) / f"pp_v69_audio_{int(_time_v69.time()*1000)}.wav"
        ff = _v69_find_ffmpeg(self)
        cmd = [ff, "-y", "-hide_banner", "-loglevel", "error", "-ss", f"{start:.3f}", "-to", f"{end:.3f}", "-i", video, "-vn", "-ac", "1", "-ar", "22050", str(out)]
        _v69_notice(self, "正在提取并播放原片音频。", "info")
        def worker():
            flags = getattr(_subprocess_v69, "CREATE_NO_WINDOW", 0) if _os_v69.name == "nt" else 0
            try:
                r = _subprocess_v69.run(cmd, stdout=_subprocess_v69.DEVNULL, stderr=_subprocess_v69.DEVNULL, creationflags=flags, timeout=30)
                if r.returncode == 0 and out.exists():
                    if _os_v69.name == "nt":
                        import winsound
                        winsound.PlaySound(str(out), winsound.SND_FILENAME | winsound.SND_ASYNC)
                    else:
                        _subprocess_v69.Popen(["ffplay", "-nodisp", "-autoexit", str(out)])
                    self.after(0, lambda: _v69_notice(self, "原片音频播放中。", "ok"))
                    return
            except Exception:
                pass
            self.after(0, lambda: _v69_tts(self, _v69_item_text(m)))
        _threading_v69.Thread(target=worker, daemon=True).start()
        return
    _v69_tts(self, _v69_item_text(m))

def _v69_tts(self, text):
    text = str(text or "").strip()
    if not text:
        _v69_notice(self, "没有可朗读文本。", "bad"); return
    for name in ["_v55_speak_text", "_v46_speak_text"]:
        fn = globals().get(name) or getattr(self, name, None)
        if callable(fn):
            try:
                try: return fn(self, text, mode="chunk")
                except TypeError:
                    try: return fn(self, text)
                    except TypeError: return fn(text)
            except Exception:
                pass
    _v69_notice(self, "TTS 引擎不可用；请在设置中心选择 Edge-TTS 或生成音频缓存。", "bad")

def _v69_cache_online_video(self, m):
    url = str(m.get("video_url") or m.get("url") or "")
    if not url:
        _v69_notice(self, "在线素材没有视频 URL，只能做文本/TTS。", "bad")
        return ""
    cfg = _v69_cfg(self)
    if cfg["loading"].get("online_storage_mode") == "存储到本地资源":
        root = _v69_download_root(self)
    else:
        root = _Path_v69(cfg["paths"]["cache_root"]) / "online_temp"
        root.mkdir(parents=True, exist_ok=True)
    out = root / (_v69_safe_name(_v69_item_text(m), 70) + ".mp4")
    if out.exists() and out.stat().st_size > 1024:
        return str(out)
    _v69_notice(self, "在线视频正在缓存；缓存完成后播放。", "info")
    ok, why = _v69_download_file(url, out)
    if not ok:
        _v69_notice(self, f"在线视频缓存失败：{why}", "bad")
        return ""
    m["video_path"] = str(out); m["media_path"] = str(out); m["local_path"] = str(out)
    return str(out)

def _v69_play_video(self):
    m = _v69_current_material(self)
    if not m:
        _v69_notice(self, "没有选中素材，无法播放视频。", "bad"); return
    if str(m.get("source_type","")) == "local_text" and not (m.get("video_path") or m.get("media_path")):
        _v69_notice(self, "文本资源不支持视频播放；请使用音频/TTS。", "bad"); return
    video = str(m.get("video_path") or m.get("media_path") or "")
    if not video and str(m.get("source_type","")).startswith("online"):
        video = _v69_cache_online_video(self, m)
    if not video and m.get("local_path") and _Path_v69(str(m.get("local_path"))).suffix.lower() in V69_VIDEO_EXTS:
        video = str(m.get("local_path"))
    if not video or not _Path_v69(video).exists():
        _v69_notice(self, "当前素材没有可用视频。", "bad"); return
    _v69_notice(self, f"正在打开视频：{_Path_v69(video).name}", "ok")
    try:
        if _os_v69.name == "nt": _os_v69.startfile(video)
        elif _sys_v69.platform == "darwin": _subprocess_v69.Popen(["open", video])
        else: _subprocess_v69.Popen(["xdg-open", video])
    except Exception as e:
        _v69_notice(self, f"视频打开失败：{type(e).__name__}: {e}", "bad")

