def _v69_row(parent, title, desc=""):
    r = tk.Frame(parent, bg=V69_PANEL)
    r.pack(fill="x", padx=14, pady=7)
    l = tk.Frame(r, bg=V69_PANEL)
    l.pack(side="left", fill="x", expand=True)
    tk.Label(l, text=title, bg=V69_PANEL, fg=V69_TEXT, font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w")
    if desc:
        tk.Label(l, text=desc, bg=V69_PANEL, fg=V69_MUTED, wraplength=780, justify="left").pack(anchor="w")
    return r

def _v69_choose_dir(var):
    d = filedialog.askdirectory()
    if d: var.set(d)

def _v69_open_path(path):
    p = _Path_v69(str(path or "."))
    p.mkdir(parents=True, exist_ok=True)
    try:
        if _os_v69.name == "nt": _os_v69.startfile(str(p))
        elif _sys_v69.platform == "darwin": _subprocess_v69.Popen(["open", str(p)])
        else: _subprocess_v69.Popen(["xdg-open", str(p)])
    except Exception:
        pass

def _v69_open_settings_center(self):
    cfg = _v69_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置中心 V69")
    win.geometry("1360x880")
    win.configure(bg=V69_PANEL)
    outer = tk.Frame(win, bg=V69_PANEL)
    outer.pack(fill="both", expand=True, padx=16, pady=12)
    tk.Label(outer, text="设置中心 V69", bg=V69_PANEL, fg=V69_TEXT, font=("Microsoft YaHei UI", 20, "bold")).pack(anchor="w")
    tk.Label(outer, text="听写控制台、加载、路径、显示隐藏、自动拆分、六步提示、音效、主题全部集中在这里。",
             bg=V69_PANEL, fg=V69_MUTED).pack(anchor="w", pady=(2, 10))
