    tab_names = ["听写控制台", "加载设置", "路径设置", "显示隐藏", "自动拆分", "六步提示", "音效设置", "主题颜色", "快捷键"]
    tabs = {}
    for n in tab_names:
        f = tk.Frame(nb, bg=V69_PANEL); nb.add(f, text=n); tabs[n] = f

    vars_ = {k:{} for k in ["control_panel","loading","paths","display","dictation","sound","theme","hotkeys"]}

    # 听写控制台
    for k, title in [("show_core","显示核心控制"),("show_resource","显示资源控制"),("show_hint","显示提示/规则"),("show_stats","显示统计区域")]:
        r = _v69_row(tabs["听写控制台"], title, "听写训练右侧控制台显示项。")
        vars_["control_panel"][k] = tk.BooleanVar(value=bool(cfg["control_panel"].get(k, True)))
        ttk.Checkbutton(r, text="显示", variable=vars_["control_panel"][k]).pack(side="right", padx=12)
    ttk.Button(tabs["听写控制台"], text="重建听写控制台", command=lambda: (_v69_rebuild_right_panel(self), _v69_notice(self, "听写控制台已重建。", "ok"))).pack(anchor="w", padx=14, pady=10)

    # 加载设置
    load = cfg["loading"]
    combo_defs = [
        ("online_storage_mode","在线资源视频处理","缓存学习=临时下载；存储到本地资源=写入资源平台。",["缓存学习","存储到本地资源"]),
        ("online_translate_engine","在线资源翻译引擎","用于写入翻译字幕。",["OPUS-MT 本地","Argos 本地","Google 在线","百度API","腾讯API","DeepL"]),
        ("local_translate_engine","本地字幕翻译引擎","本地视频字幕缺中文时使用。",["OPUS-MT 本地","Argos 本地","Google 在线","百度API","腾讯API","DeepL"]),
        ("text_translate_engine","文本翻译引擎","文本全文翻译写回。",["OPUS-MT 本地","Argos 本地","Google 在线","百度API","腾讯API","DeepL"]),
        ("text_tts_engine","文本发音引擎","默认 Edge-TTS。",["Edge-TTS","原片音频","在线TTS"]),
    ]
    for k,title,desc,vals in combo_defs:
        r = _v69_row(tabs["加载设置"], title, desc)
        vars_["loading"][k] = tk.StringVar(value=str(load.get(k, vals[0])))
