_old_main_init_v69 = MainApp.__init__
def _main_init_v69(self):
    _old_main_init_v69(self)
    try:
        _v69_cfg(self)
        _v69_patch_globals(self)
        _v69_build_resource_platform_inline(self)
        _v69_rebuild_right_panel(self)
        _v69_dedupe_and_bind_buttons(self)
        _v69_bind_material_tree(self)
        try:
            self.after(250, lambda: (_v69_patch_globals(self), _v69_dedupe_and_bind_buttons(self), _v69_bind_material_tree(self)))
            self.after(900, lambda: (_v69_rebuild_right_panel(self), _v69_render_learning_area(self), _v69_notice(self, "V69 主链已接管：素材加载/设置中心/资源平台不再走 V68 递归旧链。", "ok")))
        except Exception:
            pass
        self.log("【V69上线】修复 V68 递归覆盖：听写素材池加载、设置中心、资源平台加载重新走独立主链。", "ok")
        self.log("【V69上线】设置中心完整中文内容：听写控制台/加载/路径/显示/拆分/提示/音效/主题/快捷键。", "ok")
        self.log("【V69上线】我的资源站直接显示资源平台；扫描和表格刷新分批执行，减少卡顿。", "ok")
    except Exception as e:
        try: self.log(f"V69初始化失败：{type(e).__name__}: {e}", "err")
        except Exception: pass

MainApp.__init__ = _main_init_v69
