def _v70_cfg(self):
    if callable(_V70_PREV_CFG):
        try:
            cfg = _V70_PREV_CFG(self)
        except Exception:
            cfg = {}
    else:
        cfg = getattr(self, "v69_cfg", {}) if hasattr(self, "v69_cfg") else {}
    if not isinstance(cfg, dict):
        cfg = {}
    cfg.setdefault("hint", {})
    cfg["hint"].setdefault("display_mode", "逐个显示")
    cfg["hint"].setdefault("error_spelling", True)
    cfg["hint"].setdefault("error_pos", True)
    cfg["hint"].setdefault("error_plural", True)
    cfg.setdefault("display", {})
    cfg["display"].setdefault("show_chinese_toggle", True)
    cfg.setdefault("dictation", {})
    cfg["dictation"].setdefault("show_ipa_above_word", True)
    cfg["dictation"].setdefault("show_pos_below_line", True)
    cfg["dictation"].setdefault("subtitle_burn_preview", True)
    cfg.setdefault("paths", {})
    cfg["paths"].setdefault("video_preview_cache", str(_Path_v69.cwd() / "clip_cache" / "qt_preview_v70"))
    self.v69_cfg = cfg
    try:
        self.v63_cfg = cfg
    except Exception:
        pass
    return cfg

def _v70_save_cfg(self):
    cfg = _v70_cfg(self)
    if callable(_V70_PREV_SAVE_CFG):
        try:
            _V70_PREV_SAVE_CFG(self)
            return
        except Exception:
            pass
    try:
        p = _Path_v69.cwd() / "pp_studio_v70_settings.json"
        p.write_text(_json_v69.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
    except Exception:
        pass

def _v70_notice(self, msg, level="info", scope="dictation"):
    if callable(_V70_PREV_NOTICE):
        try:
            return _V70_PREV_NOTICE(self, msg, level, scope)
        except TypeError:
            try:
                return _V70_PREV_NOTICE(self, msg, level)
            except Exception:
                pass
        except Exception:
            pass
    try:
        self.log(str(msg), "ok" if level == "ok" else ("err" if level in ("bad","err") else "info"))
    except Exception:
        pass

def _v70_words(s):
    return _re_v69.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v70_norm_word(w):
    return _re_v69.sub(r"[^A-Za-z']", "", str(w or "")).lower()

def _v70_lookup_ipa_from_local_dict(self, word):
    word = _v70_norm_word(word)
    if not word:
        return ""
    cache = getattr(self, "_v70_ipa_cache", None)
    if cache is None:
        cache = {}
        self._v70_ipa_cache = cache
    if word in cache:
        return cache[word]
    if word in V70_IPA:
        cache[word] = V70_IPA[word]
        return cache[word]
    cfg = _v70_cfg(self)
    root = _Path_v69(str(cfg.get("paths", {}).get("dictionary_root", "")))
    if not root.exists():
        cache[word] = ""
        return ""
    # 轻量检索：只检索前 40 个小型文本/CSV/MDX导出的文本文件，避免 UI 卡死。
    pat = _re_v69.compile(r"\b" + _re_v69.escape(word) + r"\b.{0,120}?((?:AmE|BrE|US|UK)?\s*[/\[][^\]/\[]+[/\]])", _re_v69.I)
    count = 0
    for ext in ("*.txt", "*.csv", "*.tsv", "*.json", "*.md"):
        try:
            files = list(root.rglob(ext))
        except Exception:
            files = []
        for fp in files:
            if count >= 40:
                cache[word] = ""
                return ""
            count += 1
            try:
                if fp.stat().st_size > 15 * 1024 * 1024:
                    continue
                with fp.open("r", encoding="utf-8", errors="ignore") as f:
                    for line_no, line in enumerate(f):
                        if line_no > 200000:
                            break
                        if word not in line.lower():
                            continue
                        m = pat.search(line)
                        if m:
                            val = _re_v69.sub(r"\s+", " ", m.group(1)).strip()
                            cache[word] = val
                            return val
            except Exception:
                continue
    cache[word] = ""
    return ""

def _v70_ipa_for(self, text):
    words = _v70_words(text)
    if not words:
        return ""
    vals = []
    for w in words[:4]:
        ipa = _v70_lookup_ipa_from_local_dict(self, w)
        if ipa:
            vals.append(f"{w}: {ipa}")
    return "  ".join(vals) if vals else "音标待补"

def _v70_pos_word(w):
    lw = _v70_norm_word(w)
    if not lw:
        return "符号"
    if lw in V70_ART:
        return "冠词"
    if lw in V70_PRON_PERSONAL:
        return "人称代词"
    if lw in V70_PRON_POSSESSIVE:
        return "物主代词"
    if lw in V70_DET:
        return "限定词"
    if lw in V70_CONJ:
        return "连词/从句引导词"
    if lw in V70_PREP:
        return "介词"
    if lw in V70_AUX:
        return "助动词/情态动词"
    if lw in V70_ADV or lw.endswith("ly"):
        return "副词"
    if lw in V70_COMMON_NOUN:
        return "名词"
    if lw in V70_COMMON_VERB:
        return "动词"
    if lw in V70_ADJ:
        return "形容词"
    if lw.endswith(("tion","sion","ment","ness","ity","ism","ship","er","or","ist","age","ance","ence")):
        return "名词"
    if lw.endswith(("ous","ful","less","ive","able","ible","al","ic","ical","ary","ent","ant")):
        return "形容词"
    if lw.endswith("ing"):
        return "动名词/现在分词"
    if lw.endswith("ed"):
        return "过去式/过去分词"
    if lw.endswith("s") and len(lw) > 3:
        return "名词复数/第三人称单数"
    return "词性提示"

def _v70_role(group):
    low = [_v70_norm_word(x) for x in group if _v70_norm_word(x)]
    if not low:
        return "语块"
    txt = " ".join(low)
    if txt in V70_FIXED_PHRASES:
        return "固定短语"
    if low[0] in V70_CONJ:
        return "连接词/从句"
    if low[0] in V70_PREP:
        return "介词短语"
    if low[0] in V70_ART:
        rest = [_v70_pos_word(x) for x in low[1:]]
        return "冠词 + " + (" + ".join(rest) if rest else "名词短语")
    if low[0] in V70_PRON_PERSONAL and len(low) >= 2:
        return "主语代词 + " + _v70_pos_word(low[1])
    if low[0] in V70_PRON_POSSESSIVE:
        return "物主代词 + 名词短语"
    if any(x in V70_AUX for x in low):
        return "主句/谓语结构"
    poss = [_v70_pos_word(x) for x in low]
    # 去重但保序
    compact = []
    for p in poss:
        if p not in compact:
            compact.append(p)
    if len(compact) == 1:
        return compact[0]
    if len(low) >= 3 and all(p in {"名词","形容词","限定词","冠词","名词复数/第三人称单数","词性提示"} for p in poss):
        return "名词短语"
    return " + ".join(compact[:4])

def _v70_protect_phrases(words):
    low = [w.lower() for w in words]
    phrase_map = sorted([p.split() for p in V70_FIXED_PHRASES], key=len, reverse=True)
    groups, i = [], 0
    while i < len(words):
        hit = None
        for ph in phrase_map:
            n = len(ph)
            if i + n <= len(words) and low[i:i+n] == ph:
                hit = n
                break
        if hit:
            groups.append(words[i:i+hit])
            i += hit
        else:
            groups.append([words[i]])
            i += 1
    return groups

def _v70_chunks(self, text, mode="整句播放"):
    words = _v70_words(text)
    if not words:
        return []
    protected = _v70_protect_phrases(words)
    groups, buf = [], []

    def flush():
        nonlocal buf
        if buf:
            groups.append(buf)
            buf = []

    for g in protected:
        lw0 = _v70_norm_word(g[0]) if g else ""
        phrase = " ".join(_v70_norm_word(x) for x in g)
        if phrase in V70_FIXED_PHRASES or lw0 in V70_CONJ or lw0 in V70_PREP:
            flush()
            groups.append(g)
        else:
            # 专有名词连续/名词短语优先合并，长度控制在 4。
            if len(buf) + len(g) <= 4:
                buf += g
            else:
                flush()
                buf = list(g)
    flush()

    final = []
    for g in groups:
        if len(g) <= 5:
            final.append(g)
        else:
            for i in range(0, len(g), 4):
                final.append(g[i:i+4])
    return [{"text": " ".join(g), "words": g, "role": _v70_role(g)} for g in final]

def _v70_sentence_type(n):
    if n <= 8: return "超短句"
    if n <= 12: return "短句"
    if n <= 20: return "中句"
    if n <= 32: return "长句"
    return "超长句"

def _v70_width(text, mode):
    if mode == "拆分播放":
        return max(3, min(8, len(str(text)) + 1))
    return max(8, min(42, len(str(text)) + 2))

def _v70_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

def _v70_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or "")
    return ""

def _v70_get_current_material(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats)-1)) if mats else 0
    return mats[idx] if mats else None

def _v70_render_learning_area(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in list(parent.winfo_children()):
        try: ch.destroy()
        except Exception: pass

    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        tk.Label(parent, text="当前没有素材：请从左侧素材池或资源平台加载",
                 bg=V70_BG, fg=V70_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        if not hasattr(self, "dict_v69_notice_var"):
            self.dict_v69_notice_var = tk.StringVar(value="等待加载素材")
        tk.Label(parent, textvariable=self.dict_v69_notice_var, bg="#07111f", fg=V70_MUTED,
                 font=("Microsoft YaHei UI", 11, "bold"), anchor="w").pack(fill="x", side="bottom")
        return

    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats)-1))
    self.dictation_index_v30 = idx
    try: self.dict_index_v33 = idx
    except Exception: pass
    m = mats[idx]
    text = _v70_item_text(m)
    zh = _v70_item_zh(m)
    words = _v70_words(text)

    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    mode = self.dict_play_mode_v46.get() if self.dict_play_mode_v46.get() in ("整句播放","拆分播放") else "整句播放"

    if not hasattr(self, "dictation_show_cn_v30"):
        self.dictation_show_cn_v30 = tk.BooleanVar(value=True)

    try:
        if hasattr(self, "dictation_target_meta_var_v30"):
            self.dictation_target_meta_var_v30.set(f"{idx+1}/{len(mats)}｜{text[:100]}")
    except Exception:
        pass

    top = tk.Frame(parent, bg=V70_BG)
    top.pack(fill="x", pady=(14, 6))
    cn_text = zh if self.dictation_show_cn_v30.get() and zh else ("中文翻译/提示未加载" if self.dictation_show_cn_v30.get() else "中文翻译和提示已隐藏")
    tk.Label(top, text=cn_text, bg=V70_BG, fg=V70_TEXT if self.dictation_show_cn_v30.get() else V70_MUTED,
             font=("Microsoft YaHei UI", 20, "bold"), wraplength=1150, justify="center").pack(anchor="center")
    top_btn = tk.Frame(parent, bg=V70_BG)
    top_btn.pack(pady=(0, 6))
    ttk.Button(top_btn, text=("隐藏中文" if self.dictation_show_cn_v30.get() else "显示中文"),
               command=lambda: (self.dictation_show_cn_v30.set(not self.dictation_show_cn_v30.get()), _v70_render_learning_area(self))).pack(side="left", padx=4)

    ctl = tk.Frame(parent, bg=V70_BG)
    ctl.pack(pady=(2, 8))
    cb = ttk.Combobox(ctl, textvariable=self.dict_play_mode_v46, values=["整句播放", "拆分播放"], state="readonly", width=12)
    cb.pack(side="left", padx=4)
    cb.bind("<<ComboboxSelected>>", lambda e: _v70_render_learning_area(self))
    ttk.Button(ctl, text="播放音频", command=lambda: _v70_play_audio(self)).pack(side="left", padx=4)
    ttk.Button(ctl, text="播放视频", command=lambda: _v70_play_video(self)).pack(side="left", padx=4)
    ttk.Button(ctl, text="跳过当前块", command=lambda: _v70_next(self)).pack(side="left", padx=4)
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)
    ttk.Checkbutton(ctl, text="自动跳到下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=7)

    tk.Label(parent, text=f"句长：{len(words)}词｜类型：{_v70_sentence_type(len(words))}｜呈现：语块分组｜拆分模式：组内约3字符，组间约10字符",
             bg=V70_BG, fg=V70_MUTED, font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(0, 6))

    chunks = _v70_chunks(self, text, mode)
    board = tk.Frame(parent, bg=V70_BG)
    board.pack(anchor="center", padx=16, pady=(4, 6))
    self.dict_v46_entries = []

    show_ipa = bool(_v70_cfg(self).get("dictation", {}).get("show_ipa_above_word", True))
    show_pos = bool(_v70_cfg(self).get("dictation", {}).get("show_pos_below_line", True))

    if mode == "拆分播放":
        line = None
        used_chars = 0
        max_chars = 92
        inner_gap_px = 3 * 8
        group_gap_px = 10 * 8
        for gi, ch in enumerate(chunks):
            g_words = ch["words"]
            group_chars = sum(min(8, max(3, len(w)+1)) for w in g_words) + max(0, len(g_words)-1) * 3 + 10
            if line is None or used_chars + group_chars > max_chars:
                line = tk.Frame(board, bg=V70_BG)
                line.pack(anchor="center", pady=8)
                used_chars = 0
            group = tk.Frame(line, bg=V70_BG)
            group.pack(side="left", padx=(group_gap_px if used_chars else 0, 0))
            word_row = tk.Frame(group, bg=V70_BG)
            word_row.pack(anchor="center")
            for wi, w in enumerate(g_words):
                cell = tk.Frame(word_row, bg=V70_BG)
                cell.pack(side="left", padx=(0 if wi == 0 else inner_gap_px, 0))
                if show_ipa:
                    tk.Label(cell, text=_v70_lookup_ipa_from_local_dict(self, w) or "音标待补",
                             bg=V70_BG, fg=V70_MUTED, font=("Microsoft YaHei UI", 7)).pack(anchor="center")
                width = _v70_width(w, mode)
                ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V70_BG, fg=V70_INPUT,
                              insertbackground=V70_INPUT, relief="flat", bd=0,
                              font=("Consolas", 19, "bold"), undo=False)
                ent.pack()
                cw = max(58, min(120, width * 15))
                cv = tk.Canvas(cell, width=cw, height=8, bg=V70_BG, highlightthickness=0)
                cv.pack()
                cv.create_line(2, 4, cw-2, 4, fill=V70_INPUT if not self.dict_v46_entries else V70_LINE, width=3)
                item = {"idx": len(self.dict_v46_entries), "target": w, "role": ch["role"], "entry": ent, "line": cv, "w": cw, "group": gi}
                self.dict_v46_entries.append(item)
                ent.bind("<KeyRelease>", lambda e, it=item: _v70_live_color(self, it))
                ent.bind("<space>", lambda e, it=item: (_v70_judge_block(self, it), "break"))
                ent.bind("<Return>", lambda e: (_v70_submit_all(self), "break"))
                ent.bind("<Control-h>", lambda e: (_v70_hint_current(self), "break"))
            if show_pos:
                tk.Label(group, text=ch["role"], bg=V70_BG, fg=V70_MUTED,
                         font=("Microsoft YaHei UI", 8, "bold")).pack(pady=(4,0))
            used_chars += group_chars
    else:
        line = None
        used_chars = 0
        max_chars = 96
        for gi, ch in enumerate(chunks):
            tx = ch["text"]
            width = _v70_width(tx, mode)
            if line is None or used_chars + width > max_chars:
                line = tk.Frame(board, bg=V70_BG)
                line.pack(anchor="center", pady=8)
                used_chars = 0
            cell = tk.Frame(line, bg=V70_BG)
            cell.pack(side="left", padx=20, pady=2)
            if show_ipa:
                tk.Label(cell, text=_v70_ipa_for(self, tx), bg=V70_BG, fg=V70_MUTED,
                         font=("Microsoft YaHei UI", 8)).pack(anchor="center")
            ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V70_BG, fg=V70_INPUT,
                          insertbackground=V70_INPUT, relief="flat", bd=0,
                          font=("Consolas", 20, "bold"), undo=False)
            ent.pack()
            cw = max(130, min(600, width * 15))
            cv = tk.Canvas(cell, width=cw, height=8, bg=V70_BG, highlightthickness=0)
            cv.pack()
            cv.create_line(2, 4, cw-2, 4, fill=V70_INPUT if gi == 0 else V70_LINE, width=3)
            if show_pos:
                tk.Label(cell, text=ch["role"], bg=V70_BG, fg=V70_MUTED,
                         font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4,0))
            item = {"idx": len(self.dict_v46_entries), "target": tx, "role": ch["role"], "entry": ent, "line": cv, "w": cw, "group": gi}
            self.dict_v46_entries.append(item)
            ent.bind("<KeyRelease>", lambda e, it=item: _v70_live_color(self, it))
            ent.bind("<space>", lambda e, it=item: (_v70_judge_block(self, it), "break"))
            ent.bind("<Return>", lambda e: (_v70_submit_all(self), "break"))
            ent.bind("<Control-h>", lambda e: (_v70_hint_current(self), "break"))
            used_chars += width + 6

    hint_panel = tk.Frame(parent, bg="#0f172a", bd=1, relief="solid")
    hint_panel.pack(fill="x", padx=120, pady=(16, 6))
    tk.Label(hint_panel, text="固定提示 / 六步提示 / 错误提示", bg="#0f172a", fg=V70_TEXT,
             font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w", padx=12, pady=(8, 2))
    if not hasattr(self, "dict_v62_side_var"):
        self.dict_v62_side_var = tk.StringVar()
    self.dict_v62_side_var.set("按 Ctrl+H：音标 → 同音词 → 近反义词 → 首尾字母 → 英文释义 → 同形词/答案。")
    tk.Label(hint_panel, textvariable=self.dict_v62_side_var, bg="#0f172a", fg=V70_MUTED,
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0,4))
    if not hasattr(self, "dict_v63_hint_var"):
        self.dict_v63_hint_var = tk.StringVar()
    tk.Label(hint_panel, textvariable=self.dict_v63_hint_var, bg="#0f172a", fg="#38BDF8",
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0,8))

    if not hasattr(self, "dict_v69_notice_var"):
        self.dict_v69_notice_var = tk.StringVar(value="就绪")
    tk.Label(parent, textvariable=self.dict_v69_notice_var, bg="#07111f", fg=V70_MUTED,
             font=("Microsoft YaHei UI", 11, "bold"), anchor="w").pack(fill="x", padx=18, pady=(4,0), side="bottom")

    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    _v70_notice(self, "学习区已刷新：音标、语块提示、六步提示模式已生效。", "ok")

def _v70_norm_answer(s):
    return _re_v69.sub(r"\s+", " ", str(s or "")).strip().lower()

def _v70_lev(a, b):
    a, b = str(a), str(b)
    if len(a) < len(b):
        a, b = b, a
    prev = list(range(len(b)+1))
    for i, ca in enumerate(a, 1):
        cur = [i]
        for j, cb in enumerate(b, 1):
            cur.append(min(prev[j]+1, cur[-1]+1, prev[j-1] + (ca != cb)))
        prev = cur
    return prev[-1]

def _v70_error_details(self, user, target, role):
    cfg = _v70_cfg(self).get("hint", {})
    user_words = _v70_words(user)
    target_words = _v70_words(target)
    msgs = []
    if cfg.get("error_spelling", True):
        for i, tw in enumerate(target_words):
            uw = user_words[i] if i < len(user_words) else ""
            if not uw:
                msgs.append(f"检查拼写：第{i+1}词缺失，目标词长度 {len(tw)}。")
            elif uw.lower() != tw.lower() and _v70_lev(uw.lower(), tw.lower()) <= max(1, len(tw)//4):
                msgs.append(f"检查拼写：第{i+1}词 {uw} 接近 {tw}，但拼写不完全正确。")
    if cfg.get("error_plural", True):
        for i, tw in enumerate(target_words):
            uw = user_words[i] if i < len(user_words) else ""
            if uw and (uw.lower()+"s" == tw.lower() or uw.lower()+"es" == tw.lower() or tw.lower()+"s" == uw.lower() or tw.lower()+"es" == uw.lower()):
                msgs.append(f"检查单复数：第{i+1}词可能是单复数/三单形式错误。")
    if cfg.get("error_pos", True):
        # 词性提示不做假判断，只显示目标词性/结构，避免 music 被误判为形容词。
        pos = "；".join(f"{w}:{_v70_pos_word(w)}" for w in target_words[:6])
        msgs.append(f"检查词性：当前目标结构={role}；目标词性={pos}")
    return "\n".join(msgs[:6]) if msgs else "输入不匹配，请检查拼写、词形或顺序。"

def _v70_live_color(self, item):
    ent = item["entry"]
    val = ent.get("1.0", "end-1c").strip()
    target = str(item["target"]).strip()
    try:
        item["line"].delete("all")
        color = V70_INPUT
        if val and _v70_norm_answer(target).startswith(_v70_norm_answer(val)):
            color = V70_OK if _v70_norm_answer(val) == _v70_norm_answer(target) else V70_INPUT
        elif val:
            color = V70_BAD
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        ent.configure(fg=color)
    except Exception:
        pass

def _v70_judge_block(self, item):
    ent = item["entry"]
    val = _re_v69.sub(r"\s+", " ", ent.get("1.0", "end-1c")).strip()
    target = _re_v69.sub(r"\s+", " ", str(item["target"])).strip()
    ok = _v70_norm_answer(val) == _v70_norm_answer(target)
    color = V70_OK if ok else V70_BAD
    try:
        item["line"].delete("all")
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        ent.configure(fg=color)
    except Exception:
        pass
    if ok:
        msg = f"当前块正确：{target}"
        _v70_notice(self, msg, "ok")
        try:
            self.dict_v63_hint_var.set("✅ " + msg)
        except Exception:
            pass
        nxt = item["idx"] + 1
        entries = getattr(self, "dict_v46_entries", []) or []
        if nxt < len(entries):
            entries[nxt]["entry"].focus_set()
        else:
            if bool(getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get()):
                _v70_next(self)
    else:
        detail = _v70_error_details(self, val, target, item.get("role", "语块"))
        msg = f"当前块错误｜你输入：{val or '空'}｜目标结构：{item.get('role','语块')}\n{detail}"
        _v70_notice(self, "当前块错误，固定提示区已显示原因。", "bad")
        try:
            self.dict_v63_hint_var.set("❌ " + msg)
            self.dict_v62_side_var.set("错误提示已固定显示；请按提示修改后再按 Space 判断。")
        except Exception:
            pass
    return ok

def _v70_submit_all(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    ok_all = True
    for it in entries:
        ok_all = _v70_judge_block(self, it) and ok_all
    if ok_all:
        _v70_notice(self, "整句全部正确。", "ok")
        if bool(getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get()):
            _v70_next(self)
    return ok_all

def _v70_next(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        return
    self.dictation_index_v30 = min(len(mats)-1, int(getattr(self, "dictation_index_v30", 0) or 0) + 1)
    try: self.dict_index_v33 = self.dictation_index_v30
    except Exception: pass
    _v70_render_learning_area(self)

def _v70_prev(self):
    self.dictation_index_v30 = max(0, int(getattr(self, "dictation_index_v30", 0) or 0) - 1)
    try: self.dict_index_v33 = self.dictation_index_v30
    except Exception: pass
    _v70_render_learning_area(self)

def _v70_active_item(self):
    focus = None
    try: focus = self.focus_get()
    except Exception: pass
    entries = getattr(self, "dict_v46_entries", []) or []
    for it in entries:
        if it.get("entry") is focus:
            return it
    return entries[0] if entries else None

def _v70_base_word(s):
    w = _v70_words(s)
    return _v70_norm_word(w[0]) if w else ""

def _v70_hint_current(self):
    item = _v70_active_item(self)
    if not item:
        _v70_notice(self, "当前没有可提示的输入块。", "bad")
        return
    target = str(item.get("target") or "")
    word = _v70_base_word(target)
    step = (int(getattr(self, "_v70_hint_step", 0) or 0) % 6) + 1
    self._v70_hint_step = step
    if step == 1:
        title = "① 音标提示"; body = _v70_lookup_ipa_from_local_dict(self, word) or f"本地音标未命中：{word}。请在设置中心配置本地词典目录。"
    elif step == 2:
        title = "② 同音词提示"; body = " / ".join(V70_HOMOPHONES.get(word, [])) or "本地未记录同音词。"
    elif step == 3:
        title = "③ 近义/反义提示"; d = V70_SYN.get(word, {}); body = f"近义：{', '.join(d.get('近义', [])) or '未记录'}；反义：{', '.join(d.get('反义', [])) or '未记录'}"
    elif step == 4:
        title = "④ 首尾字母提示"; body = f"首字母：{word[:1] or '无'}；末尾字母：{word[-1:] or '无'}；长度：{len(word)}"
    elif step == 5:
        title = "⑤ 英文释义提示"; body = V70_DEF.get(word, "本地释义未命中；可接入本地词典/在线词典 API。")
    else:
        title = "⑥ 同形词/答案提示"; body = f"正确答案：{target}"

    msg = f"{title}｜当前块：{target}｜结构：{item.get('role','语块')}\n{body}"
    mode = _v70_cfg(self).get("hint", {}).get("display_mode", "逐个显示")
    if mode == "叠加显示":
        acc = getattr(self, "_v70_hint_accumulator", [])
        acc.append(msg)
        acc = acc[-6:]
        self._v70_hint_accumulator = acc
        show = "\n\n".join(acc)
    else:
        self._v70_hint_accumulator = [msg]
        show = msg
    try:
        self.dict_v63_hint_var.set(show)
        self.dict_v62_side_var.set(f"六步提示：{mode}。继续按 Ctrl+H 切换下一层。")
    except Exception:
        pass
    _v70_notice(self, f"六步提示更新：{title}｜{mode}", "info")

def _v70_find_ffmpeg(self):
    try:
        if hasattr(self, "ffmpeg") and getattr(self.ffmpeg, "ffmpeg", None):
            return self.ffmpeg.ffmpeg
    except Exception:
        pass
    try:
        return _v69_find_ffmpeg(self)
    except Exception:
        return "ffmpeg"

def _v70_subtitle_filter_path(path):
    p = str(path).replace("\\", "/")
    # FFmpeg subtitles filter on Windows needs escaped colon.
    p = p.replace(":", "\\:")
    p = p.replace("'", "\\'")
    return p

def _v70_no_window_kwargs():
    try:
        return no_window()
    except Exception:
        if _os_v69.name == "nt":
            return {"creationflags": getattr(_subprocess_v69, "CREATE_NO_WINDOW", 0)}
        return {}

def _v70_make_qt_preview_clip(self, m):
    video = str(m.get("video_path") or m.get("media_path") or m.get("local_path") or "")
    if not video and str(m.get("source_type","")).startswith("online") and callable(_V70_PREV_CACHE_ONLINE_VIDEO):
        try:
            video = _V70_PREV_CACHE_ONLINE_VIDEO(self, m) or ""
        except Exception:
            video = ""
    if not video or not _Path_v69(video).exists():
        return ""
    sub = str(m.get("subtitle_path") or "")
    start = float(m.get("start") or 0)
    end = float(m.get("end") or 0)
    cfg = _v70_cfg(self)
    burn = bool(cfg.get("dictation", {}).get("subtitle_burn_preview", True))
    # 没有时间轴就直接交给 Qt 播放原视频；有时间轴才生成片段。
    if end <= start and not (burn and sub and _Path_v69(sub).exists()):
        return video
    if end <= start:
        end = start + 8.0
    out_dir = _Path_v69(str(cfg.get("paths", {}).get("video_preview_cache", _Path_v69.cwd() / "clip_cache" / "qt_preview_v70")))
    out_dir.mkdir(parents=True, exist_ok=True)
    key = f"{_Path_v69(video).stem}_{int(start*1000)}_{int(end*1000)}_{'sub' if sub else 'nosub'}.mp4"
    key = _re_v69.sub(r'[\\/:*?"<>|]+', "_", key)
    out = out_dir / key
    if out.exists() and out.stat().st_size > 1024:
        return str(out)
    ff = _v70_find_ffmpeg(self)
    cmd = [ff, "-y", "-hide_banner", "-loglevel", "error", "-ss", f"{start:.3f}", "-to", f"{end:.3f}", "-i", video]
    if burn and sub and _Path_v69(sub).exists():
        filt = "subtitles=filename='" + _v70_subtitle_filter_path(sub) + "':force_style='FontName=Microsoft YaHei,FontSize=24,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,BorderStyle=1,Outline=2'"
        cmd += ["-vf", filt]
    cmd += ["-c:v", "libx264", "-preset", "ultrafast", "-crf", "24", "-c:a", "aac", "-b:a", "128k", "-movflags", "+faststart", str(out)]
    _v70_notice(self, "正在生成 Qt 字幕预览片段。", "info")
    try:
        r = _subprocess_v69.run(cmd, capture_output=True, text=True, timeout=90, **_v70_no_window_kwargs())
        if r.returncode == 0 and out.exists() and out.stat().st_size > 1024:
            _v70_notice(self, "Qt 字幕预览片段已生成。", "ok")
            return str(out)
        else:
            err = (r.stderr or "").splitlines()[-3:]
            _v70_notice(self, "字幕预览片段生成失败，改用原视频 Qt 播放。" + ("｜" + "；".join(err) if err else ""), "bad")
            return video
    except Exception as e:
        _v70_notice(self, f"字幕预览片段生成异常：{type(e).__name__}: {e}；改用原视频 Qt 播放。", "bad")
        return video

def _v70_play_video(self):
    m = _v70_get_current_material(self)
    if not m:
        _v70_notice(self, "没有选中素材，无法播放视频。", "bad")
        return
    if str(m.get("source_type","")) == "local_text" and not (m.get("video_path") or m.get("media_path")):
        _v70_notice(self, "文本资源不支持视频播放；请使用音频/TTS。", "bad")
        return
    path = _v70_make_qt_preview_clip(self, m)
    if not path or not _Path_v69(path).exists():
        _v70_notice(self, "当前素材没有可用视频。", "bad")
        return
    try:
        if hasattr(self, "player"):
            self.player.play(_Path_v69(path))
            _v70_notice(self, f"已交给 Qt 播放窗口播放：{_Path_v69(path).name}", "ok")
            return
    except Exception as e:
        _v70_notice(self, f"Qt 播放失败：{type(e).__name__}: {e}", "bad")
    # 最后兜底才系统播放器
    try:
        if _os_v69.name == "nt":
            _os_v69.startfile(path)
        elif _sys_v69.platform == "darwin":
            _subprocess_v69.Popen(["open", path])
        else:
            _subprocess_v69.Popen(["xdg-open", path])
        _v70_notice(self, "Qt 不可用，已兜底系统播放器。", "bad")
    except Exception as e:
        _v70_notice(self, f"视频播放失败：{type(e).__name__}: {e}", "bad")

def _v70_play_audio(self):
    try:
        return _v69_play_audio(self)
    except Exception as e:
        _v70_notice(self, f"音频播放失败：{type(e).__name__}: {e}", "bad")

def _v70_row(parent, title, desc=""):
    r = tk.Frame(parent, bg=V70_PANEL)
    r.pack(fill="x", padx=14, pady=7)
    l = tk.Frame(r, bg=V70_PANEL)
    l.pack(side="left", fill="x", expand=True)
    tk.Label(l, text=title, bg=V70_PANEL, fg=V70_TEXT, font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w")
    if desc:
        tk.Label(l, text=desc, bg=V70_PANEL, fg=V70_MUTED, wraplength=780, justify="left").pack(anchor="w")
    return r

def _v70_choose_dir(var):
    d = filedialog.askdirectory()
    if d:
        var.set(d)

def _v70_open_path(path):
    p = _Path_v69(str(path or "."))
    p.mkdir(parents=True, exist_ok=True)
    try:
        if _os_v69.name == "nt": _os_v69.startfile(str(p))
        elif _sys_v69.platform == "darwin": _subprocess_v69.Popen(["open", str(p)])
        else: _subprocess_v69.Popen(["xdg-open", str(p)])
    except Exception:
        pass

def _v70_open_settings_center(self):
    cfg = _v70_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置中心 V70")
    win.geometry("1380x900")
    win.configure(bg=V70_PANEL)
    outer = tk.Frame(win, bg=V70_PANEL)
    outer.pack(fill="both", expand=True, padx=16, pady=12)
    tk.Label(outer, text="设置中心 V70", bg=V70_PANEL, fg=V70_TEXT, font=("Microsoft YaHei UI", 20, "bold")).pack(anchor="w")
    tk.Label(outer, text="听写控制台、加载、路径、显示隐藏、自动拆分、六步提示、错误提示、音效、主题、快捷键全部集中在这里。",
             bg=V70_PANEL, fg=V70_MUTED).pack(anchor="w", pady=(2,10))
    nb = ttk.Notebook(outer)
    nb.pack(fill="both", expand=True)

    names = ["听写控制台","加载设置","路径设置","显示隐藏","自动拆分","六步提示","错误提示","音效设置","主题颜色","快捷键"]
    tabs = {}
    for name in names:
        f = tk.Frame(nb, bg=V70_PANEL)
        nb.add(f, text=name)
        tabs[name] = f

    vars_ = {"control_panel":{}, "loading":{}, "paths":{}, "display":{}, "dictation":{}, "hint":{}, "sound":{}, "theme":{}, "hotkeys":{}}

    # 听写控制台
    for k, title in [("show_core","显示核心控制"),("show_resource","显示资源控制"),("show_hint","显示提示/规则"),("show_stats","显示统计区域")]:
        r = _v70_row(tabs["听写控制台"], title, "听写训练右侧控制台显示项。")
        vars_["control_panel"][k] = tk.BooleanVar(value=bool(cfg.get("control_panel", {}).get(k, True)))
        ttk.Checkbutton(r, text="显示", variable=vars_["control_panel"][k]).pack(side="right", padx=12)
    ttk.Button(tabs["听写控制台"], text="重建听写控制台", command=lambda: (_v70_rebuild_right_panel(self), _v70_notice(self, "听写控制台已重建。", "ok"))).pack(anchor="w", padx=14, pady=10)

    # 加载设置
    load = cfg.get("loading", {})
    combo_defs = [
        ("online_storage_mode","在线资源视频处理","缓存学习=临时下载；存储到本地资源=写入资源平台。",["缓存学习","存储到本地资源"]),
        ("online_translate_engine","在线资源翻译引擎","用于写入翻译字幕。",["OPUS-MT 本地","Argos 本地","Google 在线","百度API","腾讯API","DeepL"]),
        ("local_translate_engine","本地字幕翻译引擎","本地视频字幕缺中文时使用。",["OPUS-MT 本地","Argos 本地","Google 在线","百度API","腾讯API","DeepL"]),
        ("text_translate_engine","文本翻译引擎","文本全文翻译写回。",["OPUS-MT 本地","Argos 本地","Google 在线","百度API","腾讯API","DeepL"]),
        ("text_tts_engine","文本发音引擎","默认 Edge-TTS。",["Edge-TTS","原片音频","在线TTS"]),
    ]
    for k,title,desc,vals in combo_defs:
        r = _v70_row(tabs["加载设置"], title, desc)
        vars_["loading"][k] = tk.StringVar(value=str(load.get(k, vals[0])))
        ttk.Combobox(r, values=vals, textvariable=vars_["loading"][k], state="readonly", width=24).pack(side="right", padx=12)
    for k,title,desc in [
        ("online_download_on_load","安全加载精选池时同时下载到本地","关闭时只加载文本到学习区，不阻塞。"),
        ("online_download_video","下载视频文件","开启后后补下载会尝试下载视频。"),
        ("online_write_origin_subtitle","写入原文字幕","生成 .en.srt。"),
        ("online_write_translate_subtitle","写入翻译字幕","生成 .zh.srt。"),
    ]:
        r = _v70_row(tabs["加载设置"], title, desc)
        vars_["loading"][k] = tk.BooleanVar(value=bool(load.get(k, False)))
        ttk.Checkbutton(r, text="开启", variable=vars_["loading"][k]).pack(side="right", padx=12)

    # 路径
    for k,title in [("resource_root","资源平台根目录"),("output_root","输出目录"),("cache_root","缓存目录"),("dictionary_root","本地词典目录"),("video_preview_cache","Qt字幕预览缓存目录"),("operation_log","操作日志文件")]:
        r = _v70_row(tabs["路径设置"], title, "可选择/打开。")
        vars_["paths"][k] = tk.StringVar(value=str(cfg.get("paths", {}).get(k, "")))
