def _v71_dedupe_buttons(self):
    clear_seen = False
    def walk(w):
        nonlocal clear_seen
        try:
            txt = str(w.cget("text")).strip()
            if txt == "清空学习区":
                if clear_seen:
                    w.destroy(); return
                clear_seen = True
                w.configure(command=lambda:_v71_clear_learning(self))
            elif txt in {"播放当前音频", "播放音频", "主播放 Ctrl"}:
                w.configure(command=lambda:_v71_play_audio(self))
            elif txt in {"播放当前视频", "播放视频", "加载台词视频播放"}:
                w.configure(command=lambda:_v71_play_video(self))
            elif txt in {"安全加载精选池文本", "导入精选池", "从精选池导入"}:
                if callable(_V71_PREV_IMPORT_POOL):
                    w.configure(command=lambda:_V71_PREV_IMPORT_POOL(self))
            elif txt in {"后补下载在线资源", "下载精选池到本地"}:
                w.configure(command=lambda:_v71_download_online_to_local(self))
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v71_clear_learning(self):
    self.dictation_materials_v30 = []
    try: self.dict_items_v33 = []
    except Exception: pass
    self.dictation_index_v30 = 0
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is not None:
        try: tree.delete(*tree.get_children())
        except Exception: pass
    _v71_render_learning_area(self)
    _v71_notice(self, "学习区和听写素材池已清空。", "ok")

def _v71_download_online_to_local(self, mats=None):
    if callable(_V71_PREV_DOWNLOAD_ONLINE):
        try:
            return _V71_PREV_DOWNLOAD_ONLINE(self, mats)
        except TypeError:
            try:
                return _V71_PREV_DOWNLOAD_ONLINE(self)
            except Exception as e:
                _v71_notice(self, f"在线资源下载失败：{type(e).__name__}: {e}", "bad")
        except Exception as e:
            _v71_notice(self, f"在线资源下载失败：{type(e).__name__}: {e}", "bad")
    else:
        _v71_notice(self, "没有找到在线下载主链。", "bad")

