def _v72_chunks(self, text, mode="整句播放"):
    if callable(_V72_PREV_CHUNKS):
        try:
            return _V72_PREV_CHUNKS(self, text, mode)
        except Exception:
            pass
    words = _v72_words(text)
    return [{"text": " ".join(words[i:i+4]), "words": words[i:i+4], "role": "语块"} for i in range(0, len(words), 4)]

def _v72_ipa(self, word):
    if callable(_V72_PREV_IPA):
        try:
            return _V72_PREV_IPA(self, word) or "音标待补"
        except Exception:
            pass
    return "音标待补"

def _v72_render_learning_area(self):
    """
    V72 彻底移除 V71 的 place 悬浮按钮。
    学习区只保留正常布局：中文区、控制按钮、横线输入、固定提示。
    """
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    for ch in list(parent.winfo_children()):
        try:
            ch.destroy()
        except Exception:
            pass

    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        tk.Label(parent, text="当前没有素材：请从左侧素材池或资源平台加载",
                 bg=V72_BG, fg=V72_TEXT, font=("Microsoft YaHei UI", 22, "bold")).pack(expand=True)
        return

    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats) - 1))
    self.dictation_index_v30 = idx
    m = mats[idx]
    text = _v72_item_text(m)
    zh = _v72_item_zh(m)

    if not hasattr(self, "dictation_show_cn_v30"):
        self.dictation_show_cn_v30 = tk.BooleanVar(value=bool(_v72_cfg(self).get("display", {}).get("show_chinese", True)))

    if not hasattr(self, "dict_play_mode_v46"):
        self.dict_play_mode_v46 = tk.StringVar(value="整句播放")
    if self.dict_play_mode_v46.get() not in ("整句播放", "拆分播放"):
        self.dict_play_mode_v46.set("整句播放")
    if not hasattr(self, "dict_auto_next_line_v46"):
        self.dict_auto_next_line_v46 = tk.BooleanVar(value=True)

    top_meta = tk.Frame(parent, bg=V72_BG)
    top_meta.pack(fill="x", padx=20, pady=(8, 2))
    tk.Label(top_meta, text=f"{idx+1}/{len(mats)}｜{text[:100]}", bg=V72_BG, fg="#A5F3FC",
             font=("Microsoft YaHei UI", 10, "bold")).pack(side="left")

    cn_frame = tk.Frame(parent, bg=V72_BG)
    cn_frame.pack(fill="x", pady=(18, 4))
    if self.dictation_show_cn_v30.get():
        if zh:
            cn_text = zh
            fg = V72_TEXT
        else:
            cn_text = "中文翻译未加载"
            fg = V72_WARN
    else:
        cn_text = "中文翻译和提示已隐藏"
        fg = V72_MUTED
    tk.Label(cn_frame, text=cn_text, bg=V72_BG, fg=fg, font=("Microsoft YaHei UI", 22, "bold"),
             wraplength=1200, justify="center").pack(anchor="center")

    # 正常控制行，不使用 place，不悬浮，不遮挡。
    ctl1 = tk.Frame(parent, bg=V72_BG)
    ctl1.pack(pady=(6, 4))
    ttk.Button(ctl1, text=("隐藏中文" if self.dictation_show_cn_v30.get() else "显示中文"),
               command=lambda: (self.dictation_show_cn_v30.set(not self.dictation_show_cn_v30.get()), _v72_render_learning_area(self))).pack(side="left", padx=4)
    ttk.Button(ctl1, text="制作当前翻译", command=lambda: _v72_translate_current_async(self)).pack(side="left", padx=4)
    ttk.Button(ctl1, text="制作整文件翻译", command=lambda: _v72_open_translate_builder(self, "file")).pack(side="left", padx=4)
    ttk.Button(ctl1, text="播放前检查", command=lambda: _v72_preflight(self, "audio")).pack(side="left", padx=4)

    ctl2 = tk.Frame(parent, bg=V72_BG)
    ctl2.pack(pady=(4, 12))
    ttk.Combobox(ctl2, textvariable=self.dict_play_mode_v46, values=["整句播放", "拆分播放"],
                 state="readonly", width=12).pack(side="left", padx=4)
    ttk.Button(ctl2, text="播放音频", command=lambda: _v72_play_audio(self)).pack(side="left", padx=4)
    ttk.Button(ctl2, text="播放视频", command=lambda: _v72_play_video(self)).pack(side="left", padx=4)
    ttk.Button(ctl2, text="跳过当前块", command=lambda: _v72_next(self)).pack(side="left", padx=4)
    ttk.Checkbutton(ctl2, text="自动跳到下一行", variable=self.dict_auto_next_line_v46).pack(side="left", padx=6)

    words = _v72_words(text)
    tk.Label(parent, text=f"句长：{len(words)}词｜呈现：语块分组｜拆分模式：组内约3字符，组间约10字符",
             bg=V72_BG, fg=V72_MUTED, font=("Microsoft YaHei UI", 10, "bold")).pack(pady=(0, 8))

    chunks = _v72_chunks(self, text, self.dict_play_mode_v46.get())
    board = tk.Frame(parent, bg=V72_BG)
    board.pack(anchor="center", padx=10, pady=4)
    self.dict_v46_entries = []

    max_chars = 92
    used = 0
    line = None
    mode = self.dict_play_mode_v46.get()

    def new_line():
        f = tk.Frame(board, bg=V72_BG)
        f.pack(anchor="center", pady=9)
        return f

    line = new_line()
    for gi, ch in enumerate(chunks):
        group_words = ch.get("words") or _v72_words(ch.get("text", ""))
        if mode == "拆分播放":
            display_units = group_words
        else:
            display_units = [ch.get("text", " ".join(group_words))]
        group_width_chars = sum(min(10, max(4, len(x) + 1)) for x in display_units) + 10
        if used + group_width_chars > max_chars:
            line = new_line()
            used = 0
        group = tk.Frame(line, bg=V72_BG)
        group.pack(side="left", padx=(40 if used else 0, 0))
        unit_row = tk.Frame(group, bg=V72_BG)
        unit_row.pack(anchor="center")
        for ui, unit in enumerate(display_units):
            cell = tk.Frame(unit_row, bg=V72_BG)
            cell.pack(side="left", padx=(24 if ui else 0, 0))
            first_word = (_v72_words(unit) or [""])[0]
            tk.Label(cell, text=_v72_ipa(self, first_word), bg=V72_BG, fg=V72_MUTED,
                     font=("Microsoft YaHei UI", 8)).pack(anchor="center")
            width = max(6, min(42 if mode != "拆分播放" else 8, len(unit) + 2))
            ent = tk.Text(cell, width=width, height=1, wrap="none", bg=V72_BG, fg=V72_INPUT,
                          insertbackground=V72_INPUT, relief="flat", bd=0,
                          font=("Consolas", 20, "bold"), undo=False)
            ent.pack()
            cw = max(90, min(600, width * 16))
            cv = tk.Canvas(cell, width=cw, height=8, bg=V72_BG, highlightthickness=0)
            cv.pack()
            cv.create_line(2, 4, cw-2, 4, fill=V72_INPUT if len(self.dict_v46_entries) == 0 else V72_LINE, width=3)
            item = {"idx": len(self.dict_v46_entries), "target": unit, "role": ch.get("role", "语块"),
                    "entry": ent, "line": cv, "w": cw, "group": gi}
            self.dict_v46_entries.append(item)
            ent.bind("<KeyRelease>", lambda e, it=item: _v72_live_color(self, it))
            ent.bind("<space>", lambda e, it=item: (_v72_judge_block(self, it), "break"))
            ent.bind("<Return>", lambda e: (_v72_submit_all(self), "break"))
            ent.bind("<Control-h>", lambda e: (_v72_hint_current(self), "break"))
        tk.Label(group, text=ch.get("role", "语块"), bg=V72_BG, fg=V72_MUTED,
                 font=("Microsoft YaHei UI", 9, "bold")).pack(pady=(4, 0))
        used += group_width_chars

    hint_panel = tk.Frame(parent, bg="#0f172a", bd=1, relief="solid")
    hint_panel.pack(fill="x", padx=120, pady=(18, 8))
    tk.Label(hint_panel, text="固定提示 / 六步提示 / 错误提示", bg="#0f172a", fg=V72_TEXT,
             font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w", padx=12, pady=(8, 2))
    if not hasattr(self, "dict_v62_side_var"):
        self.dict_v62_side_var = tk.StringVar()
    self.dict_v62_side_var.set("按 Ctrl+H：音标 → 同音词 → 近反义词 → 首尾字母 → 英文释义 → 同形词/答案。")
    tk.Label(hint_panel, textvariable=self.dict_v62_side_var, bg="#0f172a", fg=V72_MUTED,
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0, 4))
    if not hasattr(self, "dict_v63_hint_var"):
        self.dict_v63_hint_var = tk.StringVar()
    tk.Label(hint_panel, textvariable=self.dict_v63_hint_var, bg="#0f172a", fg="#38BDF8",
             wraplength=1180, justify="left", font=("Microsoft YaHei UI", 10, "bold")).pack(fill="x", padx=12, pady=(0, 8))

    if not hasattr(self, "dict_v69_notice_var"):
        self.dict_v69_notice_var = tk.StringVar(value="就绪")
    tk.Label(parent, textvariable=self.dict_v69_notice_var, bg="#07111f", fg=V72_MUTED,
             font=("Microsoft YaHei UI", 11, "bold"), anchor="w").pack(fill="x", padx=18, pady=(4, 0), side="bottom")

    if self.dict_v46_entries:
        self.dict_v46_entries[0]["entry"].focus_set()
    _v72_notice(self, "学习区已刷新：V72 无悬浮按钮版已生效。", "ok")

def _v72_norm_answer(s):
    return _re_v69.sub(r"\s+", " ", str(s or "")).strip().lower()

def _v72_live_color(self, item):
    ent = item["entry"]
    val = ent.get("1.0", "end-1c").strip()
    target = str(item["target"]).strip()
    try:
        item["line"].delete("all")
        if not val:
            color = V72_INPUT
        elif _v72_norm_answer(target).startswith(_v72_norm_answer(val)):
            color = V72_OK if _v72_norm_answer(val) == _v72_norm_answer(target) else V72_INPUT
        else:
            color = V72_BAD
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        ent.configure(fg=color)
    except Exception:
        pass

def _v72_judge_block(self, item):
    val = _re_v69.sub(r"\s+", " ", item["entry"].get("1.0", "end-1c")).strip()
    target = _re_v69.sub(r"\s+", " ", str(item["target"])).strip()
    ok = _v72_norm_answer(val) == _v72_norm_answer(target)
    color = V72_OK if ok else V72_BAD
    try:
        item["line"].delete("all")
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        item["entry"].configure(fg=color)
    except Exception:
        pass
    if ok:
        try:
            self.dict_v63_hint_var.set(f"✅ 当前块正确：{target}")
        except Exception:
            pass
        nxt = item["idx"] + 1
        entries = getattr(self, "dict_v46_entries", []) or []
        if nxt < len(entries):
            entries[nxt]["entry"].focus_set()
        else:
            if bool(getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get()):
                _v72_next(self)
    else:
        try:
            self.dict_v63_hint_var.set(f"❌ 当前块错误｜你输入：{val or '空'}｜目标：{target}｜请检查拼写、词形、顺序。")
        except Exception:
            pass
    return ok

def _v72_submit_all(self):
    ok = True
    for it in getattr(self, "dict_v46_entries", []) or []:
        ok = _v72_judge_block(self, it) and ok
    if ok:
        _v72_notice(self, "整句全部正确。", "ok")
    return ok

def _v72_next(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        return
    self.dictation_index_v30 = min(len(mats)-1, int(getattr(self, "dictation_index_v30", 0) or 0) + 1)
    _v72_render_learning_area(self)

def _v72_prev(self):
    self.dictation_index_v30 = max(0, int(getattr(self, "dictation_index_v30", 0) or 0) - 1)
    _v72_render_learning_area(self)

def _v72_hint_current(self):
    if callable(_V72_PREV_HINT):
        try:
            return _V72_PREV_HINT(self)
        except Exception:
            pass
    try:
        self.dict_v63_hint_var.set("提示：请检查当前语块的音标、首尾字母、词性和拼写。")
    except Exception:
        pass

def _v72_preflight(self, mode="audio"):
    # 直接复用 V71 体检，但修正“中文缺失”不阻断。
    fn = globals().get("_v71_preflight")
    if callable(fn):
        try:
            return fn(self, mode)
        except Exception:
            pass
    m = _v72_current_material(self)
    if not m:
        _v72_notice(self, "播放前检查失败：没有选中素材。", "bad")
        return False
    if not _v72_has_en(_v72_item_text(m)):
        _v72_notice(self, "播放前检查失败：原生英文缺失。", "bad")
        return False
    if not _v72_item_zh(m):
        _v72_notice(self, "播放前检查：中文翻译缺失，可点击【制作当前翻译】。", "bad")
    return True

def _v72_play_audio(self):
    # 先跑 V72 的体检；然后调 V71/旧发音链。ChatTTS 选择会由 V71 TTS 读取 cfg。
    if not _v72_preflight(self, "audio"):
        return
    fn = globals().get("_v71_play_audio") or _V72_PREV_PLAY_AUDIO
    if callable(fn):
        try:
            return fn(self)
        except Exception as e:
            _v72_notice(self, f"音频播放失败：{type(e).__name__}: {e}", "bad")
    _v72_notice(self, "没有可用音频播放主链。", "bad")

def _v72_play_video(self):
    if not _v72_preflight(self, "video"):
        return
    fn = globals().get("_v71_play_video") or _V72_PREV_PLAY_VIDEO
    if callable(fn):
        try:
            return fn(self)
        except Exception as e:
            _v72_notice(self, f"视频播放失败：{type(e).__name__}: {e}", "bad")
    _v72_notice(self, "没有可用视频播放主链。", "bad")

def _v72_open_translate_builder(self, scope="current"):
    # 优先复用 V71 的进度窗口；如果没有，则当前句直译。
    fn = globals().get("_v71_open_translate_builder")
    if callable(fn):
        try:
            return fn(self, scope)
        except Exception:
            pass
    if scope == "current":
        return _v72_translate_current_async(self)

def _v72_rebind_buttons(self):
    def walk(w):
        try:
            txt = str(w.cget("text")).strip()
            if txt.startswith("设置中心") or txt in {"配置中心", "高级设置中心 · 音效/TTS/快捷键"}:
                w.configure(text="设置中心", command=lambda: _v72_open_settings_center(self))
            elif txt in {"播放音频", "播放当前音频", "主播放 Ctrl"}:
                w.configure(command=lambda: _v72_play_audio(self))
            elif txt in {"播放视频", "播放当前视频", "加载台词视频播放"}:
                w.configure(command=lambda: _v72_play_video(self))
            elif txt in {"显示中文", "隐藏中文"}:
                w.configure(command=lambda: (getattr(self, "dictation_show_cn_v30").set(not getattr(self, "dictation_show_cn_v30").get()), _v72_render_learning_area(self)))
            elif txt in {"制作当前翻译", "制作当前台词翻译"}:
                w.configure(command=lambda: _v72_translate_current_async(self))
            elif txt in {"制作整文件翻译", "制作整文件翻译字幕"}:
                w.configure(command=lambda: _v72_open_translate_builder(self, "file"))
            elif txt in {"播放前检查"}:
                w.configure(command=lambda: _v72_preflight(self, "audio"))
            elif txt in {"清空学习区"}:
                w.configure(command=lambda: _v72_clear_learning(self))
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v72_clear_learning(self):
    self.dictation_materials_v30 = []
    try:
        self.dict_items_v33 = []
    except Exception:
        pass
    self.dictation_index_v30 = 0
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is not None:
        try:
            tree.delete(*tree.get_children())
        except Exception:
            pass
    _v72_render_learning_area(self)
    _v72_notice(self, "学习区和听写素材池已清空。", "ok")

def _v72_patch_globals(self):
    globals()["_v72_cfg"] = _v72_cfg
    globals()["_v71_cfg"] = _v72_cfg
    globals()["_v70_cfg"] = _v72_cfg
    globals()["_v69_cfg"] = _v72_cfg
    globals()["_v72_open_settings_center"] = _v72_open_settings_center
    globals()["_v71_open_settings_center"] = _v72_open_settings_center
    globals()["_v70_open_settings_center"] = _v72_open_settings_center
    globals()["_v69_open_settings_center"] = _v72_open_settings_center
    globals()["_v68_open_settings_center"] = _v72_open_settings_center
    globals()["_v67_open_settings_center"] = _v72_open_settings_center
    globals()["_v65_open_settings_center"] = _v72_open_settings_center
    globals()["_v63_open_settings_panel"] = _v72_open_settings_center
    globals()["_v72_render_learning_area"] = _v72_render_learning_area
    globals()["_v71_render_learning_area"] = _v72_render_learning_area
    globals()["_v70_render_learning_area"] = _v72_render_learning_area
    globals()["_v69_render_learning_area"] = _v72_render_learning_area
    globals()["_v68_render_learning_area"] = _v72_render_learning_area
    globals()["_v72_translate_text"] = _v72_translate_text
    globals()["_v71_translate_text"] = _v72_translate_text
    globals()["_v72_play_audio"] = _v72_play_audio
    globals()["_v71_play_audio"] = _v72_play_audio
    globals()["_v70_play_audio"] = _v72_play_audio
    globals()["_v72_play_video"] = _v72_play_video
    globals()["_v71_play_video"] = _v72_play_video
    globals()["_v70_play_video"] = _v72_play_video
    try:
        self.bind_all("<Control-h>", lambda e: (_v72_hint_current(self), "break"))
    except Exception:
        pass

_old_main_init_v72 = MainApp.__init__
def _main_init_v72(self):
    _old_main_init_v72(self)
    try:
        _v72_cfg(self)
        _v72_patch_globals(self)
        _v72_rebind_buttons(self)
        try:
            self.after(300, lambda: (_v72_patch_globals(self), _v72_rebind_buttons(self)))
            self.after(800, lambda: (_v72_rebind_buttons(self), _v72_render_learning_area(self), _v72_notice(self, "V72 已接管：设置中心、ChatTTS选项、OPUS直译、无悬浮按钮学习区已上线。", "ok")))
        except Exception:
            pass
        self.log("【V72上线】设置中心强制打开 V72，不再显示 V70 设置窗。", "ok")
        self.log("【V72上线】文本转语音引擎已加入 ChatTTS 本地 / Edge-TTS Python API / 原片音频。", "ok")
        self.log("【V72上线】翻译主链改为 OPUS-MT direct_generate，绕开 pipeline translation 报错。", "ok")
        self.log("【V72上线】学习区去除 place 悬浮按钮；显示中文按钮不再生成遮挡层。", "ok")
    except Exception as e:
        try:
            self.log(f"V72初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v72
APP_TITLE = "PlayPhrase Studio Clean v72 · 设置中心与翻译显示修复版"


# ──────────────────────────────────────────────────────────────────────
# V73：Ctrl/Alt 全局快捷键 + 跟踪播放 + Qt播放器增强 + 设置实际生效修复版
#
# 修复点：
# 1) Ctrl 无法播放 / 设置快捷键不调用：
#    - 新增统一快捷键注册中心；保存设置后立即重绑。
#    - Tk内快捷键 + keyboard库全局快捷键双链路。
# 2) 新增“跟踪播放”：
#    - 整句播放：跟踪当前语块。
#    - 拆分播放：跟踪当前单词。
#    - 默认 Alt = 跟踪播放音频。
# 3) 全局快捷键默认：
#    - Ctrl      = 播放整句音频
#    - Alt       = 跟踪播放音频
#    - Ctrl+Up   = 播放整句视频
#    - Alt+Up    = 跟踪播放视频
# 4) Qt降级播放：
#    - PlayerService 启动 helper 时尝试多个 Python 解释器。
#    - 详细输出 PySide6 缺失/启动失败原因。
#    - 如果运行的是 PyInstaller exe 且没有 qt_player_helper.exe，会尝试外部 Python。
# 5) Ctrl/Alt 防连击：
#    - 播放中按键：距离结束 >0.1s 忽略；<=0.1s 仅排队一次，不累计。
# ──────────────────────────────────────────────────────────────────────

_V73_PREV_CFG = globals().get("_v72_cfg") or globals().get("_v71_cfg") or globals().get("_v70_cfg")
_V73_PREV_SAVE_CFG = globals().get("_v72_save_cfg") or globals().get("_v71_save_cfg")
_V73_PREV_NOTICE = globals().get("_v72_notice") or globals().get("_v71_notice")
_V73_PREV_SETTINGS = globals().get("_v72_open_settings_center") or globals().get("_v71_open_settings_center")
_V73_PREV_RENDER = globals().get("_v72_render_learning_area") or globals().get("_v71_render_learning_area")
_V73_PREV_TRANSLATE_CURRENT = globals().get("_v72_translate_current_async") or globals().get("_v72_translate_current")
_V73_PREV_PRE_FLIGHT = globals().get("_v72_preflight") or globals().get("_v71_preflight")

V73_BG = "#0b1220"
V73_PANEL = "#111827"
V73_TEXT = "#E5E7EB"
V73_MUTED = "#94A3B8"
V73_OK = "#22C55E"
V73_WARN = "#F59E0B"
V73_BAD = "#EF4444"

def _v73_cfg(self):
    cfg = {}
    if callable(_V73_PREV_CFG):
        try:
            cfg = _V73_PREV_CFG(self)
        except Exception:
            cfg = getattr(self, "v69_cfg", {}) if hasattr(self, "v69_cfg") else {}
    if not isinstance(cfg, dict):
        cfg = {}
    cfg.setdefault("shortcuts", {})
    cfg["shortcuts"].setdefault("global_hotkeys", True)
    cfg["shortcuts"].setdefault("full_audio", "ctrl")
    cfg["shortcuts"].setdefault("track_audio", "alt")
    cfg["shortcuts"].setdefault("full_video", "ctrl+up")
    cfg["shortcuts"].setdefault("track_video", "alt+up")
    cfg["shortcuts"].setdefault("debounce_tail_seconds", 0.10)
    cfg.setdefault("player", {})
    cfg["player"].setdefault("qt_python_exe", "")
    cfg["player"].setdefault("prefer_qt", True)
    cfg["player"].setdefault("allow_system_fallback", True)
    cfg.setdefault("speech", {})
    cfg["speech"].setdefault("tts_engine", "Edge-TTS Python API")
    cfg.setdefault("dictation", {})
    cfg["dictation"].setdefault("tracking_mode_enabled", True)
    cfg["dictation"].setdefault("tracking_use_original_media_when_possible", True)
    self.v69_cfg = cfg
    try:
        self.v63_cfg = cfg
    except Exception:
        pass
    return cfg

def _v73_save_cfg(self):
    if callable(_V73_PREV_SAVE_CFG):
        try:
            _V73_PREV_SAVE_CFG(self)
        except Exception:
            pass
    try:
        p = _Path_v69.cwd() / "pp_studio_v73_settings.json"
        p.write_text(_json_v69.dumps(_v73_cfg(self), ensure_ascii=False, indent=2), "utf-8")
    except Exception:
        pass

def _v73_notice(self, msg, level="info", scope="dictation"):
    if callable(_V73_PREV_NOTICE):
        try:
            return _V73_PREV_NOTICE(self, msg, level, scope)
        except TypeError:
            try:
                return _V73_PREV_NOTICE(self, msg, level)
            except Exception:
                pass
        except Exception:
            pass
    try:
        self.log(str(msg), "ok" if level == "ok" else ("err" if level in ("bad", "err") else "info"))
    except Exception:
        pass

def _v73_words(s):
    return _re_v69.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v73_clean(s):
    return _re_v69.sub(r"\s+", " ", str(s or "")).strip()

def _v73_has_en(s):
    return bool(_re_v69.search(r"[A-Za-z]{2,}", str(s or "")))

def _v73_fmt_srt_time(sec):
    sec = max(0.0, float(sec or 0.0))
    h = int(sec // 3600); sec -= h * 3600
    m = int(sec // 60); sec -= m * 60
    s = int(sec); ms = int(round((sec - s) * 1000))
    if ms >= 1000:
        s += 1; ms = 0
    return f"{h:02d}:{m:02d}:{s:02d},{ms:03d}"

def _v73_current_material(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        return None
    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats)-1))
    self.dictation_index_v30 = idx
    return mats[idx]

def _v73_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

def _v73_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or "")
    return ""

def _v73_media_path(m):
    if not isinstance(m, dict):
        return ""
    for k in ("video_path", "media_path", "audio_path", "local_path", "path"):
        v = str(m.get(k) or "")
        if v and _Path_v69(v).exists():
            return v
    return ""

def _v73_get_active_entry_index(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    cur = getattr(self, "dict_current_track_index_v73", None)
    if isinstance(cur, int) and 0 <= cur < len(entries):
        return cur
    try:
        fw = self.focus_get()
        for i, it in enumerate(entries):
            if it.get("entry") is fw:
                self.dict_current_track_index_v73 = i
                return i
    except Exception:
        pass
    # 优先找第一个未完成项
    for i, it in enumerate(entries):
        try:
            val = it.get("entry").get("1.0", "end-1c").strip()
            target = str(it.get("target") or "")
            if val.lower() != target.lower():
                self.dict_current_track_index_v73 = i
                return i
        except Exception:
            pass
    return 0 if entries else -1

def _v73_get_track_text(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    idx = _v73_get_active_entry_index(self)
    if idx < 0 or idx >= len(entries):
        return ""
    return _v73_clean(entries[idx].get("target") or "")

def _v73_estimate_segment(self, mode="full"):
    """
    返回：text, start, end, media_path
    full = 当前整句
    track = 当前语块/单词，若原片有时间轴则按词数比例估算切片时间。
    """
    m = _v73_current_material(self)
    if not m:
        return "", 0.0, 0.0, ""
    full_text = _v73_clean(_v73_item_text(m))
    media = _v73_media_path(m)
    start = float(m.get("start") or 0.0) if isinstance(m, dict) else 0.0
    end = float(m.get("end") or 0.0) if isinstance(m, dict) else 0.0
    if mode == "full":
        return full_text, start, end, media
    track = _v73_get_track_text(self) or full_text
    # 无时间轴：跟踪播放走 TTS，时间随文本估算。
    if not media or end <= start or not full_text:
        return track, 0.0, 0.0, media
    full_words = _v73_words(full_text)
    track_words = _v73_words(track)
    if not full_words or not track_words:
        return track, start, end, media
    # 根据当前 entry 的顺序估算：前面 entry 的词数占比。
    entries = getattr(self, "dict_v46_entries", []) or []
    idx = _v73_get_active_entry_index(self)
    before_words = []
    if idx >= 0:
        for it in entries[:idx]:
            before_words.extend(_v73_words(it.get("target", "")))
    before = min(len(full_words), len(before_words))
    length = max(1, len(track_words))
    total = max(1, len(full_words))
    dur = max(0.7, end - start)
    s = start + dur * (before / total)
    e = start + dur * (min(total, before + length) / total)
    if e <= s:
        e = min(end, s + max(0.7, dur / total * length))
    # 留一点点尾巴，避免单词被截断
    e = min(end, e + 0.08)
    s = max(start, s - 0.03)
    return track, s, e, media

def _v73_estimated_duration(text, start=0.0, end=0.0):
    if end and start and end > start:
        return max(0.5, end - start)
    wc = max(1, len(_v73_words(text)))
    return min(8.0, max(0.8, wc * 0.42 + 0.35))

def _v73_debounce(self, key, duration, func):
    now = _time_v69.time()
    state = getattr(self, "_v73_play_state", None)
    if state is None:
        state = {}
        self._v73_play_state = state
    tail = float(_v73_cfg(self).get("shortcuts", {}).get("debounce_tail_seconds", 0.10) or 0.10)
    busy_until = float(state.get(key + "_until", 0.0) or 0.0)
    if now < busy_until:
        remain = busy_until - now
        if remain > tail:
            _v73_notice(self, f"播放中，忽略重复快捷键：{key}", "info")
            return
        if state.get(key + "_queued"):
            _v73_notice(self, f"已排队一次，不累计：{key}", "info")
            return
        state[key + "_queued"] = True
        def delayed():
            state[key + "_queued"] = False
            _v73_debounce(self, key, duration, func)
        try:
            self.after(int(max(20, remain * 1000 + 20)), delayed)
        except Exception:
            _threading_v69.Timer(max(0.05, remain + 0.02), delayed).start()
        return
    state[key + "_until"] = now + max(0.25, float(duration or 0.8))
    func()

def _v73_no_window_kwargs():
    try:
        return no_window()
    except Exception:
        if _os_v69.name == "nt":
            return {"creationflags": getattr(_subprocess_v69, "CREATE_NO_WINDOW", 0)}
        return {}

def _v73_find_ffmpeg(self):
    fn = globals().get("_v71_find_ffmpeg") or globals().get("_v70_find_ffmpeg")
    if callable(fn):
        try:
            return fn(self)
        except Exception:
            pass
    return "ffmpeg"

def _v73_play_wav(path):
    try:
        if _os_v69.name == "nt":
            import winsound
            winsound.PlaySound(str(path), winsound.SND_FILENAME | winsound.SND_ASYNC)
            return True
    except Exception:
        pass
    try:
        _subprocess_v69.Popen(["ffplay", "-nodisp", "-autoexit", str(path)],
                              stdout=_subprocess_v69.DEVNULL, stderr=_subprocess_v69.DEVNULL,
                              **_v73_no_window_kwargs())
        return True
    except Exception:
        return False

def _v73_tts_to_audio(self, text):
    text = _v73_clean(text)
    if not text:
        return None
    engine = _v73_cfg(self).get("speech", {}).get("tts_engine", "Edge-TTS Python API")
    # 复用 V71 的 Edge/ChatTTS 生成函数，避免重新写一遍模型逻辑。
    try:
        if engine == "ChatTTS 本地":
            fn = globals().get("_v71_chattts_to_wav")
            if callable(fn):
                wav = fn(self, text)
                if wav:
                    return wav
            _v73_notice(self, "ChatTTS 不可用，降级 Edge-TTS Python API。", "bad")
        fn = globals().get("_v71_edge_tts_to_wav")
        if callable(fn):
            wav = fn(self, text)
            if wav:
                return wav
    except Exception as e:
        _v73_notice(self, f"TTS生成失败：{type(e).__name__}: {e}", "bad")
    return None

def _v73_extract_media_audio(self, media, start, end, label="audio"):
    if not media or not _Path_v69(media).exists() or end <= start:
        return None
    cache = _Path_v69(str(_v73_cfg(self).get("speech", {}).get("tts_cache_dir", _Path_v69.cwd() / "clip_cache" / "tts_v73")))
    cache.mkdir(parents=True, exist_ok=True)
    out = cache / f"{label}_{abs(hash((media, start, end))) % 10000000}.wav"
    if out.exists() and out.stat().st_size > 1000:
        return out
    ff = _v73_find_ffmpeg(self)
    cmd = [ff, "-y", "-hide_banner", "-loglevel", "error", "-ss", f"{start:.3f}", "-to", f"{end:.3f}",
           "-i", str(media), "-vn", "-ac", "1", "-ar", "22050", str(out)]
    try:
        _subprocess_v69.run(cmd, stdout=_subprocess_v69.DEVNULL, stderr=_subprocess_v69.DEVNULL,
                            timeout=45, **_v73_no_window_kwargs())
        if out.exists() and out.stat().st_size > 1000:
            return out
    except Exception as e:
        _v73_notice(self, f"原片音频提取失败：{type(e).__name__}: {e}", "bad")
    return None

def _v73_play_audio_mode(self, mode="full"):
    text, start, end, media = _v73_estimate_segment(self, mode)
    if not text:
        _v73_notice(self, "没有可播放文本。", "bad")
        return
    duration = _v73_estimated_duration(text, start, end)
    key = "audio_track" if mode == "track" else "audio_full"
    def run():
        cfg = _v73_cfg(self)
        engine = cfg.get("speech", {}).get("tts_engine", "Edge-TTS Python API")
        prefer_original = bool(cfg.get("dictation", {}).get("tracking_use_original_media_when_possible", True))
        _v73_notice(self, ("跟踪播放音频：" if mode == "track" else "整句播放音频：") + text[:80], "info")
        def worker():
            wav = None
            if (engine == "原片音频" or prefer_original) and media and end > start:
                wav = _v73_extract_media_audio(self, media, start, end, "track" if mode == "track" else "full")
            if wav is None:
                wav = _v73_tts_to_audio(self, text)
            if wav and _v73_play_wav(wav):
                _v73_notice(self, "音频播放已触发。", "ok")
            else:
                _v73_notice(self, "音频播放失败：请检查发音引擎/原片路径/FFmpeg。", "bad")
        _threading_v69.Thread(target=worker, daemon=True).start()
    _v73_debounce(self, key, duration, run)

def _v73_srt_for_text(self, text, zh="", dur=2.0):
    cache = _Path_v69.cwd() / "clip_cache" / "qt_preview_v73"
    try:
        cfg = _v73_cfg(self)
        cache = _Path_v69(str(cfg.get("paths", {}).get("video_preview_cache", cache)))
    except Exception:
        pass
    cache.mkdir(parents=True, exist_ok=True)
    srt = cache / f"track_{abs(hash((text, zh, dur))) % 10000000}.srt"
    body = _v73_clean(text)
    if zh:
        body += "\n" + _v73_clean(zh)
    srt.write_text(f"1\n00:00:00,000 --> {_v73_fmt_srt_time(dur)}\n{body}\n", "utf-8")
    return srt

def _v73_subtitle_path_arg(path):
    p = str(path).replace("\\", "/")
    p = p.replace(":", "\\:")
    p = p.replace("'", "\\'")
    return p

def _v73_make_video_clip(self, mode="full"):
    m = _v73_current_material(self)
    if not m:
        return ""
    text, start, end, media = _v73_estimate_segment(self, mode)
    if not media or not _Path_v69(media).exists():
        _v73_notice(self, "没有本地视频/媒体路径。在线资源请先下载或缓存。", "bad")
        return ""
    if _Path_v69(media).suffix.lower() not in {".mp4", ".mkv", ".avi", ".mov", ".webm", ".m4v"}:
        _v73_notice(self, "当前资源不是视频文件，不能播放视频。", "bad")
        return ""
    if end <= start:
        start = float(m.get("start") or 0.0) if isinstance(m, dict) else 0.0
        end = start + _v73_estimated_duration(text)
    dur = max(0.5, end - start)
    cache = _Path_v69.cwd() / "clip_cache" / "qt_preview_v73"
    try:
        cache = _Path_v69(str(_v73_cfg(self).get("paths", {}).get("video_preview_cache", cache)))
    except Exception:
        pass
    cache.mkdir(parents=True, exist_ok=True)
    out = cache / f"{_Path_v69(media).stem}_{mode}_{int(start*1000)}_{int(end*1000)}_{abs(hash(text))%999999}.mp4"
    if out.exists() and out.stat().st_size > 1000:
        return str(out)
    zh = _v73_item_zh(m) if mode == "full" else ""
    srt = _v73_srt_for_text(self, text, zh, dur)
    ff = _v73_find_ffmpeg(self)
    filt = "subtitles=filename='" + _v73_subtitle_path_arg(srt) + "':force_style='FontName=Microsoft YaHei,FontSize=28,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,BorderStyle=1,Outline=2,Shadow=1'"
    cmd = [ff, "-y", "-hide_banner", "-loglevel", "error",
           "-ss", f"{start:.3f}", "-t", f"{dur:.3f}", "-i", str(media),
           "-vf", filt, "-c:v", "libx264", "-preset", "ultrafast", "-crf", "24",
           "-c:a", "aac", "-b:a", "128k", "-movflags", "+faststart", str(out)]
    try:
        r = _subprocess_v69.run(cmd, capture_output=True, text=True, timeout=90, **_v73_no_window_kwargs())
        if r.returncode == 0 and out.exists() and out.stat().st_size > 1000:
            return str(out)
        _v73_notice(self, "视频切片生成失败：" + ((r.stderr or "")[-400:]), "bad")
    except Exception as e:
        _v73_notice(self, f"视频切片生成异常：{type(e).__name__}: {e}", "bad")
    return ""

def _v73_play_with_qt(self, path):
    if not path or not _Path_v69(path).exists():
        _v73_notice(self, "Qt播放失败：文件不存在。", "bad")
        return False
    try:
        player = getattr(self, "player", None)
        if player is not None:
            player.play(_Path_v69(path))
            _v73_notice(self, f"已请求 Qt 播放：{_Path_v69(path).name}", "ok")
            return True
    except Exception as e:
        _v73_notice(self, f"Qt播放调用异常：{type(e).__name__}: {e}", "bad")
    return False

def _v73_play_video_mode(self, mode="full"):
    text, start, end, media = _v73_estimate_segment(self, mode)
    duration = _v73_estimated_duration(text, start, end)
    key = "video_track" if mode == "track" else "video_full"
    def run():
        _v73_notice(self, ("跟踪播放视频：" if mode == "track" else "整句播放视频：") + text[:80], "info")
        def worker():
            path = _v73_make_video_clip(self, mode)
            if not path:
                return
            try:
                self.after(0, lambda: _v73_play_with_qt(self, path))
            except Exception:
                _v73_play_with_qt(self, path)
        _threading_v69.Thread(target=worker, daemon=True).start()
    _v73_debounce(self, key, duration, run)

def _v73_handle_hotkey(self, action, source="tk"):
    """
    action:
      full_audio / track_audio / full_video / track_video
    """
    try:
        if action == "full_audio":
            _v73_play_audio_mode(self, "full")
        elif action == "track_audio":
            _v73_play_audio_mode(self, "track")
        elif action == "full_video":
            _v73_play_video_mode(self, "full")
        elif action == "track_video":
            _v73_play_video_mode(self, "track")
    except Exception as e:
        _v73_notice(self, f"快捷键执行失败：{action} | {type(e).__name__}: {e}", "bad")

def _v73_tk_hotkey_event(self, action):
    return lambda e: (_v73_handle_hotkey(self, action, "tk"), "break")

def _v73_key_to_tk_sequences(key):
    key = str(key or "").strip().lower().replace(" ", "")
    mp = {
        "ctrl": ["<KeyPress-Control_L>", "<KeyPress-Control_R>"],
        "alt": ["<KeyPress-Alt_L>", "<KeyPress-Alt_R>", "<KeyPress-Menu>"],
        "ctrl+up": ["<Control-Up>"],
        "alt+up": ["<Alt-Up>"],
        "enter": ["<Return>"],
        "space": ["<space>"],
    }
    return mp.get(key, [])

def _v73_unbind_old_tk_hotkeys(self):
    old = getattr(self, "_v73_tk_hotkey_sequences", []) or []
    for seq in old:
        try:
            self.unbind_all(seq)
        except Exception:
            pass
    self._v73_tk_hotkey_sequences = []

def _v73_register_tk_hotkeys(self):
    _v73_unbind_old_tk_hotkeys(self)
    cfg = _v73_cfg(self).get("shortcuts", {})
    pairs = [
        ("full_audio", cfg.get("full_audio", "ctrl")),
        ("track_audio", cfg.get("track_audio", "alt")),
        ("full_video", cfg.get("full_video", "ctrl+up")),
        ("track_video", cfg.get("track_video", "alt+up")),
    ]
    seqs = []
    for action, key in pairs:
        for seq in _v73_key_to_tk_sequences(key):
            try:
                self.bind_all(seq, _v73_tk_hotkey_event(self, action), add="+")
                seqs.append(seq)
            except Exception as e:
                _v73_notice(self, f"Tk快捷键绑定失败：{key} -> {action} | {e}", "bad")
    self._v73_tk_hotkey_sequences = seqs
    _v73_notice(self, f"软件内快捷键已绑定：{', '.join([p[1] for p in pairs])}", "ok")

def _v73_unregister_global_hotkeys(self):
    handles = getattr(self, "_v73_keyboard_hotkey_handles", []) or []
    kb = getattr(self, "_v73_keyboard_module", None)
    if kb is not None:
        for h in handles:
            try:
                kb.remove_hotkey(h)
            except Exception:
                pass
    self._v73_keyboard_hotkey_handles = []

def _v73_register_global_hotkeys(self):
    _v73_unregister_global_hotkeys(self)
    cfg = _v73_cfg(self)
    if not bool(cfg.get("shortcuts", {}).get("global_hotkeys", True)):
        _v73_notice(self, "全局快捷键已关闭，仅保留软件内快捷键。", "info")
        return
    try:
        import keyboard  # type: ignore
        self._v73_keyboard_module = keyboard
    except Exception as e:
        self._v73_keyboard_module = None
        _v73_notice(self, f"全局快捷键不可用：未安装 keyboard。可运行 pip install keyboard。软件内快捷键仍可用。", "bad")
        return
    pairs = [
        ("full_audio", cfg["shortcuts"].get("full_audio", "ctrl")),
        ("track_audio", cfg["shortcuts"].get("track_audio", "alt")),
        ("full_video", cfg["shortcuts"].get("full_video", "ctrl+up")),
        ("track_video", cfg["shortcuts"].get("track_video", "alt+up")),
    ]
    handles = []
    for action, key in pairs:
        try:
            # trigger_on_release=False 才能按下立即触发；suppress=False 避免影响系统。
            h = keyboard.add_hotkey(key, lambda a=action: _v73_handle_hotkey(self, a, "global"),
                                    suppress=False, trigger_on_release=False)
            handles.append(h)
        except Exception as e:
            _v73_notice(self, f"全局快捷键绑定失败：{key} -> {action} | {type(e).__name__}: {e}", "bad")
    self._v73_keyboard_hotkey_handles = handles
    if handles:
        _v73_notice(self, "全局快捷键已启用：Ctrl整句音频 / Alt跟踪音频 / Ctrl+Up整句视频 / Alt+Up跟踪视频。", "ok")

def _v73_register_all_hotkeys(self):
    _v73_register_tk_hotkeys(self)
    _v73_register_global_hotkeys(self)

def _v73_after_render(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    for i, it in enumerate(entries):
        ent = it.get("entry")
        if ent is None:
            continue
        try:
            ent.bind("<FocusIn>", lambda e, idx=i: setattr(self, "dict_current_track_index_v73", idx), add="+")
            ent.bind("<Button-1>", lambda e, idx=i: setattr(self, "dict_current_track_index_v73", idx), add="+")
        except Exception:
            pass
    try:
        if entries:
            cur = _v73_get_active_entry_index(self)
            self.dict_current_track_index_v73 = cur
    except Exception:
        pass

def _v73_render_learning_area(self):
    if callable(_V73_PREV_RENDER):
        _V73_PREV_RENDER(self)
    _v73_after_render(self)

def _v73_open_settings_center(self):
    cfg = _v73_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置中心 V73 · 快捷键/播放/Qt")
    win.geometry("1160x780")
    win.configure(bg=V73_PANEL)

    root = tk.Frame(win, bg=V73_PANEL)
    root.pack(fill="both", expand=True, padx=18, pady=14)
    top = tk.Frame(root, bg=V73_PANEL)
    top.pack(fill="x")
    tk.Label(top, text="设置中心 V73", bg=V73_PANEL, fg=V73_TEXT,
             font=("Microsoft YaHei UI", 22, "bold")).pack(side="left")
    ttk.Button(top, text="关闭", command=win.destroy).pack(side="right")
    tk.Label(root, text="本页设置保存后立即生效：Ctrl/Alt 全局快捷键、跟踪播放、Qt播放器、发音引擎。",
             bg=V73_PANEL, fg=V73_MUTED, font=("Microsoft YaHei UI", 10)).pack(anchor="w", pady=(4, 10))

    nb = ttk.Notebook(root)
    nb.pack(fill="both", expand=True)
    pages = {}
    for name in ["快捷键", "播放模式", "Qt播放器", "发音引擎", "翻译引擎"]:
        f = tk.Frame(nb, bg=V73_PANEL)
        nb.add(f, text=name)
        pages[name] = f

    def row(page, title, desc=""):
        r = tk.Frame(pages[page], bg=V73_PANEL)
        r.pack(fill="x", padx=16, pady=8)
        left = tk.Frame(r, bg=V73_PANEL)
        left.pack(side="left", fill="x", expand=True)
        tk.Label(left, text=title, bg=V73_PANEL, fg=V73_TEXT,
                 font=("Microsoft YaHei UI", 12, "bold")).pack(anchor="w")
        if desc:
            tk.Label(left, text=desc, bg=V73_PANEL, fg=V73_MUTED,
                     wraplength=760, justify="left").pack(anchor="w")
        return r

    shortcuts = cfg.setdefault("shortcuts", {})
    global_hotkeys = tk.BooleanVar(value=bool(shortcuts.get("global_hotkeys", True)))
    full_audio = tk.StringVar(value=shortcuts.get("full_audio", "ctrl"))
    track_audio = tk.StringVar(value=shortcuts.get("track_audio", "alt"))
    full_video = tk.StringVar(value=shortcuts.get("full_video", "ctrl+up"))
    track_video = tk.StringVar(value=shortcuts.get("track_video", "alt+up"))
    tail = tk.DoubleVar(value=float(shortcuts.get("debounce_tail_seconds", 0.10) or 0.10))

    choices = ["ctrl", "alt", "ctrl+up", "alt+up", "ctrl+r", "alt+r", "ctrl+space", "alt+space", "f7", "f8", "f9", "f10"]

    r = row("快捷键", "启用全局快捷键", "开启后即使焦点不在软件上，也可以尝试调用。需要 keyboard 库；若失败，软件内快捷键仍可用。")
    ttk.Checkbutton(r, text="开启", variable=global_hotkeys).pack(side="right", padx=10)
    for title, var, desc in [
        ("整句音频播放", full_audio, "默认 Ctrl。播放当前整句/当前台词音频。"),
        ("跟踪音频播放", track_audio, "默认 Alt。整句模式播放当前语块；拆分模式播放当前单词。"),
        ("整句视频播放", full_video, "默认 Ctrl+Up。播放当前整句视频切片。"),
        ("跟踪视频播放", track_video, "默认 Alt+Up。播放当前语块/单词的视频估算切片。"),
    ]:
        r = row("快捷键", title, desc)
        ttk.Combobox(r, textvariable=var, values=choices, width=20).pack(side="right", padx=10)
    r = row("快捷键", "播放防连击尾部窗口", "播放中重复按键：距离结束大于该值则忽略；小于等于该值只排队一次。")
    ttk.Spinbox(r, textvariable=tail, from_=0.03, to=0.5, increment=0.01, width=8).pack(side="right", padx=10)

    tracking_enabled = tk.BooleanVar(value=bool(cfg.get("dictation", {}).get("tracking_mode_enabled", True)))
    original_track = tk.BooleanVar(value=bool(cfg.get("dictation", {}).get("tracking_use_original_media_when_possible", True)))
    r = row("播放模式", "启用跟踪播放", "整句播放=当前语块；拆分播放=当前单词。")
    ttk.Checkbutton(r, text="开启", variable=tracking_enabled).pack(side="right", padx=10)
    r = row("播放模式", "跟踪播放优先使用原片音频/视频切片", "有时间轴时按词数比例估算语块/单词片段；没有时间轴则使用 TTS。")
    ttk.Checkbutton(r, text="开启", variable=original_track).pack(side="right", padx=10)
    ttk.Button(pages["播放模式"], text="测试：整句音频 Ctrl", command=lambda: _v73_play_audio_mode(self, "full")).pack(anchor="w", padx=16, pady=8)
