# ──────────────────────────────────────────────────────────────────────
# Qt PlayerService 增强：多解释器尝试 + 详细错误 + 可配置兜底
# ──────────────────────────────────────────────────────────────────────

def _v73_player_candidate_commands(self):
    candidates = []
    # bundled helper exe first
    try:
        helper_exe = self._bundled_helper_exe()
        if helper_exe is not None:
            candidates.append([str(helper_exe), str(self.port)])
            return candidates
    except Exception:
        pass
    try:
        self.helper_path.write_text(QT_PLAYER_HELPER, "utf-8")
    except Exception:
        pass
    helper = str(getattr(self, "helper_path", _Path_v69(_tempfile_v69.gettempdir()) / "pp_studio_qt_player.py"))
    cfg = {}
    try:
        # self here is PlayerService, not MainApp; read config file directly.
        p = _Path_v69.cwd() / "pp_studio_v73_settings.json"
        if p.exists():
            cfg = _json_v69.loads(p.read_text("utf-8"))
    except Exception:
        cfg = {}
    qt_py = str((cfg.get("player") or {}).get("qt_python_exe") or "").strip()
    paths = []
    if qt_py:
        paths.append(qt_py)
    for attr in ["_base_executable", "executable"]:
        try:
            v = getattr(_sys_v69, attr, "")
            if v and str(v).lower().endswith(("python.exe", "pythonw.exe", "python")):
                paths.append(str(v))
        except Exception:
            pass
    paths.extend([
        r"G:\Python_Env\Python312\python.exe",
        r"C:\Users\Administrator\AppData\Local\Programs\Python\Python312\python.exe",
        r"C:\Python312\python.exe",
    ])
    seen = set()
    for py in paths:
        if py and py.lower() not in seen and _Path_v69(py).exists():
            candidates.append([py, helper, str(self.port)])
            seen.add(py.lower())
    # py launcher fallback
    if _os_v69.name == "nt":
        candidates.append(["py", "-3", helper, str(self.port)])
    else:
        candidates.append([_sys_v69.executable, helper, str(self.port)])
    return candidates

def _v73_player_ensure_server(self):
    if self.proc and self.proc.poll() is None and self.port:
        return True
    self.port = self._free_port()
    all_errors = []
    for cmd in _v73_player_candidate_commands(self):
        try:
            self.log("Qt 播放器尝试启动：" + " ".join(map(str, cmd[:2])), "info")
            self.proc = _subprocess_v69.Popen(
                cmd,
                stdout=_subprocess_v69.PIPE,
                stderr=_subprocess_v69.STDOUT,
                text=True,
                **_v73_no_window_kwargs()
            )
            deadline = _time_v69.time() + 7.0
            last_err = ""
            while _time_v69.time() < deadline:
                if self.proc.poll() is not None:
                    out = ""
                    try:
                        out = self.proc.stdout.read() if self.proc.stdout else ""
                    except Exception:
                        pass
                    all_errors.append("cmd=" + " ".join(map(str, cmd)) + "\n" + out[:800])
                    break
                try:
                    with _socket_v69.create_connection(("127.0.0.1", self.port), timeout=0.35):
                        self.log("Qt 播放窗口已启动；后续会复用同一窗口切换片段。", "ok")
                        return True
                except Exception as e:
                    last_err = str(e)
                    _time_v69.sleep(0.12)
            else:
                all_errors.append("cmd=" + " ".join(map(str, cmd)) + f"\n启动超时 last={last_err}")
                try:
                    if self.proc and self.proc.poll() is None:
                        self.proc.terminate()
                except Exception:
                    pass
        except Exception as e:
            all_errors.append("cmd=" + " ".join(map(str, cmd)) + f"\n{type(e).__name__}: {e}")
    detail = "\n---\n".join(all_errors[-3:])
    if "PY_SIDE6_IMPORT_FAILED" in detail:
        self.log("Qt 播放窗口启动失败：当前 helper Python 未安装 PySide6。请在设置中心填写装有 PySide6 的 python.exe，或运行 pip install PySide6。", "err")
    self.log("Qt 播放窗口全部启动失败，将按设置决定是否降级。详情：" + detail[:1200], "warn")
    return False

def _v73_player_play(self, path):
    p = _Path_v69(path)
    if not p.exists():
        self.log("播放失败：本地缓存文件不存在。", "err")
        return
    # 读取是否允许兜底
    allow = True
    prefer = True
    try:
        cfgp = _Path_v69.cwd() / "pp_studio_v73_settings.json"
        if cfgp.exists():
            cfg = _json_v69.loads(cfgp.read_text("utf-8"))
            allow = bool((cfg.get("player") or {}).get("allow_system_fallback", True))
            prefer = bool((cfg.get("player") or {}).get("prefer_qt", True))
    except Exception:
        pass
    if prefer and self._ensure_server():
        if self._send({"cmd": "play", "path": str(p)}):
            return
    if not allow:
        self.log("Qt 播放失败，且设置禁止系统播放器兜底。", "err")
        return
    self.log("降级：用系统播放器打开。", "warn")
    try:
        if _os_v69.name == "nt":
            _os_v69.startfile(str(p))  # type: ignore[attr-defined]
        elif _sys_v69.platform == "darwin":
            _subprocess_v69.Popen(["open", str(p)])
        else:
            _subprocess_v69.Popen(["xdg-open", str(p)])
    except Exception as e:
        self.log(f"系统播放器打开失败：{e}", "err")

try:
    PlayerService._ensure_server = _v73_player_ensure_server
    PlayerService.play = _v73_player_play
except Exception:
    pass

def _v73_rebind_buttons(self):
    def walk(w):
        try:
            txt = str(w.cget("text")).strip()
            if txt.startswith("设置中心") or txt in {"配置中心", "高级设置中心 · 音效/TTS/快捷键"}:
                w.configure(text="设置中心", command=lambda: _v73_open_settings_center(self))
            elif txt in {"播放音频", "播放当前音频", "主播放 Ctrl"}:
                w.configure(text="播放音频 Ctrl", command=lambda: _v73_play_audio_mode(self, "full"))
            elif txt in {"跟踪播放", "跟踪音频", "播放当前块", "播放当前语块"}:
                w.configure(text="跟踪播放 Alt", command=lambda: _v73_play_audio_mode(self, "track"))
            elif txt in {"播放视频", "播放当前视频", "加载台词视频播放"}:
                w.configure(text="播放视频 Ctrl+↑", command=lambda: _v73_play_video_mode(self, "full"))
            elif txt in {"跟踪视频", "播放当前块视频"}:
                w.configure(text="跟踪视频 Alt+↑", command=lambda: _v73_play_video_mode(self, "track"))
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v73_add_tracking_buttons(self):
    parent = getattr(self, "dict_v46_study", None)
    if parent is None:
        return
    # 如果底部按钮区没有跟踪播放，补一个轻量浮动在底部，不遮挡学习区。
