#    → V74 设置中心加入：显示隐藏、音效设置、全快捷键表。
# 5) ChatTTS 选择后不生效。
#    → 发音引擎选择 ChatTTS 时强制走 ChatTTS，不再优先原片音频。
# ──────────────────────────────────────────────────────────────────────

_V74_PREV_CFG = globals().get("_v73_cfg") or globals().get("_v72_cfg")
_V74_PREV_SAVE = globals().get("_v73_save_cfg") or globals().get("_v72_save_cfg")
