def _v74_cfg(self):
    cfg = {}
    if callable(_V74_PREV_CFG):
        try:
            cfg = _V74_PREV_CFG(self)
        except Exception:
            cfg = getattr(self, "v69_cfg", {}) if hasattr(self, "v69_cfg") else {}
    if not isinstance(cfg, dict):
        cfg = {}
    cfg.setdefault("display", {})
    cfg["display"].setdefault("show_chinese", True)
    cfg["display"].setdefault("show_next_english_subtitle", False)  # 青色字幕默认关闭
    cfg["display"].setdefault("show_current_english_subtitle", True) # 粉色当前句保留
    cfg["display"].setdefault("show_keytips", True)
    cfg["display"].setdefault("show_statusline", True)
    cfg.setdefault("sound", {})
    cfg["sound"].setdefault("enabled", True)
    cfg["sound"].setdefault("typing_enabled", True)
    cfg["sound"].setdefault("correct_enabled", True)
    cfg["sound"].setdefault("wrong_enabled", True)
    cfg["sound"].setdefault("typing_scope_letters_only", True)
    cfg["sound"].setdefault("volume", 70)
    cfg.setdefault("shortcuts", {})
    # 全部听写训练按钮都集中到这里，保存后立即重绑。
    defaults = {
        "full_audio": "ctrl",
        "track_audio": "alt",
        "full_video": "ctrl+up",
        "track_video": "alt+up",
        "prev_sentence": "ctrl+left",
        "next_sentence": "ctrl+right",
        "judge_current": "space",
        "submit_sentence": "enter",
        "hint": "ctrl+h",
        "toggle_next_subtitle": "alt+h",
        "toggle_chinese": "ctrl+shift+c",
        "copy_selected": "ctrl+c",
        "clear_learning": "ctrl+shift+delete",
        "open_material_pool": "ctrl+m",
        "open_settings": "ctrl+,",
        "refresh_material": "ctrl+f5",
        "translate_current": "ctrl+t",
        "translate_file": "ctrl+shift+t",
        "skip_block": "ctrl+shift+s",
    }
    for k, v in defaults.items():
        cfg["shortcuts"].setdefault(k, v)
    cfg["shortcuts"].setdefault("global_hotkeys", True)
    cfg["shortcuts"].setdefault("debounce_tail_seconds", 0.10)
    cfg.setdefault("speech", {})
    cfg["speech"].setdefault("tts_engine", "Edge-TTS Python API")
    cfg["speech"].setdefault("edge_voice", "en-US-JennyNeural")
    cfg["speech"].setdefault("chattts_force_when_selected", True)
    cfg.setdefault("hint", {})
    cfg["hint"].setdefault("display_mode", "逐个显示")
    cfg["hint"].setdefault("no_answer_leak", True)
    self.v69_cfg = cfg
    try:
        self.v63_cfg = cfg
    except Exception:
        pass
    return cfg

def _v74_save_cfg(self):
    if callable(_V74_PREV_SAVE):
        try:
            _V74_PREV_SAVE(self)
        except Exception:
            pass
    try:
        (_Path_v69.cwd() / "pp_studio_v74_settings.json").write_text(
            _json_v69.dumps(_v74_cfg(self), ensure_ascii=False, indent=2), "utf-8"
        )
    except Exception:
        pass

def _v74_notice(self, msg, level="info", scope="dictation"):
    if callable(_V74_PREV_NOTICE):
        try:
            return _V74_PREV_NOTICE(self, msg, level, scope)
        except TypeError:
            try:
                return _V74_PREV_NOTICE(self, msg, level)
            except Exception:
                pass
        except Exception:
            pass
    try:
        self.log(str(msg), "ok" if level == "ok" else ("err" if level in ("bad", "err") else "info"))
    except Exception:
        pass

def _v74_words(s):
    return _re_v69.findall(r"[A-Za-z]+(?:'[A-Za-z]+)?|\d+", str(s or ""))

def _v74_clean(s):
    return _re_v69.sub(r"\s+", " ", str(s or "")).strip()

def _v74_norm(s):
    return _re_v69.sub(r"\s+", " ", str(s or "")).strip().lower()

def _v74_mask_answer(s):
    words = _v74_words(s)
    out = []
    for w in words:
        if len(w) <= 2:
            out.append(w[:1] + "·" * max(0, len(w)-1))
        else:
            out.append(w[0] + "·" * (len(w)-2) + w[-1])
    return " ".join(out)

def _v74_current_material(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        return None
    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats)-1))
    self.dictation_index_v30 = idx
    return mats[idx]

def _v74_item_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

def _v74_item_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or "")
    return ""

# ── 当前输入框定位：修复 Ctrl+H 老是提示 and 的问题 ─────────────────────────────
def _v74_get_active_entry_index(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    if not entries:
        return -1
    # 1. 当前焦点输入框
    try:
        fw = self.focus_get()
        for i, it in enumerate(entries):
            if it.get("entry") is fw:
                self.dict_current_track_index_v73 = i
                return i
    except Exception:
        pass
    # 2. 鼠标/上次焦点记录
    cur = getattr(self, "dict_current_track_index_v73", None)
    if isinstance(cur, int) and 0 <= cur < len(entries):
        ent = entries[cur].get("entry")
        try:
            val = ent.get("1.0", "end-1c").strip() if ent else ""
            if val:
                return cur
        except Exception:
            return cur
    # 3. 最后一个有输入但未完全正确的输入框
    last_partial = -1
    for i, it in enumerate(entries):
        ent = it.get("entry")
        try:
            val = _v74_norm(ent.get("1.0", "end-1c")) if ent else ""
            tar = _v74_norm(it.get("target", ""))
            if val and val != tar:
                last_partial = i
        except Exception:
            pass
    if last_partial >= 0:
        self.dict_current_track_index_v73 = last_partial
        return last_partial
    # 4. 最后一个有输入的输入框
    last_any = -1
    for i, it in enumerate(entries):
        ent = it.get("entry")
        try:
            val = ent.get("1.0", "end-1c").strip() if ent else ""
            if val:
                last_any = i
        except Exception:
            pass
    if last_any >= 0:
        self.dict_current_track_index_v73 = last_any
        return last_any
    # 5. 第一个未完成
    for i, it in enumerate(entries):
        ent = it.get("entry")
        try:
            val = _v74_norm(ent.get("1.0", "end-1c")) if ent else ""
            tar = _v74_norm(it.get("target", ""))
            if val != tar:
                self.dict_current_track_index_v73 = i
                return i
        except Exception:
            pass
    return 0

def _v74_active_item(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    idx = _v74_get_active_entry_index(self)
    if 0 <= idx < len(entries):
        return entries[idx]
    return None

# 覆盖 V73 的定位函数，让跟踪播放也用同一个定位逻辑。
globals()["_v73_get_active_entry_index"] = _v74_get_active_entry_index

# ── 错误诊断：不泄露正确答案 ───────────────────────────────────────────────
def _v74_error_tips(target, val, role="语块"):
    tw = _v74_words(target)
    vw = _v74_words(val)
    tips = []

    if not val.strip():
        return "当前块还没有输入。"

    if len(vw) != len(tw):
        if len(vw) < len(tw):
            tips.append("缺词：当前输入的词数偏少，请检查是否漏掉功能词、介词、冠词或结尾词。")
        else:
            tips.append("多词：当前输入的词数偏多，请检查是否多打了重复词或多余功能词。")

    # 用位置比较，但不公布目标词。
    min_len = min(len(vw), len(tw))
    wrong_pos = []
    import difflib
    for i in range(min_len):
        a = vw[i].lower()
        b = tw[i].lower()
        if a == b:
            continue
        sim = difflib.SequenceMatcher(None, a, b).ratio()
        if sim >= 0.74:
            tips.append(f"第 {i+1} 个词：拼写接近，但有字母错误或漏字母。")
        else:
            wrong_pos.append(i+1)

        # 单复数
        if a.rstrip("s") == b.rstrip("s") and a != b:
            tips.append(f"第 {i+1} 个词：检查单复数形式。")
        # 动词形式
        bases = {a.rstrip("ed"), a.rstrip("ing"), a.rstrip("s")}
        bbases = {b.rstrip("ed"), b.rstrip("ing"), b.rstrip("s")}
        if bases & bbases and a != b:
            tips.append(f"第 {i+1} 个词：检查动词时态、第三人称或 -ing/-ed 形式。")
        # 所有格
        if a.replace("'", "") == b.replace("'", "") and a != b:
            tips.append(f"第 {i+1} 个词：检查所有格或缩写中的撇号。")

    if wrong_pos and not tips:
        tips.append("词形或顺序不匹配：请检查当前块中的词序和搭配。")
    elif wrong_pos:
        tips.append("另有词序/词形不匹配的位置，请结合上方颜色查看。")

    if not tips:
        tips.append("当前块未通过：请检查大小写以外的拼写、词形或顺序。")
    tips.append(f"当前语法提示：{role}。")
    return " ".join(dict.fromkeys(tips))

def _v74_judge_block(self, item):
    val = _v74_clean(item["entry"].get("1.0", "end-1c"))
    target = _v74_clean(str(item.get("target") or ""))
    ok = _v74_norm(val) == _v74_norm(target)
    color = V74_OK if ok else V74_BAD
    try:
        item["line"].delete("all")
        item["line"].create_line(2, 4, item["w"]-2, 4, fill=color, width=3)
        item["entry"].configure(fg=color)
    except Exception:
        pass

    if ok:
        try:
            self.dict_v63_hint_var.set("✅ 当前块正确。")
            if hasattr(self, "dict_v62_side_var"):
                self.dict_v62_side_var.set("正确后自动定位到下一条横线；继续输入。")
        except Exception:
            pass
        nxt = int(item.get("idx", 0)) + 1
        entries = getattr(self, "dict_v46_entries", []) or []
        if nxt < len(entries):
            try:
                entries[nxt]["entry"].focus_set()
                self.dict_current_track_index_v73 = nxt
            except Exception:
                pass
        else:
            if bool(getattr(self, "dict_auto_next_line_v46", tk.BooleanVar(value=True)).get()):
                fn = globals().get("_v72_next") or globals().get("_v73_next")
                if callable(fn):
                    fn(self)
        return True

    role = item.get("role", "语块")
    tip = _v74_error_tips(target, val, role)
    try:
        self.dict_v63_hint_var.set("❌ 当前块未通过。\n" + tip)
        if hasattr(self, "dict_v62_side_var"):
            self.dict_v62_side_var.set("错误提示不会公布正确答案；请按 Ctrl+H 逐层获取提示。")
    except Exception:
        pass
    _v74_notice(self, "当前块未通过：" + tip, "bad")
    return False

# 覆盖旧判断函数，避免错误提示暴露目标答案。
globals()["_v72_judge_block"] = _v74_judge_block

# ── 六步提示：定位到当前输入框，且默认不直接给答案 ─────────────────────────
def _v74_lookup_ipa(self, word):
    for name in ["_v70_lookup_ipa_from_local_dict", "_v72_ipa", "_v73_ipa"]:
        fn = globals().get(name)
        if callable(fn):
            try:
                r = fn(self, word)
                if r:
                    return r
            except Exception:
                pass
    return "音标待补"

def _v74_hint_current(self):
    item = _v74_active_item(self)
    if not item:
        _v74_notice(self, "当前没有可提示的输入块。", "bad")
        return "break"
    target = _v74_clean(item.get("target", ""))
    words = _v74_words(target)
    base = words[0].lower() if words else target.lower()
    idx = int(item.get("idx", 0))
    key = f"_v74_hint_step_{idx}"
    step = (int(getattr(self, key, 0) or 0) % 6) + 1
    setattr(self, key, step)

    title = ""
    body = ""
    if step == 1:
        title = "① 音标提示"
        ipas = []
        for w in words[:5]:
            ipas.append(f"{w}: {_v74_lookup_ipa(self, w)}")
        body = "；".join(ipas) if ipas else "暂无音标。"
    elif step == 2:
        title = "② 同音词提示"
        table = globals().get("V70_HOMOPHONES", {}) or {}
        arr = table.get(base, [])
        body = " / ".join(arr) if arr else "本地未记录同音词。"
    elif step == 3:
        title = "③ 近义 / 反义提示"
        table = globals().get("V70_SYN", {}) or {}
        d = table.get(base, {})
        body = f"近义：{', '.join(d.get('近义', [])) or '未记录'}；反义：{', '.join(d.get('反义', [])) or '未记录'}"
    elif step == 4:
        title = "④ 首尾字母提示"
        parts = []
        for w in words[:6]:
            parts.append(f"{w[:1]}…{w[-1:]}（{len(w)}字母）")
        body = "；".join(parts) if parts else "暂无。"
    elif step == 5:
        title = "⑤ 英文释义提示"
        table = globals().get("V70_DEF", {}) or {}
        body = table.get(base, "本地释义未命中；可接入本地词典目录。")
    else:
        title = "⑥ 词形 / 答案轮廓"
        # 不直接公布答案，只给轮廓。
        body = f"答案轮廓：{_v74_mask_answer(target)}；词数：{len(words)}；结构：{item.get('role','语块')}。"

    msg = f"{title}\n当前提示对象：第 {idx+1} 条横线；结构：{item.get('role','语块')}\n{body}"
    mode = _v74_cfg(self).get("hint", {}).get("display_mode", "逐个显示")
    if mode == "叠加显示":
        acc = getattr(self, "_v74_hint_accumulator", [])
        acc.append(msg)
        acc = acc[-6:]
        self._v74_hint_accumulator = acc
        show = "\n\n".join(acc)
    else:
        self._v74_hint_accumulator = [msg]
        show = msg
    try:
        self.dict_v63_hint_var.set(show)
        self.dict_v62_side_var.set(f"六步提示：{mode}；继续按 Ctrl+H 进入下一层。")
    except Exception:
        pass
    _v74_notice(self, f"六步提示更新：{title}", "info")
    return "break"

globals()["_v72_hint_current"] = _v74_hint_current
globals()["_v70_hint_current"] = _v74_hint_current

# ── 青色下一句英文字幕显示/隐藏：Alt+H ─────────────────────────────────────
def _v74_apply_next_subtitle_visibility(self):
    cfg = _v74_cfg(self)
    show_next = bool(cfg.get("display", {}).get("show_next_english_subtitle", False))
    show_current = bool(cfg.get("display", {}).get("show_current_english_subtitle", True))
    cur_idx = int(getattr(self, "dictation_index_v30", 0) or 0) + 1
    pat = _re_v69.compile(r"^\s*(\d+)\s*/\s*(\d+)\s*\|")
    def walk(w):
        try:
            if isinstance(w, tk.Label):
                txt = str(w.cget("text") or "")
                m = pat.search(txt)
                if m:
                    n = int(m.group(1))
                    if not hasattr(w, "_v74_original_fg"):
                        try:
                            w._v74_original_fg = w.cget("fg")
                        except Exception:
                            w._v74_original_fg = V74_CYAN
                    if n == cur_idx:
                        w.configure(fg=(w._v74_original_fg if show_current else w.cget("bg")))
                    else:
                        w.configure(fg=(w._v74_original_fg if show_next else w.cget("bg")))
        except Exception:
            pass
        try:
            for ch in w.winfo_children():
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v74_toggle_next_subtitle(self):
    cfg = _v74_cfg(self)
    cur = bool(cfg.get("display", {}).get("show_next_english_subtitle", False))
    cfg["display"]["show_next_english_subtitle"] = not cur
    _v74_save_cfg(self)
    _v74_apply_next_subtitle_visibility(self)
    _v74_notice(self, "青色英文字幕已" + ("显示" if not cur else "隐藏"), "ok")
    return "break"

def _v74_toggle_chinese(self):
    try:
        if not hasattr(self, "dictation_show_cn_v30"):
            self.dictation_show_cn_v30 = tk.BooleanVar(value=True)
        self.dictation_show_cn_v30.set(not self.dictation_show_cn_v30.get())
        cfg = _v74_cfg(self)
        cfg["display"]["show_chinese"] = bool(self.dictation_show_cn_v30.get())
        _v74_save_cfg(self)
        fn = globals().get("_v74_render_learning_area") or globals().get("_v73_render_learning_area")
        if callable(fn):
            fn(self)
    except Exception as e:
        _v74_notice(self, f"中文显示切换失败：{e}", "bad")
    return "break"

# ── ChatTTS 强制生效：选择 ChatTTS 时不再优先原片音频 ───────────────────────
def _v74_chattts_to_wav(self, text):
    text = _v74_clean(text)
    if not text:
        return None
    cfg = _v74_cfg(self)
    cache = _Path_v69(str(cfg.get("speech", {}).get("tts_cache_dir", _Path_v69.cwd() / "clip_cache" / "tts_v74")))
    cache.mkdir(parents=True, exist_ok=True)
    key = _re_v69.sub(r"[^A-Za-z0-9]+", "_", text[:70]).strip("_") or "tts"
    wav = cache / f"chattts_{key}_{abs(hash(text)) % 1000000}.wav"
    if wav.exists() and wav.stat().st_size > 1000:
        return wav
    try:
        import ChatTTS  # type: ignore
        import numpy as np  # type: ignore
        chat = getattr(self, "_v74_chattts", None)
        if chat is None:
            chat = ChatTTS.Chat()
            # 兼容不同 ChatTTS 版本
            try:
                chat.load(compile=False)
            except TypeError:
                chat.load()
            self._v74_chattts = chat
            _v74_notice(self, "ChatTTS 本地模型加载成功。", "ok")
        wavs = chat.infer([text])
        audio = wavs[0]
        if hasattr(audio, "detach"):
            audio = audio.detach().cpu().numpy()
        audio = np.asarray(audio).squeeze()
        if audio.size == 0:
            return None
        maxv = float(np.max(np.abs(audio))) or 1.0
        audio16 = (audio / maxv * 32767).astype("int16")
        try:
            from scipy.io.wavfile import write as wavwrite  # type: ignore
            wavwrite(str(wav), 24000, audio16)
        except Exception:
            import wave
            with wave.open(str(wav), "wb") as wf:
                wf.setnchannels(1)
                wf.setsampwidth(2)
                wf.setframerate(24000)
                wf.writeframes(audio16.tobytes())
        return wav if wav.exists() and wav.stat().st_size > 1000 else None
    except Exception as e:
        _v74_notice(self, f"ChatTTS 发音失败：{type(e).__name__}: {e}", "bad")
        return None

def _v74_tts_to_audio(self, text):
    text = _v74_clean(text)
    if not text:
        return None
    engine = _v74_cfg(self).get("speech", {}).get("tts_engine", "Edge-TTS Python API")
    _v74_notice(self, f"当前发音引擎：{engine}", "info")
    if engine == "ChatTTS 本地":
        wav = _v74_chattts_to_wav(self, text)
        if wav:
            return wav
        _v74_notice(self, "ChatTTS 未能生成音频，降级 Edge-TTS Python API。", "bad")
    # Edge / 旧版兜底
    fn = globals().get("_v71_edge_tts_to_wav")
    if callable(fn):
        try:
            wav = fn(self, text)
            if wav:
                return wav
        except Exception as e:
            _v74_notice(self, f"Edge-TTS 生成失败：{type(e).__name__}: {e}", "bad")
    if callable(_V74_PREV_TTS):
        try:
            return _V74_PREV_TTS(self, text)
        except Exception:
            pass
    return None

globals()["_v73_tts_to_audio"] = _v74_tts_to_audio
globals()["_v71_chattts_to_wav"] = _v74_chattts_to_wav

# 覆盖 V73 播放逻辑：ChatTTS/Edge 选择时强制走 TTS；只有“原片音频”才走原片。
def _v74_play_audio_mode(self, mode="full"):
    est = globals().get("_v73_estimate_segment")
    if callable(est):
        text, start, end, media = est(self, mode)
    else:
        m = _v74_current_material(self)
        text = _v74_item_text(m) if m else ""
        start = end = 0.0
        media = ""
    if not text:
        _v74_notice(self, "没有可播放文本。", "bad")
        return
    dur_fn = globals().get("_v73_estimated_duration")
    duration = dur_fn(text, start, end) if callable(dur_fn) else 1.0
    key = "audio_track" if mode == "track" else "audio_full"

    def run():
        engine = _v74_cfg(self).get("speech", {}).get("tts_engine", "Edge-TTS Python API")
        label = "跟踪播放音频：" if mode == "track" else "整句播放音频："
        _v74_notice(self, label + text[:80], "info")
        def worker():
            wav = None
            if engine == "原片音频" and media and end > start:
                fn = globals().get("_v73_extract_media_audio")
                if callable(fn):
                    wav = fn(self, media, start, end, "track" if mode == "track" else "full")
            else:
                wav = _v74_tts_to_audio(self, text)
            play = globals().get("_v73_play_wav")
            if wav and callable(play) and play(wav):
                _v74_notice(self, "音频播放已触发。", "ok")
            else:
                _v74_notice(self, "音频播放失败：请检查 ChatTTS/Edge-TTS/FFmpeg。", "bad")
        _threading_v69.Thread(target=worker, daemon=True).start()

    db = globals().get("_v73_debounce")
    if callable(db):
        db(self, key, duration, run)
    else:
        run()

globals()["_v73_play_audio_mode"] = _v74_play_audio_mode

# ── 全按钮快捷键：动作表、设置中心、注册 ─────────────────────────────────
def _v74_action_defs():
    return [
        ("full_audio", "播放音频", "ctrl"),
        ("track_audio", "跟踪播放", "alt"),
        ("full_video", "播放视频", "ctrl+up"),
        ("track_video", "跟踪视频", "alt+up"),
        ("prev_sentence", "上一句", "ctrl+left"),
        ("next_sentence", "下一句", "ctrl+right"),
        ("judge_current", "判断当前块", "space"),
        ("submit_sentence", "提交整句", "enter"),
        ("hint", "六步提示", "ctrl+h"),
        ("toggle_next_subtitle", "显示/隐藏青色英文字幕", "alt+h"),
        ("toggle_chinese", "显示/隐藏中文", "ctrl+shift+c"),
        ("copy_selected", "复制选中台词", "ctrl+c"),
        ("clear_learning", "清空学习区", "ctrl+shift+delete"),
        ("open_material_pool", "打开素材池", "ctrl+m"),
        ("open_settings", "打开设置中心", "ctrl+,"),
        ("refresh_material", "刷新素材树", "ctrl+f5"),
        ("translate_current", "制作当前翻译", "ctrl+t"),
        ("translate_file", "制作整文件翻译", "ctrl+shift+t"),
        ("skip_block", "跳过当前块", "ctrl+shift+s"),
    ]

def _v74_do_action(self, action):
    try:
        if action == "full_audio":
            return _v74_play_audio_mode(self, "full")
        if action == "track_audio":
            return _v74_play_audio_mode(self, "track")
        if action == "full_video":
            fn = globals().get("_v73_play_video_mode")
            return fn(self, "full") if callable(fn) else None
        if action == "track_video":
            fn = globals().get("_v73_play_video_mode")
            return fn(self, "track") if callable(fn) else None
        if action == "prev_sentence":
            fn = globals().get("_v72_prev") or globals().get("_v73_prev")
            return fn(self) if callable(fn) else None
        if action == "next_sentence":
            fn = globals().get("_v72_next") or globals().get("_v73_next")
            return fn(self) if callable(fn) else None
        if action == "judge_current":
            item = _v74_active_item(self)
            return _v74_judge_block(self, item) if item else None
        if action == "submit_sentence":
            fn = globals().get("_v72_submit_all")
            return fn(self) if callable(fn) else None
        if action == "hint":
            return _v74_hint_current(self)
        if action == "toggle_next_subtitle":
            return _v74_toggle_next_subtitle(self)
        if action == "toggle_chinese":
            return _v74_toggle_chinese(self)
        if action == "copy_selected":
            m = _v74_current_material(self)
            txt = _v74_item_text(m) if m else ""
            try:
                self.clipboard_clear(); self.clipboard_append(txt)
                _v74_notice(self, "已复制当前台词。", "ok")
            except Exception:
                pass
            return
        if action == "clear_learning":
            fn = globals().get("_v72_clear_learning")
            return fn(self) if callable(fn) else None
        if action == "open_settings":
            return _v74_open_settings_center(self)
        if action == "refresh_material":
            for nm in ["_v68_refresh_material_tree", "_v63_refresh_material_tree", "refresh_dictation_materials"]:
                fn = globals().get(nm) or getattr(self, nm, None)
                if callable(fn):
                    try:
                        return fn(self) if fn in globals().values() else fn()
                    except Exception:
                        pass
            _v74_notice(self, "没有找到可调用的刷新素材函数。", "bad")
            return
        if action == "translate_current":
            fn = globals().get("_v72_translate_current_async") or globals().get("_v74_translate_current_async")
            return fn(self) if callable(fn) else None
        if action == "translate_file":
            fn = globals().get("_v72_open_translate_builder")
            return fn(self, "file") if callable(fn) else None
        if action == "skip_block":
            fn = globals().get("_v72_next") or globals().get("_v73_next")
            return fn(self) if callable(fn) else None
        if action == "open_material_pool":
            _v74_notice(self, "素材池已在左侧；可在显示隐藏中控制。", "info")
            return
    except Exception as e:
        _v74_notice(self, f"快捷键动作失败：{action} | {type(e).__name__}: {e}", "bad")

def _v74_key_to_tk_sequences(key):
    key = str(key or "").strip().lower().replace(" ", "")
    # 直接支持单键 ctrl / alt / space / enter，也支持组合键。
    special = {
        "ctrl": ["<KeyPress-Control_L>", "<KeyPress-Control_R>"],
        "alt": ["<KeyPress-Alt_L>", "<KeyPress-Alt_R>", "<KeyPress-Menu>"],
        "space": ["<space>"],
        "enter": ["<Return>"],
        "esc": ["<Escape>"],
        "delete": ["<Delete>"],
        "f5": ["<F5>"],
    }
    if key in special:
        return special[key]
    # ctrl+shift+delete 等
    parts = key.split("+")
    mods = []
    normal = ""
    for p in parts:
        if p in ("ctrl", "control"):
            mods.append("Control")
        elif p == "alt":
            mods.append("Alt")
        elif p == "shift":
            mods.append("Shift")
        else:
            normal = p
    keymap = {"up": "Up", "down": "Down", "left": "Left", "right": "Right",
              "enter": "Return", "space": "space", "delete": "Delete",
              ",": "comma"}
    if len(normal) == 1 and normal.isalpha():
        normal = normal.lower()
    else:
        normal = keymap.get(normal, normal.upper() if normal.startswith("f") and normal[1:].isdigit() else normal)
    if normal:
        return ["<" + "-".join(mods + [normal]) + ">"]
    return []

def _v74_unregister_tk_hotkeys(self):
    for seq in getattr(self, "_v74_tk_sequences", []) or []:
        try:
            self.unbind_all(seq)
        except Exception:
            pass
    self._v74_tk_sequences = []

def _v74_register_tk_hotkeys(self):
    _v74_unregister_tk_hotkeys(self)
    cfg = _v74_cfg(self)
    seqs = []
    for action, label, default in _v74_action_defs():
        key = cfg.get("shortcuts", {}).get(action, default)
        for seq in _v74_key_to_tk_sequences(key):
            try:
                self.bind_all(seq, lambda e, a=action: (_v74_do_action(self, a), "break"), add="+")
                seqs.append(seq)
            except Exception as e:
                _v74_notice(self, f"软件内快捷键绑定失败：{label} {key} | {e}", "bad")
    self._v74_tk_sequences = seqs
    _v74_notice(self, "V74 软件内快捷键已全部重新绑定。", "ok")

def _v74_unregister_global_hotkeys(self):
    kb = getattr(self, "_v74_keyboard_module", None) or getattr(self, "_v73_keyboard_module", None)
    for h in getattr(self, "_v74_keyboard_handles", []) or []:
        try:
            kb.remove_hotkey(h)
        except Exception:
            pass
    self._v74_keyboard_handles = []

def _v74_register_global_hotkeys(self):
    _v74_unregister_global_hotkeys(self)
    cfg = _v74_cfg(self)
    if not bool(cfg.get("shortcuts", {}).get("global_hotkeys", True)):
        return
    try:
        import keyboard  # type: ignore
        self._v74_keyboard_module = keyboard
    except Exception:
        _v74_notice(self, "全局快捷键不可用：请 pip install keyboard；软件内快捷键仍可用。", "bad")
        return
    handles = []
    # 仅注册播放类和显示类为全局，避免全局 ctrl+c / enter 干扰系统。
    global_actions = {"full_audio", "track_audio", "full_video", "track_video", "toggle_next_subtitle"}
    for action, label, default in _v74_action_defs():
        if action not in global_actions:
            continue
        key = cfg.get("shortcuts", {}).get(action, default)
        try:
            h = keyboard.add_hotkey(key, lambda a=action: _v74_do_action(self, a),
                                    suppress=False, trigger_on_release=False)
            handles.append(h)
        except Exception as e:
            _v74_notice(self, f"全局快捷键绑定失败：{label} {key} | {type(e).__name__}: {e}", "bad")
    self._v74_keyboard_handles = handles
    if handles:
        _v74_notice(self, "V74 全局快捷键已注册：Ctrl / Alt / Ctrl+↑ / Alt+↑ / Alt+H。", "ok")

def _v74_register_all_hotkeys(self):
    # 尝试移除 V73 旧全局，避免重复触发。
    try:
        fn = globals().get("_v73_unregister_global_hotkeys")
        if callable(fn):
            fn(self)
    except Exception:
        pass
    _v74_register_tk_hotkeys(self)
    _v74_register_global_hotkeys(self)

# ── 设置中心 V74 ───────────────────────────────────────────────────────
def _v74_open_settings_center(self):
    cfg = _v74_cfg(self)
    win = tk.Toplevel(self)
    win.title("设置中心 V74 · 全快捷键/提示/显示/音效")
    win.geometry("1220x820")
    win.configure(bg=V74_PANEL)
    root = tk.Frame(win, bg=V74_PANEL)
    root.pack(fill="both", expand=True, padx=16, pady=12)

    head = tk.Frame(root, bg=V74_PANEL)
    head.pack(fill="x")
    tk.Label(head, text="设置中心 V74", bg=V74_PANEL, fg=V74_TEXT,
             font=("Microsoft YaHei UI", 22, "bold")).pack(side="left")
    ttk.Button(head, text="关闭", command=win.destroy).pack(side="right")
    tk.Label(root, text="保存后立即生效：所有听写训练按钮快捷键、显示隐藏、音效、ChatTTS、六步提示。",
             bg=V74_PANEL, fg=V74_MUTED, font=("Microsoft YaHei UI", 10)).pack(anchor="w", pady=(4, 10))

    nb = ttk.Notebook(root)
    nb.pack(fill="both", expand=True)
    pages = {}
    for name in ["全快捷键", "播放/发音", "提示/错误", "显示隐藏", "音效设置", "翻译/路径"]:
        f = tk.Frame(nb, bg=V74_PANEL)
        nb.add(f, text=name)
        pages[name] = f

    def row(page, title, desc=""):
        r = tk.Frame(pages[page], bg=V74_PANEL)
        r.pack(fill="x", padx=14, pady=7)
        left = tk.Frame(r, bg=V74_PANEL)
        left.pack(side="left", fill="x", expand=True)
        tk.Label(left, text=title, bg=V74_PANEL, fg=V74_TEXT,
                 font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w")
        if desc:
            tk.Label(left, text=desc, bg=V74_PANEL, fg=V74_MUTED,
                     wraplength=720, justify="left").pack(anchor="w")
        return r

    # 全快捷键
    global_hotkeys = tk.BooleanVar(value=bool(cfg["shortcuts"].get("global_hotkeys", True)))
    r = row("全快捷键", "启用全局播放快捷键", "全局只注册：整句音频、跟踪音频、整句视频、跟踪视频、青色字幕开关，避免干扰系统复制/回车。")
    ttk.Checkbutton(r, text="开启", variable=global_hotkeys).pack(side="right", padx=10)

    shortcut_vars = {}
    canvas = tk.Canvas(pages["全快捷键"], bg=V74_PANEL, highlightthickness=0)
    scroll = ttk.Scrollbar(pages["全快捷键"], orient="vertical", command=canvas.yview)
    inner = tk.Frame(canvas, bg=V74_PANEL)
    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.create_window((0, 0), window=inner, anchor="nw")
    canvas.configure(yscrollcommand=scroll.set)
    canvas.pack(side="left", fill="both", expand=True, padx=(14, 0), pady=6)
    scroll.pack(side="right", fill="y", pady=6)

    for action, label, default in _v74_action_defs():
        var = tk.StringVar(value=cfg["shortcuts"].get(action, default))
        shortcut_vars[action] = var
        rr = tk.Frame(inner, bg=V74_PANEL)
        rr.pack(fill="x", pady=4)
        tk.Label(rr, text=label, bg=V74_PANEL, fg=V74_TEXT, width=24, anchor="w",
                 font=("Microsoft YaHei UI", 10, "bold")).pack(side="left")
        tk.Entry(rr, textvariable=var, width=22, bg="#0f172a", fg=V74_TEXT,
                 insertbackground=V74_TEXT, relief="solid").pack(side="left", padx=8)
        tk.Label(rr, text=f"默认：{default}", bg=V74_PANEL, fg=V74_MUTED, width=22, anchor="w").pack(side="left")

    # 播放/发音
    tts_engine = tk.StringVar(value=cfg["speech"].get("tts_engine", "Edge-TTS Python API"))
    edge_voice = tk.StringVar(value=cfg["speech"].get("edge_voice", "en-US-JennyNeural"))
    force_chattts = tk.BooleanVar(value=bool(cfg["speech"].get("chattts_force_when_selected", True)))
    r = row("播放/发音", "文本转语音引擎", "选择 ChatTTS 本地时会强制走 ChatTTS，不再优先原片音频。")
    ttk.Combobox(r, textvariable=tts_engine, values=["Edge-TTS Python API", "ChatTTS 本地", "原片音频", "旧版TTS兜底"],
                 state="readonly", width=28).pack(side="right", padx=10)
    r = row("播放/发音", "Edge-TTS 音色", "ChatTTS 不使用此项。")
    ttk.Combobox(r, textvariable=edge_voice, values=[
        "en-US-JennyNeural", "en-US-GuyNeural", "en-US-AriaNeural", "en-US-DavisNeural",
        "en-GB-SoniaNeural", "en-GB-RyanNeural", "en-CA-ClaraNeural", "en-CA-LiamNeural",
        "en-AU-NatashaNeural", "en-AU-WilliamNeural"
    ], width=32).pack(side="right", padx=10)
    r = row("播放/发音", "ChatTTS 选择后强制生效", "关闭后才允许优先使用原片音频。")
    ttk.Checkbutton(r, text="开启", variable=force_chattts).pack(side="right", padx=10)

    # 提示/错误
    hint_mode = tk.StringVar(value=cfg["hint"].get("display_mode", "逐个显示"))
    no_answer = tk.BooleanVar(value=bool(cfg["hint"].get("no_answer_leak", True)))
    r = row("提示/错误", "六步提示显示方式", "逐个显示 / 叠加显示。")
    ttk.Combobox(r, textvariable=hint_mode, values=["逐个显示", "叠加显示"], state="readonly", width=18).pack(side="right", padx=10)
    r = row("提示/错误", "错误提示不公布正确答案", "错误提示只从拼写、词性、单复数、动词形式、所有格、顺序等角度提示。")
    ttk.Checkbutton(r, text="开启", variable=no_answer).pack(side="right", padx=10)

    # 显示隐藏
    show_cn = tk.BooleanVar(value=bool(cfg["display"].get("show_chinese", True)))
    show_cur = tk.BooleanVar(value=bool(cfg["display"].get("show_current_english_subtitle", True)))
    show_next = tk.BooleanVar(value=bool(cfg["display"].get("show_next_english_subtitle", False)))
    show_keytips = tk.BooleanVar(value=bool(cfg["display"].get("show_keytips", True)))
    show_statusline = tk.BooleanVar(value=bool(cfg["display"].get("show_statusline", True)))
    for title, desc, var in [
        ("默认显示中文", "控制学习区中文翻译默认显示。", show_cn),
        ("显示左上角当前英文字幕", "粉色当前台词，建议保留。", show_cur),
        ("显示左上角下一句英文字幕", "青色下一句字幕；默认关闭。快捷键 Alt+H。", show_next),
        ("显示快捷键提示", "底部快捷键提示区。", show_keytips),
        ("显示状态提示栏", "底部操作日志/状态栏。", show_statusline),
    ]:
        r = row("显示隐藏", title, desc)
        ttk.Checkbutton(r, text="显示", variable=var).pack(side="right", padx=10)

    # 音效设置
    sound_enabled = tk.BooleanVar(value=bool(cfg["sound"].get("enabled", True)))
    typing_enabled = tk.BooleanVar(value=bool(cfg["sound"].get("typing_enabled", True)))
    correct_enabled = tk.BooleanVar(value=bool(cfg["sound"].get("correct_enabled", True)))
    wrong_enabled = tk.BooleanVar(value=bool(cfg["sound"].get("wrong_enabled", True)))
    letters_only = tk.BooleanVar(value=bool(cfg["sound"].get("typing_scope_letters_only", True)))
    volume = tk.IntVar(value=int(cfg["sound"].get("volume", 70) or 70))
    for title, desc, var in [
        ("启用音效系统", "听写训练和背诵听忆共用。", sound_enabled),
        ("打字音效", "默认只在 26 个英文字母输入时触发。", typing_enabled),
        ("正确音效", "单词/语块正确时触发。", correct_enabled),
        ("错误音效", "输入错误时触发。", wrong_enabled),
        ("打字音效仅限 26 个英文字母", "关闭后可扩展到数字、空格、功能键。", letters_only),
    ]:
        r = row("音效设置", title, desc)
        ttk.Checkbutton(r, text="开启", variable=var).pack(side="right", padx=10)
    r = row("音效设置", "音效音量", "0-100。")
    ttk.Scale(r, variable=volume, from_=0, to=100, orient="horizontal", length=220).pack(side="right", padx=10)

    # 翻译/路径
    trans_engine = tk.StringVar(value=cfg.get("translation", {}).get("engine", "OPUS-MT 本地 direct_generate"))
    opus_dir = tk.StringVar(value=cfg.get("translation", {}).get("opus_en_zh_dir", r"G:\AI_Models\translation\opus-mt-en-zh"))
    r = row("翻译/路径", "翻译引擎", "默认 OPUS-MT direct_generate。")
    ttk.Combobox(r, textvariable=trans_engine, values=["OPUS-MT 本地 direct_generate", "旧版OPUS", "Argos 本地", "Google 在线", "百度API"],
                 width=32).pack(side="right", padx=10)
    r = row("翻译/路径", "OPUS 模型目录", "例如：G:\\AI_Models\\translation\\opus-mt-en-zh")
    ttk.Entry(r, textvariable=opus_dir, width=72).pack(side="right", padx=6)

    def save_all():
        cfg = _v74_cfg(self)
        cfg["shortcuts"]["global_hotkeys"] = bool(global_hotkeys.get())
        for action, var in shortcut_vars.items():
            cfg["shortcuts"][action] = var.get().strip().lower()
        cfg["speech"]["tts_engine"] = tts_engine.get()
        cfg["speech"]["edge_voice"] = edge_voice.get()
        cfg["speech"]["chattts_force_when_selected"] = bool(force_chattts.get())
        cfg["hint"]["display_mode"] = hint_mode.get()
        cfg["hint"]["no_answer_leak"] = bool(no_answer.get())
        cfg["display"]["show_chinese"] = bool(show_cn.get())
        cfg["display"]["show_current_english_subtitle"] = bool(show_cur.get())
        cfg["display"]["show_next_english_subtitle"] = bool(show_next.get())
        cfg["display"]["show_keytips"] = bool(show_keytips.get())
        cfg["display"]["show_statusline"] = bool(show_statusline.get())
        cfg["sound"]["enabled"] = bool(sound_enabled.get())
        cfg["sound"]["typing_enabled"] = bool(typing_enabled.get())
        cfg["sound"]["correct_enabled"] = bool(correct_enabled.get())
        cfg["sound"]["wrong_enabled"] = bool(wrong_enabled.get())
        cfg["sound"]["typing_scope_letters_only"] = bool(letters_only.get())
        cfg["sound"]["volume"] = int(volume.get())
        cfg.setdefault("translation", {})["engine"] = trans_engine.get()
        cfg.setdefault("translation", {})["opus_en_zh_dir"] = opus_dir.get().strip()
        try:
            if not hasattr(self, "dictation_show_cn_v30"):
                self.dictation_show_cn_v30 = tk.BooleanVar(value=bool(show_cn.get()))
            self.dictation_show_cn_v30.set(bool(show_cn.get()))
        except Exception:
            pass
        _v74_save_cfg(self)
        _v74_register_all_hotkeys(self)
        _v74_apply_next_subtitle_visibility(self)
        _v74_rebind_buttons(self)
        _v74_notice(self, "V74 设置已保存并立即生效。", "ok")
        try:
            messagebox.showinfo("已保存", "V74 设置已保存并立即生效。")
        except Exception:
            pass

    bottom = tk.Frame(root, bg=V74_PANEL)
    bottom.pack(fill="x", pady=(10, 0))
    ttk.Button(bottom, text="保存全部设置并立即生效", command=save_all).pack(side="right", padx=5)
    ttk.Button(bottom, text="关闭", command=win.destroy).pack(side="right", padx=5)

# ── 渲染后补丁：绑定焦点、隐藏青色字幕、按钮命令 ─────────────────────────────
def _v74_after_render(self):
    entries = getattr(self, "dict_v46_entries", []) or []
    for i, it in enumerate(entries):
        ent = it.get("entry")
        if ent is None:
            continue
        try:
            ent.bind("<FocusIn>", lambda e, idx=i: setattr(self, "dict_current_track_index_v73", idx), add="+")
            ent.bind("<Button-1>", lambda e, idx=i: setattr(self, "dict_current_track_index_v73", idx), add="+")
            ent.bind("<Control-h>", lambda e: (_v74_hint_current(self), "break"), add="+")
            ent.bind("<space>", lambda e, item=it: (_v74_judge_block(self, item), "break"), add="+")
        except Exception:
            pass
    _v74_apply_next_subtitle_visibility(self)

def _v74_render_learning_area(self):
    if callable(_V74_PREV_RENDER):
        _V74_PREV_RENDER(self)
    _v74_after_render(self)

def _v74_rebind_buttons(self):
    def walk(w):
        try:
            txt = str(w.cget("text")).strip()
            if txt.startswith("设置中心") or txt in {"配置中心", "高级设置中心 · 音效/TTS/快捷键"}:
                w.configure(text="设置中心", command=lambda: _v74_open_settings_center(self))
            elif txt in {"提示 Ctrl+H", "提示", "六步提示"}:
                w.configure(text="六步提示 Ctrl+H", command=lambda: _v74_hint_current(self))
            elif txt in {"播放音频", "播放音频 Ctrl", "播放当前音频"}:
                w.configure(text="播放音频 Ctrl", command=lambda: _v74_play_audio_mode(self, "full"))
            elif txt in {"跟踪播放 Alt", "跟踪播放", "跟踪音频"}:
                w.configure(text="跟踪播放 Alt", command=lambda: _v74_play_audio_mode(self, "track"))
            elif txt in {"显示中文", "隐藏中文"}:
                w.configure(command=lambda: _v74_toggle_chinese(self))
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v74_patch_globals(self):
    globals()["_v74_cfg"] = _v74_cfg
    globals()["_v73_cfg"] = _v74_cfg
    globals()["_v72_cfg"] = _v74_cfg
    globals()["_v71_cfg"] = _v74_cfg
    globals()["_v74_open_settings_center"] = _v74_open_settings_center
    globals()["_v73_open_settings_center"] = _v74_open_settings_center
    globals()["_v72_open_settings_center"] = _v74_open_settings_center
    globals()["_v71_open_settings_center"] = _v74_open_settings_center
    globals()["_v74_render_learning_area"] = _v74_render_learning_area
    globals()["_v73_render_learning_area"] = _v74_render_learning_area
    globals()["_v72_render_learning_area"] = _v74_render_learning_area
    globals()["_v74_hint_current"] = _v74_hint_current
    globals()["_v73_hint_current"] = _v74_hint_current
    globals()["_v72_hint_current"] = _v74_hint_current
    globals()["_v70_hint_current"] = _v74_hint_current
    globals()["_v73_play_audio_mode"] = _v74_play_audio_mode
    globals()["_v73_tts_to_audio"] = _v74_tts_to_audio
    globals()["_v72_judge_block"] = _v74_judge_block

_old_main_init_v74 = MainApp.__init__
def _main_init_v74(self):
    _old_main_init_v74(self)
    try:
        _v74_cfg(self)
        _v74_patch_globals(self)
        _v74_register_all_hotkeys(self)
        _v74_rebind_buttons(self)
        try:
            self.after(300, lambda: (_v74_patch_globals(self), _v74_register_all_hotkeys(self), _v74_rebind_buttons(self)))
            self.after(900, lambda: (_v74_after_render(self), _v74_notice(self, "V74 已接管：六步提示定位、错误提示、青色字幕开关、全快捷键、ChatTTS强制生效。", "ok")))
        except Exception:
            pass
        self.log("【V74上线】Ctrl+H 六步提示改为当前横线定位，不再错到前面的 and。", "ok")
        self.log("【V74上线】错误提示不再暴露正确答案，只提示拼写/词形/单复数/动词形式/所有格/顺序。", "ok")
        self.log("【V74上线】青色下一句英文字幕默认隐藏，Alt+H 可开关；粉色当前句保留。", "ok")
        self.log("【V74上线】设置中心加入全按钮快捷键、显示隐藏、音效设置；保存后立即生效。", "ok")
        self.log("【V74上线】选择 ChatTTS 本地后强制走 ChatTTS，不再被原片音频优先级覆盖。", "ok")
    except Exception as e:
        try:
            self.log(f"V74初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v74
APP_TITLE = "PlayPhrase Studio Clean v74 · 提示定位/快捷键/ChatTTS修复版"


# ──────────────────────────────────────────────────────────────────────
# V75：横线长度/Space跳转/设置生效主线修复版
#
# 重点修复：
# 1) 横线长度：
#    - 拆分模式：横线字符宽度 = 单词长度 + 2，视觉长度一定大于单词长度 + 1。
#    - 整句模式：横线字符宽度 = 语块总字母数 + 语块词数 + 2。
#    - 不再用 90px 最小线宽，避免 uh/this/is 这类短词横线过长。
# 2) Space 判断后不跳转：
#    - 覆盖所有旧 space 绑定。
#    - 正确后 after_idle 强制焦点跳到下一条横线。
#    - 最后一块正确后根据“自动跳到下一行”跳下一句。
#    - 输入框严格压缩空格，不允许多个空格、开头空格、结尾空格。
# 3) 设置中心设置不生效：
#    - V75 配置从 v75/v74/v73/v72/v69 多配置文件合并读取。
#    - 保存时同步写入 v75/v74/v73 三份，旧函数也能读到。
#    - 所有 _v70/_v71/_v72/_v73/_v74_cfg 全部重定向到 _v75_cfg。
#    - 保存后立即：重新绑定快捷键、刷新学习区、重绑按钮、应用显示隐藏。
# ──────────────────────────────────────────────────────────────────────

_V75_PREV_CFG = globals().get("_v74_cfg") or globals().get("_v73_cfg") or globals().get("_v72_cfg")
_V75_PREV_NOTICE = globals().get("_v74_notice") or globals().get("_v73_notice") or globals().get("_v72_notice")
_V75_PREV_OPEN_SETTINGS = globals().get("_v74_open_settings_center") or globals().get("_v73_open_settings_center")
_V75_PREV_TTS = globals().get("_v74_tts_to_audio") or globals().get("_v73_tts_to_audio")

V75_BG = "#0b1220"
V75_PANEL = "#111827"
V75_PANEL2 = "#0f172a"
V75_TEXT = "#E5E7EB"
V75_MUTED = "#94A3B8"
V75_LINE = "#CBD5E1"
V75_INPUT = "#8B5CF6"
V75_OK = "#22C55E"
V75_BAD = "#EF4444"
V75_WARN = "#F59E0B"
V75_CYAN = "#67E8F9"
V75_PINK = "#F0ABFC"
V75_CHAR_PX = 16
V75_SPLIT_INNER_GAP_CH = 3
V75_GROUP_GAP_CH = 10

def _v75_deep_merge(a, b):
    """return merged dict: b overrides a"""
    out = dict(a or {})
    for k, v in (b or {}).items():
        if isinstance(v, dict) and isinstance(out.get(k), dict):
            out[k] = _v75_deep_merge(out[k], v)
        else:
            out[k] = v
    return out

def _v75_load_disk_cfg():
    cfg = {}
    # 旧版先读，新版后覆盖，保证用户最新设置不会被 V73/V74 覆盖掉
    names = [
        "pp_studio_v69_settings.json",
        "pp_studio_v72_settings.json",
        "pp_studio_v73_settings.json",
        "pp_studio_v74_settings.json",
        "pp_studio_v75_settings.json",
    ]
    for n in names:
        p = _Path_v69.cwd() / n
        try:
            if p.exists():
                cfg = _v75_deep_merge(cfg, _json_v69.loads(p.read_text("utf-8")))
        except Exception:
            pass
    return cfg

