def _v75_patch_globals(self=None):
    # 所有旧 cfg 全部指向 V75，解决设置中心保存但播放/渲染/快捷键读取旧配置的问题。
    for name in ["_v75_cfg", "_v74_cfg", "_v73_cfg", "_v72_cfg", "_v71_cfg", "_v70_cfg"]:
        globals()[name] = _v75_cfg
    for name in ["_v75_save_cfg", "_v74_save_cfg", "_v73_save_cfg", "_v72_save_cfg"]:
        globals()[name] = _v75_save_cfg
    for name in ["_v75_notice", "_v74_notice", "_v73_notice", "_v72_notice"]:
        globals()[name] = _v75_notice
    for name in ["_v75_render_learning_area", "_v74_render_learning_area", "_v73_render_learning_area", "_v72_render_learning_area"]:
        globals()[name] = _v75_render_learning_area
    for name in ["_v75_open_settings_center", "_v74_open_settings_center", "_v73_open_settings_center", "_v72_open_settings_center"]:
        globals()[name] = _v75_open_settings_center
    for name in ["_v75_judge_block", "_v74_judge_block", "_v72_judge_block"]:
        globals()[name] = _v75_judge_block
    for name in ["_v75_force_check_current", "_v46_force_check_current"]:
        globals()[name] = _v75_force_check_current
    globals()["_v75_live_color"] = _v75_live_color
    globals()["_v72_live_color"] = _v75_live_color
    globals()["_v75_do_action"] = _v75_do_action
    globals()["_v74_do_action"] = _v75_do_action
    globals()["_v75_tts_to_audio"] = _v75_tts_to_audio
    globals()["_v73_tts_to_audio"] = _v75_tts_to_audio

_old_main_init_v75 = MainApp.__init__
def _main_init_v75(self):
    _old_main_init_v75(self)
    try:
        _v75_patch_globals(self)
        _v75_cfg(self)
        _v75_register_all_hotkeys(self)
        _v75_rebind_buttons(self)
        try:
            self.after(250, lambda: (_v75_patch_globals(self), _v75_register_all_hotkeys(self), _v75_rebind_buttons(self)))
            self.after(700, lambda: (_v75_render_learning_area(self), _v75_notice(self, "V75 已接管：横线长度、Space跳转、设置实时生效。", "ok")))
        except Exception:
            pass
        self.log("【V75上线】横线长度已按单词/语块字符精确计算，不再短词长横线。", "ok")
        self.log("【V75上线】Space 判断正确后强制跳转下一条横线，旧绑定已覆盖。", "ok")
        self.log("【V75上线】设置中心保存后同步写入 V75/V74/V73 配置，并立即刷新学习区。", "ok")
        self.log("【V75上线】所有旧 cfg/render/judge/settings 入口已重定向到 V75。", "ok")
    except Exception as e:
        try:
            self.log(f"V75初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v75
APP_TITLE = "PlayPhrase Studio Clean v75 · 横线长度与设置生效修复版"

# ──────────────────────────────────────────────────────────────────────
# V76：反递归硬修复 + 设置中心强制接管 + 翻译/TTS 主链恢复版
#
# 本版不是继续套旧函数，而是把导致未响应的三个递归点切断：
# 1) _v62_refresh_material_tree / _v66_refresh_material_tree 互相覆盖递归
# 2) _v74_tts_to_audio -> _v75_tts_to_audio -> _v74_tts_to_audio 递归
# 3) 设置中心被旧 V72 after/rebind 抢回，保存内容不进入真实运行链
# ──────────────────────────────────────────────────────────────────────

import hashlib as _hashlib_v76
import asyncio as _asyncio_v76
import tempfile as _tempfile_v76
