def _v76_load_disk_cfg():
    cfg = {}
    for name in [
        "pp_studio_v69_settings.json",
        "pp_studio_v70_settings.json",
        "pp_studio_v71_settings.json",
        "pp_studio_v72_settings.json",
        "pp_studio_v73_settings.json",
        "pp_studio_v74_settings.json",
        "pp_studio_v75_settings.json",
        "pp_studio_v76_settings.json",
    ]:
        p = _Path_v69.cwd() / name
        try:
            if p.exists():
                cfg = _v76_deep_merge(cfg, _json_v69.loads(p.read_text("utf-8")))
        except Exception:
            pass
    return cfg

def _v76_cfg(self):
    cfg = _v76_deep_merge(_v76_default_cfg(), _v76_load_disk_cfg())
    mem = getattr(self, "v69_cfg", None)
    if isinstance(mem, dict):
        cfg = _v76_deep_merge(cfg, mem)
    self.v69_cfg = cfg
    try: self.v63_cfg = cfg
    except Exception: pass
    return cfg

def _v76_save_cfg(self):
    cfg = _v76_cfg(self)
    # 同步写回旧版本文件，防止旧闭包/旧模块读到旧配置。
    for name in [
        "pp_studio_v76_settings.json",
        "pp_studio_v75_settings.json",
        "pp_studio_v74_settings.json",
        "pp_studio_v73_settings.json",
        "pp_studio_v72_settings.json",
    ]:
        try:
            (_Path_v69.cwd() / name).write_text(_json_v69.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
        except Exception:
            pass
    return cfg

def _v76_notice(self, msg, level="info", scope="dictation"):
    try:
        if hasattr(self, "dict_v69_notice_var"):
            self.dict_v69_notice_var.set(str(msg))
    except Exception:
        pass
    try:
        self.log(str(msg), "ok" if level == "ok" else ("err" if level in ("bad","err") else "warn" if level == "warn" else "info"))
    except Exception:
        pass

def _v76_clean_text(s):
    return _re_v69.sub(r"\s+", " ", str(s or "")).strip()

def _v76_has_en(s):
    return bool(_re_v69.search(r"[A-Za-z]{2,}", str(s or "")))

def _v76_material_text(m):
    if isinstance(m, dict):
        return str(m.get("text") or m.get("en") or m.get("line") or m.get("sentence") or "")
    return str(m or "")

def _v76_material_zh(m):
    if isinstance(m, dict):
        return str(m.get("zh") or m.get("cn") or m.get("translation") or "")
    return ""

def _v76_set_material_zh(m, zh):
    if isinstance(m, dict):
        m["zh"] = str(zh or "")
        m["cn"] = str(zh or "")
        m["translation"] = str(zh or "")

def _v76_current_material(self):
    mats = getattr(self, "dictation_materials_v30", []) or []
    if not mats:
        return None
    idx = max(0, min(int(getattr(self, "dictation_index_v30", 0) or 0), len(mats) - 1))
    self.dictation_index_v30 = idx
    return mats[idx]

# ── 1) 材料树刷新：独立实现，不调用旧 _v62/_v66，彻底避免递归 ───────────────
def _v76_bucket(m):
    if isinstance(m, dict):
        st = str(m.get("source_type") or m.get("bucket") or m.get("origin") or "").lower()
        if "local_video" in st or "video" in st or m.get("video_path"):
            return "本地素材"
        if "text" in st or m.get("subtitle_path") or m.get("text_path"):
            return "文本素材"
        if "online" in st or "playphrase" in st:
            return "在线素材"
    return "在线素材"

def _v76_path_of(m):
    if isinstance(m, dict):
        for k in ("video_path", "media_path", "local_path", "audio_path", "subtitle_path", "path", "text_path"):
            v = m.get(k)
            if v:
                return str(v)
    return ""

def _v76_group_name(m):
    p = _v76_path_of(m)
    if p:
        try: return _Path_v69(p).name
        except Exception: return str(p)
    if isinstance(m, dict):
        return str(m.get("title") or m.get("keyword") or "在线精选池")
    return "在线精选池"

def _v76_refresh_material_tree(self):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None:
        return
    try:
        tree.delete(*tree.get_children())
    except Exception:
        pass
    self.dict_v62_node_map = {}
    self.dict_v62_page_map = {}
    self.dict_v76_item_map = {}
    mats = getattr(self, "dictation_materials_v30", []) or []

    try:
        filt = getattr(self, "dict_v46_source_filter").get()
    except Exception:
        filt = "全部"

    groups = {}
    for i, m in enumerate(mats):
        bucket = _v76_bucket(m)
        if filt not in ("", "全部", bucket):
            continue
        key = (bucket, _v76_group_name(m))
        groups.setdefault(key, []).append(i)

    node_cache = {}
    def node(parent, key, text, open_flag=True):
        if key in node_cache:
            return node_cache[key]
        iid = "v76_" + _hashlib_v76.md5(("|".join(map(str, key))).encode("utf-8", "ignore")).hexdigest()
        try:
            tree.insert(parent, "end", iid=iid, text=text, open=open_flag, values=("DIR", text))
        except Exception:
            iid = tree.insert(parent, "end", text=text, open=open_flag, values=("DIR", text))
        node_cache[key] = iid
        return iid

    page_size = 200
    try:
        page_size = int(getattr(self, "dict_v62_page_size", tk.IntVar(value=200)).get() or 200)
    except Exception:
        pass
    page_size = max(50, min(1000, page_size))

    for (bucket, fname), idxs in groups.items():
        root_iid = node("", (bucket,), f"{bucket}｜{sum(1 for k in groups if k[0]==bucket)}组", True)
        file_key = (bucket, fname)
        file_iid = "v76_file_" + _hashlib_v76.md5(("|".join(file_key)).encode("utf-8", "ignore")).hexdigest()
        try:
            tree.insert(root_iid, "end", iid=file_iid, text=f"📄 {fname}｜{len(idxs)}句", open=(len(idxs) <= 80), values=("FILE", fname))
        except Exception:
            file_iid = tree.insert(root_iid, "end", text=f"📄 {fname}｜{len(idxs)}句", open=(len(idxs) <= 80), values=("FILE", fname))
        self.dict_v62_node_map[file_iid] = list(idxs)

        if len(idxs) <= 200:
            for idx in idxs:
                txt = _v76_material_text(mats[idx])
                iid = f"v76_item_{idx}"
                try:
                    tree.insert(file_iid, "end", iid=iid, text=f"· {idx+1:04d}. {txt[:180]}", values=("ITEM", str(idx)))
                except Exception:
                    iid = tree.insert(file_iid, "end", text=f"· {idx+1:04d}. {txt[:180]}", values=("ITEM", str(idx)))
                self.dict_v76_item_map[iid] = idx
        else:
            for start in range(0, len(idxs), page_size):
                end = min(start + page_size, len(idxs))
                page_iid = f"{file_iid}_p{start}"
                try:
                    tree.insert(file_iid, "end", iid=page_iid, text=f"▶ {start+1:04d}-{end:04d}", open=False, values=("PAGE", str(start), str(end)))
                except Exception:
                    page_iid = tree.insert(file_iid, "end", text=f"▶ {start+1:04d}-{end:04d}", open=False, values=("PAGE", str(start), str(end)))
                self.dict_v62_page_map[page_iid] = idxs[start:end]
    _v76_notice(self, f"听写素材树已刷新：{len(mats)} 条；V76安全树无递归。", "ok")

def _v76_on_tree_select(self, event=None):
    tree = getattr(self, "dict_material_tree_v46", None)
    if tree is None:
        return
    try:
        sel = tree.selection()
        if not sel:
            return
        iid = sel[0]
        vals = tree.item(iid, "values") or ()
    except Exception:
        return
    mats = getattr(self, "dictation_materials_v30", []) or []
    idx = None
    if iid in getattr(self, "dict_v76_item_map", {}):
        idx = self.dict_v76_item_map[iid]
    elif vals and str(vals[0]) == "ITEM":
        try: idx = int(vals[1])
        except Exception: idx = None
    elif iid in getattr(self, "dict_v62_node_map", {}):
        lst = self.dict_v62_node_map.get(iid) or []
        idx = lst[0] if lst else None
    elif iid in getattr(self, "dict_v62_page_map", {}):
        lst = self.dict_v62_page_map.get(iid) or []
        # 展开分页内容
        try:
            if not tree.get_children(iid):
                for x in lst:
                    if x < len(mats):
                        text = _v76_material_text(mats[x])
                        tree.insert(iid, "end", iid=f"v76_item_{x}", text=f"· {x+1:04d}. {text[:180]}", values=("ITEM", str(x)))
                        self.dict_v76_item_map[f"v76_item_{x}"] = x
        except Exception:
            pass
        idx = lst[0] if lst else None
    if idx is not None and 0 <= idx < len(mats):
        self.dictation_index_v30 = idx
        _v76_render_learning_area_safe(self)
        _v76_notice(self, f"已加载素材到学习区：第 {idx+1} 条。", "ok")

# ── 2) TTS：独立实现，彻底不再反调 _v74_tts_to_audio ─────────────────────
async def _v76_edge_tts_save(text, voice, out_file):
    import edge_tts  # type: ignore
    communicate = edge_tts.Communicate(str(text), str(voice or "en-US-JennyNeural"))
    await communicate.save(str(out_file))
    return out_file

def _v76_edge_tts_to_audio(self, text):
    cfg = _v76_cfg(self)
    cache_dir = _Path_v69(cfg.get("speech", {}).get("tts_cache_dir") or (_Path_v69.cwd() / "clip_cache" / "tts_v76"))
    try:
        cache_dir.mkdir(parents=True, exist_ok=True)
    except Exception:
        pass
    voice = cfg.get("speech", {}).get("edge_voice", "en-US-JennyNeural")
    key = _hashlib_v76.md5((voice + "||" + text).encode("utf-8", "ignore")).hexdigest()
    out = cache_dir / f"edge_{key}.mp3"
    if out.exists() and out.stat().st_size > 1000:
        return out
    try:
        _asyncio_v76.run(_v76_edge_tts_save(text, voice, out))
        if out.exists() and out.stat().st_size > 1000:
            return out
    except RuntimeError:
        # 已存在 event loop 时用新 loop
        loop = _asyncio_v76.new_event_loop()
        try:
            loop.run_until_complete(_v76_edge_tts_save(text, voice, out))
        finally:
            loop.close()
        if out.exists() and out.stat().st_size > 1000:
            return out
    except Exception as e:
        _v76_notice(self, f"Edge-TTS Python API 发音失败：{type(e).__name__}: {e}", "bad")
    return None

def _v76_chattts_to_audio(self, text):
    if callable(_V76_ORIG_CHAT):
        try:
            wav = _V76_ORIG_CHAT(self, text)
            if wav:
                return wav
        except Exception as e:
            _v76_notice(self, f"ChatTTS 本地发音失败：{type(e).__name__}: {e}", "bad")
    else:
        _v76_notice(self, "ChatTTS 函数不存在：请确认 chattts 相关依赖和模型已安装。", "bad")
    return None

def _v76_tts_to_audio(self, text):
    text = _v76_clean_text(text)
    if not text:
        return None
    cfg = _v76_cfg(self)
    engine = cfg.get("speech", {}).get("tts_engine", "Edge-TTS Python API")
    _v76_notice(self, f"当前发音引擎：{engine}", "info")
    if "ChatTTS" in engine:
        wav = _v76_chattts_to_audio(self, text)
        if wav:
            return wav
        _v76_notice(self, "ChatTTS 未返回音频，自动降级 Edge-TTS Python API。", "warn")
    if "Edge" in engine or "TTS" in engine or engine in ("在线TTS", "旧版TTS兜底"):
        wav = _v76_edge_tts_to_audio(self, text)
        if wav:
            return wav
    # 最后才允许旧 Edge 函数兜底，绝不调用 _v74_tts_to_audio
    if callable(_V76_ORIG_EDGE):
        try:
            return _V76_ORIG_EDGE(self, text)
        except Exception:
            pass
    return None

# ── 3) 播放：入口清晰，不递归 ─────────────────────────────────────────────
def _v76_play_audio_mode(self, mode="full"):
    # 尽量复用 V74 的媒体定位逻辑，但 TTS函数已经被 V76 替换，不会递归。
    if callable(_V76_ORIG_PLAY_AUDIO_MODE) and _V76_ORIG_PLAY_AUDIO_MODE is not _v76_play_audio_mode:
        try:
            return _V76_ORIG_PLAY_AUDIO_MODE(self, mode)
        except RecursionError:
            _v76_notice(self, "旧播放链发生递归，已切换 V76 兜底TTS播放。", "bad")
        except Exception as e:
            _v76_notice(self, f"旧播放链失败，改用V76兜底：{type(e).__name__}: {e}", "warn")
    m = _v76_current_material(self)
    text = _v76_material_text(m)
    if not text:
        _v76_notice(self, "当前没有可播放文本。", "bad")
        return
    audio = _v76_tts_to_audio(self, text)
    if not audio:
        _v76_notice(self, "TTS未能生成音频。", "bad")
        return
    try:
        os.startfile(str(audio))
        _v76_notice(self, f"已播放音频：{text[:60]}", "ok")
    except Exception as e:
        _v76_notice(self, f"音频播放失败：{type(e).__name__}: {e}", "bad")

# ── 4) 翻译：OPUS direct_generate 独立主链，不再掉到旧 self.config.get ─────
def _v76_opus_direct_translate(self, text):
    text = _v76_clean_text(text)
    if not text:
        return ""
    cfg = _v76_cfg(self)
    model_dir = cfg.get("translation", {}).get("opus_en_zh_dir") or r"G:\AI_Models\translation\opus-mt-en-zh"
    candidates = [
        _Path_v69(str(model_dir)),
        _Path_v69(r"G:\AI_Models\translation\opus-mt-en-zh"),
        _Path_v69.cwd() / "AI_Models" / "translation" / "opus-mt-en-zh",
        _Path_v69.cwd() / "models" / "opus-mt-en-zh",
    ]
    model_path = None
    for p in candidates:
        try:
            if p.exists():
                model_path = p
                break
        except Exception:
            pass
    if model_path is None:
        _v76_notice(self, "OPUS模型目录不存在：请在设置中心填写 opus-mt-en-zh 目录。", "bad")
        return ""
    try:
        from transformers import AutoTokenizer, AutoModelForSeq2SeqLM  # type: ignore
        import torch  # type: ignore
        cache = getattr(self, "_v76_opus_cache", {})
        if str(model_path) not in cache:
            tok = AutoTokenizer.from_pretrained(str(model_path), local_files_only=True)
            model = AutoModelForSeq2SeqLM.from_pretrained(str(model_path), local_files_only=True)
            model.eval()
            cache[str(model_path)] = (tok, model)
            self._v76_opus_cache = cache
            _v76_notice(self, f"OPUS-MT direct_generate 加载成功：{model_path}", "ok")
        tok, model = cache[str(model_path)]
        inputs = tok([text], return_tensors="pt", truncation=True, max_length=512)
        with torch.no_grad():
            out = model.generate(**inputs, max_new_tokens=220, num_beams=4)
        zh = tok.batch_decode(out, skip_special_tokens=True)[0]
        return _v76_clean_text(zh)
    except Exception as e:
        _v76_notice(self, f"OPUS-MT direct_generate 翻译失败：{type(e).__name__}: {e}", "bad")
        return ""

def _v76_translate_text(self, text):
    text = _v76_clean_text(text)
    if not text:
        return ""
    zh = _v76_opus_direct_translate(self, text)
    if zh:
        return zh
    # 兜底用非常简单的提示，不调用旧 _opus_translate_v19，避免 self.config.get 旧错误反复刷屏。
    return ""

def _v76_translate_current(self, refresh=True):
    m = _v76_current_material(self)
    if not m:
        _v76_notice(self, "当前没有素材，无法翻译。", "bad")
        return ""
    text = _v76_material_text(m)
    if not _v76_has_en(text):
        _v76_notice(self, "当前台词没有英文，无法翻译。", "bad")
        return ""
    _v76_notice(self, "正在翻译当前台词……", "info")
    zh = _v76_translate_text(self, text)
    if zh:
        _v76_set_material_zh(m, zh)
        _v76_notice(self, f"当前台词翻译完成：{zh[:80]}", "ok")
        if refresh:
            _v76_render_learning_area_safe(self)
        return zh
    _v76_notice(self, "当前台词翻译失败：OPUS direct_generate 没有返回中文；请检查模型目录。", "bad")
    return ""

def _v76_translate_current_async(self):
    def worker():
        _v76_translate_current(self, refresh=False)
        try: self.after(0, lambda: _v76_render_learning_area_safe(self))
        except Exception: pass
    _threading_v69.Thread(target=worker, daemon=True).start()

