def _v76_setting_row(parent, title, desc=""):
    r = tk.Frame(parent, bg=V76_PANEL)
    r.pack(fill="x", padx=16, pady=8)
    l = tk.Frame(r, bg=V76_PANEL)
    l.pack(side="left", fill="x", expand=True)
