    cfg["display"].setdefault("show_right_notification_panel", True)
    cfg.setdefault("player", {})
    cfg["player"].setdefault("prefer_qt", True)
    cfg["player"].setdefault("allow_system_fallback", False)  # V78 默认不静默降级；失败必须显示原因
    cfg["player"].setdefault("qt_python_exe", "")
    cfg.setdefault("speech", {})
    cfg["speech"].setdefault("tts_engine", "Edge-TTS Python API")
    cfg["speech"].setdefault("edge_voice", "en-US-JennyNeural")
    cfg["speech"].setdefault("tts_cache_dir", str(_Path_v69.cwd() / "clip_cache" / "tts_v78"))
