def _v78_save_cfg(self):
    cfg = _v78_cfg(self)
    for name in [
        "pp_studio_v78_settings.json", "pp_studio_v77_settings.json", "pp_studio_v76_settings.json",
        "pp_studio_v75_settings.json", "pp_studio_v74_settings.json", "pp_studio_v73_settings.json", "pp_studio_v72_settings.json"
    ]:
        try:
            (_Path_v69.cwd() / name).write_text(_json_v69.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
        except Exception:
            pass
    return cfg

def _v78_notice(self, msg, level="info", scope="dictation"):
    # 右侧通知栏 + 底部状态 + 日志三路同步
    text = str(msg)
    try:
        if "_v77_append_notice_widget" in globals():
            _v77_append_notice_widget(self, text, level)
    except Exception:
        pass
    try:
        if hasattr(self, "dict_v69_notice_var"):
            self.dict_v69_notice_var.set(text)
    except Exception:
        pass
    try:
        self.log(text, "ok" if level=="ok" else "err" if level in ("bad","err") else "warn" if level=="warn" else "info")
    except Exception:
        pass

def _v78_no_window_kwargs():
    if os.name == "nt":
        return {"creationflags": getattr(subprocess, "CREATE_NO_WINDOW", 0)}
    return {}

# ── 1. Qt播放器：失败显示原因；默认不偷偷降级 ─────────────────────────────
def _v78_player_load_cfg():
    cfg = {}
    for name in ["pp_studio_v78_settings.json","pp_studio_v77_settings.json","pp_studio_v76_settings.json","pp_studio_v73_settings.json"]:
        try:
            p = Path.cwd() / name
            if p.exists():
                cfg = {**cfg, **json.loads(p.read_text("utf-8"))}
        except Exception:
            pass
    cfg.setdefault("player", {})
    cfg["player"].setdefault("allow_system_fallback", False)
    cfg["player"].setdefault("qt_python_exe", "")
    return cfg

def _v78_player_helper_commands(self):
    cmds = []
    try:
        helper_exe = self._bundled_helper_exe()
        if helper_exe is not None:
            cmds.append([str(helper_exe), str(self.port)])
    except Exception:
        pass
    try:
        self.helper_path.write_text(QT_PLAYER_HELPER, "utf-8")
    except Exception:
        pass
    helper = str(getattr(self, "helper_path", Path(tempfile.gettempdir()) / "pp_studio_qt_player.py"))
    cfg = _v78_player_load_cfg()
    candidates = [
        str(cfg.get("player", {}).get("qt_python_exe", "") or "").strip(),
        sys.executable,
        getattr(sys, "_base_executable", ""),
        r"G:\Python_Env\Python312\python.exe",
        r"C:\Users\Administrator\AppData\Local\Programs\Python\Python312\python.exe",
    ]
    seen = set()
    for py in candidates:
        if py and py.lower() not in seen and Path(py).exists():
            cmds.append([py, helper, str(self.port)])
            seen.add(py.lower())
    if os.name == "nt":
        cmds.append(["py", "-3", helper, str(self.port)])
    return cmds

def _v78_player_ensure_server(self):
    if getattr(self, "proc", None) and self.proc.poll() is None and getattr(self, "port", None):
        return True
    self.port = self._free_port()
    errors = []
    for cmd in _v78_player_helper_commands(self):
        try:
            self.log("Qt播放器启动尝试：" + " ".join(map(str, cmd[:2])), "info")
            self.proc = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, **_v78_no_window_kwargs())
            deadline = time.time() + 7.0
            last = ""
            while time.time() < deadline:
                if self.proc.poll() is not None:
                    out = ""
                    try: out = self.proc.stdout.read() if self.proc.stdout else ""
                    except Exception: pass
                    errors.append("命令：" + " ".join(map(str, cmd)) + "\n输出：" + out[:1600])
                    break
                try:
                    with socket.create_connection(("127.0.0.1", self.port), timeout=0.35):
                        self.log("Qt播放器已启动，后续复用内嵌窗口。", "ok")
                        return True
                except Exception as e:
                    last = str(e)
                    time.sleep(0.12)
            else:
                errors.append("命令：" + " ".join(map(str, cmd)) + "\n启动超时：" + last)
                try:
                    if self.proc and self.proc.poll() is None:
                        self.proc.terminate()
                except Exception:
                    pass
        except Exception as e:
            errors.append("命令：" + " ".join(map(str, cmd)) + f"\n异常：{type(e).__name__}: {e}")
    detail = "\n\n".join(errors[-4:])
    if "PySide6" in detail or "ModuleNotFoundError" in detail:
        self.log("Qt播放器失败：当前 helper Python 缺少 PySide6。请在【设置中心→播放/Qt】填写已安装 PySide6 的 python.exe，或 pip install PySide6。", "err")
    else:
        self.log("Qt播放器失败：未能建立本地播放窗口。详情：" + detail[:2200], "err")
    return False

def _v78_player_play(self, path):
    path = Path(str(path))
    if not path.exists():
        self.log("播放失败：本地文件不存在：" + str(path), "err")
        return
    if self._ensure_server():
        if self._send({"cmd": "play", "path": str(path)}):
            return
    cfg = _v78_player_load_cfg()
    if not cfg.get("player", {}).get("allow_system_fallback", False):
        self.log("Qt播放失败；已按设置禁止系统播放器降级。请先修复 Qt/PySide6 或打开允许兜底。", "err")
        return
    self.log("Qt失败，按设置降级系统播放器。", "warn")
    try:
        if os.name == "nt":
            os.startfile(str(path))
        elif sys.platform == "darwin":
            subprocess.Popen(["open", str(path)])
        else:
            subprocess.Popen(["xdg-open", str(path)])
    except Exception as e:
        self.log(f"系统播放器打开失败：{type(e).__name__}: {e}", "err")

try:
    PlayerService._ensure_server = _v78_player_ensure_server
    PlayerService.play = _v78_player_play
except Exception:
    pass

