# ── 4. UI 去冗余：不只隐藏当前窗口，还把旧函数入口全部改掉 ────────────────
def _v78_cleanup_buttons(self):
    remove_contains = [
        "听写控制台", "刷新素材树", "刷新资源目录", "快捷键设置", "自定义快捷键",
        "打开快捷键设置", "打开快捷键捕获设置", "分块横线听写",
        "高级设置中心", "打开快捷键",
    ]
    setting_texts = ["设置中心", "配置中心"]
    maker_contains = ["制作当前翻译", "制作整文件翻译", "制作翻译字幕"]
    def walk(w):
        try:
            text = str(w.cget("text")).strip()
            if any(x in text for x in remove_contains):
                try: w.destroy()
                except Exception:
                    try: w.pack_forget()
                    except Exception: pass
                return
            if any(x in text for x in setting_texts):
                try: w.configure(text="设置中心", command=lambda: _v78_open_settings_center(self))
                except Exception: pass
            if any(x in text for x in maker_contains):
                try: w.configure(text="制作台", command=lambda: _v78_open_maker(self))
                except Exception: pass
            if text in ("播放当前音频", "主播放 Ctrl+R", "播放音频 Ctrl"):
                try: w.configure(text="播放音频", command=lambda: _v77_play_audio_mode(self, "full") if "_v77_play_audio_mode" in globals() else None)
                except Exception: pass
            if text in ("视频播放 Ctrl+Alt+V", "播放当前视频"):
                try: w.configure(text="播放视频", command=lambda: _v77_action(self, "full_video") if "_v77_action" in globals() else None)
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

