def _v79_deep_merge(a, b):
    out = dict(a or {})
    for k, v in (b or {}).items():
        if isinstance(v, dict) and isinstance(out.get(k), dict):
            out[k] = _v79_deep_merge(out[k], v)
        else:
            out[k] = v
    return out

