def _v79_load_disk_cfg():
    cfg = {}
    # 只读文件，不调用任何旧 cfg 函数，避免递归。
    for name in [
        "pp_studio_v72_settings.json",
        "pp_studio_v73_settings.json",
        "pp_studio_v74_settings.json",
        "pp_studio_v75_settings.json",
        "pp_studio_v76_settings.json",
        "pp_studio_v77_settings.json",
        "pp_studio_v78_settings.json",
        "pp_studio_v79_settings.json",
    ]:
        try:
            p = _Path_v69.cwd() / name
            if p.exists():
                cfg = _v79_deep_merge(cfg, _json_v69.loads(p.read_text("utf-8", errors="ignore")))
        except Exception:
            pass
    return cfg

def _v79_cfg(self=None):
    cfg = _v79_deep_merge(_v79_default_cfg(), _v79_load_disk_cfg())
    if self is not None:
        try:
            mem = getattr(self, "v69_cfg", None)
            if isinstance(mem, dict):
                cfg = _v79_deep_merge(cfg, mem)
            self.v69_cfg = cfg
            self.v63_cfg = cfg
        except Exception:
            pass
    return cfg

def _v79_save_cfg(self=None, cfg=None):
    if cfg is None:
        cfg = _v79_cfg(self)
    if self is not None:
        try:
            self.v69_cfg = cfg
            self.v63_cfg = cfg
        except Exception:
            pass
    for name in [
        "pp_studio_v79_settings.json",
        "pp_studio_v78_settings.json",
        "pp_studio_v77_settings.json",
        "pp_studio_v76_settings.json",
        "pp_studio_v75_settings.json",
        "pp_studio_v74_settings.json",
        "pp_studio_v73_settings.json",
        "pp_studio_v72_settings.json",
    ]:
        try:
            (_Path_v69.cwd() / name).write_text(_json_v69.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
        except Exception:
            pass
    return cfg

def _v79_notice(self, msg, level="info", scope="dictation"):
    text = str(msg)
    try:
        if "_v77_append_notice_widget" in globals():
            _v77_append_notice_widget(self, text, level)
    except Exception:
        pass
    try:
        if hasattr(self, "dict_v69_notice_var"):
            self.dict_v69_notice_var.set(text)
    except Exception:
        pass
    try:
        self.log(text, "ok" if level == "ok" else "err" if level in ("bad", "err") else "warn" if level == "warn" else "info")
    except Exception:
        pass

