def _v79_key_to_tk(key):
    key = str(key or "").strip().lower().replace(" ", "")
    if key in ("ctrl", "control"):
        return ["<KeyPress-Control_L>", "<KeyPress-Control_R>"]
    if key == "alt":
        return ["<KeyPress-Alt_L>", "<KeyPress-Alt_R>", "<KeyPress-Menu>"]
    if key == "space":
        return ["<space>", "<KeyPress-space>"]
    if key == "enter":
        return ["<Return>"]
    parts = key.split("+")
    mods, normal = [], ""
    for p in parts:
        if p in ("ctrl", "control"):
            mods.append("Control")
        elif p == "alt":
            mods.append("Alt")
        elif p == "shift":
            mods.append("Shift")
        else:
            normal = p
    mp = {
        "up": "Up", "down": "Down", "left": "Left", "right": "Right",
        "space": "space", "enter": "Return", "delete": "Delete",
        ",": "comma", "f5": "F5", "f11": "F11",
    }
    normal = mp.get(normal, normal)
    if not normal:
        return []
    return ["<" + "-".join(mods + [normal]) + ">"]

def _v79_play_audio(self, mode="full"):
    # 不从 globals 取已被覆盖的 V78 函数，优先使用安装前捕获的播放链。
    try:
        if callable(_V79_ORIG_PLAY_AUDIO):
            return _V79_ORIG_PLAY_AUDIO(self, mode)
    except RecursionError:
        _v79_notice(self, "旧音频播放链递归，已切换 V79 兜底播放。", "bad")
    except Exception as e:
        _v79_notice(self, f"旧音频播放链失败，尝试V79兜底：{type(e).__name__}: {e}", "warn")

    text = ""
    try:
        m = _v76_current_material(self) if "_v76_current_material" in globals() else None
        text = _v76_material_text(m) if "_v76_material_text" in globals() else ""
    except Exception:
        pass
    if not text:
        _v79_notice(self, "当前没有可播放文本。", "bad")
        return
    try:
        audio = _v76_tts_to_audio(self, text) if "_v76_tts_to_audio" in globals() else None
        if audio and "_v77_play_audio_file" in globals():
            if _v77_play_audio_file(self, audio):
                _v79_notice(self, "音频播放已触发。", "ok")
                return
        if audio and os.name == "nt":
            os.startfile(str(audio))
            _v79_notice(self, "音频文件已打开播放。", "ok")
            return
    except Exception as e:
        _v79_notice(self, f"V79兜底音频播放失败：{type(e).__name__}: {e}", "bad")

def _v79_play_video(self, mode="full"):
    try:
        if callable(_V79_ORIG_PLAY_VIDEO):
            return _V79_ORIG_PLAY_VIDEO(self, mode)
    except RecursionError:
        _v79_notice(self, "旧视频播放链递归。", "bad")
    except Exception as e:
        _v79_notice(self, f"视频播放失败：{type(e).__name__}: {e}", "bad")

def _v79_action(self, action):
    if action == "full_audio":
        return _v79_play_audio(self, "full")
    if action == "track_audio":
        return _v79_play_audio(self, "track")
    if action == "full_video":
        return _v79_play_video(self, "full")
    if action == "track_video":
        return _v79_play_video(self, "track")
    if action == "open_settings":
        return _v79_open_settings_center(self)
    if action == "open_maker":
        return _v79_open_maker(self)
    if action == "hint" and callable(_V79_ORIG_HINT):
        return _V79_ORIG_HINT(self)
    if action == "toggle_current_subtitle":
        return _v79_toggle_bool(self, "show_current_english_subtitle", "粉色当前英文字幕")
    if action == "toggle_next_subtitle":
        return _v79_toggle_bool(self, "show_next_english_subtitle", "青色下一句英文字幕")
    if action == "toggle_chinese":
        try:
            fn = globals().get("_v75_toggle_chinese") or globals().get("_v72_toggle_chinese")
            if callable(fn):
                return fn(self)
        except Exception:
            pass
    if action == "prev_sentence":
        fn = globals().get("_v46_prev") or globals().get("_v72_prev")
        if callable(fn): return fn(self)
    if action == "next_sentence":
        fn = globals().get("_v46_next") or globals().get("_v72_next")
        if callable(fn): return fn(self)
    if action == "judge_current":
        fn = globals().get("_v75_force_check_current") or globals().get("_v46_force_check_current")
        if callable(fn): return fn(self)
    if action == "submit_sentence":
        fn = globals().get("_v75_submit_all") or globals().get("_v46_submit")
        if callable(fn): return fn(self)
    if action == "clear_learning":
        fn = globals().get("_v66_clear_learning_area") or globals().get("_v46_clear")
        if callable(fn): return fn(self)

def _v79_toggle_bool(self, key, label):
    cfg = _v79_cfg(self)
    cfg["display"][key] = not bool(cfg["display"].get(key, False))
    _v79_save_cfg(self, cfg)
    try:
        _v79_render_learning_area(self)
    except Exception:
        pass
    _v79_notice(self, f"{label}已{'显示' if cfg['display'][key] else '隐藏'}。", "ok")

def _v79_apply_shortcuts(self, silent=False):
    # 不调用旧快捷键函数，完全独立绑定。
    try:
        for seq in getattr(self, "_v79_tk_sequences", []) or []:
            try:
                self.unbind_all(seq)
            except Exception:
                pass
    except Exception:
        pass

    cfg = _v79_cfg(self)
    seqs = []
    for action, key in cfg.get("shortcuts", {}).items():
        if action == "global_hotkeys":
            continue
        for seq in _v79_key_to_tk(key):
            try:
                self.bind_all(seq, lambda e, a=action: (_v79_action(self, a), "break"))
                seqs.append(seq)
            except Exception:
                pass
    self._v79_tk_sequences = seqs

    # 全局快捷键仅处理播放四项，避免输入训练时过度抢键。
    try:
        import keyboard  # type: ignore
        for h in getattr(self, "_v79_global_handles", []) or []:
            try:
                keyboard.remove_hotkey(h)
            except Exception:
                pass
        self._v79_global_handles = []
        if cfg.get("shortcuts", {}).get("global_hotkeys", True):
            for action in ("full_audio", "track_audio", "full_video", "track_video"):
                key = cfg["shortcuts"].get(action)
                if key:
                    self._v79_global_handles.append(
                        keyboard.add_hotkey(key, lambda a=action: _v79_action(self, a), suppress=False)
                    )
    except Exception as e:
        if not silent:
            _v79_notice(self, f"全局快捷键不可用，仅软件内生效：{type(e).__name__}: {e}", "warn")
    if not silent:
        _v79_notice(self, "快捷键已立即生效。", "ok")

