def _v79_open_maker(self, *args, **kwargs):
    # 不从 globals 取 _v77_open_maker，防止被 V78/V79 覆盖后又递归。
    if callable(_V79_ORIG_MAKER):
        try:
            return _V79_ORIG_MAKER(self)
        except RecursionError:
            _v79_notice(self, "旧制作台递归，无法打开。", "bad")
            return
        except Exception as e:
            _v79_notice(self, f"制作台打开失败：{type(e).__name__}: {e}", "bad")
            return
    _v79_notice(self, "制作台函数不存在。", "bad")

def _v79_cleanup_buttons(self):
    remove_contains = [
        "听写控制台", "刷新素材树", "刷新资源目录", "快捷键设置", "自定义快捷键",
        "打开快捷键设置", "打开快捷键捕获设置", "分块横线听写",
        "高级设置中心", "打开快捷键",
    ]
    maker_contains = ["制作当前翻译", "制作整文件翻译", "制作翻译字幕"]
    settings_seen = 0

    def walk(w):
        nonlocal settings_seen
        try:
            text = str(w.cget("text")).strip()
            if any(x in text for x in remove_contains):
                try:
                    w.destroy()
                except Exception:
                    try: w.pack_forget()
                    except Exception: pass
                return
            if "设置中心" in text or text == "配置中心":
                settings_seen += 1
                if settings_seen > 1:
                    try:
                        w.destroy()
                    except Exception:
                        try: w.pack_forget()
                        except Exception: pass
                    return
                try:
                    w.configure(text="设置中心", command=lambda: _v79_open_settings_center(self))
                except Exception:
                    pass
            if any(x in text for x in maker_contains):
                try:
                    w.configure(text="制作台", command=lambda: _v79_open_maker(self))
                except Exception:
                    pass
            if text in ("播放当前音频", "主播放 Ctrl+R", "播放音频 Ctrl"):
                try:
                    w.configure(text="播放音频", command=lambda: _v79_play_audio(self, "full"))
                except Exception:
                    pass
            if text in ("视频播放 Ctrl+Alt+V", "播放当前视频"):
                try:
                    w.configure(text="播放视频", command=lambda: _v79_play_video(self, "full"))
                except Exception:
                    pass
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try:
        walk(self)
    except Exception:
        pass

def _v79_render_learning_area(self):
    # 不调用已被 V78 覆盖的 globals 版本，调用安装前捕获的原始 render。
    if callable(_V79_ORIG_RENDER):
        try:
            _V79_ORIG_RENDER(self)
        except RecursionError:
            _v79_notice(self, "旧学习区渲染递归，已跳过。", "bad")
        except Exception as e:
            _v79_notice(self, f"学习区渲染失败：{type(e).__name__}: {e}", "bad")
    try:
        _v79_cleanup_buttons(self)
    except Exception:
        pass

def _v79_three_check(self, mats=None):
    mats = mats if mats is not None else (getattr(self, "dictation_materials_v30", []) or [])
    if not mats:
        return "三要素检查：未加载素材。"
    def text_of(m):
        try:
            return _v76_material_text(m) if "_v76_material_text" in globals() else str(m.get("text", ""))
        except Exception:
            return ""
    def zh_of(m):
        try:
            return _v76_material_zh(m) if "_v76_material_zh" in globals() else str(m.get("zh") or m.get("cn") or m.get("translation") or "")
        except Exception:
            return ""
    def media_of(m):
        if not isinstance(m, dict):
            return ""
        for k in ("video_path", "audio_path", "media_path", "local_path"):
            if m.get(k):
                return str(m.get(k))
        return ""
    has_media = any(media_of(m) and Path(media_of(m)).exists() for m in mats if isinstance(m, dict))
    has_en = any(text_of(m).strip() for m in mats)
    has_zh = any(zh_of(m).strip() for m in mats)
    miss = []
    if not has_media: miss.append("音/视频缺失")
    if not has_en: miss.append("原生英文缺失")
    if not has_zh: miss.append("中文翻译缺失")
    return "三要素检查：" + ("完整" if not miss else "，".join(miss) + "；可打开制作台补齐。")

def _v79_load_selected_resource(self, mode="dictation"):
    # 只调用捕获的原始资源加载函数，不再从 globals 动态取，避免 V78 自调用递归。
    if not callable(_V79_ORIG_RESOURCE_LOAD):
        _v79_notice(self, "资源平台加载函数不存在。", "bad")
        return
    _v79_notice(self, "正在从资源平台加载到听写训练……", "info")
    try:
        _V79_ORIG_RESOURCE_LOAD(self, mode)
        self.after(500, lambda: (_v79_render_learning_area(self), _v79_notice(self, _v79_three_check(self), "warn" if "缺失" in _v79_three_check(self) else "ok")))
    except RecursionError:
        _v79_notice(self, "资源加载旧链递归，已阻断。", "bad")
    except Exception as e:
        _v79_notice(self, f"资源加载失败：{type(e).__name__}: {e}", "bad")

def _v79_install(self=None, repeat=True):
    # 1. cfg/save：全部指向独立函数，绝不调用 V77/V78 cfg。
    for nm in ["_v79_cfg", "_v78_cfg", "_v77_cfg", "_v76_cfg", "_v75_cfg", "_v74_cfg", "_v73_cfg", "_v72_cfg", "_v71_cfg", "_v70_cfg", "_v69_cfg"]:
        globals()[nm] = _v79_cfg
    for nm in ["_v79_save_cfg", "_v78_save_cfg", "_v77_save_cfg", "_v76_save_cfg", "_v75_save_cfg", "_v74_save_cfg", "_v73_save_cfg", "_v72_save_cfg", "_v71_save_cfg", "_v70_save_cfg", "_v69_save_cfg"]:
        globals()[nm] = _v79_save_cfg

    # 2. 设置/快捷键/音效设置旧入口：全部指向 V79 独立设置中心。
    for nm in [
        "_v79_open_settings_center", "_v78_open_settings_center", "_v77_open_settings_center", "_v76_open_settings_center",
        "_v75_open_settings_center", "_v74_open_settings_center", "_v73_open_settings_center", "_v72_open_settings_center",
        "_v71_open_settings_center", "_v70_open_settings_center", "_v69_open_settings_center",
        "_v60_open_shortcut_editor", "_v58_open_shortcut_editor", "_v57_open_shortcut_editor", "_v56_open_shortcut_editor",
        "_v46_open_shortcut_editor", "_dictation_open_shortcut_editor_v37", "_dictation_open_shortcut_editor_v34",
        "_v54_open_sound_settings", "_v53_open_sound_settings", "_v56_open_sound_settings",
    ]:
        globals()[nm] = _v79_open_settings_center

    # 3. 制作台：统一指向 V79，但内部调用捕获的原始 V77 maker。
    for nm in ["_v79_open_maker", "_v78_open_maker", "_v77_open_maker", "_v71_open_translate_builder"]:
        globals()[nm] = _v79_open_maker

    # 4. 渲染/资源加载：统一指向 V79，内部调用捕获的原始函数，避免自调用。
    for nm in ["_v79_render_learning_area", "_v78_render_learning_area", "_v77_render_learning_area", "_v75_render_learning_area", "_v74_render_learning_area"]:
        globals()[nm] = _v79_render_learning_area
    for nm in ["_v79_load_selected_resource", "_v78_load_selected_resource", "_v77_load_selected_resource", "_v71_load_selected_resource", "_v69_load_selected_resource"]:
        globals()[nm] = _v79_load_selected_resource

    # 5. notice/action。
    for nm in ["_v79_notice", "_v78_notice", "_v77_notice", "_v76_notice", "_v75_notice", "_v74_notice"]:
        globals()[nm] = _v79_notice

    try:
        MainApp._dictation_open_shortcut_editor_v34 = lambda app: _v79_open_settings_center(app)
        MainApp._dictation_open_shortcut_editor_v37 = lambda app: _v79_open_settings_center(app)
    except Exception:
        pass

    if self is not None:
        try:
            self.v69_cfg = _v79_cfg(self)
        except Exception:
            pass
        try:
            if "_v77_rebuild_right_notification_panel" in globals():
                _v77_rebuild_right_notification_panel(self)
        except Exception:
            pass
        try:
            _v79_cleanup_buttons(self)
        except Exception:
            pass
        try:
            _v79_apply_shortcuts(self, silent=True)
        except Exception:
            pass

        if repeat:
            # 抵消旧 after 抢入口，但 V79 的函数本身不会再回调旧入口，因此不会再递归。
            for ms in [200, 700, 1400, 2400, 3800, 6000, 9000]:
                try:
                    self.after(ms, lambda app=self: (_v79_install(app, repeat=False), _v79_cleanup_buttons(app)))
                except Exception:
                    pass

_old_main_init_v79 = MainApp.__init__
def _main_init_v79(self):
    _old_main_init_v79(self)
    try:
        _v79_install(self, repeat=True)
        self.log("【V79上线】设置中心递归已硬切断：V79设置中心完全独立，不调用V77/V78设置函数。", "ok")
        self.log("【V79上线】配置递归已硬切断：V79 cfg只读写JSON，不调用旧cfg。", "ok")
        self.log("【V79上线】资源加载/制作台不再从globals取已覆盖入口，改用安装前捕获的原始函数引用。", "ok")
    except Exception as e:
        try:
            self.log(f"V79初始化失败：{type(e).__name__}: {e}", "err")
        except Exception:
            pass

MainApp.__init__ = _main_init_v79
