def _v80_load_json_cfg():
    cfg = {}
    for name in [
        "pp_studio_v72_settings.json", "pp_studio_v73_settings.json", "pp_studio_v74_settings.json",
        "pp_studio_v75_settings.json", "pp_studio_v76_settings.json", "pp_studio_v77_settings.json",
        "pp_studio_v78_settings.json", "pp_studio_v79_settings.json", "pp_studio_v80_settings.json",
    ]:
        try:
            p = Path.cwd() / name
            if p.exists():
                cfg = _v80_merge(cfg, json.loads(p.read_text("utf-8", errors="ignore")))
        except Exception:
            pass
    return cfg

def _v80_cfg(self=None):
    cfg = _v80_merge(_v80_defaults(), _v80_load_json_cfg())
    if self is not None:
        try:
            mem = getattr(self, "v69_cfg", None)
            if isinstance(mem, dict):
                cfg = _v80_merge(cfg, mem)
            self.v69_cfg = cfg
            self.v63_cfg = cfg
        except Exception:
            pass
    return cfg

def _v80_save_cfg(self=None, cfg=None):
    if cfg is None:
        cfg = _v80_cfg(self)
    if self is not None:
        try:
            self.v69_cfg = cfg
            self.v63_cfg = cfg
        except Exception:
            pass
    for name in [
        "pp_studio_v80_settings.json", "pp_studio_v79_settings.json", "pp_studio_v78_settings.json",
        "pp_studio_v77_settings.json", "pp_studio_v76_settings.json", "pp_studio_v75_settings.json",
        "pp_studio_v74_settings.json", "pp_studio_v73_settings.json", "pp_studio_v72_settings.json",
    ]:
        try:
            (Path.cwd() / name).write_text(json.dumps(cfg, ensure_ascii=False, indent=2), "utf-8")
        except Exception:
            pass
    return cfg

def _v80_notice(self, msg, level="info", scope="dictation"):
    text = str(msg)
    try:
        if "_v77_append_notice_widget" in globals():
            _v77_append_notice_widget(self, text, level)
    except Exception:
        pass
    try:
        if hasattr(self, "dict_v69_notice_var"):
            self.dict_v69_notice_var.set(text)
    except Exception:
        pass
    try:
        self.log(text, "ok" if level == "ok" else "err" if level in ("bad", "err") else "warn" if level == "warn" else "info")
    except Exception:
        pass

def _v80_clean_text(text, limit=280):
    s = str(text or "")
    s = re.sub(r"\s+", " ", s).strip()
    s = re.sub(r"[\u200b\u200c\u200d\ufeff]", "", s)
    # Edge/ChatTTS 都不喜欢超长、控制符、空文本。
    if len(s) > limit:
        s = s[:limit].rsplit(" ", 1)[0] or s[:limit]
    return s

def _v80_text_duration_estimate(text):
    words = re.findall(r"[A-Za-z']+", str(text or ""))
    # 按英语 TTS 粗略估计，避免播放锁太短。
    return max(1.2, min(12.0, len(words) * 0.42 + 0.8))

def _v80_hash(*parts):
    return _hashlib_v80.md5(("||".join(map(str, parts))).encode("utf-8", "ignore")).hexdigest()

def _v80_cache_dir(self):
    cfg = _v80_cfg(self)
    p = Path(cfg.get("speech", {}).get("tts_cache_dir") or (Path.cwd() / "clip_cache" / "tts_v80"))
    p.mkdir(parents=True, exist_ok=True)
    return p

def _v80_find_ffmpeg(self=None):
    # 优先复用工程内部 ffmpeg，然后找常见路径。
    try:
        ff = getattr(getattr(self, "ffmpeg", None), "ffmpeg", None)
        if ff and Path(str(ff)).exists():
            return str(ff)
    except Exception:
        pass
    for p in [
        r"C:\ffmpeg\bin\ffmpeg.exe",
        r"C:\ffmpeg\ffmpeg.exe",
        r"C:\ffmpeg\ffmpeg-2026-03-30-git-e54e117998-full_build\ffmpeg-2026-03-30-git-e54e117998-full_build\bin\ffmpeg.exe",
        "ffmpeg",
    ]:
        try:
            if p == "ffmpeg" or Path(p).exists():
                return p
        except Exception:
            pass
    return "ffmpeg"

def _v80_no_window_kwargs():
    if os.name == "nt":
        return {"creationflags": getattr(subprocess, "CREATE_NO_WINDOW", 0)}
    return {}

async def _v80_edge_stream_save_async(text, voice, out_file):
    import edge_tts  # type: ignore
    out_file = Path(out_file)
    tmp = out_file.with_suffix(".part")
    if tmp.exists():
        try: tmp.unlink()
        except Exception: pass
    communicate = edge_tts.Communicate(text=text, voice=voice, rate="+0%", volume="+0%")
    audio_bytes = 0
    with open(tmp, "wb") as f:
        async for chunk in communicate.stream():
            if chunk.get("type") == "audio":
                data = chunk.get("data") or b""
                f.write(data)
                audio_bytes += len(data)
    if audio_bytes < 800:
        raise RuntimeError(f"Edge-TTS没有返回有效音频：voice={voice}, bytes={audio_bytes}")
    tmp.replace(out_file)
    return out_file

def _v80_run_async(coro):
    try:
        return _asyncio_v80.run(coro)
    except RuntimeError:
        loop = _asyncio_v80.new_event_loop()
        try:
            return loop.run_until_complete(coro)
        finally:
            loop.close()

def _v80_edge_tts_to_audio(self, text):
    text = _v80_clean_text(text)
    if not text:
        return None
    cfg = _v80_cfg(self)
    speech = cfg.get("speech", {})
    voices = []
    v0 = str(speech.get("edge_voice") or "en-US-JennyNeural").strip()
    if v0:
        voices.append(v0)
    for v in speech.get("edge_fallback_voices") or []:
        if v and v not in voices:
            voices.append(v)
    if not voices:
        voices = ["en-US-JennyNeural", "en-US-AriaNeural", "en-US-GuyNeural"]
    cache = _v80_cache_dir(self)
    errors = []
    for voice in voices[:4]:
        out = cache / f"edge_{_v80_hash(voice, text)}.mp3"
        if out.exists() and out.stat().st_size > 1000:
            return out
        try:
            _v80_run_async(_v80_edge_stream_save_async(text, voice, out))
            if out.exists() and out.stat().st_size > 1000:
                if voice != v0:
                    _v80_notice(self, f"Edge-TTS主音色失败后已用备用音色：{voice}", "warn")
                return out
        except Exception as e:
            errors.append(f"{voice}: {type(e).__name__}: {e}")
    _v80_notice(self, "Edge-TTS Python API 全部音色失败：" + " | ".join(errors[-3:]), "bad")
    return None

def _v80_chattts_to_audio(self, text):
    text = _v80_clean_text(text, limit=180)
    if not text:
        return None
    now = time.time()
    # ChatTTS 一旦断言失败，30秒内不要连续炸模型。
    if getattr(self, "_v80_chattts_disabled_until", 0) > now:
        _v80_notice(self, "ChatTTS刚失败过，30秒保护期内不再重复调用。", "warn")
        return None

    cache = _v80_cache_dir(self)
    out = cache / f"chattts_{_v80_hash(text)}.wav"
    if out.exists() and out.stat().st_size > 1000:
        return out

    try:
        import ChatTTS  # type: ignore
        import numpy as np  # type: ignore

        chat = getattr(self, "_v80_chattts", None)
        if chat is None:
            chat = ChatTTS.Chat()
            cfg = _v80_cfg(self)
            local_dir = str(cfg.get("speech", {}).get("chattts_local_dir") or "").strip()
            loaded = False
            # 兼容不同版本：source/local_path/compile 参数可能不同，所以多种方式尝试。
            load_attempts = []
            if local_dir:
                load_attempts += [
                    {"compile": False, "source": "local", "local_path": local_dir},
                    {"compile": False, "source": "local", "custom_path": local_dir},
                ]
            load_attempts += [{"compile": False}, {}]
            last_err = None
            for kw in load_attempts:
                try:
                    chat.load(**kw)
                    loaded = True
                    break
                except TypeError:
                    try:
                        chat.load()
                        loaded = True
                        break
                    except Exception as e:
                        last_err = e
                except Exception as e:
                    last_err = e
            if not loaded:
                raise RuntimeError(f"ChatTTS模型加载失败：{last_err}")
            self._v80_chattts = chat
            _v80_notice(self, "ChatTTS 本地模型加载成功。", "ok")

        infer_attempts = [
            {"skip_refine_text": True, "do_text_normalization": True},
            {"skip_refine_text": False, "do_text_normalization": True},
            {},
        ]
        wavs = None
        last_err = None
        for kw in infer_attempts:
            try:
                wavs = chat.infer([text], **kw)
                if wavs is not None:
                    break
            except AssertionError as e:
                last_err = e
            except TypeError as e:
                last_err = e
                try:
                    wavs = chat.infer([text])
                    if wavs is not None:
                        break
                except Exception as e2:
                    last_err = e2
            except Exception as e:
                last_err = e
        if wavs is None:
            raise RuntimeError(f"ChatTTS infer未返回音频：{type(last_err).__name__}: {last_err}")

        audio = wavs[0] if isinstance(wavs, (list, tuple)) else wavs
        if hasattr(audio, "detach"):
            audio = audio.detach().cpu().numpy()
        audio = np.asarray(audio).squeeze()
        if audio.size < 100:
            raise RuntimeError("ChatTTS返回空音频。")
        maxv = float(np.max(np.abs(audio))) or 1.0
        audio16 = (audio / maxv * 32767).astype("int16")
        try:
            from scipy.io.wavfile import write as wavwrite  # type: ignore
            wavwrite(str(out), 24000, audio16)
        except Exception:
            with _wave_v80.open(str(out), "wb") as wf:
                wf.setnchannels(1)
                wf.setsampwidth(2)
                wf.setframerate(24000)
                wf.writeframes(audio16.tobytes())
        return out if out.exists() and out.stat().st_size > 1000 else None
    except Exception as e:
        self._v80_chattts_disabled_until = time.time() + 30
        detail = _traceback_v80.format_exc(limit=3).splitlines()[-1]
        _v80_notice(self, f"ChatTTS 发音失败，已进入30秒保护：{type(e).__name__}: {detail}", "bad")
        return None

def _v80_audio_to_wav(self, path):
    p = Path(str(path))
    if not p.exists():
        return None
    if p.suffix.lower() == ".wav":
        return p
    out = _v80_cache_dir(self) / f"play_{_v80_hash(p, p.stat().st_mtime_ns)}.wav"
    if out.exists() and out.stat().st_size > 1000:
        return out
    ff = _v80_find_ffmpeg(self)
    try:
        subprocess.run(
            [ff, "-y", "-hide_banner", "-loglevel", "error", "-i", str(p), "-ac", "1", "-ar", "22050", str(out)],
            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=45, **_v80_no_window_kwargs()
        )
        if out.exists() and out.stat().st_size > 1000:
            return out
    except Exception as e:
        _v80_notice(self, f"FFmpeg转WAV失败：{type(e).__name__}: {e}", "bad")
    return None

def _v80_extract_original_audio(self, media, start, end, tag="full"):
    media = Path(str(media or ""))
    if not media.exists() or not end or end <= start:
        return None
    out = _v80_cache_dir(self) / f"orig_{tag}_{_v80_hash(media, start, end)}.wav"
    if out.exists() and out.stat().st_size > 1000:
        return out
    ff = _v80_find_ffmpeg(self)
    dur = max(0.2, float(end) - float(start))
    try:
        subprocess.run(
            [ff, "-y", "-hide_banner", "-loglevel", "error", "-ss", f"{float(start):.3f}", "-t", f"{dur:.3f}",
             "-i", str(media), "-vn", "-ac", "1", "-ar", "22050", str(out)],
            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=45, **_v80_no_window_kwargs()
        )
        if out.exists() and out.stat().st_size > 1000:
            return out
    except Exception as e:
        _v80_notice(self, f"原片音频提取失败：{type(e).__name__}: {e}", "bad")
    return None

def _v80_sapi_speak_async(self, text):
    # 这是最后紧急兜底：不显示为可选发音引擎，不抢用户的主设置；只在 Edge/ChatTTS 全失败时让软件至少有声音。
    if os.name != "nt":
        return False
    if not _v80_cfg(self).get("speech", {}).get("allow_emergency_sapi_fallback", True):
        return False
    try:
        import win32com.client  # type: ignore
        speaker = win32com.client.Dispatch("SAPI.SpVoice")
        speaker.Speak(str(text), 1)  # async
        _v80_notice(self, "Edge/ChatTTS均失败，已启用 Windows SAPI 紧急兜底发音。", "warn")
        return True
    except Exception:
        return False

def _v80_play_file(self, path):
    p = Path(str(path or ""))
    if not p.exists():
        return False
    try:
        if os.name == "nt":
            wav = _v80_audio_to_wav(self, p)
            if wav and wav.exists():
                import winsound
                winsound.PlaySound(str(wav), winsound.SND_FILENAME | winsound.SND_ASYNC)
                return True
        # 非 Windows 或转换失败时，才走系统默认打开。
        if os.name == "nt":
            os.startfile(str(p))
        elif sys.platform == "darwin":
            subprocess.Popen(["open", str(p)])
        else:
            subprocess.Popen(["xdg-open", str(p)])
        return True
    except Exception as e:
        _v80_notice(self, f"音频文件播放失败：{type(e).__name__}: {e}", "bad")
        return False

def _v80_tts_to_audio(self, text):
    text = _v80_clean_text(text)
    if not text:
        return None
    cfg = _v80_cfg(self)
    engine = cfg.get("speech", {}).get("tts_engine", "Edge-TTS Python API")
    if getattr(self, "_v80_last_engine_log", ("", 0))[0] != engine or time.time() - getattr(self, "_v80_last_engine_log", ("", 0))[1] > 5:
        _v80_notice(self, f"当前发音引擎：{engine}", "info")
        self._v80_last_engine_log = (engine, time.time())

    if engine == "原片音频":
        return None

    if "ChatTTS" in engine:
        wav = _v80_chattts_to_audio(self, text)
        if wav:
            return wav
        _v80_notice(self, "ChatTTS 未返回音频；本次只尝试一次 Edge-TTS 兜底，避免刷屏。", "warn")
        edge = _v80_edge_tts_to_audio(self, text)
        if edge:
            return edge
        return None

    if "Edge" in engine or "TTS" in engine or engine in ("在线TTS", "旧版TTS兜底"):
        return _v80_edge_tts_to_audio(self, text)

    return _v80_edge_tts_to_audio(self, text)

def _v80_estimate_segment(self, mode="full"):
    text = ""
    start = end = 0.0
    media = ""
    try:
        fn = globals().get("_v73_estimate_segment")
        if callable(fn):
            text, start, end, media = fn(self, mode)
    except Exception:
        pass
    if not text:
        try:
            m = _v76_current_material(self) if "_v76_current_material" in globals() else None
            text = _v76_material_text(m) if "_v76_material_text" in globals() else ""
            if isinstance(m, dict):
                media = m.get("audio_path") or m.get("video_path") or m.get("media_path") or m.get("local_path") or ""
                start = float(m.get("start") or m.get("start_time") or 0)
                end = float(m.get("end") or m.get("end_time") or 0)
        except Exception:
            pass
    return _v80_clean_text(text), float(start or 0), float(end or 0), str(media or "")

def _v80_playback_gate(self, key, duration, launch_func):
    cfg = _v80_cfg(self)
    if not cfg.get("speech", {}).get("playback_single_flight", True):
        return launch_func()

    now = time.time()
    state = getattr(self, "_v80_play_state", {})
    busy_until = float(state.get(key, 0) or 0)
    if now < busy_until:
        remain = busy_until - now
        if remain > 0.10:
            if now - float(state.get(key + "_last_ignore_log", 0) or 0) > 0.8:
                _v80_notice(self, f"播放中，重复触发已忽略；剩余约 {remain:.1f}s。", "warn")
                state[key + "_last_ignore_log"] = now
                self._v80_play_state = state
            return
        # 只排队一次
        if state.get(key + "_queued"):
            return
        state[key + "_queued"] = True
        self._v80_play_state = state
        def delayed():
            time.sleep(max(0.03, remain + 0.02))
            st = getattr(self, "_v80_play_state", {})
            st[key + "_queued"] = False
            self._v80_play_state = st
            _v80_playback_gate(self, key, duration, launch_func)
        threading.Thread(target=delayed, daemon=True).start()
        return

    state[key] = now + max(0.5, float(duration or 1.5))
    self._v80_play_state = state
    return launch_func()

def _v80_play_audio_mode(self, mode="full"):
    text, start, end, media = _v80_estimate_segment(self, mode)
    if not text:
        _v80_notice(self, "当前没有可播放文本/语块。", "bad")
        return
    duration = (end - start) if (end and end > start) else _v80_text_duration_estimate(text)
    key = "track_audio" if mode == "track" else "full_audio"
    cfg = _v80_cfg(self)
    engine = cfg.get("speech", {}).get("tts_engine", "Edge-TTS Python API")

    def run():
        def worker():
            audio = None
            if engine == "原片音频":
                audio = _v80_extract_original_audio(self, media, start, end, tag=key)
                if not audio:
                    _v80_notice(self, "原片音频不可用：缺少媒体文件或时间轴，改用 Edge-TTS 兜底。", "warn")
                    audio = _v80_edge_tts_to_audio(self, text)
            else:
                audio = _v80_tts_to_audio(self, text)
            if audio and _v80_play_file(self, audio):
                _v80_notice(self, ("跟踪播放音频：" if mode == "track" else "播放音频：") + text[:90], "ok")
            else:
                if not _v80_sapi_speak_async(self, text):
                    _v80_notice(self, "音频没有播放成功：ChatTTS/Edge-TTS/原片音频均失败。", "bad")
        threading.Thread(target=worker, daemon=True).start()

    return _v80_playback_gate(self, key, duration, run)

def _v80_play_video_mode(self, mode="full"):
    text, start, end, media = _v80_estimate_segment(self, mode)
    if not media or not Path(media).exists():
        _v80_notice(self, "当前素材没有可播放的视频/媒体路径。", "bad")
        return
    duration = (end - start) if (end and end > start) else 2.0
    key = "track_video" if mode == "track" else "full_video"

    def run():
        try:
            fn = globals().get("_v73_play_video_mode") or globals().get("_v74_play_video_mode")
            if callable(fn) and fn is not _v80_play_video_mode:
                return fn(self, mode)
        except RecursionError:
            _v80_notice(self, "旧视频播放链递归，已阻断。", "bad")
        except Exception as e:
            _v80_notice(self, f"视频播放失败：{type(e).__name__}: {e}", "bad")
    return _v80_playback_gate(self, key, duration, run)

