def _v80_call_known(self, names, *args):
    for nm in names:
        fn = globals().get(nm) or getattr(self, nm, None)
        if callable(fn):
            try:
                return fn(self, *args) if nm in globals() else fn(*args)
            except TypeError:
                try: return fn(*args)
                except Exception: pass
            except Exception as e:
                _v80_notice(self, f"{nm} 执行失败：{type(e).__name__}: {e}", "bad")
                return
    return None

def _v80_copy_text(self, text, label="文本"):
    try:
        self.clipboard_clear()
        self.clipboard_append(str(text or ""))
        _v80_notice(self, f"已复制{label}。", "ok")
    except Exception as e:
        _v80_notice(self, f"复制失败：{type(e).__name__}: {e}", "bad")

def _v80_action(self, action):
    try:
        if action == "full_audio": return _v80_play_audio_mode(self, "full")
        if action == "track_audio": return _v80_play_audio_mode(self, "track")
        if action == "full_video": return _v80_play_video_mode(self, "full")
        if action == "track_video": return _v80_play_video_mode(self, "track")
        if action == "pause_resume": return _v80_call_known(self, ["_v73_pause_resume", "_v46_pause_resume"])
        if action == "prev_sentence": return _v80_call_known(self, ["_v75_prev", "_v72_prev", "_v46_prev"])
        if action == "next_sentence": return _v80_call_known(self, ["_v75_next", "_v72_next", "_v46_next"])
        if action == "judge_current": return _v80_call_known(self, ["_v75_force_check_current", "_v46_force_check_current"])
        if action == "submit_sentence": return _v80_call_known(self, ["_v75_submit_all", "_v72_submit_all", "_v46_submit"])
        if action == "hint": return _v80_call_known(self, ["_v75_hint_current", "_v74_hint_current", "_v72_hint_current"])
        if action == "toggle_chinese": return _v80_call_known(self, ["_v75_toggle_chinese", "_v74_toggle_chinese", "_v72_toggle_chinese"])
        if action == "toggle_current_subtitle": return _v80_toggle_display(self, "show_current_english_subtitle", "粉色当前英文字幕")
        if action == "toggle_next_subtitle": return _v80_toggle_display(self, "show_next_english_subtitle", "青色下一句英文字幕")
        if action == "toggle_left_material_pool": return _v80_toggle_display(self, "show_left_material_pool", "左侧素材池")
        if action == "toggle_right_notice": return _v80_toggle_display(self, "show_right_notification_panel", "右侧通知栏")
        if action == "window_fullscreen":
            try:
                self.attributes("-fullscreen", not bool(self.attributes("-fullscreen")))
            except Exception:
                pass
            return
        if action == "copy_selected":
            m = _v76_current_material(self) if "_v76_current_material" in globals() else None
            return _v80_copy_text(self, _v76_material_text(m) if "_v76_material_text" in globals() else "", "选中台词")
        if action == "copy_current_sentence":
            m = _v76_current_material(self) if "_v76_current_material" in globals() else None
            return _v80_copy_text(self, _v76_material_text(m) if "_v76_material_text" in globals() else "", "当前整句")
        if action == "copy_current_block":
            text, *_ = _v80_estimate_segment(self, "track")
            return _v80_copy_text(self, text, "当前语块")
        if action == "clear_learning": return _v80_call_known(self, ["_v66_clear_learning_area", "_v72_clear_learning"])
        if action == "clear_material_pool":
            try:
                self.dictation_materials_v30 = []
                _v80_render_learning_area(self)
                _v80_notice(self, "听写素材池已清空。", "ok")
            except Exception as e:
                _v80_notice(self, f"清空素材池失败：{type(e).__name__}: {e}", "bad")
            return
        if action == "resource_sync": return _v80_call_known(self, ["_v71_refresh_resource_platform", "_v76_refresh_material_tree", "_v63_refresh_material_tree"])
        if action == "refresh_material": return _v80_call_known(self, ["_v76_refresh_material_tree", "_v63_refresh_material_tree", "refresh_dictation_materials"])
        if action == "import_txt_srt": return _v80_call_known(self, ["_v50_import_txt_srt", "_v46_import_txt_srt"])
        if action == "import_from_selected_result": return _v80_call_known(self, ["_v50_import_from_checked", "_v46_import_from_checked"])
        if action == "import_from_selection_pool": return _v80_call_known(self, ["_v76_safe_load_selection_pool", "_v50_safe_load_selection_pool"])
        if action == "download_selected_to_local": return _v80_call_known(self, ["_v71_download_selection_to_local", "_v50_download_selection_to_local"])
        if action == "add_local_video_subtitle_path": return _v80_call_known(self, ["_v71_add_local_video_subtitle_path", "_v50_add_local_video_subtitle_path"])
        if action == "add_text_path": return _v80_call_known(self, ["_v71_add_text_path", "_v50_add_text_path"])
        if action == "open_resource_platform": return _v80_call_known(self, ["_v71_open_resource_platform", "_v69_open_resource_platform"])
        if action == "open_maker": return _v80_open_maker(self)
        if action in ("make_current_translation", "make_file_translation", "make_folder_translation", "make_current_tts", "make_file_tts"):
            return _v80_open_maker(self)
        if action == "open_settings": return _v80_open_settings_center(self)
        if action in ("skip_block", "auto_jump_toggle", "show_fixed_hint", "reset_current_input", "stop_maker"):
            _v80_notice(self, f"动作已登记快捷键，但当前版本没有找到对应实现函数：{action}", "warn")
            return
    except Exception as e:
        _v80_notice(self, f"快捷动作执行失败：{action}｜{type(e).__name__}: {e}", "bad")

def _v80_toggle_display(self, key, label):
    cfg = _v80_cfg(self)
    cfg["display"][key] = not bool(cfg["display"].get(key, False))
    _v80_save_cfg(self, cfg)
    _v80_render_learning_area(self)
    _v80_notice(self, f"{label}已{'显示' if cfg['display'][key] else '隐藏'}。", "ok")

def _v80_key_to_tk(key):
    key = str(key or "").strip().lower().replace(" ", "")
    if not key:
        return []
    if key in ("ctrl", "control"):
        return ["<KeyPress-Control_L>", "<KeyPress-Control_R>"]
    if key == "alt":
        return ["<KeyPress-Alt_L>", "<KeyPress-Alt_R>", "<KeyPress-Menu>"]
    if key == "space":
        return ["<space>", "<KeyPress-space>"]
    if key == "enter":
        return ["<Return>"]
    if key == "esc":
        return ["<Escape>"]
    parts = key.split("+")
    mods, normal = [], ""
    for p in parts:
        if p in ("ctrl", "control"):
            mods.append("Control")
        elif p == "alt":
            mods.append("Alt")
        elif p == "shift":
            mods.append("Shift")
        else:
            normal = p
    mp = {"up":"Up", "down":"Down", "left":"Left", "right":"Right", "space":"space", "enter":"Return", "esc":"Escape", "delete":"Delete", ",":"comma", "/":"slash"}
    if re.fullmatch(r"f\d{1,2}", normal):
        normal = normal.upper()
    normal = mp.get(normal, normal)
    if not normal:
        return []
    return ["<" + "-".join(mods + [normal]) + ">"]

def _v80_apply_shortcuts(self, silent=False):
    try:
        for seq in getattr(self, "_v80_tk_sequences", []) or []:
            try: self.unbind_all(seq)
            except Exception: pass
    except Exception:
        pass
    cfg = _v80_cfg(self)
    action_set = {a for a, _, _, _ in _v80_action_defs()}
    seqs = []
    for action, key in (cfg.get("shortcuts") or {}).items():
        if action == "global_hotkeys" or action not in action_set:
            continue
        for seq in _v80_key_to_tk(key):
            try:
                self.bind_all(seq, lambda e, a=action: (_v80_action(self, a), "break"))
                seqs.append(seq)
            except Exception:
                pass
    self._v80_tk_sequences = seqs

    # 全局只注册四个播放键，防止把 Enter/Space/输入按键抢坏。
    try:
        import keyboard  # type: ignore
        for h in getattr(self, "_v80_global_handles", []) or []:
            try: keyboard.remove_hotkey(h)
            except Exception: pass
        self._v80_global_handles = []
        if cfg.get("shortcuts", {}).get("global_hotkeys", True):
            for action in ("full_audio", "track_audio", "full_video", "track_video"):
                key = cfg["shortcuts"].get(action)
                if key:
                    self._v80_global_handles.append(keyboard.add_hotkey(key, lambda a=action: _v80_action(self, a), suppress=False))
    except Exception as e:
        if not silent:
            _v80_notice(self, f"全局快捷键不可用，仅软件内快捷键生效：{type(e).__name__}: {e}", "warn")
    if not silent:
        _v80_notice(self, "快捷键已立即生效。", "ok")

def _v80_row(parent, title, desc=""):
    row = tk.Frame(parent, bg=V80_PANEL)
    row.pack(fill="x", padx=16, pady=7)
    left = tk.Frame(row, bg=V80_PANEL)
    left.pack(side="left", fill="x", expand=True)
    tk.Label(left, text=title, bg=V80_PANEL, fg=V80_TEXT, font=("Microsoft YaHei UI", 11, "bold")).pack(anchor="w")
    if desc:
        tk.Label(left, text=desc, bg=V80_PANEL, fg=V80_MUTED, wraplength=760, justify="left").pack(anchor="w")
    return row

