def _v80_open_maker(self, *args, **kwargs):
    # 尽量调用 V77 制作台；如果被旧版本覆盖导致递归，就提示而不是炸。
    fn = globals().get("_v77_open_maker")
    if callable(fn) and fn is not _v80_open_maker:
        try:
            return fn(self)
        except RecursionError:
            _v80_notice(self, "旧制作台递归，已阻断。", "bad")
        except Exception as e:
            _v80_notice(self, f"制作台打开失败：{type(e).__name__}: {e}", "bad")
    _v80_notice(self, "制作台暂不可用：旧制作台函数没有安全入口。", "bad")

def _v80_cleanup_buttons(self):
    remove_contains = [
        "听写控制台", "刷新素材树", "刷新资源目录", "快捷键设置", "自定义快捷键",
        "打开快捷键设置", "打开快捷键捕获设置", "分块横线听写", "高级设置中心", "打开快捷键",
    ]
    maker_contains = ["制作当前翻译", "制作整文件翻译", "制作翻译字幕"]
    settings_seen = 0
    def walk(w):
        nonlocal settings_seen
        try:
            text = str(w.cget("text")).strip()
            if any(x in text for x in remove_contains):
                try: w.destroy()
                except Exception:
                    try: w.pack_forget()
                    except Exception: pass
                return
            if "设置中心" in text or text == "配置中心":
                settings_seen += 1
                if settings_seen > 1:
                    try: w.destroy()
                    except Exception:
                        try: w.pack_forget()
                        except Exception: pass
                    return
                try: w.configure(text="设置中心", command=lambda: _v80_open_settings_center(self))
                except Exception: pass
            if any(x in text for x in maker_contains):
                try: w.configure(text="制作台", command=lambda: _v80_open_maker(self))
                except Exception: pass
            if text in ("播放当前音频", "主播放 Ctrl+R", "播放音频 Ctrl"):
                try: w.configure(text="播放音频", command=lambda: _v80_play_audio_mode(self, "full"))
                except Exception: pass
            if text in ("跟踪播放", "跟踪播放 Alt"):
                try: w.configure(text="跟踪播放", command=lambda: _v80_play_audio_mode(self, "track"))
                except Exception: pass
            if text in ("视频播放 Ctrl+Alt+V", "播放当前视频"):
                try: w.configure(text="播放视频", command=lambda: _v80_play_video_mode(self, "full"))
                except Exception: pass
        except Exception:
            pass
        try:
            for ch in list(w.winfo_children()):
                walk(ch)
        except Exception:
            pass
    try: walk(self)
    except Exception: pass

def _v80_render_learning_area(self):
    # 调旧渲染前先临时避免递归；失败则至少不炸。
    fn = globals().get("_v79_render_learning_area") or globals().get("_v75_render_learning_area") or globals().get("_v74_render_learning_area")
    if callable(fn) and fn is not _v80_render_learning_area:
        try:
            fn(self)
        except RecursionError:
            _v80_notice(self, "旧学习区渲染递归，已阻断。", "bad")
        except Exception as e:
            _v80_notice(self, f"学习区刷新失败：{type(e).__name__}: {e}", "bad")
    try:
        _v80_cleanup_buttons(self)
    except Exception:
        pass

def _v80_install(self=None, repeat=True):
    # 配置/通知/设置全部指向 V80 独立链。
    for nm in ["_v80_cfg", "_v79_cfg", "_v78_cfg", "_v77_cfg", "_v76_cfg", "_v75_cfg", "_v74_cfg", "_v73_cfg", "_v72_cfg", "_v71_cfg", "_v70_cfg", "_v69_cfg"]:
        globals()[nm] = _v80_cfg
    for nm in ["_v80_save_cfg", "_v79_save_cfg", "_v78_save_cfg", "_v77_save_cfg", "_v76_save_cfg", "_v75_save_cfg", "_v74_save_cfg", "_v73_save_cfg", "_v72_save_cfg", "_v71_save_cfg", "_v70_save_cfg", "_v69_save_cfg"]:
        globals()[nm] = _v80_save_cfg
    for nm in ["_v80_notice", "_v79_notice", "_v78_notice", "_v77_notice", "_v76_notice", "_v75_notice", "_v74_notice"]:
        globals()[nm] = _v80_notice
    for nm in [
        "_v80_open_settings_center", "_v79_open_settings_center", "_v78_open_settings_center", "_v77_open_settings_center", "_v76_open_settings_center",
        "_v75_open_settings_center", "_v74_open_settings_center", "_v73_open_settings_center", "_v72_open_settings_center",
        "_v60_open_shortcut_editor", "_v58_open_shortcut_editor", "_v57_open_shortcut_editor", "_v56_open_shortcut_editor",
        "_v46_open_shortcut_editor", "_dictation_open_shortcut_editor_v37", "_dictation_open_shortcut_editor_v34",
        "_v54_open_sound_settings", "_v53_open_sound_settings", "_v56_open_sound_settings",
    ]:
        globals()[nm] = _v80_open_settings_center

    # TTS/播放硬覆盖。
    for nm in ["_v80_tts_to_audio", "_v79_tts_to_audio", "_v78_tts_to_audio", "_v77_tts_to_audio", "_v76_tts_to_audio", "_v75_tts_to_audio", "_v74_tts_to_audio", "_v73_tts_to_audio"]:
        globals()[nm] = _v80_tts_to_audio
    for nm in ["_v80_edge_tts_to_audio", "_v76_edge_tts_to_audio", "_v71_edge_tts_to_wav"]:
        globals()[nm] = _v80_edge_tts_to_audio
    for nm in ["_v80_chattts_to_audio", "_v76_chattts_to_audio", "_v74_chattts_to_wav", "_v71_chattts_to_wav"]:
        globals()[nm] = _v80_chattts_to_audio
